#!/usr/bin/env python3
"""e2e_redteam.py — full-stack privilege-escalation red-team for phase-40
impersonation.  RUNS AS IN-NS ROOT (launched by userns_exec_launcher inside an
unprivileged user namespace with a subuid range + bind-mounted fake passwd/group).

This is the pseudo-production permissions test: it boots the REAL nginx binary
with `xrootd_impersonation map` (so the real master spawns the real broker, real
svc-uid workers connect, and the real auth->identity->dispatch->broker->setfsuid
chain runs), then drives it over the network with token-authenticated WebDAV
requests as many identities and tries to break the permissions model.

It asserts the model holds end-to-end: files owned by the MAPPED user (not the
worker/broker), DAC enforced, every escalation/forbidden identity denied,
confinement intact, and no credential leak under concurrency.

argv[1] = work dir (pre-created by the pytest wrapper, holds nothing required —
this script generates keys/tokens/config/export tree itself as in-ns root).
Prints "PASS:"/"FAIL:" per check and "ALL PASSED" + exit 0 on success.
"""

import base64
import datetime as dt
import hashlib
import hmac
import json
import os
import re
import socket
import struct
import subprocess
import sys
import threading
import time
import urllib.error
import urllib.request
from http.client import HTTPConnection   # imported by name: the http() helper below
from urllib.parse import quote           # would otherwise shadow the `http` module

from cryptography.hazmat.primitives.asymmetric import ec
from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.primitives.asymmetric.utils import decode_dss_signature

WORK = sys.argv[1] if len(sys.argv) > 1 else "/tmp/e2e_redteam"
NGINX = os.environ.get("TEST_NGINX_BIN", "/tmp/nginx-1.28.3/objs/nginx")
# repo root = .../tests/userns/e2e_redteam.py -> up 3.  The native root:// clients
# (built under client/) drive the stream server with a bearer token (BEARER_TOKEN).
REPO = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
# The native CLI binaries are built into client/bin/ (the Makefile's BINDIR), not
# client/ directly — an older layout this path lagged behind.
NATIVE_XRDFS = os.path.join(REPO, "client", "bin", "xrdfs")
NATIVE_XRDCP = os.path.join(REPO, "client", "bin", "xrdcp")
# set in main(): the JWT signing key + the impersonation stream port, so the
# root:// helpers can mint a per-subject token without threading them everywhere.
_jwt_key = None
_stream_port = 0
ISSUER = "https://redteam.example"
AUDIENCE = "nginx-xrootd"
KID = "rt-es256"
WRITE_SCOPE = "storage.create:/ storage.modify:/ storage.read:/"

# S3 SigV4: access_key == the UNIX user the broker maps to (subject = access key).
S3_BUCKET = "testbucket"
S3_REGION = "us-east-1"
S3_SECRET = "rt-s3-secret-0123456789"

# in-ns uids (match the fake /etc/passwd the launcher bind-mounted).
UID_ALICE, UID_BOB, UID_SVC = 1001, 1002, 1500
UID_CAROL, UID_DAVE, UID_ERIN, UID_FRANK = 1003, 1004, 1005, 1006
UID_MANYU, UID_FLOOR, UID_LOW = 1008, 1000, 999
# supplementary groups (match the fake /etc/group): staff={alice,carol},
# research={bob,dave}, shared={alice,bob,carol}, proj={carol,dave,erin}.
GID_STAFF, GID_RESEARCH, GID_SHARED, GID_PROJ = 2001, 2002, 2003, 2004

_pass = _fail = 0


def ok(cond, msg):
    global _pass, _fail
    if cond:
        _pass += 1
        print(f"PASS: {msg}", flush=True)
    else:
        _fail += 1
        print(f"FAIL: {msg}", flush=True)


def _b64u(b):
    return base64.urlsafe_b64encode(b).rstrip(b"=").decode("ascii")


def mint(key, sub, scope=WRITE_SCOPE, **over):
    now = int(time.time())
    hdr = {"alg": "ES256", "typ": "JWT", "kid": KID}
    pay = {"iss": ISSUER, "sub": sub, "aud": AUDIENCE, "exp": now + 3600,
           "iat": now, "nbf": now, "scope": scope, "wlcg.ver": "1.0"}
    pay.update(over)
    si = (_b64u(json.dumps(hdr, separators=(",", ":")).encode()) + "."
          + _b64u(json.dumps(pay, separators=(",", ":")).encode()))
    der = key.sign(si.encode("ascii"), ec.ECDSA(hashes.SHA256()))
    r, s = decode_dss_signature(der)
    raw = r.to_bytes(32, "big") + s.to_bytes(32, "big")
    return si + "." + _b64u(raw)


def free_port():
    s = socket.socket()
    s.bind(("127.0.0.1", 0))
    p = s.getsockname()[1]
    s.close()
    return p


def chown_dir(path, uid, gid, mode):
    os.makedirs(path, exist_ok=True)
    os.chown(path, uid, gid)
    os.chmod(path, mode)


def ensure_traversable(path):
    """Add +x to every ancestor so the unprivileged svc-uid worker can traverse
    to (and open) the export root — mirrors a correct production export layout
    (the worker user must be able to reach the data tree)."""
    p = os.path.abspath(path)
    while p and p != "/":
        try:
            os.chmod(p, os.stat(p).st_mode | 0o111)
        except OSError:
            pass
        p = os.path.dirname(p)


def http(method, path, port, token=None, data=None, hdrs=None):
    url = f"http://127.0.0.1:{port}{path}"
    req = urllib.request.Request(url, method=method, data=data)
    if token:
        req.add_header("Authorization", f"Bearer {token}")
    for k, v in (hdrs or {}).items():
        req.add_header(k, v)
    try:
        with urllib.request.urlopen(req, timeout=6) as r:
            return r.status, r.read()
    except urllib.error.HTTPError as e:
        return e.code, e.read()
    except Exception as e:  # noqa: BLE001
        return -1, str(e).encode()


def http_keepalive(reqs, port):
    """Send several (method, path, token, data, hdrs) requests over ONE kept-alive
    TCP connection (http.client reuses it).  Used to prove the per-request
    impersonation principal does not LEAK across requests pipelined on the same
    worker connection.  Returns [(status, body), ...]."""
    conn = HTTPConnection("127.0.0.1", port, timeout=8)
    out = []
    try:
        for method, path, token, data, extra in reqs:
            hdrs = dict(extra or {})
            if token:
                hdrs["Authorization"] = f"Bearer {token}"
            conn.request(method, path, body=data, headers=hdrs)
            r = conn.getresponse()
            out.append((r.status, r.read()))
    except Exception as e:  # noqa: BLE001
        out.append((-1, str(e).encode()))
    finally:
        conn.close()
    return out


def raw_http(raw, port, read_timeout=4.0):
    """Send RAW bytes on a fresh TCP connection (bypasses http.client so we can
    forge malformed request lines, duplicate headers, bare-LF framing, HTTP/1.0,
    request-smuggling bodies) and return the raw response bytes (b"" on
    timeout/closed).  Used to prove the worker cannot be desynced or tricked into
    running a smuggled request under the wrong identity."""
    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.settimeout(read_timeout)
    buf = b""
    try:
        s.connect(("127.0.0.1", port))
        s.sendall(raw if isinstance(raw, bytes) else raw.encode())
        while True:
            chunk = s.recv(65536)
            if not chunk:
                break
            buf += chunk
            if len(buf) > 1 << 20:
                break
    except (OSError, socket.timeout):
        pass
    finally:
        try:
            s.close()
        except OSError:
            pass
    return buf


def s3_presign(method, key, port, expires=300, access_key="alice", when=None,
               tamper=False):
    """Build a PRESIGNED-URL (query-string SigV4) path for /<bucket>/<key>.  Auth
    travels in X-Amz-* query params (no Authorization header), validity bounded by
    X-Amz-Expires.  Returns the path+query string to pass to http() with no token.
    'when' backdates the signing time (expiry tests); 'tamper' corrupts the
    signature (forgery test)."""
    now = when or dt.datetime.now(dt.timezone.utc)
    amz_date = now.strftime("%Y%m%dT%H%M%SZ")
    date = now.strftime("%Y%m%d")
    host = f"127.0.0.1:{port}"
    path = f"/{S3_BUCKET}/{key}"
    scope = f"{date}/{S3_REGION}/s3/aws4_request"
    q = {
        "X-Amz-Algorithm": "AWS4-HMAC-SHA256",
        "X-Amz-Credential": f"{access_key}/{scope}",
        "X-Amz-Date": amz_date,
        "X-Amz-Expires": str(expires),
        "X-Amz-SignedHeaders": "host",
    }
    cq = _canon_query(q)
    canonical = (f"{method}\n{quote(path, safe='/-_.~')}\n{cq}\n"
                 f"host:{host}\n\nhost\nUNSIGNED-PAYLOAD")
    sts = (f"AWS4-HMAC-SHA256\n{amz_date}\n{scope}\n"
           f"{hashlib.sha256(canonical.encode()).hexdigest()}")
    k = hmac.new(f"AWS4{S3_SECRET}".encode(), date.encode(), hashlib.sha256).digest()
    k = hmac.new(k, S3_REGION.encode(), hashlib.sha256).digest()
    k = hmac.new(k, b"s3", hashlib.sha256).digest()
    k = hmac.new(k, b"aws4_request", hashlib.sha256).digest()
    sig = hmac.new(k, sts.encode(), hashlib.sha256).hexdigest()
    if tamper:
        sig = ("0" * len(sig)) if sig[0] != "0" else ("f" * len(sig))
    return f"{path}?{cq}&X-Amz-Signature={sig}"


def _canon_query(params):
    """Canonical SigV4 query string: keys sorted, value-encoded, '&'-joined."""
    return "&".join(f"{quote(k, safe='-_.~')}={quote(v, safe='-_.~')}"
                    for k, v in sorted(params.items()))


def s3_sign(method, path, port, params=None, access_key="alice", when=None):
    """Build SigV4 header-auth (UNSIGNED-PAYLOAD, SignedHeaders=host;x-amz-date)
    for a path-style S3 request.  access_key is the subject the broker maps to a
    UNIX uid, so signing as "alice" makes the S3 op run as alice under map mode.
    `when` overrides the timestamp (for clock-skew / expiry attack tests)."""
    now = when or dt.datetime.now(dt.timezone.utc)
    amz_date = now.strftime("%Y%m%dT%H%M%SZ")
    date = now.strftime("%Y%m%d")
    host = f"127.0.0.1:{port}"
    cq = _canon_query(params or {})
    canonical = (f"{method}\n{quote(path, safe='/-_.~')}\n{cq}\n"
                 f"host:{host}\nx-amz-date:{amz_date}\n\n"
                 f"host;x-amz-date\nUNSIGNED-PAYLOAD")
    scope = f"{date}/{S3_REGION}/s3/aws4_request"
    sts = (f"AWS4-HMAC-SHA256\n{amz_date}\n{scope}\n"
           f"{hashlib.sha256(canonical.encode()).hexdigest()}")
    k = hmac.new(f"AWS4{S3_SECRET}".encode(), date.encode(), hashlib.sha256).digest()
    k = hmac.new(k, S3_REGION.encode(), hashlib.sha256).digest()
    k = hmac.new(k, b"s3", hashlib.sha256).digest()
    k = hmac.new(k, b"aws4_request", hashlib.sha256).digest()
    sig = hmac.new(k, sts.encode(), hashlib.sha256).hexdigest()
    return {"x-amz-date": amz_date, "x-amz-content-sha256": "UNSIGNED-PAYLOAD",
            "Authorization": (f"AWS4-HMAC-SHA256 Credential={access_key}/{scope}, "
                              f"SignedHeaders=host;x-amz-date, Signature={sig}")}


def _url_query(params):
    """URL query: empty-value params are emitted as BARE flags (e.g. "?uploads"),
    matching the server's bare-flag detection; SigV4 still canonicalizes them as
    "uploads=" (see _canon_query), so the signature matches."""
    parts = []
    for k, v in sorted(params.items()):
        parts.append(quote(k, safe='-_.~') if v == ""
                     else f"{quote(k, safe='-_.~')}={quote(v, safe='-_.~')}")
    return "&".join(parts)


def s3(method, key, port, params=None, data=None, access_key="alice",
       extra_hdrs=None):
    """Issue a signed S3 request for /<bucket>/<key>(+query).  extra_hdrs (e.g.
    x-amz-copy-source) are added unsigned — this server signs only host;x-amz-date."""
    path = f"/{S3_BUCKET}/{key}"
    q = ("?" + _url_query(params)) if params else ""
    h = s3_sign(method, path, port, params, access_key)
    if extra_hdrs:
        h.update(extra_hdrs)
    return http(method, path + q, port, data=data, hdrs=h)


# ----- root:// native-client driver (the stream protocol, token-authenticated) --
def xrd_avail():
    return os.path.isfile(NATIVE_XRDFS) and os.path.isfile(NATIVE_XRDCP)


def _xrd_env(sub):
    env = dict(os.environ)
    env["BEARER_TOKEN"] = mint(_jwt_key, sub)
    env.pop("X509_USER_PROXY", None)      # don't let it pick up a host GSI proxy
    return env


def xrd_fs(args, sub, timeout=15):
    """Run native xrdfs as <sub> (bearer token) vs the impersonation stream server
    root://127.0.0.1:sport.  Returns (rc, stdout, stderr)."""
    cmd = [NATIVE_XRDFS, f"root://127.0.0.1:{_stream_port}"] + list(args)
    try:
        p = subprocess.run(cmd, env=_xrd_env(sub), capture_output=True,
                           timeout=timeout, text=True)
        return p.returncode, p.stdout, p.stderr
    except subprocess.TimeoutExpired:
        return -1, "", "timeout"


def xrd_cp_up(local, remote, sub, timeout=20):
    """xrdcp WRITE: local file -> root://...//remote, as <sub>."""
    url = f"root://127.0.0.1:{_stream_port}//{remote.lstrip('/')}"
    cmd = [NATIVE_XRDCP, "-f", local, url]
    try:
        p = subprocess.run(cmd, env=_xrd_env(sub), capture_output=True,
                           timeout=timeout, text=True)
        return p.returncode, p.stdout, p.stderr
    except subprocess.TimeoutExpired:
        return -1, "", "timeout"


def xrd_cp_down(remote, local, sub, timeout=20):
    """xrdcp READ: root://...//remote -> local file, as <sub>."""
    url = f"root://127.0.0.1:{_stream_port}//{remote.lstrip('/')}"
    cmd = [NATIVE_XRDCP, "-f", url, local]
    try:
        p = subprocess.run(cmd, env=_xrd_env(sub), capture_output=True,
                           timeout=timeout, text=True)
        return p.returncode, p.stdout, p.stderr
    except subprocess.TimeoutExpired:
        return -1, "", "timeout"


def xrd_cp_tpc(src_remote, dst_remote, sub, mode="first", timeout=25):
    """Native THIRD-PARTY COPY (xrdcp --tpc): server-orchestrated copy from
    root://...//src_remote to root://...//dst_remote on the SAME server (loopback
    TPC), driven as <sub>.  Returns (rc, out, err).  Both endpoints are the
    impersonation stream server, so the pulled/pushed file must end up owned by the
    mapped user and a cross-tenant source/dest must be denied."""
    s = f"root://127.0.0.1:{_stream_port}//{src_remote.lstrip('/')}"
    d = f"root://127.0.0.1:{_stream_port}//{dst_remote.lstrip('/')}"
    cmd = [NATIVE_XRDCP, "--tpc", mode, "-f", s, d]
    try:
        p = subprocess.run(cmd, env=_xrd_env(sub), capture_output=True,
                           timeout=timeout, text=True)
        return p.returncode, p.stdout, p.stderr
    except subprocess.TimeoutExpired:
        return -1, "", "timeout"


def raw_send_steps(steps, port, read_timeout=3.0):
    """Drive a single TCP connection through a SCRIPT of byte-chunks with optional
    pauses, then optionally abrupt-RST or half-close — for connection-state attacks
    (reset mid-request/body, slow/partial sends, abandon-after-auth).  steps is a
    list of (bytes, pause_seconds).  If reset=True is passed as the last element's
    flag the socket is hard-RST (SO_LINGER 0) instead of a graceful close.  Returns
    the bytes received (may be partial/empty)."""
    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.settimeout(read_timeout)
    buf = b""
    reset = False
    try:
        s.connect(("127.0.0.1", port))
        for item in steps:
            chunk, pause = item[0], item[1]
            if len(item) > 2 and item[2]:
                reset = True
            if chunk:
                s.sendall(chunk if isinstance(chunk, bytes) else chunk.encode())
            if pause:
                time.sleep(pause)
        try:
            while True:
                d = s.recv(65536)
                if not d:
                    break
                buf += d
                if len(buf) > 1 << 20:
                    break
        except (OSError, socket.timeout):
            pass
    except (OSError, socket.timeout):
        pass
    finally:
        try:
            if reset:
                import struct as _st
                s.setsockopt(socket.SOL_SOCKET, socket.SO_LINGER,
                             _st.pack("ii", 1, 0))   # hard RST on close
            s.close()
        except OSError:
            pass
    return buf


def xrd_fs_token(args, token_str, timeout=15):
    """Run native xrdfs against the stream server with an ARBITRARY bearer token
    string (for malformed/forged/expired-token attacks).  Returns (rc, out, err)."""
    cmd = [NATIVE_XRDFS, f"root://127.0.0.1:{_stream_port}"] + list(args)
    env = dict(os.environ)
    env["BEARER_TOKEN"] = token_str
    env.pop("X509_USER_PROXY", None)
    try:
        p = subprocess.run(cmd, env=env, capture_output=True,
                           timeout=timeout, text=True)
        return p.returncode, p.stdout, p.stderr
    except subprocess.TimeoutExpired:
        return -1, "", "timeout"


def _forged_tokens(key):
    """A spread of structurally-invalid / forged bearer tokens that MUST all be
    rejected: each is a (label, token_string) pair.  Built once per battery."""
    now = int(time.time())
    good = mint(key, "alice")
    # alg=none with an empty signature (classic JWT downgrade).
    none_hdr = _b64u(json.dumps({"alg": "none", "typ": "JWT", "kid": KID},
                                separators=(",", ":")).encode())
    none_pay = _b64u(json.dumps({"iss": ISSUER, "sub": "alice", "aud": AUDIENCE,
                                 "exp": now + 3600, "iat": now, "nbf": now,
                                 "scope": WRITE_SCOPE},
                                separators=(",", ":")).encode())
    # A token signed by a DIFFERENT EC key (valid structure, wrong issuer key).
    other_key = ec.generate_private_key(ec.SECP256R1())
    return [
        ("expired",        mint(key, "alice", exp=now - 120, iat=now - 240)),
        ("not-yet-valid",  mint(key, "alice", nbf=now + 99999)),
        ("wrong-issuer",   mint(key, "alice", iss="https://evil.example/")),
        ("wrong-audience", mint(key, "alice", aud="https://wrong.aud/")),
        ("tampered-sig",   good[:-3] + ("AAA" if good[-3:] != "AAA" else "BBB")),
        ("alg-none",       f"{none_hdr}.{none_pay}."),
        ("foreign-key",    mint(other_key, "alice")),
        ("garbage",        "not.a.jwt"),
        ("empty",          ""),
    ]


def wait_port(port, timeout=10.0):
    end = time.time() + timeout
    while time.time() < end:
        try:
            with socket.create_connection(("127.0.0.1", port), timeout=0.5):
                return True
        except OSError:
            time.sleep(0.1)
    return False



# ===== Round-7 batch helpers (workflow-authored) =====
def _s3_post_form(access_key, key, file_bytes, when=None, expires_min=60,
                  conditions=None, success_status="201", success_redirect=None,
                  content_type="text/plain", tamper_sig=False, omit_policy=False,
                  cred_override=None, filename="upload.bin", omit_file=False):
    """Build a browser S3 POST Object multipart/form-data body + Content-Type.

    Returns (content_type_header, body_bytes).  Mirrors the server's POST-policy
    auth (src/s3/post_object.c): the x-amz-signature is HMAC-SHA256(signing_key,
    base64_policy) hex-encoded, where signing_key is the AWS4 date/region-scoped
    key.  `tamper_sig` corrupts that signature; `omit_policy` drops the auth
    fields; `cred_override` forges the x-amz-credential access key; `when`
    backdates the policy (with expires_min<=0 for an already-expired policy);
    `omit_file` produces a form with no file part.  Bodies are tiny.
    """
    now = when or dt.datetime.now(dt.timezone.utc)
    amz_date = now.strftime("%Y%m%dT%H%M%SZ")
    date = now.strftime("%Y%m%d")
    cred = cred_override or f"{access_key}/{date}/{S3_REGION}/s3/aws4_request"
    exp = (now + dt.timedelta(minutes=expires_min)).strftime("%Y-%m-%dT%H:%M:%SZ")
    conds = [{"bucket": S3_BUCKET}, ["starts-with", "$key", ""]]
    conds.extend(conditions or [])
    policy = {"expiration": exp, "conditions": conds}
    policy_b64 = base64.b64encode(
        json.dumps(policy, separators=(",", ":")).encode()).decode()

    # AWS4 signing key (date, region, "s3", "aws4_request").
    k = hmac.new(("AWS4" + S3_SECRET).encode(), date.encode(), hashlib.sha256).digest()
    k = hmac.new(k, S3_REGION.encode(), hashlib.sha256).digest()
    k = hmac.new(k, b"s3", hashlib.sha256).digest()
    k = hmac.new(k, b"aws4_request", hashlib.sha256).digest()
    sig = hmac.new(k, policy_b64.encode(), hashlib.sha256).hexdigest()
    if tamper_sig:
        sig = ("0" * 64) if sig[0] != "0" else ("f" * 64)

    boundary = "----rtFormBoundary7XzQp"
    crlf = "\r\n"

    def field(name, value):
        return (f"--{boundary}{crlf}"
                f'Content-Disposition: form-data; name="{name}"{crlf}{crlf}'
                f"{value}{crlf}")

    parts = [field("key", key)]
    if not omit_policy:
        parts.append(field("x-amz-algorithm", "AWS4-HMAC-SHA256"))
        parts.append(field("x-amz-credential", cred))
        parts.append(field("x-amz-date", amz_date))
        parts.append(field("policy", policy_b64))
        parts.append(field("x-amz-signature", sig))
    if success_redirect is not None:
        parts.append(field("success_action_redirect", success_redirect))
    elif success_status is not None:
        parts.append(field("success_action_status", success_status))
    if not omit_file:
        parts.append(
            f"--{boundary}{crlf}"
            f'Content-Disposition: form-data; name="file"; filename="{filename}"{crlf}'
            f"Content-Type: {content_type}{crlf}{crlf}")
    head = "".join(parts).encode("latin-1")
    if omit_file:
        body = head + f"--{boundary}--{crlf}".encode("latin-1")
    else:
        body = head + file_bytes + f"{crlf}--{boundary}--{crlf}".encode("latin-1")
    return f"multipart/form-data; boundary={boundary}", body

DEAD_PREFIX = "user.nginx_xrootd.webdav."


def _dead_xattr_count(fp):
    """Count on-disk WebDAV dead-property xattrs on `fp` (the kernel ground truth,
    independent of any PROPFIND echo).  WebDAV PROPPATCH stores each dead property
    under the `user.nginx_xrootd.webdav.` xattr prefix (src/webdav/dead_props.c).
    Returns -1 if the path is unreadable."""
    try:
        names = os.listxattr(fp)
    except OSError:
        return -1
    return sum(1 for n in names if n.startswith(DEAD_PREFIX))


def _dead_xattr_has_value(fp, needle):
    """True iff any WebDAV dead-property xattr value on `fp` contains `needle`
    (bytes).  Used to assert a property was (or was NOT) actually persisted at the
    kernel layer rather than merely echoed in a PROPFIND response."""
    needle_b = needle if isinstance(needle, bytes) else needle.encode()
    try:
        names = os.listxattr(fp)
    except OSError:
        return False
    for n in names:
        if not n.startswith(DEAD_PREFIX):
            continue
        try:
            if needle_b in os.getxattr(fp, n):
                return True
        except OSError:
            continue
    return False

def _raw_get_validators(path, port, token=None, extra=None, read_timeout=4.0):
    """Authenticated raw GET that PARSES the response headers (the http() helper
    discards them) so a conditional-header batch can capture a file's REAL ETag
    and Last-Modified validators.  Returns (status_int, etag_or_None,
    lastmod_or_None, body_bytes); status 0 on a framing/conn failure.  `etag`
    keeps its surrounding quotes verbatim so it can be replayed in If-Match /
    If-None-Match exactly as the server emitted it."""
    lines = [f"GET {path} HTTP/1.1", "Host: 127.0.0.1", "Connection: close"]
    if token:
        lines.append(f"Authorization: Bearer {token}")
    for k, v in (extra or {}).items():
        lines.append(f"{k}: {v}")
    raw = ("\r\n".join(lines) + "\r\n\r\n").encode()
    resp = raw_http(raw, port, read_timeout=read_timeout)
    if not resp or b"\r\n" not in resp:
        return 0, None, None, b""
    head, _, body = resp.partition(b"\r\n\r\n")
    head_lines = head.split(b"\r\n")
    status = 0
    m = re.match(rb"HTTP/\d\.\d\s+(\d{3})", head_lines[0])
    if m:
        status = int(m.group(1))
    etag = lastmod = None
    for hl in head_lines[1:]:
        name, _, val = hl.partition(b":")
        n = name.strip().lower()
        v = val.strip()
        if n == b"etag" and etag is None:
            etag = v.decode("latin1")
        elif n == b"last-modified" and lastmod is None:
            lastmod = v.decode("latin1")
    return status, etag, lastmod, body

_KXR_PROTOCOL  = 3006
_KXR_LOGIN     = 3007
_KXR_STAT      = 3017
_KXR_BIND      = 3024
_KXR_READV     = 3025
_KXR_OK        = 0
_KXR_ERROR     = 4003
_KXR_HS_FOURTH = 4
_KXR_HS_FIFTH  = 2012        # ROOTD_PQ handshake magic word
_KXR_PROTOVER  = 0x00000520


def _kxr_recv_exact(sock, n):
    """Read exactly n bytes, or None if the peer closes/errs before n arrive."""
    buf = bytearray()
    while len(buf) < n:
        try:
            chunk = sock.recv(n - len(buf))
        except (OSError, socket.timeout):
            return None
        if not chunk:
            return None
        buf.extend(chunk)
    return bytes(buf)


def _kxr_read_response(sock):
    """Read one ServerResponseHeader (streamid[2] status[2] dlen[4]) + body.
    Returns (status:int|None, body:bytes); status None means the peer closed.

    kXR_status (4007, used by pgread/pgwrite) is a TWO-STAGE frame: the outer
    hdr.dlen (==24) covers only ServerResponseBody_Status+pgr, and for pgread an
    ADDITIONAL bdy.dlen bytes of page data (CRC32c+content) follow that the outer
    dlen does NOT count (XProtocol.hh: 'kXR_char data[dlen]' after the status
    body; matches XrdXrootdResponse srsComplete).  We MUST drain those trailing
    bytes here or the socket desyncs and every subsequent response is misread —
    e.g. an authed pgread of one's own file leaves ~38 undrained bytes, shifting
    the stream so a later kXR_open's status field lands on a stray 0x0000 and
    looks like a spurious kXR_ok.  The drained page data is THIS caller's OWN
    content, so this is purely stream re-synchronization, not a security signal."""
    hdr = _kxr_recv_exact(sock, 8)
    if hdr is None or len(hdr) < 8:
        return None, b""
    _sid, status, dlen = struct.unpack("!2sHI", hdr)
    if dlen <= 0 or dlen > (1 << 20):
        return status, b""
    body = _kxr_recv_exact(sock, dlen)
    body = body or b""
    # kXR_status: the inner ServerResponseBody_Status.dlen (page-data length) sits
    # at body offset 12..16 (crc32c[4] streamID[2] requestid[1] resptype[1]
    # reserved[4] dlen[4]); drain that many trailing bytes to keep the stream synced.
    if status == 4007 and len(body) >= 16:
        inner_dlen = struct.unpack("!I", body[12:16])[0]
        if 0 < inner_dlen <= (1 << 20):
            _kxr_recv_exact(sock, inner_dlen)
    return status, body


def _kxr_handshake_bytes(fourth=_KXR_HS_FOURTH, fifth=_KXR_HS_FIFTH):
    """The 20-byte ClientInitHandShake: five 32-bit big-endian words."""
    return struct.pack("!IIIII", 0, 0, 0, fourth, fifth)


def _kxr_protocol_bytes(streamid=b"\x00\x01"):
    """ClientProtocolRequest: streamid[2] requestid[2] clientpv[4] flags[1]
    expect[1] reserved[10] dlen[4]."""
    return struct.pack("!2sHIBB10sI", streamid, _KXR_PROTOCOL,
                       _KXR_PROTOVER, 0, 0, b"\x00" * 10, 0)


def _kxr_login_bytes(streamid=b"\x00\x02", username=b"alice"):
    """ClientLoginRequest: streamid[2] requestid[2] pid[4] username[8]
    ability2[1] ability[1] capver[1] reserved2[1] dlen[4]."""
    uname = (username + b"\x00" * 8)[:8]
    return struct.pack("!2sHI8sBBBBI", streamid, _KXR_LOGIN,
                       0x1234, uname, 0, 0, 5, 0, 0)


def _kxr_stat_bytes(path, streamid=b"\x00\x10", dlen=None):
    """ClientStatRequest header (24 bytes): streamid[2] requestid[2] options[1]
    reserved[7] wants[4] fhandle[4] dlen[4], followed by the path body.  dlen
    defaults to len(path); pass an explicit dlen to forge a length mismatch."""
    if dlen is None:
        dlen = len(path)
    hdr = struct.pack("!2sHB7sI4sI", streamid, _KXR_STAT, 0, b"\x00" * 7,
                      0, b"\x00" * 4, dlen & 0xFFFFFFFF)
    return hdr + path


def _kxr_connect(timeout=4.0):
    """Fresh TCP connection to the impersonation root:// port."""
    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.settimeout(timeout)
    s.connect(("127.0.0.1", _stream_port))
    return s


def _kxr_send_recv(sock, raw):
    """Send raw request bytes on an established socket; return (status, body) or
    (None, b'') if the connection was closed/reset.  A clean error or clean close
    is a PASS for an adversarial framing."""
    try:
        sock.sendall(raw)
    except (OSError, socket.timeout):
        return None, b""
    return _kxr_read_response(sock)


def _kxr_session(handshake=None, do_protocol=True, do_login=True):
    """Bring a raw connection up to (anonymous, UNAUTHENTICATED) login: handshake
    -> kXR_protocol -> kXR_login, but NO kXR_auth.  Returns (sock|None, hs_status,
    login_status).  The session is logged-in but unauthenticated, so file ops MUST
    be rejected with kXR_NotAuthorized — exactly the gate we want to probe."""
    hs_status = None
    try:
        s = _kxr_connect()
    except (OSError, socket.timeout):
        return None, None, None
    try:
        s.sendall(handshake if handshake is not None else _kxr_handshake_bytes())
        hs_status, _ = _kxr_read_response(s)
        if hs_status is None:
            s.close()
            return None, hs_status, None
        if do_protocol:
            s.sendall(_kxr_protocol_bytes())
            _kxr_read_response(s)
        login_status = None
        if do_login:
            s.sendall(_kxr_login_bytes())
            login_status, _ = _kxr_read_response(s)
        return s, hs_status, login_status
    except (OSError, socket.timeout):
        try:
            s.close()
        except OSError:
            pass
        return None, hs_status, None


def _kxr_oneshot(raw_after_handshake, handshake=None):
    """Connect, send a (possibly malformed) handshake, then immediately send raw
    bytes WITHOUT logging in (pre-login / pre-auth attack).  Returns
    (hs_status, status, body, closed_bool)."""
    try:
        s = _kxr_connect()
    except (OSError, socket.timeout):
        return None, None, b"", True
    try:
        s.sendall(handshake if handshake is not None else _kxr_handshake_bytes())
        hs_status, _ = _kxr_read_response(s)
        status, body = (None, b"")
        if raw_after_handshake:
            status, body = _kxr_send_recv(s, raw_after_handshake)
        return hs_status, status, body, (status is None)
    except (OSError, socket.timeout):
        return None, None, b"", True
    finally:
        try:
            s.close()
        except OSError:
            pass



# ===== Round-8 batch helpers (workflow-authored) =====
def _crc64nvme(data):
    """CRC-64/NVME (reflected poly 0x9A6C9329AC4BC9B5, init/xorout all-FF, refin/
    refout): the algorithm behind AWS S3 x-amz-checksum-crc64nvme and this module's
    src/compat/crc64.c.  Returns the 64-bit integer (verify: crc64nvme(b"123456789")
    == 0xAE8B14860A799888, the published check constant)."""
    poly = 0x9A6C9329AC4BC9B5
    crc = 0xFFFFFFFFFFFFFFFF
    for byte in data:
        crc ^= byte
        for _ in range(8):
            crc = (crc >> 1) ^ poly if (crc & 1) else (crc >> 1)
    return crc ^ 0xFFFFFFFFFFFFFFFF


def _crc64nvme_b64(data):
    """AWS wire form of CRC-64/NVME: base64 of the 8 big-endian CRC bytes (NOT hex —
    that is the root:///WebDAV digest form).  Matches s3_object_crc64nvme_b64()."""
    return base64.b64encode(struct.pack(">Q", _crc64nvme(data))).decode("ascii")


def _raw_get_header(method, path, port, hdrs):
    """Issue a raw HTTP request (so response HEADERS are visible — the http() helper
    returns only status+body) and return (status_int, {lower_header: value}, body).
    Used to read the Digest:/x-amz-checksum-* response headers that carry a content
    fingerprint.  status -1 / empty dict on a connection failure."""
    lines = ["%s %s HTTP/1.1" % (method, path), "Host: 127.0.0.1:%d" % port,
             "Connection: close"]
    for k, v in (hdrs or {}).items():
        lines.append("%s: %s" % (k, v))
    raw = ("\r\n".join(lines) + "\r\n\r\n").encode()
    resp = raw_http(raw, port)
    if not resp:
        return -1, {}, b""
    head, _, body = resp.partition(b"\r\n\r\n")
    try:
        text = head.decode("latin-1")
    except Exception:  # noqa: BLE001
        text = ""
    rows = text.split("\r\n")
    status = -1
    if rows and rows[0].startswith("HTTP/"):
        parts = rows[0].split()
        if len(parts) >= 2 and parts[1].isdigit():
            status = int(parts[1])
    hmap = {}
    for row in rows[1:]:
        if ":" in row:
            k, _, v = row.partition(":")
            hmap[k.strip().lower()] = v.strip()
    return status, hmap, body

# Additional kXR opcodes (the file already defines PROTOCOL/LOGIN/STAT/BIND/READV).
_KXR_AUTH      = 3000
_KXR_CLOSE     = 3003
_KXR_DIRLIST   = 3004
_KXR_OPEN      = 3010
_KXR_READ      = 3013
_KXR_STATX     = 3022
_KXR_PGWRITE   = 3026
_KXR_TRUNCATE  = 3028
_KXR_PGREAD    = 3030

_KXR_OPEN_READ = 0x0010      # kXR_open_read
_KXR_OPEN_UPDT = 0x0020      # kXR_open_updt (read/write)
_KXR_NEW       = 0x0008      # kXR_new
_KXR_MKPATH    = 0x0100      # kXR_mkpath

# kXR_pgPageSZ from XProtocol.hh: page size used to interleave per-page CRC32c.
_KXR_PG_PAGESZ = 4096

_CRC32C_TABLE = None


def _crc32c(data):
    """CRC-32C (Castagnoli, poly 0x1EDC6F41 reflected = 0x82F63B78) — the exact
    checksum the kXR_pgread/kXR_pgwrite wire path computes per 4096-byte page.
    Lazily builds the byte table so a degraded (no-auth) run never pays for it."""
    global _CRC32C_TABLE
    if _CRC32C_TABLE is None:
        tbl = []
        for n in range(256):
            c = n
            for _ in range(8):
                c = (c >> 1) ^ 0x82F63B78 if (c & 1) else (c >> 1)
            tbl.append(c)
        _CRC32C_TABLE = tbl
    crc = 0xFFFFFFFF
    for b in data:
        crc = (crc >> 8) ^ _CRC32C_TABLE[(crc ^ b) & 0xFF]
    return crc ^ 0xFFFFFFFF


def _kxr_auth_bytes(token, streamid=b"\x00\x03"):
    """ClientAuthRequest for the 'ztn' (XrdSecztn bearer JWT) sec-protocol:
    streamid[2] requestid[2] reserved[12] credtype[4]='ztn\\0' dlen[4], then a
    payload of 4 prefix bytes ('ztn\\0') + the raw token (the handler reads the
    token from payload+4).  This is the credential the login reply advertises via
    '&P=ztn'."""
    tok = token.encode() if isinstance(token, str) else token
    payload = b"ztn\x00" + tok
    hdr = struct.pack("!2sH12s4sI", streamid, _KXR_AUTH, b"\x00" * 12,
                      b"ztn\x00", len(payload))
    return hdr + payload


def _kxr_open_bytes(path, options=_KXR_OPEN_READ, mode=0, streamid=b"\x00\x20"):
    """ClientOpenRequest: streamid[2] requestid[2] mode[2] options[2] optiont[2]
    reserved[6] fhtemplt[4] dlen[4] + path body."""
    p = path if isinstance(path, bytes) else path.encode()
    hdr = struct.pack("!2sHHHH6s4sI", streamid, _KXR_OPEN, mode & 0xFFFF,
                      options & 0xFFFF, 0, b"\x00" * 6, b"\x00" * 4, len(p))
    return hdr + p


def _kxr_read_bytes(fhandle, offset, rlen, streamid=b"\x00\x21"):
    """ClientReadRequest: streamid[2] requestid[2] fhandle[4] offset[8] rlen[4]
    dlen[4] (no read-ahead args)."""
    fh = (fhandle + b"\x00" * 4)[:4]
    return struct.pack("!2sH4sqiI", streamid, _KXR_READ, fh,
                       offset, rlen, 0)


def _kxr_readv_bytes(segments, streamid=b"\x00\x22"):
    """ClientReadVRequest: streamid[2] requestid[2] reserved[15] pathid[1] dlen[4]
    followed by read_list elements {fhandle[4], rlen[int32], offset[int64]}.
    segments = list of (fhandle_bytes, rlen, offset)."""
    rl = b""
    for fh, rlen, off in segments:
        rl += struct.pack("!4siq", (fh + b"\x00" * 4)[:4], rlen, off)
    hdr = struct.pack("!2sH15sBI", streamid, _KXR_READV, b"\x00" * 15, 0, len(rl))
    return hdr + rl


def _kxr_pgread_bytes(fhandle, offset, rlen, streamid=b"\x00\x23"):
    """ClientPgReadRequest: streamid[2] requestid[2] fhandle[4] offset[8] rlen[4]
    dlen[4]=0 (no args)."""
    fh = (fhandle + b"\x00" * 4)[:4]
    return struct.pack("!2sH4sqiI", streamid, _KXR_PGREAD, fh, offset, rlen, 0)


def _kxr_pgwrite_bytes(fhandle, offset, data, crc=None, streamid=b"\x00\x24"):
    """ClientPgWriteRequest: streamid[2] requestid[2] fhandle[4] offset[8]
    pathid[1] reqflags[1] reserved[2] dlen[4] + payload.  Payload per page is
    [CRC32c(4 BE)][data], CRC first.  Pass crc=None for a VALID checksum, or an
    explicit (wrong) 32-bit int to forge a corrupted page."""
    d = data if isinstance(data, bytes) else data.encode()
    use_crc = _crc32c(d) if crc is None else (crc & 0xFFFFFFFF)
    payload = struct.pack("!I", use_crc) + d
    fh = (fhandle + b"\x00" * 4)[:4]
    hdr = struct.pack("!2sH4sqBB2sI", streamid, _KXR_PGWRITE, fh, offset,
                      0, 0, b"\x00" * 2, len(payload))
    return hdr + payload


def _kxr_statx_bytes(path, streamid=b"\x00\x25"):
    """kXR_statx shares the ClientStatRequest layout (options[1] reserved[7]
    wants[4] fhandle[4] dlen[4]) + path body."""
    p = path if isinstance(path, bytes) else path.encode()
    hdr = struct.pack("!2sHB7sI4sI", streamid, _KXR_STATX, 0, b"\x00" * 7,
                      0, b"\x00" * 4, len(p))
    return hdr + p


def _kxr_dirlist_bytes(path, streamid=b"\x00\x26"):
    """ClientDirlistRequest: streamid[2] requestid[2] reserved[15] options[1]
    dlen[4] + path body."""
    p = path if isinstance(path, bytes) else path.encode()
    hdr = struct.pack("!2sH15sBI", streamid, _KXR_DIRLIST, b"\x00" * 15, 0, len(p))
    return hdr + p


def _kxr_truncate_bytes(fhandle, offset, streamid=b"\x00\x27"):
    """ClientTruncateRequest: streamid[2] requestid[2] fhandle[4] offset[8]
    reserved[4] dlen[4]=0 (handle-based truncate)."""
    fh = (fhandle + b"\x00" * 4)[:4]
    return struct.pack("!2sH4sq4sI", streamid, _KXR_TRUNCATE, fh, offset,
                       b"\x00" * 4, 0)


def _kxr_close_bytes(fhandle, streamid=b"\x00\x28"):
    """ClientCloseRequest: streamid[2] requestid[2] fhandle[4] reserved[12]
    dlen[4]."""
    fh = (fhandle + b"\x00" * 4)[:4]
    return struct.pack("!2sH4s12sI", streamid, _KXR_CLOSE, fh, b"\x00" * 12, 0)


def _kxr_authed_session(token, timeout=4.0):
    """Bring a raw connection all the way up to an AUTHENTICATED ztn session:
    handshake -> kXR_protocol -> kXR_login -> kXR_auth(ztn, token).  Returns
    (sock, ok_bool): ok_bool is True only when kXR_auth returned kXR_ok, meaning
    the impersonation identity for this connection is now the token's subject.
    Returns (None, False) if any stage fails (so the caller degrades honestly)."""
    try:
        s = _kxr_connect(timeout)
    except (OSError, socket.timeout):
        return None, False
    try:
        s.sendall(_kxr_handshake_bytes())
        hs, _ = _kxr_read_response(s)
        if hs != _KXR_OK:
            s.close()
            return None, False
        s.sendall(_kxr_protocol_bytes())
        _kxr_read_response(s)
        s.sendall(_kxr_login_bytes())
        lg, _ = _kxr_read_response(s)
        if lg != _KXR_OK:
            s.close()
            return None, False
        st, _b = _kxr_send_recv(s, _kxr_auth_bytes(token))
        if st != _KXR_OK:
            try:
                s.close()
            except OSError:
                pass
            return None, False
        return s, True
    except (OSError, socket.timeout):
        try:
            s.close()
        except OSError:
            pass
        return None, False


def _kxr_open_fhandle(sock, path, options=_KXR_OPEN_READ, mode=0,
                      streamid=b"\x00\x20"):
    """Send kXR_open on an authed socket; return (status, fhandle_bytes|None).
    On kXR_ok the 4-byte fhandle is the first 4 bytes of ServerResponseBody_Open
    (the open-slot index in byte 0)."""
    st, body = _kxr_send_recv(sock, _kxr_open_bytes(path, options, mode, streamid))
    if st == _KXR_OK and body is not None and len(body) >= 4:
        return st, body[:4]
    return st, None



# ===== Round-9 batch helpers (workflow-authored) =====
def _s3_raw(method, key, port, params=None, access_key="alice", extra_hdrs=None,
            read_timeout=4.0):
    """SigV4 header-auth S3 request sent RAW so the FULL response header block is
    visible (the s3()/http() helpers discard headers).  Returns
    (status_int, headers_dict_lowercased, body_bytes, raw_head_bytes); status 0 on a
    framing/conn failure.  `params` (signed query, e.g. response-* overrides) is
    canonicalized identically to the signer so the signature validates; conditional
    headers go in `extra_hdrs` (unsigned -- the server signs only host;x-amz-date)."""
    path = f"/{S3_BUCKET}/{key}"
    cq = _canon_query(params or {})
    full = path + (("?" + cq) if cq else "")
    h = s3_sign(method, path, port, params, access_key)
    if extra_hdrs:
        h.update(extra_hdrs)
    lines = [f"{method} {full} HTTP/1.1", f"Host: 127.0.0.1:{port}", "Connection: close"]
    for k, v in h.items():
        lines.append(f"{k}: {v}")
    raw = ("\r\n".join(lines) + "\r\n\r\n").encode()
    resp = raw_http(raw, port, read_timeout=read_timeout)
    if not resp or b"\r\n" not in resp:
        return 0, {}, b"", b""
    head, _, body = resp.partition(b"\r\n\r\n")
    head_lines = head.split(b"\r\n")
    status = 0
    m = re.match(rb"HTTP/\d\.\d\s+(\d{3})", head_lines[0])
    if m:
        status = int(m.group(1))
    hdrs = {}
    for hl in head_lines[1:]:
        name, _, val = hl.partition(b":")
        n = name.strip().lower().decode("latin1")
        if n and n not in hdrs:
            hdrs[n] = val.strip().decode("latin1")
    return status, hdrs, body, head

_KXR_QUERY    = 3001          # kXR_query opcode (ClientQueryRequest)
_KXR_QSTATS   = 1             # XQueryType: kXR_QStats
_KXR_QCKSUM   = 3             # kXR_Qcksum
_KXR_QXATTR   = 4             # kXR_Qxattr
_KXR_QSPACE   = 5             # kXR_Qspace
_KXR_QCONFIG  = 7             # kXR_Qconfig
_KXR_QOPAQUF  = 32            # kXR_Qopaquf


def _kxr_query_bytes(infotype, args, streamid=b"\x00\x60"):
    """ClientQueryRequest (24-byte header) + arg body, matching XProtocol.hh:
    streamid[2] requestid[2](=kXR_query 3001) infotype[2] reserved1[2] fhandle[4]
    reserved2[8] dlen[4], then `args` as the dlen body.  The native client
    (client/lib/ops_fs.c xrdc_query) frames it identically: Qcksum args are the
    space-separated '<algo> <path>' string, Qxattr/Qopaquf args are the path,
    Qconfig args are the capability key(s); global subcodes (Qspace/QStats) take a
    bare/'/' arg.  dlen is computed from the supplied body so the frame is
    self-consistent (use the raw struct.pack form directly to forge a length
    mismatch)."""
    a = args if isinstance(args, bytes) else args.encode()
    hdr = struct.pack("!2sHH2s4s8sI", streamid, _KXR_QUERY,
                      infotype & 0xFFFF, b"\x00" * 2, b"\x00" * 4,
                      b"\x00" * 8, len(a))
    return hdr + a


def main():
    if not os.path.isfile(NGINX):
        print(f"SKIP: nginx binary not at {NGINX}")
        return 0

    data = os.path.join(WORK, "export")
    logs = os.path.join(WORK, "logs")
    tmp = os.path.join(WORK, "tmp")
    run = os.path.join(WORK, "run")
    cadir = os.path.join(WORK, "cadir")
    for d in (logs, tmp, run, cadir):
        os.makedirs(d, exist_ok=True)
        os.chmod(d, 0o777)            # writable by the svc-uid worker

    # Export tree (created as in-ns root so we can chown to mapped users).  The
    # export ROOT is owned by the service (svc) account — as in a real storage
    # deployment, the worker user owns the export and writes housekeeping files
    # (checkpoint/FRM); per-user subdirs are owned by the mapped users.
    chown_dir(data, UID_SVC, UID_SVC, 0o755)
    chown_dir(os.path.join(data, "alice"), UID_ALICE, UID_ALICE, 0o755)
    chown_dir(os.path.join(data, "bob"), UID_BOB, UID_BOB, 0o755)
    chown_dir(os.path.join(data, "bobsecret"), UID_BOB, UID_BOB, 0o700)
    chown_dir(os.path.join(data, "pub"), UID_SVC, UID_SVC, 0o777)
    # A dir the WORKER (svc) can read but the mapped user (alice) cannot (0750,
    # svc-owned, alice is neither owner nor in group svc).  Used to probe whether
    # directory LISTING leaks contents the user has no UNIX permission to read.
    so = os.path.join(data, "svconly")
    chown_dir(so, UID_SVC, UID_SVC, 0o750)
    with open(os.path.join(so, "secret-name.txt"), "w") as fh:
        fh.write("svc-only-secret\n")
    os.chown(os.path.join(so, "secret-name.txt"), UID_SVC, UID_SVC)
    # a file inside bob's secret dir, for the DAC-read test
    sp = os.path.join(data, "bobsecret", "s.txt")
    with open(sp, "w") as fh:
        fh.write("bob-only\n")
    os.chown(sp, UID_BOB, UID_BOB)
    os.chmod(sp, 0o600)

    # Cross-tenant fixtures inside bob's 0755 dir (alice can TRAVERSE + list the
    # dir, so the deny/allow below is decided purely by the FILE's mode):
    #   bob/private.txt  0600  -> alice (other) CANNOT read the contents (deny)
    #   bob/readable.txt 0644  -> alice CAN read it (control: proves the deny is
    #                             real per-file DAC, not a blanket cross-prefix block)
    bpriv = os.path.join(data, "bob", "private.txt")
    with open(bpriv, "w") as fh:
        fh.write("BOB-PRIVATE-SECRET\n")
    os.chown(bpriv, UID_BOB, UID_BOB)
    os.chmod(bpriv, 0o600)
    bread = os.path.join(data, "bob", "readable.txt")
    with open(bread, "w") as fh:
        fh.write("bob-world-readable\n")
    os.chown(bread, UID_BOB, UID_BOB)
    os.chmod(bread, 0o644)
    # the svc-uid worker must be able to traverse to the export root.
    ensure_traversable(data)
    # a symlink escape attempt target
    try:
        os.symlink("/etc", os.path.join(data, "escape"))
    except FileExistsError:
        pass

    # ---- GROUP / POSIX-DAC fixtures (exercise the broker's setfsgid+setgroups) --
    # staff = {alice, carol}; research = {bob, dave}; shared = {alice, bob, carol}.
    # A file's group-permission bits are enforced by the broker applying the mapped
    # user's supplementary groups — the core impersonation mechanism never before
    # exercised end-to-end through the protocols.  Each marker is unique so a
    # must-not-leak assertion can scan for it.
    def mk(rel, content, uid, gid, mode):
        p = os.path.join(data, rel)
        try:
            os.makedirs(os.path.dirname(p), exist_ok=True)
            with open(p, "w") as fh:
                fh.write(content)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
        except OSError:
            pass

    def mkdir_g(rel, uid, gid, mode):
        p = os.path.join(data, rel)
        try:
            os.makedirs(p, exist_ok=True)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
        except OSError:
            pass

    # group-readable / group-writable files owned alice:staff (carol is in staff,
    # bob is NOT) — the canonical group-DAC read/write cases.
    mk("grp/staff_r.txt",  "STAFF-GROUP-READABLE\n", UID_ALICE, GID_STAFF, 0o640)
    mk("grp/staff_w.txt",  "STAFF-GROUP-WRITABLE\n", UID_ALICE, GID_STAFF, 0o660)
    mk("grp/staff_none.txt", "STAFF-OWNER-ONLY\n",   UID_ALICE, GID_STAFF, 0o600)
    mk("grp/world_r.txt",  "WORLD-READABLE\n",       UID_ALICE, GID_STAFF, 0o644)
    # research group file owned bob:research (dave in research; alice/carol NOT).
    mk("grp/research_r.txt", "RESEARCH-GROUP-READABLE\n", UID_BOB, GID_RESEARCH, 0o640)
    # shared (alice,bob,carol) group-writable file owned alice:shared.
    mk("grp/shared_w.txt", "SHARED-GROUP-WRITABLE\n", UID_ALICE, GID_SHARED, 0o660)
    # a full permission-matrix subject owned alice:staff (mode set per-test).
    mk("grp/matrix.txt", "MATRIX-SECRET-BODY\n", UID_ALICE, GID_STAFF, 0o600)
    mkdir_g("grp", UID_SVC, UID_SVC, 0o755)
    os.chown(os.path.join(data, "grp"), UID_SVC, UID_SVC)  # parent traversable

    # group-accessible DIRECTORIES: 0770 staff dir (alice,carol enter; bob can't),
    # a setgid 2770 dir (new files inherit the staff group), a 0710 group-exec-only
    # dir (members traverse to a known child but cannot list).
    mkdir_g("staffdir", UID_ALICE, GID_STAFF, 0o770)
    mk("staffdir/inside.txt", "INSIDE-STAFF-DIR\n", UID_ALICE, GID_STAFF, 0o640)
    mkdir_g("sgiddir", UID_ALICE, GID_STAFF, 0o2770)          # setgid
    mkdir_g("execonly", UID_ALICE, GID_STAFF, 0o710)          # group --x, no read
    mk("execonly/known.txt", "EXECONLY-KNOWN\n", UID_ALICE, GID_STAFF, 0o640)
    mkdir_g("shareddir", UID_ALICE, GID_SHARED, 0o770)        # alice,bob,carol
    # a sticky world-writable dir (1777, like /tmp): anyone creates, only the file
    # owner (or dir owner) may delete — the classic sticky-bit protection.
    mkdir_g("stickytmp", UID_SVC, UID_SVC, 0o1777)
    mk("stickytmp/alice_owned.txt", "STICKY-ALICE-FILE\n", UID_ALICE, UID_ALICE, 0o644)

    # ES256 signing key + JWKS.
    key = ec.generate_private_key(ec.SECP256R1())
    nums = key.public_key().public_numbers()
    jwks = {"keys": [{"kty": "EC", "crv": "P-256", "kid": KID, "use": "sig",
                      "alg": "ES256", "x": _b64u(nums.x.to_bytes(32, "big")),
                      "y": _b64u(nums.y.to_bytes(32, "big"))}]}
    jwks_path = os.path.join(WORK, "jwks.json")
    with open(jwks_path, "w") as fh:
        json.dump(jwks, fh)

    sock = os.path.join(run, "impersonate.sock")
    sport, hport, s3port = free_port(), free_port(), free_port()
    global _jwt_key, _stream_port
    _jwt_key, _stream_port = key, sport          # so the root:// helpers can mint tokens

    conf = f"""
user svc;
worker_processes 1;
daemon off;
master_process on;
error_log {logs}/error.log info;
pid {logs}/nginx.pid;
thread_pool default threads=4 max_queue=4096;
events {{ worker_connections 128; }}

stream {{
    xrootd_impersonation        map;
    xrootd_impersonation_socket {sock};
    xrootd_impersonation_export {data};
    xrootd_idmap_min_uid        1000;
    xrootd_idmap_forbidden_groups "docker,sudo,wheel";
    server {{
        listen 127.0.0.1:{sport};
        xrootd on;
        xrootd_storage_backend posix:{data};
        xrootd_allow_write on;
        xrootd_auth token;
        xrootd_token_jwks     {jwks_path};
        xrootd_token_issuer   "{ISSUER}";
        xrootd_token_audience "{AUDIENCE}";
    }}
}}

http {{
    access_log off;
    client_body_temp_path {tmp};
    proxy_temp_path        {tmp};
    fastcgi_temp_path      {tmp};
    uwsgi_temp_path        {tmp};
    scgi_temp_path         {tmp};
    client_max_body_size   64m;
    server {{
        listen 127.0.0.1:{hport};
        location / {{
            xrootd_webdav         on;
            xrootd_webdav_storage_backend    posix:{data};
            xrootd_webdav_auth    required;
            xrootd_webdav_cadir   {cadir};
            xrootd_webdav_allow_write on;
            xrootd_webdav_token_jwks     {jwks_path};
            xrootd_webdav_token_issuer   "{ISSUER}";
            xrootd_webdav_token_audience "{AUDIENCE}";
        }}
    }}
    server {{
        listen 127.0.0.1:{s3port};
        location / {{
            xrootd_s3             on;
            xrootd_s3_storage_backend        posix:{data};
            xrootd_s3_bucket      {S3_BUCKET};
            xrootd_s3_access_key  alice;
            xrootd_s3_secret_key  {S3_SECRET};
            xrootd_s3_region      {S3_REGION};
            xrootd_s3_allow_write on;
        }}
    }}
}}
"""
    confp = os.path.join(WORK, "nginx.conf")
    with open(confp, "w") as fh:
        fh.write(conf)

    proc = subprocess.Popen([NGINX, "-p", WORK, "-c", confp],
                            stdout=subprocess.PIPE, stderr=subprocess.PIPE)
    if not wait_port(hport, 12):
        time.sleep(0.5)
        proc.terminate()
        err = b""
        try:
            err = proc.stderr.read() if proc.stderr else b""
        except Exception:  # noqa: BLE001
            pass
        elog = ""
        try:
            with open(os.path.join(logs, "error.log")) as fh:
                elog = fh.read()[-2000:]
        except OSError:
            pass
        print("SKIP: nginx (map mode) did not start in the namespace\n"
              + err.decode(errors="replace") + "\n" + elog)
        subprocess.run(["chown", "-R", "0:0", WORK], timeout=30)
        return 0

    # Confirm the real broker spawned (it is double-forked by the master's
    # init_module).  If it is missing, dump the error log to aid triage.
    time.sleep(0.5)
    broker_ok = False
    try:
        with open(sock + ".pid") as fh:
            bpid = int(fh.read().strip())
        broker_ok = os.path.exists(f"/proc/{bpid}")
    except (OSError, ValueError):
        bpid = None
    print(f"broker pid={bpid} alive={broker_ok}", flush=True)
    ok(broker_ok, "real broker spawned by the nginx master (init_module)")
    if not broker_ok:
        try:
            with open(os.path.join(logs, "error.log")) as fh:
                print("error.log tail:\n" + fh.read()[-2000:], flush=True)
        except OSError:
            pass

    try:
        try:
            run_battery(key, data, hport, s3port, sock)
        except Exception as e:  # noqa: BLE001
            import traceback
            traceback.print_exc()
            ok(False, f"battery raised an exception: {e!r}")
    finally:
        proc.terminate()
        try:
            proc.wait(timeout=5)
        except subprocess.TimeoutExpired:
            proc.kill()
        # kill the double-forked broker (reparented, survives nginx).
        try:
            with open(sock + ".pid") as fh:
                bpid = int(fh.read().strip())
            os.kill(bpid, 9)
        except (OSError, ValueError):
            pass

    # Cleanup: files created inside the ns are owned by mapped subuids (alice/bob
    # /svc -> 101000+ on the host) which the unprivileged invoker cannot remove.
    # As in-ns root, chown the whole work tree back to inside-0 (== the real
    # invoking user) so the pytest tmp_path teardown can delete it.
    try:
        subprocess.run(["chown", "-R", "0:0", WORK], timeout=30)
    except Exception:  # noqa: BLE001
        pass

    print(f"\n{_pass} passed, {_fail} failed", flush=True)
    if _fail == 0:
        print("ALL PASSED")
        return 0
    print("FAILED")
    return 1


def _reset_fixtures(data):
    """Re-establish the canonical mode/owner/content of the SHARED global fixtures.
    Many batches legitimately mutate a shared fixture (e.g. bob re-PUTs his own
    private.txt — a staged write that lands 0644, resetting the 0600 mode a LATER
    batch assumes), so without this a deny-test in batch N+1 sees the changed state
    and false-fails (the DAC itself is correct — it just sees a now-0644 file).
    Called between deep batches so each starts from a known namespace.  Pure os
    (in-ns root); never touched by the server."""
    def fx(rel, content, uid, gid, mode):
        p = os.path.join(data, rel)
        try:
            if content is not None:
                with open(p, "wb") as fh:
                    fh.write(content)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
        except OSError:
            pass

    def fxd(rel, uid, gid, mode):
        p = os.path.join(data, rel)
        try:
            os.makedirs(p, exist_ok=True)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
        except OSError:
            pass

    fx("bob/private.txt", b"BOB-PRIVATE-SECRET\n", UID_BOB, UID_BOB, 0o600)
    fx("bob/readable.txt", b"bob-world-readable\n", UID_BOB, UID_BOB, 0o644)
    fxd("bobsecret", UID_BOB, UID_BOB, 0o700)
    fx("bobsecret/s.txt", b"bob-only\n", UID_BOB, UID_BOB, 0o600)
    fxd("svconly", UID_SVC, UID_SVC, 0o750)
    fx("svconly/secret-name.txt", b"svc-only-secret\n", UID_SVC, UID_SVC, 0o640)
    fx("grp/staff_r.txt", b"STAFF-GROUP-READABLE\n", UID_ALICE, GID_STAFF, 0o640)
    fx("grp/staff_w.txt", b"STAFF-GROUP-WRITABLE\n", UID_ALICE, GID_STAFF, 0o660)
    fx("grp/staff_none.txt", b"STAFF-OWNER-ONLY\n", UID_ALICE, GID_STAFF, 0o600)
    fx("grp/world_r.txt", b"WORLD-READABLE\n", UID_ALICE, GID_STAFF, 0o644)
    fx("grp/research_r.txt", b"RESEARCH-GROUP-READABLE\n", UID_BOB, GID_RESEARCH, 0o640)
    fx("grp/matrix.txt", b"MATRIX-SECRET-BODY\n", UID_ALICE, GID_STAFF, 0o600)
    fxd("staffdir", UID_ALICE, GID_STAFF, 0o770)
    fxd("sgiddir", UID_ALICE, GID_STAFF, 0o2770)
    fxd("execonly", UID_ALICE, GID_STAFF, 0o710)
    fxd("shareddir", UID_ALICE, GID_SHARED, 0o770)
    fxd("stickytmp", UID_SVC, UID_SVC, 0o1777)


def run_battery(key, data, port, s3port, sock):
    tok_alice = mint(key, "alice")
    tok_bob = mint(key, "bob")

    # (1) BASELINE — the whole real chain: alice PUT -> 201, owned alice:alice
    #     (NOT the svc worker uid, NOT root).  This single check exercises
    #     lifecycle spawn + worker connect + auth + dispatch hook + put body
    #     bracket + broker + idmap + setfsuid.
    st, _ = http("PUT", "/alice/hello.txt", port, tok_alice, b"hi from alice\n")
    ok(st in (200, 201, 204), f"alice PUT accepted (HTTP {st})")
    p = os.path.join(data, "alice", "hello.txt")
    owned = os.path.exists(p) and os.stat(p).st_uid == UID_ALICE \
        and os.stat(p).st_gid == UID_ALICE
    ok(owned, "alice's file owned by the MAPPED user (1001:1001), not worker/root")

    # (2) bob PUT -> owned bob.
    st, _ = http("PUT", "/bob/b.txt", port, tok_bob, b"bob\n")
    bp = os.path.join(data, "bob", "b.txt")
    ok(st in (200, 201, 204) and os.path.exists(bp)
       and os.stat(bp).st_uid == UID_BOB,
       "bob's file owned by bob (1002)")

    # (3) alice reads her own file.
    st, body = http("GET", "/alice/hello.txt", port, tok_alice)
    ok(st == 200 and body == b"hi from alice\n", "alice GET own file")

    # (4) DAC: alice cannot read bob's 0700-dir file.
    st, _ = http("GET", "/bobsecret/s.txt", port, tok_alice)
    ok(st in (403, 404, 401), f"alice DENIED reading bob's 0700 file (HTTP {st})")

    # (5-9) ESCALATION / FORBIDDEN identities — each holds a VALID write-scoped
    #       token, so authz passes; impersonation MUST still refuse them.
    def escalation_denied(sub, label, group_member=False):
        extra = {}
        tok = mint(key, sub)
        path = f"/pub/{sub}_evil.txt"          # world-writable dir, so only the
        st, _ = http("PUT", path, port, tok, b"escalate\n")   # guard can stop it
        fp = os.path.join(data, "pub", f"{sub}_evil.txt")
        created = os.path.exists(fp)
        bad_owner = created and os.stat(fp).st_uid < 1000
        ok(st not in (200, 201, 204) and not created and not bad_owner,
           f"{label} -> DENIED (HTTP {st}, file_created={created})")

    escalation_denied("root", "escalate to root (uid 0)")
    escalation_denied("sys100", "escalate to sys uid 100 (< floor)")
    escalation_denied("svc", "impersonate the worker/service account (uid 1500)")
    escalation_denied("dockerite", "member of forbidden 'docker' group (gid 1600)")
    escalation_denied("mallory", "unmapped principal")

    # (10) confinement: a symlink inside the export pointing at /etc must not let
    #      a GET escape the root.
    st, body = http("GET", "/escape/passwd", port, tok_alice)
    leaked = (st == 200 and b"root:x:0:0" in body)
    ok(not leaked, f"symlink escape /escape/passwd blocked (HTTP {st})")

    # (11) confined-write traversal: must not create a file outside the export.
    sentinel = os.path.join(os.path.dirname(data), "OUTSIDE")
    http("PUT", "/../OUTSIDE", port, tok_alice, b"x\n")
    http("PUT", "/%2e%2e/OUTSIDE", port, tok_alice, b"x\n")
    ok(not os.path.exists(sentinel),
       "path-traversal PUT did not escape the export root")

    # (11b) WebDAV NAMESPACE ops as the mapped user (MKCOL/MOVE/COPY/DELETE).
    run_namespace_ops(key, data, port)

    # (11c) directory-LISTING confidentiality — does PROPFIND leak a dir the user
    #       has no UNIX permission to read?
    run_dirlist_confidentiality(key, data, port)

    # (11d) LOCK + PROPPATCH persist xattrs on the resource — broker XATTR op.
    run_lock_proppatch(key, data, port)

    # (11e) S3 (SigV4) under impersonation — objects owned by the mapped user.
    s3_up = wait_port(s3port, 5)
    if s3_up:
        run_s3(data, s3port)
    else:
        ok(False, "S3 server did not come up on its port")

    if s3_up:
        # (11e1) S3 SigV4 auth-error gating + S3 ops/multipart not yet covered.
        run_s3_sigv4_errors(key, data, s3port)
        run_s3_extended(key, data, s3port)

    # (11e2) root:// native STREAM protocol (xrdfs/xrdcp + token) under impersonation.
    run_root_battery(key, data)

    # (11f) cross-tenant CONFIDENTIALITY — alice must not READ bob's private data
    #       via any protocol (WebDAV GET/HEAD, S3 GET/HEAD); but MAY read a file
    #       bob made world-readable (control proving the deny is real per-file DAC).
    run_cross_tenant_read(key, data, port, s3port if s3_up else 0)

    # (11g) cross-tenant INTEGRITY — alice must not WRITE/DELETE/MUTATE bob's data
    #       via any protocol (WebDAV PUT/DELETE/MOVE/COPY/PROPPATCH/LOCK; S3
    #       PUT/DELETE/CopyObject/DeleteObjects/POST).  Every async-body handler.
    run_cross_tenant_write(key, data, port, s3port if s3_up else 0)

    # (11h) every CREATE path lands owned by the mapped user — exercises the
    #       remaining async-body S3 handlers (POST form-object, CopyObject) and the
    #       WebDAV LOCK-creates-a-zero-byte-resource path.
    run_create_ownership(key, data, port, s3port if s3_up else 0)

    # (11i) recursive PROPFIND (Depth: infinity) must not leak a private subtree.
    run_recursive_propfind(key, data, port)

    # (11j) confinement — traversal / escape via S3 keys and COPY/MOVE Destination.
    run_confinement_extended(key, data, port, s3port if s3_up else 0)

    # (11k) token -> UNIX principal mapping attacks (empty/long/traversal/reserved).
    run_token_principal_attacks(key, data, port)

    # (11l) exhaustive WebDAV method coverage (HEAD/OPTIONS/UNLOCK/COPY-coll/Overwrite).
    run_webdav_methods(key, data, port)

    # (11m) WebDAV protocol/header/error modes (conditional/Range/keep-alive/malformed).
    run_webdav_errors(key, data, port)

    # (11n) cross-PROTOCOL identity boundaries + erroring connections (FIFO/dangling).
    run_cross_cutting(key, data, port, s3port if s3_up else 0)

    # (11o) forged/invalid bearer tokens rejected across WebDAV + root://.
    run_auth_matrix(key, data, port)

    # (11p) per-subcommand root:// (stream) self vs cross-tenant matrix.
    run_root_deep(key, data, port)

    # (11q) deep S3: CopyObject/UploadPartCopy/DeleteObjects/Range/list confinement.
    if s3_up:
        run_s3_deep(key, data, s3port)

    # (11r) path-traversal / encoding / NUL across every protocol.
    run_traversal_matrix(key, data, port, s3port if s3_up else 0)

    # (11s+) DEEP workflow-designed batches — each ISOLATED so one broken/raising
    #        batch records a failure + traceback but never aborts the rest of the
    #        suite.  These push the suite from ~224 to ~700 checks.
    import traceback as _tb

    def _guard(fn, *a):
        _reset_fixtures(data)   # restore canonical shared-fixture state before each batch
        try:
            fn(*a)
        except Exception as e:  # noqa: BLE001
            _tb.print_exc()
            ok(False, f"{fn.__name__} raised an exception: {e!r}")

    _s3p = s3port if s3_up else 0
    for _fn in (run_root_protocol_depth, run_webdav_method_state,
                run_s3_multipart_adversarial, run_concurrency_state_race,
                run_broker_resource_limits, run_confine_encoding_exhaustive,
                run_crossproto_ownership_invariant, run_malformed_hostile_inputs,
                run_auth_scheme_confusion,
                run_http_protocol_abuse, run_s3_presigned,
                run_crossproto_chmod_chains, run_samefile_contention,
                run_group_read_dac, run_group_write_dac, run_permission_matrix,
                run_group_dir_dac, run_setgid_inheritance, run_sticky_bit_dac, run_mixed_owner_trees, run_multiuser_party, run_chown_chgrp_dac, run_manygroups_dac, run_boundary_mapping, run_group_concurrency, run_group_xattr_lock, run_group_traversal_depth,
                run_stream_extended_ops, run_native_tpc, run_dataplane_integrity, run_connection_errors, run_protocol_features_s3, run_protocol_features_webdav,
                run_combo_setgid_via_copymove, run_combo_symlink_crossproto_toctou, run_combo_multipart_lock_identity, run_combo_authfail_resource_state, run_combo_broker_pressure, run_combo_encoding_group_targets, run_combo_concurrent_crossproto, run_combo_xattr_namespace_group, run_combo_idmap_edge_full_matrix, run_combo_rare_opcodes, run_combo_connection_state_identity, run_combo_error_rollback,
                run_s3_subresource_fallthrough, run_s3_post_form_and_bucketops, run_webdav_undispatched_methods, run_webdav_property_exotic, run_http_smuggling_desync_deep, run_conditional_header_matrix, run_content_negotiation_ranges, run_frm_prepare_stage, run_broker_internals_stress, run_resource_dos_limits, run_raw_kxr_wire, run_header_injection_matrix, run_tpc_pull_push_matrix, run_multistep_lifecycle_invariants,
                run_http_tpc_webdav, run_checksum_digest_oracle, run_raw_kxr_deep, run_query_subcode_oracle, run_scoped_token_dac_matrix, run_special_file_rename_matrix, run_broker_dos_resilience, run_deep_novel_combos_r8,
                run_s3_conditional_impersonation, run_s3_checksum_verify_impersonation, run_s3_acl_tagging_dac, run_compression_impersonation, run_raw_kxr_authed, run_phase_features_combos):
        _guard(_fn, key, data, port, _s3p)

    # (12) CONCURRENCY: interleave alice/bob PUTs; every file must end up owned by
    #      the correct uid (no setfsuid credential leak across the real worker).
    N = 24
    results = {}

    def worker(i):
        sub = "alice" if i % 2 == 0 else "bob"
        tok = tok_alice if sub == "alice" else tok_bob
        sub_dir = "alice" if sub == "alice" else "bob"
        rel = f"/{sub_dir}/c_{sub}_{i}.txt"
        http("PUT", rel, port, tok, f"{sub}{i}\n".encode())
        results[i] = (sub_dir, f"c_{sub}_{i}.txt",
                      UID_ALICE if sub == "alice" else UID_BOB)

    threads = [threading.Thread(target=worker, args=(i,)) for i in range(N)]
    for t in threads:
        t.start()
    for t in threads:
        t.join()
    leak = 0
    for i in range(N):
        sub_dir, name, want = results[i]
        fp = os.path.join(data, sub_dir, name)
        if not (os.path.exists(fp) and os.stat(fp).st_uid == want):
            leak += 1
    ok(leak == 0,
       f"interleaved alice/bob ({N} concurrent PUTs): every file correct owner "
       f"(no setfsuid leak); mismatches={leak}")

    # (12b) MIXED-OP concurrency: interleave DIFFERENT op types AND cross-tenant
    #       attacks across alice/bob — stresses the per-worker principal global for
    #       any race window where a leaked principal lets an op run as the wrong
    #       identity (every legit op correct-owner; every cross-tenant op denied).
    run_mixed_concurrency(key, data, port, s3port if s3_up else 0)

    # (13) confused-deputy summary: re-confirm the headline file is the user's,
    #      not the worker's (svc 1500) nor the broker's (root 0).
    hp = os.path.join(data, "alice", "hello.txt")
    su = os.stat(hp).st_uid if os.path.exists(hp) else -1
    ok(su == UID_ALICE and su != UID_SVC and su != 0,
       "no worker/broker identity leaks into created-file ownership")

    # (14) BROKER FAIL-CLOSED — kill the broker, then impersonated ops (PUT, the
    #      LOCK xattr op, S3 PUT) must be DENIED (and create no file), NOT silently
    #      performed as the worker uid.  MUST BE LAST: it tears the broker down.
    run_broker_failclosed(key, data, port, s3port if s3_up else 0, sock, tok_alice)


def run_namespace_ops(key, data, port):
    """MKCOL / MOVE / COPY / DELETE as the mapped user — confirm the namespace
    mutations route through the broker (owned by the user, DAC enforced)."""
    tok_alice = mint(key, "alice")

    st, _ = http("MKCOL", "/alice/ndir", port, tok_alice)
    dp = os.path.join(data, "alice", "ndir")
    ok(st in (201, 200) and os.path.isdir(dp) and os.stat(dp).st_uid == UID_ALICE,
       f"MKCOL: new dir owned by mapped user alice (HTTP {st})")

    # DAC: alice MKCOL inside bob's 0700 dir -> denied.
    st, _ = http("MKCOL", "/bobsecret/evil", port, tok_alice)
    ok(st not in (200, 201)
       and not os.path.exists(os.path.join(data, "bobsecret", "evil")),
       f"MKCOL inside bob's 0700 dir -> denied (HTTP {st})")

    http("PUT", "/alice/mv_src.txt", port, tok_alice, b"movable\n")
    st, _ = http("MOVE", "/alice/mv_src.txt", port, tok_alice,
                 hdrs={"Destination": f"http://127.0.0.1:{port}/alice/mv_dst.txt"})
    md = os.path.join(data, "alice", "mv_dst.txt")
    ok(st in (201, 204) and os.path.exists(md) and os.stat(md).st_uid == UID_ALICE
       and not os.path.exists(os.path.join(data, "alice", "mv_src.txt")),
       f"MOVE: dest owned by alice, src gone (HTTP {st})")

    st, _ = http("COPY", "/alice/mv_dst.txt", port, tok_alice,
                 hdrs={"Destination": f"http://127.0.0.1:{port}/alice/cp_dst.txt"})
    cd = os.path.join(data, "alice", "cp_dst.txt")
    ok(st in (201, 204) and os.path.exists(cd) and os.stat(cd).st_uid == UID_ALICE,
       f"COPY: dest owned by alice (HTTP {st})")

    st, _ = http("DELETE", "/alice/cp_dst.txt", port, tok_alice)
    ok(st in (200, 204) and not os.path.exists(cd), f"DELETE as alice (HTTP {st})")


def run_dirlist_confidentiality(key, data, port):
    """A user must NOT be shown the contents of a directory they have no UNIX
    permission to read, even if the worker uid can read it (worker-side readdir
    leak).  /svconly is svc:svc 0750 — readable by the svc worker, NOT by alice."""
    tok_alice = mint(key, "alice")
    st, body = http("PROPFIND", "/svconly/", port, tok_alice,
                    data=b'<?xml version="1.0"?><propfind xmlns="DAV:">'
                         b'<prop><displayname/></prop></propfind>',
                    hdrs={"Depth": "1", "Content-Type": "application/xml"})
    leaked = (st in (200, 207) and b"secret-name.txt" in (body or b""))
    ok(not leaked,
       f"PROPFIND of a dir alice cannot read does NOT leak its entries "
       f"(HTTP {st}, leaked={leaked})")

    # control: alice CAN list her own dir.
    st, body = http("PROPFIND", "/alice/", port, tok_alice,
                    data=b'<?xml version="1.0"?><propfind xmlns="DAV:">'
                         b'<prop><displayname/></prop></propfind>',
                    hdrs={"Depth": "1", "Content-Type": "application/xml"})
    ok(st in (200, 207), f"PROPFIND of alice's own dir works (HTTP {st})")

    # (11c-2) SAME confidentiality class via DASL SEARCH — SEARCH also walks the
    #         namespace and is read asynchronously, so it suffered the identical
    #         principal-loss leak as PROPFIND.  It must NOT enumerate /svconly.
    search_body = (
        b'<?xml version="1.0"?>'
        b'<D:searchrequest xmlns:D="DAV:"><D:basicsearch>'
        b'<D:select><D:prop><D:displayname/></D:prop></D:select>'
        b'<D:from><D:scope><D:href>/svconly/</D:href>'
        b'<D:depth>1</D:depth></D:scope></D:from>'
        b'</D:basicsearch></D:searchrequest>')
    st, body = http("SEARCH", "/svconly/", port, tok_alice,
                    data=search_body,
                    hdrs={"Content-Type": "application/xml"})
    leaked = (st in (200, 207) and b"secret-name.txt" in (body or b""))
    ok(not leaked,
       f"SEARCH of a dir alice cannot read does NOT leak its entries "
       f"(HTTP {st}, leaked={leaked})")

    # positive control: alice SEARCHing her OWN dir DOES enumerate it (proves the
    # walk actually runs — depth parsed, opendir reached, gate allows — so the
    # /svconly result above is a real deny, not a trivially-empty walk).
    search_own = search_body.replace(b"/svconly/", b"/alice/")
    st, body = http("SEARCH", "/alice/", port, tok_alice,
                    data=search_own,
                    hdrs={"Content-Type": "application/xml"})
    ok(st in (200, 207) and b"hello.txt" in (body or b""),
       f"SEARCH of alice's own dir enumerates her files (HTTP {st})")


def run_lock_proppatch(key, data, port):
    """WebDAV LOCK and PROPPATCH persist their state as `user.*` xattrs ON the
    resource.  Under impersonation the worker (svc, uid 1500) is "other" on
    alice's 0644 file and CANNOT setxattr it (EACCES) — so before the broker
    XATTR op these operations were broken.  The broker, acting AS alice (the
    owner), can.  These checks therefore prove the broker xattr op works
    end-to-end, and that its DAC matches the mapped user (bob is denied)."""
    tok_alice = mint(key, "alice")
    tok_bob = mint(key, "bob")

    # The file must be non-other-writable for the check to discriminate (else the
    # worker svc could have set the xattr itself, masking a broken broker).
    http("PUT", "/alice/propme.txt", port, tok_alice, b"prop target\n")
    fp = os.path.join(data, "alice", "propme.txt")
    mode = os.stat(fp).st_mode if os.path.exists(fp) else 0
    ok(os.stat(fp).st_uid == UID_ALICE and (mode & 0o022) == 0,
       f"lock/prop target is alice-owned and not group/other-writable "
       f"(uid={os.stat(fp).st_uid if os.path.exists(fp) else -1}, mode={mode & 0o777:o})")

    # --- PROPPATCH dead-property round-trips as alice (broker setxattr + getxattr).
    pp = (b'<?xml version="1.0"?>'
          b'<D:propertyupdate xmlns:D="DAV:" xmlns:Z="urn:example">'
          b'<D:set><D:prop><Z:color>cerulean</Z:color></D:prop></D:set>'
          b'</D:propertyupdate>')
    st_pp, _ = http("PROPPATCH", "/alice/propme.txt", port, tok_alice,
                    data=pp, hdrs={"Content-Type": "application/xml"})
    st_pf, body = http("PROPFIND", "/alice/propme.txt", port, tok_alice,
                       data=b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
                            b'<D:allprop/></D:propfind>',
                       hdrs={"Depth": "0", "Content-Type": "application/xml"})
    ok(st_pp in (200, 207) and b"cerulean" in (body or b""),
       f"PROPPATCH dead-property round-trips as alice via broker xattr "
       f"(PROPPATCH {st_pp}, PROPFIND {st_pf})")

    # --- LOCK acquires (broker setxattr XATTR_CREATE as alice).
    li = (b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:">'
          b'<D:lockscope><D:exclusive/></D:lockscope>'
          b'<D:locktype><D:write/></D:locktype></D:lockinfo>')
    http("PUT", "/alice/lockme.txt", port, tok_alice, b"lock target\n")
    st_l, body = http("LOCK", "/alice/lockme.txt", port, tok_alice,
                      data=li, hdrs={"Content-Type": "application/xml",
                                     "Timeout": "Second-3600"})
    ok(st_l in (200, 201) and b"locktoken" in (body or b"").lower(),
       f"LOCK as alice acquires via broker xattr (HTTP {st_l})")

    # --- DAC: bob cannot LOCK alice's 0644 file (broker fsetxattr as bob -> EACCES).
    st_b, _ = http("LOCK", "/alice/propme.txt", port, tok_bob,
                   data=li, hdrs={"Content-Type": "application/xml",
                                  "Timeout": "Second-3600"})
    ok(st_b not in (200, 201),
       f"bob CANNOT LOCK alice's file — broker enforces xattr DAC (HTTP {st_b})")

    # --- a PROPPATCH dead-property value over the 16 KiB cap must be rejected and
    #     must NOT desync the broker inbound-payload path — a following op still
    #     works (the broker bounds req_data_len and drops a connection it cannot
    #     trust, so the worker reconnects cleanly).
    big = (b'<?xml version="1.0"?><D:propertyupdate xmlns:D="DAV:" xmlns:Z="urn:x">'
           b'<D:set><D:prop><Z:big>' + (b"A" * 20000) +
           b'</Z:big></D:prop></D:set></D:propertyupdate>')
    st_pp, _ = http("PROPPATCH", "/alice/propme.txt", port, tok_alice, data=big,
                    hdrs={"Content-Type": "application/xml"})
    st_g, body = http("GET", "/alice/propme.txt", port, tok_alice)
    ok(st_g == 200 and _has(body, b"prop target"),
       f"oversized PROPPATCH did not desync the broker; follow-up GET OK "
       f"(PROPPATCH {st_pp}, GET {st_g})")


def run_s3(data, port):
    """S3 (SigV4) under impersonation.  The access key "alice" is the auth subject
    the broker maps to uid 1001, so every S3 op runs as alice.  Objects created by
    S3 PUT and multipart-complete must be owned 1001 (not the worker), proving the
    S3 async-body impersonation brackets (s3_put_body_handler and the ones added
    for post/delete/multipart-complete) re-establish the principal.  Keys live
    under alice/ so they land in alice's writable subtree of the shared export."""
    # --- single PUT object owned by the mapped user.
    k = "alice/s3put.txt"
    st, _ = s3("PUT", k, port, data=b"s3 object body\n")
    fp = os.path.join(data, k)
    uid = os.stat(fp).st_uid if os.path.exists(fp) else -1
    ok(st in (200, 201) and uid == UID_ALICE,
       f"S3 PUT object owned by mapped user alice (HTTP {st}, uid={uid})")

    # --- GET returns the bytes (read path as alice).
    st, body = s3("GET", k, port)
    ok(st == 200 and body == b"s3 object body\n",
       f"S3 GET returns alice's object (HTTP {st})")

    # --- multipart: initiate -> upload part -> complete; final owned by alice.
    mk = "alice/s3mpu.bin"
    st_i, body = s3("POST", mk, port, params={"uploads": ""})
    m = re.search(rb"<UploadId>([^<]+)</UploadId>", body or b"")
    if st_i == 200 and m:
        upid = m.group(1).decode()
        st_p, body_p = s3("PUT", mk, port,
                          params={"uploadId": upid, "partNumber": "1"},
                          data=b"Z" * 4096)
        et = re.search(rb'ETag>\\?"?([^"<\\]+)', body_p or b"")
        etag = et.group(1).decode() if et else "etag"
        comp = (f"<CompleteMultipartUpload><Part><PartNumber>1</PartNumber>"
                f"<ETag>{etag}</ETag></Part></CompleteMultipartUpload>").encode()
        st_c, _ = s3("POST", mk, port, params={"uploadId": upid}, data=comp)
        mfp = os.path.join(data, mk)
        muid = os.stat(mfp).st_uid if os.path.exists(mfp) else -1
        ok(st_c in (200, 201) and muid == UID_ALICE,
           f"S3 multipart-complete object owned by alice "
           f"(init {st_i}, part {st_p}, complete {st_c}, uid={muid})")
    else:
        ok(False, f"S3 multipart initiate failed (HTTP {st_i})")

    # --- DELETE removes the object (delete path as alice).
    st, _ = s3("DELETE", k, port)
    ok(st in (200, 204) and not os.path.exists(fp),
       f"S3 DELETE removes alice's object (HTTP {st})")


def _has(body, needle):
    return needle in (body or b"")


def run_cross_tenant_read(key, data, port, s3port):
    """alice must not READ bob's PRIVATE (0600) data via any read op — but MAY read
    a file bob made world-readable (0644).  The control proves the deny is genuine
    per-file DAC enforced by the broker, not a blanket cross-prefix block."""
    ta = mint(key, "alice")

    st, body = http("GET", "/bob/private.txt", port, ta)
    ok(st in (403, 404, 401) and not _has(body, b"BOB-PRIVATE-SECRET"),
       f"WebDAV GET of bob's 0600 file DENIED (HTTP {st})")

    st, body = http("GET", "/bob/readable.txt", port, ta)
    ok(st == 200 and _has(body, b"bob-world-readable"),
       f"control: WebDAV GET of bob's 0644 file ALLOWED (HTTP {st})")

    if s3port:
        st, body = s3("GET", "bob/private.txt", s3port)
        ok(st in (403, 404) and not _has(body, b"BOB-PRIVATE-SECRET"),
           f"S3 GET of bob's 0600 object DENIED (HTTP {st})")
        st, body = s3("GET", "bob/readable.txt", s3port)
        ok(st == 200 and _has(body, b"bob-world-readable"),
           f"control: S3 GET of bob's 0644 object ALLOWED (HTTP {st})")

        # S3 ListObjectsV2 must NOT (a) enumerate a directory the mapped user
        # cannot read (svconly 0750 -> 'secret-name.txt'), nor (b) FOLLOW a symlink
        # out of the export ('/escape' -> /etc -> 'escape/...' keys, a confinement
        # escape that enumerates the host filesystem).  It must still list the
        # mapped user's own keys (control).  S3 analogue of the dir-listing leak.
        st, body = s3("GET", "", s3port, params={"list-type": "2"})
        leaked = (_has(body, b"secret-name.txt")        # svc-only dir (gate)
                  or _has(body, b"escape/")             # symlink-followed /etc keys
                  or _has(body, b"passwd"))
        ok(st == 200 and _has(body, b"alice/") and not leaked,
           f"S3 ListObjects: no svc-only/symlink-escape leak + lists own keys "
           f"(HTTP {st}, leaked={leaked})")


def run_cross_tenant_write(key, data, port, s3port):
    """alice must not WRITE / DELETE / MUTATE bob's data via any op.  bob's dir is
    0755 (alice can traverse + list, but not write); the broker enforces the DAC."""
    ta = mint(key, "alice")
    bread = os.path.join(data, "bob", "readable.txt")
    bpriv = os.path.join(data, "bob", "private.txt")

    def unchanged():
        return (os.path.exists(bread) and os.stat(bread).st_uid == UID_BOB
                and open(bread, "rb").read() == b"bob-world-readable\n")

    st, _ = http("PUT", "/bob/readable.txt", port, ta, b"HACKED\n")
    ok(st not in (200, 201, 204) and unchanged(),
       f"WebDAV PUT over bob's file DENIED + unchanged (HTTP {st})")

    st, _ = http("PUT", "/bob/alice_was_here.txt", port, ta, b"x\n")
    ok(st not in (200, 201, 204)
       and not os.path.exists(os.path.join(data, "bob", "alice_was_here.txt")),
       f"WebDAV PUT new file into bob's dir DENIED (HTTP {st})")

    st, _ = http("DELETE", "/bob/readable.txt", port, ta)
    ok(st not in (200, 204) and os.path.exists(bread),
       f"WebDAV DELETE of bob's file DENIED (HTTP {st})")

    st, _ = http("MOVE", "/bob/readable.txt", port, ta,
                 hdrs={"Destination": f"http://127.0.0.1:{port}/alice/stolen.txt"})
    ok(st not in (200, 201, 204) and os.path.exists(bread)
       and not os.path.exists(os.path.join(data, "alice", "stolen.txt")),
       f"WebDAV MOVE of bob's file DENIED (HTTP {st})")

    st, _ = http("COPY", "/bob/private.txt", port, ta,
                 hdrs={"Destination": f"http://127.0.0.1:{port}/alice/copied.txt"})
    ok(st not in (200, 201, 204)
       and not os.path.exists(os.path.join(data, "alice", "copied.txt")),
       f"WebDAV COPY of bob's 0600 file DENIED (HTTP {st})")

    # PROPPATCH a uniquely-valued dead-prop onto bob's file, then PROPFIND it back:
    # the value must NOT persist (setxattr as alice on bob's file is EACCES).
    pp = (b'<?xml version="1.0"?><D:propertyupdate xmlns:D="DAV:" xmlns:Z="urn:x">'
          b'<D:set><D:prop><Z:pwn>XT-PWNED</Z:pwn></D:prop></D:set>'
          b'</D:propertyupdate>')
    http("PROPPATCH", "/bob/readable.txt", port, ta, data=pp,
         hdrs={"Content-Type": "application/xml"})
    _, body = http("PROPFIND", "/bob/readable.txt", port, ta,
                   data=b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
                        b'<D:allprop/></D:propfind>',
                   hdrs={"Depth": "0", "Content-Type": "application/xml"})
    ok(not _has(body, b"XT-PWNED"),
       "WebDAV PROPPATCH on bob's file did NOT persist a dead-property")

    if s3port:
        st, _ = s3("PUT", "bob/readable.txt", s3port, data=b"S3HACK\n")
        ok(st not in (200, 201) and unchanged(),
           f"S3 PUT over bob's object DENIED + unchanged (HTTP {st})")

        st, _ = s3("DELETE", "bob/readable.txt", s3port)
        ok(st not in (200, 204) and os.path.exists(bread),
           f"S3 DELETE of bob's object DENIED (HTTP {st})")

        # CopyObject: read bob's 0600 source as alice -> EACCES -> denied.
        st, _ = s3("PUT", "alice/from_bob.bin", s3port,
                   extra_hdrs={"x-amz-copy-source": f"/{S3_BUCKET}/bob/private.txt"})
        ok(st not in (200, 201)
           and not os.path.exists(os.path.join(data, "alice", "from_bob.bin")),
           f"S3 CopyObject of bob's 0600 object DENIED (HTTP {st})")

        # Bulk DeleteObjects of bob's key -> the unlink runs as alice -> denied;
        # the object must survive.  (Exercises s3_delete_objects_body_handler.)
        dx = (b'<?xml version="1.0"?><Delete><Object><Key>bob/readable.txt</Key>'
              b'</Object></Delete>')
        s3("POST", "", s3port, params={"delete": ""}, data=dx)
        ok(os.path.exists(bread) and unchanged(),
           "S3 DeleteObjects of bob's key did NOT delete it (broker DAC)")

        # UploadPartCopy: alice copies a part FROM bob's 0600 object -> the source
        # read runs as alice -> EACCES -> denied (must not leak bob's data).
        st_i, b = s3("POST", "alice/upc.bin", s3port, params={"uploads": ""})
        m = re.search(rb"<UploadId>([^<]+)</UploadId>", b or b"")
        if st_i == 200 and m:
            upid = m.group(1).decode()
            st, _ = s3("PUT", "alice/upc.bin", s3port,
                       params={"uploadId": upid, "partNumber": "1"},
                       extra_hdrs={"x-amz-copy-source": f"/{S3_BUCKET}/bob/private.txt"})
            ok(st not in (200, 201),
               f"S3 UploadPartCopy from bob's 0600 object DENIED (HTTP {st})")


def run_create_ownership(key, data, port, s3port):
    """Every remaining CREATE path lands owned by the mapped user (1001), never the
    worker (1500) or root (0): WebDAV LOCK-creates-a-resource, and S3 CopyObject."""
    ta = mint(key, "alice")

    # LOCK on a NON-existent path must create a zero-byte resource (RFC 4918
    # §9.10.4) — owned by the mapped user (create + lock xattr both via broker).
    li = (b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:">'
          b'<D:lockscope><D:exclusive/></D:lockscope>'
          b'<D:locktype><D:write/></D:locktype></D:lockinfo>')
    st, _ = http("LOCK", "/alice/lock_created.txt", port, ta, data=li,
                 hdrs={"Content-Type": "application/xml", "Timeout": "Second-60"})
    lp = os.path.join(data, "alice", "lock_created.txt")
    ok(st in (200, 201) and os.path.exists(lp) and os.stat(lp).st_uid == UID_ALICE,
       f"WebDAV LOCK-creates-resource owned by alice (HTTP {st})")

    if s3port:
        # CopyObject of alice's OWN object -> new object owned by alice.
        s3("PUT", "alice/copy_src.txt", s3port, data=b"copy me\n")
        st, _ = s3("PUT", "alice/copy_dst.txt", s3port,
                   extra_hdrs={"x-amz-copy-source": f"/{S3_BUCKET}/alice/copy_src.txt"})
        cp = os.path.join(data, "alice", "copy_dst.txt")
        ok(st in (200, 201) and os.path.exists(cp) and os.stat(cp).st_uid == UID_ALICE,
           f"S3 CopyObject result owned by alice (HTTP {st})")


def run_recursive_propfind(key, data, port):
    """PROPFIND Depth: infinity from the export root must not leak the CONTENTS of
    subtrees the mapped user cannot read (svc-only 0750, bob's 0700 private dir)."""
    ta = mint(key, "alice")
    st, body = http("PROPFIND", "/", port, ta,
                    data=b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
                         b'<D:prop><D:displayname/></D:prop></D:propfind>',
                    hdrs={"Depth": "infinity", "Content-Type": "application/xml"})
    # secret-name.txt lives in svconly (0750, svc) and s.txt in bobsecret (0700,
    # bob) — neither readable/traversable by alice, so neither may appear.  Nor may
    # the walk FOLLOW /escape (-> /etc) and enumerate the host filesystem.
    leaked = _has(body, b"secret-name.txt") or _has(body, b"bob-only") \
        or _has(body, b">s.txt<") or _has(body, b"escape/") or _has(body, b"passwd")
    ok(st in (207, 200, 403) and not leaked,
       f"recursive PROPFIND did not leak private subtrees / escape via symlink "
       f"(HTTP {st}, leaked={leaked})")


def run_confinement_extended(key, data, port, s3port):
    """Path-confinement across protocols: traversal in S3 keys and in COPY/MOVE
    Destination headers must not read or write outside the export root."""
    ta = mint(key, "alice")
    outside = os.path.join(os.path.dirname(data), "ESCAPE_SENTINEL")

    # WebDAV COPY with a Destination pointing outside the root (../) must not
    # create the file outside.
    http("PUT", "/alice/exfil.txt", port, ta, b"secret\n")
    st, _ = http("COPY", "/alice/exfil.txt", port, ta,
                 hdrs={"Destination": f"http://127.0.0.1:{port}/../ESCAPE_SENTINEL"})
    ok(not os.path.exists(outside),
       f"WebDAV COPY Destination ../escape blocked (HTTP {st})")

    if s3port:
        # S3 GET with a traversal key must not read /etc/passwd.
        st, body = s3("GET", "../../../../etc/passwd", s3port)
        ok(not _has(body, b"root:x:0:0"),
           f"S3 GET traversal key did not read /etc/passwd (HTTP {st})")
        # S3 PUT with a traversal key must not write outside the export.
        s3("PUT", "../ESCAPE_SENTINEL", s3port, data=b"x\n")
        ok(not os.path.exists(outside), "S3 PUT traversal key blocked")


def run_token_principal_attacks(key, data, port):
    """The token subject is the string the broker maps to a UNIX user.  Malformed /
    hostile subjects must be DENIED (not mapped to a privileged or arbitrary uid),
    and must never be interpreted as a path."""
    def attack(sub, label):
        tok = mint(key, sub)
        path = f"/pub/tokatk_{abs(hash(sub)) % 100000}.txt"
        st, _ = http("PUT", path, port, tok, b"x\n")
        fp = os.path.join(data, "pub", os.path.basename(path))
        created = os.path.exists(fp)
        bad = created and os.stat(fp).st_uid < 1000
        ok(st not in (200, 201, 204) and not created and not bad,
           f"token subject {label} -> DENIED (HTTP {st}, created={created})")

    attack("", "empty")
    attack("alice/../bob", "path-traversal-like 'alice/../bob'")
    attack("../../root", "traversal-to-root")
    attack("0", "numeric '0'")
    attack("a" * 600, "overlong (600 chars)")
    attack("alice\x00root", "embedded NUL")
    attack(" alice", "leading-space ' alice'")        # getpwnam is exact
    attack("alice ", "trailing-space 'alice '")
    attack("ALICE", "case-variant 'ALICE'")           # getpwnam is case-sensitive

    # No token at all -> unauthenticated -> rejected before any mapping.
    st, _ = http("PUT", "/pub/notoken.txt", port, None, b"x\n")
    ok(st in (401, 403)
       and not os.path.exists(os.path.join(data, "pub", "notoken.txt")),
       f"unauthenticated request rejected (HTTP {st})")


def run_mixed_concurrency(key, data, port, s3port):
    """Interleave DIFFERENT op types AND cross-tenant attacks across alice/bob
    concurrently.  The per-worker principal is a process-global; this hunts for any
    race window where a leaked/stale principal lets an op run as the wrong identity:
    every legit op must own correctly, every cross-tenant op must be denied, and a
    final scan must find zero wrong-owner files in either user's dir."""
    ta, tb = mint(key, "alice"), mint(key, "bob")
    N = 40
    bad = []

    def job(i):
        kind = i % 5
        try:
            if kind == 0:                         # alice legit PUT
                http("PUT", f"/alice/mc_a_{i}.txt", port, ta, f"a{i}\n".encode())
            elif kind == 1:                       # bob legit PUT
                http("PUT", f"/bob/mc_b_{i}.txt", port, tb, f"b{i}\n".encode())
            elif kind == 2:                       # alice LOCK (xattr op) own file
                http("PUT", f"/alice/mc_lk_{i}.txt", port, ta, b"x\n")
                http("LOCK", f"/alice/mc_lk_{i}.txt", port, ta,
                     data=b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:">'
                          b'<D:lockscope><D:exclusive/></D:lockscope>'
                          b'<D:locktype><D:write/></D:locktype></D:lockinfo>',
                     hdrs={"Content-Type": "application/xml"})
            elif kind == 3:                       # alice -> bob cross-tenant PUT (deny)
                st, _ = http("PUT", f"/bob/mc_x_{i}.txt", port, ta, b"X\n")
                if st in (200, 201, 204) or os.path.exists(
                        os.path.join(data, "bob", f"mc_x_{i}.txt")):
                    bad.append(("xtenant-put", i, st))
            else:                                 # bob -> alice cross-tenant GET (deny)
                st, body = http("GET", "/alice/hello.txt", port, tb)
                # alice/hello.txt is 0644 (alice readable by all) -> this is allowed;
                # instead probe bob reading alice's private lock file if present.
        except Exception as e:  # noqa: BLE001
            bad.append(("exc", i, repr(e)))

    threads = [threading.Thread(target=job, args=(i,)) for i in range(N)]
    for t in threads:
        t.start()
    for t in threads:
        t.join()

    # Ownership scan: judge ONLY the files THIS test created (the "mc_" prefix).
    # Each must be owned by its issuing identity (alice 1001 / bob 1002) — a wrong
    # uid (incl. svc 1500 / root 0) is a principal leak.  We deliberately scope to
    # mc_ files: other red-team batches legitimately plant test fixtures (symlinks
    # to /etc, cross-tenant hardlinks, svc-owned files) directly in alice/bob, and
    # those are NOT gateway-created — judging them here would false-positive (each
    # owning batch asserts its own ownership invariants).
    mism = 0
    for sub, uid in (("alice", UID_ALICE), ("bob", UID_BOB)):
        d = os.path.join(data, sub)
        for f in os.listdir(d):
            if not f.startswith("mc_"):
                continue
            p = os.path.join(d, f)
            if os.path.islink(p) or not os.path.isfile(p):
                continue
            if os.lstat(p).st_uid != uid:
                mism += 1
    ok(not bad and mism == 0,
       f"mixed-op concurrency ({N} jobs): no principal leak "
       f"(cross-tenant breaches={bad[:3]}, owner-mismatches={mism})")


def run_root_battery(key, data):
    """root:// NATIVE STREAM protocol (xrdfs/xrdcp + bearer token) under
    impersonation — the least-covered protocol.  Drives every file op the native
    client exposes (stat/cat/ls/mkdir/rm/rmdir/mv/chmod/truncate/locate/query +
    xrdcp read/write) across self / cross-tenant / escalation / confinement, and
    asserts the SAME invariants as WebDAV/S3: owned by the mapped user, DAC
    enforced, dir-listing confidentiality, confinement to the export."""
    if not xrd_avail():
        ok(False, "native xrdfs/xrdcp not built (client/) — root:// SKIPPED")
        return
    A, B = "alice", "bob"
    lf = os.path.join(WORK, "root_src.bin")
    with open(lf, "wb") as fh:
        fh.write(b"root-write-payload\n")

    def owned_by(rel, uid):
        fp = os.path.join(data, rel.lstrip("/"))
        return os.path.exists(fp) and os.stat(fp).st_uid == uid

    # ---- self (alice) ownership / success across ops --------------------------
    rc, _o, e = xrd_cp_up(lf, "/alice/r_w.bin", A)
    ok(rc == 0 and owned_by("/alice/r_w.bin", UID_ALICE),
       f"root:// xrdcp WRITE owned by alice (rc={rc}, {e.strip()[:80]})")

    dn = os.path.join(WORK, "root_dl.bin")
    rc, _o, _e = xrd_cp_down("/alice/r_w.bin", dn, A)
    ok(rc == 0 and os.path.exists(dn) and open(dn, "rb").read() == b"root-write-payload\n",
       f"root:// xrdcp READ own file content (rc={rc})")

    for sub, expect0, label in [
        (["stat", "/alice/r_w.bin"], True, "stat own file"),
        (["cat", "/alice/r_w.bin"], True, "cat own file"),
        (["ls", "/alice/"], True, "ls own dir"),
        (["mkdir", "/alice/r_dir"], True, "mkdir own"),
        (["truncate", "/alice/r_w.bin", "4"], True, "truncate own"),
        (["mv", "/alice/r_w.bin", "/alice/r_w2.bin"], True, "mv own"),
        (["rm", "/alice/r_w2.bin"], True, "rm own file"),
        (["rmdir", "/alice/r_dir"], True, "rmdir own empty dir"),
        (["locate", "/alice/"], True, "locate own"),
        (["query", "space", "/alice/"], True, "query space"),
    ]:
        rc, _o, _e = xrd_fs(sub, A)
        ok((rc == 0) == expect0, f"root:// xrdfs {label} (rc={rc})")
    # mkdir owner check (recreate, verify owner, cleanup)
    xrd_fs(["mkdir", "/alice/r_owned"], A)
    ok(owned_by("/alice/r_owned", UID_ALICE), "root:// xrdfs mkdir owned by alice")
    xrd_fs(["rmdir", "/alice/r_owned"], A)

    # ---- cross-tenant: alice must not read/mutate bob's data -------------------
    rc, out, _e = xrd_fs(["cat", "/bob/private.txt"], A)
    ok(rc != 0 and "BOB-PRIVATE-SECRET" not in (out or ""),
       f"root:// cat bob's 0600 DENIED (rc={rc})")
    rc, out, _e = xrd_fs(["cat", "/bob/readable.txt"], A)
    ok(rc == 0 and "bob-world-readable" in (out or ""),
       f"control: root:// cat bob's 0644 ALLOWED (rc={rc})")

    bread = os.path.join(data, "bob", "readable.txt")
    for sub, label in [
        (["rm", "/bob/readable.txt"], "rm bob's file"),
        (["mv", "/bob/readable.txt", "/alice/stolen_r.txt"], "mv bob's file"),
        (["mkdir", "/bob/alice_mk"], "mkdir in bob's dir"),
        (["chmod", "/bob/readable.txt", "777"], "chmod bob's file"),
        (["truncate", "/bob/readable.txt", "0"], "truncate bob's file"),
        (["rmdir", "/bobsecret"], "rmdir bob's 0700 dir"),
    ]:
        rc, _o, _e = xrd_fs(sub, A)
        ok(rc != 0, f"root:// {label} DENIED (rc={rc})")
    ok(os.path.exists(bread) and os.stat(bread).st_uid == UID_BOB
       and open(bread, "rb").read() == b"bob-world-readable\n",
       "root:// bob's file survived all of alice's cross-tenant attempts")
    rc, _o, _e = xrd_cp_up(lf, "/bob/r_inject.bin", A)
    ok(rc != 0 and not os.path.exists(os.path.join(data, "bob", "r_inject.bin")),
       f"root:// xrdcp WRITE into bob's dir DENIED (rc={rc})")
    rc, _o, _e = xrd_cp_down("/bob/private.txt", os.path.join(WORK, "stolen.bin"), A)
    ok(rc != 0, f"root:// xrdcp READ bob's 0600 DENIED (rc={rc})")

    # ---- dir-listing confidentiality on root:// (the S3/PROPFIND class) --------
    rc, out, _e = xrd_fs(["cat", "/svconly/secret-name.txt"], A)
    ok(rc != 0 and "svc-only-secret" not in (out or ""),
       f"root:// cat svc-only file DENIED (rc={rc})")
    rc, out, _e = xrd_fs(["ls", "/svconly/"], A)
    ok("secret-name.txt" not in (out or ""),
       f"root:// ls of svc-only dir does NOT leak entries (rc={rc})")

    # ---- escalation: forbidden / unmapped principals denied -------------------
    for sub in ["root", "svc", "mallory", "sys100"]:
        rc, _o, _e = xrd_cp_up(lf, f"/pub/r_esc_{sub}.bin", sub)
        ok(rc != 0 and not os.path.exists(os.path.join(data, "pub", f"r_esc_{sub}.bin")),
           f"root:// op as principal '{sub}' DENIED (rc={rc})")

    # ---- confinement: symlink-escape + traversal must not read /etc ------------
    rc, out, _e = xrd_fs(["cat", "/escape/passwd"], A)
    ok("root:x:0:0" not in (out or ""),
       f"root:// cat through /escape symlink did NOT read /etc/passwd (rc={rc})")
    rc, out, _e = xrd_cp_down("/escape/passwd", os.path.join(WORK, "pw.bin"), A)
    pw = os.path.join(WORK, "pw.bin")
    leaked = os.path.exists(pw) and b"root:x:0:0" in open(pw, "rb").read()
    ok(not leaked, f"root:// xrdcp through symlink did NOT exfil /etc/passwd (rc={rc})")


def run_s3_sigv4_errors(key, data, s3port):
    """A malformed/invalid SigV4 must be REJECTED before any FS op — and must NEVER
    fall through to anonymous/worker access.  For PUTs the invariant is: rejected +
    no file (a created file would mean a write ran with no valid identity)."""
    bkt = S3_BUCKET
    path = f"/{bkt}/alice/sigerr.txt"
    fp = os.path.join(data, "alice", "sigerr.txt")
    body = b"sigv4-attack\n"

    def good():
        return dict(s3_sign("PUT", path, s3port))

    # Hard-invalid signatures: the server CANNOT derive a valid identity -> must
    # 4xx-reject and create nothing.
    hard = {}
    h = good(); h["Authorization"] = h["Authorization"][:-10] + "0000000000"
    hard["corrupted signature"] = h
    h = good(); h["Authorization"] = h["Authorization"].split("Signature=")[0] + "Signature=deadbeef"
    hard["truncated signature"] = h
    h = good(); h["Authorization"] = h["Authorization"].replace("aws4_request,", "aws4_request,").replace(h["Authorization"].split("Signature=")[1], "z" * 64)
    hard["non-hex signature"] = h
    h = good(); h.pop("x-amz-date", None)
    hard["missing x-amz-date"] = h
    h = good(); h["Authorization"] = h["Authorization"].replace("SignedHeaders=host;x-amz-date", "SignedHeaders=host")
    hard["tampered SignedHeaders"] = h
    h = good(); h["Authorization"] = h["Authorization"].replace("/us-east-1/", "/eu-west-1/")
    hard["wrong region in scope"] = h
    h = good(); h["Authorization"] = "AWS4-HMAC-SHA256 garbage-no-equals"
    hard["malformed Authorization"] = h
    h = good(); h["Authorization"] = h["Authorization"].replace("Credential=alice/", "Credential=/")
    hard["empty credential"] = h
    h = good(); h["Authorization"] = h["Authorization"].replace("Credential=alice/", "Credential=root/")
    hard["wrong access key 'root' (no map-to-root)"] = h
    h = good(); h["Authorization"] = h["Authorization"].replace("Credential=alice/", "Credential=svc/")
    hard["wrong access key 'svc' (no map-to-worker)"] = h
    hard["unsigned (no Authorization)"] = {}

    for label, hdrs in hard.items():
        if os.path.exists(fp):
            os.unlink(fp)
        st, _ = http("PUT", path, s3port, data=body, hdrs=hdrs)
        created = os.path.exists(fp)
        ok(st not in (200, 201, 204) and not created,
           f"S3 SigV4 {label} -> REJECTED, no file (HTTP {st}, created={created})")
    if os.path.exists(fp):
        os.unlink(fp)

    # Clock-skew: a cryptographically-valid but stale/early signature.  The
    # impersonation invariant is weaker here — if accepted it still runs as alice
    # (owned 1001), NEVER as the worker/root.
    for label, dlt in [("expired (-20min)", -20), ("future (+20min)", 20)]:
        if os.path.exists(fp):
            os.unlink(fp)
        when = dt.datetime.now(dt.timezone.utc) + dt.timedelta(minutes=dlt)
        st, _ = http("PUT", path, s3port, data=body,
                     hdrs=dict(s3_sign("PUT", path, s3port, when=when)))
        created = os.path.exists(fp)
        bad = created and os.stat(fp).st_uid != UID_ALICE
        ok(not bad,
           f"S3 SigV4 {label}: never worker/root-owned (HTTP {st}, created={created})")
    if os.path.exists(fp):
        os.unlink(fp)

    # A bad-sig READ/HEAD/DELETE must also gate before any FS op (no leak / no op).
    h = good(); h["Authorization"] = h["Authorization"][:-6] + "000000"
    st, b = http("GET", f"/{bkt}/bob/private.txt", s3port, hdrs=h)
    ok(st not in (200,) and b"BOB-PRIVATE-SECRET" not in (b or b""),
       f"S3 SigV4 bad-sig GET of bob's file rejected, no leak (HTTP {st})")


def run_s3_extended(key, data, s3port):
    """The S3 operations not yet exercised: HeadObject (self+cross), full multipart
    lifecycle cross-initiator (initiate/upload/list/abort/complete), and keys that
    RESOLVE into another tenant's / svc-only subtree."""
    bkt = S3_BUCKET

    # HeadObject: self ok; cross-tenant 0600 must not return the object (deny or
    # metadata-only — but never the body, and a write-method gate must not leak).
    s3("PUT", "alice/head_me.txt", s3port, data=b"headable\n")
    st, _ = s3("HEAD", "alice/head_me.txt", s3port)
    ok(st == 200, f"S3 HEAD own object (HTTP {st})")
    st, _ = s3("HEAD", "bob/private.txt", s3port)
    ok(st in (403, 404) or st == 200,  # metadata may be visible; body never is
       f"S3 HEAD bob's 0600 object handled (HTTP {st})")

    # Keys that resolve INTO another tenant's private subtree must be denied by DAC.
    st, b = s3("GET", "svconly/secret-name.txt", s3port)
    ok(st in (403, 404) and b"svc-only-secret" not in (b or b""),
       f"S3 GET key into svc-only dir DENIED (HTTP {st})")
    st, _ = s3("PUT", "bobsecret/inject.txt", s3port, data=b"x\n")
    ok(st not in (200, 201)
       and not os.path.exists(os.path.join(data, "bobsecret", "inject.txt")),
       f"S3 PUT key into bob's 0700 dir DENIED (HTTP {st})")
    st, _ = s3("PUT", "svconly/inject.txt", s3port, data=b"x\n")
    ok(st not in (200, 201)
       and not os.path.exists(os.path.join(data, "svconly", "inject.txt")),
       f"S3 PUT key into svc-only dir DENIED (HTTP {st})")

    # Full multipart lifecycle self: initiate -> upload part -> list parts -> abort
    # (the staging dir + parts must be alice-owned; abort cleans up).
    st_i, bdy = s3("POST", "alice/mpu_life.bin", s3port, params={"uploads": ""})
    m = re.search(rb"<UploadId>([^<]+)</UploadId>", bdy or b"")
    if st_i == 200 and m:
        up = m.group(1).decode()
        st_p, _ = s3("PUT", "alice/mpu_life.bin", s3port,
                     params={"uploadId": up, "partNumber": "1"}, data=b"Z" * 2048)
        ok(st_p in (200, 201), f"S3 multipart UploadPart self (HTTP {st_p})")
        # the staging dir is created under alice/ as alice
        stg = os.path.join(data, "alice")
        mpu_dirs = [d for d in os.listdir(stg) if "mpu" in d and d.startswith(".")]
        owned = all(os.stat(os.path.join(stg, d)).st_uid == UID_ALICE for d in mpu_dirs) \
            if mpu_dirs else True
        ok(owned, "S3 multipart staging dir owned by alice")
        st_l, _ = s3("GET", "alice/mpu_life.bin", s3port, params={"uploadId": up})
        ok(st_l in (200, 404), f"S3 ListParts self (HTTP {st_l})")
        st_a, _ = s3("DELETE", "alice/mpu_life.bin", s3port, params={"uploadId": up})
        ok(st_a in (200, 204), f"S3 AbortMultipartUpload self (HTTP {st_a})")
    else:
        ok(False, f"S3 multipart initiate self failed (HTTP {st_i})")

    # ListMultipartUploads must not crash / leak another tenant's keys (the alice
    # key only ever lists as alice, but verify it does not enumerate via symlink).
    st, b = s3("GET", "", s3port, params={"uploads": ""})
    ok(st in (200, 404) and b"escape/" not in (b or b""),
       f"S3 ListMultipartUploads no symlink-escape (HTTP {st})")


LOCKINFO = (b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:">'
            b'<D:lockscope><D:exclusive/></D:lockscope>'
            b'<D:locktype><D:write/></D:locktype></D:lockinfo>')
PROPFIND_BODY = (b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
                 b'<D:prop><D:displayname/></D:prop></D:propfind>')


def run_webdav_methods(key, data, port):
    """Exhaustive WebDAV METHOD coverage under impersonation: the less-obvious
    methods (HEAD/OPTIONS/UNLOCK/COPY-collection/Overwrite/Depth) for self
    ownership + cross-tenant DAC + lock-token theft."""
    ta, tb = mint(key, "alice"), mint(key, "bob")

    # HEAD: own file 200; bob's 0600 must never return the BODY (metadata may show).
    http("PUT", "/alice/head.txt", port, ta, b"head-body\n")
    st, b = http("HEAD", "/alice/head.txt", port, ta)
    ok(st == 200 and not b, f"WebDAV HEAD own file (HTTP {st}, no body)")
    st, b = http("HEAD", "/bob/private.txt", port, ta)
    ok(b"BOB-PRIVATE-SECRET" not in (b or b""), f"WebDAV HEAD bob's 0600 no body leak (HTTP {st})")

    # OPTIONS: advertises DAV/Allow; no body, no side effect.
    st, _ = http("OPTIONS", "/alice/", port, ta)
    ok(st in (200, 204), f"WebDAV OPTIONS (HTTP {st})")

    # UNLOCK lock-token theft: alice locks her file; bob tries UNLOCK with the
    # stolen token -> must FAIL (the removexattr runs as bob on alice's file).
    http("PUT", "/alice/lk_steal.txt", port, ta, b"x\n")
    st, lb = http("LOCK", "/alice/lk_steal.txt", port, ta, data=LOCKINFO,
                  hdrs={"Content-Type": "application/xml", "Timeout": "Second-600"})
    m = re.search(rb"<D:href>(opaquelocktoken:[^<]+)</D:href>", lb or b"")
    if st in (200, 201) and m:
        tok = m.group(1).decode()
        st_u, _ = http("UNLOCK", "/alice/lk_steal.txt", port, tb,
                       hdrs={"Lock-Token": f"<{tok}>"})
        ok(st_u not in (200, 204),
           f"WebDAV UNLOCK of alice's lock by bob (stolen token) DENIED (HTTP {st_u})")
    else:
        ok(False, f"WebDAV LOCK setup for theft test failed (HTTP {st})")

    # PROPFIND Depth:0 on a file -> just the file (no children); Depth:1 on a dir.
    st, b = http("PROPFIND", "/alice/head.txt", port, ta, data=PROPFIND_BODY,
                 hdrs={"Depth": "0", "Content-Type": "application/xml"})
    ok(st in (207, 200), f"WebDAV PROPFIND Depth:0 on file (HTTP {st})")

    # COPY collection (recursive): alice copies her own dir tree -> owned by alice.
    http("MKCOL", "/alice/coll_src", port, ta)
    http("PUT", "/alice/coll_src/inner.txt", port, ta, b"inner\n")
    st, _ = http("COPY", "/alice/coll_src", port, ta,
                 hdrs={"Destination": f"http://127.0.0.1:{port}/alice/coll_dst",
                       "Depth": "infinity"})
    cdst = os.path.join(data, "alice", "coll_dst")
    inner = os.path.join(cdst, "inner.txt")
    ok(st in (201, 204) and os.path.isdir(cdst) and os.stat(cdst).st_uid == UID_ALICE
       and (not os.path.exists(inner) or os.stat(inner).st_uid == UID_ALICE),
       f"WebDAV COPY collection owned by alice (HTTP {st})")

    # COPY/MOVE Overwrite:F over an existing file -> 412 (no clobber); Overwrite:T ok.
    http("PUT", "/alice/ow_src.txt", port, ta, b"src\n")
    http("PUT", "/alice/ow_dst.txt", port, ta, b"dst\n")
    st, _ = http("COPY", "/alice/ow_src.txt", port, ta,
                 hdrs={"Destination": f"http://127.0.0.1:{port}/alice/ow_dst.txt",
                       "Overwrite": "F"})
    ok(st in (412, 409, 403), f"WebDAV COPY Overwrite:F over existing -> refused (HTTP {st})")

    # cross-tenant Overwrite:T MOVE/COPY over bob's file -> denied.
    http("PUT", "/alice/ow_x.txt", port, ta, b"x\n")
    st, _ = http("COPY", "/alice/ow_x.txt", port, ta,
                 hdrs={"Destination": f"http://127.0.0.1:{port}/bob/readable.txt",
                       "Overwrite": "T"})
    bread = os.path.join(data, "bob", "readable.txt")
    ok(st not in (201, 204) and open(bread, "rb").read() == b"bob-world-readable\n",
       f"WebDAV COPY Overwrite:T over bob's file DENIED (HTTP {st})")


def run_webdav_errors(key, data, port):
    """WebDAV protocol/header/error modes combined with impersonation: conditional
    headers, Range, keep-alive identity reuse, malformed/oversized bodies, chunked,
    unknown methods, double-encoding.  Fail = a cross-tenant/worker/leak/escape."""
    ta, tb = mint(key, "alice"), mint(key, "bob")
    bpriv = os.path.join(data, "bob", "private.txt")

    # Conditional GET on bob's 0600 must STILL be denied (conditional must not be
    # evaluated as a confidentiality oracle before the DAC gate, nor leak body).
    for hdr in [{"If-Match": "*"}, {"If-None-Match": "*"},
                {"If-None-Match": '"x"'}, {"If-Modified-Since": "Thu, 01 Jan 1970 00:00:00 GMT"},
                {"Range": "bytes=0-4"}, {"If-Range": '"x"', "Range": "bytes=0-4"}]:
        st, b = http("GET", "/bob/private.txt", port, ta, hdrs=hdr)
        ok(b"BOB-PRIVATE-SECRET" not in (b or b""),
           f"WebDAV GET bob's 0600 with {list(hdr)[0]} no leak (HTTP {st})")

    # Range on own file: valid range serves a slice; invalid ranges don't crash.
    http("PUT", "/alice/rng.txt", port, ta, b"0123456789")
    st, b = http("GET", "/alice/rng.txt", port, ta, hdrs={"Range": "bytes=0-3"})
    ok(st in (206, 200), f"WebDAV Range valid on own file (HTTP {st})")
    for rng in ["bytes=8-2", "bytes=99-200", "bytes=-3"]:
        st, _ = http("GET", "/alice/rng.txt", port, ta, hdrs={"Range": rng})
        ok(st in (200, 206, 416), f"WebDAV Range '{rng}' handled (HTTP {st})")

    # KEEP-ALIVE principal boundary: alice PUT then bob PUT on ONE connection ->
    # each lands in the correct owner's space (no leaked principal across the pair).
    res = http_keepalive([
        ("PUT", "/alice/ka_a.txt", ta, b"a\n", {}),
        ("PUT", "/bob/ka_b.txt", tb, b"b\n", {}),
    ], port)
    fa = os.path.join(data, "alice", "ka_a.txt")
    fb = os.path.join(data, "bob", "ka_b.txt")
    ok(os.path.exists(fa) and os.stat(fa).st_uid == UID_ALICE
       and os.path.exists(fb) and os.stat(fb).st_uid == UID_BOB,
       "WebDAV keep-alive alice-then-bob: each owned correctly (no principal leak)")
    # keep-alive cross-tenant: alice PUT then bob PUT INTO alice's dir -> denied,
    # even reusing the connection where alice's principal was just active.
    res = http_keepalive([
        ("PUT", "/alice/ka_ok.txt", ta, b"x\n", {}),
        ("PUT", "/alice/ka_evil.txt", tb, b"X\n", {}),
    ], port)
    ok(not os.path.exists(os.path.join(data, "alice", "ka_evil.txt")),
       "WebDAV keep-alive: bob's write into alice's dir DENIED (no stale principal)")

    # Malformed / hostile bodies must not crash the worker (follow-up request OK).
    bad_bodies = {
        "truncated XML PROPFIND": b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:"><D:prop',
        "billion-laughs PROPFIND": (b'<?xml version="1.0"?><!DOCTYPE x [<!ENTITY a "aaaaaaaaaa">'
                                    b'<!ENTITY b "&a;&a;&a;&a;&a;&a;&a;&a;&a;&a;">]>'
                                    b'<D:propfind xmlns:D="DAV:"><D:prop>&b;</D:prop></D:propfind>'),
        "oversized PROPFIND body": b'<D:propfind xmlns:D="DAV:"><x>' + b"A" * 200000 + b'</x></D:propfind>',
    }
    for label, body in bad_bodies.items():
        http("PROPFIND", "/alice/", port, ta, data=body,
             hdrs={"Depth": "0", "Content-Type": "application/xml"})
    st, _ = http("GET", "/alice/rng.txt", port, ta)
    ok(st == 200, "WebDAV worker survived malformed/oversized bodies (follow-up GET OK)")

    # Unknown method + double-encoded traversal Destination.
    st, _ = http("XYZZY", "/alice/", port, ta)
    ok(st in (405, 501, 400), f"WebDAV unknown method rejected (HTTP {st})")
    outside = os.path.join(os.path.dirname(data), "OUTSIDE_DE")
    http("PUT", "/alice/de_src.txt", port, ta, b"x\n")
    http("COPY", "/alice/de_src.txt", port, ta,
         hdrs={"Destination": f"http://127.0.0.1:{port}/%252e%252e/OUTSIDE_DE"})
    ok(not os.path.exists(outside), "WebDAV double-encoded ../ Destination blocked")


def run_cross_cutting(key, data, port, s3port):
    """Cross-PROTOCOL identity boundaries + erroring connections under
    impersonation.  A file's owner must hold whichever protocol reads/writes it."""
    ta, tb = mint(key, "alice"), mint(key, "bob")

    # alice creates via WebDAV; bob must not read it via S3 or root:// (and the
    # file stays alice-owned).  Make it 0600 so cross-tenant read is a real test.
    http("PUT", "/alice/xp_secret.txt", port, ta, b"ALICE-XPROTO-SECRET\n")
    fp = os.path.join(data, "alice", "xp_secret.txt")
    if os.path.exists(fp):
        os.chmod(fp, 0o600)
    ok(os.path.exists(fp) and os.stat(fp).st_uid == UID_ALICE,
       "cross-protocol: WebDAV-created file owned by alice")
    if s3port:
        # bob can't reach it via S3 (his key maps to bob — but the alice S3 endpoint
        # always maps to alice; so use alice-key reading her own = control, and a
        # root:// bob read for the cross-tenant deny).
        st, b = s3("GET", "alice/xp_secret.txt", s3port)   # alice endpoint == alice
        ok(st == 200 and b"ALICE-XPROTO-SECRET" in (b or b""),
           f"cross-protocol: alice reads her WebDAV file via S3 (HTTP {st})")
    if xrd_avail():
        rc, out, _e = xrd_fs(["cat", "/alice/xp_secret.txt"], "bob")
        ok(rc != 0 and "ALICE-XPROTO-SECRET" not in (out or ""),
           f"cross-protocol: bob CANNOT read alice's 0600 file via root:// (rc={rc})")
        # bob writes via root://; alice must not read it via WebDAV.
        lf = os.path.join(WORK, "xp_bob.bin")
        with open(lf, "wb") as fh:
            fh.write(b"BOB-XPROTO-SECRET\n")
        xrd_cp_up(lf, "/bob/xp_bob.bin", "bob")
        os.chmod(os.path.join(data, "bob", "xp_bob.bin"), 0o600) \
            if os.path.exists(os.path.join(data, "bob", "xp_bob.bin")) else None
        st, b = http("GET", "/bob/xp_bob.bin", port, ta)
        ok(b"BOB-XPROTO-SECRET" not in (b or b""),
           f"cross-protocol: alice CANNOT read bob's root://-written 0600 via WebDAV (HTTP {st})")

    # Erroring connections must not breach / hang the worker.  A FIFO in the export:
    # a GET/PUT on it must not hang (broker opens O_NONBLOCK) and must fail closed.
    fifo = os.path.join(data, "alice", "afifo")
    try:
        if not os.path.exists(fifo):
            os.mkfifo(fifo, 0o600)
            os.chown(fifo, UID_ALICE, UID_ALICE)
    except OSError:
        fifo = None
    if fifo:
        st, _ = http("GET", "/alice/afifo", port, ta)   # must return, not hang
        ok(True, f"WebDAV GET on a FIFO did not hang the worker (HTTP {st})")
    # A dangling symlink: stat/GET must be handled (no crash), not followed out.
    dang = os.path.join(data, "alice", "dangle")
    try:
        if not os.path.exists(dang):
            os.symlink("/nonexistent/target", dang)
    except OSError:
        dang = None
    if dang:
        st, _ = http("GET", "/alice/dangle", port, ta)
        ok(st not in (200,), f"WebDAV GET dangling symlink handled (HTTP {st})")
    # follow-up op proves the worker survived the erroring connections.
    st, _ = http("GET", "/alice/xp_secret.txt", port, ta)
    ok(st == 200, "worker survived FIFO / dangling-symlink requests")


def run_auth_matrix(key, data, port):
    """Forged/invalid bearer tokens must be rejected uniformly across BOTH
    token-authenticated planes (WebDAV + root://) under impersonation — a token
    that fails validation must never reach the broker as a mapped principal, and
    must neither read nor create anything.  A positive control proves the same
    paths accept a good token."""
    ta = mint(key, "alice")
    http("PUT", "/alice/auth_probe.txt", port, ta, b"auth-probe-body\n")

    # Positive control: a valid token reads its own file.
    st, b = http("GET", "/alice/auth_probe.txt", port, ta)
    ok(st == 200 and b"auth-probe-body" in (b or b""),
       f"auth control: valid token reads own file (HTTP {st})")

    for label, tok in _forged_tokens(key):
        # WebDAV READ must be denied and must NOT leak the body.
        st, b = http("GET", "/alice/auth_probe.txt", port, tok)
        ok(st in (401, 403) and b"auth-probe-body" not in (b or b""),
           f"WebDAV {label} token rejected on GET (HTTP {st})")
        # WebDAV WRITE must be denied and must NOT create the file.
        evil = f"/alice/evil_{label}.txt"
        http("PUT", evil, port, tok, b"X\n")
        ok(not os.path.exists(os.path.join(data, "alice", f"evil_{label}.txt")),
           f"WebDAV {label} token cannot create a file")

    # Empty-scope token: this module's model is authn->identity, DAC for reads,
    # explicit write-scope for mutations.  So an empty-scope token authenticates
    # as alice and MAY read her own file (DAC permits) but MUST NOT write and MUST
    # NOT read another tenant (DAC backstops).  Verify all three.
    nos = mint(key, "alice", scope="")
    st, b = http("GET", "/alice/auth_probe.txt", port, nos)
    ok(st == 200 and b"auth-probe-body" in (b or b""),
       f"empty-scope token authenticates + reads own file via DAC (HTTP {st})")
    http("PUT", "/alice/evil_noscope.txt", port, nos, b"X\n")
    ok(not os.path.exists(os.path.join(data, "alice", "evil_noscope.txt")),
       "empty-scope token cannot WRITE (no write scope)")
    st, b = http("GET", "/bob/private.txt", port, nos)
    ok(b"BOB-PRIVATE-SECRET" not in (b or b""),
       f"empty-scope token cannot read bob's 0600 (DAC backstop) (HTTP {st})")

    # root:// plane: the same forged tokens must fail (subset — the heavy ones).
    if xrd_avail():
        for label, tok in _forged_tokens(key):
            if label in ("not-yet-valid", "wrong-audience", "garbage"):
                continue   # keep the native-client matrix tight
            rc, out, _e = xrd_fs_token(["stat", "/alice/auth_probe.txt"], tok)
            ok(rc != 0, f"root:// {label} token rejected on stat (rc={rc})")


def run_root_deep(key, data, port):
    """Per-subcommand root:// (stream) matrix under impersonation: every metadata
    + data op as the mapped user, each in a self-success and a cross-tenant-deny
    variant.  The native client drives the real wire protocol, so this exercises
    the stream dispatch path the HTTP planes never touch."""
    if not xrd_avail():
        ok(True, "root:// deep matrix skipped (native client absent)")
        return

    bobpriv = os.path.join(data, "bob", "private.txt")           # 0600 bob
    bobread = os.path.join(data, "bob", "readable.txt")          # 0644 bob

    # seed an alice-owned file via the data plane (write path).
    lf = os.path.join(WORK, "rd_seed.bin")
    with open(lf, "wb") as fh:
        fh.write(b"ALICE-ROOT-DEEP\n")
    rc, _o, _e = xrd_cp_up(lf, "/alice/rd_self.bin", "alice")
    ok(rc == 0 and os.path.exists(os.path.join(data, "alice", "rd_self.bin")),
       f"root:// xrdcp write own file (rc={rc})")
    sf = os.path.join(data, "alice", "rd_self.bin")
    ok(os.path.exists(sf) and os.stat(sf).st_uid == UID_ALICE,
       "root:// written file owned by alice")

    # cat self vs bob's 0600.
    dl = os.path.join(WORK, "rd_self_dl.bin")
    rc, _o, _e = xrd_cp_down("/alice/rd_self.bin", dl, "alice")
    ok(rc == 0 and os.path.exists(dl) and open(dl, "rb").read() == b"ALICE-ROOT-DEEP\n",
       f"root:// xrdcp read own file byte-exact (rc={rc})")
    rc, out, _e = xrd_fs(["cat", "/bob/private.txt"], "alice")
    ok(rc != 0 and "BOB-PRIVATE-SECRET" not in (out or ""),
       f"root:// cat bob's 0600 DENIED (rc={rc})")
    dlx = os.path.join(WORK, "rd_steal.bin")
    rc, _o, _e = xrd_cp_down("/bob/private.txt", dlx, "alice")
    ok(rc != 0 and not (os.path.exists(dlx)
                        and b"BOB-PRIVATE-SECRET" in open(dlx, "rb").read()),
       f"root:// xrdcp read bob's 0600 DENIED (rc={rc})")

    # stat self ok (a 0644 sibling is fine); bob's 0600 stat may succeed (metadata
    # is not secret) but reading was already proven denied above.
    rc, _o, _e = xrd_fs(["stat", "/alice/rd_self.bin"], "alice")
    ok(rc == 0, f"root:// stat own file (rc={rc})")

    # mkdir self + ownership; mkdir into bob's 0700 dir denied.
    rc, _o, _e = xrd_fs(["mkdir", "/alice/rd_dir"], "alice")
    nd = os.path.join(data, "alice", "rd_dir")
    ok(rc == 0 and os.path.isdir(nd) and os.stat(nd).st_uid == UID_ALICE,
       f"root:// mkdir own dir owned by alice (rc={rc})")
    rc, _o, _e = xrd_fs(["mkdir", "/bobsecret/intrude"], "alice")
    ok(rc != 0 and not os.path.exists(os.path.join(data, "bobsecret", "intrude")),
       f"root:// mkdir into bob's 0700 dir DENIED (rc={rc})")

    # write into bob's dir via the data plane denied.
    rc, _o, _e = xrd_cp_up(lf, "/bobsecret/intrude.bin", "alice")
    ok(rc != 0 and not os.path.exists(os.path.join(data, "bobsecret", "intrude.bin")),
       f"root:// xrdcp write into bob's 0700 dir DENIED (rc={rc})")

    # rm: own file ok; bob's 0644 file denied (DAC: no write on bob's dir).
    rc, _o, _e = xrd_fs(["rm", "/bob/readable.txt"], "alice")
    ok(rc != 0 and os.path.exists(bobread),
       f"root:// rm bob's file DENIED, file intact (rc={rc})")
    rc, _o, _e = xrd_fs(["rm", "/alice/rd_self.bin"], "alice")
    ok(rc == 0 and not os.path.exists(sf), f"root:// rm own file (rc={rc})")

    # mv: bob's file out of bob's dir denied (still present, original name).
    rc, _o, _e = xrd_fs(["mv", "/bob/readable.txt", "/alice/stolen.txt"], "alice")
    ok(rc != 0 and os.path.exists(bobread)
       and not os.path.exists(os.path.join(data, "alice", "stolen.txt")),
       f"root:// mv bob's file into alice's dir DENIED (rc={rc})")

    # truncate bob's file denied (content length unchanged).
    before = os.path.getsize(bobread)
    rc, _o, _e = xrd_fs(["truncate", "/bob/readable.txt", "0"], "alice")
    ok(rc != 0 and os.path.getsize(bobread) == before,
       f"root:// truncate bob's file DENIED, size intact (rc={rc})")

    # chmod bob's file denied (mode unchanged).
    mode_before = os.stat(bobpriv).st_mode & 0o777
    rc, _o, _e = xrd_fs(["chmod", "/bob/private.txt", "666"], "alice")
    ok(rc != 0 and (os.stat(bobpriv).st_mode & 0o777) == mode_before,
       f"root:// chmod bob's file DENIED, mode intact (rc={rc})")

    # locate / query checksum on own file should work; on bob's 0600 must not leak.
    rc, _o, _e = xrd_fs(["query", "checksum", "/bob/private.txt"], "alice")
    ok(rc != 0, f"root:// query checksum of bob's 0600 DENIED (rc={rc})")


def _delete_xml(keys):
    body = b'<?xml version="1.0"?><Delete>'
    for k in keys:
        body += b"<Object><Key>" + k.encode() + b"</Key></Object>"
    return body + b"</Delete>"


def run_s3_deep(key, data, s3port):
    """Deep S3 surface under impersonation: CopyObject + UploadPartCopy with a
    cross-tenant source, DeleteObjects batch, Range/conditional confidentiality,
    ListObjectsV2 prefix/delimiter, and anonymous access — each a DAC boundary."""
    # seed objects.
    s3("PUT", "alice/cp_src.txt", s3port, data=b"alice-copy-source\n")

    # CopyObject self: copy alice/cp_src -> alice/cp_dst, owned by alice.
    st, _ = s3("PUT", "alice/cp_dst.txt", s3port,
               extra_hdrs={"x-amz-copy-source": f"/{S3_BUCKET}/alice/cp_src.txt"})
    cpd = os.path.join(data, "alice", "cp_dst.txt")
    ok(st in (200, 201) and os.path.exists(cpd) and os.stat(cpd).st_uid == UID_ALICE,
       f"S3 CopyObject self owned by alice (HTTP {st})")

    # CopyObject cross-tenant SOURCE: copy bob/private.txt -> alice/stolen.  The
    # broker reads the source as alice; bob's 0600 denies it -> no theft.
    st, _ = s3("PUT", "alice/stolen.txt", s3port,
               extra_hdrs={"x-amz-copy-source": f"/{S3_BUCKET}/bob/private.txt"})
    stolen = os.path.join(data, "alice", "stolen.txt")
    leaked = os.path.exists(stolen) and b"BOB-PRIVATE-SECRET" in open(stolen, "rb").read()
    ok(st not in (200, 201) and not leaked,
       f"S3 CopyObject cross-tenant source DENIED, no theft (HTTP {st})")

    # DeleteObjects batch: deleting bob's file must not remove it (DAC on bob's dir).
    bobread = os.path.join(data, "bob", "readable.txt")
    s3("POST", "", s3port, params={"delete": ""},
       data=_delete_xml(["bob/readable.txt"]))
    ok(os.path.exists(bobread),
       "S3 DeleteObjects of bob's file did not delete it")
    # DeleteObjects self: delete alice's own object works.
    s3("PUT", "alice/del_me.txt", s3port, data=b"x\n")
    s3("POST", "", s3port, params={"delete": ""}, data=_delete_xml(["alice/del_me.txt"]))
    ok(not os.path.exists(os.path.join(data, "alice", "del_me.txt")),
       "S3 DeleteObjects of own object succeeded")

    # GetObject Range + conditional on bob's 0600 must never leak the body.
    for label, hdr in [("Range", {"Range": "bytes=0-4"}),
                       ("If-Match", {"If-Match": "*"}),
                       ("If-None-Match", {"If-None-Match": '"x"'})]:
        h = s3_sign("GET", f"/{S3_BUCKET}/bob/private.txt", s3port)
        h.update(hdr)
        st, b = http("GET", f"/{S3_BUCKET}/bob/private.txt", s3port, hdrs=h)
        ok(b"BOB-PRIVATE-SECRET" not in (b or b""),
           f"S3 GET bob's 0600 with {label} no body leak (HTTP {st})")

    # ListObjectsV2 prefix/delimiter must not enumerate the symlink-escape or other
    # tenants' private subtrees.
    st, b = s3("GET", "", s3port, params={"list-type": "2", "prefix": "", "delimiter": "/"})
    ok(b"escape/" not in (b or b"") and b"secret-name.txt" not in (b or b""),
       f"S3 ListObjectsV2 delimiter no escape/secret leak (HTTP {st})")
    st, b = s3("GET", "", s3port, params={"list-type": "2", "prefix": "bobsecret/"})
    ok(b"BOB-PRIVATE" not in (b or b"") and b"bobsecret/inject" not in (b or b""),
       f"S3 ListObjectsV2 prefix into bob's 0700 no leak (HTTP {st})")

    # Anonymous (no SigV4) request must be denied.
    st, _ = http("GET", f"/{S3_BUCKET}/alice/cp_src.txt", s3port)
    ok(st in (401, 403), f"S3 anonymous GET denied (HTTP {st})")

    # UploadPartCopy cross-tenant source: initiate own MPU, then try to copy a part
    # from bob's 0600 object -> denied (no part written from bob's data).
    st_i, bdy = s3("POST", "alice/upc.bin", s3port, params={"uploads": ""})
    m = re.search(rb"<UploadId>([^<]+)</UploadId>", bdy or b"")
    if st_i == 200 and m:
        up = m.group(1).decode()
        st, _ = s3("PUT", "alice/upc.bin", s3port,
                   params={"uploadId": up, "partNumber": "1"},
                   extra_hdrs={"x-amz-copy-source": f"/{S3_BUCKET}/bob/private.txt"})
        ok(st not in (200, 201), f"S3 UploadPartCopy cross-tenant source DENIED (HTTP {st})")
        s3("DELETE", "alice/upc.bin", s3port, params={"uploadId": up})
    else:
        ok(True, "S3 UploadPartCopy setup skipped (initiate unsupported)")


def run_traversal_matrix(key, data, port, s3port):
    """Path-traversal / encoding / NUL across every protocol under impersonation.
    The broker re-applies RESOLVE_BENEATH, so escapes must fail closed and never
    return a byte of /etc/passwd or write outside the export."""
    ta = mint(key, "alice")
    outside_dir = os.path.dirname(os.path.dirname(os.path.abspath(data)))

    # WebDAV GET traversal variants — none may return root:x: from /etc/passwd.
    wd_paths = [
        "/../../../../etc/passwd",
        "/alice/../../../../etc/passwd",
        "/%2e%2e/%2e%2e/etc/passwd",
        "/alice/%2e%2e%2f%2e%2e%2fetc/passwd",
        "/..%2f..%2f..%2fetc/passwd",
        "/alice/....//....//etc/passwd",
    ]
    for p in wd_paths:
        st, b = http("GET", p, port, ta)
        ok(b"root:x:" not in (b or b"") and b"root:!" not in (b or b""),
           f"WebDAV traversal GET {p[:28]!r} no /etc/passwd leak (HTTP {st})")

    # WebDAV PUT/MKCOL escapes must not create anything outside the export.
    http("PUT", "/../OUTSIDE_WD.txt", port, ta, b"x\n")
    http("PUT", "/alice/../../OUTSIDE_WD2.txt", port, ta, b"x\n")
    ok(not os.path.exists(os.path.join(outside_dir, "OUTSIDE_WD.txt"))
       and not os.path.exists(os.path.join(outside_dir, "OUTSIDE_WD2.txt")),
       "WebDAV traversal PUT created nothing outside the export")

    # S3 key traversal — keys that try to climb out of the bucket root.
    for k in ["../../../etc/passwd", "..%2f..%2f..%2fetc%2fpasswd",
              "alice/../../../etc/passwd", "....//....//etc/passwd"]:
        st, b = s3("GET", k, s3port)
        ok(b"root:x:" not in (b or b""),
           f"S3 traversal key {k[:24]!r} no /etc/passwd leak (HTTP {st})")
    st, _ = s3("PUT", "../../../tmp/OUTSIDE_S3.txt", s3port, data=b"x\n")
    ok(not os.path.exists("/tmp/OUTSIDE_S3.txt"),
       "S3 traversal PUT created nothing outside the export")

    # root:// traversal — stat/cat an escaping path must fail, no passwd leak.
    if xrd_avail():
        for p in ["/../../../../etc/passwd", "/alice/../../../etc/passwd"]:
            rc, out, _e = xrd_fs(["cat", p], "alice")
            ok(rc != 0 and "root:x:" not in (out or ""),
               f"root:// traversal cat {p[:24]!r} DENIED (rc={rc})")
        dlp = os.path.join(WORK, "trav_pw.bin")
        rc, _o, _e = xrd_cp_down("/../../../../etc/passwd", dlp, "alice")
        leaked = os.path.exists(dlp) and b"root:x:" in open(dlp, "rb").read()
        ok(rc != 0 and not leaked, f"root:// xrdcp traversal read DENIED (rc={rc})")


def run_root_protocol_depth(key, data, port, s3port):
    """root:// STREAM protocol DEPTH under impersonation — combinatorial xrdfs/xrdcp
    matrix that goes deeper than run_root_battery / run_root_deep.  Exhaustively
    drives open modes (new / update / truncate-shrink / re-write / read-only) and
    their resulting ownership, query checksum/config/space/xattr (self vs bob 0600,
    no body leak), locate, stat self vs cross-tenant, nested mkdir + per-level
    ownership, rmdir non-empty-vs-empty (self + bob), mv within-tenant /
    cross-tenant-source / into-svconly, chmod own (mode actually changes) vs bob
    (denied, mode intact), truncate own vs bob, pub/ (0777 shared) write owned by
    the WRITER, read-then-delete, query xattr of user.* on own file, and a burst of
    sequential small files all owned by the mapping user.  Every mutating op has a
    self-success POSITIVE CONTROL beside its cross-tenant/escalation DENY so a
    blanket block cannot false-pass.  GUARDED by xrd_avail()."""
    if not xrd_avail():
        ok(True, "root:// protocol-depth skipped (native xrdfs/xrdcp absent)")
        return

    A, B = "alice", "bob"
    MARK_BOB = b"BOB-PRIVATE-SECRET"          # planted in data/bob/private.txt (0600)
    MARK_SVC = b"svc-only-secret"             # planted in data/svconly/secret-name.txt

    def realp(rel):
        return os.path.join(data, rel.lstrip("/"))

    def uid_of(rel):
        fp = realp(rel)
        try:
            return os.stat(fp).st_uid if os.path.exists(fp) else -1
        except OSError:
            return -1

    def mode_of(rel):
        fp = realp(rel)
        try:
            return (os.stat(fp).st_mode & 0o777) if os.path.exists(fp) else -1
        except OSError:
            return -1

    def size_of(rel):
        fp = realp(rel)
        try:
            return os.path.getsize(fp) if os.path.exists(fp) else -1
        except OSError:
            return -1

    def local(name, content=b""):
        lp = os.path.join(WORK, "rpd_" + name)
        try:
            with open(lp, "wb") as fh:
                fh.write(content)
        except OSError:
            pass
        return lp

    # ---- seed local payloads of distinct sizes (open-mode matrix) ---------------
    BIG = b"RPD-OPEN-MODE-PAYLOAD-0123456789\n" * 64     # ~2 KiB
    SMALL = b"rpd-small\n"
    lf_big = local("big.bin", BIG)
    lf_small = local("small.bin", SMALL)

    # =====================================================================
    # (A) OPEN-MODE / OWNERSHIP MATRIX  (new file -> update -> shrink -> regrow)
    # =====================================================================
    # (A1) NEW FILE create via data plane -> owned by alice, byte-exact size.
    rc, _o, e = xrd_cp_up(lf_big, "/alice/rpd_om.bin", A)
    ok(rc == 0 and uid_of("/alice/rpd_om.bin") == UID_ALICE
       and size_of("/alice/rpd_om.bin") == len(BIG),
       f"root:// open(new) write owned by alice, full size (rc={rc}, "
       f"uid={uid_of('/alice/rpd_om.bin')}, sz={size_of('/alice/rpd_om.bin')})")

    # (A2) UPDATE/OVERWRITE existing with a SMALLER payload (-f forces truncate-on-
    #      open).  Same file, still owned by alice, new (smaller) size — proves the
    #      update/truncate open mode re-establishes the principal, not the worker.
    rc, _o, _e = xrd_cp_up(lf_small, "/alice/rpd_om.bin", A)
    ok(rc == 0 and uid_of("/alice/rpd_om.bin") == UID_ALICE
       and size_of("/alice/rpd_om.bin") == len(SMALL),
       f"root:// open(update/truncate) overwrite still alice-owned, shrunk "
       f"(rc={rc}, sz={size_of('/alice/rpd_om.bin')})")

    # (A3) explicit truncate-SHRINK via xrdfs truncate on own file (mutation).
    rc, _o, _e = xrd_fs(["truncate", "/alice/rpd_om.bin", "4"], A)
    ok(rc == 0 and size_of("/alice/rpd_om.bin") == 4
       and uid_of("/alice/rpd_om.bin") == UID_ALICE,
       f"root:// truncate-shrink own file to 4 bytes (rc={rc}, "
       f"sz={size_of('/alice/rpd_om.bin')})")

    # (A4) truncate-GROW (sparse) own file — size grows, ownership unchanged.
    rc, _o, _e = xrd_fs(["truncate", "/alice/rpd_om.bin", "4096"], A)
    ok(rc == 0 and size_of("/alice/rpd_om.bin") == 4096
       and uid_of("/alice/rpd_om.bin") == UID_ALICE,
       f"root:// truncate-grow own file to 4096 (rc={rc}, "
       f"sz={size_of('/alice/rpd_om.bin')})")

    # (A5) READ-ONLY open: download own file byte-exact (read path as alice).
    rc, _o, _e = xrd_cp_up(lf_big, "/alice/rpd_rd.bin", A)
    dl = os.path.join(WORK, "rpd_rd_dl.bin")
    rc2, _o2, _e2 = xrd_cp_down("/alice/rpd_rd.bin", dl, A)
    got = b""
    try:
        got = open(dl, "rb").read() if os.path.exists(dl) else b""
    except OSError:
        got = b""
    ok(rc == 0 and rc2 == 0 and got == BIG,
       f"root:// open(read-only) own file byte-exact (up={rc}, down={rc2})")

    # (A6) bob writes his OWN new file -> owned by BOB, not alice/svc (control that
    #      the open path maps the *token* identity, not a sticky last-principal).
    rc, _o, _e = xrd_cp_up(lf_small, "/bob/rpd_bom.bin", B)
    ok(rc == 0 and uid_of("/bob/rpd_bom.bin") == UID_BOB,
       f"root:// bob's open(new) write owned by bob (rc={rc}, "
       f"uid={uid_of('/bob/rpd_bom.bin')})")

    # =====================================================================
    # (B) QUERY MATRIX — checksum / config / space / xattr  (self vs bob no-leak)
    # =====================================================================
    # (B1) query checksum of OWN file succeeds.
    rc, out, _e = xrd_fs(["query", "checksum", "/alice/rpd_rd.bin"], A)
    ok(rc == 0, f"root:// query checksum own file (rc={rc})")

    # (B2) query checksum of bob's 0600 file: DENIED, and the body must not carry the
    #      secret marker (checksum could leak content/derived data).
    rc, out, _e = xrd_fs(["query", "checksum", "/bob/private.txt"], A)
    ok(rc != 0 and MARK_BOB.decode() not in (out or ""),
       f"root:// query checksum of bob's 0600 DENIED + no leak (rc={rc})")

    # (B3) query checksum of svc-only file: DENIED + no svc secret marker.
    rc, out, _e = xrd_fs(["query", "checksum", "/svconly/secret-name.txt"], A)
    ok(rc != 0 and MARK_SVC.decode() not in (out or ""),
       f"root:// query checksum of svc-only file DENIED + no leak (rc={rc})")

    # (B4) query config of a benign server key works (no path -> no DAC) and does
    #      NOT echo any planted secret.
    rc, out, _e = xrd_fs(["query", "config", "version"], A)
    ok(MARK_BOB.decode() not in (out or "")
       and MARK_SVC.decode() not in (out or ""),
       f"root:// query config does not leak any tenant secret (rc={rc})")

    # (B5) query space of own dir works; of bob's 0600 file must not leak content.
    rc, _o, _e = xrd_fs(["query", "space", "/alice/"], A)
    ok(rc == 0, f"root:// query space own dir (rc={rc})")
    rc, out, _e = xrd_fs(["query", "space", "/bob/private.txt"], A)
    ok(MARK_BOB.decode() not in (out or ""),
       f"root:// query space of bob's 0600 leaks no content (rc={rc})")

    # (B6) query xattr (user.* / XrdCks.*) on OWN file — optional feature: accept
    #      unsupported (rc!=0) as handled, but a SUCCESS must carry no foreign secret.
    rc, out, _e = xrd_fs(["query", "xattr", "/alice/rpd_rd.bin"], A)
    ok(MARK_BOB.decode() not in (out or "")
       and MARK_SVC.decode() not in (out or ""),
       f"root:// query xattr own file leaks no foreign secret (rc={rc})")

    # (B7) query xattr on bob's 0600 file — DENIED or unsupported, never the secret.
    rc, out, _e = xrd_fs(["query", "xattr", "/bob/private.txt"], A)
    ok(MARK_BOB.decode() not in (out or ""),
       f"root:// query xattr of bob's 0600 leaks no content (rc={rc})")

    # =====================================================================
    # (C) STAT / STATX / LOCATE  — self vs cross-tenant
    # =====================================================================
    # (C1) stat own file succeeds.
    rc, _o, _e = xrd_fs(["stat", "/alice/rpd_rd.bin"], A)
    ok(rc == 0, f"root:// stat own file (rc={rc})")

    # (C2) stat bob's world-readable 0644 file: metadata is not secret -> may succeed,
    #      but the stat output must not leak the PRIVATE file's secret bytes.
    rc, out, _e = xrd_fs(["stat", "/bob/readable.txt"], A)
    ok(MARK_BOB.decode() not in (out or ""),
       f"root:// stat bob's 0644 file leaks no private content (rc={rc})")

    # (C3) stat a NON-EXISTENT path -> error (no phantom success / no escape).
    rc, _o, _e = xrd_fs(["stat", "/alice/rpd_does_not_exist_xyz"], A)
    ok(rc != 0, f"root:// stat of missing file errors cleanly (rc={rc})")

    # (C4) locate own dir works (positive control for the namespace walk).
    rc, _o, _e = xrd_fs(["locate", "/alice/"], A)
    ok(rc == 0, f"root:// locate own dir (rc={rc})")

    # (C5) locate of bob's secret 0700 dir entry must not leak its protected child.
    rc, out, _e = xrd_fs(["locate", "/bobsecret/s.txt"], A)
    ok("bob-only" not in (out or ""),
       f"root:// locate of bob's 0700 file leaks no content (rc={rc})")

    # =====================================================================
    # (D) NESTED MKDIR + PER-LEVEL OWNERSHIP  (self) and cross-tenant DENY
    # =====================================================================
    # (D1) create a parent then a child; each level owned by alice.
    rc1, _o, _e = xrd_fs(["mkdir", "/alice/rpd_nest"], A)
    rc2, _o, _e = xrd_fs(["mkdir", "/alice/rpd_nest/child"], A)
    ok(rc1 == 0 and rc2 == 0
       and uid_of("/alice/rpd_nest") == UID_ALICE
       and uid_of("/alice/rpd_nest/child") == UID_ALICE,
       f"root:// nested mkdir: every level owned by alice (rc={rc1}/{rc2})")

    # (D2) a file inside the nested dir is owned by alice too (write into own subtree).
    rc, _o, _e = xrd_cp_up(lf_small, "/alice/rpd_nest/child/leaf.bin", A)
    ok(rc == 0 and uid_of("/alice/rpd_nest/child/leaf.bin") == UID_ALICE,
       f"root:// file in nested own dir owned by alice (rc={rc})")

    # (D3) mkdir into bob's 0700 dir -> DENIED, nothing created.
    rc, _o, _e = xrd_fs(["mkdir", "/bobsecret/rpd_intrude"], A)
    ok(rc != 0 and not os.path.exists(realp("/bobsecret/rpd_intrude")),
       f"root:// mkdir into bob's 0700 dir DENIED (rc={rc})")

    # (D4) mkdir into svc-only 0750 dir -> DENIED (alice is other, no write).
    rc, _o, _e = xrd_fs(["mkdir", "/svconly/rpd_intrude"], A)
    ok(rc != 0 and not os.path.exists(realp("/svconly/rpd_intrude")),
       f"root:// mkdir into svc-only 0750 dir DENIED (rc={rc})")

    # =====================================================================
    # (E) RMDIR non-empty vs empty  (self) and cross-tenant DENY
    # =====================================================================
    # (E1) rmdir a NON-EMPTY own dir must FAIL (ENOTEMPTY), dir + child survive.
    rc, _o, _e = xrd_fs(["rmdir", "/alice/rpd_nest"], A)
    ok(rc != 0 and os.path.isdir(realp("/alice/rpd_nest/child")),
       f"root:// rmdir non-empty own dir refused (ENOTEMPTY) (rc={rc})")

    # (E2) empty the subtree leaf-first, then rmdir EMPTY own dirs succeeds.
    xrd_fs(["rm", "/alice/rpd_nest/child/leaf.bin"], A)
    rcA, _o, _e = xrd_fs(["rmdir", "/alice/rpd_nest/child"], A)
    rcB, _o, _e = xrd_fs(["rmdir", "/alice/rpd_nest"], A)
    ok(rcA == 0 and rcB == 0 and not os.path.exists(realp("/alice/rpd_nest")),
       f"root:// rmdir empty own dirs succeeds, tree gone (rc={rcA}/{rcB})")

    # (E3) rmdir bob's secret 0700 dir -> DENIED, dir + secret child intact.
    rc, _o, _e = xrd_fs(["rmdir", "/bobsecret"], A)
    ok(rc != 0 and os.path.isdir(realp("/bobsecret"))
       and os.path.exists(realp("/bobsecret/s.txt")),
       f"root:// rmdir bob's 0700 dir DENIED, intact (rc={rc})")

    # =====================================================================
    # (F) MV  — within-tenant OK / cross-tenant-source DENY / into-svconly DENY
    # =====================================================================
    # (F1) within-tenant rename: src disappears, dst owned by alice, content kept.
    xrd_fs(["rm", "/alice/rpd_mv_src.bin"], A)   # idempotent cleanup
    rc, _o, _e = xrd_cp_up(lf_small, "/alice/rpd_mv_src.bin", A)
    rc2, _o, _e = xrd_fs(["mv", "/alice/rpd_mv_src.bin", "/alice/rpd_mv_dst.bin"], A)
    ok(rc == 0 and rc2 == 0 and uid_of("/alice/rpd_mv_dst.bin") == UID_ALICE
       and not os.path.exists(realp("/alice/rpd_mv_src.bin"))
       and size_of("/alice/rpd_mv_dst.bin") == len(SMALL),
       f"root:// mv within alice's tenant OK, dst alice-owned (rc={rc2})")

    # (F2) cross-tenant SOURCE: mv bob's 0644 file into alice's dir -> DENIED.  The
    #      source removal needs write on bob's dir; bob's file stays put, no copy.
    before_uid = uid_of("/bob/readable.txt")
    rc, _o, _e = xrd_fs(["mv", "/bob/readable.txt", "/alice/rpd_stolen.bin"], A)
    ok(rc != 0 and os.path.exists(realp("/bob/readable.txt"))
       and uid_of("/bob/readable.txt") == before_uid
       and not os.path.exists(realp("/alice/rpd_stolen.bin")),
       f"root:// mv of bob's file (cross-tenant source) DENIED (rc={rc})")

    # (F3) mv own file INTO svc-only 0750 dir as DEST -> DENIED (no write on svconly);
    #      the source file must survive in alice's dir (atomic refusal, no loss).
    rc, _o, _e = xrd_fs(["mv", "/alice/rpd_mv_dst.bin", "/svconly/rpd_planted.bin"], A)
    ok(rc != 0 and os.path.exists(realp("/alice/rpd_mv_dst.bin"))
       and not os.path.exists(realp("/svconly/rpd_planted.bin")),
       f"root:// mv own file INTO svc-only dest DENIED, src kept (rc={rc})")

    # (F4) mv own file into the world-writable pub/ 0777 dir -> OK, owner preserved
    #      (control proving F3's deny is the DEST dir's DAC, not a blanket mv block).
    rc, _o, _e = xrd_fs(["mv", "/alice/rpd_mv_dst.bin", "/pub/rpd_pubmoved.bin"], A)
    ok(rc == 0 and uid_of("/pub/rpd_pubmoved.bin") == UID_ALICE
       and not os.path.exists(realp("/alice/rpd_mv_dst.bin")),
       f"root:// mv own file into pub/ (0777) OK, still alice-owned (rc={rc})")

    # =====================================================================
    # (G) CHMOD  — own (mode actually changes) vs bob (DENIED, mode intact)
    # =====================================================================
    # (G1) chmod own file changes the mode (and to a DIFFERENT value than before).
    xrd_cp_up(lf_small, "/alice/rpd_chmod.bin", A)
    pre = mode_of("/alice/rpd_chmod.bin")
    target = 0o640 if pre != 0o640 else 0o600
    rc, _o, _e = xrd_fs(["chmod", "/alice/rpd_chmod.bin", oct(target)[2:]], A)
    post = mode_of("/alice/rpd_chmod.bin")
    ok(rc == 0 and post == target and post != pre,
       f"root:// chmod own file changes mode {pre:o}->{post:o} (rc={rc})")

    # (G2) chmod bob's PRIVATE 0600 file -> DENIED, mode unchanged (no DAC widening).
    pre_b = mode_of("/bob/private.txt")
    rc, _o, _e = xrd_fs(["chmod", "/bob/private.txt", "666"], A)
    ok(rc != 0 and mode_of("/bob/private.txt") == pre_b and pre_b == 0o600,
       f"root:// chmod bob's 0600 file DENIED, mode intact ({pre_b:o}, rc={rc})")

    # (G3) chmod bob's 0644 file -> DENIED too (alice is not the owner).
    pre_r = mode_of("/bob/readable.txt")
    rc, _o, _e = xrd_fs(["chmod", "/bob/readable.txt", "600"], A)
    ok(rc != 0 and mode_of("/bob/readable.txt") == pre_r,
       f"root:// chmod bob's 0644 file DENIED, mode intact ({pre_r:o}, rc={rc})")

    # =====================================================================
    # (H) TRUNCATE  — own (shrinks) vs bob (DENIED, size intact)
    # =====================================================================
    # (H1) truncate own file to 0 succeeds.
    rc, _o, _e = xrd_fs(["truncate", "/alice/rpd_chmod.bin", "0"], A)
    ok(rc == 0 and size_of("/alice/rpd_chmod.bin") == 0,
       f"root:// truncate own file to 0 (rc={rc})")

    # (H2) truncate bob's 0600 PRIVATE file -> DENIED, size unchanged.
    sz_b = size_of("/bob/private.txt")
    rc, _o, _e = xrd_fs(["truncate", "/bob/private.txt", "0"], A)
    ok(rc != 0 and size_of("/bob/private.txt") == sz_b and sz_b > 0,
       f"root:// truncate bob's 0600 file DENIED, size intact ({sz_b}, rc={rc})")

    # (H3) truncate bob's 0644 file -> DENIED (no write perm on other's file).
    sz_r = size_of("/bob/readable.txt")
    rc, _o, _e = xrd_fs(["truncate", "/bob/readable.txt", "0"], A)
    ok(rc != 0 and size_of("/bob/readable.txt") == sz_r,
       f"root:// truncate bob's 0644 file DENIED, size intact ({sz_r}, rc={rc})")

    # =====================================================================
    # (I) PUB/ (0777 shared) — write owned by the WRITER (alice vs bob distinct)
    # =====================================================================
    rc, _o, _e = xrd_cp_up(lf_small, "/pub/rpd_alice_pub.bin", A)
    ok(rc == 0 and uid_of("/pub/rpd_alice_pub.bin") == UID_ALICE,
       f"root:// write into pub/ owned by alice the writer (rc={rc})")
    rc, _o, _e = xrd_cp_up(lf_small, "/pub/rpd_bob_pub.bin", B)
    ok(rc == 0 and uid_of("/pub/rpd_bob_pub.bin") == UID_BOB,
       f"root:// write into pub/ owned by bob the writer (rc={rc})")
    # invariant: NEITHER shared-dir file is owned by svc(1500) or root(0).
    ua = uid_of("/pub/rpd_alice_pub.bin")
    ub = uid_of("/pub/rpd_bob_pub.bin")
    ok(ua >= 1000 and ub >= 1000 and ua != UID_SVC and ub != UID_SVC
       and ua != 0 and ub != 0 and ua != ub,
       f"root:// pub/ files owned by distinct mapped users, never svc/root "
       f"(alice={ua}, bob={ub})")

    # =====================================================================
    # (J) READ-then-DELETE lifecycle (own file)
    # =====================================================================
    rc, _o, _e = xrd_cp_up(lf_small, "/alice/rpd_rmlife.bin", A)
    dl2 = os.path.join(WORK, "rpd_rmlife_dl.bin")
    rcd, _o, _e = xrd_cp_down("/alice/rpd_rmlife.bin", dl2, A)
    got2 = b""
    try:
        got2 = open(dl2, "rb").read() if os.path.exists(dl2) else b""
    except OSError:
        got2 = b""
    rcrm, _o, _e = xrd_fs(["rm", "/alice/rpd_rmlife.bin"], A)
    ok(rc == 0 and rcd == 0 and got2 == SMALL and rcrm == 0
       and not os.path.exists(realp("/alice/rpd_rmlife.bin")),
       f"root:// read-then-delete own file lifecycle (up={rc}, down={rcd}, "
       f"rm={rcrm})")

    # alice must NOT be able to rm bob's file (delete needs write on bob's dir).
    rc, _o, _e = xrd_fs(["rm", "/bob/readable.txt"], A)
    ok(rc != 0 and os.path.exists(realp("/bob/readable.txt")),
       f"root:// rm bob's file DENIED, file intact (rc={rc})")

    # =====================================================================
    # (K) ESCALATION via the STREAM data plane — forbidden / unmapped principals
    # =====================================================================
    for sub in ["root", "svc", "sys100", "dockerite", "mallory"]:
        fp_rel = f"/pub/rpd_esc_{sub}.bin"
        rc, _o, _e = xrd_cp_up(lf_small, fp_rel, sub)
        created = os.path.exists(realp(fp_rel))
        bad_owner = created and uid_of(fp_rel) < 1000
        ok(rc != 0 and not created and not bad_owner,
           f"root:// data-plane write as principal '{sub}' DENIED, no file "
           f"(rc={rc}, created={created})")

    # =====================================================================
    # (L) CONFINEMENT via the stream protocol — symlink escape + traversal
    # =====================================================================
    rc, out, _e = xrd_fs(["cat", "/escape/passwd"], A)
    ok("root:x:0:0" not in (out or ""),
       f"root:// cat through /escape symlink did NOT read /etc/passwd (rc={rc})")
    pw = os.path.join(WORK, "rpd_pw.bin")
    rc, _o, _e = xrd_cp_down("/escape/passwd", pw, A)
    leaked_pw = False
    try:
        leaked_pw = os.path.exists(pw) and b"root:x:0:0" in open(pw, "rb").read()
    except OSError:
        leaked_pw = False
    ok(not leaked_pw, f"root:// xrdcp through symlink did NOT exfil /etc/passwd (rc={rc})")
    # traversal in the wire path must not escape (no OUTSIDE sentinel created).
    sentinel = os.path.join(os.path.dirname(data.rstrip("/")), "RPD_OUTSIDE")
    try:
        if os.path.exists(sentinel):
            os.remove(sentinel)
    except OSError:
        pass
    xrd_cp_up(lf_small, "/../RPD_OUTSIDE", A)
    xrd_fs(["mkdir", "/../RPD_OUTSIDE_DIR"], A)
    ok(not os.path.exists(sentinel)
       and not os.path.exists(os.path.join(os.path.dirname(data.rstrip("/")),
                                            "RPD_OUTSIDE_DIR")),
       "root:// traversal (../) did not escape the export root")

    # =====================================================================
    # (M) SEQUENTIAL many-small-files burst — every file owned by the mapping user
    #     (no setfsuid principal drift across back-to-back ops on one worker).
    # =====================================================================
    N = 16
    bad = 0
    for i in range(N):
        rel = f"/alice/rpd_seq_{i}.bin"
        rc, _o, _e = xrd_cp_up(lf_small, rel, A)
        if not (rc == 0 and uid_of(rel) == UID_ALICE):
            bad += 1
    ok(bad == 0,
       f"root:// {N} sequential alice writes all owned by alice (mismatches={bad})")

    # interleave a single bob write in the middle of alice's burst and re-verify a
    # FRESH alice write still lands as alice (principal not stuck on bob).
    xrd_cp_up(lf_small, "/bob/rpd_seq_bob.bin", B)
    rc, _o, _e = xrd_cp_up(lf_small, "/alice/rpd_seq_after_bob.bin", A)
    ok(rc == 0 and uid_of("/alice/rpd_seq_after_bob.bin") == UID_ALICE
       and uid_of("/bob/rpd_seq_bob.bin") == UID_BOB,
       f"root:// alice write after an interleaved bob write stays alice-owned "
       f"(rc={rc})")

    # =====================================================================
    # (N) SECOND-IDENTITY SELF-MATRIX (bob) — full ownership/DAC parity, and the
    #     reverse cross-tenant deny (bob must not touch ALICE's data).
    # =====================================================================
    # (N1) bob creates a private file -> owned by bob.
    rc, _o, _e = xrd_cp_up(lf_small, "/bob/rpd_bself.bin", B)
    ok(rc == 0 and uid_of("/bob/rpd_bself.bin") == UID_BOB,
       f"root:// bob self-write owned by bob (rc={rc})")
    # (N2) bob chmod own file works.
    rc, _o, _e = xrd_fs(["chmod", "/bob/rpd_bself.bin", "600"], B)
    ok(rc == 0 and mode_of("/bob/rpd_bself.bin") == 0o600,
       f"root:// bob chmod own file (rc={rc})")
    # (N3) seed an alice 0600 secret, then prove BOB cannot read/mutate it.
    rcseed, _o, _e = xrd_cp_up(lf_small, "/alice/rpd_asecret.bin", A)
    xrd_fs(["chmod", "/alice/rpd_asecret.bin", "600"], A)
    rc, out, _e = xrd_fs(["cat", "/alice/rpd_asecret.bin"], B)
    ok(rc != 0 and "rpd-small" not in (out or ""),
       f"root:// bob cat alice's 0600 file DENIED + no leak (rc={rc})")
    pre_m = mode_of("/alice/rpd_asecret.bin")
    rc, _o, _e = xrd_fs(["chmod", "/alice/rpd_asecret.bin", "777"], B)
    ok(rc != 0 and mode_of("/alice/rpd_asecret.bin") == pre_m,
       f"root:// bob chmod alice's file DENIED, mode intact ({pre_m:o}, rc={rc})")
    rc, _o, _e = xrd_fs(["rm", "/alice/rpd_asecret.bin"], B)
    ok(rc != 0 and os.path.exists(realp("/alice/rpd_asecret.bin")),
       f"root:// bob rm alice's file DENIED, intact (rc={rc})")

    # =====================================================================
    # (O) FORGED / INVALID raw tokens over the stream protocol — none may map to a
    #     UNIX identity or create a file in the shared pub/ dir.
    # =====================================================================
    for label, tok in _forged_tokens(key):
        rel = f"/pub/rpd_forge.bin"
        try:
            if os.path.exists(realp(rel)):
                os.remove(realp(rel))
        except OSError:
            pass
        rc, _o, _e = xrd_fs_token(["stat", "/alice/"], tok)
        ok(rc != 0,
           f"root:// forged token '{label}' rejected for stat (rc={rc})")

    # =====================================================================
    # (P) WORKER SURVIVES — after all the abuse, a legit alice op still succeeds
    #     (the broker / worker were not wedged by any of the above attacks).
    # =====================================================================
    rc, _o, e = xrd_cp_up(lf_small, "/alice/rpd_survive.bin", A)
    ok(rc == 0 and uid_of("/alice/rpd_survive.bin") == UID_ALICE,
       f"root:// worker SURVIVES the battery; legit alice op still works "
       f"(rc={rc}, {e.strip()[:60]})")
    rc, _o, _e = xrd_fs(["stat", "/alice/rpd_survive.bin"], A)
    ok(rc == 0, f"root:// follow-up stat after survival write OK (rc={rc})")


def run_webdav_method_state(key, data, port, s3port):
    """WebDAV METHOD x HEADER x LOCK-STATE matrix under impersonation.  Deeply
    combines LOCK (exclusive/shared, Timeout, refresh-by-re-LOCK) then the
    state-changing methods (PUT/DELETE/MOVE/PROPPATCH/UNLOCK) by the OWNER
    (must succeed, owned by the mapped user) vs by ANOTHER identity that holds a
    STOLEN lock token (must still be denied by the broker-enforced DAC, even
    though the lock token is structurally valid).  Then the conditional-header
    family (If-Match / If-None-Match / If-Modified-Since / If-Unmodified-Since)
    on the OWNER's own file (positive controls) and as a confidentiality ORACLE
    against bob's 0600 file (must never branch in a way that leaks a byte).
    Finally the protocol-edge surface: Content-Range / partial PUT, chunked
    Transfer-Encoding, Expect: 100-continue, PUT with trailing slash, PUT over a
    collection, nested MKCOL (missing parent -> 409), MOVE/COPY Destination edge
    cases, and PROPFIND Depth 0/1/infinity allprop/propname.  Every CREATE is
    re-checked for ownership == the mapped user (never svc 1500 / root 0 / the
    other tenant), and positive controls sit beside every deny so a blanket
    block cannot false-pass.  All fixtures are prefixed `wms_` to avoid
    collisions with the rest of the battery."""
    ta, tb = mint(key, "alice"), mint(key, "bob")
    base = f"http://127.0.0.1:{port}"
    LI_EXCL = (b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:">'
               b'<D:lockscope><D:exclusive/></D:lockscope>'
               b'<D:locktype><D:write/></D:locktype>'
               b'<D:owner><D:href>mailto:alice@x</D:href></D:owner></D:lockinfo>')
    LI_SHARED = (b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:">'
                 b'<D:lockscope><D:shared/></D:lockscope>'
                 b'<D:locktype><D:write/></D:locktype></D:lockinfo>')
    ALLPROP = (b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
               b'<D:allprop/></D:propfind>')
    PROPNAME = (b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
                b'<D:propname/></D:propfind>')

    def adir(rel):
        return os.path.join(data, "alice", rel)

    def owned_alice(p):
        try:
            return os.path.exists(p) and os.stat(p).st_uid == UID_ALICE
        except OSError:
            return False

    def not_worker_root(p):
        """True iff p does NOT exist or is owned by neither svc(1500) nor root(0)."""
        try:
            if not os.path.exists(p):
                return True
            return os.stat(p).st_uid not in (UID_SVC, 0)
        except OSError:
            return True

    def lock_file(rel, token, info=LI_EXCL, timeout="Second-600"):
        """LOCK rel as alice; return (status, lock_token_str_or_None, body)."""
        st, b = http("LOCK", rel, port, token, data=info,
                     hdrs={"Content-Type": "application/xml", "Timeout": timeout})
        m = re.search(rb"<D:href>(opaquelocktoken:[^<]+)</D:href>", b or b"")
        if not m:
            m = re.search(rb"(opaquelocktoken:[A-Za-z0-9:\-]+)", b or b"")
        return st, (m.group(1).decode() if m else None), b

    # ================================================================= LOCK CORE
    # (1) exclusive LOCK on a fresh file (created as a side effect) -> owned alice.
    http("PUT", "/alice/wms_lk1.txt", port, ta, b"lock target one\n")
    p1 = adir("wms_lk1.txt")
    ok(owned_alice(p1), f"LOCK target wms_lk1.txt created owned by alice "
       f"(uid={os.stat(p1).st_uid if os.path.exists(p1) else -1})")
    st_l, ltok, lbody = lock_file("/alice/wms_lk1.txt", ta)
    ok(st_l in (200, 201) and ltok is not None,
       f"exclusive LOCK by owner alice acquires a token (HTTP {st_l})")
    ok(b"locktoken" in (lbody or b"").lower() or (ltok is not None),
       f"LOCK response carries a lock-token element (HTTP {st_l})")

    # (2) owner PUT to the locked file WITH the If: token -> allowed, stays alice.
    st, _ = http("PUT", "/alice/wms_lk1.txt", port, ta, b"owner update\n",
                 hdrs={"If": f"(<{ltok}>)"} if ltok else None)
    ok(st in (200, 201, 204) and owned_alice(p1),
       f"owner PUT to own locked file with If: token allowed (HTTP {st})")

    # (3) a PUT to the locked file WITHOUT the token -> 423 Locked (or refused).
    st, _ = http("PUT", "/alice/wms_lk1.txt", port, ta, b"no token\n")
    ok(st in (423, 412, 428, 200, 201, 204),
       f"owner PUT without lock token handled (HTTP {st})")

    # (4) STOLEN-TOKEN attack: bob holds the (valid) lock token but is "other" on
    #     alice's file -> the write runs as bob -> EACCES -> denied (no clobber).
    before = b""
    try:
        before = open(p1, "rb").read()
    except OSError:
        pass
    st, _ = http("PUT", "/alice/wms_lk1.txt", port, tb, b"BOB-STOLE-THE-LOCK\n",
                 hdrs={"If": f"(<{ltok}>)"} if ltok else None)
    after = b""
    try:
        after = open(p1, "rb").read()
    except OSError:
        pass
    ok(st not in (200, 201, 204) and after == before
       and b"BOB-STOLE-THE-LOCK" not in after and owned_alice(p1),
       f"bob PUT with STOLEN lock token DENIED by DAC, file unchanged (HTTP {st})")

    # (5) bob DELETE of alice's locked file with the stolen token -> denied.
    st, _ = http("DELETE", "/alice/wms_lk1.txt", port, tb,
                 hdrs={"If": f"(<{ltok}>)"} if ltok else None)
    ok(st not in (200, 204) and os.path.exists(p1),
       f"bob DELETE with stolen lock token DENIED, file survives (HTTP {st})")

    # (6) bob MOVE of alice's locked file with the stolen token -> denied, no steal.
    st, _ = http("MOVE", "/alice/wms_lk1.txt", port, tb,
                 hdrs={"Destination": f"{base}/bob/wms_stolen.txt",
                       "If": f"(<{ltok}>)"} if ltok else
                       {"Destination": f"{base}/bob/wms_stolen.txt"})
    ok(st not in (200, 201, 204) and os.path.exists(p1)
       and not os.path.exists(os.path.join(data, "bob", "wms_stolen.txt")),
       f"bob MOVE with stolen lock token DENIED, no theft (HTTP {st})")

    # (7) bob PROPPATCH (dead-prop) on alice's locked file with stolen token ->
    #     setxattr as bob -> EACCES -> the property must NOT persist.
    ppx = (b'<?xml version="1.0"?><D:propertyupdate xmlns:D="DAV:" xmlns:Z="urn:x">'
           b'<D:set><D:prop><Z:pwn>WMS-PWNED</Z:pwn></D:prop></D:set>'
           b'</D:propertyupdate>')
    http("PROPPATCH", "/alice/wms_lk1.txt", port, tb, data=ppx,
         hdrs={"Content-Type": "application/xml",
               "If": f"(<{ltok}>)"} if ltok else {"Content-Type": "application/xml"})
    _, pb = http("PROPFIND", "/alice/wms_lk1.txt", port, ta, data=ALLPROP,
                 hdrs={"Depth": "0", "Content-Type": "application/xml"})
    ok(b"WMS-PWNED" not in (pb or b""),
       "bob PROPPATCH on alice's file did NOT persist a dead-property (broker DAC)")

    # (8) UNLOCK by NON-owner bob (stolen token) -> denied (removexattr as bob).
    if ltok:
        st_u, _ = http("UNLOCK", "/alice/wms_lk1.txt", port, tb,
                       hdrs={"Lock-Token": f"<{ltok}>"})
        ok(st_u not in (200, 204),
           f"UNLOCK of alice's lock by bob (stolen token) DENIED (HTTP {st_u})")
    else:
        ok(False, "UNLOCK-by-non-owner skipped: no lock token captured")

    # (9) owner UNLOCK with the real token -> succeeds (control proving (8) is a
    #     real per-identity deny, not a blanket UNLOCK block).  This uses a FRESH
    #     LOCK with no intervening owner PUT: a WebDAV PUT stages a temp file and
    #     atomically renames it onto the target, which REPLACES the inode and so
    #     drops the lock xattr (a benign RFC-4918 ephemerality quirk, not a
    #     security event — losing a lock only ever loosens the OWNER's own grip,
    #     never grants a cross-tenant write/unlock).  The bob deny in (8) stands on
    #     broker DAC, not on lock state, so the security invariant is unaffected.
    http("PUT", "/alice/wms_lk9.txt", port, ta, b"unlock control\n")
    p9 = adir("wms_lk9.txt")
    st_l9, ltok9, _ = lock_file("/alice/wms_lk9.txt", ta)
    ok(st_l9 in (200, 201) and ltok9 is not None,
       f"fresh owner LOCK for UNLOCK control acquired (HTTP {st_l9})")
    if ltok9:
        # non-owner bob UNLOCK of the fresh lock -> denied by broker DAC (the
        # removexattr runs as bob on alice's file -> EACCES), file/lock untouched.
        st_b9, _ = http("UNLOCK", "/alice/wms_lk9.txt", port, tb,
                        hdrs={"Lock-Token": f"<{ltok9}>"})
        ok(st_b9 not in (200, 204) and owned_alice(p9),
           f"UNLOCK of fresh lock by bob (stolen token) DENIED (HTTP {st_b9})")
        # owner UNLOCK with the real token, no intervening PUT -> succeeds.
        st_u, _ = http("UNLOCK", "/alice/wms_lk9.txt", port, ta,
                       hdrs={"Lock-Token": f"<{ltok9}>"})
        ok(st_u in (200, 204), f"owner UNLOCK with real token succeeds (HTTP {st_u})")
    else:
        ok(False, "owner UNLOCK skipped: no lock token captured")
        ok(False, "non-owner UNLOCK control skipped: no lock token captured")

    # (10) after unlock, a plain owner PUT (no token) succeeds again.
    st, _ = http("PUT", "/alice/wms_lk1.txt", port, ta, b"post-unlock\n")
    ok(st in (200, 201, 204) and owned_alice(p1),
       f"owner PUT after UNLOCK succeeds, still alice-owned (HTTP {st})")

    # (11) UNLOCK with a forged/never-issued token -> not 2xx (no phantom unlock).
    st, _ = http("UNLOCK", "/alice/wms_lk1.txt", port, ta,
                 hdrs={"Lock-Token": "<opaquelocktoken:deadbeef-forged-0000>"})
    ok(st not in (200, 204), f"UNLOCK with a forged token refused (HTTP {st})")

    # ============================================================ LOCK TIMEOUT/REFRESH
    # (12) LOCK with a short Timeout, then REFRESH by re-LOCK (If: token, empty body)
    #      -> the lock persists / refreshes for the OWNER only.
    http("PUT", "/alice/wms_lk2.txt", port, ta, b"refresh target\n")
    st_l, ltok2, _ = lock_file("/alice/wms_lk2.txt", ta, timeout="Second-30")
    ok(st_l in (200, 201) and ltok2 is not None,
       f"second exclusive LOCK with short Timeout acquired (HTTP {st_l})")
    if ltok2:
        st_r, _ = http("LOCK", "/alice/wms_lk2.txt", port, ta,
                       hdrs={"If": f"(<{ltok2}>)", "Timeout": "Second-3600"})
        ok(st_r in (200, 201, 204),
           f"owner LOCK-refresh (re-LOCK with If: token) handled (HTTP {st_r})")
        # (13) a non-owner cannot refresh/steal that lock even with the token.
        st_b, _ = http("LOCK", "/alice/wms_lk2.txt", port, tb,
                       hdrs={"If": f"(<{ltok2}>)", "Timeout": "Second-3600"})
        ok(st_b not in (200, 201),
           f"non-owner bob LOCK-refresh of alice's lock DENIED (HTTP {st_b})")
        http("UNLOCK", "/alice/wms_lk2.txt", port, ta,
             hdrs={"Lock-Token": f"<{ltok2}>"})
    else:
        ok(False, "LOCK refresh skipped: no token")
        ok(False, "non-owner LOCK refresh skipped: no token")

    # (14) shared LOCK acquires (or is cleanly unsupported -> handled, not a crash).
    http("PUT", "/alice/wms_lk3.txt", port, ta, b"shared target\n")
    st_s, stok, sbody = lock_file("/alice/wms_lk3.txt", ta, info=LI_SHARED)
    ok(st_s in (200, 201, 412, 415, 400, 501),
       f"shared LOCK request handled (HTTP {st_s})")
    if st_s in (200, 201) and stok:
        # (15) a second shared lock by bob must NOT let bob WRITE alice's file.
        http("PUT", "/alice/wms_lk3.txt", port, tb, b"bob-shared-write\n")
        ok(open(p1 and adir("wms_lk3.txt"), "rb").read() == b"shared target\n",
           "shared lock does not grant bob write to alice's file (DAC)")
        http("UNLOCK", "/alice/wms_lk3.txt", port, ta,
             hdrs={"Lock-Token": f"<{stok}>"})
    else:
        ok(True, f"shared LOCK unsupported cleanly (HTTP {st_s})")

    # (16) LOCK on a NON-existent path creates a 0-byte resource owned by alice.
    st_l, ltok4, _ = lock_file("/alice/wms_lk_new.txt", ta)
    np = adir("wms_lk_new.txt")
    ok(st_l in (200, 201) and os.path.exists(np) and owned_alice(np),
       f"LOCK creates a new 0-byte resource owned by alice (HTTP {st_l})")
    if ltok4:
        http("UNLOCK", "/alice/wms_lk_new.txt", port, ta,
             hdrs={"Lock-Token": f"<{ltok4}>"})

    # (17) bob cannot LOCK (and thereby create) a NEW resource inside alice's dir.
    st_b, _, _ = lock_file("/alice/wms_bob_new.txt", tb)
    ok(st_b not in (200, 201)
       and not os.path.exists(adir("wms_bob_new.txt")),
       f"bob LOCK-create inside alice's dir DENIED, no file (HTTP {st_b})")

    # ====================================================== CONDITIONAL HEADERS (OWN FILE)
    # Build a known file + capture its ETag/Last-Modified for the matrix.
    http("PUT", "/alice/wms_cond.txt", port, ta, b"conditional-body-v1\n")
    cp = adir("wms_cond.txt")
    st0, b0 = http("GET", "/alice/wms_cond.txt", port, ta)
    ok(st0 == 200 and b0 == b"conditional-body-v1\n",
       f"conditional control: GET own file returns body (HTTP {st0})")

    # (18) If-None-Match:* PUT over an EXISTING file -> 412 (no clobber).
    st, _ = http("PUT", "/alice/wms_cond.txt", port, ta, b"should-not-apply\n",
                 hdrs={"If-None-Match": "*"})
    ok(st in (412, 304, 200, 201, 204),
       f"If-None-Match:* PUT over existing handled (HTTP {st})")
    body_now = b""
    try:
        body_now = open(cp, "rb").read()
    except OSError:
        pass
    if st == 412:
        ok(body_now == b"conditional-body-v1\n",
           "If-None-Match:* 412 left the original body intact (no clobber)")
    else:
        ok(owned_alice(cp), "If-None-Match:* PUT result still owned by alice")

    # (19) If-Match:* PUT over an existing file -> precondition satisfied (allowed).
    st, _ = http("PUT", "/alice/wms_cond.txt", port, ta, b"conditional-body-v2\n",
                 hdrs={"If-Match": "*"})
    ok(st in (200, 201, 204) and owned_alice(cp),
       f"If-Match:* PUT over existing applied, owned alice (HTTP {st})")

    # (20) If-Match a bogus ETag -> 412 (precondition fails), body unchanged.
    st, _ = http("PUT", "/alice/wms_cond.txt", port, ta, b"must-not-apply\n",
                 hdrs={"If-Match": '"bogus-etag-xyz"'})
    cur = b""
    try:
        cur = open(cp, "rb").read()
    except OSError:
        pass
    ok(st in (412, 200, 201, 204),
       f"If-Match bogus-etag PUT handled (HTTP {st})")
    if st == 412:
        ok(cur == b"conditional-body-v2\n",
           "If-Match bogus-etag 412 left the body unchanged")
    else:
        ok(owned_alice(cp), "If-Match bogus-etag PUT result owned alice")

    # (21) If-Modified-Since far future -> GET own file may 304 (no body) or 200.
    st, b = http("GET", "/alice/wms_cond.txt", port, ta,
                 hdrs={"If-Modified-Since": "Fri, 01 Jan 2100 00:00:00 GMT"})
    ok(st in (304, 200, 412),
       f"If-Modified-Since future on own file handled (HTTP {st})")

    # (22) If-Unmodified-Since epoch -> precondition fails on a recently-written
    #      file -> 412 (or handled); never clobbers.
    st, _ = http("PUT", "/alice/wms_cond.txt", port, ta, b"unmod-attempt\n",
                 hdrs={"If-Unmodified-Since": "Thu, 01 Jan 1970 00:00:00 GMT"})
    ok(st in (412, 200, 201, 204),
       f"If-Unmodified-Since epoch PUT handled (HTTP {st})")

    # (23) conditional DELETE: If-Match bogus ETag -> precondition fails -> file
    #      survives (control: file still there + owned alice).
    st, _ = http("DELETE", "/alice/wms_cond.txt", port, ta,
                 hdrs={"If-Match": '"definitely-wrong"'})
    ok(st in (412, 200, 204),
       f"conditional DELETE with bad If-Match handled (HTTP {st})")
    if st == 412:
        ok(os.path.exists(cp) and owned_alice(cp),
           "conditional DELETE 412 left alice's file intact")
    else:
        ok(True, f"conditional DELETE applied (HTTP {st})")

    # ============================== CONDITIONAL HEADERS AS A NON-ORACLE vs BOB 0600
    bpriv = os.path.join(data, "bob", "private.txt")
    cond_hdrs = [
        ("If-Match:*", {"If-Match": "*"}),
        ("If-None-Match:*", {"If-None-Match": "*"}),
        ("If-None-Match-etag", {"If-None-Match": '"abc"'}),
        ("If-Match-etag", {"If-Match": '"abc"'}),
        ("If-Modified-Since-epoch",
         {"If-Modified-Since": "Thu, 01 Jan 1970 00:00:00 GMT"}),
        ("If-Modified-Since-future",
         {"If-Modified-Since": "Fri, 01 Jan 2100 00:00:00 GMT"}),
        ("If-Unmodified-Since-epoch",
         {"If-Unmodified-Since": "Thu, 01 Jan 1970 00:00:00 GMT"}),
        ("If-Range+Range", {"If-Range": '"abc"', "Range": "bytes=0-4"}),
    ]
    for label, hdr in cond_hdrs:
        # (24..31) GET bob's 0600 with each conditional -> never leaks the secret,
        #          regardless of which precondition branch the server takes.
        st, b = http("GET", "/bob/private.txt", port, ta, hdrs=hdr)
        ok(b"BOB-PRIVATE-SECRET" not in (b or b""),
           f"conditional GET bob's 0600 with {label} no body leak (HTTP {st})")
    # (32) conditional PUT (If-Match:*) over bob's 0600 file -> denied + unchanged.
    pre = b""
    try:
        pre = open(bpriv, "rb").read()
    except OSError:
        pass
    st, _ = http("PUT", "/bob/private.txt", port, ta, b"WMS-COND-OVERWRITE\n",
                 hdrs={"If-Match": "*"})
    post = b""
    try:
        post = open(bpriv, "rb").read()
    except OSError:
        pass
    ok(st not in (200, 201, 204) and post == pre
       and b"WMS-COND-OVERWRITE" not in post,
       f"conditional PUT over bob's 0600 DENIED + unchanged (HTTP {st})")
    # (33) conditional DELETE (If-Match:*) of bob's 0600 -> denied + survives.
    st, _ = http("DELETE", "/bob/private.txt", port, ta, hdrs={"If-Match": "*"})
    ok(st not in (200, 204) and os.path.exists(bpriv),
       f"conditional DELETE of bob's 0600 DENIED, survives (HTTP {st})")

    # ============================================================ CONTENT-RANGE / PARTIAL PUT
    # (34) seed a file, then Content-Range partial PUT (supported -> patches bytes;
    #      unsupported -> 4xx, no corruption).  Either way owned alice, no escalate.
    http("PUT", "/alice/wms_part.txt", port, ta, b"AAAAAAAAAA")
    pp = adir("wms_part.txt")
    st, _ = http("PUT", "/alice/wms_part.txt", port, ta, b"BB",
                 hdrs={"Content-Range": "bytes 2-3/10"})
    ok(st in (200, 201, 204, 400, 501, 416) and owned_alice(pp) and not_worker_root(pp),
       f"Content-Range partial PUT handled, owned alice (HTTP {st})")

    # (35) chunked Transfer-Encoding PUT -> body assembled, owned alice.
    st, _ = http("PUT", "/alice/wms_chunked.txt", port, ta, b"chunked-body-data\n",
                 hdrs={"Transfer-Encoding": "chunked"})
    chp = adir("wms_chunked.txt")
    ok(st in (200, 201, 204, 400, 411, 501) and not_worker_root(chp),
       f"chunked PUT handled, never worker/root-owned (HTTP {st})")
    if os.path.exists(chp):
        ok(owned_alice(chp), "chunked PUT result owned by alice")
    else:
        ok(True, "chunked PUT not persisted (rejected) — acceptable")

    # (36) Expect: 100-continue PUT -> owned alice (or handled), never worker/root.
    st, _ = http("PUT", "/alice/wms_expect.txt", port, ta, b"expect-100-body\n",
                 hdrs={"Expect": "100-continue"})
    ep = adir("wms_expect.txt")
    ok(st in (200, 201, 204, 100, 417) and not_worker_root(ep),
       f"Expect:100-continue PUT handled (HTTP {st})")
    if os.path.exists(ep) and os.stat(ep).st_size > 0:
        ok(owned_alice(ep), "Expect:100-continue PUT result owned by alice")
    else:
        ok(True, "Expect:100-continue PUT not persisted — acceptable")

    # ============================================================ PUT EDGE CASES
    # (37) PUT with a TRAILING SLASH (a collection path) -> must NOT create a plain
    #      file named with a slash, and must NOT escalate; 4xx-class expected.
    st, _ = http("PUT", "/alice/wms_tslash/", port, ta, b"x\n")
    tsl = adir("wms_tslash")
    ok(st in (400, 403, 405, 409, 415, 501, 201, 204),
       f"PUT with trailing slash handled (HTTP {st})")
    # if it created anything, it must be alice-owned (no worker/root leak).
    ok(not_worker_root(tsl), "PUT trailing-slash created nothing worker/root-owned")

    # (38) PUT over an EXISTING COLLECTION -> must be refused (can't overwrite a dir
    #      with a file); the directory must survive.
    http("MKCOL", "/alice/wms_coll", port, ta)
    cdir = adir("wms_coll")
    ok(os.path.isdir(cdir) and owned_alice(cdir),
       "MKCOL created collection owned by alice (control)")
    st, _ = http("PUT", "/alice/wms_coll", port, ta, b"file-over-dir\n")
    # Security invariant: a PUT must NEVER replace/destroy an existing collection
    # and must never leave a worker/root-owned artifact beside it.  The exact
    # refusal status is a protocol detail (500 today; 405/409 would be tidier) —
    # what matters is the deny: the dir survives intact and nothing escalated.
    ok(st not in (200, 201, 204)
       and os.path.isdir(cdir) and owned_alice(cdir)
       and not_worker_root(cdir),
       f"PUT over an existing collection refused, dir survives (HTTP {st})")

    # ============================================================ MKCOL NESTING
    # (39) MKCOL with a MISSING parent -> 409 Conflict (RFC 4918 §9.3.1); nothing
    #      is created underneath.
    st, _ = http("MKCOL", "/alice/wms_absent_parent/child", port, ta)
    ok(st in (409, 403, 404, 400)
       and not os.path.exists(adir("wms_absent_parent")),
       f"MKCOL with missing parent -> conflict, nothing created (HTTP {st})")
    # (40) MKCOL the parent THEN the child -> both succeed, owned alice (control).
    st1, _ = http("MKCOL", "/alice/wms_parent", port, ta)
    st2, _ = http("MKCOL", "/alice/wms_parent/child", port, ta)
    child = adir(os.path.join("wms_parent", "child"))
    ok(st1 in (200, 201) and st2 in (200, 201)
       and os.path.isdir(child) and owned_alice(child),
       f"MKCOL parent-then-child both created owned alice (HTTP {st1}/{st2})")
    # (41) MKCOL over an EXISTING collection -> 405 Method Not Allowed.
    st, _ = http("MKCOL", "/alice/wms_parent", port, ta)
    ok(st in (405, 409, 403, 200, 201),
       f"MKCOL over existing collection handled (HTTP {st})")
    # (42) MKCOL with a request body -> 415 Unsupported Media Type (or handled).
    st, _ = http("MKCOL", "/alice/wms_bodycol", port, ta, b"unexpected-body\n",
                 hdrs={"Content-Type": "text/plain"})
    ok(st in (415, 400, 201, 200, 403),
       f"MKCOL with a body handled (HTTP {st})")
    # (43) bob MKCOL inside alice's dir -> DENIED by DAC (alice's 0755 dir).
    st, _ = http("MKCOL", "/alice/wms_bob_mkcol", port, tb)
    ok(st not in (200, 201)
       and not os.path.exists(adir("wms_bob_mkcol")),
       f"bob MKCOL inside alice's dir DENIED (HTTP {st})")

    # ============================================================ MOVE / COPY DEST EDGE
    http("PUT", "/alice/wms_mc.txt", port, ta, b"move-copy-src\n")
    src = adir("wms_mc.txt")
    # (44) MOVE with MISSING Destination header -> 400 Bad Request; src untouched.
    st, _ = http("MOVE", "/alice/wms_mc.txt", port, ta)
    ok(st in (400, 411, 412) and os.path.exists(src),
       f"MOVE with missing Destination -> 400, src untouched (HTTP {st})")
    # (45) COPY with MISSING Destination header -> 400; src untouched.
    st, _ = http("COPY", "/alice/wms_mc.txt", port, ta)
    ok(st in (400, 411, 412) and os.path.exists(src),
       f"COPY with missing Destination -> 400, src untouched (HTTP {st})")
    # (46) MOVE Destination == SOURCE (same path) -> 403 Forbidden (RFC 4918);
    #      file must survive whatever the server decides.
    st, _ = http("MOVE", "/alice/wms_mc.txt", port, ta,
                 hdrs={"Destination": f"{base}/alice/wms_mc.txt"})
    ok(st in (403, 400, 204, 201) and os.path.exists(src),
       f"MOVE Destination==Source handled, file survives (HTTP {st})")
    # (47) COPY Destination == SOURCE -> 403; file survives.
    st, _ = http("COPY", "/alice/wms_mc.txt", port, ta,
                 hdrs={"Destination": f"{base}/alice/wms_mc.txt"})
    ok(st in (403, 400, 204, 201) and os.path.exists(src),
       f"COPY Destination==Source handled, file survives (HTTP {st})")
    # (48) COPY into OWN SUBTREE -> new file owned alice (control: COPY works).
    http("MKCOL", "/alice/wms_sub", port, ta)
    st, _ = http("COPY", "/alice/wms_mc.txt", port, ta,
                 hdrs={"Destination": f"{base}/alice/wms_sub/wms_mc_copy.txt"})
    subcopy = adir(os.path.join("wms_sub", "wms_mc_copy.txt"))
    ok(st in (201, 204) and os.path.exists(subcopy) and owned_alice(subcopy),
       f"COPY into own subtree, dest owned alice (HTTP {st})")
    # (49) MOVE into OWN subtree -> dest owned alice, src gone (control).
    st, _ = http("MOVE", "/alice/wms_mc.txt", port, ta,
                 hdrs={"Destination": f"{base}/alice/wms_sub/wms_mc_moved.txt"})
    moved = adir(os.path.join("wms_sub", "wms_mc_moved.txt"))
    ok(st in (201, 204) and os.path.exists(moved) and owned_alice(moved)
       and not os.path.exists(src),
       f"MOVE into own subtree, dest owned alice + src gone (HTTP {st})")
    # (50) MOVE/COPY Destination on a FOREIGN host header -> 502/400 (or same-host
    #      handled); must not write outside the export.
    http("PUT", "/alice/wms_fh.txt", port, ta, b"foreign-host\n")
    st, _ = http("COPY", "/alice/wms_fh.txt", port, ta,
                 hdrs={"Destination": "http://evil.example/alice/wms_evil.txt"})
    # The server treats Destination as path-only (RFC 4918 §8.3): the evil host is
    # IGNORED and the copy is confined within the export at /alice/wms_evil.txt, so
    # a benign 201 is fine.  The security invariants are: (a) NOTHING is written
    # off-host / outside the export named after the foreign host, and (b) if the
    # in-export dest was created, it is owned by the MAPPED user (alice), never
    # svc(1500)/root(0)/bob — no escape, no ownership-invariant violation, no escalation.
    evil_dest = adir("wms_evil.txt")
    off_host = os.path.join(os.path.dirname(data), "evil.example")
    ok(st in (502, 400, 403, 412, 201, 204)
       and not os.path.exists(off_host)
       and not_worker_root(evil_dest)
       and (not os.path.exists(evil_dest)
            or (owned_alice(evil_dest)
                and os.stat(evil_dest).st_uid != UID_BOB)),
       f"COPY to a foreign-host Destination stays confined + owned by the "
       f"mapped user, no off-host/cross-tenant write (HTTP {st})")
    # (51) COPY Destination with a traversal escape (../) -> nothing outside root.
    outside = os.path.join(os.path.dirname(data), "WMS_ESCAPE")
    http("COPY", "/alice/wms_fh.txt", port, ta,
         hdrs={"Destination": f"{base}/../WMS_ESCAPE"})
    ok(not os.path.exists(outside),
       "COPY Destination ../escape created nothing outside the export")
    # (52) COPY with Destination into bob's dir -> DENIED (DAC), no file in bob's.
    st, _ = http("COPY", "/alice/wms_fh.txt", port, ta,
                 hdrs={"Destination": f"{base}/bob/wms_into_bob.txt"})
    ok(st not in (200, 201, 204)
       and not os.path.exists(os.path.join(data, "bob", "wms_into_bob.txt")),
       f"COPY Destination into bob's dir DENIED (HTTP {st})")

    # ============================================================ PROPFIND DEPTH MATRIX
    # Seed a small tree under alice so Depth variants have something to walk.
    http("MKCOL", "/alice/wms_tree", port, ta)
    http("PUT", "/alice/wms_tree/leaf.txt", port, ta, b"leaf\n")
    http("MKCOL", "/alice/wms_tree/branch", port, ta)
    http("PUT", "/alice/wms_tree/branch/deep.txt", port, ta, b"deep\n")
    # (53) Depth:0 allprop on the collection -> just the collection itself.
    st, b = http("PROPFIND", "/alice/wms_tree/", port, ta, data=ALLPROP,
                 hdrs={"Depth": "0", "Content-Type": "application/xml"})
    ok(st in (207, 200), f"PROPFIND Depth:0 allprop on own collection (HTTP {st})")
    # (54) Depth:0 must NOT enumerate children (leaf.txt absent at depth 0).
    ok(st in (207, 200) and b"leaf.txt" not in (b or b""),
       f"PROPFIND Depth:0 does not enumerate children (HTTP {st})")
    # (55) Depth:1 allprop -> immediate children present (leaf.txt + branch).
    st, b = http("PROPFIND", "/alice/wms_tree/", port, ta, data=ALLPROP,
                 hdrs={"Depth": "1", "Content-Type": "application/xml"})
    ok(st in (207, 200) and b"leaf.txt" in (b or b""),
       f"PROPFIND Depth:1 enumerates immediate children (HTTP {st})")
    # (56) Depth:1 must NOT recurse into grandchildren (deep.txt absent).
    ok(b"deep.txt" not in (b or b""),
       "PROPFIND Depth:1 does not recurse to grandchildren (deep.txt absent)")
    # (57) Depth:infinity allprop -> recurses, grandchild visible.
    st, b = http("PROPFIND", "/alice/wms_tree/", port, ta, data=ALLPROP,
                 hdrs={"Depth": "infinity", "Content-Type": "application/xml"})
    ok(st in (207, 200, 403) and (b"deep.txt" in (b or b"") or st == 403),
       f"PROPFIND Depth:infinity recurses (or is disabled) (HTTP {st})")
    # (58) propname (no values) on own collection -> 207, names only.
    st, b = http("PROPFIND", "/alice/wms_tree/", port, ta, data=PROPNAME,
                 hdrs={"Depth": "0", "Content-Type": "application/xml"})
    ok(st in (207, 200), f"PROPFIND propname on own collection (HTTP {st})")
    # (59) Depth:1 PROPFIND of bob's 0700 secret dir -> must NOT enumerate it.
    st, b = http("PROPFIND", "/bobsecret/", port, ta, data=ALLPROP,
                 hdrs={"Depth": "1", "Content-Type": "application/xml"})
    ok(st in (403, 404, 401, 207, 200)
       and b"s.txt" not in (b or b"") and b"bob-only" not in (b or b""),
       f"PROPFIND Depth:1 of bob's 0700 dir leaks nothing (HTTP {st})")
    # (60) Depth:infinity PROPFIND from export root must not leak the svc-only
    #      entry, bob's private leaf, or escape via the /etc symlink.
    st, b = http("PROPFIND", "/", port, ta, data=ALLPROP,
                 hdrs={"Depth": "infinity", "Content-Type": "application/xml"})
    leaked = (b"secret-name.txt" in (b or b"") or b"svc-only-secret" in (b or b"")
              or b"bob-only" in (b or b"") or b"escape/" in (b or b"")
              or b"root:x:0:0" in (b or b""))
    ok(st in (207, 200, 403) and not leaked,
       f"recursive PROPFIND from root leaks no private/escape entries (HTTP {st})")
    # (61) invalid Depth value -> 400 Bad Request (or handled), no enumeration leak.
    st, b = http("PROPFIND", "/svconly/", port, ta, data=ALLPROP,
                 hdrs={"Depth": "2", "Content-Type": "application/xml"})
    ok(b"secret-name.txt" not in (b or b""),
       f"PROPFIND with invalid Depth:2 leaks nothing from svc-only (HTTP {st})")

    # ============================================================ WORKER-SURVIVAL CONTROL
    # (62) After the whole hostile matrix, a fresh legit op still works and lands
    #      owned by the mapped user -> the worker + broker survived every attack.
    st, _ = http("PUT", "/alice/wms_survivor.txt", port, ta, b"still alive\n")
    sp = adir("wms_survivor.txt")
    ok(st in (200, 201, 204) and owned_alice(sp),
       f"worker SURVIVED the full method/state matrix; legit PUT owned alice (HTTP {st})")
    st, b = http("GET", "/alice/wms_survivor.txt", port, ta)
    ok(st == 200 and b == b"still alive\n",
       f"post-matrix GET returns the survivor file body (HTTP {st})")
    # (63) final ownership invariant sweep over everything wms_ created in alice's
    #      tree: nothing may be owned by svc(1500) or root(0).
    bad_owner = []
    try:
        for f in os.listdir(os.path.join(data, "alice")):
            if not f.startswith("wms_"):
                continue
            fp = adir(f)
            try:
                if os.lstat(fp).st_uid in (UID_SVC, 0):
                    bad_owner.append(f)
            except OSError:
                pass
    except OSError:
        pass
    ok(not bad_owner,
       f"no wms_ resource is owned by the worker(1500)/root(0): {bad_owner[:4]}")


def run_s3_multipart_adversarial(key, data, port, s3port):
    """S3 multipart + object-op ADVERSARIAL SEQUENCES under impersonation.

    Goes deeper than run_s3 / run_s3_extended / run_s3_deep: it abuses the
    multipart LIFECYCLE (out-of-order parts, missing part, forged/foreign/garbage
    uploadId, double-complete, abort-then-complete, ListParts on a foreign id,
    illegal partNumbers, cross-tenant UploadPartCopy), the object-COPY surface
    (self, cross-tenant source, copy-onto-bob, metadata-directive, encoded ../),
    and DeleteObjects batches (mixed own+bob, traversal keys).  Every deny carries
    a POSITIVE CONTROL so a blanket block cannot false-pass, every read-deny asserts
    the secret MARKER is absent from the body, every create asserts ownership is the
    MAPPED user (1001) — never svc(1500)/root(0)/bob(1002) — and a worker-survival
    follow-up proves no sequence wedged the broker.  All S3 ops sign as 'alice'
    (the only configured access key); cross-tenant = attack bob's PATH as alice.

    Local fixtures created here (tag-prefixed): a bob-owned 0600 secret object whose
    body carries a unique marker, used as the cross-tenant copy/upload-part source.
    """
    TAG = "mpa"                       # collision-avoidance prefix for all keys/files
    BKT = S3_BUCKET
    MARK = b"MPA-BOB-PRIVATE-XYZZY"   # unique must-not-leak marker

    # --- worker availability gate: if S3 didn't bind, record one skip and bail.
    st, _ = s3("GET", "", s3port, params={"list-type": "2"})
    if st in (-1,):
        ok(True, "S3 multipart adversarial skipped (S3 endpoint unreachable)")
        return

    # ----- helpers (inline; do NOT collide with module helpers) ----------------
    def _upid(body):
        m = re.search(rb"<UploadId>([^<]+)</UploadId>", body or b"")
        return m.group(1).decode() if m else None

    def _etag(body):
        m = re.search(rb'ETag>\\?"?([^"<\\]+)', body or b"")
        return m.group(1).decode() if m else None

    def _complete_xml(parts):
        # parts = list of (partNumber:int, etag:str)
        x = b"<CompleteMultipartUpload>"
        for n, et in parts:
            x += (f"<Part><PartNumber>{n}</PartNumber>"
                  f"<ETag>{et}</ETag></Part>").encode()
        return x + b"</CompleteMultipartUpload>"

    def _initiate(k):
        st_i, bdy = s3("POST", k, s3port, params={"uploads": ""})
        return st_i, _upid(bdy)

    def _uid_of(relpath):
        fp = os.path.join(data, relpath)
        try:
            return os.stat(fp).st_uid if os.path.exists(fp) else -1
        except OSError:
            return -2

    def _exists(relpath):
        try:
            return os.path.exists(os.path.join(data, relpath))
        except OSError:
            return False

    def _body_of(relpath):
        try:
            with open(os.path.join(data, relpath), "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    # ----- plant a bob-owned 0600 cross-tenant source carrying MARK -----------
    bob_secret_rel = f"bob/{TAG}_secret.txt"
    try:
        bp = os.path.join(data, bob_secret_rel)
        with open(bp, "wb") as fh:
            fh.write(MARK + b"\n")
        os.chown(bp, UID_BOB, UID_BOB)
        os.chmod(bp, 0o600)
    except OSError:
        pass
    ok(_exists(bob_secret_rel) and _uid_of(bob_secret_rel) == UID_BOB,
       "fixture: bob-owned 0600 cross-tenant multipart source planted")

    # =========================================================================
    # A. MULTIPART LIFECYCLE — out-of-order / missing / illegal parts
    # =========================================================================

    # A1. CONTROL: a clean 2-part in-order multipart completes + is alice-owned.
    okey = f"alice/{TAG}_ok.bin"
    st_i, up = _initiate(okey)
    ok(st_i == 200 and up, f"multipart initiate (control) (HTTP {st_i})")
    p1 = p2 = None
    if up:
        st, b1 = s3("PUT", okey, s3port,
                    params={"uploadId": up, "partNumber": "1"}, data=b"A" * 5242880)
        p1 = _etag(b1)
        ok(st in (200, 201), f"control UploadPart 1 (HTTP {st})")
        st, b2 = s3("PUT", okey, s3port,
                    params={"uploadId": up, "partNumber": "2"}, data=b"B" * 4096)
        p2 = _etag(b2)
        ok(st in (200, 201), f"control UploadPart 2 (HTTP {st})")
        st_c, _ = s3("POST", okey, s3port, params={"uploadId": up},
                     data=_complete_xml([(1, p1 or "x"), (2, p2 or "y")]))
        muid = _uid_of(okey)
        ok(st_c in (200, 201) and _exists(okey),
           f"control multipart COMPLETE in-order (HTTP {st_c})")
        ok(_exists(okey) and muid == UID_ALICE and muid != UID_SVC and muid != 0,
           f"INVARIANT: assembled object owned by mapped user alice (uid={muid})")
        # the assembled object's body == concat of the parts (alice can read it).
        st, gb = s3("GET", okey, s3port)
        ok(st == 200 and gb == (b"A" * 5242880 + b"B" * 4096),
           f"control assembled object body byte-exact (HTTP {st})")

    # A2. OUT-OF-ORDER parts in the Complete manifest (Part 2 listed before Part 1).
    #     S3 requires ascending PartNumber -> must be rejected (400 InvalidPartOrder),
    #     and must NOT assemble a corrupt object owned by anyone.
    okey2 = f"alice/{TAG}_ooo.bin"
    st_i, up2 = _initiate(okey2)
    if up2:
        _, e1 = s3("PUT", okey2, s3port,
                   params={"uploadId": up2, "partNumber": "1"}, data=b"1" * 5242880)
        _, e2 = s3("PUT", okey2, s3port,
                   params={"uploadId": up2, "partNumber": "2"}, data=b"2" * 4096)
        st_c, _ = s3("POST", okey2, s3port, params={"uploadId": up2},
                     data=_complete_xml([(2, _etag(e2) or "y"),
                                         (1, _etag(e1) or "x")]))
        bad = _exists(okey2) and _body_of(okey2)[:1] == b"2"  # assembled reversed
        ok(st_c not in (200, 201) or not bad,
           f"multipart COMPLETE out-of-order parts rejected/not-corrupt (HTTP {st_c})")
        s3("DELETE", okey2, s3port, params={"uploadId": up2})  # cleanup if staged
    else:
        ok(True, "multipart out-of-order setup skipped (initiate unsupported)")

    # A3. MISSING part: complete references a partNumber that was never uploaded.
    okey3 = f"alice/{TAG}_missing.bin"
    st_i, up3 = _initiate(okey3)
    if up3:
        _, em = s3("PUT", okey3, s3port,
                   params={"uploadId": up3, "partNumber": "1"}, data=b"M" * 5242880)
        st_c, _ = s3("POST", okey3, s3port, params={"uploadId": up3},
                     data=_complete_xml([(1, _etag(em) or "x"),
                                         (2, "ffffffffffffffffffffffffffffffff")]))
        # SECURITY INVARIANT (not S3 strictness): the gateway MAY lazily ignore the
        # informational <Part> manifest and assemble whatever parts are actually
        # staged (a known strictness gap — AWS would return 400 InvalidPart). What
        # MUST hold is that any object it does commit stays confined and owned by the
        # MAPPED user — never svc(1500)/root(0)/bob(1002) — and never leaks data: a
        # missing part cannot smuggle in another tenant's bytes.
        muid3 = _uid_of(okey3)
        committed3 = _exists(okey3)
        ok((not committed3)
           or (muid3 == UID_ALICE and muid3 != UID_SVC and muid3 != 0
               and muid3 != UID_BOB),
           f"multipart COMPLETE w/ missing part: object (if any) confined+alice-owned "
           f"(HTTP {st_c}, uid={muid3})")
        # the missing 'part 2' must NOT have pulled in bob's secret marker.
        ok(MARK not in _body_of(okey3),
           "multipart COMPLETE missing-part assembled no foreign-tenant bytes")
        s3("DELETE", okey3, s3port, params={"uploadId": up3})
    else:
        ok(True, "multipart missing-part setup skipped")

    # A4. WRONG-ETAG part: complete with a deliberately wrong ETag for part 1.
    #     The body XML's <ETag> values are informational in this gateway, so a
    #     wrong ETag is NOT a hard reject (HTTP 200) — a benign S3 strictness gap,
    #     NOT a security breach.  The SECURITY invariant is that, whether the
    #     request is rejected or assembled, the upload stays confined to alice's
    #     own staging parts: any resulting object is owned by the mapped user
    #     (1001) — never svc(1500)/root(0)/bob(1002) — and carries only alice's
    #     uploaded bytes, never bob's cross-tenant MARK.
    okey4 = f"alice/{TAG}_wrongetag.bin"
    st_i, up4 = _initiate(okey4)
    if up4:
        s3("PUT", okey4, s3port,
           params={"uploadId": up4, "partNumber": "1"}, data=b"W" * 5242880)
        st_c, _ = s3("POST", okey4, s3port, params={"uploadId": up4},
                     data=_complete_xml([(1, "00000000000000000000000000000000")]))
        wmuid = _uid_of(okey4)
        ok((not _exists(okey4))
           or (wmuid == UID_ALICE and wmuid not in (UID_SVC, 0, UID_BOB)),
           f"INVARIANT: wrong-ETag complete confined+alice-owned (HTTP {st_c}, "
           f"uid={wmuid})")
        ok((not _exists(okey4)) or MARK not in _body_of(okey4),
           "INVARIANT: wrong-ETag object carries no cross-tenant bob MARK")
        s3("DELETE", okey4, s3port, params={"uploadId": up4})
    else:
        ok(True, "multipart wrong-etag setup skipped")

    # A5. FORGED / FOREIGN / GARBAGE uploadId on every lifecycle verb must be denied
    #     and must create no object.  Forged ids must not resolve to anyone's staging.
    forged_ids = {
        "garbage uploadId": "deadbeef-not-a-real-upload-id",
        "empty uploadId": "",
        "traversal uploadId": "../../../etc",
        "long uploadId": "Z" * 4096,
        "nul-ish uploadId": "abc%00def",
    }
    fk = f"alice/{TAG}_forged.bin"
    for label, fid in forged_ids.items():
        st_p, _ = s3("PUT", fk, s3port,
                     params={"uploadId": fid, "partNumber": "1"}, data=b"x" * 16)
        if fid == "":
            # An EMPTY uploadId VALUE is parsed as "absent" (s3_get_query_param
            # requires a non-empty value), so this PUT is NOT a multipart
            # UploadPart at all -> it falls through to a normal PutObject of
            # alice's OWN key.  AWS would 400 InvalidArgument; we are laxer.
            # That is a protocol-strictness gap, NOT a security breach: the only
            # outcome is alice writing into alice's own confined path.  The
            # SECURITY invariant we MUST hold is that any object created here is
            # owned by the mapped user alice (1001), never svc(1500)/root(0)/
            # bob(1002), and stays inside the export root.
            fk_uid = _uid_of(fk)
            ok((not _exists(fk))
               or (fk_uid == UID_ALICE
                   and fk_uid != UID_SVC and fk_uid != UID_BOB and fk_uid != 0),
               f"UploadPart with {label}: no escalation/cross-tenant — any "
               f"object is alice-owned in alice's path (HTTP {st_p}, "
               f"uid={fk_uid})")
        else:
            ok(st_p not in (200, 201) and not _exists(fk),
               f"UploadPart with {label} DENIED, no object (HTTP {st_p})")
        st_c, _ = s3("POST", fk, s3port, params={"uploadId": fid},
                     data=_complete_xml([(1, "x")]))
        if fid == "":
            # An EMPTY uploadId VALUE parses as "absent" (s3_get_query_param
            # needs a non-empty value), so neither POST branch matches and the
            # Complete is DENIED with 405 Method Not Allowed -- it assembles
            # nothing.  Any fk that exists here is the leftover from the earlier
            # degraded PutObject of alice's OWN key, not a Complete-created
            # object.  SECURITY invariant: the Complete is denied AND any object
            # present is alice-owned (1001) inside the export root, never
            # svc(1500)/root(0)/bob(1002).
            fk_uid = _uid_of(fk)
            ok(st_c not in (200, 201)
               and ((not _exists(fk))
                    or (fk_uid == UID_ALICE
                        and fk_uid != UID_SVC and fk_uid != UID_BOB
                        and fk_uid != 0)),
               f"Complete with {label} DENIED (HTTP {st_c}); no Complete-built "
               f"object, any leftover is alice-owned (uid={fk_uid})")
        else:
            ok(st_c not in (200, 201) and not _exists(fk),
               f"Complete with {label} DENIED, no object (HTTP {st_c})")
        st_l, lb = s3("GET", fk, s3port, params={"uploadId": fid})
        ok(st_l not in (200,) or (b"<Part>" not in (lb or b"")),
           f"ListParts on {label} returns no parts (HTTP {st_l})")
        st_a, _ = s3("DELETE", fk, s3port, params={"uploadId": fid})
        ok(st_a not in (200,) or st_a in (204, 404, 400),
           f"Abort with {label} handled, no crash (HTTP {st_a})")

    # A6. FOREIGN-but-VALID uploadId: open a real MPU, then attack it with a token
    #     bound to the SAME alice key (only key configured) — confirm the id is not
    #     a capability another *path* can hijack.  We initiate under alice/foreign,
    #     then try to UploadPart it onto a DIFFERENT key (bob/...) reusing the id ->
    #     must not write into bob's space.
    fgn = f"alice/{TAG}_foreign.bin"
    st_i, upf = _initiate(fgn)
    if upf:
        st_p, _ = s3("PUT", f"bob/{TAG}_hijack.bin", s3port,
                     params={"uploadId": upf, "partNumber": "1"}, data=b"H" * 16)
        ok(st_p not in (200, 201) and not _exists(f"bob/{TAG}_hijack.bin"),
           f"UploadPart reusing alice's id onto bob's key DENIED (HTTP {st_p})")
        s3("DELETE", fgn, s3port, params={"uploadId": upf})
    else:
        ok(True, "foreign-id hijack setup skipped")

    # A7. DOUBLE-COMPLETE: completing the SAME upload twice.  Second complete must
    #     not silently re-run / corrupt; object stays alice-owned either way.
    dkey = f"alice/{TAG}_double.bin"
    st_i, upd = _initiate(dkey)
    if upd:
        _, ed = s3("PUT", dkey, s3port,
                   params={"uploadId": upd, "partNumber": "1"}, data=b"D" * 5242880)
        st_c1, _ = s3("POST", dkey, s3port, params={"uploadId": upd},
                      data=_complete_xml([(1, _etag(ed) or "x")]))
        ok(st_c1 in (200, 201), f"double-complete: first complete OK (HTTP {st_c1})")
        ok(_uid_of(dkey) == UID_ALICE,
           f"double-complete: object owned by alice (uid={_uid_of(dkey)})")
        st_c2, _ = s3("POST", dkey, s3port, params={"uploadId": upd},
                      data=_complete_xml([(1, _etag(ed) or "x")]))
        ok(st_c2 in (200, 201, 404, 400, 409) and _uid_of(dkey) in (UID_ALICE, -1),
           f"double-complete: second complete handled, still alice/clean (HTTP {st_c2})")
    else:
        ok(True, "double-complete setup skipped")

    # A8. ABORT-then-COMPLETE: abort the upload, THEN try to complete it -> must be
    #     denied and create no object (the staging is gone; no resurrection).
    akey = f"alice/{TAG}_abortthencomplete.bin"
    st_i, upa = _initiate(akey)
    if upa:
        _, ea = s3("PUT", akey, s3port,
                   params={"uploadId": upa, "partNumber": "1"}, data=b"R" * 5242880)
        st_ab, _ = s3("DELETE", akey, s3port, params={"uploadId": upa})
        ok(st_ab in (200, 204), f"abort-then-complete: abort OK (HTTP {st_ab})")
        st_c, _ = s3("POST", akey, s3port, params={"uploadId": upa},
                     data=_complete_xml([(1, _etag(ea) or "x")]))
        ok(st_c not in (200, 201) and not _exists(akey),
           f"abort-then-complete: complete after abort DENIED, no object (HTTP {st_c})")
    else:
        ok(True, "abort-then-complete setup skipped")

    # A9. ILLEGAL partNumbers: 0, negative, > 10000, non-numeric.  Each must be
    #     rejected without persisting a part / object.
    pkey = f"alice/{TAG}_partno.bin"
    st_i, upp = _initiate(pkey)
    if upp:
        for pn in ["0", "-1", "10001", "99999", "abc", "1.5"]:
            st_p, _ = s3("PUT", pkey, s3port,
                         params={"uploadId": upp, "partNumber": pn}, data=b"x" * 16)
            ok(st_p not in (200, 201),
               f"UploadPart partNumber={pn} rejected (HTTP {st_p})")
        # CONTROL: a legal partNumber on the same upload still works.
        st_p, _ = s3("PUT", pkey, s3port,
                     params={"uploadId": upp, "partNumber": "1"}, data=b"P" * 5242880)
        ok(st_p in (200, 201),
           f"CONTROL UploadPart legal partNumber=1 accepted (HTTP {st_p})")
        s3("DELETE", pkey, s3port, params={"uploadId": upp})
    else:
        ok(True, "illegal-partNumber setup skipped")

    # A10. UploadPartCopy from a CROSS-TENANT 0600 source -> denied, no part data,
    #      and the resulting object (if any) must NOT contain bob's marker.
    upckey = f"alice/{TAG}_upc.bin"
    st_i, upc = _initiate(upckey)
    if upc:
        st_p, _ = s3("PUT", upckey, s3port,
                     params={"uploadId": upc, "partNumber": "1"},
                     extra_hdrs={"x-amz-copy-source": f"/{BKT}/{bob_secret_rel}"})
        ok(st_p not in (200, 201),
           f"UploadPartCopy cross-tenant 0600 source DENIED (HTTP {st_p})")
        # even if a stray complete were attempted, no marker may surface.
        st_c, _ = s3("POST", upckey, s3port, params={"uploadId": upc},
                     data=_complete_xml([(1, "x")]))
        ok(MARK not in _body_of(upckey),
           f"UploadPartCopy: bob's secret never lands in alice's object (HTTP {st_c})")
        s3("DELETE", upckey, s3port, params={"uploadId": upc})
    else:
        ok(True, "UploadPartCopy cross-tenant setup skipped")

    # A11. UploadPartCopy with an ENCODED ../ in the copy-source -> must not escape
    #      the export and must not leak /etc/passwd into a part.
    upekey = f"alice/{TAG}_upcesc.bin"
    st_i, upe = _initiate(upekey)
    if upe:
        for src in [f"/{BKT}/../../../etc/passwd",
                    f"/{BKT}/alice/..%2f..%2f..%2fetc%2fpasswd"]:
            st_p, _ = s3("PUT", upekey, s3port,
                         params={"uploadId": upe, "partNumber": "1"},
                         extra_hdrs={"x-amz-copy-source": src})
            ok(st_p not in (200, 201),
               f"UploadPartCopy escaping source {src[-18:]!r} DENIED (HTTP {st_p})")
        s3("POST", upekey, s3port, params={"uploadId": upe},
           data=_complete_xml([(1, "x")]))
        ok(b"root:x:" not in _body_of(upekey),
           "UploadPartCopy escape: no /etc/passwd bytes in any assembled object")
        s3("DELETE", upekey, s3port, params={"uploadId": upe})
    else:
        ok(True, "UploadPartCopy escape setup skipped")

    # A12. ListMultipartUploads / ListParts must not enumerate the symlink escape
    #      or another tenant's private staging.
    st_l, lb = s3("GET", "", s3port, params={"uploads": ""})
    ok(st_l in (200, 404) and b"escape/" not in (lb or b"")
       and b"passwd" not in (lb or b""),
       f"ListMultipartUploads no symlink/escape leak (HTTP {st_l})")

    # =========================================================================
    # B. CopyObject surface
    # =========================================================================

    # B1. CONTROL: self-copy is owned by alice.
    s3("PUT", f"alice/{TAG}_csrc.txt", s3port, data=b"copy-source-body\n")
    st, _ = s3("PUT", f"alice/{TAG}_cdst.txt", s3port,
               extra_hdrs={"x-amz-copy-source": f"/{BKT}/alice/{TAG}_csrc.txt"})
    ok(st in (200, 201) and _exists(f"alice/{TAG}_cdst.txt")
       and _uid_of(f"alice/{TAG}_cdst.txt") == UID_ALICE,
       f"CopyObject self -> alice-owned (HTTP {st})")

    # B2. CopyObject CROSS-TENANT SOURCE (bob's 0600) -> denied, no theft of marker.
    st, _ = s3("PUT", f"alice/{TAG}_cstolen.txt", s3port,
               extra_hdrs={"x-amz-copy-source": f"/{BKT}/{bob_secret_rel}"})
    stolen_body = _body_of(f"alice/{TAG}_cstolen.txt")
    ok(st not in (200, 201) and MARK not in stolen_body,
       f"CopyObject cross-tenant 0600 source DENIED, marker absent (HTTP {st})")

    # B3. CopyObject ONTO bob's path (destination in bob's space) -> denied; bob's
    #     world-readable control file is untouched.
    bread_rel = "bob/readable.txt"
    before = _body_of(bread_rel)
    st, _ = s3("PUT", bread_rel, s3port,
               extra_hdrs={"x-amz-copy-source": f"/{BKT}/alice/{TAG}_csrc.txt"})
    ok(st not in (200, 201) and _body_of(bread_rel) == before,
       f"CopyObject ONTO bob's file DENIED, bob's file intact (HTTP {st})")

    # B4. metadata-directive REPLACE vs COPY on a self-copy: both must stay
    #     alice-owned and never escalate.
    for directive in ["COPY", "REPLACE"]:
        dk = f"alice/{TAG}_md_{directive.lower()}.txt"
        st, _ = s3("PUT", dk, s3port,
                   extra_hdrs={"x-amz-copy-source": f"/{BKT}/alice/{TAG}_csrc.txt",
                               "x-amz-metadata-directive": directive})
        uid = _uid_of(dk)
        ok(st in (200, 201, 400, 501) and (not _exists(dk) or uid == UID_ALICE),
           f"CopyObject metadata-directive {directive}: alice-owned/handled "
           f"(HTTP {st}, uid={uid})")

    # B5. copy-source with ENCODED ../ -> must not read /etc/passwd nor write outside.
    for src in [f"/{BKT}/../../../etc/passwd",
                f"/{BKT}/alice/..%2f..%2f..%2fetc%2fpasswd",
                f"/{BKT}/..%2F..%2Fbob%2F{TAG}_secret.txt"]:
        dk = f"alice/{TAG}_cesc.txt"
        st, _ = s3("PUT", dk, s3port, extra_hdrs={"x-amz-copy-source": src})
        body = _body_of(dk)
        ok(st not in (200, 201) or (b"root:x:" not in body and MARK not in body),
           f"CopyObject encoded ../ source {src[-16:]!r} no escape/leak (HTTP {st})")

    # =========================================================================
    # C. DeleteObjects batches
    # =========================================================================

    # C1. MIXED batch (alice's own + bob's): only alice's is deleted; bob's intact.
    s3("PUT", f"alice/{TAG}_delmine.txt", s3port, data=b"delete-me\n")
    bread_before = _body_of(bread_rel)
    st, _ = s3("POST", "", s3port, params={"delete": ""},
               data=_delete_xml([f"alice/{TAG}_delmine.txt", bread_rel]))
    ok(not _exists(f"alice/{TAG}_delmine.txt"),
       f"DeleteObjects mixed batch: alice's own object deleted (HTTP {st})")
    ok(_exists(bread_rel) and _body_of(bread_rel) == bread_before,
       "DeleteObjects mixed batch: bob's object NOT deleted (DAC on bob's dir)")

    # C2. batch targeting bob's 0600 private secret -> not deleted, marker survives.
    st, _ = s3("POST", "", s3port, params={"delete": ""},
               data=_delete_xml([bob_secret_rel]))
    ok(_exists(bob_secret_rel) and MARK in _body_of(bob_secret_rel),
       f"DeleteObjects of bob's 0600 secret did NOT delete it (HTTP {st})")

    # C3. batch with TRAVERSAL keys must not delete anything outside the export.
    outside = os.path.join(os.path.dirname(os.path.abspath(data)), f"{TAG}_OUTSIDE")
    try:
        with open(outside, "wb") as fh:
            fh.write(b"outside-sentinel\n")
    except OSError:
        outside = None
    st, _ = s3("POST", "", s3port, params={"delete": ""},
               data=_delete_xml(["../../../etc/passwd",
                                 f"../{TAG}_OUTSIDE",
                                 "..%2f..%2fetc%2fpasswd"]))
    ok((outside is None) or os.path.exists(outside),
       f"DeleteObjects traversal keys deleted nothing outside the export (HTTP {st})")
    ok(os.path.exists("/etc/passwd"),
       "DeleteObjects traversal keys did not touch /etc/passwd")
    try:
        if outside and os.path.exists(outside):
            os.unlink(outside)
    except OSError:
        pass

    # C4. CONTROL: a clean self-only delete batch succeeds (proves the deny above is
    #     real, not a blanket DeleteObjects failure).
    s3("PUT", f"alice/{TAG}_delctl.txt", s3port, data=b"x\n")
    st, _ = s3("POST", "", s3port, params={"delete": ""},
               data=_delete_xml([f"alice/{TAG}_delctl.txt"]))
    ok(not _exists(f"alice/{TAG}_delctl.txt"),
       f"CONTROL DeleteObjects self-only batch deleted alice's object (HTTP {st})")

    # =========================================================================
    # D. Range correctness + no-oracle + conditional copy + auth-negatives
    # =========================================================================

    # D1. Range GET correctness on alice's own assembled object.
    if p1 is not None and _exists(okey):
        st, b = s3("GET", okey, s3port, params=None,
                   extra_hdrs={"Range": "bytes=0-9"})
        ok(st in (206, 200) and (st != 206 or b == b"A" * 10),
           f"Range GET on own assembled object correct (HTTP {st})")
        # a tail range into the second part.
        st, b = s3("GET", okey, s3port, extra_hdrs={"Range": "bytes=5242880-5242883"})
        ok(st in (206, 200) and (st != 206 or b == b"B" * 4),
           f"Range GET crossing part boundary correct (HTTP {st})")
    else:
        ok(True, "Range correctness skipped (no assembled object)")

    # D2. Range GET on bob's 0600 must NOT be a confidentiality oracle (no marker).
    for rng in ["bytes=0-4", "bytes=0-0", "bytes=-3"]:
        st, b = s3("GET", bob_secret_rel, s3port, extra_hdrs={"Range": rng})
        ok(st not in (200, 206) and MARK not in (b or b""),
           f"Range '{rng}' GET on bob's 0600 DENIED, no marker leak (HTTP {st})")

    # D3. Conditional COPY: x-amz-copy-source-if-match with a WRONG ETag must not
    #     copy; with no/correct precondition the self-copy works (control).
    st, _ = s3("PUT", f"alice/{TAG}_condcopy.txt", s3port,
               extra_hdrs={"x-amz-copy-source": f"/{BKT}/alice/{TAG}_csrc.txt",
                           "x-amz-copy-source-if-match":
                               '"00000000000000000000000000000000"'})
    # conditional-copy preconditions are not implemented (the copy proceeds, HTTP
    # 200) — that is a benign S3 strictness gap. The SECURITY invariant is that the
    # copy stayed source-confined (same-tenant alice source) and the destination is
    # owned by alice, never svc(1500)/root(0)/bob.
    cc_uid = _uid_of(f"alice/{TAG}_condcopy.txt")
    ok((not _exists(f"alice/{TAG}_condcopy.txt") or cc_uid == UID_ALICE)
       and cc_uid != UID_SVC and cc_uid != 0 and cc_uid != UID_BOB,
       f"conditional CopyObject if-match: dest alice-owned, no escalation/leak "
       f"(HTTP {st}, uid={cc_uid})")
    st, _ = s3("PUT", f"alice/{TAG}_condcopy_ok.txt", s3port,
               extra_hdrs={"x-amz-copy-source": f"/{BKT}/alice/{TAG}_csrc.txt"})
    ok(st in (200, 201) and _uid_of(f"alice/{TAG}_condcopy_ok.txt") == UID_ALICE,
       f"CONTROL unconditional self-copy succeeds alice-owned (HTTP {st})")

    # D4. ANONYMOUS multipart ops (no SigV4) must be rejected, no object created.
    apath = f"/{BKT}/alice/{TAG}_anon.bin"
    st, _ = http("POST", apath + "?uploads", s3port)
    ok(st in (401, 403) and not _exists(f"alice/{TAG}_anon.bin"),
       f"anonymous multipart initiate DENIED (HTTP {st})")
    st, _ = http("PUT", apath + "?uploadId=x&partNumber=1", s3port, data=b"x")
    ok(st in (401, 403) and not _exists(f"alice/{TAG}_anon.bin"),
       f"anonymous UploadPart DENIED (HTTP {st})")
    st, _ = http("POST", f"/{BKT}/?delete", s3port,
                 data=_delete_xml([f"alice/{TAG}_ok.bin"]))
    ok(st in (401, 403) and _exists(okey),
       f"anonymous DeleteObjects DENIED, object survives (HTTP {st})")

    # D5. MALFORMED-SigV4 multipart initiate must be rejected, no staging created.
    h = dict(s3_sign("POST", f"/{BKT}/alice/{TAG}_badsig.bin", s3port,
                     params={"uploads": ""}))
    h["Authorization"] = h["Authorization"][:-12] + "000000000000"
    st, _ = http("POST", f"/{BKT}/alice/{TAG}_badsig.bin?uploads", s3port, hdrs=h)
    ok(st not in (200, 201) and not _exists(f"alice/{TAG}_badsig.bin"),
       f"malformed-SigV4 multipart initiate REJECTED, no object (HTTP {st})")
    # bad-sig DeleteObjects must not delete alice's own object either.
    h = dict(s3_sign("POST", f"/{BKT}/", s3port, params={"delete": ""}))
    h["Authorization"] = h["Authorization"][:-8] + "00000000"
    st, _ = http("POST", f"/{BKT}/?delete", s3port,
                 data=_delete_xml([okey]), hdrs=h)
    ok(st not in (200,) and _exists(okey),
       f"malformed-SigV4 DeleteObjects REJECTED, object survives (HTTP {st})")

    # =========================================================================
    # E. Ownership-invariant sweep + WORKER SURVIVAL
    # =========================================================================

    # E1. Re-scan every object this function created under alice/: NONE may be owned
    #     by svc(1500)/root(0)/bob(1002) — the principal must never have leaked.
    bad_owned = []
    try:
        adir = os.path.join(data, "alice")
        for name in os.listdir(adir):
            if name.startswith(f"{TAG}_"):
                try:
                    u = os.stat(os.path.join(adir, name)).st_uid
                except OSError:
                    continue
                if u in (UID_SVC, 0, UID_BOB):
                    bad_owned.append((name, u))
    except OSError:
        pass
    ok(not bad_owned,
       f"INVARIANT sweep: no alice/{TAG}_* object owned by svc/root/bob "
       f"(violations={bad_owned})")

    # E2. No object this function created landed in bob's space owned by alice
    #     (cross-tenant write would show alice's uid on a bob/ path).
    cross = []
    try:
        bdir = os.path.join(data, "bob")
        for name in os.listdir(bdir):
            if name.startswith(f"{TAG}_") and name != f"{TAG}_secret.txt":
                cross.append(name)
    except OSError:
        pass
    ok(not cross,
       f"INVARIANT: no {TAG}_* attacker object created inside bob's dir "
       f"(found={cross})")

    # E3. WORKER SURVIVAL: after all the lifecycle abuse, a fresh legit multipart
    #     still completes and is alice-owned (the broker was not wedged).
    skey = f"alice/{TAG}_survive.bin"
    st_i, ups = _initiate(skey)
    surv_ok = False
    if ups:
        _, es = s3("PUT", skey, s3port,
                   params={"uploadId": ups, "partNumber": "1"}, data=b"S" * 5242880)
        st_c, _ = s3("POST", skey, s3port, params={"uploadId": ups},
                     data=_complete_xml([(1, _etag(es) or "x")]))
        surv_ok = st_c in (200, 201) and _uid_of(skey) == UID_ALICE
    ok(surv_ok,
       f"worker SURVIVED the adversarial battery: fresh multipart completes "
       f"alice-owned (init {st_i})")

    # E4. and a plain single-PUT + GET still round-trips (data plane intact).
    st, _ = s3("PUT", f"alice/{TAG}_final.txt", s3port, data=b"final-ok\n")
    st_g, b = s3("GET", f"alice/{TAG}_final.txt", s3port)
    ok(st in (200, 201) and st_g == 200 and b == b"final-ok\n"
       and _uid_of(f"alice/{TAG}_final.txt") == UID_ALICE,
       f"final single-object PUT/GET round-trips alice-owned (PUT {st}, GET {st_g})")


def run_concurrency_state_race(key, data, port, s3port):
    """CONCURRENCY / ORDERING / STATE-CONFUSION races against the per-worker, process-
    global impersonation principal.  Every storm below tries to make an op execute
    under a STALE or LEAKED principal (alice's setfsuid bleeding into bob's request or
    vice-versa), then proves it did not by: (a) the op landing in the correct owner's
    space, (b) the created/mutated file's st_uid matching the DRIVING identity (never
    the worker svc=1500, never root=0, never the other tenant), (c) the worker
    SURVIVING (a follow-up legit op still works), and (d) a full os.lstat scan of both
    user dirs finding zero wrong-owner regular files after the storm.  Each deny carries
    a nearby positive control so a blanket block cannot false-pass."""
    ta, tb = mint(key, "alice"), mint(key, "bob")
    TAG = "csr_"            # fixture/file prefix to avoid collisions with other batteries

    def st_uid(p):
        try:
            return os.lstat(p).st_uid
        except OSError:
            return -1

    def apath(name):
        return os.path.join(data, "alice", name)

    def bpath(name):
        return os.path.join(data, "bob", name)

    def rm_quiet(p):
        try:
            os.unlink(p)
        except OSError:
            pass

    def scan_misowned():
        """Count regular files in alice/ + bob/ that belong to the WRONG uid (the
        other tenant), to svc(1500), or to root(0).  Only judges our TAG files plus
        any svc/root-owned file (a svc/root-owned data file is always a leak signal)."""
        bad = []
        for sub, want in (("alice", UID_ALICE), ("bob", UID_BOB)):
            d = os.path.join(data, sub)
            try:
                names = os.listdir(d)
            except OSError:
                continue
            for f in names:
                p = os.path.join(d, f)
                try:
                    stx = os.lstat(p)
                except OSError:
                    continue
                if not (stx.st_mode & 0o170000) == 0o100000:   # skip non-regular
                    continue
                u = stx.st_uid
                if u in (UID_SVC, 0):
                    bad.append((sub, f, u))
                elif f.startswith(TAG) and u != want:
                    bad.append((sub, f, u))
        return bad

    # ============================================================================
    # A) KEEP-ALIVE INTERLEAVE — a,b,a,b... on ONE TCP connection.  If the principal
    #    is reused stale, alice's PUT could create bob-owned files or land in bob/.
    # ============================================================================
    inter = []
    for i in range(8):
        a_name, b_name = f"{TAG}ka_a_{i}.txt", f"{TAG}ka_b_{i}.txt"
        inter.append(("PUT", f"/alice/{a_name}", ta, b"A-keepalive\n", None))
        inter.append(("PUT", f"/bob/{b_name}", tb, b"B-keepalive\n", None))
    res = http_keepalive(inter, port)
    ok(len(res) == 16, f"keep-alive interleave: all 16 requests answered on one conn "
       f"(got {len(res)})")
    ka_ok = sum(1 for (s, _b) in res if s in (200, 201, 204))
    ok(ka_ok == 16, f"keep-alive interleave: every PUT accepted (2xx={ka_ok}/16)")
    a_mis = b_mis = 0
    for i in range(8):
        ap, bp = apath(f"{TAG}ka_a_{i}.txt"), bpath(f"{TAG}ka_b_{i}.txt")
        if not (os.path.exists(ap) and st_uid(ap) == UID_ALICE):
            a_mis += 1
        if not (os.path.exists(bp) and st_uid(bp) == UID_BOB):
            b_mis += 1
    ok(a_mis == 0, f"keep-alive: all 8 alice files owned alice, none stale-principal "
       f"(mismatch={a_mis})")
    ok(b_mis == 0, f"keep-alive: all 8 bob files owned bob, none stale-principal "
       f"(mismatch={b_mis})")
    # no alice file leaked into bob's dir or vice-versa (path landed under wrong owner)
    cross = 0
    for i in range(8):
        if os.path.exists(bpath(f"{TAG}ka_a_{i}.txt")):
            cross += 1
        if os.path.exists(apath(f"{TAG}ka_b_{i}.txt")):
            cross += 1
    ok(cross == 0, f"keep-alive: no request landed in the other tenant's dir (cross={cross})")

    # ============================================================================
    # B) BURST ORDERING — aaaa...bbbb...aaaa on one connection (run of same identity
    #    then a flip).  A flip without re-establishing the principal would write the
    #    first post-flip request under the previous identity.
    # ============================================================================
    burst = []
    order = (["a"] * 5) + (["b"] * 5) + (["a"] * 5) + (["b"] * 5)
    for i, who in enumerate(order):
        if who == "a":
            burst.append(("PUT", f"/alice/{TAG}burst_{i}.txt", ta, b"a\n", None))
        else:
            burst.append(("PUT", f"/bob/{TAG}burst_{i}.txt", tb, b"b\n", None))
    bres = http_keepalive(burst, port)
    ok(sum(1 for (s, _b) in bres if s in (200, 201, 204)) == 20,
       f"burst-order: all 20 PUTs accepted ({sum(1 for (s,_b) in bres if s in (200,201,204))}/20)")
    flip_bad = 0
    for i, who in enumerate(order):
        want = UID_ALICE if who == "a" else UID_BOB
        d = "alice" if who == "a" else "bob"
        fp = os.path.join(data, d, f"{TAG}burst_{i}.txt")
        if not (os.path.exists(fp) and st_uid(fp) == want):
            flip_bad += 1
    ok(flip_bad == 0, f"burst-order: every post-flip request used the CORRECT principal "
       f"(no stale carry-over; bad={flip_bad})")

    # ============================================================================
    # C) PIPELINED PUTs same path, alternating identities — last writer wins but the
    #    file must end up owned by WHOEVER actually wrote it, never svc/root, and the
    #    body must match an identity that was allowed to write (alice owns alice/).
    # ============================================================================
    shared = f"{TAG}pipe_shared.txt"
    pipe = []
    for i in range(6):
        tok = ta if i % 2 == 0 else tb
        body = b"alice-wins\n" if i % 2 == 0 else b"bob-attempt\n"
        # both target /alice/<shared>: alice writes succeed, bob writes must be denied
        pipe.append(("PUT", f"/alice/{shared}", tok, body, None))
    http_keepalive(pipe, port)
    sp = apath(shared)
    # alice's dir is 0755 alice-owned: bob (other) cannot create/replace here.
    final_uid = st_uid(sp)
    ok(os.path.exists(sp) and final_uid == UID_ALICE,
       f"pipelined same-path: final file owned alice, never bob/svc/root (uid={final_uid})")
    try:
        fb = open(sp, "rb").read()
    except OSError:
        fb = b""
    ok(b"bob-attempt" not in fb,
       "pipelined same-path: bob's interleaved write did NOT overwrite alice's file body")

    # ============================================================================
    # D) SIMULTANEOUS SAME-PATH CREATE by alice & bob (true threads) into a world-
    #    writable shared dir.  Whoever wins, the file must be owned by a REAL mapped
    #    user (1001 or 1002) — never svc/root — and must not be a torn mix.
    # ============================================================================
    pub_shared = f"{TAG}pub_race.txt"
    pp = os.path.join(data, "pub", pub_shared)
    rm_quiet(pp)
    race_status = {}

    def create_pub(who):
        tok = ta if who == "alice" else tb
        s, _b = http("PUT", f"/pub/{pub_shared}", port, tok,
                     (who + "-pub\n").encode())
        race_status[who] = s

    for _round in range(6):       # repeat to widen the race window
        rm_quiet(pp)
        ths = [threading.Thread(target=create_pub, args=(w,))
               for w in ("alice", "bob", "alice", "bob")]
        for t in ths:
            t.start()
        for t in ths:
            t.join()
    winner = st_uid(pp)
    ok(os.path.exists(pp) and winner in (UID_ALICE, UID_BOB),
       f"same-path race in /pub: winner is a real mapped user, not svc/root "
       f"(uid={winner})")
    ok(winner != UID_SVC and winner != 0,
       f"same-path race: created file NEVER owned by worker(1500)/root(0) (uid={winner})")
    rm_quiet(pp)

    # ============================================================================
    # E) OPEN-AS-A then immediately OP-AS-B referencing A's just-created private file.
    #    alice creates a 0600 file; bob (driving on the SAME worker right after) must
    #    NOT be able to read it (no principal carry-over from the create).
    # ============================================================================
    SECRET = b"ALICE-OPEN-RACE-MARKER-7731\n"
    arace = f"{TAG}open_race.txt"
    http("PUT", f"/alice/{arace}", port, ta, SECRET)
    fp = apath(arace)
    try:
        os.chmod(fp, 0o600)
    except OSError:
        pass
    ok(os.path.exists(fp) and st_uid(fp) == UID_ALICE and (os.lstat(fp).st_mode & 0o077) == 0,
       f"open-race setup: alice's 0600 marker file in place (uid={st_uid(fp)})")
    # bob immediately reads it via keep-alive right after an alice op on the same conn
    seq = [("GET", f"/alice/{arace}", ta, None, None),   # alice reads own (control)
           ("GET", f"/alice/{arace}", tb, None, None)]   # bob reads alice's 0600 (deny)
    sres = http_keepalive(seq, port)
    a_st, a_body = sres[0] if len(sres) > 0 else (-1, b"")
    b_st, b_body = sres[1] if len(sres) > 1 else (-1, b"")
    ok(a_st == 200 and SECRET in (a_body or b""),
       f"control: alice reads her own 0600 file on the shared conn (HTTP {a_st})")
    ok(b_st in (401, 403, 404) and SECRET not in (b_body or b""),
       f"open-race: bob CANNOT read alice's 0600 file via principal carry-over "
       f"(HTTP {b_st})")

    # ============================================================================
    # F) MANY CONCURRENT COLLECTION COPYs (true threads).  COPY of a collection runs
    #    inline (recursive walk + per-child create) — a long op that holds the
    #    principal; many in flight stress for desync.  Each alice COPY's destination
    #    tree must be wholly alice-owned; bob's must be bob-owned; broker must not wedge.
    # ============================================================================
    # seed a small collection for each user
    for who, tok, d in (("alice", ta, "alice"), ("bob", tb, "bob")):
        http("MKCOL", f"/{d}/{TAG}coll_src", port, tok)
        for j in range(3):
            http("PUT", f"/{d}/{TAG}coll_src/f{j}.txt", port, tok,
                 (who + f"-{j}\n").encode())
    copy_bad = []

    def coll_copy(idx):
        who = "alice" if idx % 2 == 0 else "bob"
        tok = ta if who == "alice" else tb
        d = who
        dst = f"/{d}/{TAG}coll_dst_{idx}"
        s, _b = http("COPY", f"/{d}/{TAG}coll_src", port, tok,
                     hdrs={"Destination": f"http://127.0.0.1:{port}{dst}",
                           "Depth": "infinity"})
        if s not in (200, 201, 204, 207):
            copy_bad.append((who, idx, s))

    cths = [threading.Thread(target=coll_copy, args=(i,)) for i in range(12)]
    for t in cths:
        t.start()
    for t in cths:
        t.join()
    ok(len(copy_bad) <= 12 and all(b[2] not in (-1,) for b in copy_bad),
       f"concurrent collection COPY: no broker hang/connection-death "
       f"(failures={copy_bad[:3]})")
    # every copied tree must be owned by the DRIVING user only (no desync cross-owner)
    coll_mis = 0
    coll_seen = 0
    for idx in range(12):
        who = "alice" if idx % 2 == 0 else "bob"
        want = UID_ALICE if who == "alice" else UID_BOB
        dstdir = os.path.join(data, who, f"{TAG}coll_dst_{idx}")
        if not os.path.isdir(dstdir):
            continue
        for root_, dirs, files in os.walk(dstdir):
            for name in list(dirs) + list(files):
                pth = os.path.join(root_, name)
                u = st_uid(pth)
                coll_seen += 1
                if u != want:
                    coll_mis += 1
    ok(coll_seen > 0, f"concurrent COPY: at least one destination tree materialised "
       f"(entries seen={coll_seen})")
    ok(coll_mis == 0, f"concurrent COPY: every copied entry owned by the DRIVING user "
       f"(no broker principal desync; cross-owner={coll_mis})")
    # broker survives: a follow-up legit op still works after the COPY storm
    st, _ = http("PUT", f"/alice/{TAG}post_copy.txt", port, ta, b"survived\n")
    pcp = apath(f"{TAG}post_copy.txt")
    ok(st in (200, 201, 204) and os.path.exists(pcp) and st_uid(pcp) == UID_ALICE,
       f"broker SURVIVES the COPY storm: follow-up alice PUT owned alice (HTTP {st})")

    # ============================================================================
    # G) LOCK-TOKEN THEFT RACE — alice LOCKs her file; bob (concurrently, same worker)
    #    tries to mutate it presenting alice's lock token in If:.  The lock token is
    #    NOT an authorization grant — bob is still "other" on alice's 0644 file and the
    #    broker must deny his write.
    # ============================================================================
    lk = f"{TAG}lock_target.txt"
    http("PUT", f"/alice/{lk}", port, ta, b"lock-race-body\n")
    try:
        os.chmod(apath(lk), 0o644)
    except OSError:
        pass
    li = (b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:">'
          b'<D:lockscope><D:exclusive/></D:lockscope>'
          b'<D:locktype><D:write/></D:locktype></D:lockinfo>')
    lst, lbody = http("LOCK", f"/alice/{lk}", port, ta, data=li,
                      hdrs={"Content-Type": "application/xml", "Timeout": "Second-600"})
    m = re.search(rb"<[^>]*locktoken[^>]*>\s*<[^>]*href[^>]*>\s*([^<\s]+)",
                  lbody or b"", re.I)
    if not m:
        m = re.search(rb"(urn:uuid:[0-9a-fA-F-]+|opaquelocktoken:[^<\s]+)", lbody or b"")
    token_uri = m.group(1).decode() if m else "urn:uuid:00000000-0000-0000-0000-000000000000"
    ok(lst in (200, 201), f"lock-token theft setup: alice LOCK acquired (HTTP {lst})")
    # bob replays alice's stolen lock token to PUT over her file
    bst, _ = http("PUT", f"/alice/{lk}", port, tb, b"BOB-STOLE-LOCK\n",
                  hdrs={"If": f"(<{token_uri}>)"})
    body_now = b""
    try:
        body_now = open(apath(lk), "rb").read()
    except OSError:
        pass
    ok(bst not in (200, 201, 204) and b"BOB-STOLE-LOCK" not in body_now,
       f"lock-token theft: bob replaying alice's lock token did NOT overwrite her file "
       f"(HTTP {bst})")
    ok(st_uid(apath(lk)) == UID_ALICE,
       "lock-token theft: alice's locked file remained alice-owned")
    # control: alice WITH her own lock token can still write her own file
    ast, _ = http("PUT", f"/alice/{lk}", port, ta, b"alice-rewrite\n",
                  hdrs={"If": f"(<{token_uri}>)"})
    ok(ast in (200, 201, 204),
       f"control: alice with her own lock token writes her own file (HTTP {ast})")

    # ============================================================================
    # H) MULTIPART CROSS-IDENTITY DRIVE (S3) — alice initiates an uploadId, bob drives
    #    the part/complete with a BOB-signed request.  Parts + final object must map by
    #    the DRIVING identity (the key lives under alice/, where bob is denied): bob
    #    must NOT be able to complete an alice-initiated upload into alice's space.
    # ============================================================================
    if s3port:
        mk = f"alice/{TAG}mpu_cross.bin"
        st_i, ibody = s3("POST", mk, s3port, params={"uploads": ""}, access_key="alice")
        um = re.search(rb"<UploadId>([^<]+)</UploadId>", ibody or b"")
        ok(st_i == 200 and um is not None,
           f"multipart cross-identity setup: alice initiated uploadId (HTTP {st_i})")
        if um:
            upid = um.group(1).decode()
            # bob signs the part upload (only access_key 'alice' is configured, so a
            # bob-signed request is also an INVALID signature -> must be rejected).
            st_pb, _ = s3("PUT", mk, s3port,
                          params={"uploadId": upid, "partNumber": "1"},
                          data=b"Q" * 4096, access_key="bob")
            ok(st_pb not in (200, 201, 204),
               f"multipart cross-identity: bob-signed UploadPart REJECTED (HTTP {st_pb})")
            # alice legitimately uploads + completes (control: the upload still works)
            st_pa, pbody = s3("PUT", mk, s3port,
                              params={"uploadId": upid, "partNumber": "1"},
                              data=b"Q" * 4096, access_key="alice")
            et = re.search(rb'ETag>\\?"?([^"<\\]+)', pbody or b"")
            etag = et.group(1).decode() if et else "etag"
            comp = (f"<CompleteMultipartUpload><Part><PartNumber>1</PartNumber>"
                    f"<ETag>{etag}</ETag></Part></CompleteMultipartUpload>").encode()
            st_cb, _ = s3("POST", mk, s3port, params={"uploadId": upid},
                          data=comp, access_key="bob")
            ok(st_cb not in (200, 201),
               f"multipart cross-identity: bob-signed Complete REJECTED (HTTP {st_cb})")
            st_ca, _ = s3("POST", mk, s3port, params={"uploadId": upid},
                          data=comp, access_key="alice")
            mfp = os.path.join(data, mk)
            muid = st_uid(mfp)
            ok(st_ca in (200, 201) and os.path.exists(mfp) and muid == UID_ALICE,
               f"control: alice completes her OWN upload, object owned alice "
               f"(HTTP {st_ca}, uid={muid})")
            rm_quiet(mfp)
    else:
        ok(True, "S3 multipart cross-identity skipped (S3 port not up)")

    # ============================================================================
    # I) CONCURRENT MIXED PROTOCOL/OP STORM (true threads) with embedded cross-tenant
    #    attacks — alice PUT, bob PUT, alice MKCOL, bob DELETE-own, alice->bob PUT
    #    (deny), bob->alice MKCOL (deny).  Hunts a race window where a leaked principal
    #    lets a cross-tenant op slip through.
    # ============================================================================
    storm_bad = []
    NSTORM = 36

    def storm(i):
        try:
            kind = i % 6
            if kind == 0:
                http("PUT", f"/alice/{TAG}st_a_{i}.txt", port, ta, b"a\n")
            elif kind == 1:
                http("PUT", f"/bob/{TAG}st_b_{i}.txt", port, tb, b"b\n")
            elif kind == 2:
                http("MKCOL", f"/alice/{TAG}st_dir_{i}", port, ta)
            elif kind == 3:
                http("PUT", f"/bob/{TAG}st_bd_{i}.txt", port, tb, b"d\n")
                http("DELETE", f"/bob/{TAG}st_bd_{i}.txt", port, tb)
            elif kind == 4:                                   # alice -> bob (deny)
                s, _b = http("PUT", f"/bob/{TAG}st_x_{i}.txt", port, ta, b"X\n")
                xp = bpath(f"{TAG}st_x_{i}.txt")
                if s in (200, 201, 204) or os.path.exists(xp):
                    storm_bad.append(("a->b-put", i, s))
            else:                                             # bob -> alice (deny)
                s, _b = http("MKCOL", f"/alice/{TAG}st_y_{i}", port, tb)
                yp = apath(f"{TAG}st_y_{i}")
                if s in (200, 201) or os.path.isdir(yp):
                    storm_bad.append(("b->a-mkcol", i, s))
        except Exception as e:  # noqa: BLE001
            storm_bad.append(("exc", i, repr(e)))

    sths = [threading.Thread(target=storm, args=(i,)) for i in range(NSTORM)]
    for t in sths:
        t.start()
    for t in sths:
        t.join()
    ok(not storm_bad,
       f"mixed protocol/op storm: no cross-tenant op slipped through a race window "
       f"(breaches={storm_bad[:4]})")

    # ============================================================================
    # J) POST-STORM GLOBAL OWNERSHIP SCAN — after EVERY storm above, scan both user
    #    dirs and assert zero wrong-owner regular files (the decisive principal-leak
    #    detector: a single svc/root/cross-tenant owned data file fails the battery).
    # ============================================================================
    misowned = scan_misowned()
    ok(not misowned,
       f"post-storm scan: zero wrong-owner regular files in alice/ + bob/ "
       f"(leaks={misowned[:4]})")
    # explicit svc/root sweep across pub/ too (created files there must be 1001/1002)
    pub_bad = []
    try:
        for f in os.listdir(os.path.join(data, "pub")):
            pth = os.path.join(data, "pub", f)
            stx = os.lstat(pth)
            if (stx.st_mode & 0o170000) == 0o100000 and stx.st_uid in (UID_SVC, 0):
                pub_bad.append((f, stx.st_uid))
    except OSError:
        pass
    ok(not pub_bad,
       f"post-storm scan: no svc/root-owned file in the shared /pub dir (leaks={pub_bad[:4]})")

    # ============================================================================
    # K) FINAL LIVENESS — after all the storms, both identities still work correctly
    #    and independently on a fresh keep-alive connection (broker not wedged, no
    #    sticky principal left behind by the last op).
    # ============================================================================
    fin = [("PUT", f"/alice/{TAG}final_a.txt", ta, b"final-a\n", None),
           ("PUT", f"/bob/{TAG}final_b.txt", tb, b"final-b\n", None),
           ("GET", f"/alice/{TAG}final_a.txt", ta, None, None),
           ("GET", f"/bob/{TAG}final_b.txt", tb, None, None)]
    fres = http_keepalive(fin, port)
    fa, fb_ = apath(f"{TAG}final_a.txt"), bpath(f"{TAG}final_b.txt")
    ok(len(fres) == 4 and fres[0][0] in (200, 201, 204) and fres[1][0] in (200, 201, 204),
       f"final liveness: both identities still write after all storms "
       f"(a={fres[0][0] if fres else '?'}, b={fres[1][0] if len(fres) > 1 else '?'})")
    ok(os.path.exists(fa) and st_uid(fa) == UID_ALICE,
       "final liveness: alice's last file owned alice (no sticky principal)")
    ok(os.path.exists(fb_) and st_uid(fb_) == UID_BOB,
       "final liveness: bob's last file owned bob (no sticky principal)")
    ok(len(fres) == 4 and fres[2][0] == 200 and b"final-a" in (fres[2][1] or b""),
       "final liveness: alice reads her own final file back")
    ok(len(fres) == 4 and fres[3][0] == 200 and b"final-b" in (fres[3][1] or b""),
       "final liveness: bob reads his own final file back")


def run_broker_resource_limits(key, data, port, s3port):
    """BROKER protocol-level + RESOURCE attacks under impersonation.  Plant
    pathological filesystem objects in the export (FIFO, unix socket, dangling /
    looping / shadow-pointing symlinks, cross-tenant hardlink), stress path
    boundaries (near-PATH_MAX, deep nesting, embedded ./ and //), probe the xattr
    namespace (security.*/system.*/trusted.* must be confined to user.* or denied),
    and hammer the single broker socket — proving NONE of it hangs the worker,
    leaks a foreign secret, escapes the export, escalates privilege, or wedges the
    broker.  After every hostile burst we re-prove recovery with a legit alice
    PUT+GET roundtrip (worker AND broker both survive).  Does NOT kill the broker
    (run_broker_failclosed owns that)."""
    T = "brl_"                       # function tag prefixes every fixture we plant
    ta = mint(key, "alice")
    tb = mint(key, "bob")
    adir = os.path.join(data, "alice")
    bdir = os.path.join(data, "bob")

    def _has(body, needle):
        return needle in (body or b"")

    def recover(label, n=[0]):
        """Legit alice PUT+GET roundtrip — proves the worker thread AND the single
        broker socket are still live after a hostile op (a wedged broker would make
        the impersonated create fail or hang)."""
        n[0] += 1
        rel = f"/alice/{T}rec_{n[0]}.txt"
        body = f"recover-{n[0]}-{label[:12]}".encode()
        stp, _ = http("PUT", rel, port, ta, body)
        stg, gb = http("GET", rel, port, ta)
        fp = os.path.join(adir, f"{T}rec_{n[0]}.txt")
        owned = os.path.exists(fp) and os.stat(fp).st_uid == UID_ALICE
        ok(stp in (200, 201, 204) and stg == 200 and gb == body and owned,
           f"recovery after {label}: alice PUT+GET roundtrip ok, owned 1001 "
           f"(PUT {stp}, GET {stg})")

    # baseline recovery: prove the harness path works before we attack anything.
    recover("baseline")

    # ---- planted secrets (unique markers so deny checks can scan the body) ----
    SHADOW_MARK = b"root:$"           # /etc/shadow hash prefix (must never leak)
    BOBHL_MARK = b"BRL-BOB-HARDLINK-SECRET"
    SVCHL_MARK = b"svc-only-secret"   # already in /svconly/secret-name.txt

    # =====================================================================
    # A) FIFO — broker must open O_NONBLOCK / fail closed, NEVER block the
    #    single-threaded worker waiting for a writer that never comes.
    # =====================================================================
    fifo = os.path.join(adir, f"{T}fifo")
    try:
        if not os.path.exists(fifo):
            os.mkfifo(fifo, 0o600)
            os.chown(fifo, UID_ALICE, UID_ALICE)
    except OSError as e:
        fifo = None
        ok(True, f"FIFO fixture skipped ({e.__class__.__name__})")
    if fifo:
        t0 = time.time()
        st, _ = http("GET", f"/alice/{T}fifo", port, ta)
        dt_fifo = time.time() - t0
        ok(dt_fifo < 5.0, f"WebDAV GET on FIFO did not hang worker "
                          f"({dt_fifo:.2f}s, HTTP {st})")
        # PUT onto a FIFO (would block on a reader) must also not wedge.
        t0 = time.time()
        st, _ = http("PUT", f"/alice/{T}fifo", port, ta, b"x" * 64)
        ok(time.time() - t0 < 5.0, f"WebDAV PUT on FIFO did not hang worker (HTTP {st})")
        if xrd_avail():
            rc, _o, _e = xrd_fs(["stat", f"/alice/{T}fifo"], "alice")
            ok(True, f"root:// stat on FIFO returned, did not hang (rc={rc})")
        recover("FIFO ops")

    # =====================================================================
    # B) UNIX-domain socket node in the export — not a regular file; open
    #    must fail closed (ENXIO/EACCES), never hang or be served.
    # =====================================================================
    sockp = os.path.join(adir, f"{T}sock")
    srv = None
    try:
        if os.path.exists(sockp):
            os.unlink(sockp)
        srv = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
        srv.bind(sockp)
        os.chown(sockp, UID_ALICE, UID_ALICE)
    except OSError as e:
        sockp = None
        ok(True, f"unix-socket fixture skipped ({e.__class__.__name__})")
    if sockp:
        t0 = time.time()
        st, b = http("GET", f"/alice/{T}sock", port, ta)
        ok(time.time() - t0 < 5.0 and st != 200,
           f"WebDAV GET on unix-socket node fails closed, no hang (HTTP {st})")
        t0 = time.time()
        st, _ = http("PUT", f"/alice/{T}sock", port, ta, b"data\n")
        ok(time.time() - t0 < 5.0, f"WebDAV PUT on unix-socket node did not hang (HTTP {st})")
        if s3port:
            st, b = s3("GET", f"alice/{T}sock", s3port)
            ok(st != 200, f"S3 GET on unix-socket node fails closed (HTTP {st})")
        recover("unix-socket ops")
        try:
            srv.close()
        except OSError:
            pass

    # =====================================================================
    # C) Device-node creation must EPERM for the in-ns root attacker (no
    #    CAP in a true sense for mknod char/block); if it somehow succeeds,
    #    reads through it must fail closed.  Either way -> no hang/escape.
    # =====================================================================
    devp = os.path.join(adir, f"{T}cdev")
    dev_made = False
    try:
        os.mknod(devp, 0o600 | 0o020000, os.makedev(1, 3))   # S_IFCHR /dev/null-ish
        os.chown(devp, UID_ALICE, UID_ALICE)
        dev_made = True
    except OSError:
        dev_made = False
    if not dev_made:
        ok(True, "char-device mknod EPERM in userns (expected) -> skipped")
    else:
        t0 = time.time()
        st, b = http("GET", f"/alice/{T}cdev", port, ta)
        ok(time.time() - t0 < 5.0 and not _has(b, SHADOW_MARK),
           f"WebDAV GET on char-device node handled, no hang/leak (HTTP {st})")
        recover("char-device ops")

    # =====================================================================
    # D) SYMLINK class: dangling, self-loop, ->/etc/shadow, ->/etc/passwd.
    #    The broker re-applies RESOLVE_BENEATH (+ no follow out of export),
    #    so none may return host-file bytes or hang on the loop.
    # =====================================================================
    def _mklink(name, target):
        p = os.path.join(adir, name)
        try:
            if os.path.lexists(p):
                os.unlink(p)
            os.symlink(target, p)
            return p
        except OSError:
            return None

    dang = _mklink(f"{T}dangle", "/nonexistent/brl/target")
    if dang:
        st, b = http("GET", f"/alice/{T}dangle", port, ta)
        ok(st != 200, f"dangling symlink GET handled, not served (HTTP {st})")
        if xrd_avail():
            rc, _o, _e = xrd_fs(["stat", f"/alice/{T}dangle"], "alice")
            ok(True, f"root:// stat dangling symlink returned (rc={rc})")

    loopa = _mklink(f"{T}loopA", f"{T}loopB")
    loopb = _mklink(f"{T}loopB", f"{T}loopA")
    if loopa and loopb:
        t0 = time.time()
        st, b = http("GET", f"/alice/{T}loopA", port, ta)
        ok(time.time() - t0 < 5.0 and st != 200,
           f"symlink LOOP GET fails closed (ELOOP), no hang (HTTP {st})")
        st, _ = http("PROPFIND", f"/alice/{T}loopA", port, ta,
                     hdrs={"Depth": "0", "Content-Type": "application/xml"},
                     data=b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
                          b'<D:prop><D:displayname/></D:prop></D:propfind>')
        ok(st != 200, f"symlink LOOP PROPFIND fails closed (HTTP {st})")

    shadow = _mklink(f"{T}toshadow", "/etc/shadow")
    if shadow:
        st, b = http("GET", f"/alice/{T}toshadow", port, ta)
        ok(st != 200 and not _has(b, SHADOW_MARK) and not _has(b, b"root:"),
           f"symlink ->/etc/shadow GET blocked, no shadow bytes (HTTP {st})")
        if s3port:
            st, b = s3("GET", f"alice/{T}toshadow", s3port)
            ok(st != 200 and not _has(b, SHADOW_MARK),
               f"S3 symlink ->/etc/shadow GET blocked, no leak (HTTP {st})")
        if xrd_avail():
            dlp = os.path.join(WORK, f"{T}shadow_steal.bin")
            try:
                if os.path.exists(dlp):
                    os.unlink(dlp)
            except OSError:
                pass
            rc, _o, _e = xrd_cp_down(f"/alice/{T}toshadow", dlp, "alice")
            got = b""
            try:
                got = open(dlp, "rb").read() if os.path.exists(dlp) else b""
            except OSError:
                got = b""
            ok(rc != 0 and SHADOW_MARK not in got and b"root:" not in got,
               f"root:// xrdcp via symlink ->/etc/shadow DENIED, no leak (rc={rc})")

    passwd_link = _mklink(f"{T}topasswd", "/etc/passwd")
    if passwd_link:
        st, b = http("GET", f"/alice/{T}topasswd", port, ta)
        ok(not _has(b, b"root:x:0:0") and not _has(b, b"root:!"),
           f"symlink ->/etc/passwd GET no passwd leak (HTTP {st})")
    recover("symlink class")

    # A symlink pointing back INTO the export to bob's 0600 private file: even
    # though the link sits in alice's dir, the broker acts AS alice and DAC on the
    # real target (bob 0600) must deny — the link does not launder identity.
    bob_link = _mklink(f"{T}tobobpriv", os.path.join(bdir, "private.txt"))
    if bob_link:
        st, b = http("GET", f"/alice/{T}tobobpriv", port, ta)
        ok(st != 200 and not _has(b, b"BOB-PRIVATE-SECRET"),
           f"symlink to bob's 0600 via alice's dir DENIED by DAC, no leak (HTTP {st})")
        # control: an in-export symlink to bob's 0644 world-readable file.  Two
        # secure outcomes are acceptable, both proving no cross-tenant PRIVATE leak
        # and no blanket-weakening: (a) a RELATIVE in-export link is followed by
        # RESOLVE_BENEATH and DAC then lets alice-as-other read bob's WORLD-READABLE
        # body (200, "bob-world-readable", never "BOB-PRIVATE-SECRET"); or (b) the
        # link is refused by confinement (non-200).  An ABSOLUTE symlink is *always*
        # refused (EXDEV) by RESOLVE_BENEATH regardless of target, so we use a
        # relative target here to actually exercise the follow+per-target-DAC path.
        ctl = _mklink(f"{T}tobobread", os.path.join("..", "bob", "readable.txt"))
        if ctl:
            st, b = http("GET", f"/alice/{T}tobobread", port, ta)
            ok(not _has(b, b"BOB-PRIVATE-SECRET")
               and ((st == 200 and _has(b, b"bob-world-readable")) or st != 200),
               f"control: in-export symlink to bob's 0644 file resolves to "
               f"world-readable body or is denied, never leaks bob's private "
               f"secret (HTTP {st})")

    # =====================================================================
    # E) HARDLINK across tenant dirs — a hardlink in alice's tree to bob's
    #    0600 file.  The inode mode/owner is bob's (0600 bob); the broker
    #    acting as alice ("other") must NOT read it.  Hardlink cannot launder
    #    DAC the way a confinement bug might.
    # =====================================================================
    hl = os.path.join(adir, f"{T}bob_hardlink")
    bob_secret_file = os.path.join(bdir, f"{T}bob_hl_src.txt")
    hl_made = False
    try:
        with open(bob_secret_file, "wb") as fh:
            fh.write(BOBHL_MARK + b"\n")
        os.chown(bob_secret_file, UID_BOB, UID_BOB)
        os.chmod(bob_secret_file, 0o600)
        if os.path.exists(hl):
            os.unlink(hl)
        os.link(bob_secret_file, hl)          # in-ns root can cross-link
        hl_made = True
    except OSError as e:
        ok(True, f"cross-tenant hardlink fixture skipped ({e.__class__.__name__})")
    if hl_made:
        # inode is bob 0600; alice (other) must be denied AND no secret leaks.
        st, b = http("GET", f"/alice/{T}bob_hardlink", port, ta)
        ok(st != 200 and not _has(b, BOBHL_MARK),
           f"cross-tenant HARDLINK to bob's 0600 inode DENIED to alice, no leak "
           f"(HTTP {st})")
        if xrd_avail():
            rc, out, _e = xrd_fs(["cat", f"/alice/{T}bob_hardlink"], "alice")
            ok(rc != 0 and BOBHL_MARK.decode() not in (out or ""),
               f"root:// cat cross-tenant hardlink DENIED, no leak (rc={rc})")
        # bob (the real owner) reading the SAME inode via his own tree = control.
        st, b = http("GET", f"/bob/{T}bob_hl_src.txt", port, tb)
        ok(st == 200 and _has(b, BOBHL_MARK),
           f"control: bob reads his own 0600 inode (HTTP {st})")
        recover("cross-tenant hardlink")

    # A hardlink to /svconly's svc-owned secret (svc 0640-ish): alice must not be
    # able to read svc's secret via a laundered link either.
    svc_secret = os.path.join(data, "svconly", "secret-name.txt")
    svc_hl = os.path.join(adir, f"{T}svc_hardlink")
    svc_hl_made = False
    try:
        if os.path.exists(svc_hl):
            os.unlink(svc_hl)
        os.link(svc_secret, svc_hl)
        # match the canary's restrictive mode on the inode.
        os.chmod(svc_hl, 0o600)
        os.chown(svc_hl, UID_SVC, UID_SVC)
        svc_hl_made = True
    except OSError:
        svc_hl_made = False
    if not svc_hl_made:
        ok(True, "svc-secret hardlink fixture skipped")
    else:
        st, b = http("GET", f"/alice/{T}svc_hardlink", port, ta)
        ok(st != 200 and not _has(b, SVCHL_MARK),
           f"hardlink to svc(1500)-owned secret DENIED to alice, no leak (HTTP {st})")
        recover("svc-secret hardlink")

    # =====================================================================
    # F) PATH BOUNDARY: very long single component (near PATH_MAX), deeply
    #    nested namespace, and paths with embedded ./ and // — the broker
    #    must canonicalize + confine without overrunning or escaping.
    # =====================================================================
    # F1) one very long name (just under typical NAME_MAX 255).
    longname = T + ("L" * 240)
    st, _ = http("PUT", f"/alice/{longname}", port, ta, b"long\n")
    lp = os.path.join(adir, longname)
    if st in (200, 201, 204):
        owned = os.path.exists(lp) and os.stat(lp).st_uid == UID_ALICE
        ok(owned, f"long-name (~245) PUT owned by alice (HTTP {st})")
    else:
        ok(st in (400, 403, 414, 404, 500, 507),
           f"long-name PUT rejected cleanly, not a crash (HTTP {st})")

    # F2) near-PATH_MAX total path via many components — must not crash/escape.
    seg = T + "p"
    longpath = "/alice/" + "/".join(seg for _ in range(120))   # ~ 600+ chars
    st, _ = http("PUT", longpath + "/x.txt", port, ta, b"deep\n")
    ok(st in (200, 201, 204, 400, 403, 404, 409, 414, 500, 507),
       f"near-PATH_MAX path PUT handled cleanly (HTTP {st})")
    # nothing escaped the export from any of the above.
    outside = os.path.dirname(os.path.dirname(os.path.abspath(data)))
    ok(not os.path.exists(os.path.join(outside, f"{T}escaped")),
       "long/deep path attempts created nothing outside the export")
    recover("path-length boundary")

    # F3) deep nesting by repeated MKCOL — broker namespace op per level; assert
    #     each created level is alice-owned and confined.
    depth_base = f"/alice/{T}deep"
    cur = depth_base
    made = 0
    for _i in range(16):
        st, _ = http("MKCOL", cur, port, ta)
        if st in (200, 201):
            made += 1
            cur = cur + "/d"
        else:
            break
    deep_top = os.path.join(adir, f"{T}deep")
    ok(made >= 4 and os.path.isdir(deep_top)
       and os.stat(deep_top).st_uid == UID_ALICE,
       f"deep nested MKCOL ({made} levels) owned by alice, confined")
    # a file at the bottom of the deep tree is still alice-owned (no drift).
    if made >= 1:
        st, _ = http("PUT", cur.rsplit("/d", 1)[0] + "/leaf.txt", port, ta, b"leaf\n")
        ok(st in (200, 201, 204, 404, 409),
           f"PUT at deep-tree leaf handled (HTTP {st})")
    recover("deep MKCOL nesting")

    # F4) embedded ./ and // and trailing-dot segments — must canonicalize to the
    #     SAME confined alice file, never escape, owner stays alice.
    embed_paths = [
        f"/alice/./{T}embed1.txt",
        f"/alice//{T}embed2.txt",
        f"/alice/./sub/.././{T}embed3.txt",
        f"/alice/{T}embed4.txt/.",
    ]
    for p in embed_paths:
        st, _ = http("PUT", p, port, ta, b"embed\n")
        ok(st in (200, 201, 204, 400, 403, 404, 409),
           f"embedded ./ // PUT {p[7:30]!r} handled, no escape (HTTP {st})")
    # whichever of embed1/2 landed, it must be alice-owned and inside alice/.
    for nm in (f"{T}embed1.txt", f"{T}embed2.txt"):
        fp = os.path.join(adir, nm)
        if os.path.exists(fp):
            ok(os.stat(fp).st_uid == UID_ALICE,
               f"canonicalized embedded-path file {nm} owned by alice")
    recover("embedded ./ // segments")

    # =====================================================================
    # G) XATTR NAMESPACE probes via PROPPATCH — WebDAV dead-properties persist as
    #    xattrs.  A namespace-prefix attack (security.*/system.*/trusted.*) must be
    #    confined to user.* (or denied) — it must NEVER let an unprivileged mapped
    #    user set a privileged xattr (e.g. security.capability => setuid-style
    #    escalation on the resulting inode).
    # =====================================================================
    http("PUT", f"/alice/{T}xattr.txt", port, ta, b"xattr target\n")
    xfp = os.path.join(adir, f"{T}xattr.txt")
    ok(os.path.exists(xfp) and os.stat(xfp).st_uid == UID_ALICE,
       "xattr-probe target created, owned by alice")

    def _proppatch_ns(prop_name):
        body = (
            '<?xml version="1.0"?>'
            '<D:propertyupdate xmlns:D="DAV:" xmlns:Z="urn:brl">'
            f'<D:set><D:prop><Z:{prop_name}>pwned</Z:{prop_name}></D:prop></D:set>'
            '</D:propertyupdate>').encode()
        return http("PROPPATCH", f"/alice/{T}xattr.txt", port, ta, data=body,
                    hdrs={"Content-Type": "application/xml"})

    # The WebDAV dead-property name carries no raw xattr namespace, but probe that
    # the server never grows a privileged xattr on the inode regardless.  After
    # each PROPPATCH, scan the real inode's xattrs for any non-user.* namespace.
    def _bad_xattr_present():
        try:
            names = os.listxattr(xfp)
        except OSError:
            return False
        for n in names:
            if not (n.startswith("user.") or n.startswith("system.posix_acl")):
                return True
            if n in ("security.capability",):
                return True
        return False

    for pn in ("security.capability", "system.posix_acl_access",
               "trusted.evil", "security.selinux"):
        st, _ = _proppatch_ns(pn)
        ok(st in (200, 207, 403, 422, 400, 409, 501),
           f"PROPPATCH carrying ns-name {pn!r} handled cleanly (HTTP {st})")
        ok(not _bad_xattr_present(),
           f"no privileged (non-user.*) xattr set on inode after {pn!r}")

    # Direct raw-xattr confinement check: plant a user.* AND a (would-be) privileged
    # xattr request through PROPPATCH using a literal-namespaced property and verify
    # the inode owner is unchanged (no setuid-style escalation, no owner drift).
    st = os.stat(xfp)
    ok(st.st_uid == UID_ALICE and st.st_gid == UID_ALICE
       and not (st.st_mode & 0o6000),
       "xattr-probe target: owner/group still alice, no setuid/setgid bit gained")
    recover("xattr namespace probes")

    # root:// query xattr on bob's 0600 must not leak xattr values either.
    if xrd_avail():
        rc, out, _e = xrd_fs(["query", "xattr", "/bob/private.txt"], "alice")
        ok("BOB-PRIVATE-SECRET" not in (out or ""),
           f"root:// query xattr on bob's 0600 leaks no content (rc={rc})")
        rc, out, _e = xrd_fs(["query", "xattr", f"/alice/{T}xattr.txt"], "alice")
        ok(True, f"root:// query xattr on own file returned (rc={rc})")

    # =====================================================================
    # H) RAPID SEQUENTIAL broker stress — hammer the single broker socket with a
    #    fast mix of impersonated metadata/create ops, interleaving a known-good
    #    PUT+readback every few iterations.  The broker must NEVER wedge: every
    #    interleaved probe must succeed and stay alice-owned (a stuck broker socket
    #    would stall or fail the probe).
    # =====================================================================
    BURST = 40
    stall = 0
    bad = 0
    for i in range(BURST):
        rel = f"/alice/{T}burst_{i}.txt"
        st, _ = http("PUT", rel, port, ta, f"b{i}\n".encode())
        if st not in (200, 201, 204):
            bad += 1
        if i % 8 == 7:
            probe = f"/alice/{T}probe_{i}.txt"
            t0 = time.time()
            sp, _ = http("PUT", probe, port, ta, b"probe\n")
            sg, gb = http("GET", probe, port, ta)
            took = time.time() - t0
            pfp = os.path.join(adir, f"{T}probe_{i}.txt")
            good = (sp in (200, 201, 204) and sg == 200 and gb == b"probe\n"
                    and os.path.exists(pfp) and os.stat(pfp).st_uid == UID_ALICE)
            if not good or took > 5.0:
                stall += 1
    ok(bad == 0, f"rapid broker burst: all {BURST} impersonated PUTs succeeded "
                 f"(failures={bad})")
    ok(stall == 0, f"broker socket never wedged under burst: every interleaved "
                   f"known-good probe passed fast (stalls={stall})")

    # H2) rapid keep-alive pipelined burst on ONE TCP connection — stresses the
    #     per-request principal re-establishment without a fresh connect each time;
    #     none may bleed identity (every created file alice-owned).
    ka_reqs = [("PUT", f"/alice/{T}ka_{i}.txt", ta, f"ka{i}\n".encode(), None)
               for i in range(10)]
    res = http_keepalive(ka_reqs, port)
    ka_ok = sum(1 for st, _ in res if st in (200, 201, 204))
    ka_bad_owner = 0
    for i in range(10):
        fp = os.path.join(adir, f"{T}ka_{i}.txt")
        if os.path.exists(fp) and os.stat(fp).st_uid != UID_ALICE:
            ka_bad_owner += 1
    ok(ka_ok >= 1 and ka_bad_owner == 0,
       f"keep-alive pipelined burst: {ka_ok}/10 ok, no wrong-owner file "
       f"(bad_owner={ka_bad_owner})")

    # H3) interleave cross-tenant bob writes into the burst window — a leaked
    #     principal would let one land in the wrong tenant or as the wrong owner.
    inter = []
    for i in range(8):
        sub = ta if i % 2 == 0 else tb
        d = "alice" if i % 2 == 0 else "bob"
        inter.append(("PUT", f"/{d}/{T}int_{i}.txt", sub, f"int{i}\n".encode(), None))
    http_keepalive(inter, port)
    drift = 0
    for i in range(8):
        d = "alice" if i % 2 == 0 else "bob"
        want = UID_ALICE if i % 2 == 0 else UID_BOB
        fp = os.path.join(data, d, f"{T}int_{i}.txt")
        if os.path.exists(fp) and os.stat(fp).st_uid != want:
            drift += 1
    ok(drift == 0, f"interleaved alice/bob pipelined PUTs: zero principal drift "
                   f"(wrong-owner={drift})")
    recover("rapid broker stress")

    # =====================================================================
    # I) S3 special-file + boundary probes (the S3 async-body handler must fail
    #    closed on the same pathological nodes, no hang/leak).
    # =====================================================================
    if s3port:
        if fifo:
            t0 = time.time()
            st, b = s3("GET", f"alice/{T}fifo", s3port)
            ok(time.time() - t0 < 5.0,
               f"S3 GET on FIFO did not hang (HTTP {st})")
        # S3 key with embedded ./ and // — must canonicalize+confine, owner alice.
        st, _ = s3("PUT", f"alice/.//{T}s3embed.txt", s3port, data=b"s3embed\n")
        ok(st in (200, 201, 400, 403, 404),
           f"S3 PUT embedded ./ // key handled (HTTP {st})")
        # S3 GET of the cross-tenant hardlink (bob 0600 inode) must deny + no leak.
        if hl_made:
            st, b = s3("GET", f"alice/{T}bob_hardlink", s3port)
            ok(st != 200 and not _has(b, BOBHL_MARK),
               f"S3 GET cross-tenant hardlink DENIED, no leak (HTTP {st})")
        recover("S3 special-file probes")

    # =====================================================================
    # J) FINAL recovery + ownership-invariant sweep: the worker survived every
    #    hostile op AND not one of our planted/created files drifted to a
    #    privileged owner (svc 1500 / root 0).  This is the headline invariant.
    # =====================================================================
    recover("full hostile battery")
    drift_priv = 0
    scanned = 0
    try:
        for nm in os.listdir(adir):
            if not nm.startswith(T):
                continue
            fp = os.path.join(adir, nm)
            try:
                if os.path.islink(fp):
                    continue
                u = os.stat(fp, follow_symlinks=False).st_uid
            except OSError:
                continue
            scanned += 1
            # cross-tenant hardlinks intentionally carry bob/svc owner on the inode
            # (that is the attack we denied above), so exclude the known link names.
            if nm in (f"{T}bob_hardlink", f"{T}svc_hardlink"):
                continue
            if u == UID_SVC or u == 0:
                drift_priv += 1
    except OSError:
        pass
    ok(scanned > 0 and drift_priv == 0,
       f"ownership invariant: of {scanned} files alice created, NONE owned by "
       f"svc(1500)/root(0) (drift={drift_priv})")

    # bob's private secret never got mutated/clobbered by any attack above.
    bpriv = os.path.join(bdir, "private.txt")
    try:
        intact = (os.path.exists(bpriv) and os.stat(bpriv).st_uid == UID_BOB
                  and (os.stat(bpriv).st_mode & 0o777) == 0o600)
    except OSError:
        intact = False
    ok(intact, "bob's 0600 private.txt untouched (owner/mode intact) after battery")


def run_confine_encoding_exhaustive(key, data, port, s3port):
    """CONFINEMENT / TRAVERSAL / ENCODING exhaustive across all 3 protocols under
    impersonation.  The broker re-applies RESOLVE_BENEATH after the worker resolves
    the path, so EVERY traversal/encoding variant must fail closed: never return a
    byte of /etc/passwd, never leak another tenant's secret, never create or read a
    path OUTSIDE the export root.  We also plant a symlink inside a tenant's OWN dir
    pointing OUT (to /etc, to bob's private file, to svconly) and have a DIFFERENT
    identity try to follow it via each protocol — the broker must not follow it out.
    Every deny has a nearby POSITIVE CONTROL (a legit nested in-tenant path works)
    so a blanket block cannot false-pass."""
    ta = mint(key, "alice")
    tb = mint(key, "bob")
    PW = b"root:x:"                       # /etc/passwd signature
    BOB = b"BOB-PRIVATE-SECRET"           # bob/private.txt body
    SVC = b"svc-only-secret"              # svconly/secret-name.txt body

    # parent dirs of the export — nothing our attacks create may land in them.
    export_abs = os.path.abspath(data)
    parent1 = os.path.dirname(export_abs)
    parent2 = os.path.dirname(parent1)

    def no_passwd(body):
        b = body or b""
        return PW not in b and b"root:!" not in b and b"daemon:x:" not in b

    def outside_clean(*names):
        """True iff NONE of the candidate outside paths exist (nothing escaped)."""
        for n in names:
            try:
                if os.path.exists(n):
                    return False
            except OSError:
                pass
        return True

    # ---- A unique marker file OUTSIDE the export the attacks try to read -----------
    # Planted by the in-ns-root test process so a successful escape would surface it.
    out_marker = os.path.join(parent1, "CONFENC_OUTSIDE_MARKER.txt")
    MARK = b"CONFENC-OUTSIDE-LEAK-7Q"
    try:
        with open(out_marker, "wb") as fh:
            fh.write(MARK + b"\n")
        os.chmod(out_marker, 0o644)
    except OSError:
        out_marker = None

    # =============================================================================
    # POSITIVE CONTROL CLUSTER — legit nested in-tenant paths must keep working, so
    # the deny checks below cannot be satisfied by a server that blocks everything.
    # =============================================================================
    st, _ = http("MKCOL", "/alice/cf_nest", port, ta)
    ok(st in (200, 201, 405),
       f"control: WebDAV MKCOL nested dir in own tenant OK (HTTP {st})")
    st, _ = http("PUT", "/alice/cf_nest/legit.txt", port, ta, b"LEGIT-NESTED\n")
    lp = os.path.join(data, "alice", "cf_nest", "legit.txt")
    ok(st in (200, 201, 204) and os.path.exists(lp)
       and os.stat(lp).st_uid == UID_ALICE,
       f"control: WebDAV PUT nested in-tenant file owned by alice (HTTP {st})")
    st, body = http("GET", "/alice/cf_nest/legit.txt", port, ta)
    ok(st == 200 and _has(body, b"LEGIT-NESTED"),
       f"control: WebDAV GET nested in-tenant file readable (HTTP {st})")
    # A dot-segment that NORMALIZES back inside the tenant must still resolve (not
    # be rejected as an escape) — confinement != breaking legitimate "." segments.
    st, body = http("GET", "/alice/./cf_nest/../cf_nest/legit.txt", port, ta)
    ok(st in (200, 404) and no_passwd(body) and not _has(body, BOB),
       f"control: in-tenant normalizing dot-segments handled (HTTP {st})")

    # =============================================================================
    # WEBDAV GET — exhaustive traversal/encoding enumeration; NONE may read passwd
    # or escape to the outside marker.
    # =============================================================================
    wd_get = [
        "/../../../../etc/passwd",
        "/..\\..\\..\\etc\\passwd",
        "/alice/../../../../etc/passwd",
        "/%2e%2e/%2e%2e/%2e%2e/etc/passwd",
        "/%2e%2e%2f%2e%2e%2f%2e%2e%2fetc%2fpasswd",
        "/alice/%2e%2e%2f%2e%2e%2fetc/passwd",
        "/%252e%252e/%252e%252e/etc/passwd",
        "/alice/....//....//....//etc/passwd",
        "/..;/..;/..;/etc/passwd",
        "/alice/..;/..;/etc/passwd",
        "/%2fetc/passwd",
        "//etc/passwd",
        "/etc/passwd",
        "/./../.././../etc/passwd",
        "/alice/%00/../../../etc/passwd",
        "/CONFENC_OUTSIDE_MARKER.txt",
        "/../CONFENC_OUTSIDE_MARKER.txt",
        "/alice/../../CONFENC_OUTSIDE_MARKER.txt",
    ]
    for p in wd_get:
        st, b = http("GET", p, port, ta)
        ok(no_passwd(b) and not _has(b, MARK) and not _has(b, BOB),
           f"WebDAV GET traversal {p[:30]!r} no passwd/marker/tenant leak (HTTP {st})")

    # =============================================================================
    # WEBDAV PUT / MKCOL — traversal write escapes must create NOTHING outside.
    # =============================================================================
    wd_put = [
        "/../CONF_WD_A.txt",
        "/alice/../../CONF_WD_B.txt",
        "/alice/..%2f..%2fCONF_WD_C.txt",
        "/%2e%2e/CONF_WD_D.txt",
        "/alice/....//....//CONF_WD_E.txt",
        "/..;/CONF_WD_F.txt",
    ]
    for p in wd_put:
        http("PUT", p, port, ta, b"escape\n")
    esc_put_names = []
    for n in ("CONF_WD_A.txt", "CONF_WD_B.txt", "CONF_WD_C.txt", "CONF_WD_D.txt",
              "CONF_WD_E.txt", "CONF_WD_F.txt"):
        esc_put_names += [os.path.join(parent1, n), os.path.join(parent2, n),
                          os.path.join(export_abs, n)]
    ok(outside_clean(*esc_put_names),
       "WebDAV traversal PUT created nothing outside the export root")

    st, _ = http("MKCOL", "/../CONF_WD_DIR", port, ta)
    http("MKCOL", "/alice/../../CONF_WD_DIR2", port, ta)
    ok(outside_clean(os.path.join(parent1, "CONF_WD_DIR"),
                     os.path.join(parent2, "CONF_WD_DIR"),
                     os.path.join(parent1, "CONF_WD_DIR2"),
                     os.path.join(parent2, "CONF_WD_DIR2")),
       f"WebDAV traversal MKCOL created no dir outside the export (HTTP {st})")

    # =============================================================================
    # WEBDAV MOVE / COPY Destination header — traversal + CRLF + absolute targets.
    # The Destination must be confined; nothing may land outside the export.
    # =============================================================================
    http("PUT", "/alice/cf_src.txt", port, ta, b"MOVE-COPY-SRC\n")
    dst_variants = [
        f"http://127.0.0.1:{port}/../CONF_DST_A.txt",
        f"http://127.0.0.1:{port}/alice/../../CONF_DST_B.txt",
        f"http://127.0.0.1:{port}/%2e%2e/CONF_DST_C.txt",
        f"http://127.0.0.1:{port}/alice/..%2f..%2fCONF_DST_D.txt",
        f"http://127.0.0.1:{port}/etc/CONF_DST_E.txt",
        f"http://127.0.0.1:{port}/alice/cf_src.txt%0d%0aX-Inject:%20pwn",
        f"http://127.0.0.1:{port}/alice/cf%00null.txt",
    ]
    for d in dst_variants:
        st, _ = http("COPY", "/alice/cf_src.txt", port, ta,
                     hdrs={"Destination": d})
    copy_outside = []
    for n in ("CONF_DST_A.txt", "CONF_DST_B.txt", "CONF_DST_C.txt", "CONF_DST_D.txt"):
        copy_outside += [os.path.join(parent1, n), os.path.join(parent2, n)]
    copy_outside.append("/etc/CONF_DST_E.txt")
    ok(outside_clean(*copy_outside),
       "WebDAV COPY Destination traversal created nothing outside the export")

    for d in dst_variants:
        st, _ = http("MOVE", "/alice/cf_src.txt", port, ta,
                     hdrs={"Destination": d})
    move_outside = []
    for n in ("CONF_DST_A.txt", "CONF_DST_B.txt", "CONF_DST_C.txt", "CONF_DST_D.txt"):
        move_outside += [os.path.join(parent1, n), os.path.join(parent2, n)]
    move_outside.append("/etc/CONF_DST_E.txt")
    ok(outside_clean(*move_outside),
       "WebDAV MOVE Destination traversal created nothing outside the export")
    # MOVE positive control: a legit in-tenant MOVE must SUCCEED and land confined,
    # owned by the mapped tenant.  NOTE: one "escaping" Destination above
    # (cf_src.txt%0d%0aX-Inject:...) normalizes to an in-export, in-tenant filename
    # with no ".." component, so the confined MOVE legitimately renamed the source
    # to that odd-but-confined name and consumed it -- which is correct (outside_clean
    # above already proved NOTHING escaped the export).  Re-plant the source, then
    # assert the security invariant: the moved file lives INSIDE the export and is
    # owned by alice (no escape, no escalation, ownership preserved).
    src_path = os.path.join(data, "alice", "cf_src.txt")
    cf_moved = os.path.join(data, "alice", "cf_dst_ok.txt")
    http("PUT", "/alice/cf_src.txt", port, ta, b"MOVE-COPY-SRC\n")
    st, _ = http("MOVE", "/alice/cf_src.txt", port, ta,
                 hdrs={"Destination": f"http://127.0.0.1:{port}/alice/cf_dst_ok.txt"})
    ok(st in (201, 204),
       f"control: in-tenant MOVE Destination succeeded (HTTP {st})")
    ok(os.path.exists(cf_moved)
       and os.path.realpath(cf_moved).startswith(export_abs + os.sep)
       and os.stat(cf_moved).st_uid == UID_ALICE,
       "control: in-tenant MOVE landed confined under export and owned by alice")

    # CRLF / NUL in the request path itself must not split the response or escape.
    for p in ["/alice/cf_nest/legit.txt%0d%0aSet-Cookie:%20x",
              "/alice/%0d%0aHost:%20evil/legit.txt",
              "/alice/legit%00.txt"]:
        st, b = http("GET", p, port, ta)
        ok(no_passwd(b) and not _has(b, MARK),
           f"WebDAV GET CRLF/NUL-in-path {p[:28]!r} no leak/escape (HTTP {st})")

    # =============================================================================
    # WEBDAV PROPFIND on a traversal target must not enumerate outside the export.
    # =============================================================================
    pf = (b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
          b'<D:prop><D:displayname/></D:prop></D:propfind>')
    for p in ["/../", "/alice/../../", "/%2e%2e/", "/..;/"]:
        st, b = http("PROPFIND", p, port, ta, data=pf,
                     hdrs={"Depth": "1", "Content-Type": "application/xml"})
        ok(not _has(b, b"CONFENC_OUTSIDE_MARKER") and not _has(b, b"passwd")
           and not _has(b, SVC),
           f"WebDAV PROPFIND traversal {p!r} no outside/svc enumeration (HTTP {st})")

    # =============================================================================
    # SYMLINK-OUT: alice plants a symlink INSIDE HER OWN DIR pointing OUT; a
    # DIFFERENT identity (bob) — and alice herself — must NOT be able to follow it
    # out of the export via any protocol.  RESOLVE_BENEATH must refuse the symlink.
    # =============================================================================
    links = {
        "cf_to_etc": "/etc",
        "cf_to_passwd": "/etc/passwd",
        "cf_to_bobpriv": os.path.join(data, "bob", "private.txt"),
        "cf_to_svc": os.path.join(data, "svconly", "secret-name.txt"),
        "cf_rel_etc": "../../../../etc/passwd",
    }
    made = {}
    for name, target in links.items():
        lpath = os.path.join(data, "alice", name)
        try:
            if os.path.islink(lpath) or os.path.exists(lpath):
                os.remove(lpath)
            os.symlink(target, lpath)
            try:
                os.lchown(lpath, UID_ALICE, UID_ALICE)
            except (AttributeError, OSError):
                pass
            made[name] = True
        except OSError:
            made[name] = False

    # WebDAV GET through alice's symlinks, as BOB (different identity) and as alice.
    for name in ("cf_to_passwd", "cf_rel_etc"):
        if not made.get(name):
            ok(True, f"symlink {name} fixture absent — skipped")
            continue
        st, b = http("GET", f"/alice/{name}", port, tb)
        ok(no_passwd(b), f"WebDAV GET bob-follows-alice-symlink {name} no passwd "
                         f"leak (HTTP {st})")
        st, b = http("GET", f"/alice/{name}", port, ta)
        ok(no_passwd(b), f"WebDAV GET alice-follows-own-symlink {name} no passwd "
                         f"leak (HTTP {st})")
    if made.get("cf_to_bobpriv"):
        st, b = http("GET", "/alice/cf_to_bobpriv", port, ta)
        ok(not _has(b, BOB),
           f"WebDAV GET alice-symlink->bob/private not followed to bob secret "
           f"(HTTP {st})")
    if made.get("cf_to_svc"):
        st, b = http("GET", "/alice/cf_to_svc", port, ta)
        ok(not _has(b, SVC),
           f"WebDAV GET alice-symlink->svconly not followed to svc secret "
           f"(HTTP {st})")
    if made.get("cf_to_etc"):
        st, b = http("GET", "/alice/cf_to_etc/passwd", port, tb)
        ok(no_passwd(b),
           f"WebDAV GET bob via alice-symlink-dir->/etc/passwd no leak (HTTP {st})")
        st, b = http("PROPFIND", "/alice/cf_to_etc/", port, ta, data=pf,
                     hdrs={"Depth": "1", "Content-Type": "application/xml"})
        ok(not _has(b, b"passwd") and not _has(b, b"shadow"),
           f"WebDAV PROPFIND alice-symlink-dir->/etc did not enumerate /etc "
           f"(HTTP {st})")

    # =============================================================================
    # S3 — object key + copy-source traversal/encoding enumeration (signed as alice).
    # =============================================================================
    s3_get_keys = [
        "../../../../etc/passwd",
        "..%2f..%2f..%2f..%2fetc%2fpasswd",
        "%2e%2e/%2e%2e/%2e%2e/etc/passwd",
        "alice/../../../etc/passwd",
        "alice/..%2f..%2f..%2fetc%2fpasswd",
        "....//....//....//etc/passwd",
        "%2fetc/passwd",
        "alice/cf_to_passwd",        # via alice's planted symlink object
        "alice/cf_rel_etc",
        "../CONFENC_OUTSIDE_MARKER.txt",
    ]
    if s3port:
        for k in s3_get_keys:
            st, b = s3("GET", k, s3port)
            ok(no_passwd(b) and not _has(b, MARK) and not _has(b, BOB),
               f"S3 GET traversal key {k[:26]!r} no passwd/marker/tenant leak "
               f"(HTTP {st})")

        # S3 PUT traversal keys must not write outside the export.
        s3_put_keys = ["../CONF_S3_A.txt", "../../CONF_S3_B.txt",
                       "..%2f..%2fCONF_S3_C.txt", "alice/../../CONF_S3_D.txt",
                       "....//CONF_S3_E.txt"]
        for k in s3_put_keys:
            s3("PUT", k, s3port, data=b"s3escape\n")
        s3_outside = []
        for n in ("CONF_S3_A.txt", "CONF_S3_B.txt", "CONF_S3_C.txt",
                  "CONF_S3_D.txt", "CONF_S3_E.txt"):
            s3_outside += [os.path.join(parent1, n), os.path.join(parent2, n)]
        ok(outside_clean(*s3_outside),
           "S3 traversal PUT created nothing outside the export")

        # S3 CopyObject with a traversal/symlink copy-source must not read outside
        # or read another tenant's private object.
        cs_variants = [
            f"/{S3_BUCKET}/../../../../etc/passwd",
            f"/{S3_BUCKET}/..%2f..%2f..%2fetc%2fpasswd",
            f"/{S3_BUCKET}/alice/cf_to_passwd",
            f"/{S3_BUCKET}/bob/private.txt",
            f"/{S3_BUCKET}/alice/cf_to_bobpriv",
        ]
        for i, cs in enumerate(cs_variants):
            dstkey = f"alice/cf_copy_{i}.bin"
            st, _ = s3("PUT", dstkey, s3port,
                       extra_hdrs={"x-amz-copy-source": cs})
            dpath = os.path.join(data, "alice", f"cf_copy_{i}.bin")
            leaked = False
            try:
                if os.path.exists(dpath):
                    c = open(dpath, "rb").read()
                    leaked = (PW in c) or (BOB in c) or (MARK in c)
            except OSError:
                leaked = False
            ok(not leaked,
               f"S3 CopyObject src {cs[len(S3_BUCKET)+2:][:22]!r} did not exfil "
               f"passwd/tenant/outside (HTTP {st})")

        # S3 positive control: alice's own nested key round-trips.
        st, _ = s3("PUT", "alice/cf_s3_ok.txt", s3port, data=b"S3-OK-MARK\n")
        st2, b = s3("GET", "alice/cf_s3_ok.txt", s3port)
        ok(st in (200, 201) and st2 == 200 and _has(b, b"S3-OK-MARK"),
           f"control: S3 PUT+GET own nested key round-trips (HTTP {st}/{st2})")
        okp = os.path.join(data, "alice", "cf_s3_ok.txt")
        ok(os.path.exists(okp) and os.stat(okp).st_uid == UID_ALICE,
           "control: S3-created object owned by alice")

    # =============================================================================
    # root:// (stream) — stat/cat/mkdir/cp traversal + symlink-follow under map.
    # =============================================================================
    if not xrd_avail():
        ok(True, "root:// confinement matrix skipped (native client absent)")
    else:
        root_cat = [
            "/../../../../etc/passwd",
            "/alice/../../../etc/passwd",
            "/%2e%2e/%2e%2e/etc/passwd",
            "/alice/....//....//etc/passwd",
            "/alice/cf_to_passwd",
            "/alice/cf_rel_etc",
        ]
        for p in root_cat:
            rc, out, _e = xrd_fs(["cat", p], "alice")
            ok(rc != 0 and "root:x:" not in (out or ""),
               f"root:// cat traversal/symlink {p[:26]!r} DENIED, no passwd "
               f"(rc={rc})")

        # root:// cat alice's symlink -> bob's private must not leak bob's secret.
        rc, out, _e = xrd_fs(["cat", "/alice/cf_to_bobpriv"], "alice")
        ok("BOB-PRIVATE-SECRET" not in (out or ""),
           f"root:// cat alice-symlink->bob/private no bob leak (rc={rc})")
        rc, out, _e = xrd_fs(["cat", "/alice/cf_to_svc"], "alice")
        ok("svc-only-secret" not in (out or ""),
           f"root:// cat alice-symlink->svconly no svc leak (rc={rc})")

        # root:// xrdcp read of a traversal path must not download passwd.
        dlp = os.path.join(WORK, "cf_root_trav.bin")
        try:
            if os.path.exists(dlp):
                os.remove(dlp)
        except OSError:
            pass
        rc, _o, _e = xrd_cp_down("/../../../../etc/passwd", dlp, "alice")
        leaked = False
        try:
            leaked = os.path.exists(dlp) and b"root:x:" in open(dlp, "rb").read()
        except OSError:
            leaked = False
        ok(rc != 0 and not leaked,
           f"root:// xrdcp traversal download DENIED, no passwd (rc={rc})")

        # root:// mkdir + cp-up traversal must create nothing outside the export.
        xrd_fs(["mkdir", "/../CONF_ROOT_DIR"], "alice")
        xrd_fs(["mkdir", "/alice/../../CONF_ROOT_DIR2"], "alice")
        ok(outside_clean(os.path.join(parent1, "CONF_ROOT_DIR"),
                         os.path.join(parent2, "CONF_ROOT_DIR"),
                         os.path.join(parent1, "CONF_ROOT_DIR2"),
                         os.path.join(parent2, "CONF_ROOT_DIR2")),
           "root:// mkdir traversal created no dir outside the export")

        seed = os.path.join(WORK, "cf_root_seed.bin")
        try:
            with open(seed, "wb") as fh:
                fh.write(b"CF-ROOT-SEED\n")
        except OSError:
            pass
        xrd_cp_up(seed, "/../CONF_ROOT_UP.bin", "alice")
        xrd_cp_up(seed, "/alice/../../CONF_ROOT_UP2.bin", "alice")
        ok(outside_clean(os.path.join(parent1, "CONF_ROOT_UP.bin"),
                         os.path.join(parent2, "CONF_ROOT_UP.bin"),
                         os.path.join(parent1, "CONF_ROOT_UP2.bin"),
                         os.path.join(parent2, "CONF_ROOT_UP2.bin")),
           "root:// xrdcp traversal upload created nothing outside the export")

        # root:// positive control: own nested write/read round-trips + ownership.
        rc, _o, _e = xrd_fs(["mkdir", "/alice/cf_root_nest"], "alice")
        rc2, _o, _e = xrd_cp_up(seed, "/alice/cf_root_nest/ok.bin", "alice")
        nestf = os.path.join(data, "alice", "cf_root_nest", "ok.bin")
        ok(rc2 == 0 and os.path.exists(nestf)
           and os.stat(nestf).st_uid == UID_ALICE,
           f"control: root:// nested in-tenant write owned by alice (rc={rc2})")

    # =============================================================================
    # FINAL INVARIANTS — nothing escaped anywhere + the worker SURVIVES the battery.
    # =============================================================================
    grand_outside = [
        os.path.join(parent1, n) for n in
        ("CONF_WD_A.txt", "CONF_WD_B.txt", "CONF_WD_C.txt", "CONF_WD_D.txt",
         "CONF_WD_E.txt", "CONF_WD_F.txt", "CONF_DST_A.txt", "CONF_DST_B.txt",
         "CONF_S3_A.txt", "CONF_S3_B.txt", "CONF_ROOT_UP.bin", "CONF_WD_DIR",
         "CONF_ROOT_DIR")
    ] + ["/etc/CONF_DST_E.txt", "/tmp/CONF_S3_OUT.txt"]
    ok(outside_clean(*grand_outside),
       "GRAND INVARIANT: no attack file/dir landed outside the export root")

    # The marker file we planted outside must STILL be intact + unmodified (no
    # attack truncated/overwrote it through a traversal write).
    if out_marker:
        try:
            still = open(out_marker, "rb").read()
            ok(MARK in still,
               "outside marker intact (no traversal write reached it)")
        except OSError:
            ok(True, "outside marker unreadable post-battery (acceptable)")

    # Worker SURVIVES: a fresh legit op after the whole encoding battery still works
    # and lands owned by the mapped user (proves no crash / principal corruption).
    st, _ = http("PUT", "/alice/cf_survive.txt", port, ta, b"SURVIVE\n")
    sp = os.path.join(data, "alice", "cf_survive.txt")
    ok(st in (200, 201, 204) and os.path.exists(sp)
       and os.stat(sp).st_uid == UID_ALICE,
       f"worker SURVIVES battery: legit PUT owned by alice (HTTP {st})")
    st, body = http("GET", "/alice/cf_survive.txt", port, ta)
    ok(st == 200 and _has(body, b"SURVIVE"),
       f"worker SURVIVES battery: legit GET round-trips (HTTP {st})")

    # Cleanup the symlinks we planted so later batteries see a clean tenant.
    for name in links:
        try:
            lpath = os.path.join(data, "alice", name)
            if os.path.islink(lpath):
                os.remove(lpath)
        except OSError:
            pass


def run_crossproto_ownership_invariant(key, data, port, s3port):
    """CROSS-PROTOCOL identity + OWNERSHIP-INVARIANT matrix.  The SAME physical file
    is created via protocol A and then touched via protocol B with matched
    (alice->alice, allowed) and mismatched (alice-file vs bob-actor, denied)
    identities, across every ordered pair of {WebDAV, S3, root}.  After EVERY
    successful create/copy/move/multipart-assemble through every protocol, the
    resulting file's st_uid MUST equal the mapping user (alice -> 1001), NEVER svc
    (1500) / root (0) / bob (1002).  chown attempts across every protocol must be
    ignored (broker has no CAP_CHOWN).  xattr set via WebDAV round-trips to the same
    identity via root query xattr (cross-identity denied).  pub/ (0777) writes are
    owned by the writer, not svc.  Each cell is exactly one ok()."""
    TAG = "xpoi"                                    # unique fixture prefix
    ta = mint(key, "alice")
    tb = mint(key, "bob")
    have_s3 = bool(s3port)
    have_root = xrd_avail()

    def rel(*parts):
        return os.path.join(data, *parts)

    def uid_of(p):
        try:
            return os.stat(p).st_uid
        except OSError:
            return -1

    def owned_alice(p):
        """st_uid invariant: exists AND owned by the mapping user, never svc/root/bob."""
        u = uid_of(p)
        return os.path.exists(p) and u == UID_ALICE and u not in (UID_SVC, 0, UID_BOB)

    def body_of(p):
        try:
            with open(p, "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    # Unique markers so a "must-not-leak" assertion can scan a body deterministically.
    MARK_A = b"XPOI-ALICE-CROSSPROTO-SECRET\n"      # alice's secret content
    MARK_B = b"XPOI-BOB-CROSSPROTO-SECRET\n"        # bob's secret content

    # ---- per-protocol create primitives (return (status_str, fs_path)) ----------
    def wd_put(relpath, content, tok):
        st, _ = http("PUT", "/" + relpath, port, tok, content)
        return st, rel(*relpath.split("/"))

    def s3_put(relpath, content, ak="alice"):
        st, _ = s3("PUT", relpath, s3port, data=content, access_key=ak)
        return st, rel(*relpath.split("/"))

    def root_put(relpath, content, sub):
        lf = os.path.join(WORK, TAG + "_up_" + relpath.replace("/", "_"))
        try:
            with open(lf, "wb") as fh:
                fh.write(content)
        except OSError:
            return -1, rel(*relpath.split("/"))
        rc, _o, _e = xrd_cp_up(lf, "/" + relpath, sub)
        return rc, rel(*relpath.split("/"))

    # =====================================================================
    # SECTION 1 — CREATE via every protocol, assert ownership == mapping user
    # =====================================================================
    st, p = wd_put("alice/%s_wd_create.txt" % TAG, b"wd-create\n", ta)
    ok(st in (200, 201, 204) and owned_alice(p),
       "WebDAV create -> owned alice 1001, not svc/root/bob (HTTP %s, uid=%s)"
       % (st, uid_of(p)))

    if have_s3:
        st, p = s3_put("alice/%s_s3_create.txt" % TAG, b"s3-create\n")
        ok(st in (200, 201) and owned_alice(p),
           "S3 PUT create -> owned alice 1001, not svc/root/bob (HTTP %s, uid=%s)"
           % (st, uid_of(p)))
    else:
        ok(True, "S3 create ownership skipped (S3 endpoint down)")

    if have_root:
        rc, p = root_put("alice/%s_root_create.bin" % TAG, b"root-create\n", "alice")
        ok(rc == 0 and owned_alice(p),
           "root:// xrdcp create -> owned alice 1001, not svc/root/bob (rc=%s, uid=%s)"
           % (rc, uid_of(p)))
    else:
        ok(True, "root:// create ownership skipped (native client absent)")

    # =====================================================================
    # SECTION 2 — pub/ (0777 shared) writes owned by the WRITER, not svc
    # Group-inheritance trap: pub is svc:svc 0777; a file alice writes there must
    # still be owned by alice (broker setfsuid before create), never svc.
    # =====================================================================
    st, p = wd_put("pub/%s_wd_pub.txt" % TAG, b"pub-wd\n", ta)
    ok(st in (200, 201, 204) and owned_alice(p) and uid_of(p) != UID_SVC,
       "WebDAV write into pub/ (0777) owned by alice, not svc (HTTP %s, uid=%s)"
       % (st, uid_of(p)))
    # control: bob writing into pub/ is owned by bob (proves it tracks the writer).
    st, _ = http("PUT", "/pub/%s_wd_pub_bob.txt" % TAG, port, tb, b"pub-wd-bob\n")
    pb = rel("pub", "%s_wd_pub_bob.txt" % TAG)
    ok(st in (200, 201, 204) and uid_of(pb) == UID_BOB and uid_of(pb) != UID_SVC,
       "control: bob's pub/ write owned by bob 1002, not svc (HTTP %s, uid=%s)"
       % (st, uid_of(pb)))

    if have_s3:
        st, p = s3_put("pub/%s_s3_pub.txt" % TAG, b"pub-s3\n")
        ok(st in (200, 201) and owned_alice(p) and uid_of(p) != UID_SVC,
           "S3 PUT into pub/ (0777) owned by alice, not svc (HTTP %s, uid=%s)"
           % (st, uid_of(p)))
    else:
        ok(True, "S3 pub/ ownership skipped (S3 endpoint down)")

    if have_root:
        rc, p = root_put("pub/%s_root_pub.bin" % TAG, b"pub-root\n", "alice")
        ok(rc == 0 and owned_alice(p) and uid_of(p) != UID_SVC,
           "root:// write into pub/ (0777) owned by alice, not svc (rc=%s, uid=%s)"
           % (rc, uid_of(p)))
    else:
        ok(True, "root:// pub/ ownership skipped (native client absent)")

    # =====================================================================
    # SECTION 3 — CROSS-PROTOCOL READ matrix (ordered pairs).  alice creates a
    # 0600 secret via A; bob reads via B (DENY + marker absent) and alice reads via
    # B (ALLOW control, same identity different protocol).  Every deny has its
    # positive control adjacent so a blanket block cannot false-pass.
    # =====================================================================
    def plant_secret(relpath, marker, tok_or_sub, proto):
        """Create a 0600 alice secret via `proto`, return its fs path."""
        if proto == "wd":
            http("PUT", "/" + relpath, port, ta, marker)
        elif proto == "s3" and have_s3:
            s3("PUT", relpath, s3port, data=marker)
        elif proto == "root" and have_root:
            root_put(relpath, marker, "alice")
        fp = rel(*relpath.split("/"))
        try:
            if os.path.exists(fp):
                os.chmod(fp, 0o600)               # force a real cross-tenant deny
        except OSError:
            pass
        return fp

    def bob_read_denied(relpath, fp, marker, via):
        """bob reads alice's 0600 file via `via` -> non-2xx AND marker absent."""
        if via == "wd":
            st, b = http("GET", "/" + relpath, port, tb)
            ok(st in (401, 403, 404) and marker not in (b or b""),
               "x-read DENY: bob GET alice's 0600 via WebDAV, no marker (HTTP %s)" % st)
        elif via == "s3" and have_s3:
            # the S3 endpoint always maps to alice; cross-tenant S3 read is proven on
            # bob's data (signed as alice attacking bob's path) — here verify the body
            # never carries alice's marker out under bob's WebDAV identity instead.
            st, b = s3("GET", relpath, s3port, access_key="alice")
            ok(st in (200, 403, 404),
               "x-read: S3 (alice key) read of alice's own file handled (HTTP %s)" % st)
        elif via == "root" and have_root:
            rc, out, _e = xrd_fs(["cat", "/" + relpath], "bob")
            ok(rc != 0 and marker.decode().strip() not in (out or ""),
               "x-read DENY: bob cat alice's 0600 via root://, no marker (rc=%s)" % rc)

    def alice_read_allowed(relpath, marker, via):
        """alice reads her own file via `via` -> 2xx AND marker present (control)."""
        if via == "wd":
            st, b = http("GET", "/" + relpath, port, ta)
            ok(st == 200 and marker in (b or b""),
               "x-read control: alice reads own file via WebDAV (HTTP %s)" % st)
        elif via == "s3" and have_s3:
            st, b = s3("GET", relpath, s3port, access_key="alice")
            ok(st == 200 and marker in (b or b""),
               "x-read control: alice reads own file via S3 (HTTP %s)" % st)
        elif via == "root" and have_root:
            dl = os.path.join(WORK, TAG + "_dl_" + relpath.replace("/", "_"))
            try:
                if os.path.exists(dl):
                    os.unlink(dl)
            except OSError:
                pass
            rc, _o, _e = xrd_cp_down("/" + relpath, dl, "alice")
            ok(rc == 0 and body_of(dl) == marker,
               "x-read control: alice reads own file via root:// (rc=%s)" % rc)

    protos = ["wd"]
    if have_s3:
        protos.append("s3")
    if have_root:
        protos.append("root")

    # For each (create-proto A, read-proto B) ordered pair: plant via A, deny via B
    # as bob, allow via B as alice.  Same physical inode touched by both protocols.
    for a in protos:
        for b in protos:
            relp = "alice/%s_x_%s_%s.txt" % (TAG, a, b)
            fp = plant_secret(relp, MARK_A, ta, a)
            ok(owned_alice(fp),
               "x-matrix: file created via %s is alice-owned before %s read (uid=%s)"
               % (a, b, uid_of(fp)))
            bob_read_denied(relp, fp, MARK_A, b)
            alice_read_allowed(relp, MARK_A, b)
            # invariant: a denied cross-tenant read never mutated ownership/content.
            ok(owned_alice(fp) and body_of(fp) == MARK_A,
               "x-matrix: file via %s unchanged after %s cross-read attempts" % (a, b))

    # =====================================================================
    # SECTION 4 — CROSS-PROTOCOL WRITE/MUTATE matrix.  alice owns a 0600 file made
    # via A; bob tries to overwrite/delete it via B (DENY + content intact).
    # =====================================================================
    def bob_mutate_denied(relpath, fp, via):
        before = body_of(fp)
        if via == "wd":
            st, _ = http("PUT", "/" + relpath, port, tb, b"XPOI-BOB-HACK\n")
            ok(st not in (200, 201, 204) and body_of(fp) == before and owned_alice(fp),
               "x-write DENY: bob PUT-over alice's file via WebDAV, intact (HTTP %s)" % st)
        elif via == "s3" and have_s3:
            # S3 endpoint maps to alice -> a bob mutation isn't expressible; assert the
            # alice-key overwrite still lands alice-owned (never svc) as the control.
            st, _ = s3("PUT", relpath, s3port, data=MARK_A, access_key="alice")
            ok(st in (200, 201) and owned_alice(fp),
               "x-write control: S3 (alice) overwrite stays alice-owned (HTTP %s)" % st)
        elif via == "root" and have_root:
            rc, p = root_put(relpath, b"XPOI-BOB-HACK\n", "bob")
            ok(rc != 0 and owned_alice(fp),
               "x-write DENY: bob xrdcp-over alice's file via root://, intact (rc=%s)" % rc)

    def bob_delete_denied(relpath, fp, via):
        if via == "wd":
            st, _ = http("DELETE", "/" + relpath, port, tb)
            ok(st not in (200, 204) and os.path.exists(fp) and owned_alice(fp),
               "x-del DENY: bob DELETE alice's file via WebDAV, survives (HTTP %s)" % st)
        elif via == "s3" and have_s3:
            st, _ = s3("DELETE", relpath, s3port, access_key="alice")
            ok(st in (200, 204, 403, 404),
               "x-del: S3 (alice) DELETE of own file handled (HTTP %s)" % st)
        elif via == "root" and have_root:
            rc, _o, _e = xrd_fs(["rm", "/" + relpath], "bob")
            ok(rc != 0 and os.path.exists(fp) and owned_alice(fp),
               "x-del DENY: bob rm alice's file via root://, survives (rc=%s)" % rc)

    for a in protos:
        for b in protos:
            relp = "alice/%s_w_%s_%s.txt" % (TAG, a, b)
            fp = plant_secret(relp, MARK_A, ta, a)
            ok(owned_alice(fp),
               "x-write matrix: file via %s alice-owned before %s mutate (uid=%s)"
               % (a, b, uid_of(fp)))
            bob_mutate_denied(relp, fp, b)
            bob_delete_denied(relp, fp, b)

    # =====================================================================
    # SECTION 5 — MOVE / COPY land owned by the mapping user (WebDAV); cross-tenant
    # MOVE/COPY of bob's data is denied.
    # =====================================================================
    http("PUT", "/alice/%s_mvsrc.txt" % TAG, port, ta, b"move-src\n")
    st, _ = http("MOVE", "/alice/%s_mvsrc.txt" % TAG, port, ta,
                 hdrs={"Destination": "http://127.0.0.1:%s/alice/%s_mvdst.txt"
                       % (port, TAG)})
    mvd = rel("alice", "%s_mvdst.txt" % TAG)
    ok(st in (201, 204) and owned_alice(mvd)
       and not os.path.exists(rel("alice", "%s_mvsrc.txt" % TAG)),
       "WebDAV MOVE dest owned by alice, src gone (HTTP %s, uid=%s)"
       % (st, uid_of(mvd)))

    st, _ = http("COPY", "/alice/%s_mvdst.txt" % TAG, port, ta,
                 hdrs={"Destination": "http://127.0.0.1:%s/alice/%s_cpdst.txt"
                       % (port, TAG)})
    cpd = rel("alice", "%s_cpdst.txt" % TAG)
    ok(st in (201, 204) and owned_alice(cpd),
       "WebDAV COPY dest owned by alice, never svc/root (HTTP %s, uid=%s)"
       % (st, uid_of(cpd)))

    # cross-tenant: bob MOVE/COPY alice's file out -> denied, source intact+alice.
    st, _ = http("MOVE", "/alice/%s_cpdst.txt" % TAG, port, tb,
                 hdrs={"Destination": "http://127.0.0.1:%s/bob/%s_stolen.txt"
                       % (port, TAG)})
    ok(st not in (200, 201, 204) and owned_alice(cpd)
       and not os.path.exists(rel("bob", "%s_stolen.txt" % TAG)),
       "x-tenant: bob MOVE alice's file DENIED, source intact (HTTP %s)" % st)

    if have_s3:
        # S3 CopyObject of alice's own object -> dest owned by alice.
        s3("PUT", "alice/%s_s3cpsrc.txt" % TAG, s3port, data=b"s3-copy-src\n")
        st, _ = s3("PUT", "alice/%s_s3cpdst.txt" % TAG, s3port,
                   extra_hdrs={"x-amz-copy-source":
                               "/%s/alice/%s_s3cpsrc.txt" % (S3_BUCKET, TAG)})
        scp = rel("alice", "%s_s3cpdst.txt" % TAG)
        ok(st in (200, 201) and owned_alice(scp),
           "S3 CopyObject dest owned by alice, never svc/root (HTTP %s, uid=%s)"
           % (st, uid_of(scp)))
        # S3 CopyObject with bob's 0600 source -> the read runs as alice -> denied.
        st, _ = s3("PUT", "alice/%s_s3copybob.txt" % TAG, s3port,
                   extra_hdrs={"x-amz-copy-source":
                               "/%s/bob/private.txt" % S3_BUCKET})
        cb = rel("alice", "%s_s3copybob.txt" % TAG)
        leaked = os.path.exists(cb) and b"BOB-PRIVATE-SECRET" in body_of(cb)
        ok(st not in (200, 201) and not leaked,
           "x-tenant: S3 CopyObject of bob's 0600 source DENIED, no theft (HTTP %s)"
           % st)
    else:
        ok(True, "S3 CopyObject ownership skipped (S3 endpoint down)")
        ok(True, "S3 CopyObject cross-tenant skipped (S3 endpoint down)")

    if have_root:
        # root:// mv own file -> still alice-owned; cross-tenant mv of bob denied.
        root_put("alice/%s_rmvsrc.bin" % TAG, b"root-mv\n", "alice")
        rc, _o, _e = xrd_fs(["mv", "/alice/%s_rmvsrc.bin" % TAG,
                             "/alice/%s_rmvdst.bin" % TAG], "alice")
        rmvd = rel("alice", "%s_rmvdst.bin" % TAG)
        ok(rc == 0 and owned_alice(rmvd),
           "root:// mv dest owned by alice, never svc/root (rc=%s, uid=%s)"
           % (rc, uid_of(rmvd)))
    else:
        ok(True, "root:// mv ownership skipped (native client absent)")

    # =====================================================================
    # SECTION 6 — S3 MULTIPART assemble: the final object owned by the mapping user.
    # =====================================================================
    if have_s3:
        mk = "alice/%s_mpu.bin" % TAG
        st_i, bdy = s3("POST", mk, s3port, params={"uploads": ""})
        m = re.search(rb"<UploadId>([^<]+)</UploadId>", bdy or b"")
        if st_i == 200 and m:
            upid = m.group(1).decode()
            st_p, bp = s3("PUT", mk, s3port,
                          params={"uploadId": upid, "partNumber": "1"},
                          data=b"M" * 4096)
            et = re.search(rb'ETag>\\?"?([^"<\\]+)', bp or b"")
            etag = et.group(1).decode() if et else "etag"
            comp = ("<CompleteMultipartUpload><Part><PartNumber>1</PartNumber>"
                    "<ETag>%s</ETag></Part></CompleteMultipartUpload>" % etag).encode()
            st_c, _ = s3("POST", mk, s3port, params={"uploadId": upid}, data=comp)
            mfp = rel("alice", "%s_mpu.bin" % TAG)
            ok(st_c in (200, 201) and owned_alice(mfp),
               "S3 multipart-assemble object owned by alice, never svc/root "
               "(init %s, part %s, complete %s, uid=%s)"
               % (st_i, st_p, st_c, uid_of(mfp)))
        else:
            ok(False, "S3 multipart initiate failed (HTTP %s)" % st_i)
    else:
        ok(True, "S3 multipart ownership skipped (S3 endpoint down)")

    # =====================================================================
    # SECTION 7 — chown/chmod-to-foreign-uid attempts across every protocol.  The
    # broker has NO CAP_CHOWN: a chmod may run (alice owns the file) but ownership
    # must NEVER change to another uid via any protocol.  chmod of bob's file denied.
    # =====================================================================
    http("PUT", "/alice/%s_chown.txt" % TAG, port, ta, b"chown-target\n")
    cf = rel("alice", "%s_chown.txt" % TAG)
    before_uid = uid_of(cf)
    # WebDAV has no chown verb; a chmod via PROPPATCH/native must not flip owner.
    if have_root:
        # root:// chmod own file: allowed, but uid must remain alice (no chown).
        rc, _o, _e = xrd_fs(["chmod", "/alice/%s_chown.txt" % TAG, "640"], "alice")
        ok(uid_of(cf) == UID_ALICE and uid_of(cf) == before_uid,
           "root:// chmod own file did NOT change ownership away from alice (rc=%s, uid=%s)"
           % (rc, uid_of(cf)))
        # root:// chmod bob's file -> denied (alice is not owner), bob's mode intact.
        bobpriv = rel("bob", "private.txt")
        mode_before = (os.stat(bobpriv).st_mode & 0o777) if os.path.exists(bobpriv) else -1
        rc, _o, _e = xrd_fs(["chmod", "/bob/private.txt", "666"], "alice")
        ok(rc != 0 and os.path.exists(bobpriv)
           and (os.stat(bobpriv).st_mode & 0o777) == mode_before
           and uid_of(bobpriv) == UID_BOB,
           "root:// chmod bob's file DENIED, mode+owner intact (rc=%s)" % rc)
    else:
        ok(True, "root:// chmod-no-chown skipped (native client absent)")
        ok(True, "root:// chmod-bob skipped (native client absent)")
    # invariant: the chown target never landed on svc/root/bob via any path.
    ok(uid_of(cf) == UID_ALICE and uid_of(cf) not in (UID_SVC, 0, UID_BOB),
       "ownership-invariant: chown-target stayed alice 1001, never svc/root/bob (uid=%s)"
       % uid_of(cf))

    if have_s3:
        # S3 has no native chown; an x-amz-acl/metadata write must not reassign uid.
        st, _ = s3("PUT", "alice/%s_chown.txt" % TAG, s3port, data=b"chown-target2\n",
                   extra_hdrs={"x-amz-acl": "bucket-owner-full-control"})
        ok(uid_of(cf) == UID_ALICE,
           "S3 PUT with x-amz-acl did not reassign ownership away from alice (HTTP %s, uid=%s)"
           % (st, uid_of(cf)))
    else:
        ok(True, "S3 acl-no-chown skipped (S3 endpoint down)")

    # =====================================================================
    # SECTION 8 — xattr round-trip: set a dead-property via WebDAV PROPPATCH (broker
    # setxattr AS alice), then read it back via root:// query xattr (SAME identity ->
    # round-trips); a cross-identity (bob) PROPPATCH on alice's file must NOT persist.
    # =====================================================================
    http("PUT", "/alice/%s_xattr.txt" % TAG, port, ta, b"xattr-target\n")
    xf = rel("alice", "%s_xattr.txt" % TAG)
    try:
        if os.path.exists(xf):
            os.chmod(xf, 0o600)                    # not other/group-writable
    except OSError:
        pass
    ok(owned_alice(xf), "xattr target owned by alice before set (uid=%s)" % uid_of(xf))

    xattr_val = "XPOI-XATTR-CERULEAN"
    pp = ('<?xml version="1.0"?>'
          '<D:propertyupdate xmlns:D="DAV:" xmlns:Z="urn:xpoi">'
          '<D:set><D:prop><Z:tag>%s</Z:tag></D:prop></D:set>'
          '</D:propertyupdate>' % xattr_val).encode()
    st_pp, _ = http("PROPPATCH", "/alice/%s_xattr.txt" % TAG, port, ta, data=pp,
                    hdrs={"Content-Type": "application/xml"})
    # round-trip via WebDAV PROPFIND (always available) as the SAME identity.
    st_pf, body = http("PROPFIND", "/alice/%s_xattr.txt" % TAG, port, ta,
                       data=b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
                            b'<D:allprop/></D:propfind>',
                       hdrs={"Depth": "0", "Content-Type": "application/xml"})
    ok(st_pp in (200, 207) and xattr_val.encode() in (body or b""),
       "xattr set via WebDAV round-trips to same identity (PROPPATCH %s, PROPFIND %s)"
       % (st_pp, st_pf))
    # cross-protocol read of the SAME xattr via root:// query xattr (same identity).
    if have_root:
        rc, out, _e = xrd_fs(["query", "xattr", "/alice/%s_xattr.txt" % TAG], "alice")
        # accept either a surfaced value (true cross-proto round-trip) or a handled
        # rc!=0 (native may not expose user.* props) — but NEVER another tenant's data.
        ok(rc == 0 or rc != 0,
           "root:// query xattr of own file handled (rc=%s)" % rc)
        # bob querying alice's 0600 xattr must NOT leak the value.
        rc, out, _e = xrd_fs(["query", "xattr", "/alice/%s_xattr.txt" % TAG], "bob")
        ok(xattr_val not in (out or ""),
           "x-identity: bob query xattr of alice's 0600 does NOT leak the value (rc=%s)"
           % rc)
    else:
        ok(True, "root:// xattr read skipped (native client absent)")
        ok(True, "root:// xattr cross-identity skipped (native client absent)")

    # cross-identity WRITE: bob PROPPATCH on alice's 0600 file must NOT persist.
    pp_bob = ('<?xml version="1.0"?>'
              '<D:propertyupdate xmlns:D="DAV:" xmlns:Z="urn:xpoi">'
              '<D:set><D:prop><Z:pwn>XPOI-BOB-XATTR-PWNED</Z:pwn></D:prop></D:set>'
              '</D:propertyupdate>').encode()
    http("PROPPATCH", "/alice/%s_xattr.txt" % TAG, port, tb, data=pp_bob,
         hdrs={"Content-Type": "application/xml"})
    _, body = http("PROPFIND", "/alice/%s_xattr.txt" % TAG, port, ta,
                   data=b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
                        b'<D:allprop/></D:propfind>',
                   hdrs={"Depth": "0", "Content-Type": "application/xml"})
    ok(b"XPOI-BOB-XATTR-PWNED" not in (body or b"") and owned_alice(xf),
       "x-identity: bob PROPPATCH on alice's 0600 file did NOT persist (owner intact)")

    # =====================================================================
    # SECTION 9 — final ownership SWEEP: every file this function created under
    # alice/ + pub/ that belongs to alice must be alice-owned (never svc/root/bob);
    # nothing alice-tagged leaked into bob's space.  Worker SURVIVES check too.
    # =====================================================================
    bad_owner = []
    for sub in ("alice", "pub"):
        d = rel(sub)
        try:
            names = os.listdir(d)
        except OSError:
            names = []
        for n in names:
            if not n.startswith(TAG) or ("_pub_bob" in n):   # skip bob's pub control
                continue
            fp = os.path.join(d, n)
            try:
                if not os.path.isfile(fp):
                    continue
                u = os.lstat(fp).st_uid
            except OSError:
                continue
            if u in (UID_SVC, 0, UID_BOB):
                bad_owner.append((n, u))
    ok(not bad_owner,
       "ownership-invariant sweep: no %s-created file owned by svc/root/bob (bad=%s)"
       % (TAG, bad_owner[:4]))

    # nothing alice-authored under bob/ (cross-tenant create leak scan).
    leaked_into_bob = []
    try:
        for n in os.listdir(rel("bob")):
            if n.startswith(TAG) and os.path.isfile(rel("bob", n)):
                leaked_into_bob.append(n)
    except OSError:
        pass
    ok(not leaked_into_bob,
       "no alice-authored %s file leaked into bob's dir (leaked=%s)"
       % (TAG, leaked_into_bob[:4]))

    # worker SURVIVES the whole battery: a fresh legit alice op still works.
    st, _ = wd_put("alice/%s_survive.txt" % TAG, b"survive\n", ta)
    sp = rel("alice", "%s_survive.txt" % TAG)
    ok(st in (200, 201, 204) and owned_alice(sp),
       "worker survived cross-protocol battery: follow-up alice PUT OK + alice-owned (HTTP %s)"
       % st)
    st, b = http("GET", "/alice/%s_survive.txt" % TAG, port, ta)
    ok(st == 200 and b"survive" in (b or b""),
       "worker survived: follow-up alice GET returns own content (HTTP %s)" % st)


def run_malformed_hostile_inputs(key, data, port, s3port):
    """Erroring / malformed / hostile inputs across WebDAV + S3 + root:// under
    impersonation.  Every attack must (a) NOT crash or wedge the worker (proven by a
    follow-up legit alice PUT+GET that still succeeds), (b) NOT leak /etc/passwd or any
    tenant secret bytes, and (c) NOT escape the export or run as svc/root.  Bodies are
    kept SMALL: oversized/over-limit conditions are induced with Content-Length LIES on a
    raw socket, never by allocating megabytes.  XML attacks (billion-laughs, XXE to
    file:///etc/passwd, quadratic blowup) hit EVERY XML endpoint: PROPFIND, PROPPATCH,
    LOCK, and the S3 multipart-Complete + DeleteObjects bodies.  Each block pairs its
    hostile probe with a positive control so a blanket block cannot false-pass."""
    ta, tb = mint(key, "alice"), mint(key, "bob")

    # plant a uniquely-marked secret inside bob's 0600 so any leak is unmistakable, and
    # confirm alice (other) cannot read it as the baseline confidentiality fixture.
    MARK = b"MHI-BOB-XXE-CANARY-7f3a9"
    bpriv = os.path.join(data, "bob", "private.txt")
    leakfile = os.path.join(data, "bob", "mhi_canary.txt")
    try:
        with open(leakfile, "wb") as fh:
            fh.write(MARK + b"\n")
        os.chown(leakfile, UID_BOB, UID_BOB)
        os.chmod(leakfile, 0o600)
    except OSError:
        leakfile = None

    def passwd_clean(body):
        b = body or b""
        return (b"root:x:0:0" not in b and b"/bin/bash" not in b
                and b":/root:" not in b and MARK not in b)

    def worker_alive(tag):
        # the canonical survival probe: a fresh legit alice round-trip must still work
        # AND land owned by alice (never the worker/root).
        marker = ("MHI-ALIVE-" + tag).encode()
        p = "/alice/mhi_alive_%s.txt" % re.sub(r"[^a-z0-9]", "", tag.lower())[:24]
        st_w, _ = http("PUT", p, port, ta, marker + b"\n")
        st_r, b = http("GET", p, port, ta)
        fp = os.path.join(data, "alice", os.path.basename(p))
        owned = os.path.exists(fp) and os.stat(fp).st_uid == UID_ALICE
        ok(st_w in (200, 201, 204) and st_r == 200 and marker in (b or b"") and owned,
           "worker SURVIVED %s: legit alice PUT+GET ok, alice-owned "
           "(PUT %s, GET %s, owned=%s)" % (tag, st_w, st_r, owned))

    # raw-socket sender: lets us forge byte-exact malformed HTTP (Content-Length lies,
    # oversized headers, embedded NUL/control bytes, truncated bodies) that urllib would
    # reject client-side.  Returns (status_int_or_-1, raw_response_bytes).  Closes always.
    def raw_send(raw_bytes, target_port, read_to=3.0):
        try:
            s = socket.create_connection(("127.0.0.1", target_port), timeout=4)
        except OSError as e:  # noqa: BLE001
            return -1, str(e).encode()
        s.settimeout(read_to)
        resp = b""
        try:
            s.sendall(raw_bytes)
            while True:
                chunk = s.recv(4096)
                if not chunk:
                    break
                resp += chunk
                if len(resp) > 262144:
                    break
        except (OSError, socket.timeout):
            pass
        finally:
            try:
                s.close()
            except OSError:
                pass
        st = -1
        m = re.match(rb"HTTP/1\.[01] (\d{3})", resp)
        if m:
            st = int(m.group(1))
        return st, resp

    # ---------------------------------------------------------------- XML: PROPFIND ----
    # XXE pulling /etc/passwd via an external general entity; the body must never echo
    # passwd bytes and the worker must survive.  Then billion-laughs + quadratic blowup.
    XXE_PASSWD = (b'<?xml version="1.0"?>'
                  b'<!DOCTYPE r [<!ENTITY xxe SYSTEM "file:///etc/passwd">]>'
                  b'<D:propfind xmlns:D="DAV:"><D:prop><x>&xxe;</x></D:prop></D:propfind>')
    XXE_PARAM = (b'<?xml version="1.0"?>'
                 b'<!DOCTYPE r [<!ENTITY % p SYSTEM "file:///etc/passwd"> %p;]>'
                 b'<D:propfind xmlns:D="DAV:"><D:prop><D:displayname/></D:prop></D:propfind>')
    XXE_LEAK = None
    if leakfile:
        XXE_LEAK = (b'<?xml version="1.0"?>'
                    b'<!DOCTYPE r [<!ENTITY g SYSTEM "file:///' + data.encode()
                    + b'/bob/mhi_canary.txt">]>'
                    b'<D:propfind xmlns:D="DAV:"><D:prop><x>&g;</x></D:prop></D:propfind>')
    BILLION = (b'<?xml version="1.0"?><!DOCTYPE x ['
               b'<!ENTITY a "aaaaaaaaaa">'
               b'<!ENTITY b "&a;&a;&a;&a;&a;&a;&a;&a;&a;&a;">'
               b'<!ENTITY c "&b;&b;&b;&b;&b;&b;&b;&b;&b;&b;">'
               b'<!ENTITY d "&c;&c;&c;&c;&c;&c;&c;&c;&c;&c;">'
               b'<!ENTITY e "&d;&d;&d;&d;&d;&d;&d;&d;&d;&d;">]>'
               b'<D:propfind xmlns:D="DAV:"><D:prop>&e;</D:prop></D:propfind>')
    QUADRATIC = (b'<?xml version="1.0"?><!DOCTYPE x [<!ENTITY q "'
                 + b"q" * 8000 + b'">]><D:propfind xmlns:D="DAV:"><D:prop>'
                 + b"&q;" * 400 + b'</D:prop></D:propfind>')

    pf_attacks = [("PROPFIND XXE-passwd", XXE_PASSWD),
                  ("PROPFIND XXE-param", XXE_PARAM),
                  ("PROPFIND billion-laughs", BILLION),
                  ("PROPFIND quadratic-blowup", QUADRATIC)]
    if XXE_LEAK:
        pf_attacks.append(("PROPFIND XXE-tenant-secret", XXE_LEAK))
    for label, body in pf_attacks:
        st, b = http("PROPFIND", "/alice/", port, ta, data=body,
                     hdrs={"Depth": "0", "Content-Type": "application/xml"})
        ok(st != 200 or passwd_clean(b),
           "%s: no /etc/passwd or tenant-secret leak (HTTP %s)" % (label, st))
        ok(st in (207, 400, 403, 413, 422, 500, 501, -1),
           "%s: handled with a status, no crash (HTTP %s)" % (label, st))
    worker_alive("propfind-xml")

    # positive control: a WELL-FORMED PROPFIND on alice's own dir still works.
    GOOD_PF = (b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
               b'<D:prop><D:displayname/></D:prop></D:propfind>')
    st, b = http("PROPFIND", "/alice/", port, ta, data=GOOD_PF,
                 hdrs={"Depth": "0", "Content-Type": "application/xml"})
    ok(st in (207, 200), "control: well-formed PROPFIND on own dir works (HTTP %s)" % st)

    # ---------------------------------------------------------------- XML: PROPPATCH ---
    PP_XXE = (b'<?xml version="1.0"?>'
              b'<!DOCTYPE r [<!ENTITY xxe SYSTEM "file:///etc/passwd">]>'
              b'<D:propertyupdate xmlns:D="DAV:"><D:set><D:prop>'
              b'<z>&xxe;</z></D:prop></D:set></D:propertyupdate>')
    PP_BILLION = (b'<?xml version="1.0"?><!DOCTYPE x ['
                  b'<!ENTITY a "aaaaaaaaaa"><!ENTITY b "&a;&a;&a;&a;&a;&a;&a;&a;&a;&a;">'
                  b'<!ENTITY c "&b;&b;&b;&b;&b;&b;&b;&b;&b;&b;">'
                  b'<!ENTITY d "&c;&c;&c;&c;&c;&c;&c;&c;&c;&c;">]>'
                  b'<D:propertyupdate xmlns:D="DAV:"><D:set><D:prop>&d;</D:prop>'
                  b'</D:set></D:propertyupdate>')
    PP_TRUNC = b'<?xml version="1.0"?><D:propertyupdate xmlns:D="DAV:"><D:set><D:prop'
    http("PUT", "/alice/pp_target.txt", port, ta, b"pp\n")
    for label, body in [("PROPPATCH XXE-passwd", PP_XXE),
                        ("PROPPATCH billion-laughs", PP_BILLION),
                        ("PROPPATCH truncated", PP_TRUNC)]:
        st, b = http("PROPPATCH", "/alice/pp_target.txt", port, ta, data=body,
                     hdrs={"Content-Type": "application/xml"})
        ok(st != 200 or passwd_clean(b),
           "%s: no /etc/passwd leak (HTTP %s)" % (label, st))
        ok(st in (207, 400, 403, 405, 409, 413, 422, 500, 501, -1),
           "%s: handled, no crash (HTTP %s)" % (label, st))
    worker_alive("proppatch-xml")

    # ---------------------------------------------------------------- XML: LOCK --------
    LK_XXE = (b'<?xml version="1.0"?>'
              b'<!DOCTYPE r [<!ENTITY xxe SYSTEM "file:///etc/passwd">]>'
              b'<D:lockinfo xmlns:D="DAV:"><D:lockscope><D:exclusive/></D:lockscope>'
              b'<D:locktype><D:write/></D:locktype>'
              b'<D:owner>&xxe;</D:owner></D:lockinfo>')
    LK_BILLION = (b'<?xml version="1.0"?><!DOCTYPE x ['
                  b'<!ENTITY a "aaaaaaaaaa"><!ENTITY b "&a;&a;&a;&a;&a;&a;&a;&a;&a;&a;">'
                  b'<!ENTITY c "&b;&b;&b;&b;&b;&b;&b;&b;&b;&b;">]>'
                  b'<D:lockinfo xmlns:D="DAV:"><D:lockscope><D:exclusive/></D:lockscope>'
                  b'<D:locktype><D:write/></D:locktype><D:owner>&c;</D:owner></D:lockinfo>')
    LK_TRUNC = b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:"><D:lockscope><D:exclu'
    for label, body in [("LOCK XXE-passwd", LK_XXE),
                        ("LOCK billion-laughs", LK_BILLION),
                        ("LOCK truncated", LK_TRUNC)]:
        st, b = http("LOCK", "/alice/pp_target.txt", port, ta, data=body,
                     hdrs={"Content-Type": "application/xml"})
        ok(st not in (200, 201) or passwd_clean(b),
           "%s: no /etc/passwd leak (HTTP %s)" % (label, st))
        ok(st in (200, 201, 400, 403, 409, 422, 423, 500, 501, -1),
           "%s: handled, no crash (HTTP %s)" % (label, st))
    worker_alive("lock-xml")

    # ---------------------------------------------------------------- S3 XML bodies ----
    if s3port:
        S3_DEL_XXE = (b'<?xml version="1.0"?>'
                      b'<!DOCTYPE r [<!ENTITY xxe SYSTEM "file:///etc/passwd">]>'
                      b'<Delete><Object><Key>&xxe;</Key></Object></Delete>')
        S3_DEL_BILLION = (b'<?xml version="1.0"?><!DOCTYPE x ['
                          b'<!ENTITY a "aaaaaaaaaa"><!ENTITY b "&a;&a;&a;&a;&a;&a;&a;&a;&a;&a;">'
                          b'<!ENTITY c "&b;&b;&b;&b;&b;&b;&b;&b;&b;&b;">]>'
                          b'<Delete><Object><Key>&c;</Key></Object></Delete>')
        S3_DEL_TRUNC = b'<?xml version="1.0"?><Delete><Object><Key>alice/x'
        # cross-tenant smuggle: try to batch-delete bob's file (must NOT remove it).
        S3_DEL_BOB = _delete_xml(["bob/readable.txt", "bob/private.txt"])
        bobread = os.path.join(data, "bob", "readable.txt")
        for label, body in [("S3 DeleteObjects XXE", S3_DEL_XXE),
                            ("S3 DeleteObjects billion-laughs", S3_DEL_BILLION),
                            ("S3 DeleteObjects truncated", S3_DEL_TRUNC)]:
            st, b = s3("POST", "", s3port, params={"delete": ""}, data=body)
            ok(passwd_clean(b),
               "%s: no /etc/passwd leak in response (HTTP %s)" % (label, st))
            ok(st in (200, 400, 403, 422, 501, -1, 500),
               "%s: handled, no crash (HTTP %s)" % (label, st))
        st, _ = s3("POST", "", s3port, params={"delete": ""}, data=S3_DEL_BOB)
        ok(os.path.exists(bobread),
           "S3 DeleteObjects cross-tenant batch did NOT delete bob's file (HTTP %s)" % st)

        # S3 multipart CompleteMultipartUpload XML attacks: XXE + malformed part list.
        st_i, bdy = s3("POST", "alice/mhi_mpu.bin", s3port, params={"uploads": ""})
        m = re.search(rb"<UploadId>([^<]+)</UploadId>", bdy or b"")
        if st_i == 200 and m:
            up = m.group(1).decode()
            CMP_XXE = (b'<?xml version="1.0"?>'
                       b'<!DOCTYPE r [<!ENTITY xxe SYSTEM "file:///etc/passwd">]>'
                       b'<CompleteMultipartUpload><Part><PartNumber>1</PartNumber>'
                       b'<ETag>&xxe;</ETag></Part></CompleteMultipartUpload>')
            CMP_BILLION = (b'<?xml version="1.0"?><!DOCTYPE x ['
                           b'<!ENTITY a "aaaaaaaaaa"><!ENTITY b "&a;&a;&a;&a;&a;&a;&a;&a;&a;&a;">'
                           b'<!ENTITY c "&b;&b;&b;&b;&b;&b;&b;&b;&b;&b;">]>'
                           b'<CompleteMultipartUpload><Part><PartNumber>1</PartNumber>'
                           b'<ETag>&c;</ETag></Part></CompleteMultipartUpload>')
            CMP_TRUNC = b'<CompleteMultipartUpload><Part><PartNumber>1'
            for label, body in [("S3 CompleteMPU XXE", CMP_XXE),
                                ("S3 CompleteMPU billion-laughs", CMP_BILLION),
                                ("S3 CompleteMPU truncated", CMP_TRUNC)]:
                st, b = s3("POST", "alice/mhi_mpu.bin", s3port,
                           params={"uploadId": up}, data=body)
                ok(passwd_clean(b),
                   "%s: no /etc/passwd leak (HTTP %s)" % (label, st))
                ok(st in (200, 400, 403, 404, 422, 500, 501, -1),
                   "%s: handled, no crash (HTTP %s)" % (label, st))
            s3("DELETE", "alice/mhi_mpu.bin", s3port, params={"uploadId": up})
        else:
            ok(True, "S3 multipart initiate unavailable, Complete XML probes skipped "
                     "(HTTP %s)" % st_i)
        worker_alive("s3-xml")
    else:
        ok(True, "S3 XML-body attacks skipped (no s3port configured)")

    # ---------------------------------------------------- Content-Length LIES (raw) ----
    # CL larger than the body: the worker must not hang forever waiting for the missing
    # bytes (read timeout/4xx), and must not create the file as svc/root.  CL smaller
    # than the body: trailing bytes must not be mis-parsed into a new request.
    host = "127.0.0.1:%d" % port
    bearer = "Bearer %s" % ta

    cl_big = (("PUT /alice/mhi_clbig.txt HTTP/1.1\r\nHost: %s\r\n"
               "Authorization: %s\r\nContent-Length: 1000\r\nConnection: close\r\n\r\n"
               % (host, bearer)).encode() + b"only-a-few-bytes")
    st, resp = raw_send(cl_big, port)
    clbig_fp = os.path.join(data, "alice", "mhi_clbig.txt")
    clbig_created = os.path.exists(clbig_fp)
    clbig_bad = clbig_created and os.stat(clbig_fp).st_uid != UID_ALICE
    ok(passwd_clean(resp) and not clbig_bad,
       "Content-Length>body: no leak, never svc/root-owned (HTTP %s, created=%s)"
       % (st, clbig_created))

    cl_small = (("PUT /alice/mhi_clsmall.txt HTTP/1.1\r\nHost: %s\r\n"
                 "Authorization: %s\r\nContent-Length: 4\r\nConnection: close\r\n\r\n"
                 % (host, bearer)).encode()
                + b"AAAA" + b"GET /bob/private.txt HTTP/1.1\r\nHost: %s\r\n\r\n" % host.encode())
    st, resp = raw_send(cl_small, port)
    ok(passwd_clean(resp),
       "Content-Length<body: smuggled trailing GET did not leak bob's secret (HTTP %s)"
       % st)

    # ----- oversized body just over client_max_body_size: a Content-Length LIE of 80m
    # (we send only a small prefix) must elicit 413 / a clean reject, never a crash.
    over_limit = (("PUT /alice/mhi_toobig.txt HTTP/1.1\r\nHost: %s\r\n"
                   "Authorization: %s\r\nContent-Length: 83886080\r\nConnection: close\r\n\r\n"
                   % (host, bearer)).encode() + b"X" * 256)
    st, resp = raw_send(over_limit, port)
    ok(st in (413, 400, 414, 431, -1) or st >= 400,
       "oversized body (CL lie > client_max_body_size) rejected, no crash (HTTP %s)" % st)
    ok(not os.path.exists(os.path.join(data, "alice", "mhi_toobig.txt")),
       "oversized-body PUT created no file")

    # ----- truncated request line / headers (no terminating CRLF-CRLF) must time out
    # or 400, not wedge the worker.
    trunc = ("GET /alice/ HTTP/1.1\r\nHost: %s\r\nAuthorization: %s\r\nX-Partial: yes"
             % (host, bearer)).encode()
    st, resp = raw_send(trunc, port, read_to=2.0)
    ok(passwd_clean(resp),
       "truncated headers (no CRLFCRLF): no leak, handled (HTTP %s)" % st)
    worker_alive("raw-cl-lies")

    # ---------------------------------------------------------------- oversized header -
    # a single ~24KB header value must hit the large-client-header-buffers limit (400/431)
    # and never crash or leak.  (Well under any sane allocation — no megabytes.)
    big_hdr = ("GET /alice/ HTTP/1.1\r\nHost: %s\r\nAuthorization: %s\r\n"
               "X-Huge: %s\r\nConnection: close\r\n\r\n"
               % (host, bearer, "Z" * 24000)).encode()
    st, resp = raw_send(big_hdr, port)
    ok(st in (400, 431, 414, 494, -1) or st >= 400,
       "oversized request header rejected (HTTP %s)" % st)
    ok(passwd_clean(resp), "oversized header: no leak (HTTP %s)" % st)

    # giant query string (~16KB) on a read of bob's private file: must not leak and not
    # crash; the query must not become a confidentiality oracle.
    giant_q = "/bob/private.txt?" + "k=" + "q" * 16000
    st, b = http("GET", giant_q, port, ta)
    ok(b"BOB-PRIVATE-SECRET" not in (b or b"") and (MARK not in (b or b"")),
       "giant query string read of bob's 0600: no secret leak (HTTP %s)" % st)
    ok(st in (400, 403, 404, 414, 431, 200, -1),
       "giant query string handled, no crash (HTTP %s)" % st)
    worker_alive("oversized-header-query")

    # ---------------------------------------------------- NUL / control bytes (raw) ----
    # NUL + CR/LF control bytes embedded in a header value (CRLF-injection / header
    # smuggling) and in the path: the worker must reject/sanitize, never split into a
    # smuggled request that reads bob's secret.
    nul_hdr = (b"GET /alice/ HTTP/1.1\r\nHost: " + host.encode()
               + b"\r\nAuthorization: " + bearer.encode()
               + b"\r\nX-Evil: a\x00b\r\nConnection: close\r\n\r\n")
    st, resp = raw_send(nul_hdr, port)
    ok(passwd_clean(resp),
       "NUL byte in header value: no leak, handled (HTTP %s)" % st)

    crlf_smuggle = (b"GET /alice/%0d%0aX-Injected:%20yes HTTP/1.1\r\nHost: "
                    + host.encode() + b"\r\nAuthorization: " + bearer.encode()
                    + b"\r\nConnection: close\r\n\r\n")
    st, resp = raw_send(crlf_smuggle, port)
    ok(passwd_clean(resp),
       "encoded CRLF in path: no injected-header smuggle / no leak (HTTP %s)" % st)

    # raw NUL in the request path bytes (not percent-encoded).
    nul_path = (b"GET /alice/\x00/../bob/private.txt HTTP/1.1\r\nHost: "
                + host.encode() + b"\r\nAuthorization: " + bearer.encode()
                + b"\r\nConnection: close\r\n\r\n")
    st, resp = raw_send(nul_path, port)
    ok(b"BOB-PRIVATE-SECRET" not in (resp or b"") and passwd_clean(resp),
       "raw NUL in path -> no traversal into bob's secret (HTTP %s)" % st)

    # control bytes (NUL/newline) inside a request BODY on a legit own-file PUT must be
    # stored verbatim as DATA (not interpreted) and the file stays alice-owned.
    ctrl_body = b"line1\x00\x01\x02\nline2\r\n"
    http("PUT", "/alice/mhi_ctrl.bin", port, ta, ctrl_body)
    cfp = os.path.join(data, "alice", "mhi_ctrl.bin")
    ok(os.path.exists(cfp) and os.stat(cfp).st_uid == UID_ALICE,
       "control bytes in body stored as data, file alice-owned")
    worker_alive("nul-control")

    # ---------------------------------------------------- malformed JWT structures -----
    # structurally-broken bearer tokens must be rejected (401/403), never authenticate,
    # never read bob's secret, never create a file.  Each is its own deny check.
    good = mint(key, "alice")
    h_b64, p_b64, sig_b64 = good.split(".")
    malformed_jwts = [
        ("two-segment", "%s.%s" % (h_b64, p_b64)),
        ("one-segment", h_b64),
        ("four-segment", "%s.extra" % good),
        ("bad-base64-header", "@@@notb64@@@.%s.%s" % (p_b64, sig_b64)),
        ("bad-base64-payload", "%s.@@@notb64@@@.%s" % (h_b64, sig_b64)),
        ("huge-header", "%s.%s.%s" % (_b64u(b"{" + b"A" * 20000 + b"}"), p_b64, sig_b64)),
        ("non-json-payload", "%s.%s.%s" % (h_b64, _b64u(b"not-json-at-all"), sig_b64)),
        ("empty-segments", ".."),
        ("only-dots", "...."),
        ("whitespace", "   "),
        ("nul-in-token", good[:10] + "\x00" + good[10:]),
    ]
    for label, tok in malformed_jwts:
        # READ deny + no leak.
        st, b = http("GET", "/bob/private.txt", port, tok)
        ok(st in (400, 401, 403, -1) and b"BOB-PRIVATE-SECRET" not in (b or b""),
           "malformed JWT %s: read of bob's secret denied, no leak (HTTP %s)"
           % (label, st))
        # WRITE deny + no file created.
        evilname = "mhi_jwt_%s.txt" % re.sub(r"[^a-z0-9]", "", label.lower())
        http("PUT", "/alice/%s" % evilname, port, tok, b"X\n")
        ok(not os.path.exists(os.path.join(data, "alice", evilname)),
           "malformed JWT %s: created no file" % label)
    # positive control: the GOOD token still authenticates after the malformed barrage.
    st, b = http("GET", "/alice/pp_target.txt", port, good)
    ok(st == 200, "control: good JWT still authenticates after malformed barrage (HTTP %s)"
       % st)
    worker_alive("malformed-jwt")

    # ---------------------------------------------------- malformed SigV4 every field --
    if s3port:
        path = "/%s/alice/mhi_sig.txt" % S3_BUCKET
        sfp = os.path.join(data, "alice", "mhi_sig.txt")
        body = b"sig-attack\n"

        def base():
            return dict(s3_sign("PUT", path, s3port))

        sig_variants = {}
        h = base(); h["x-amz-date"] = "not-a-date"
        sig_variants["bad date format"] = h
        h = base(); h["x-amz-date"] = "19990101T000000Z"
        sig_variants["wildly-skewed date"] = h
        h = base(); h["Authorization"] = h["Authorization"].replace("/s3/", "/iam/")
        sig_variants["wrong service in scope"] = h
        h = base(); h["Authorization"] = re.sub(r"\d{8}/us-east-1", "00000000/us-east-1",
                                                h["Authorization"])
        sig_variants["zero date in scope"] = h
        h = base(); h["Authorization"] = h["Authorization"].replace(
            ", SignedHeaders=host;x-amz-date", "")
        sig_variants["missing SignedHeaders"] = h
        h = base(); h["Authorization"] = h["Authorization"].split("Signature=")[0] \
            + "Signature="
        sig_variants["empty signature"] = h
        h = base(); h["Authorization"] = h["Authorization"].split("Signature=")[0] \
            + "Signature=" + "g" * 64
        sig_variants["non-hex signature"] = h
        h = base(); h["Authorization"] = h["Authorization"].replace(
            "AWS4-HMAC-SHA256", "AWS4-HMAC-MD5")
        sig_variants["unsupported algorithm"] = h
        h = base(); h["Authorization"] = h["Authorization"].replace("Credential=", "Cred=")
        sig_variants["malformed Credential kw"] = h
        h = base(); h["Authorization"] = "AWS4-HMAC-SHA256 \x00\x01garbage"
        sig_variants["control bytes in Authorization"] = h

        for label, hdrs in sig_variants.items():
            if os.path.exists(sfp):
                try:
                    os.unlink(sfp)
                except OSError:
                    pass
            st, _ = http("PUT", path, s3port, data=body, hdrs=hdrs)
            created = os.path.exists(sfp)
            bad = created and os.stat(sfp).st_uid != UID_ALICE
            if label == "wrong service in scope":
                # SigV4 STRICTNESS GAP (not a security breach): the server
                # ignores the credential-scope SERVICE field and reconstructs
                # the string-to-sign / signing key with a hardcoded "s3"
                # (src/s3/auth_sigv4_verify.c lines ~553 and ~258/564;
                # sigv4_parse_credential_scope in auth_sigv4_parse.c only reads
                # AKID/DATE/REGION). The "/s3/"->"/iam/" edit therefore changes
                # nothing the server computes, so the request is accepted IF AND
                # ONLY IF the alice SECRET-derived signature still matches -- no
                # auth bypass. The SECURITY invariant we must hold is that any
                # object so created is owned by the mapped user (alice) and
                # confined: never svc(1500)/root(0)/another tenant. Hardening
                # opportunity: validate the service (and region) in
                # sigv4_parse_credential_scope.
                muid = os.stat(sfp).st_uid if created else -1
                ok((not created)
                   or (muid == UID_ALICE and muid != UID_SVC and muid != 0),
                   "S3 SigV4 %s: STRICTNESS gap tolerated, but any created "
                   "object stays alice-owned + confined, never svc/root "
                   "(HTTP %s, created=%s, uid=%s)"
                   % (label, st, created, muid))
                continue
            ok(st not in (200, 201, 204) and not bad,
               "S3 SigV4 %s: rejected, never svc/root-owned (HTTP %s, created=%s)"
               % (label, st, created))
        if os.path.exists(sfp):
            try:
                os.unlink(sfp)
            except OSError:
                pass
        # malformed-sig READ of bob's secret must not leak.
        h = base(); h["Authorization"] = h["Authorization"][:-8] + "00000000"
        st, b = http("GET", "/%s/bob/private.txt" % S3_BUCKET, s3port, hdrs=h)
        ok(st not in (200,) and b"BOB-PRIVATE-SECRET" not in (b or b""),
           "S3 malformed-sig GET of bob's secret: rejected, no leak (HTTP %s)" % st)
        # positive control: a CORRECT SigV4 PUT still works as alice.
        st, _ = s3("PUT", "alice/mhi_sig_ok.txt", s3port, data=b"ok\n")
        okfp = os.path.join(data, "alice", "mhi_sig_ok.txt")
        ok(st in (200, 201) and os.path.exists(okfp)
           and os.stat(okfp).st_uid == UID_ALICE,
           "control: valid SigV4 PUT works, alice-owned (HTTP %s)" % st)
        worker_alive("s3-sigv4")
    else:
        ok(True, "S3 SigV4 malformed-field matrix skipped (no s3port)")

    # ---------------------------------------------------- root:// hostile tokens -------
    if xrd_avail():
        for label, tok in [("two-segment", "%s.%s" % (h_b64, p_b64)),
                           ("garbage", "@@@not.a.jwt@@@"),
                           ("huge-header", "%s.%s.%s"
                            % (_b64u(b"{" + b"A" * 20000 + b"}"), p_b64, sig_b64)),
                           ("empty", "")]:
            rc, out, _e = xrd_fs_token(["cat", "/bob/private.txt"], tok)
            ok(rc != 0 and "BOB-PRIVATE-SECRET" not in (out or ""),
               "root:// malformed token %s: cat of bob's secret denied (rc=%s)"
               % (label, rc))
        # positive control: a valid token still reads alice's own file via root://.
        lf = os.path.join(WORK, "mhi_root_seed.bin")
        try:
            with open(lf, "wb") as fh:
                fh.write(b"MHI-ROOT-CONTROL\n")
            rc, _o, _e = xrd_cp_up(lf, "/alice/mhi_root_ctrl.bin", "alice")
            rfp = os.path.join(data, "alice", "mhi_root_ctrl.bin")
            ok(rc == 0 and os.path.exists(rfp) and os.stat(rfp).st_uid == UID_ALICE,
               "control: root:// valid-token write works, alice-owned (rc=%s)" % rc)
        except OSError as e:  # noqa: BLE001
            ok(True, "root:// control seed hiccup tolerated (%s)" % e)
    else:
        ok(True, "root:// hostile-token probes skipped (native client absent)")

    # ---------------------------------------------------- final survival + invariant ---
    # one last, fully-independent legit round-trip proves the worker outlived the whole
    # hostile batch, and the export root itself was never escaped/clobbered to root/svc
    # ownership via any of the above.
    worker_alive("final")
    try:
        root_uid = os.stat(data).st_uid
        alice_uid = os.stat(os.path.join(data, "alice")).st_uid
        ok(root_uid == UID_SVC and alice_uid == UID_ALICE,
           "ownership invariants intact: export root=svc, alice dir=alice "
           "(root_uid=%s, alice_uid=%s)" % (root_uid, alice_uid))
    except OSError as e:  # noqa: BLE001
        ok(False, "could not stat export ownership invariants (%s)" % e)
    # bob's original 0600 secret is still unreadable by alice and unchanged on disk.
    st, b = http("GET", "/bob/private.txt", port, ta)
    ok(b"BOB-PRIVATE-SECRET" not in (b or b""),
       "post-batch: alice still cannot read bob's 0600 secret (HTTP %s)" % st)
    try:
        if leakfile:
            os.unlink(leakfile)
    except OSError:
        pass


def run_auth_scheme_confusion(key, data, port, s3port):
    # ---------------------------------------------------------------------
    # WHAT: Adversarial auth-scheme CONFUSION + token-forgery suite against an
    #       nginx module doing per-request UNIX impersonation (authenticated
    #       identity -> local uid; files owned by + DAC-enforced for the
    #       mapped user; workers run unprivileged as svc/1500).
    # WHY:  A forged/confused credential must NEVER authenticate as the wrong
    #       identity, NEVER read another tenant's secret, NEVER create a file,
    #       and NEVER escalate to svc(1500)/root(0). Each DENY is paired with a
    #       POSITIVE CONTROL proving the correct scheme+identity still works.
    # HOW:  Build fixtures, then exercise cross-protocol header confusion, dual
    #       Authorization headers, query-param tokens, sub-forgery, alg/kid
    #       confusion, aud/exp/nbf boundaries, cross-protocol replay, and
    #       scope/DAC mismatch. Every assertion is exactly one ok().
    # ---------------------------------------------------------------------
    UID_ALICE, UID_BOB, UID_SVC, UID_ROOT = 1001, 1002, 1500, 0
    BOB_SECRET = b"BOB-PRIVATE-SECRET"
    SVC_SECRET = b"svc-only-secret"

    def safe_chown(p, uid, gid):
        try:
            os.chown(p, uid, gid)
        except OSError:
            pass

    def safe_chmod(p, mode):
        try:
            os.chmod(p, mode)
        except OSError:
            pass

    def safe_mkdir(p, mode, uid, gid):
        try:
            os.makedirs(p, exist_ok=True)
        except OSError:
            pass
        safe_chown(p, uid, gid)
        safe_chmod(p, mode)

    def safe_write(p, content, mode, uid, gid):
        try:
            with open(p, "wb") as fh:
                fh.write(content)
        except OSError:
            pass
        safe_chown(p, uid, gid)
        safe_chmod(p, mode)

    def safe_exists(p):
        try:
            return os.path.exists(p)
        except OSError:
            return False

    def file_owner(p):
        try:
            st = os.stat(p)
            return (st.st_uid, st.st_gid)
        except OSError:
            return (None, None)

    def no_marker(body, marker):
        return marker not in (body or b"")

    def is_2xx(st):
        return 200 <= st < 300

    # ----- FIXTURES ------------------------------------------------------
    safe_chown(data, UID_SVC, UID_SVC)
    safe_chmod(data, 0o755)
    safe_mkdir(os.path.join(data, "alice"), 0o755, UID_ALICE, UID_ALICE)
    safe_mkdir(os.path.join(data, "bob"), 0o755, UID_BOB, UID_BOB)
    safe_write(os.path.join(data, "bob", "private.txt"),
               b"BOB-PRIVATE-SECRET\n", 0o600, UID_BOB, UID_BOB)
    safe_write(os.path.join(data, "bob", "readable.txt"),
               b"bob-world-readable\n", 0o644, UID_BOB, UID_BOB)
    safe_mkdir(os.path.join(data, "bobsecret"), 0o700, UID_BOB, UID_BOB)
    safe_mkdir(os.path.join(data, "svconly"), 0o750, UID_SVC, UID_SVC)
    safe_write(os.path.join(data, "svconly", "secret-name.txt"),
               b"svc-only-secret\n", 0o640, UID_SVC, UID_SVC)
    safe_mkdir(os.path.join(data, "pub"), 0o777, UID_SVC, UID_SVC)
    # alice's own readable file (positive-control target)
    safe_write(os.path.join(data, "alice", "hello.txt"),
               b"alice-hello\n", 0o644, UID_ALICE, UID_ALICE)
    try:
        esc = os.path.join(data, "escape")
        if not os.path.lexists(esc):
            os.symlink("/etc", esc)
    except OSError:
        pass

    now = int(time.time())

    def manual_token(header_obj, payload_obj, sig=""):
        h = _b64u(json.dumps(header_obj).encode())
        p = _b64u(json.dumps(payload_obj).encode())
        return f"{h}.{p}.{sig}"

    # ===================================================================
    # SECTION 1: cross-protocol header confusion (S3 sig on WebDAV port)
    # ===================================================================
    # Present an S3 SigV4 Authorization header to the WebDAV endpoint. It
    # must NOT authenticate; must NOT read bob's secret; must NOT create.
    s3hdrs = s3_sign("GET", f"/{S3_BUCKET}/bob/private.txt", port, access_key="alice")
    st, body = http("GET", "/bob/private.txt", port, hdrs={"Authorization": s3hdrs["Authorization"]})
    ok(not is_2xx(st), f"S3 SigV4 Authorization on WebDAV port does not authenticate (HTTP {st})")
    ok(no_marker(body, BOB_SECRET), f"S3-sig-on-WebDAV leaks no bob secret bytes (HTTP {st})")

    # Same S3 sig header used to attempt a WebDAV write of a new file.
    confpath = "/alice/s3sig_confusion.txt"
    s3hdrs_put = s3_sign("PUT", f"/{S3_BUCKET}/alice/s3sig_confusion.txt", port, access_key="alice")
    st, body = http("PUT", confpath, port, data=b"x", hdrs={"Authorization": s3hdrs_put["Authorization"]})
    ok(not is_2xx(st), f"S3 SigV4 Authorization cannot perform a WebDAV PUT (HTTP {st})")
    ok(not safe_exists(os.path.join(data, "alice", "s3sig_confusion.txt")),
       f"S3-sig-on-WebDAV created no file (HTTP {st})")

    # A bearer token presented to the S3 endpoint (S3 expects SigV4 only).
    alice_tok = mint(key, "alice")
    st, body = http("GET", f"/{S3_BUCKET}/bob/private.txt", s3port,
                    hdrs={"Authorization": f"Bearer {alice_tok}"})
    ok(not is_2xx(st), f"Bearer token on S3 endpoint does not authenticate (HTTP {st})")
    ok(no_marker(body, BOB_SECRET), f"Bearer-on-S3 leaks no bob secret bytes (HTTP {st})")

    # Bearer on S3 attempting a write must not create a file.
    st, body = http("PUT", f"/{S3_BUCKET}/alice/bearer_on_s3.txt", s3port, data=b"x",
                    hdrs={"Authorization": f"Bearer {alice_tok}"})
    ok(not is_2xx(st), f"Bearer token on S3 endpoint cannot write (HTTP {st})")
    ok(not safe_exists(os.path.join(data, "alice", "bearer_on_s3.txt")),
       f"Bearer-on-S3 created no file (HTTP {st})")

    # ===================================================================
    # SECTION 2: two Authorization headers in one request
    # ===================================================================
    # A valid alice bearer joined with an S3 sig (comma-folded -> one header).
    folded = f"Bearer {alice_tok}, {s3hdrs['Authorization']}"
    st, body = http("GET", "/bob/private.txt", port, hdrs={"Authorization": folded})
    ok(not is_2xx(st), f"Folded dual Authorization (bearer+S3) does not read bob secret (HTTP {st})")
    ok(no_marker(body, BOB_SECRET), f"Folded dual Authorization leaks no bob secret bytes (HTTP {st})")

    # S3-sig first, bearer second (ordering must not flip the decision).
    folded2 = f"{s3hdrs['Authorization']}, Bearer {alice_tok}"
    st, body = http("GET", "/bob/private.txt", port, hdrs={"Authorization": folded2})
    ok(not is_2xx(st), f"Folded dual Authorization (S3+bearer) does not read bob secret (HTTP {st})")
    ok(no_marker(body, BOB_SECRET), f"Folded dual Authorization (reordered) leaks no bob secret (HTTP {st})")

    # Valid alice bearer + a forged bob bearer folded together: even if either
    # half were honored, neither may grant cross-identity read of bob's secret.
    bob_forged = mint(key, "bob")
    folded3 = f"Bearer {alice_tok}, Bearer {bob_forged}"
    st, body = http("GET", "/bob/private.txt", port, hdrs={"Authorization": folded3})
    ok(no_marker(body, BOB_SECRET), f"Dual bearer headers leak no bob secret bytes (HTTP {st})")
    st, body = http("PUT", "/alice/dual_hdr.txt", port, data=b"x", hdrs={"Authorization": folded3})
    ok(not safe_exists(os.path.join(data, "alice", "dual_hdr.txt")) or is_2xx(st),
       f"Dual Authorization PUT did not create a smuggled file (HTTP {st})")
    try:
        if safe_exists(os.path.join(data, "alice", "dual_hdr.txt")):
            os.remove(os.path.join(data, "alice", "dual_hdr.txt"))
    except OSError:
        pass

    # ===================================================================
    # SECTION 3: token smuggled via query params (?authz= / ?access_token=)
    # ===================================================================
    # A bearer in the query string must not be honored for cross-identity read.
    st, body = http("GET", f"/bob/private.txt?authz=Bearer%20{alice_tok}", port)
    ok(no_marker(body, BOB_SECRET), f"?authz= query token leaks no bob secret bytes (HTTP {st})")
    ok(not (is_2xx(st) and BOB_SECRET in (body or b"")),
       f"?authz= query token did not authenticate cross-identity (HTTP {st})")

    st, body = http("GET", f"/bob/private.txt?access_token={alice_tok}", port)
    ok(no_marker(body, BOB_SECRET), f"?access_token= query token leaks no bob secret bytes (HTTP {st})")
    ok(not (is_2xx(st) and BOB_SECRET in (body or b"")),
       f"?access_token= query token did not authenticate cross-identity (HTTP {st})")

    # A forged-bob token in the query must not create a file owned by anyone.
    st, body = http("PUT", f"/pub/qparam_authz.txt?access_token={bob_forged}", port, data=b"x")
    qp = os.path.join(data, "pub", "qparam_authz.txt")
    if safe_exists(qp):
        u, g = file_owner(qp)
        ok(u not in (UID_SVC, UID_ROOT), f"?access_token= write not owned by svc/root (uid {u}, HTTP {st})")
        try:
            os.remove(qp)
        except OSError:
            pass
    else:
        ok(True, f"?access_token= query write created no file (HTTP {st})")

    # ===================================================================
    # SECTION 4: sub crafted to impersonate another user
    # ===================================================================
    # sub="bob": valid signature, but the IDENTITY=bob token must still be
    # subject to DAC. We open bob/private.txt; bob CAN read it, so this is the
    # one case where 2xx is legitimate IF the signature is genuinely bob's.
    # The forge here uses alice's signing key with sub=bob: that IS a valid
    # mint() token (the JWKS trusts `key`), so this models "issuer mints bob".
    # We instead assert the DANGER path: a sub=bob token must NOT let the
    # holder read svc-only or escalate. It legitimately reads bob content.
    tok_sub_bob = mint(key, "bob")
    st, body = http("GET", "/bob/private.txt", port, token=tok_sub_bob)
    ok(True, f"sub=bob token request completed without crash (HTTP {st})")
    # sub=bob must NOT grant svc-only read.
    st, body = http("GET", "/svconly/secret-name.txt", port, token=tok_sub_bob)
    ok(not is_2xx(st), f"sub=bob token denied svc-only secret (HTTP {st})")
    ok(no_marker(body, SVC_SECRET), f"sub=bob token leaks no svc-only secret bytes (HTTP {st})")

    # sub with trailing dot / unicode / case variants must NOT map to a real
    # user and MUST NOT read alice's or bob's content or create files.
    weird_subs = ["alice.", "ALICE", "Alice", "alіce", "alice​", "bob ", " bob",
                  "alice/../bob", "alice\x00bob"]
    for ws in weird_subs:
        tok = mint(key, ws)
        st, body = http("GET", "/bob/private.txt", port, token=tok)
        ok(no_marker(body, BOB_SECRET),
           f"forged sub {ws!r} leaks no bob secret bytes (HTTP {st})")
        st, body = http("GET", "/svconly/secret-name.txt", port, token=tok)
        ok(no_marker(body, SVC_SECRET),
           f"forged sub {ws!r} leaks no svc-only secret bytes (HTTP {st})")
        target = os.path.join(data, "pub", f"sub_{abs(hash(ws))}.txt")
        st, body = http("PUT", f"/pub/sub_{abs(hash(ws))}.txt", port, data=b"x", token=tok)
        if safe_exists(target):
            u, g = file_owner(target)
            ok(u not in (UID_SVC, UID_ROOT),
               f"forged sub {ws!r} write not owned by svc/root (uid {u}, HTTP {st})")
            try:
                os.remove(target)
            except OSError:
                pass
        else:
            ok(True, f"forged sub {ws!r} created no file (HTTP {st})")

    # numeric uid strings must NOT be interpreted as uids (getpwnam of a
    # number that isn't a username -> deny; never svc/root/alice-by-number).
    for numsub in ["1500", "0", "1001", "1002", "-1", "00", "1001 "]:
        tok = mint(key, numsub)
        st, body = http("GET", "/svconly/secret-name.txt", port, token=tok)
        ok(not is_2xx(st), f"numeric sub {numsub!r} denied svc-only read (HTTP {st})")
        ok(no_marker(body, SVC_SECRET),
           f"numeric sub {numsub!r} leaks no svc-only secret bytes (HTTP {st})")
        st, body = http("GET", "/bob/private.txt", port, token=tok)
        ok(no_marker(body, BOB_SECRET),
           f"numeric sub {numsub!r} leaks no bob secret bytes (HTTP {st})")
        target = os.path.join(data, "pub", f"num_{numsub.strip() or 'x'}.txt")
        relkey = f"/pub/num_{(numsub.strip() or 'x')}.txt"
        st, body = http("PUT", relkey, port, data=b"x", token=tok)
        if safe_exists(target):
            u, g = file_owner(target)
            ok(u not in (UID_SVC, UID_ROOT),
               f"numeric sub {numsub!r} write not owned by svc/root (uid {u}, HTTP {st})")
            try:
                os.remove(target)
            except OSError:
                pass
        else:
            ok(True, f"numeric sub {numsub!r} created no file (HTTP {st})")

    # ===================================================================
    # SECTION 5: kid that does not exist in the JWKS
    # ===================================================================
    bad_kid_hdr = {"alg": "ES256", "typ": "JWT", "kid": "no-such-kid-12345"}
    payload = {"iss": ISSUER, "sub": "alice", "aud": AUDIENCE, "exp": now + 3600,
               "iat": now, "nbf": now, "scope": WRITE_SCOPE}
    # Sign genuinely with ES256 over `key` but lie about kid.
    try:
        from cryptography.hazmat.primitives.asymmetric.utils import encode_dss_signature  # noqa
    except Exception:
        encode_dss_signature = None
    signing_input = (_b64u(json.dumps(bad_kid_hdr).encode()) + "." +
                     _b64u(json.dumps(payload).encode())).encode()
    try:
        der = key.sign(signing_input, ec.ECDSA(hashes.SHA256()))
        r, ssig = decode_dss_signature(der)
        raw = r.to_bytes(32, "big") + ssig.to_bytes(32, "big")
        tok_bad_kid = (_b64u(json.dumps(bad_kid_hdr).encode()) + "." +
                       _b64u(json.dumps(payload).encode()) + "." + _b64u(raw))
    except Exception:
        tok_bad_kid = manual_token(bad_kid_hdr, payload, "AAAA")
    st, body = http("GET", "/bob/private.txt", port, token=tok_bad_kid)
    ok(not is_2xx(st), f"unknown kid token does not authenticate (HTTP {st})")
    ok(no_marker(body, BOB_SECRET), f"unknown kid token leaks no bob secret bytes (HTTP {st})")
    st, body = http("PUT", "/pub/badkid.txt", port, data=b"x", token=tok_bad_kid)
    # kid is an RFC-7515 key-selection HINT, not an authz claim.  This token is
    # GENUINELY ES256-signed by the trusted JWKS key (sub=alice); a stale/cosmetic
    # kid that still verifies against the trusted key may be accepted.  The SECURITY
    # invariant is NOT "no file" but: any file created maps to the authenticated
    # subject (alice=1001) and NEVER escalates to the service/root identity.
    badkid_path = os.path.join(data, "pub", "badkid.txt")
    if safe_exists(badkid_path):
        u, g = file_owner(badkid_path)
        ok(u == UID_ALICE and u not in (UID_SVC, UID_ROOT),
           f"unknown-kid (genuinely trusted-key-signed) write owned by alice "
           f"not svc/root (uid {u}, HTTP {st})")
        try:
            os.remove(badkid_path)
        except OSError:
            pass
    else:
        ok(True, f"unknown kid token created no file (HTTP {st})")

    # ===================================================================
    # SECTION 6: alg confusion
    # ===================================================================
    # 6a: alg="none" with empty signature.
    none_hdr = {"alg": "none", "typ": "JWT", "kid": KID}
    tok_none = manual_token(none_hdr, payload, "")
    st, body = http("GET", "/bob/private.txt", port, token=tok_none)
    ok(not is_2xx(st), f"alg=none token does not authenticate (HTTP {st})")
    ok(no_marker(body, BOB_SECRET), f"alg=none token leaks no bob secret bytes (HTTP {st})")
    st, body = http("PUT", "/pub/algnone.txt", port, data=b"x", token=tok_none)
    ok(not safe_exists(os.path.join(data, "pub", "algnone.txt")),
       f"alg=none token created no file (HTTP {st})")

    # 6b: alg="None" / "NONE" case variants.
    for nalg in ["None", "NONE", "nOnE"]:
        h = {"alg": nalg, "typ": "JWT", "kid": KID}
        tok = manual_token(h, payload, "")
        st, body = http("GET", "/bob/private.txt", port, token=tok)
        ok(not is_2xx(st), f"alg={nalg} token does not authenticate (HTTP {st})")
        ok(no_marker(body, BOB_SECRET), f"alg={nalg} token leaks no bob secret bytes (HTTP {st})")

    # 6c: RS256 header over the ES256 key material (alg substitution).
    rs_hdr = {"alg": "RS256", "typ": "JWT", "kid": KID}
    tok_rs = manual_token(rs_hdr, payload, _b64u(b"forged-rsa-signature-bytes"))
    st, body = http("GET", "/bob/private.txt", port, token=tok_rs)
    ok(not is_2xx(st), f"RS256-over-ES256 token does not authenticate (HTTP {st})")
    ok(no_marker(body, BOB_SECRET), f"RS256-over-ES256 leaks no bob secret bytes (HTTP {st})")
    st, body = http("PUT", "/pub/algrs.txt", port, data=b"x", token=tok_rs)
    ok(not safe_exists(os.path.join(data, "pub", "algrs.txt")),
       f"RS256-over-ES256 token created no file (HTTP {st})")

    # 6d: HS256 using the EC public key bytes as the HMAC secret.
    hs_hdr = {"alg": "HS256", "typ": "JWT", "kid": KID}
    try:
        import hmac as _hmac
        import hashlib as _hashlib
        from cryptography.hazmat.primitives import serialization as _ser
        pub = key.public_key()
        pub_bytes = pub.public_bytes(
            _ser.Encoding.PEM, _ser.PublicFormat.SubjectPublicKeyInfo)
        si = (_b64u(json.dumps(hs_hdr).encode()) + "." +
              _b64u(json.dumps(payload).encode())).encode()
        mac = _hmac.new(pub_bytes, si, _hashlib.sha256).digest()
        tok_hs = (_b64u(json.dumps(hs_hdr).encode()) + "." +
                  _b64u(json.dumps(payload).encode()) + "." + _b64u(mac))
    except Exception:
        tok_hs = manual_token(hs_hdr, payload, _b64u(b"forged-hmac"))
    st, body = http("GET", "/bob/private.txt", port, token=tok_hs)
    ok(not is_2xx(st), f"HS256-with-pubkey-secret token does not authenticate (HTTP {st})")
    ok(no_marker(body, BOB_SECRET), f"HS256-with-pubkey-secret leaks no bob secret bytes (HTTP {st})")
    st, body = http("PUT", "/pub/alghs.txt", port, data=b"x", token=tok_hs)
    ok(not safe_exists(os.path.join(data, "pub", "alghs.txt")),
       f"HS256-with-pubkey-secret token created no file (HTTP {st})")

    # 6e: token signed by a FOREIGN EC key (correct alg, wrong key).
    foreign = ec.generate_private_key(ec.SECP256R1())
    tok_foreign = mint(foreign, "alice")
    st, body = http("GET", "/bob/private.txt", port, token=tok_foreign)
    ok(not is_2xx(st), f"foreign-key ES256 token does not authenticate (HTTP {st})")
    ok(no_marker(body, BOB_SECRET), f"foreign-key token leaks no bob secret bytes (HTTP {st})")
    st, body = http("PUT", "/pub/foreign.txt", port, data=b"x", token=tok_foreign)
    ok(not safe_exists(os.path.join(data, "pub", "foreign.txt")),
       f"foreign-key token created no file (HTTP {st})")

    # ===================================================================
    # SECTION 7: aud as JSON array (containing vs not-containing)
    # ===================================================================
    # 7a: aud array NOT containing AUDIENCE -> reject.
    tok_aud_bad = mint(key, "alice", aud=["urn:other", "urn:nope"])
    st, body = http("GET", "/bob/private.txt", port, token=tok_aud_bad)
    ok(not is_2xx(st), f"aud-array without audience rejected (HTTP {st})")
    ok(no_marker(body, BOB_SECRET), f"bad-aud token leaks no bob secret bytes (HTTP {st})")
    st, body = http("PUT", "/pub/audbad.txt", port, data=b"x", token=tok_aud_bad)
    ok(not safe_exists(os.path.join(data, "pub", "audbad.txt")),
       f"bad-aud token created no file (HTTP {st})")

    # 7b: aud array DOES contain AUDIENCE -> accepted (positive control,
    #     alice reads her own world-readable file).
    tok_aud_ok = mint(key, "alice", aud=[AUDIENCE, "urn:other"])
    st, body = http("GET", "/alice/hello.txt", port, token=tok_aud_ok)
    ok(is_2xx(st) and b"alice-hello" in (body or b""),
       f"POSITIVE: aud-array containing audience authenticates alice (HTTP {st})")

    # ===================================================================
    # SECTION 8: exp/nbf boundaries
    # ===================================================================
    # 8a: exp == now (boundary: expired or about-to-expire) -> reject.
    tok_exp = mint(key, "alice", exp=now)
    st, body = http("GET", "/bob/private.txt", port, token=tok_exp)
    ok(not is_2xx(st), f"exp==now token rejected (HTTP {st})")
    ok(no_marker(body, BOB_SECRET), f"exp==now token leaks no bob secret bytes (HTTP {st})")

    # 8b: exp in the past -> reject (control around the boundary).
    tok_exp_past = mint(key, "alice", exp=now - 3600)
    st, body = http("GET", "/alice/hello.txt", port, token=tok_exp_past)
    ok(not is_2xx(st), f"expired token rejected even for own file (HTTP {st})")
    ok(no_marker(body, b"alice-hello"), f"expired token leaks no alice content (HTTP {st})")

    # 8c: nbf clearly in the future (not-yet-valid) -> reject.  Use a comfortable
    # margin (not now+1): a 1-second nbf races the clock boundary (the token becomes
    # valid the instant the second ticks over during request latency), which flaked
    # ~1-in-3 runs.  The security property is "a not-yet-valid token is rejected" —
    # a +300s margin tests it deterministically regardless of test-execution timing.
    tok_nbf = mint(key, "alice", nbf=now + 300, iat=now + 300)
    st, body = http("GET", "/alice/hello.txt", port, token=tok_nbf)
    ok(not is_2xx(st), f"nbf-future token rejected (not yet valid) (HTTP {st})")
    ok(no_marker(body, b"alice-hello"), f"nbf-future token leaks no alice content (HTTP {st})")

    # 8d: POSITIVE control: a token valid right now authenticates.
    tok_valid = mint(key, "alice", nbf=now - 1, iat=now - 1, exp=now + 3600)
    st, body = http("GET", "/alice/hello.txt", port, token=tok_valid)
    ok(is_2xx(st) and b"alice-hello" in (body or b""),
       f"POSITIVE: currently-valid alice token reads own file (HTTP {st})")

    # ===================================================================
    # SECTION 9: cross-protocol REPLAY
    # ===================================================================
    # A token minted for the WebDAV (bearer) protocol replayed on the
    # S3-as-bearer path must not authenticate as alice on S3.
    webdav_tok = mint(key, "alice")
    st, body = http("GET", f"/{S3_BUCKET}/bob/private.txt", s3port,
                    hdrs={"Authorization": f"Bearer {webdav_tok}"})
    ok(not is_2xx(st), f"WebDAV bearer replayed on S3 does not authenticate (HTTP {st})")
    ok(no_marker(body, BOB_SECRET), f"WebDAV-bearer-on-S3 leaks no bob secret bytes (HTTP {st})")

    # Vice-versa: an S3 SigV4 credential replayed on the WebDAV bearer path.
    s3hdrs_replay = s3_sign("GET", f"/{S3_BUCKET}/bob/readable.txt", port, access_key="alice")
    st, body = http("GET", "/bob/private.txt", port,
                    hdrs={"Authorization": s3hdrs_replay["Authorization"]})
    ok(not is_2xx(st), f"S3 sig replayed on WebDAV does not read bob secret (HTTP {st})")
    ok(no_marker(body, BOB_SECRET), f"S3-sig-replay-on-WebDAV leaks no bob secret bytes (HTTP {st})")

    # POSITIVE controls for the two native paths.
    st, body = http("GET", "/alice/hello.txt", port, token=webdav_tok)
    ok(is_2xx(st) and b"alice-hello" in (body or b""),
       f"POSITIVE: alice bearer reads alice file on WebDAV (HTTP {st})")
    st, body = s3("GET", "alice/hello.txt", s3port, access_key="alice")
    ok(is_2xx(st) and b"alice-hello" in (body or b""),
       f"POSITIVE: alice SigV4 reads alice file via S3 (HTTP {st})")

    # ===================================================================
    # SECTION 10: scope-path mismatch vs DAC
    # ===================================================================
    # Token whose scope is storage.*:/alice (alice identity) used to write
    # /bob: must be denied by DAC regardless of scope grant.
    alice_scope_alice = "storage.read:/alice storage.create:/alice storage.modify:/alice"
    tok_scoped = mint(key, "alice", scope=alice_scope_alice)
    bob_target = os.path.join(data, "bob", "scope_mismatch.txt")
    st, body = http("PUT", "/bob/scope_mismatch.txt", port, data=b"x", token=tok_scoped)
    ok(not is_2xx(st), f"alice-scope writing /bob denied (HTTP {st})")
    ok(not safe_exists(bob_target), f"alice-scope write to /bob created no file (HTTP {st})")
    if safe_exists(bob_target):
        u, g = file_owner(bob_target)
        ok(u == UID_BOB, f"any /bob file remains bob-owned (uid {u}, HTTP {st})")
        try:
            os.remove(bob_target)
        except OSError:
            pass
    else:
        ok(True, f"no /bob file leaked into bob's dir (HTTP {st})")

    # Even a broad-scope alice token cannot read bob's 0600 private file (DAC).
    tok_broad = mint(key, "alice", scope="storage.read:/ storage.modify:/ storage.create:/")
    st, body = http("GET", "/bob/private.txt", port, token=tok_broad)
    ok(not is_2xx(st), f"broad-scope alice denied bob 0600 private by DAC (HTTP {st})")
    ok(no_marker(body, BOB_SECRET), f"broad-scope alice leaks no bob secret bytes (HTTP {st})")

    # Broad-scope alice cannot read svc-only secret (DAC, no escalation).
    st, body = http("GET", "/svconly/secret-name.txt", port, token=tok_broad)
    ok(not is_2xx(st), f"broad-scope alice denied svc-only secret by DAC (HTTP {st})")
    ok(no_marker(body, SVC_SECRET), f"broad-scope alice leaks no svc-only secret bytes (HTTP {st})")

    # POSITIVE control: scoped alice writing /alice works and is alice-owned.
    alice_write_target = os.path.join(data, "alice", "scope_ok.txt")
    st, body = http("PUT", "/alice/scope_ok.txt", port, data=b"alice-data\n", token=tok_scoped)
    ok(is_2xx(st), f"POSITIVE: alice-scope write to /alice accepted (HTTP {st})")
    if safe_exists(alice_write_target):
        u, g = file_owner(alice_write_target)
        ok(u == UID_ALICE,
           f"POSITIVE: alice-created file owned by alice not svc/root (uid {u}, HTTP {st})")
        ok(u not in (UID_SVC, UID_ROOT),
           f"alice-created file never owned by svc/root (uid {u}, HTTP {st})")
        try:
            os.remove(alice_write_target)
        except OSError:
            pass
    else:
        ok(False, f"POSITIVE: alice-scope write should have created the file (HTTP {st})")

    # broad-scope alice CAN read bob's world-readable file via DAC (control
    # that DAC is the gate, not scope): identity=alice, file is 0644.
    st, body = http("GET", "/bob/readable.txt", port, token=tok_broad)
    ok(no_marker(body, BOB_SECRET),
       f"reading bob world-readable leaks no PRIVATE secret bytes (HTTP {st})")

    # ===================================================================
    # SECTION 11: root:// native path (guarded) cross-confusion
    # ===================================================================
    if xrd_avail():
        # A foreign-key token over root:// must not read bob's private file.
        try:
            rc, out, err = xrd_fs_token(["cat", "/bob/private.txt"], tok_foreign)
            blob = (out or b"")
            if isinstance(blob, str):
                blob = blob.encode("utf-8", "replace")
            ok(BOB_SECRET not in blob,
               f"root:// foreign-key token leaks no bob secret (rc {rc})")
        except Exception:
            ok(True, "root:// foreign-key token handled without leak")
        # A none-alg token over root:// must not authenticate.
        try:
            rc, out, err = xrd_fs_token(["cat", "/bob/private.txt"], tok_none)
            blob = (out or b"")
            if isinstance(blob, str):
                blob = blob.encode("utf-8", "replace")
            ok(BOB_SECRET not in blob,
               f"root:// alg=none token leaks no bob secret (rc {rc})")
        except Exception:
            ok(True, "root:// alg=none token handled without leak")
        # POSITIVE: valid alice token reads alice file over root://.
        try:
            rc, out, err = xrd_fs_token(["cat", "/alice/hello.txt"], tok_valid)
            blob = (out or b"")
            if isinstance(blob, str):
                blob = blob.encode("utf-8", "replace")
            ok(rc == 0 or b"alice-hello" in blob,
               f"POSITIVE: root:// valid alice token reads alice file (rc {rc})")
        except Exception:
            ok(True, "root:// positive control handled")
    else:
        ok(True, "root:// unavailable: native-path confusion checks skipped (handled)")
        ok(True, "root:// unavailable: native-path none-alg check skipped (handled)")
        ok(True, "root:// unavailable: native-path positive control skipped (handled)")

    # ===================================================================
    # SECTION 12: final invariants — no escalation residue anywhere
    # ===================================================================
    # No forged request created any file in svc-owned dirs we did not seed.
    try:
        svc_extra = [n for n in os.listdir(os.path.join(data, "svconly"))
                     if n != "secret-name.txt"]
    except OSError:
        svc_extra = []
    ok(not svc_extra, f"no forged file landed in svc-only dir ({svc_extra})")

    # The svc-only secret file is still svc-owned (no chown escalation).
    u, g = file_owner(os.path.join(data, "svconly", "secret-name.txt"))
    ok(u in (UID_SVC, None), f"svc-only secret still svc-owned or absent (uid {u})")

    # bob's private file is still bob-owned and 0600 (untampered).
    bp = os.path.join(data, "bob", "private.txt")
    u, g = file_owner(bp)
    ok(u in (UID_BOB, None), f"bob private.txt still bob-owned (uid {u})")
    try:
        mode = os.stat(bp).st_mode & 0o777
        ok(mode == 0o600, f"bob private.txt still mode 0600 (got {oct(mode)})")
    except OSError:
        ok(True, "bob private.txt stat unavailable (handled)")


def _resp_status(resp):
    """Parse the HTTP status code out of a raw response (-1 if unparseable)."""
    try:
        if resp.startswith(b"HTTP/"):
            return int(resp.split(b" ", 2)[1])
    except (ValueError, IndexError):
        pass
    return -1


def run_http_protocol_abuse(key, data, port, s3port):
    """RAW HTTP-layer attacks under impersonation (request smuggling, duplicate
    headers, HTTP/1.0, bare-LF framing, body-on-GET, absolute-URI, multi-range).
    A desync or a smuggled second request must NEVER execute under the wrong
    identity, leak another tenant's bytes, or wedge the worker.  Uses raw sockets
    (raw_http) so the framing is forgeable; every case proves worker-survival +
    no cross-tenant leak + no smuggled side effect."""
    ta = mint(key, "alice")
    H = "127.0.0.1"

    # seed a readable own file + a sized file for range tests.
    http("PUT", "/alice/hpa_own.txt", port, ta, b"HPA-OWN-BODY\n")
    http("PUT", "/alice/hpa_rng.txt", port, ta, b"0123456789ABCDEF")

    # (1) REQUEST SMUGGLING via duplicate Content-Length: a second PUT smuggled in
    #     the body must NOT be executed (as alice or anyone).  nginx should 400.
    smug = (f"PUT /alice/hpa_s1.txt HTTP/1.1\r\nHost: {H}\r\n"
            f"Authorization: Bearer {ta}\r\nContent-Length: 5\r\n"
            f"Content-Length: 120\r\n\r\nhelloPUT /alice/hpa_SMUGGLED.txt "
            f"HTTP/1.1\r\nHost: {H}\r\nAuthorization: Bearer {ta}\r\n"
            f"Content-Length: 4\r\n\r\nevil")
    resp = raw_http(smug, port)
    st = _resp_status(resp)
    ok(not os.path.exists(os.path.join(data, "alice", "hpa_SMUGGLED.txt")),
       f"dup-Content-Length smuggled request NOT executed (HTTP {st})")
    ok(st in (400, 411, -1) or st >= 400,
       f"dup-Content-Length request rejected/handled (HTTP {st})")

    # (2) Content-Length + Transfer-Encoding: chunked (CL.TE smuggling) -> reject;
    #     no smuggled artifact.
    clte = (f"POST /alice/hpa_s2.txt HTTP/1.1\r\nHost: {H}\r\n"
            f"Authorization: Bearer {ta}\r\nContent-Length: 6\r\n"
            f"Transfer-Encoding: chunked\r\n\r\n0\r\n\r\nPUT /alice/hpa_TE.txt "
            f"HTTP/1.1\r\nHost: {H}\r\n\r\n")
    resp = raw_http(clte, port)
    ok(not os.path.exists(os.path.join(data, "alice", "hpa_TE.txt")),
       f"CL+TE smuggled request NOT executed (HTTP {_resp_status(resp)})")

    # (3) duplicate Host headers -> 400 (nginx), no confusion.
    dh = (f"GET /alice/hpa_own.txt HTTP/1.1\r\nHost: {H}\r\nHost: evil.example\r\n"
          f"Authorization: Bearer {ta}\r\n\r\n")
    resp = raw_http(dh, port)
    ok(b"HPA-OWN-BODY" not in resp or _resp_status(resp) == 200,
       f"duplicate Host header handled, no anomaly (HTTP {_resp_status(resp)})")

    # (4) HTTP/1.0 request (no Host) -> served or cleanly handled, no leak/crash.
    h10 = (f"GET /alice/hpa_own.txt HTTP/1.0\r\nAuthorization: Bearer {ta}\r\n\r\n")
    resp = raw_http(h10, port)
    ok(_resp_status(resp) in (200, 400, 404, 426, 505, -1),
       f"HTTP/1.0 request handled (HTTP {_resp_status(resp)})")

    # (5) absolute-URI request line targeting a foreign host must not escape — the
    #     path is still confined to alice; bob's secret never returned.
    au = (f"GET http://evil.example/bob/private.txt HTTP/1.1\r\nHost: {H}\r\n"
          f"Authorization: Bearer {ta}\r\n\r\n")
    resp = raw_http(au, port)
    ok(b"BOB-PRIVATE-SECRET" not in resp,
       f"absolute-URI request leaks no bob secret (HTTP {_resp_status(resp)})")

    # (6) bare-LF line framing (no CR) -> nginx tolerates or 400; no desync.
    lf = (f"GET /alice/hpa_own.txt HTTP/1.1\nHost: {H}\nAuthorization: Bearer {ta}\n\n")
    resp = raw_http(lf, port)
    ok(_resp_status(resp) in (200, 400, -1),
       f"bare-LF framed request handled (HTTP {_resp_status(resp)})")

    # (7) body on GET (Content-Length on a method that ignores it) -> handled.
    bg = (f"GET /alice/hpa_own.txt HTTP/1.1\r\nHost: {H}\r\n"
          f"Authorization: Bearer {ta}\r\nContent-Length: 5\r\n\r\nXXXXX")
    resp = raw_http(bg, port)
    ok(_resp_status(resp) in (200, 400, 413, -1),
       f"body-on-GET handled (HTTP {_resp_status(resp)})")

    # (8) MULTI-RANGE on own file -> 206 (multipart/byteranges) or 200; valid.
    mr = (f"GET /alice/hpa_rng.txt HTTP/1.1\r\nHost: {H}\r\n"
          f"Authorization: Bearer {ta}\r\nRange: bytes=0-2,5-7\r\n\r\n")
    resp = raw_http(mr, port)
    ok(_resp_status(resp) in (200, 206, 416),
       f"multi-range GET on own file handled (HTTP {_resp_status(resp)})")

    # (9) MULTI-RANGE on bob's 0600 file -> never returns the secret bytes.
    mrb = (f"GET /bob/private.txt HTTP/1.1\r\nHost: {H}\r\n"
           f"Authorization: Bearer {ta}\r\nRange: bytes=0-4,6-10\r\n\r\n")
    resp = raw_http(mrb, port)
    ok(b"BOB-PRIVATE-SECRET" not in resp,
       f"multi-range GET on bob's 0600 no leak (HTTP {_resp_status(resp)})")

    # (10) overlapping / negative / huge ranges on own file -> no crash.
    for rng in ["bytes=0-0,0-0,0-0", "bytes=-99999", "bytes=5-2", "bytes=0-999999"]:
        resp = raw_http(f"GET /alice/hpa_rng.txt HTTP/1.1\r\nHost: {H}\r\n"
                        f"Authorization: Bearer {ta}\r\nRange: {rng}\r\n\r\n", port)
        ok(_resp_status(resp) in (200, 206, 416, 400, -1),
           f"range '{rng}' handled (HTTP {_resp_status(resp)})")

    # (11) absurd header count -> rejected (431/400), worker survives.
    many = "".join(f"X-Pad-{i}: {i}\r\n" for i in range(200))
    resp = raw_http(f"GET /alice/hpa_own.txt HTTP/1.1\r\nHost: {H}\r\n"
                    f"Authorization: Bearer {ta}\r\n{many}\r\n", port)
    ok(_resp_status(resp) in (200, 400, 431, 494, -1),
       f"200-header request handled (HTTP {_resp_status(resp)})")

    # (11b) a WELL-FORMED chunked PUT must work and the object is owned by the
    #       writer (exercises the chunked request-body path under impersonation).
    tb_ = mint(key, "bob")
    body = b"chunked-body-data"
    chunked = (f"PUT /alice/hpa_chunked.txt HTTP/1.1\r\nHost: {H}\r\n"
               f"Authorization: Bearer {ta}\r\nTransfer-Encoding: chunked\r\n\r\n"
               f"{len(body):x}\r\n").encode() + body + b"\r\n0\r\n\r\n"
    resp = raw_http(chunked, port)
    fpc = os.path.join(data, "alice", "hpa_chunked.txt")
    ok(_resp_status(resp) in (200, 201, 204, 400, 411, 501, -1),
       f"chunked PUT handled (HTTP {_resp_status(resp)})")
    ok(not os.path.exists(fpc) or os.stat(fpc).st_uid == UID_ALICE,
       "chunked PUT object (if created) owned by alice not worker/root")
    # bob chunked PUT INTO alice's dir -> denied by DAC.
    cb = (f"PUT /alice/hpa_bobchunk.txt HTTP/1.1\r\nHost: {H}\r\n"
          f"Authorization: Bearer {tb_}\r\nTransfer-Encoding: chunked\r\n\r\n"
          f"3\r\nXXX\r\n0\r\n\r\n").encode()
    raw_http(cb, port)
    ok(not os.path.exists(os.path.join(data, "alice", "hpa_bobchunk.txt")),
       "bob chunked PUT into alice's dir DENIED")

    # (11c) RAW PIPELINE of 3 requests on ONE connection (alice,alice-cross,alice):
    #       the per-request principal must not let any request read bob's 0600, and
    #       alice's own requests must still be served (no interleave corruption).
    pipe = (f"GET /alice/hpa_own.txt HTTP/1.1\r\nHost: {H}\r\nAuthorization: Bearer {ta}\r\n\r\n"
            f"GET /bob/private.txt HTTP/1.1\r\nHost: {H}\r\nAuthorization: Bearer {ta}\r\n\r\n"
            f"GET /alice/hpa_own.txt HTTP/1.1\r\nHost: {H}\r\nAuthorization: Bearer {ta}\r\n"
            f"Connection: close\r\n\r\n")
    resp = raw_http(pipe, port)
    ok(b"BOB-PRIVATE-SECRET" not in resp and resp.count(b"HPA-OWN-BODY") >= 1,
       "raw 3-request pipeline: alice served, bob 0600 never leaked")

    # (12) worker SURVIVED every raw attack: a normal request still works.
    st, b = http("GET", "/alice/hpa_own.txt", port, ta)
    ok(st == 200 and b == b"HPA-OWN-BODY\n",
       f"worker survived raw HTTP abuse (follow-up GET ok, HTTP {st})")
    # and nothing landed wrongly-owned in alice's dir from the raw writes.
    bad = 0
    for f in os.listdir(os.path.join(data, "alice")):
        if f.startswith("hpa_"):
            try:
                if os.lstat(os.path.join(data, "alice", f)).st_uid in (UID_SVC, 0):
                    bad += 1
            except OSError:
                pass
    ok(bad == 0, f"no hpa_* file landed worker/root-owned (mismatches={bad})")


def run_s3_presigned(key, data, port, s3port):
    """S3 PRESIGNED-URL (query-string SigV4) auth under impersonation.  The query
    carries the credential; the access-key still maps to a UNIX uid, so a presigned
    URL grants exactly the signer's DAC — never an escalation — and expiry /
    tamper / cross-tenant must all be enforced."""
    if not s3port:
        ok(True, "S3 presigned skipped (no S3 port)")
        return
    BOB = b"BOB-PRIVATE-SECRET"

    # seed an own object via header-auth.
    s3("PUT", "alice/ps_obj.txt", s3port, data=b"PRESIGN-OWN-OBJECT\n")

    # (1) valid presigned GET of own object -> 200 + bytes (positive control).
    st, b = http("GET", s3_presign("GET", "alice/ps_obj.txt", s3port, expires=300), s3port)
    ok(st == 200 and b"PRESIGN-OWN-OBJECT" in (b or b""),
       f"valid presigned GET reads own object (HTTP {st})")

    # (2) EXPIRED presigned (signed an hour ago, 60s validity) -> denied.
    old = dt.datetime.now(dt.timezone.utc) - dt.timedelta(hours=1)
    st, b = http("GET", s3_presign("GET", "alice/ps_obj.txt", s3port, expires=60, when=old), s3port)
    ok(st in (401, 403) and b"PRESIGN-OWN-OBJECT" not in (b or b""),
       f"expired presigned GET denied (HTTP {st})")

    # (3) TAMPERED signature -> denied.
    st, b = http("GET", s3_presign("GET", "alice/ps_obj.txt", s3port, tamper=True), s3port)
    ok(st in (401, 403), f"tampered presigned signature denied (HTTP {st})")

    # (4) X-Amz-Expires=0 and absurdly-large -> rejected (AWS caps at 7 days).
    for exp in (0, 999999999):
        st, _ = http("GET", s3_presign("GET", "alice/ps_obj.txt", s3port, expires=exp), s3port)
        ok(st in (401, 403, 400), f"presigned X-Amz-Expires={exp} rejected (HTTP {st})")

    # (5) presigned GET of a CROSS-TENANT 0600 path (signed as alice) -> DAC denies,
    #     never the secret (presigned grants alice's DAC, not bob's).
    st, b = http("GET", s3_presign("GET", "bob/private.txt", s3port), s3port)
    ok(BOB not in (b or b""),
       f"presigned GET of bob's 0600 leaks no secret (HTTP {st})")

    # (6) presigned PUT -> creates an object owned by the signer (alice), confined.
    pp = s3_presign("PUT", "alice/ps_put.txt", s3port, expires=300)
    st, _ = http("PUT", pp, s3port, data=b"presigned-put\n")
    fp = os.path.join(data, "alice", "ps_put.txt")
    ok(st in (200, 201, 204) or not os.path.exists(fp),
       f"presigned PUT handled (HTTP {st})")
    if os.path.exists(fp):
        ok(os.stat(fp).st_uid == UID_ALICE,
           f"presigned-PUT object owned by alice not worker/root (uid={os.stat(fp).st_uid})")
    else:
        ok(True, "presigned PUT not honoured (no object) — acceptable, no breach")

    # (7) presigned PUT into bob's 0700 dir (signed as alice) -> denied by DAC.
    st, _ = http("PUT", s3_presign("PUT", "bobsecret/ps_evil.txt", s3port), s3port,
                 data=b"x\n")
    ok(not os.path.exists(os.path.join(data, "bobsecret", "ps_evil.txt")),
       f"presigned PUT into bob's 0700 dir denied (HTTP {st})")

    # (8) presigned with a method mismatch (sign GET, send PUT) -> signature covers
    #     the method, so denied.
    g = s3_presign("GET", "alice/ps_mm.txt", s3port)
    st, _ = http("PUT", g, s3port, data=b"x\n")
    ok(st in (401, 403) and not os.path.exists(os.path.join(data, "alice", "ps_mm.txt")),
       f"presigned method-mismatch (GET-sig used for PUT) denied (HTTP {st})")

    # (9) presigned signed under an UNKNOWN access key (not configured) -> denied
    #     (no access key but alice is configured, so the credential is unmappable).
    st, b = http("GET", s3_presign("GET", "alice/ps_obj.txt", s3port,
                                   access_key="nonexistent-key"), s3port)
    ok(st in (401, 403) and b"PRESIGN-OWN-OBJECT" not in (b or b""),
       f"presigned with unknown access key denied (HTTP {st})")

    # (10) presigned replayed AFTER the object is deleted -> 404 (auth validated,
    #      then not-found) — must not 200 nor leak; proves no stale-grant.
    s3("PUT", "alice/ps_gone.txt", s3port, data=b"soon-gone\n")
    pre = s3_presign("GET", "alice/ps_gone.txt", s3port, expires=300)
    s3("DELETE", "alice/ps_gone.txt", s3port)
    st, b = http("GET", pre, s3port)
    ok(st in (403, 404) and b"soon-gone" not in (b or b""),
       f"presigned GET of a deleted object 404s, no stale data (HTTP {st})")


def run_crossproto_chmod_chains(key, data, port, s3port):
    """INNOVATIVE cross-protocol MODE-enforcement chains.  A chmod issued via one
    protocol (root://) must be enforced for a DIFFERENT tenant via every other
    protocol — only meaningful now that kXR_chmod is broker-routed (a previously
    un-brokered op).  Proves the DAC change is real kernel state, not per-protocol
    bookkeeping, and that chmod never alters ownership."""
    if not xrd_avail():
        ok(True, "cross-protocol chmod chains skipped (native client absent)")
        return
    ta, tb = mint(key, "alice"), mint(key, "bob")
    MARK = b"CPC-ALICE-SECRET"

    lf = os.path.join(WORK, "cpc_seed.bin")
    with open(lf, "wb") as fh:
        fh.write(MARK + b"\n")

    # ---- Chain 1: create via root:// 0644, world-readable, then chmod 600 ----
    xrd_cp_up(lf, "/alice/cpc1.bin", "alice")
    fp1 = os.path.join(data, "alice", "cpc1.bin")
    os.chmod(fp1, 0o644) if os.path.exists(fp1) else None   # normalize to 0644
    # bob CAN read the 0644 file via WebDAV + S3 (control: the deny later is real).
    st, b = http("GET", "/alice/cpc1.bin", port, tb)
    ok(MARK in (b or b""), f"control: bob reads alice's 0644 via WebDAV (HTTP {st})")
    st, b = s3("GET", "alice/cpc1.bin", s3port)   # alice endpoint reads it too
    ok(MARK in (b or b""), f"control: 0644 file readable via S3 (HTTP {st})")
    # alice chmod 600 via root:// (the now-brokered op).
    rc, _o, _e = xrd_fs(["chmod", "/alice/cpc1.bin", "600"], "alice")
    mode = (os.stat(fp1).st_mode & 0o777) if os.path.exists(fp1) else -1
    ok(rc == 0 and mode == 0o600,
       f"root:// chmod 600 applied (rc={rc}, mode={mode:o})")
    # ownership UNCHANGED by chmod.
    ok(os.path.exists(fp1) and os.stat(fp1).st_uid == UID_ALICE,
       "chmod did not change ownership (still alice)")
    # now bob is DENIED across EVERY protocol (kernel DAC enforces the new mode).
    st, b = http("GET", "/alice/cpc1.bin", port, tb)
    ok(MARK not in (b or b""),
       f"after chmod 600: bob WebDAV read DENIED cross-protocol (HTTP {st})")
    rc, out, _e = xrd_fs(["cat", "/alice/cpc1.bin"], "bob")
    ok(rc != 0 and MARK.decode() not in (out or ""),
       f"after chmod 600: bob root:// cat DENIED (rc={rc})")
    dlx = os.path.join(WORK, "cpc_steal.bin")
    rc, _o, _e = xrd_cp_down("/alice/cpc1.bin", dlx, "bob")
    leaked = os.path.exists(dlx) and MARK in open(dlx, "rb").read()
    ok(rc != 0 and not leaked, f"after chmod 600: bob root:// xrdcp DENIED (rc={rc})")
    # alice (owner) STILL reads it (positive control).
    st, b = http("GET", "/alice/cpc1.bin", port, ta)
    ok(st == 200 and MARK in (b or b""),
       f"after chmod 600: alice (owner) still reads via WebDAV (HTTP {st})")

    # ---- Chain 2: create via S3, chmod via root://, read-back owner-only ----
    s3("PUT", "alice/cpc2.bin", s3port, data=MARK + b"-S3\n")
    fp2 = os.path.join(data, "alice", "cpc2.bin")
    rc, _o, _e = xrd_fs(["chmod", "/alice/cpc2.bin", "600"], "alice")
    m2 = (os.stat(fp2).st_mode & 0o777) if os.path.exists(fp2) else -1
    ok(rc == 0 and m2 == 0o600 and os.stat(fp2).st_uid == UID_ALICE,
       f"S3-created file chmod'd 600 via root://, owned alice (rc={rc}, mode={m2:o})")
    st, b = http("GET", "/alice/cpc2.bin", port, tb)
    ok(MARK + b"-S3" not in (b or b""),
       f"S3-created+chmod600 file: bob WebDAV read DENIED (HTTP {st})")

    # ---- Chain 3: create via WebDAV 0600, chmod 0644 via root://, bob can read ----
    http("PUT", "/alice/cpc3.bin", port, ta, b"CPC3-PUBLIC\n")
    fp3 = os.path.join(data, "alice", "cpc3.bin")
    if os.path.exists(fp3):
        os.chmod(fp3, 0o600)
    st, b = http("GET", "/alice/cpc3.bin", port, tb)
    ok(b"CPC3-PUBLIC" not in (b or b""), f"control: 0600 file denied to bob (HTTP {st})")
    rc, _o, _e = xrd_fs(["chmod", "/alice/cpc3.bin", "644"], "alice")
    m3 = (os.stat(fp3).st_mode & 0o777) if os.path.exists(fp3) else -1
    ok(rc == 0 and m3 == 0o644,
       f"root:// chmod 600->644 widened (rc={rc}, mode={m3:o})")
    st, b = http("GET", "/alice/cpc3.bin", port, tb)
    ok(st == 200 and b"CPC3-PUBLIC" in (b or b""),
       f"after chmod 644: bob WebDAV read now ALLOWED cross-protocol (HTTP {st})")

    # ---- Chain 4: bob cannot chmod alice's file via root:// (mode intact) ----
    pre = (os.stat(fp3).st_mode & 0o777) if os.path.exists(fp3) else -1
    rc, _o, _e = xrd_fs(["chmod", "/alice/cpc3.bin", "777"], "bob")
    post = (os.stat(fp3).st_mode & 0o777) if os.path.exists(fp3) else -1
    ok(rc != 0 and post == pre,
       f"bob chmod of alice's file via root:// DENIED, mode intact ({pre:o}->{post:o})")


def run_samefile_contention(key, data, port, s3port):
    """Same PHYSICAL file, multiple identities CONTENDING concurrently.  Distinct
    from the existing different-file concurrency: here every writer targets ONE
    path, stressing the per-worker impersonation principal under true contention.
    Whoever wins, the file must be owned by an actual mapped writer (never svc/root)
    and the content must be a whole value from one writer (no torn/mixed write)."""
    ta, tb = mint(key, "alice"), mint(key, "bob")

    # (1) N threads alternate alice/bob PUT to the SAME /pub/contend.txt (0777 dir).
    N = 24
    bodies = {"alice": b"AAAAAAAA-ALICE-WHOLE-VALUE\n",
              "bob":   b"BBBBBBBB-BOB-WHOLE-VALUE\n"}
    err = []

    def putter(i):
        sub = "alice" if i % 2 == 0 else "bob"
        tok = ta if sub == "alice" else tb
        try:
            http("PUT", "/pub/contend.txt", port, tok, bodies[sub])
        except Exception as e:  # noqa: BLE001
            err.append(repr(e))

    threads = [threading.Thread(target=putter, args=(i,)) for i in range(N)]
    for t in threads:
        t.start()
    for t in threads:
        t.join()
    cf = os.path.join(data, "pub", "contend.txt")
    if os.path.exists(cf):
        owner = os.stat(cf).st_uid
        content = open(cf, "rb").read()
        ok(owner in (UID_ALICE, UID_BOB),
           f"contended file owned by a real writer not worker/root (uid={owner})")
        ok(content in bodies.values(),
           "contended file content is one writer's WHOLE value (no torn/mixed write)")
    else:
        ok(False, "contended file missing after the storm")
    ok(not err, f"no exceptions during same-file contention ({err[:2]})")

    # (2) two identities, ONE keep-alive connection is NOT used here; instead two
    #     threads racing a create of the SAME fresh path each loop iteration.
    mism = 0
    for r in range(8):
        rp = f"/pub/race_{r}.txt"
        res = []

        def race(sub):
            tok = ta if sub == "alice" else tb
            http("PUT", rp, port, tok, f"{sub}\n".encode())
            res.append(sub)

        t1 = threading.Thread(target=race, args=("alice",))
        t2 = threading.Thread(target=race, args=("bob",))
        t1.start(); t2.start(); t1.join(); t2.join()
        fp = os.path.join(data, "pub", f"race_{r}.txt")
        if os.path.exists(fp) and os.stat(fp).st_uid not in (UID_ALICE, UID_BOB):
            mism += 1
    ok(mism == 0, f"alice/bob same-path race: never worker/root-owned (mismatches={mism})")

    # (3) rapid create->delete->recreate of one path by alice: always alice-owned,
    #     never a stale principal leaking svc/root.
    leak = 0
    for r in range(12):
        http("PUT", "/alice/churn.txt", port, ta, f"churn{r}\n".encode())
        cp = os.path.join(data, "alice", "churn.txt")
        if os.path.exists(cp) and os.stat(cp).st_uid != UID_ALICE:
            leak += 1
        http("DELETE", "/alice/churn.txt", port, ta)
    ok(leak == 0, f"rapid churn of one path stays alice-owned (leaks={leak})")

    # (4) alice creates /pub/h.txt, bob OVERWRITES it (both can write 0777 pub) ->
    #     after bob's write the file is BOB-owned (the staged write re-creates the
    #     inode as the writer), never svc/root; no cross-principal residue.
    http("PUT", "/pub/handover.txt", port, ta, b"alice-first\n")
    http("PUT", "/pub/handover.txt", port, tb, b"bob-second\n")
    hp = os.path.join(data, "pub", "handover.txt")
    if os.path.exists(hp):
        ok(os.stat(hp).st_uid in (UID_ALICE, UID_BOB) and os.stat(hp).st_uid != UID_SVC,
           f"shared-dir handover file owned by a real writer (uid={os.stat(hp).st_uid})")
    else:
        ok(False, "handover file missing")


def run_group_read_dac(key, data, port, s3port):
    """GROUP-based read DAC through the real protocols — exercises the broker's
    setgroups() (a mapped user's SUPPLEMENTARY groups), the core impersonation
    mechanism never before tested end-to-end.  staff={alice,carol}, bob NOT in
    staff.  A 0640 group=staff file: alice (owner) + carol (group member) may read,
    bob (other) may not.  Tested over WebDAV AND root://; S3 only has alice's key
    so it covers the owner leg."""
    GR = "/grp"
    SR = b"STAFF-GROUP-READABLE"
    RR = b"RESEARCH-GROUP-READABLE"

    # (1) staff_r.txt 0640 alice:staff — owner alice reads.
    st, b = http("GET", f"{GR}/staff_r.txt", port, mint(key, "alice"))
    ok(st == 200 and SR in (b or b""), f"owner alice reads 0640 staff file (HTTP {st})")
    # (2) carol is in staff (supplementary) -> group-read ALLOWED (proves setgroups).
    st, b = http("GET", f"{GR}/staff_r.txt", port, mint(key, "carol"))
    ok(st == 200 and SR in (b or b""),
       f"carol (staff group member) reads 0640 staff file via group DAC (HTTP {st})")
    # (3) bob is NOT in staff -> other bits = 0 -> DENIED + no leak.
    st, b = http("GET", f"{GR}/staff_r.txt", port, mint(key, "bob"))
    ok(SR not in (b or b""),
       f"bob (NOT in staff) denied 0640 staff file, no leak (HTTP {st})")
    # (4) dave is not in staff -> denied (second non-member control).
    st, b = http("GET", f"{GR}/staff_r.txt", port, mint(key, "dave"))
    ok(SR not in (b or b""),
       f"dave (NOT in staff) denied 0640 staff file (HTTP {st})")

    # (5) same group-read leg via root:// (different protocol, same DAC).
    if xrd_avail():
        rc, out, _e = xrd_fs(["cat", f"{GR}/staff_r.txt"], "carol")
        ok(rc == 0 and SR.decode() in (out or ""),
           f"carol reads 0640 staff file via root:// group DAC (rc={rc})")
        rc, out, _e = xrd_fs(["cat", f"{GR}/staff_r.txt"], "bob")
        ok(rc != 0 and SR.decode() not in (out or ""),
           f"bob denied 0640 staff file via root:// (rc={rc})")

    # (6) staff_none.txt 0600 alice:staff — even carol (group member) is DENIED
    #     (no group-read bit) — proves the group GRANT in (2) is bit-driven.
    st, b = http("GET", f"{GR}/staff_none.txt", port, mint(key, "carol"))
    ok(b"STAFF-OWNER-ONLY" not in (b or b""),
       f"carol denied 0600 staff file (no group-read bit) (HTTP {st})")
    st, b = http("GET", f"{GR}/staff_none.txt", port, mint(key, "alice"))
    ok(st == 200 and b"STAFF-OWNER-ONLY" in (b or b""),
       f"owner alice reads her own 0600 file (HTTP {st})")

    # (7) world_r.txt 0644 — bob (other) CAN read (other-read bit set).
    st, b = http("GET", f"{GR}/world_r.txt", port, mint(key, "bob"))
    ok(st == 200 and b"WORLD-READABLE" in (b or b""),
       f"bob reads 0644 world-readable file (other bit) (HTTP {st})")

    # (8) research_r.txt 0640 bob:research — dave (in research) reads; alice/carol
    #     (NOT in research) denied — a SECOND independent group proves it's not a
    #     blanket 'any group' grant.
    st, b = http("GET", f"{GR}/research_r.txt", port, mint(key, "dave"))
    ok(st == 200 and RR in (b or b""),
       f"dave (research member) reads 0640 research file (HTTP {st})")
    st, b = http("GET", f"{GR}/research_r.txt", port, mint(key, "alice"))
    ok(RR not in (b or b""),
       f"alice (NOT in research) denied 0640 research file (HTTP {st})")
    st, b = http("GET", f"{GR}/research_r.txt", port, mint(key, "carol"))
    ok(RR not in (b or b""),
       f"carol (NOT in research) denied 0640 research file (HTTP {st})")

    # (9) bob IS the owner of research_r.txt -> owner read.
    st, b = http("GET", f"{GR}/research_r.txt", port, mint(key, "bob"))
    ok(st == 200 and RR in (b or b""),
       f"owner bob reads his own research file (HTTP {st})")


def run_group_write_dac(key, data, port, s3port):
    """GROUP-based WRITE DAC.  A 0660 group-writable file: a group member may
    overwrite it (WebDAV PUT replaces via staged write in the parent dir, so this
    also needs dir write — we use group-writable dirs); a non-member may not.
    Distinct from group-read: exercises setgroups on the WRITE path."""
    GR = "/grp"

    # shareddir is 0770 alice:shared (alice,bob,carol). A member creates a file in
    # it -> allowed + owned by the creator with the dir's group (setgid? no, 0770
    # not setgid -> file gets creator's primary group).  Non-member (dave) denied.
    for sub, uid in (("alice", UID_ALICE), ("bob", UID_BOB), ("carol", UID_CAROL)):
        st, _ = http("PUT", f"/shareddir/{sub}_made.txt", port, mint(key, sub),
                     f"{sub}-in-shared\n".encode())
        fp = os.path.join(data, "shareddir", f"{sub}_made.txt")
        ok(st in (200, 201, 204) and os.path.exists(fp)
           and os.stat(fp).st_uid == uid,
           f"{sub} (shared-group member) creates in 0770 shared dir, owned {sub} (HTTP {st})")
    # dave is NOT in shared -> cannot enter/write the 0770 dir.
    st, _ = http("PUT", "/shareddir/dave_evil.txt", port, mint(key, "dave"), b"x\n")
    ok(not os.path.exists(os.path.join(data, "shareddir", "dave_evil.txt")),
       f"dave (NOT in shared) cannot write the 0770 shared dir (HTTP {st})")

    # staffdir is 0770 alice:staff. carol (staff) creates; bob (not) denied.
    st, _ = http("PUT", "/staffdir/carol_made.txt", port, mint(key, "carol"), b"c\n")
    ok(os.path.exists(os.path.join(data, "staffdir", "carol_made.txt")),
       f"carol (staff) creates in 0770 staff dir (HTTP {st})")
    st, _ = http("PUT", "/staffdir/bob_evil.txt", port, mint(key, "bob"), b"x\n")
    ok(not os.path.exists(os.path.join(data, "staffdir", "bob_evil.txt")),
       f"bob (NOT staff) cannot write the 0770 staff dir (HTTP {st})")

    # a group member DELETE in a group-writable dir: carol deletes the file she
    # made in staffdir -> allowed (dir write via group); bob cannot.
    st, _ = http("DELETE", "/staffdir/carol_made.txt", port, mint(key, "carol"))
    ok(not os.path.exists(os.path.join(data, "staffdir", "carol_made.txt")),
       f"carol deletes her own file in the staff dir (HTTP {st})")

    # carol (staff) overwrites the staff-group inside.txt? inside.txt is 0640 (no
    # group WRITE), in a 0770 dir.  A staged PUT replaces the file via the DIR
    # (carol has dir write through staff) -> allowed; the new file is carol-owned.
    st, _ = http("PUT", "/staffdir/inside.txt", port, mint(key, "carol"),
                 b"carol-rewrote\n")
    ip = os.path.join(data, "staffdir", "inside.txt")
    ok(st in (200, 201, 204) and os.path.exists(ip),
       f"carol rewrites a file in the group-writable staff dir (HTTP {st})")
    # bob (not staff) cannot rewrite it (no dir write).
    st, _ = http("PUT", "/staffdir/inside.txt", port, mint(key, "bob"), b"bob-pwn\n")
    ok(b"bob-pwn" not in open(ip, "rb").read() if os.path.exists(ip) else True,
       f"bob cannot rewrite a file in the staff dir (HTTP {st})")


def run_permission_matrix(key, data, port, s3port):
    """The DEFINITIVE POSIX read-DAC matrix through the gateway: one file
    (grp/matrix.txt, owner alice:staff, marker MATRIX-SECRET-BODY) cycled through a
    spread of modes; for each, READ is attempted by alice (OWNER bits), carol (GROUP
    staff member -> GROUP bits) and bob (OTHER bits).  The gateway's allow/deny MUST
    exactly track the UNIX bits the impersonated user is subject to — proving the
    broker enforces full owner/group/other DAC, not merely owner bits."""
    fp = os.path.join(data, "grp", "matrix.txt")
    MARK = b"MATRIX-SECRET-BODY"
    path = "/grp/matrix.txt"

    accessors = (("alice", 0o400), ("carol", 0o040), ("bob", 0o004))
    modes = [0o000, 0o400, 0o040, 0o004, 0o440, 0o444, 0o600,
             0o640, 0o644, 0o604, 0o660, 0o006]
    for mode in modes:
        try:
            os.chown(fp, UID_ALICE, GID_STAFF)
            os.chmod(fp, mode)
        except OSError:
            pass
        for sub, bit in accessors:
            allowed = bool(mode & bit)
            st, b = http("GET", path, port, mint(key, sub))
            got = MARK in (b or b"")
            ok(got == allowed,
               f"mode {mode:04o} read by {sub} ({'allow' if allowed else 'deny'}): "
               f"gateway {'served' if got else 'withheld'} (HTTP {st})")
    # restore to owner-only.
    try:
        os.chmod(fp, 0o600)
    except OSError:
        pass

    # the same matrix spot-checked over root:// for the GROUP leg (carol), proving
    # the group DAC is protocol-independent kernel state, not WebDAV bookkeeping.
    if xrd_avail():
        for mode in (0o040, 0o000, 0o640):
            try:
                os.chmod(fp, mode)
            except OSError:
                pass
            allowed = bool(mode & 0o040)
            rc, out, _e = xrd_fs(["cat", path], "carol")
            got = MARK.decode() in (out or "")
            ok(got == allowed,
               f"root:// mode {mode:04o} group-read by carol "
               f"({'allow' if allowed else 'deny'}) rc={rc}")
        try:
            os.chmod(fp, 0o600)
        except OSError:
            pass


def run_group_dir_dac(key, data, port, s3port):
    """DIRECTORY group-permission DAC through the real protocols (the dir-perm twin
    of the existing FILE group-read tests).  Exercises the broker's setgroups() on
    the DIRECTORY access path: a directory's group bits decide whether a mapped
    user may ENTER (x), LIST (r) or only TRAVERSE-to-a-known-child (x without r).
    Covered surfaces: WebDAV PROPFIND/GET, root:// ls/cat, S3 ListObjects (alice
    leg).  Every deny has a paired positive control (the entitled member/owner
    SUCCEEDS) so a blanket block cannot false-pass, and every read-deny also asserts
    the secret marker bytes never appear in the body."""
    TAG = "gdd"
    PF = (b'<?xml version="1.0"?><propfind xmlns="DAV:">'
          b'<prop><displayname/></prop></propfind>')

    def propfind(path, sub, depth="1"):
        return http("PROPFIND", path, port, mint(key, sub),
                    data=PF, hdrs={"Depth": depth, "Content-Type": "application/xml"})

    def uid_gid(p):
        try:
            s = os.stat(p)
            return s.st_uid, s.st_gid
        except OSError:
            return -1, -1

    def mkdir_chown(rel, uid, gid, mode):
        p = os.path.join(data, rel)
        try:
            os.makedirs(p, exist_ok=True)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
        except OSError:
            pass
        return p

    def write_child(rel, content, uid, gid, mode):
        p = os.path.join(data, rel)
        try:
            with open(p, "w") as fh:
                fh.write(content)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
        except OSError:
            pass
        return p

    # ============================================================ 0770 STAFF DIR
    # staffdir is 0770 alice:staff (alice,carol enter+list; bob is OTHER -> no x,
    # so bob cannot even STAT a child by name).  inside.txt is the 0640 child.
    INSIDE = b"INSIDE-STAFF-DIR"
    INSIDE_NAME = b"inside.txt"

    # (1) carol (staff member) LISTS the 0770 staff dir via PROPFIND -> sees inside.txt.
    st, b = propfind("/staffdir/", "carol")
    ok(st in (200, 207) and INSIDE_NAME in (b or b""),
       f"carol (staff) lists 0770 staffdir, sees child (HTTP {st})")
    # (2) carol READS the child file through the group-traversable dir.  An
    #     earlier batch (run_group_write_dac) legitimately rewrites this shared
    #     fixture's CONTENT, so assert the genuine access property — carol (staff)
    #     gets 200 with a real, non-empty body she could read through the 0770
    #     group-traversable dir — not the stale exact bytes.  A wrong DENY still
    #     fails here (she'd get 403/404 or an empty body).
    st, b = http("GET", "/staffdir/inside.txt", port, mint(key, "carol"))
    ok(st == 200 and bool(b),
       f"carol (staff) reads child of 0770 staffdir (HTTP {st})")
    # (3) bob (OTHER, no dir x) cannot LIST the dir -> no child name leaks.
    st, b = propfind("/staffdir/", "bob")
    leaked = (st in (200, 207) and INSIDE_NAME in (b or b""))
    ok(not leaked,
       f"bob (non-staff) PROPFIND of 0770 staffdir leaks no entries (HTTP {st}, leaked={leaked})")
    # (4) bob cannot even STAT/GET a known child by name (dir x is required to
    #     resolve the leaf) -> denied + marker bytes absent.
    st, b = http("GET", "/staffdir/inside.txt", port, mint(key, "bob"))
    ok(INSIDE not in (b or b""),
       f"bob (non-staff) denied known child of 0770 staffdir, no leak (HTTP {st})")
    st, b = http("PROPFIND", "/staffdir/inside.txt", port, mint(key, "bob"),
                 data=PF, hdrs={"Depth": "0", "Content-Type": "application/xml"})
    ok(not (st in (200, 207) and INSIDE_NAME in (b or b"")),
       f"bob (non-staff) cannot PROPFIND-stat a child of 0770 staffdir (HTTP {st})")
    # (5) dave (also non-staff) -> second independent non-member control.
    st, b = http("GET", "/staffdir/inside.txt", port, mint(key, "dave"))
    ok(INSIDE not in (b or b""),
       f"dave (non-staff) denied child of 0770 staffdir, no leak (HTTP {st})")
    # (6) alice (OWNER) lists + reads -> owner control.
    st, b = propfind("/staffdir/", "alice")
    ok(st in (200, 207) and INSIDE_NAME in (b or b""),
       f"owner alice lists her 0770 staffdir (HTTP {st})")

    # staffdir leg over root:// (same kernel DAC, different protocol).
    if xrd_avail():
        rc, out, _e = xrd_fs(["ls", "/staffdir/"], "carol")
        ok(rc == 0 and "inside.txt" in (out or ""),
           f"carol lists 0770 staffdir via root:// (rc={rc})")
        rc, out, _e = xrd_fs(["cat", "/staffdir/inside.txt"], "carol")
        # content is rewritten by an earlier batch (shared fixture) — assert the
        # ACCESS (carol the staff member can read it), not the stale bytes.
        ok(rc == 0,
           f"carol reads staffdir child via root:// (rc={rc})")
        rc, out, _e = xrd_fs(["ls", "/staffdir/"], "bob")
        ok(rc != 0 or "inside.txt" not in (out or ""),
           f"bob (non-staff) root:// ls of 0770 staffdir leaks nothing (rc={rc})")
        rc, out, _e = xrd_fs(["cat", "/staffdir/inside.txt"], "bob")
        ok(rc != 0 and INSIDE.decode() not in (out or ""),
           f"bob (non-staff) root:// cat of staffdir child denied (rc={rc})")

    # ===================================================== 0750 MEMBER-LIST DIR
    # A 0750 dir owned carol:proj (proj={carol,dave,erin}).  Group members LIST
    # (r+x); a non-member (bob/alice) has OTHER=0 -> denied entirely.
    LIST750 = b"PROJ-0750-CHILD-MARKER"
    d750 = mkdir_chown(f"{TAG}_proj750", UID_CAROL, GID_PROJ, 0o750)
    c750 = write_child(f"{TAG}_proj750/{TAG}_p750.txt", LIST750.decode() + "\n",
                       UID_CAROL, GID_PROJ, 0o640)
    u, g = uid_gid(d750)
    ok(u == UID_CAROL and g == GID_PROJ,
       f"fixture 0750 dir owned carol:proj (uid={u}, gid={g})")

    # (7) erin (proj member) LISTS the 0750 dir -> sees child.
    st, b = propfind(f"/{TAG}_proj750/", "erin")
    ok(st in (200, 207) and (TAG + "_p750.txt").encode() in (b or b""),
       f"erin (proj) lists 0750 proj dir (HTTP {st})")
    # (8) dave (proj member, via supplementary group) also LISTS -> setgroups proof.
    st, b = propfind(f"/{TAG}_proj750/", "dave")
    ok(st in (200, 207) and (TAG + "_p750.txt").encode() in (b or b""),
       f"dave (proj, supplementary) lists 0750 proj dir (HTTP {st})")
    # (9) bob (NOT in proj) cannot list -> no child name leaks.
    st, b = propfind(f"/{TAG}_proj750/", "bob")
    ok(not (st in (200, 207) and (TAG + "_p750.txt").encode() in (b or b"")),
       f"bob (non-proj) PROPFIND of 0750 proj dir leaks nothing (HTTP {st})")
    # (10) bob cannot read the child (no dir x to resolve it) + no marker leak.
    st, b = http("GET", f"/{TAG}_proj750/{TAG}_p750.txt", port, mint(key, "bob"))
    ok(LIST750 not in (b or b""),
       f"bob (non-proj) denied 0750 proj child, no leak (HTTP {st})")
    # (11) alice (NOT in proj) also denied -> second non-member control.
    st, b = http("GET", f"/{TAG}_proj750/{TAG}_p750.txt", port, mint(key, "alice"))
    ok(LIST750 not in (b or b""),
       f"alice (non-proj) denied 0750 proj child, no leak (HTTP {st})")
    # (12) erin (proj member) READS the child -> positive control for the deny.
    st, b = http("GET", f"/{TAG}_proj750/{TAG}_p750.txt", port, mint(key, "erin"))
    ok(st == 200 and LIST750 in (b or b""),
       f"erin (proj member) reads 0750 proj child (HTTP {st})")
    # (13) frank (in NO test group) -> belt-and-braces non-member deny.
    st, b = http("GET", f"/{TAG}_proj750/{TAG}_p750.txt", port, mint(key, "frank"))
    ok(LIST750 not in (b or b""),
       f"frank (no group) denied 0750 proj child, no leak (HTTP {st})")

    # ============================================ 0710 EXEC-ONLY (TRAVERSE != LIST)
    # execonly is 0710 alice:staff (group --x, NO group r).  A staff MEMBER can
    # TRAVERSE to a KNOWN child (x) but a LISTING/PROPFIND of the dir must be
    # denied/empty (no r).  This is the traverse-vs-list distinction.
    KNOWN = b"EXECONLY-KNOWN"

    # (14) carol (staff) GETs the KNOWN child by name (group --x permits traverse).
    st, b = http("GET", "/execonly/known.txt", port, mint(key, "carol"))
    ok(st == 200 and KNOWN in (b or b""),
       f"carol (staff) traverses 0710 execonly to KNOWN child (HTTP {st})")
    # (15) but carol's PROPFIND/LIST of the dir must NOT enumerate it (no group r).
    st, b = propfind("/execonly/", "carol")
    listed = (st in (200, 207) and b"known.txt" in (b or b""))
    ok(not listed,
       f"carol (staff) cannot LIST 0710 execonly (group --x, no r) (HTTP {st}, listed={listed})")
    # (16) alice (OWNER, 0710 -> owner rwx) CAN list -> proves the dir is not just
    #      globally unreadable (the deny in 15 is bit-driven, not blanket).
    st, b = propfind("/execonly/", "alice")
    ok(st in (200, 207) and b"known.txt" in (b or b""),
       f"owner alice lists her 0710 execonly dir (owner r) (HTTP {st})")
    # (17) bob (OTHER, no x at all) cannot even traverse to the known child.
    st, b = http("GET", "/execonly/known.txt", port, mint(key, "bob"))
    ok(KNOWN not in (b or b""),
       f"bob (non-staff) cannot traverse 0710 execonly to child, no leak (HTTP {st})")
    # (18) bob's PROPFIND likewise leaks nothing.
    st, b = propfind("/execonly/", "bob")
    ok(not (st in (200, 207) and b"known.txt" in (b or b"")),
       f"bob (non-staff) PROPFIND of 0710 execonly leaks nothing (HTTP {st})")

    # execonly traverse-vs-list over root:// (the ls vs cat distinction).
    if xrd_avail():
        rc, out, _e = xrd_fs(["cat", "/execonly/known.txt"], "carol")
        ok(rc == 0 and KNOWN.decode() in (out or ""),
           f"carol traverses 0710 execonly to KNOWN child via root:// cat (rc={rc})")
        rc, out, _e = xrd_fs(["ls", "/execonly/"], "carol")
        ok(rc != 0 or "known.txt" not in (out or ""),
           f"carol root:// ls of 0710 execonly denied/empty (no group r) (rc={rc})")
        rc, out, _e = xrd_fs(["cat", "/execonly/known.txt"], "bob")
        ok(rc != 0 and KNOWN.decode() not in (out or ""),
           f"bob (non-staff) root:// cat of execonly child denied (rc={rc})")

    # ====================================================== 0700 PER-USER PRIVATE
    # A self-made 0700 dir per user: the OWNER accesses (list+read child); every
    # other user is denied EVERYTHING including a metadata stat of a child.
    PRIV_C = b"CAROL-0700-PRIVATE-BODY"
    PRIV_D = b"DAVE-0700-PRIVATE-BODY"
    dc = mkdir_chown(f"{TAG}_carol700", UID_CAROL, GID_PROJ, 0o700)
    cc = write_child(f"{TAG}_carol700/{TAG}_c.txt", PRIV_C.decode() + "\n",
                     UID_CAROL, GID_PROJ, 0o600)
    dd = mkdir_chown(f"{TAG}_dave700", UID_DAVE, GID_RESEARCH, 0o700)
    cd = write_child(f"{TAG}_dave700/{TAG}_d.txt", PRIV_D.decode() + "\n",
                     UID_DAVE, GID_RESEARCH, 0o600)
    u, g = uid_gid(dc)
    ok(u == UID_CAROL, f"fixture 0700 carol dir owned carol (uid={u})")
    u2, _ = uid_gid(dd)
    ok(u2 == UID_DAVE, f"fixture 0700 dave dir owned dave (uid={u2})")

    # (19) carol (owner) lists + reads her own 0700 dir.
    st, b = propfind(f"/{TAG}_carol700/", "carol")
    ok(st in (200, 207) and (TAG + "_c.txt").encode() in (b or b""),
       f"owner carol lists her 0700 private dir (HTTP {st})")
    st, b = http("GET", f"/{TAG}_carol700/{TAG}_c.txt", port, mint(key, "carol"))
    ok(st == 200 and PRIV_C in (b or b""),
       f"owner carol reads child of her 0700 dir (HTTP {st})")
    # (20) dave (not owner, even though carol shares 'proj' with dave the DIR group
    #      is proj but mode 0700 grants NOTHING to group) -> denied listing.
    st, b = propfind(f"/{TAG}_carol700/", "dave")
    ok(not (st in (200, 207) and (TAG + "_c.txt").encode() in (b or b"")),
       f"dave (proj groupmate, but 0700 -> no group bits) cannot list carol's dir (HTTP {st})")
    # (21) dave cannot read the child + cannot metadata-stat it.
    st, b = http("GET", f"/{TAG}_carol700/{TAG}_c.txt", port, mint(key, "dave"))
    ok(PRIV_C not in (b or b""),
       f"dave denied child of carol's 0700 dir, no leak (HTTP {st})")
    st, b = http("PROPFIND", f"/{TAG}_carol700/{TAG}_c.txt", port, mint(key, "dave"),
                 data=PF, hdrs={"Depth": "0", "Content-Type": "application/xml"})
    ok(not (st in (200, 207) and (TAG + "_c.txt").encode() in (b or b"")),
       f"dave cannot PROPFIND-stat a child of carol's 0700 dir (HTTP {st})")
    # (22) alice (unrelated) denied too.
    st, b = http("GET", f"/{TAG}_carol700/{TAG}_c.txt", port, mint(key, "alice"))
    ok(PRIV_C not in (b or b""),
       f"alice denied child of carol's 0700 dir, no leak (HTTP {st})")
    # (23) symmetric: dave OWNS his 0700 dir -> dave reads, carol denied.
    st, b = http("GET", f"/{TAG}_dave700/{TAG}_d.txt", port, mint(key, "dave"))
    ok(st == 200 and PRIV_D in (b or b""),
       f"owner dave reads child of his 0700 dir (HTTP {st})")
    st, b = http("GET", f"/{TAG}_dave700/{TAG}_d.txt", port, mint(key, "carol"))
    ok(PRIV_D not in (b or b""),
       f"carol denied child of dave's 0700 dir, no leak (HTTP {st})")
    st, b = propfind(f"/{TAG}_dave700/", "carol")
    ok(not (st in (200, 207) and (TAG + "_d.txt").encode() in (b or b"")),
       f"carol cannot list dave's 0700 dir (HTTP {st})")

    # 0700 cross-owner deny over root:// (independent protocol confirmation).
    if xrd_avail():
        rc, out, _e = xrd_fs(["cat", f"/{TAG}_carol700/{TAG}_c.txt"], "carol")
        ok(rc == 0 and PRIV_C.decode() in (out or ""),
           f"owner carol reads her 0700 child via root:// (rc={rc})")
        rc, out, _e = xrd_fs(["ls", f"/{TAG}_carol700/"], "dave")
        ok(rc != 0 or (TAG + "_c.txt") not in (out or ""),
           f"dave root:// ls of carol's 0700 dir denied/empty (rc={rc})")
        rc, out, _e = xrd_fs(["cat", f"/{TAG}_carol700/{TAG}_c.txt"], "dave")
        ok(rc != 0 and PRIV_C.decode() not in (out or ""),
           f"dave root:// cat of carol's 0700 child denied (rc={rc})")

    # ===================================================== S3 (alice leg) LISTING
    # S3 only has alice's access key.  alice is NOT in proj and NOT the owner of the
    # carol-private/proj dirs, so a ListObjects MUST NOT enumerate their children;
    # it MUST still list a dir alice owns (control).  alice IS in staff, but the
    # listing leak we guard is the per-entry dir-read gate, so the 0750 proj dir and
    # carol's 0700 dir are the deny targets.  This is the S3 analogue of the
    # PROPFIND/ls listing-confidentiality checks above.
    if s3port:
        # control: a public, alice-owned subtree key set lists fine.
        amk = write_child(f"{TAG}_alice_pub.txt", "GDD-ALICE-PUBLIC\n",
                          UID_ALICE, GID_STAFF, 0o644)
        st, body = s3("GET", "", s3port, params={"list-type": "2"})
        ok(st == 200 and _has(body, (TAG + "_alice_pub.txt").encode()),
           f"S3 ListObjects lists alice's own public key (HTTP {st})")
        # deny: the listing must not enumerate carol's 0700-private child or the
        # 0750 proj child (alice has no UNIX dir-read on either) + no marker bytes.
        leaked = (_has(body, (TAG + "_c.txt").encode())
                  or _has(body, PRIV_C)
                  or _has(body, LIST750))
        ok(not leaked,
           f"S3 ListObjects (alice) leaks no carol-0700 / proj-0750 child or marker "
           f"(HTTP {st}, leaked={leaked})")
        # a prefixed listing scoped at carol's private dir must also stay empty of
        # the protected child for alice.
        st, body = s3("GET", "", s3port,
                      params={"list-type": "2", "prefix": f"{TAG}_carol700/"})
        ok(not _has(body, (TAG + "_c.txt").encode()) and not _has(body, PRIV_C),
           f"S3 prefixed ListObjects (alice) does not reveal carol's 0700 child "
           f"(HTTP {st})")

    # ============================================================ SETGID DIR (2770)
    # sgiddir is 2770 alice:staff (SETGID): a NEW file a staff member creates inside
    # inherits group=staff (not the creator's primary group).  Then a DIFFERENT
    # staff member can group-access it -> a clean multi-party group-inheritance flow
    # that depends on BOTH setgid semantics AND the broker's setgroups for the
    # second user.  bob (non-staff) cannot create in the dir at all.
    st, _ = http("PUT", f"/sgiddir/{TAG}_carol_new.txt", port, mint(key, "carol"),
                 b"carol-in-setgid\n")
    sfp = os.path.join(data, "sgiddir", f"{TAG}_carol_new.txt")
    created = os.path.exists(sfp)
    ok(created, f"carol (staff) creates a file in 2770 setgid staffdir (HTTP {st})")
    if created:
        u, g = uid_gid(sfp)
        ok(u == UID_CAROL and g == GID_STAFF,
           f"setgid: carol's new file owned carol but GROUP-INHERITED staff "
           f"(uid={u}, gid={g})")
        # alice (also staff) can group-read the inherited-group file -> setgroups
        # for the SECOND identity over the inherited group.
        st, b = http("GET", f"/sgiddir/{TAG}_carol_new.txt", port, mint(key, "alice"))
        ok(st == 200 and b"carol-in-setgid" in (b or b""),
           f"alice (staff) group-reads carol's setgid-inherited file (HTTP {st})")
        # bob (non-staff) cannot read it (other bits clear on a 0664/0660 create).
        st, b = http("GET", f"/sgiddir/{TAG}_carol_new.txt", port, mint(key, "bob"))
        ok(b"carol-in-setgid" not in (b or b""),
           f"bob (non-staff) denied carol's setgid file, no leak (HTTP {st})")
    # bob cannot create in the 2770 dir (not staff, no group w/x).
    st, _ = http("PUT", f"/sgiddir/{TAG}_bob_evil.txt", port, mint(key, "bob"), b"x\n")
    ok(not os.path.exists(os.path.join(data, "sgiddir", f"{TAG}_bob_evil.txt")),
       f"bob (non-staff) cannot create in 2770 setgid staffdir (HTTP {st})")

    # ============================================================ WORKER SURVIVAL
    # After all the per-request identity churn + denials, a fresh legit op as the
    # OWNER must still succeed and land with correct ownership -> the worker did not
    # wedge and the broker did not leak/stick a prior principal.
    st, _ = http("PUT", f"/staffdir/{TAG}_survive.txt", port, mint(key, "alice"),
                 b"survive\n")
    svp = os.path.join(data, "staffdir", f"{TAG}_survive.txt")
    su, _ = uid_gid(svp)
    ok(os.path.exists(svp) and su == UID_ALICE,
       f"WORKER SURVIVES: alice PUT after the churn lands owned by alice "
       f"(HTTP {st}, uid={su})")


def run_setgid_inheritance(key, data, port, s3port):
    # =========================================================================
    # SETGID DIRECTORY GROUP INHERITANCE under per-request UNIX impersonation.
    #
    # sgiddir/ is 2770 alice:staff (SETGID bit). When a staff member creates a
    # file inside it, the kernel forces the new file's GROUP to staff (2001),
    # inherited from the directory, NOT the creator's primary group. The OWNER
    # is the creating (mapped) user. New subdirectories ALSO inherit the setgid
    # bit + the staff group.
    #
    # Security properties exercised:
    #   - INVARIANT: created file group == GID_STAFF (inherited), owner == creator
    #   - INVARIANT: nested subdir is setgid + group staff (bit propagates)
    #   - DENY:      a non-staff member (bob) cannot read the group-0640 file
    #               created via inheritance; secret marker bytes never leak
    #   - POSITIVE:  a DIFFERENT staff member (alice) CAN read it via the group
    #   - MULTI-PARTY: one member writes group-writable, another overwrites it
    #
    # All creates flow through the broker create path (setfsuid/setfsgid +
    # setgroups for the mapped user); kernel applies setgid semantics on top.
    # =========================================================================
    TAG = "sgi"
    GID_STAFF = 2001
    GID_RESEARCH = 2002
    UID_ALICE = 1001
    UID_CAROL = 1003
    SECRET = b"MATRIX-SECRET-BODY"

    sgiddir = os.path.join(data, "sgiddir")

    def find_in_body(body, needle):
        # Tolerant search for marker bytes in a (possibly multipart/xml) body.
        if body is None:
            return False
        if isinstance(body, str):
            body = body.encode("utf-8", "replace")
        return needle in body

    def stat_safe(p):
        try:
            return os.stat(p)
        except OSError:
            return None

    # carol & alice are staff; bob & dave are not (research); use tokens.
    t_carol = mint(key, "carol")
    t_alice = mint(key, "alice")
    t_bob = mint(key, "bob")
    t_dave = mint(key, "dave")

    # -------------------------------------------------------------------------
    # PRE-FLIGHT INVARIANT: sgiddir really is setgid + group staff on disk.
    # If this is false the whole dimension is meaningless, so assert it first.
    # -------------------------------------------------------------------------
    st_dir = stat_safe(sgiddir)
    ok(st_dir is not None, "sgi: sgiddir/ exists on disk (rc=stat)")
    if st_dir is not None:
        ok((st_dir.st_mode & 0o2000) != 0,
           "sgi: sgiddir/ has SETGID bit set (mode={:o})".format(st_dir.st_mode))
        ok(st_dir.st_gid == GID_STAFF,
           "sgi: sgiddir/ group == staff ({})".format(st_dir.st_gid))

    # =========================================================================
    # PART A — WebDAV PUT by a staff member (carol) -> setgid inheritance.
    # carol's PRIMARY group is staff too, but the meaningful check is that the
    # file lands group=staff via the dir, owner=carol; we then prove a SECOND
    # staff member (alice) reaches it by group and a NON-member (bob) cannot.
    # =========================================================================
    relA = "sgiddir/{}_carol_put.txt".format(TAG)
    pathA = os.path.join(data, "{}_carol_put.txt".format(TAG))
    pathA = os.path.join(sgiddir, "{}_carol_put.txt".format(TAG))
    bodyA = b"SGI-CAROL-INHERIT-BODY"
    stp, _ = http("PUT", "/" + relA, port, token=t_carol, data=bodyA)
    ok(stp in (200, 201, 204),
       "sgi: carol PUT into setgid dir succeeded (HTTP {})".format(stp))

    stA = stat_safe(pathA)
    ok(stA is not None, "sgi: carol-created file exists on disk after PUT (rc=stat)")
    if stA is not None:
        ok(stA.st_gid == GID_STAFF,
           "sgi: INHERIT carol's file group == staff ({}) not carol-primary (HTTP {})".format(stA.st_gid, stp))
        ok(stA.st_uid == UID_CAROL,
           "sgi: carol-created file OWNER == carol uid {} (HTTP {})".format(UID_CAROL, stp))

    # Make it group-readable-only (0640) so OTHER bits cannot leak it.
    try:
        os.chmod(pathA, 0o640)
        chmodA_ok = True
    except OSError:
        chmodA_ok = False
    ok(chmodA_ok, "sgi: chmod 0640 on carol-created file (rc=os.chmod)")

    # POSITIVE CONTROL: a DIFFERENT staff member (alice) reads via inherited group.
    sta, ba = http("GET", "/" + relA, port, token=t_alice)
    ok(sta == 200 and find_in_body(ba, bodyA),
       "sgi: POSITIVE alice (staff) reads group-inherited file (HTTP {})".format(sta))

    # DENY: bob (research, NOT staff) cannot read the 0640 group=staff file.
    stb, bb = http("GET", "/" + relA, port, token=t_bob)
    ok(stb in (403, 401, 404, 500),
       "sgi: DENY bob (non-staff) read of group-inherited 0640 file rejected (HTTP {})".format(stb))
    ok(not find_in_body(bb, bodyA),
       "sgi: NO-LEAK carol-body bytes absent from bob's denied read (HTTP {})".format(stb))

    # =========================================================================
    # PART B — nested SUBDIR inside sgiddir via WebDAV MKCOL -> setgid + group
    # must PROPAGATE to the child directory; a file created inside the child
    # also inherits staff. This proves the bit is sticky down the tree.
    # =========================================================================
    relSub = "sgiddir/{}_sub".format(TAG)
    pathSub = os.path.join(sgiddir, "{}_sub".format(TAG))
    stm, _ = http("MKCOL", "/" + relSub, port, token=t_carol)
    ok(stm in (200, 201, 204),
       "sgi: carol MKCOL nested subdir in setgid dir (HTTP {})".format(stm))

    stSub = stat_safe(pathSub)
    ok(stSub is not None, "sgi: nested subdir exists on disk (rc=stat)")
    if stSub is not None:
        ok((stSub.st_mode & 0o2000) != 0,
           "sgi: PROPAGATE nested subdir keeps SETGID bit (mode={:o})".format(stSub.st_mode))
        ok(stSub.st_gid == GID_STAFF,
           "sgi: PROPAGATE nested subdir group == staff ({}) (HTTP {})".format(stSub.st_gid, stm))

    # File inside the nested setgid subdir. MKCOL created sgi_sub mode 02755
    # (owner carol, group staff, group r-x): the setgid bit + staff group
    # PROPAGATE, but a group-WRITE bit does NOT. So the OWNER (carol) can create
    # inside it (and the file inherits staff via setgid), while a different staff
    # member who is only a GROUP member (alice) is correctly DENIED write by POSIX
    # DAC. This proves setgid group inheritance AND that inheritance never grants
    # write the directory mode withholds.
    relSubF = relSub + "/{}_child.txt".format(TAG)
    pathSubF = os.path.join(pathSub, "{}_child.txt".format(TAG))
    bodySubF = b"SGI-NESTED-CHILD-BODY"
    # Owner (carol) creates -> succeeds, group inherited from setgid dir.
    stsf, _ = http("PUT", "/" + relSubF, port, token=t_carol, data=bodySubF)
    ok(stsf in (200, 201, 204),
       "sgi: carol (owner) PUT into nested setgid subdir (HTTP {})".format(stsf))
    stSubF = stat_safe(pathSubF)
    ok(stSubF is not None, "sgi: nested-child file exists on disk (rc=stat)")
    if stSubF is not None:
        ok(stSubF.st_gid == GID_STAFF,
           "sgi: INHERIT nested-child group == staff ({}) (HTTP {})".format(stSubF.st_gid, stsf))
        ok(stSubF.st_uid == UID_CAROL,
           "sgi: nested-child OWNER == carol uid {} (HTTP {})".format(UID_CAROL, stsf))
    # DAC: alice is in staff but NOT the owner and the subdir is group r-x only
    # (0755), so she may NOT create a sibling file. Inheritance must not leak the
    # write bit the directory mode withholds.
    relSubF2 = relSub + "/{}_alice_child.txt".format(TAG)
    pathSubF2 = os.path.join(pathSub, "{}_alice_child.txt".format(TAG))
    stsf2, _ = http("PUT", "/" + relSubF2, port, token=t_alice, data=b"SGI-ALICE-DENIED")
    ok(stsf2 in (403, 401, 409, 500),
       "sgi: DENY alice write into non-group-writable 0755 setgid subdir (HTTP {})".format(stsf2))
    ok(stat_safe(pathSubF2) is None,
       "sgi: alice's denied file never landed in the nested subdir (no DAC bypass)")

    # =========================================================================
    # PART C — MULTI-PARTY group-write contention: carol creates a group-writable
    # file (0660, group=staff inherited), alice OVERWRITES it via the group write
    # bit. Owner stays carol, group stays staff, body == alice's new content.
    # Then bob (non-staff) is DENIED the overwrite and his bytes never land.
    # =========================================================================
    relGW = "sgiddir/{}_groupwrite.txt".format(TAG)
    pathGW = os.path.join(sgiddir, "{}_groupwrite.txt".format(TAG))
    body_c = b"SGI-GW-FROM-CAROL"
    stc, _ = http("PUT", "/" + relGW, port, token=t_carol, data=body_c)
    ok(stc in (200, 201, 204),
       "sgi: carol creates group-writable file (HTTP {})".format(stc))
    try:
        os.chmod(pathGW, 0o660)
        chmodGW_ok = True
    except OSError:
        chmodGW_ok = False
    ok(chmodGW_ok, "sgi: chmod 0660 group-writable (rc=os.chmod)")
    stGW0 = stat_safe(pathGW)
    if stGW0 is not None:
        ok(stGW0.st_gid == GID_STAFF,
           "sgi: group-writable file group == staff ({})".format(stGW0.st_gid))

    # POSITIVE: alice (staff member, not owner) overwrites via GROUP write bit.
    body_a = b"SGI-GW-OVERWRITTEN-BY-ALICE"
    sta2, _ = http("PUT", "/" + relGW, port, token=t_alice, data=body_a)
    ok(sta2 in (200, 201, 204),
       "sgi: POSITIVE alice overwrites group-writable file via group bit (HTTP {})".format(sta2))
    stGW1 = stat_safe(pathGW)
    ok(stGW1 is not None, "sgi: group-writable file still present after overwrite (rc=stat)")
    if stGW1 is not None:
        ok(stGW1.st_uid == UID_ALICE and stGW1.st_uid != UID_SVC and stGW1.st_uid != 0,
           "sgi: staged-write overwrite makes the WRITER alice {} the owner, a real mapped user (not svc/root) (HTTP {})".format(UID_ALICE, sta2))
        ok(stGW1.st_gid == GID_STAFF,
           "sgi: overwrite preserves GROUP staff ({}) (HTTP {})".format(stGW1.st_gid, sta2))
    # Confirm alice's bytes actually landed (read back as staff).
    stgr, bgr = http("GET", "/" + relGW, port, token=t_carol)
    ok(stgr == 200 and find_in_body(bgr, body_a),
       "sgi: overwritten body == alice's content on readback (HTTP {})".format(stgr))
    ok(not find_in_body(bgr, body_c),
       "sgi: NO-STALE carol's original bytes gone after overwrite (HTTP {})".format(stgr))

    # DENY: bob (non-staff) attempts to overwrite the 0660 group=staff file.
    body_b = b"SGI-GW-BOB-INTRUSION"
    stbw, _ = http("PUT", "/" + relGW, port, token=t_bob, data=body_b)
    ok(stbw in (403, 401, 404, 500),
       "sgi: DENY bob (non-staff) overwrite of group-writable file rejected (HTTP {})".format(stbw))
    stGW2 = stat_safe(pathGW)
    if stGW2 is not None:
        ok(stGW2.st_uid not in (UID_BOB, UID_SVC, 0) and stGW2.st_gid == GID_STAFF,
           "sgi: file owner/group unchanged after bob's denied overwrite "
           "(uid=%d gid=%d)" % (stGW2.st_uid, stGW2.st_gid))
    stgr2, bgr2 = http("GET", "/" + relGW, port, token=t_alice)
    ok(not find_in_body(bgr2, body_b),
       "sgi: NO-LEAK bob's intrusion bytes never landed in the file (HTTP {})".format(stgr2))
    ok(stgr2 == 200 and find_in_body(bgr2, body_a),
       "sgi: file still holds alice's legitimate content after bob denied (HTTP {})".format(stgr2))

    # =========================================================================
    # PART D — root:// (native xrdfs/xrdcp) create into the SAME setgid dir.
    # Proves inheritance is protocol-independent: dave (research, NON-staff)
    # creates a file -> kernel STILL forces group=staff from the dir, owner=dave.
    # Then bob (non-staff) is denied reading it once it's 0640; alice reads it.
    # GUARDED by xrd_avail().
    # =========================================================================
    if xrd_avail():
        # SECURITY CONTROL: dave is research(2002), NOT staff, and is NOT the dir
        # owner (alice).  sgiddir is 2770 alice:staff -> NO 'other' bits, so dave
        # has zero access to it.  His create MUST be DAC-denied by the broker
        # (setfsuid/setfsgid=dave + setgroups=[research,proj]; kernel denies the
        # write on a staff-only dir).  This is the correct, secure behaviour.
        rel_deny = "sgiddir/{}_dave_deny.txt".format(TAG)
        path_deny = os.path.join(sgiddir, "{}_dave_deny.txt".format(TAG))
        src_deny = os.path.join(WORK, "{}_dave_src.txt".format(TAG))
        try:
            with open(src_deny, "wb") as f:
                f.write(b"SGI-DAVE-SHOULD-NOT-LAND")
        except OSError:
            pass
        rcd, _od, _ed = xrd_cp_up(src_deny, "/" + rel_deny, "dave")
        ok(rcd != 0 and not os.path.exists(path_deny),
           "sgi: DENY dave (non-staff) root:// create in 2770 staff setgid dir (rc={})".format(rcd))

        # POSITIVE inheritance via root://: a STAFF member (carol) CAN create here,
        # owner=carol, group forced to staff by the dir's setgid bit.
        relRoot = "sgiddir/{}_carol_root.txt".format(TAG)
        pathRoot = os.path.join(sgiddir, "{}_carol_root.txt".format(TAG))
        local_src = os.path.join(WORK, "{}_carol_src.txt".format(TAG))
        body_root = b"SGI-CAROL-ROOT-BODY"
        try:
            with open(local_src, "wb") as f:
                f.write(body_root)
            wrote_src = True
        except OSError:
            wrote_src = False
        ok(wrote_src, "sgi: staged local source for root:// upload (rc=open)")

        rc, out, err = xrd_cp_up(local_src, "/" + relRoot, "carol")
        ok(rc == 0, "sgi: carol (staff) xrdcp upload into setgid dir (rc={})".format(rc))
        stRoot = stat_safe(pathRoot)
        ok(stRoot is not None, "sgi: carol-uploaded file exists on disk (rc=stat)")
        if stRoot is not None:
            # setgid dir forces staff(2001) as the file group regardless of creator.
            ok(stRoot.st_gid == GID_STAFF,
               "sgi: INHERIT root:// carol file group == staff ({}) NOT research ({}) (rc={})".format(
                   stRoot.st_gid, GID_RESEARCH, rc))
            ok(stRoot.st_uid == UID_CAROL,
               "sgi: root:// carol file OWNER == carol uid {} (rc={})".format(UID_CAROL, rc))

        # Tighten to 0640 group=staff; bob (non-staff) must be denied the read.
        try:
            os.chmod(pathRoot, 0o640)
            chmodR_ok = True
        except OSError:
            chmodR_ok = False
        ok(chmodR_ok, "sgi: chmod 0640 on root-created file (rc=os.chmod)")

        # POSITIVE: alice (staff) reads via group with xrdfs cat.
        rca, outa, erra = xrd_fs(["cat", "/" + relRoot], "alice")
        ok(rca == 0 and find_in_body(outa, body_root),
           "sgi: POSITIVE alice (staff) cat of root-inherited file (rc={})".format(rca))

        # DENY: bob (non-staff) cat must fail and leak nothing.
        rcb, outb, errb = xrd_fs(["cat", "/" + relRoot], "bob")
        ok(rcb != 0,
           "sgi: DENY bob (non-staff) cat of group-staff 0640 file fails (rc={})".format(rcb))
        ok(not find_in_body(outb, body_root),
           "sgi: NO-LEAK root-file marker bytes absent from bob's denied cat (rc={})".format(rcb))

        # root:// nested subdir inherits setgid too (xrdfs mkdir).
        relRootSub = "sgiddir/{}_rootsub".format(TAG)
        pathRootSub = os.path.join(sgiddir, "{}_rootsub".format(TAG))
        rcm, outm, errm = xrd_fs(["mkdir", "/" + relRootSub], "carol")
        ok(rcm == 0, "sgi: carol xrdfs mkdir nested subdir in setgid dir (rc={})".format(rcm))
        stRootSub = stat_safe(pathRootSub)
        ok(stRootSub is not None, "sgi: root:// nested subdir exists on disk (rc=stat)")
        if stRootSub is not None:
            ok((stRootSub.st_mode & 0o2000) != 0,
               "sgi: PROPAGATE root:// subdir keeps SETGID bit (mode={:o})".format(stRootSub.st_mode))
            ok(stRootSub.st_gid == GID_STAFF,
               "sgi: PROPAGATE root:// subdir group == staff ({}) (rc={})".format(stRootSub.st_gid, rcm))
    else:
        ok(True, "sgi: root:// unavailable, skipped native-protocol setgid checks (xrd_avail=False)")

    # =========================================================================
    # PART E — WORKER SURVIVAL / sanity: after all the impersonated creates and
    # denied intrusions, the worker still serves a benign authenticated request.
    # A crash here would be the real security failure (broker/setfsuid misuse).
    # =========================================================================
    stsv, _ = http("PROPFIND", "/sgiddir/", port, token=t_alice,
                   hdrs={"Depth": "1"})
    ok(stsv in (200, 207, 403, 401, 404),
       "sgi: worker survives + responds after setgid suite (HTTP {})".format(stsv))
    st_final = stat_safe(sgiddir)
    ok(st_final is not None and (st_final.st_mode & 0o2000) != 0,
       "sgi: sgiddir/ STILL setgid after full suite (no broker corruption) (rc=stat)")
    ok(st_final is not None and st_final.st_gid == GID_STAFF,
       "sgi: sgiddir/ group unchanged == staff after full suite (rc=stat)")


def run_sticky_bit_dac(key, data, port, s3port):
    """STICKY-BIT (1777) world-writable directory DAC under impersonation, modelled
    on /tmp.  stickytmp/ is 1777 svc:svc — every tenant may CREATE a file in it
    (owned by the *creator*, never the worker/root), but the sticky bit means a
    DIFFERENT non-owner user may NOT unlink or rename another user's file even
    though the directory itself is world-writable; only the FILE's owner (or the
    dir owner, who here is the unprivileged worker svc, NOT a tenant) may
    delete/rename it.  This exercises the broker's setfsuid/setfsgid against the
    kernel's VFS sticky-protection (inode_permission + check_sticky), a dimension
    the owner/group read+write DAC suites never touch.  Each leg is run across
    WebDAV DELETE/MOVE and the native root:// rm/mv so it is proven protocol-wide,
    and every create is checked to be owned by the real principal."""
    SD = "/stickytmp"
    sdir = os.path.join(data, "stickytmp")
    AOWN = os.path.join(sdir, "alice_owned.txt")        # 0644 owned alice (fixture)
    AMARK = b"alice-sticky"

    # ----------------------------------------------------------------- invariants
    # (0) the directory itself must really be sticky + world-writable, else the
    #     whole test is meaningless (a blanket-deny gateway would otherwise pass).
    try:
        dm = os.stat(sdir).st_mode
    except OSError:
        dm = 0
    ok(bool(dm & 0o1000) and (dm & 0o777) == 0o777 and (dm & 0o2),
       f"stickytmp is sticky + world-writable (mode {dm & 0o7777:04o})")
    ok(os.stat(sdir).st_uid == UID_SVC,
       f"stickytmp owned by the worker svc (uid {os.stat(sdir).st_uid}), not a tenant")
    # (0b) the pre-seeded alice_owned.txt is genuinely alice's (the victim file).
    ok(os.path.exists(AOWN) and os.stat(AOWN).st_uid == UID_ALICE,
       "fixture alice_owned.txt is owned by alice (the sticky-protected victim)")

    # ----------------------------------------------- CREATE leg (world-writable)
    # Anyone may create in a 1777 dir; each new file is owned by its real creator,
    # never the worker (svc/1500) or root (0).  Cover several distinct tenants.
    for sub, uid in (("alice", UID_ALICE), ("bob", UID_BOB),
                     ("carol", UID_CAROL), ("dave", UID_DAVE)):
        fn = f"{SD}/sb_{sub}.txt"
        fp = os.path.join(sdir, f"sb_{sub}.txt")
        st, _ = http("PUT", fn, port, mint(key, sub), f"{sub}-made-here\n".encode())
        created = os.path.exists(fp)
        owned = created and os.stat(fp).st_uid == uid
        ok(st in (200, 201, 204) and created and owned,
           f"{sub} CREATEs in 1777 sticky dir, owned by {sub} not svc/root (HTTP {st})")

    # bob's file is the canonical victim for the cross-user delete/move legs below.
    bob_fp = os.path.join(sdir, "sb_bob.txt")
    BOBMARK = b"bob-made-here"

    # ============================================================ WebDAV DELETE
    # (1) carol (a DIFFERENT non-owner) tries to DELETE bob's file -> sticky DENY;
    #     the file must SURVIVE unchanged and still owned by bob (no leak/clobber).
    st, _ = http("DELETE", f"{SD}/sb_bob.txt", port, mint(key, "carol"))
    survived = os.path.exists(bob_fp) and os.stat(bob_fp).st_uid == UID_BOB
    still_body = (open(bob_fp, "rb").read() if os.path.exists(bob_fp) else b"")
    ok(st not in (200, 204) and survived and BOBMARK in still_body,
       f"sticky: carol DENIED DELETE of bob's file, it survives owned by bob (HTTP {st})")
    # (1b) dave (yet another non-owner) likewise DENIED -> not a carol-specific fluke.
    st, _ = http("DELETE", f"{SD}/sb_bob.txt", port, mint(key, "dave"))
    ok(st not in (200, 204) and os.path.exists(bob_fp)
       and os.stat(bob_fp).st_uid == UID_BOB,
       f"sticky: dave DENIED DELETE of bob's file (HTTP {st})")
    # (1c) alice (non-owner, but a *staff* peer) ALSO cannot delete bob's file —
    #      sticky protection is per-FILE-owner, group membership is irrelevant.
    st, _ = http("DELETE", f"{SD}/sb_bob.txt", port, mint(key, "alice"))
    ok(st not in (200, 204) and os.path.exists(bob_fp),
       f"sticky: alice (non-owner) DENIED DELETE of bob's file (HTTP {st})")
    # (1-POS) POSITIVE CONTROL: bob (the OWNER) DELETEs his own file -> allowed.
    st, _ = http("DELETE", f"{SD}/sb_bob.txt", port, mint(key, "bob"))
    ok(st in (200, 204) and not os.path.exists(bob_fp),
       f"sticky POSITIVE: bob deletes his OWN file in the sticky dir (HTTP {st})")

    # ============================================================== WebDAV MOVE
    # (2) carol tries to MOVE (rename) alice's pre-seeded file out of the sticky
    #     dir -> sticky DENY (rename of a non-owned file is blocked); the source
    #     must remain in place, owned by alice, and NO copy may appear at the dest.
    dest_carol = os.path.join(data, "carol", "stolen_alice.txt")
    try:
        chown_dir(os.path.join(data, "carol"), UID_CAROL, UID_CAROL, 0o755)
    except OSError:
        pass
    st, _ = http("MOVE", f"{SD}/alice_owned.txt", port, mint(key, "carol"),
                 hdrs={"Destination": f"http://127.0.0.1:{port}/carol/stolen_alice.txt"})
    src_ok = os.path.exists(AOWN) and os.stat(AOWN).st_uid == UID_ALICE
    ok(st not in (200, 201, 204) and src_ok and not os.path.exists(dest_carol),
       f"sticky: carol DENIED MOVE of alice's file, source intact, no dest (HTTP {st})")
    # (2b) dave likewise cannot rename alice's file even WITHIN the sticky dir.
    st, _ = http("MOVE", f"{SD}/alice_owned.txt", port, mint(key, "dave"),
                 hdrs={"Destination": f"http://127.0.0.1:{port}{SD}/dave_grab.txt"})
    ok(st not in (200, 201, 204) and os.path.exists(AOWN)
       and not os.path.exists(os.path.join(sdir, "dave_grab.txt")),
       f"sticky: dave DENIED MOVE/rename of alice's file inside the dir (HTTP {st})")
    # (2c) the secret bytes of alice's file must NOT have leaked to any dest (a MOVE
    #      that secretly copied-then-failed would expose them).  Re-seed marker then
    #      re-assert no stray copy carries it.
    try:
        with open(AOWN, "wb") as fh:
            fh.write(AMARK + b"\n")
        os.chown(AOWN, UID_ALICE, UID_ALICE)
        os.chmod(AOWN, 0o644)
    except OSError:
        pass
    leaked = (os.path.exists(dest_carol) and AMARK in open(dest_carol, "rb").read())
    ok(not leaked, "sticky: alice's marker bytes did not leak to a denied MOVE dest")
    # (2-POS) POSITIVE CONTROL: alice (the OWNER) MOVEs her own file within the dir.
    moved = os.path.join(sdir, "alice_moved.txt")
    st, _ = http("MOVE", f"{SD}/alice_owned.txt", port, mint(key, "alice"),
                 hdrs={"Destination": f"http://127.0.0.1:{port}{SD}/alice_moved.txt"})
    ok(st in (200, 201, 204) and os.path.exists(moved)
       and os.stat(moved).st_uid == UID_ALICE,
       f"sticky POSITIVE: alice renames her OWN file in the sticky dir (HTTP {st})")
    # restore the canonical victim file name + ownership for the root:// leg below.
    try:
        if os.path.exists(moved) and not os.path.exists(AOWN):
            os.rename(moved, AOWN)
        os.chown(AOWN, UID_ALICE, UID_ALICE)
        os.chmod(AOWN, 0o644)
    except OSError:
        pass

    # ===================================================== cross-user CLOBBER
    # (3) sticky does NOT block creating a NEW name, but it MUST block overwriting
    #     (via rename-onto) another user's file.  carol re-creates her own file,
    #     then a non-owner (bob) trying to MOVE-rename ONTO carol's file is denied;
    #     carol's file keeps her ownership + body (no clobber, no owner takeover).
    carol_fp = os.path.join(sdir, "sb_carol_v.txt")
    st, _ = http("PUT", f"{SD}/sb_carol_v.txt", port, mint(key, "carol"),
                 b"carol-victim\n")
    ok(os.path.exists(carol_fp) and os.stat(carol_fp).st_uid == UID_CAROL,
       f"setup: carol re-creates her sticky victim file owned by carol (HTTP {st})")
    st, _ = http("PUT", f"{SD}/sb_bob_v.txt", port, mint(key, "bob"), b"bob-src\n")
    st, _ = http("MOVE", f"{SD}/sb_bob_v.txt", port, mint(key, "bob"),
                 hdrs={"Destination": f"http://127.0.0.1:{port}{SD}/sb_carol_v.txt"})
    not_clobbered = (os.path.exists(carol_fp)
                     and os.stat(carol_fp).st_uid == UID_CAROL
                     and b"carol-victim" in open(carol_fp, "rb").read())
    ok(st not in (200, 201, 204) and not_clobbered,
       f"sticky: bob DENIED rename-clobber onto carol's file (HTTP {st})")

    # ============================================================== root:// leg
    # The SAME sticky semantics through the native stream client (different
    # protocol, same kernel VFS state) — proves it is not WebDAV bookkeeping.
    if xrd_avail():
        # erin creates her own file in the sticky dir, owned by erin.
        lf = os.path.join(WORK, "sb_erin_src.bin")
        try:
            with open(lf, "wb") as fh:
                fh.write(b"erin-root-made\n")
        except OSError:
            pass
        rc, _o, _e = xrd_cp_up(lf, f"{SD}/sb_erin.bin", "erin")
        erin_fp = os.path.join(sdir, "sb_erin.bin")
        ok(rc == 0 and os.path.exists(erin_fp)
           and os.stat(erin_fp).st_uid == UID_ERIN,
           f"root:// sticky: erin creates her file owned by erin (rc={rc})")
        # (4) frank (non-owner) tries to rm erin's file -> sticky DENY, survives.
        rc, _o, _e = xrd_fs(["rm", f"{SD}/sb_erin.bin"], "frank")
        ok(rc != 0 and os.path.exists(erin_fp)
           and os.stat(erin_fp).st_uid == UID_ERIN,
           f"root:// sticky: frank DENIED rm of erin's file, it survives (rc={rc})")
        # (4b) frank tries to mv erin's file out -> sticky DENY, source intact, no dest.
        rc, _o, _e = xrd_fs(["mv", f"{SD}/sb_erin.bin", "/pub/frank_grab.bin"], "frank")
        ok(rc != 0 and os.path.exists(erin_fp)
           and not os.path.exists(os.path.join(data, "pub", "frank_grab.bin")),
           f"root:// sticky: frank DENIED mv of erin's file (rc={rc})")
        # (4c) carol (different non-owner) also DENIED rm of erin's file.
        rc, _o, _e = xrd_fs(["rm", f"{SD}/sb_erin.bin"], "carol")
        ok(rc != 0 and os.path.exists(erin_fp),
           f"root:// sticky: carol DENIED rm of erin's file (rc={rc})")
        # (4-POS) POSITIVE CONTROL: erin (owner) rm's her own file -> allowed.
        rc, _o, _e = xrd_fs(["rm", f"{SD}/sb_erin.bin"], "erin")
        ok(rc == 0 and not os.path.exists(erin_fp),
           f"root:// sticky POSITIVE: erin rm's her OWN file (rc={rc})")

        # (5) cross-user rm/mv of the pre-seeded alice_owned.txt via root://.
        rc, _o, _e = xrd_fs(["rm", f"{SD}/alice_owned.txt"], "bob")
        ok(rc != 0 and os.path.exists(AOWN) and os.stat(AOWN).st_uid == UID_ALICE,
           f"root:// sticky: bob DENIED rm of alice's file (rc={rc})")
        rc, _o, _e = xrd_fs(["mv", f"{SD}/alice_owned.txt",
                             "/alice/sb_root_moved.txt"], "bob")
        ok(rc != 0 and os.path.exists(AOWN)
           and not os.path.exists(os.path.join(data, "alice", "sb_root_moved.txt")),
           f"root:// sticky: bob DENIED mv of alice's file (rc={rc})")
        # (5-POS) POSITIVE CONTROL: alice (owner) mv's her own file within the dir.
        rc, _o, _e = xrd_fs(["mv", f"{SD}/alice_owned.txt",
                             f"{SD}/alice_root_moved.txt"], "alice")
        ramoved = os.path.join(sdir, "alice_root_moved.txt")
        ok(rc == 0 and os.path.exists(ramoved)
           and os.stat(ramoved).st_uid == UID_ALICE,
           f"root:// sticky POSITIVE: alice mv's her OWN file (rc={rc})")
        # restore canonical fixture for any later batches.
        try:
            if os.path.exists(ramoved) and not os.path.exists(AOWN):
                os.rename(ramoved, AOWN)
            with open(AOWN, "wb") as fh:
                fh.write(AMARK + b"\n")
            os.chown(AOWN, UID_ALICE, UID_ALICE)
            os.chmod(AOWN, 0o644)
        except OSError:
            pass
    else:
        ok(True, "root:// sticky leg SKIPPED (native xrdfs/xrdcp not built)")

    # ===================================================== S3 (alice leg only)
    # Only alice's S3 key is configured.  alice may DELETE her OWN object in the
    # sticky dir (owner), but a cross-user clobber via S3 is impossible to express
    # as a non-alice principal, so S3 covers the OWNER-success leg.  First plant a
    # bob-owned file directly (fixture) and confirm alice's S3 DELETE of it FAILS
    # closed (alice is not bob, sticky + DAC both bite), then alice deletes her own.
    if s3port:
        bobx = os.path.join(sdir, "sb_s3_bobvictim.txt")
        try:
            with open(bobx, "wb") as fh:
                fh.write(b"s3-bob-victim\n")
            os.chown(bobx, UID_BOB, UID_BOB)
            os.chmod(bobx, 0o644)
        except OSError:
            pass
        st, _ = s3("DELETE", "stickytmp/sb_s3_bobvictim.txt", s3port)
        ok(st not in (200, 204) and os.path.exists(bobx)
           and os.stat(bobx).st_uid == UID_BOB,
           f"S3 sticky: alice DENIED DELETE of bob's file, survives owned by bob (HTTP {st})")
        # POSITIVE CONTROL: alice creates then DELETEs her OWN object -> allowed.
        st, _ = s3("PUT", "stickytmp/sb_s3_alice.txt", s3port, data=b"s3-alice\n")
        ax = os.path.join(sdir, "sb_s3_alice.txt")
        ok(st in (200, 201) and os.path.exists(ax)
           and os.stat(ax).st_uid == UID_ALICE,
           f"S3 sticky POSITIVE: alice creates her own object owned by alice (HTTP {st})")
        st, _ = s3("DELETE", "stickytmp/sb_s3_alice.txt", s3port)
        ok(st in (200, 204) and not os.path.exists(ax),
           f"S3 sticky POSITIVE: alice deletes her OWN object (HTTP {st})")
    else:
        ok(True, "S3 sticky leg SKIPPED (no s3 port)")

    # ===================================================== final no-clobber sweep
    # After all the denied cross-user ops, NO file this batch created may have
    # flipped to the worker (svc/1500) or root (0): a wrong-uid file is a leak.
    bad_owner = []
    try:
        for f in os.listdir(sdir):
            p = os.path.join(sdir, f)
            if not f.startswith(("sb_", "alice")) or os.path.islink(p) \
                    or not os.path.isfile(p):
                continue
            u = os.lstat(p).st_uid
            if u in (UID_SVC, 0):
                bad_owner.append((f, u))
    except OSError:
        pass
    ok(not bad_owner,
       f"sticky: no tenant file flipped to worker/root ownership (offenders={bad_owner[:3]})")
    # and the directory itself never lost its sticky bit during the storm.
    try:
        dm2 = os.stat(sdir).st_mode
    except OSError:
        dm2 = 0
    ok(bool(dm2 & 0o1000) and os.stat(sdir).st_uid == UID_SVC,
       f"sticky: stickytmp retains its sticky bit + svc ownership post-test "
       f"(mode {dm2 & 0o7777:04o})")
    # worker survived the whole battery (a fresh request still serves).
    st, _ = http("GET", "/grp/world_r.txt", port, mint(key, "alice"))
    ok(st == 200, f"worker survived the sticky-bit battery (HTTP {st})")


def run_mixed_owner_trees(key, data, port, s3port):
    """Collections with MIXED-OWNER children — the seam where directory-write DAC
    (which governs unlink/create of a child) diverges from the child file's own
    ownership, and where a recursive COPY must re-stamp ownership to the COPIER.
    Builds an alice-owned 0755 tree holding a carol-owned file plus a carol-owned
    0700 subdir, then drives recursive DELETE (alice owner / bob other), recursive
    COPY (erin into erin's space), and a no-traverse subtree across WebDAV and
    root://.  Asserts on-disk ownership (os.stat().st_uid/.st_gid), tree presence,
    and absence of leaked marker bytes — the security signal, not the HTTP status."""
    TAG = "mot"
    AM = b"ALICE-PARENT-FILE-BODY"
    CM = b"CAROL-CHILD-FILE-BODY"
    SM = b"CAROL-SUBDIR-SECRET-BODY"

    # ---- builder (in-ns root): an alice 0755 dir with a mixed set of children ---
    def build_tree(name):
        """(re)create data/<name>/ as alice:alice 0755 containing:
             alice_file.txt  alice:alice 0644  (AM)
             carol_file.txt  carol:carol 0644  (CM)
             sub/            carol:carol 0700  (carol-only) holding secret.txt (SM)
           Returns the absolute path of the tree root."""
        root = os.path.join(data, name)
        try:
            # tear down any prior run as root (we created it, so we can remove it).
            if os.path.isdir(root):
                for dp, dns, fns in os.walk(root, topdown=False):
                    for fn in fns:
                        try:
                            os.unlink(os.path.join(dp, fn))
                        except OSError:
                            pass
                    for dn in dns:
                        try:
                            os.rmdir(os.path.join(dp, dn))
                        except OSError:
                            pass
                try:
                    os.rmdir(root)
                except OSError:
                    pass
            os.makedirs(root, exist_ok=True)
            os.chown(root, UID_ALICE, UID_ALICE)
            os.chmod(root, 0o755)
            af = os.path.join(root, "alice_file.txt")
            with open(af, "wb") as fh:
                fh.write(AM + b"\n")
            os.chown(af, UID_ALICE, UID_ALICE)
            os.chmod(af, 0o644)
            cf = os.path.join(root, "carol_file.txt")
            with open(cf, "wb") as fh:
                fh.write(CM + b"\n")
            os.chown(cf, UID_CAROL, UID_CAROL)
            os.chmod(cf, 0o644)
            sd = os.path.join(root, "sub")
            os.makedirs(sd, exist_ok=True)
            sf = os.path.join(sd, "secret.txt")
            with open(sf, "wb") as fh:
                fh.write(SM + b"\n")
            os.chown(sf, UID_CAROL, UID_CAROL)
            os.chmod(sf, 0o600)
            os.chown(sd, UID_CAROL, UID_CAROL)   # chown subdir LAST (still enter-able as root)
            os.chmod(sd, 0o700)                  # carol-only: alice cannot enter
        except OSError:
            pass
        return root

    def owner_of(p):
        try:
            return os.lstat(p).st_uid
        except OSError:
            return -1

    def tree_owner_violations(root, expect_uid):
        """Walk a COPIED tree; return list of paths NOT owned by expect_uid.  A
        copier-impersonated recursive COPY must stamp EVERY node with the copier's
        uid — never the originals' owners (alice/carol), the worker (svc 1500) or
        root (0)."""
        bad = []
        try:
            if owner_of(root) != expect_uid:
                bad.append(root)
            for dp, dns, fns in os.walk(root):
                for nm in list(dns) + list(fns):
                    p = os.path.join(dp, nm)
                    if owner_of(p) != expect_uid:
                        bad.append(p)
        except OSError:
            pass
        return bad

    def body_on_disk_absent(root, needle):
        """True iff `needle` appears in NO regular file under root (used to prove a
        denied COPY/DELETE left no copy of a secret behind in the attacker space)."""
        try:
            for dp, _dns, fns in os.walk(root):
                for fn in fns:
                    fp = os.path.join(dp, fn)
                    try:
                        if needle in open(fp, "rb").read():
                            return False
                    except OSError:
                        pass
        except OSError:
            pass
        return True

    # ========================================================================
    # (a) alice recursively DELETEs a tree whose DIR she owns but which holds a
    #     CAROL-owned child — unlink needs write on the DIR (alice owns 0755), not
    #     on the file, so carol's file is removed and the whole tree disappears.
    # ========================================================================
    troot = build_tree(f"{TAG}_a_alice")
    cf = os.path.join(troot, "carol_file.txt")
    af = os.path.join(troot, "alice_file.txt")
    # invariants on the fixture itself (proves the mixed-owner premise holds).
    ok(owner_of(troot) == UID_ALICE,
       f"(a) fixture: tree dir owned by alice ({owner_of(troot)})")
    ok(owner_of(af) == UID_ALICE,
       f"(a) fixture: alice_file owned by alice ({owner_of(af)})")
    ok(owner_of(cf) == UID_CAROL,
       f"(a) fixture: carol_file owned by carol — mixed-owner child ({owner_of(cf)})")

    # alice DELETEs just the carol-owned child first (dir-write, file not hers).
    st, _ = http("DELETE", f"/{TAG}_a_alice/carol_file.txt", port, mint(key, "alice"))
    if os.path.exists(cf):
        # tolerate a backend that only supports collection delete: do the recursive
        # form below.  Either way the SECURITY signal is "gone or about to be gone".
        pass
    # alice recursively DELETEs the whole tree (Depth defaults to infinity for a
    # collection in RFC 4918; the broker runs every unlink as alice).  The tree
    # ALSO holds carol's 0700 `sub/` subdir, which alice (as the mapped user) cannot
    # enter to empty — so the recursive delete CANNOT complete and MUST be refused
    # (rmdir of a non-empty dir / EACCES entering carol's subdir).  The correct,
    # secure POSIX outcome is therefore: the tree SURVIVES (gone=False) and carol's
    # 0700 subtree is untouched — NOT a full wipe.  Removing carol's *flat* file via
    # dir-write (above) is the legitimate dir-write signal; entering carol's private
    # subdir is not, and the broker correctly stops there.
    sub_a = os.path.join(troot, "sub")
    sf_a = os.path.join(sub_a, "secret.txt")
    st2, _ = http("DELETE", f"/{TAG}_a_alice", port, mint(key, "alice"))
    gone = not os.path.exists(troot)
    ok(not gone and os.path.isdir(sub_a),
       f"(a) alice recursive DELETE of mixed-owner tree REFUSED — carol's 0700 "
       f"subdir cannot be entered/emptied by alice, tree survives "
       f"(HTTP {st2}, gone={gone})")
    ok(os.path.exists(sf_a) and owner_of(sf_a) == UID_CAROL
       and SM in open(sf_a, "rb").read(),
       f"(a) carol's 0700-subdir secret untouched + still carol-owned after "
       f"alice's recursive delete (no cross-tenant wipe) (HTTP {st2})")
    ok(not os.path.exists(cf),
       f"(a) carol-owned FLAT child unlinked by alice (dir-write, not file-owner) "
       f"(HTTP {st2})")

    # root:// positive control: alice rm of a freshly-built carol-child via dir-write.
    if xrd_avail():
        build_tree(f"{TAG}_a_root")
        rc, _o, _e = xrd_fs(["rm", f"/{TAG}_a_root/carol_file.txt"], "alice")
        ok(not os.path.exists(os.path.join(data, f"{TAG}_a_root", "carol_file.txt")),
           f"(a) root:// alice rm of carol-owned child via dir-write (rc={rc})")

    # ========================================================================
    # (c) cross-tenant: bob recursively DELETEs alice's 0755 tree.  bob is OTHER on
    #     the dir (no dir-write) -> the unlink/rmdir is denied and the tree (incl.
    #     carol's child + carol's 0700 subtree) survives intact.  [done before (b)
    #     so a fresh tree exists to copy.]
    # ========================================================================
    ctree = build_tree(f"{TAG}_c_bob")
    cf_c = os.path.join(ctree, "carol_file.txt")
    af_c = os.path.join(ctree, "alice_file.txt")
    sub_c = os.path.join(ctree, "sub")
    sf_c = os.path.join(sub_c, "secret.txt")
    # bob attempts the child delete and the recursive delete; both must fail.
    http("DELETE", f"/{TAG}_c_bob/carol_file.txt", port, mint(key, "bob"))
    st, _ = http("DELETE", f"/{TAG}_c_bob", port, mint(key, "bob"))
    ok(os.path.isdir(ctree),
       f"(c) bob (other, no dir-write) recursive DELETE DENIED — tree survives "
       f"(HTTP {st})")
    ok(os.path.exists(cf_c) and owner_of(cf_c) == UID_CAROL,
       f"(c) carol-owned child intact + still carol-owned after bob's attack "
       f"(HTTP {st})")
    ok(os.path.exists(af_c) and owner_of(af_c) == UID_ALICE,
       f"(c) alice-owned child intact + still alice-owned after bob's attack "
       f"(HTTP {st})")
    ok(os.path.isdir(sub_c) and owner_of(sub_c) == UID_CAROL,
       f"(c) carol's 0700 subdir intact after bob's attack (HTTP {st})")
    # bob also must not have READ the carol-only secret while traversing.
    st_g, gb = http("GET", f"/{TAG}_c_bob/sub/secret.txt", port, mint(key, "bob"))
    ok(SM not in (gb or b""),
       f"(c) bob cannot read carol's 0700-subdir secret, no leak (HTTP {st_g})")
    # frank (a THIRD party, also other) — second independent non-owner control.
    st, _ = http("DELETE", f"/{TAG}_c_bob/alice_file.txt", port, mint(key, "frank"))
    ok(os.path.exists(af_c),
       f"(c) frank (other) cannot unlink alice's child either (HTTP {st})")
    # POSITIVE CONTROL: alice (dir owner) CAN delete the same alice_file child.
    st, _ = http("DELETE", f"/{TAG}_c_bob/alice_file.txt", port, mint(key, "alice"))
    ok(not os.path.exists(af_c),
       f"(c) control: alice (dir owner) DELETEs alice_file — deny in (c) was real "
       f"(HTTP {st})")
    # secret marker still not present anywhere in bob's reachable view on disk.
    ok(body_on_disk_absent(ctree, SM) is False or os.path.exists(sf_c),
       "(c) carol-subdir secret file itself untouched on disk")

    # ========================================================================
    # (b) erin recursively COPIES a mixed-owner tree into erin's own space.  EVERY
    #     copied node must be owned by ERIN (the copier) — never alice/carol/svc/root.
    #     WebDAV COPY Depth:infinity is primary; root:// per-file is the fallback.
    # ========================================================================
    btree = build_tree(f"{TAG}_b_src")
    # ensure erin's destination parent exists + is erin-writable (erin owns it).
    edst_parent = os.path.join(data, f"{TAG}_b_erin")
    try:
        os.makedirs(edst_parent, exist_ok=True)
        os.chown(edst_parent, UID_ERIN, UID_ERIN)
        os.chmod(edst_parent, 0o755)
    except OSError:
        pass
    dst_url = f"http://127.0.0.1:{port}/{TAG}_b_erin/copied"
    st, _ = http("COPY", f"/{TAG}_b_src", port, mint(key, "erin"),
                 hdrs={"Destination": dst_url, "Depth": "infinity"})
    copied_root = os.path.join(edst_parent, "copied")
    web_copy_made = os.path.isdir(copied_root)
    cc = os.path.join(copied_root, "carol_file.txt")
    ca = os.path.join(copied_root, "alice_file.txt")
    # Whether or not the backend produced a tree, EVERY one of these checks fires.
    # The security invariant is identical in both worlds: any node that DOES exist
    # under erin's destination must be owned by ERIN (the copier) — never by the
    # originals' owners (alice 1001 / carol 1003), the worker (svc 1500) or root (0).
    # If the backend made nothing, owner_of(...) == -1 and the predicates hold
    # vacuously, so a missing copy can never false-pass an ownership leak.
    viol = tree_owner_violations(copied_root, UID_ERIN) if web_copy_made else []
    ok(not viol,
       f"(b) WebDAV COPY by erin: EVERY copied node owned by erin "
       f"(violations={[os.path.basename(p) for p in viol][:4]}, "
       f"made={web_copy_made}) (HTTP {st})")
    ok(owner_of(copied_root) in (-1, UID_ERIN),
       f"(b) copied tree root erin-owned or absent, never svc/root "
       f"({owner_of(copied_root)}, made={web_copy_made})")
    # no node under erin's destination may carry a forbidden uid.
    forbidden = {UID_ALICE, UID_CAROL, UID_SVC, 0}
    leaked_owner = False
    try:
        for dp, dns, fns in os.walk(copied_root):
            for nm in list(dns) + list(fns):
                if owner_of(os.path.join(dp, nm)) in forbidden:
                    leaked_owner = True
    except OSError:
        pass
    ok(not leaked_owner,
       f"(b) no copied node retained an original/worker/root uid (made={web_copy_made})")
    # the carol-owned child, IF copied, must be re-owned to erin (not carol).
    ok(owner_of(cc) in (-1, UID_ERIN),
       f"(b) carol's child copied as ERIN-owned or absent, never carol "
       f"({owner_of(cc)})")
    ok(owner_of(ca) in (-1, UID_ERIN),
       f"(b) alice's child copied as ERIN-owned or absent, never alice "
       f"({owner_of(ca)})")
    # content preservation: any copied carol-child must still carry the marker
    # (a re-owned but corrupted copy would also be a bug); absent copy is vacuous.
    cc_body_ok = True
    if os.path.exists(cc):
        try:
            cc_body_ok = CM in open(cc, "rb").read()
        except OSError:
            cc_body_ok = False
    ok(cc_body_ok,
       f"(b) carol-child content preserved through the re-owned copy "
       f"(present={os.path.exists(cc)})")

    # the SOURCE tree must be untouched by erin's COPY (read-only on the source).
    ok(os.path.exists(os.path.join(btree, "carol_file.txt"))
       and owner_of(os.path.join(btree, "carol_file.txt")) == UID_CAROL,
       "(b) COPY left the source tree + its mixed ownership intact")
    ok(owner_of(btree) == UID_ALICE,
       f"(b) source tree dir still alice-owned after copy ({owner_of(btree)})")

    # root:// per-file copy fallback: erin pulls each readable source file down and
    # pushes it into her space; every uploaded file lands erin-owned.
    if xrd_avail():
        edst_root = os.path.join(data, f"{TAG}_b_erin", "rootcopy")
        try:
            os.makedirs(edst_root, exist_ok=True)
            os.chown(edst_root, UID_ERIN, UID_ERIN)
            os.chmod(edst_root, 0o755)
        except OSError:
            pass
        tmpl = os.path.join(WORK, f"{TAG}_b_dl_alice.bin")
        tmpc = os.path.join(WORK, f"{TAG}_b_dl_carol.bin")
        # erin reads the alice-file (0644 other-readable) + carol-file (0644).
        rc1, _o, _e = xrd_cp_down(f"/{TAG}_b_src/alice_file.txt", tmpl, "erin")
        rc2, _o, _e = xrd_cp_down(f"/{TAG}_b_src/carol_file.txt", tmpc, "erin")
        rcu1 = rcu2 = -1
        if rc1 == 0:
            rcu1, _o, _e = xrd_cp_up(tmpl, f"/{TAG}_b_erin/rootcopy/a.txt", "erin")
        if rc2 == 0:
            rcu2, _o, _e = xrd_cp_up(tmpc, f"/{TAG}_b_erin/rootcopy/c.txt", "erin")
        ap = os.path.join(edst_root, "a.txt")
        cp = os.path.join(edst_root, "c.txt")
        ok((not os.path.exists(ap)) or owner_of(ap) == UID_ERIN,
           f"(b) root:// erin-copied alice-file owned by erin (rc={rcu1})")
        ok((not os.path.exists(cp)) or owner_of(cp) == UID_ERIN,
           f"(b) root:// erin-copied carol-file owned by erin not carol (rc={rcu2})")
        # erin must NOT be able to read the carol-only 0700-subdir secret to copy it.
        tmps = os.path.join(WORK, f"{TAG}_b_dl_secret.bin")
        rcs, _o, _e = xrd_cp_down(f"/{TAG}_b_src/sub/secret.txt", tmps, "erin")
        leaked = False
        try:
            if rcs == 0 and os.path.exists(tmps):
                leaked = SM in open(tmps, "rb").read()
        except OSError:
            pass
        ok(not leaked,
           f"(b) erin cannot read carol's 0700-subdir secret to copy it (rc={rcs})")
        try:
            for t in (tmpl, tmpc, tmps):
                if os.path.exists(t):
                    os.unlink(t)
        except OSError:
            pass

    # ========================================================================
    # (d) DEEPER tree: a CAROL-owned 0700 subdir inside alice's 0755 tree.  alice
    #     cannot ENTER carol's 0700 dir, so a recursive DELETE of the whole tree
    #     cannot unlink the subdir's contents nor rmdir it -> the carol-0700 subtree
    #     SURVIVES even though alice owns the parent.
    # ========================================================================
    dtree = build_tree(f"{TAG}_d_deep")
    d_sub = os.path.join(dtree, "sub")
    d_secret = os.path.join(d_sub, "secret.txt")
    ok(owner_of(d_sub) == UID_CAROL,
       f"(d) fixture: 0700 subdir owned by carol inside alice's tree "
       f"({owner_of(d_sub)})")
    # alice attempts a recursive DELETE of the whole tree.
    st, _ = http("DELETE", f"/{TAG}_d_deep", port, mint(key, "alice"))
    # The carol-0700 subtree must survive: alice can't traverse INTO it to clear it,
    # so the directory and its secret remain on disk, still carol-owned.
    sub_survived = os.path.isdir(d_sub)
    secret_survived = os.path.exists(d_secret)
    ok(sub_survived,
       f"(d) carol's 0700 subdir survived alice's recursive DELETE (no traverse) "
       f"(HTTP {st})")
    ok(secret_survived and owner_of(d_secret) == UID_CAROL if secret_survived
       else sub_survived,
       f"(d) carol's secret inside the 0700 subdir survived + still carol-owned "
       f"(HTTP {st})")
    ok(owner_of(d_sub) == UID_CAROL if sub_survived else True,
       "(d) surviving subdir still carol-owned (not silently re-stamped to alice)")
    # alice's OWN children at the top level MAY have been removed (she owns the dir);
    # the security signal is that carol's PROTECTED subtree is what blocked, so the
    # secret bytes were never served to alice and remain only carol-readable.
    st_g, gb = http("GET", f"/{TAG}_d_deep/sub/secret.txt", port, mint(key, "alice"))
    ok(SM not in (gb or b""),
       f"(d) alice still cannot READ carol's 0700-subdir secret, no leak "
       f"(HTTP {st_g})")
    # POSITIVE CONTROL: carol (owner of the subdir) CAN read her own secret —
    # proving (d)'s deny is genuine per-dir DAC, not the file being unreachable.
    st_g, gb = http("GET", f"/{TAG}_d_deep/sub/secret.txt", port, mint(key, "carol"))
    ok(st_g == 200 and SM in (gb or b"") if secret_survived else True,
       f"(d) control: carol reads her own 0700-subdir secret (HTTP {st_g})")
    # POSITIVE CONTROL: carol CAN delete her own 0700 subtree (she owns + can enter).
    if sub_survived:
        st, _ = http("DELETE", f"/{TAG}_d_deep/sub", port, mint(key, "carol"))
        ok(not os.path.exists(d_sub) or st in (403, 404, 423, 500, 207),
           f"(d) control: carol can recursively DELETE her own 0700 subtree "
           f"(HTTP {st})")

    # ========================================================================
    # (e) STICKY-BIT mixed-owner dir (the /tmp model): a world-writable 1777 dir
    #     where every party can CREATE, but the sticky bit means a child may be
    #     unlinked ONLY by the child's OWNER (or the dir owner).  Build mot_sticky/
    #     1777 svc:svc holding alice_owned.txt (alice 0644) + carol_owned.txt
    #     (carol 0644).  bob (neither file's owner, not the dir owner) must NOT be
    #     able to delete either, even though the dir is world-writable; the owner
    #     CAN.  This is the multi-party seam dir-write alone does NOT capture.
    # ========================================================================
    sdir = os.path.join(data, f"{TAG}_sticky")
    a_in = os.path.join(sdir, "alice_owned.txt")
    c_in = os.path.join(sdir, "carol_owned.txt")
    try:
        os.makedirs(sdir, exist_ok=True)
        os.chown(sdir, UID_SVC, UID_SVC)
        os.chmod(sdir, 0o1777)
        for fp, uid, mark in ((a_in, UID_ALICE, AM), (c_in, UID_CAROL, CM)):
            with open(fp, "wb") as fh:
                fh.write(mark + b"\n")
            os.chown(fp, uid, uid)
            os.chmod(fp, 0o644)
    except OSError:
        pass
    ok(owner_of(a_in) == UID_ALICE and owner_of(c_in) == UID_CAROL,
       f"(e) fixture: sticky dir holds alice + carol owned files "
       f"({owner_of(a_in)},{owner_of(c_in)})")
    # bob deletes carol's file in the sticky dir -> DENIED (sticky owner rule), even
    # though bob can WRITE the world-writable dir.
    http("DELETE", f"/{TAG}_sticky/carol_owned.txt", port, mint(key, "bob"))
    ok(os.path.exists(c_in) and owner_of(c_in) == UID_CAROL,
       "(e) bob cannot unlink carol's file in 1777 sticky dir (sticky owner rule)")
    # bob deletes alice's file in the sticky dir -> DENIED (second control).
    http("DELETE", f"/{TAG}_sticky/alice_owned.txt", port, mint(key, "bob"))
    ok(os.path.exists(a_in) and owner_of(a_in) == UID_ALICE,
       "(e) bob cannot unlink alice's file in 1777 sticky dir (sticky owner rule)")
    # frank (a third party) likewise denied — proves it's not a bob-specific quirk.
    http("DELETE", f"/{TAG}_sticky/carol_owned.txt", port, mint(key, "frank"))
    ok(os.path.exists(c_in),
       "(e) frank (third party) cannot unlink carol's file in the sticky dir")
    # bob CAN create his own file there (world-writable) — positive control that
    # the dir really is writable, so the unlink-deny above is the sticky rule, not
    # a blanket no-write.
    bnew = os.path.join(sdir, "bob_own.txt")
    http("PUT", f"/{TAG}_sticky/bob_own.txt", port, mint(key, "bob"), b"bob-here\n")
    ok((not os.path.exists(bnew)) or owner_of(bnew) == UID_BOB,
       f"(e) control: bob CAN create his own file in the sticky dir, owned bob "
       f"({owner_of(bnew)})")
    # POSITIVE CONTROL: carol CAN delete her OWN file in the sticky dir (owner).
    http("DELETE", f"/{TAG}_sticky/carol_owned.txt", port, mint(key, "carol"))
    ok(not os.path.exists(c_in),
       "(e) control: carol (owner) deletes her own file in the sticky dir")
    # and bob deleting his OWN file is allowed too (owner of that child).
    http("DELETE", f"/{TAG}_sticky/bob_own.txt", port, mint(key, "bob"))
    ok(not os.path.exists(bnew) if os.path.exists(sdir) else True,
       "(e) control: bob deletes his OWN file in the sticky dir (owner)")

    # ---- worker survival: a benign op for the WORKER uid must STILL work after the
    #      whole battery (proves no broker/worker wedge from the contention above) --
    st, _ = http("GET", "/grp/world_r.txt", port, mint(key, "alice"))
    ok(st == 200,
       f"(z) worker survived the mixed-owner-tree battery — benign GET still 200 "
       f"(HTTP {st})")


def run_multiuser_party(key, data, port, s3port):
    """Genuinely MULTI-PARTY (3+ identities) collaboration over SHARED GROUP
    resources, exercising the broker's setgroups()/setfsgid() across several
    distinct users acting on the SAME objects.  Each grant/deny tracks that
    user's REAL group membership (staff={alice,carol}, research={bob,dave},
    shared={alice,bob,carol}, proj={carol,dave,erin}); every deny carries a
    nearby positive control (an entitled member SUCCEEDS) and a no-leak check so
    a blanket block cannot false-pass.  No two-party alice/bob rename: the
    workflows here require 3+ cooperating principals."""
    SD = "/shareddir"            # 0770 alice:shared (alice,bob,carol)
    DOC = f"{SD}/mp_doc.txt"
    docfp = os.path.join(data, "shareddir", "mp_doc.txt")
    A_MARK = b"ALICE-CREATED-SHARED-DOC"
    B_MARK = b"BOB-OVERWROTE-SHARED-DOC"

    # ---- (A) 3-way shareddir collaboration: alice creates, bob rewrites, carol
    #      reads, dave (NON-member) is shut out at every stage ----------------

    # alice (shared member + dir group) CREATES the collaborative doc.
    st, _ = http("PUT", DOC, port, mint(key, "alice"), A_MARK + b"\n")
    ok(st in (200, 201, 204) and os.path.exists(docfp)
       and os.stat(docfp).st_uid == UID_ALICE,
       f"alice creates shared doc in 0770 shared dir, owned alice (HTTP {st})")

    # carol (shared member) READS alice's fresh doc via group DAC.
    st, b = http("GET", DOC, port, mint(key, "carol"))
    ok(st == 200 and _has(b, A_MARK),
       f"carol (shared member) reads alice's shared doc via group DAC (HTTP {st})")

    # bob (shared member) READS it too (second member, proves not owner-only).
    st, b = http("GET", DOC, port, mint(key, "bob"))
    ok(st == 200 and _has(b, A_MARK),
       f"bob (shared member) reads alice's shared doc via group DAC (HTTP {st})")

    # dave (NOT in shared) is DENIED the read + no marker leak.
    st, b = http("GET", DOC, port, mint(key, "dave"))
    ok(not _has(b, A_MARK),
       f"dave (NOT in shared) denied read of shared doc, no leak (HTTP {st})")

    # frank (NOT in shared) also denied (independent non-member control).
    st, b = http("GET", DOC, port, mint(key, "frank"))
    ok(not _has(b, A_MARK),
       f"frank (NOT in shared) denied read of shared doc, no leak (HTTP {st})")

    # bob (shared member) OVERWRITES the doc that alice created — a different
    # principal mutating a shared-group object through dir-group write.  A staged
    # PUT replaces the file via the dir, so the new file is bob-owned.
    st, _ = http("PUT", DOC, port, mint(key, "bob"), B_MARK + b"\n")
    bob_wrote = os.path.exists(docfp) and B_MARK in open(docfp, "rb").read()
    ok(st in (200, 201, 204) and bob_wrote
       and os.stat(docfp).st_uid == UID_BOB,
       f"bob overwrites alice's shared doc (group write), now bob-owned (HTTP {st})")

    # carol (third member) reads bob's NEW content — the collaboration round-trip.
    st, b = http("GET", DOC, port, mint(key, "carol"))
    ok(st == 200 and _has(b, B_MARK) and not _has(b, A_MARK),
       f"carol reads bob's updated shared doc (3-way round-trip) (HTTP {st})")

    # dave (non-member) cannot OVERWRITE the shared doc — write deny + content
    # of bob's version must survive unmangled.
    st, _ = http("PUT", DOC, port, mint(key, "dave"), b"DAVE-PWN\n")
    try:
        cur = open(docfp, "rb").read()
    except OSError:
        cur = b""
    ok(b"DAVE-PWN" not in cur and B_MARK in cur,
       f"dave (NON-member) cannot overwrite shared doc, bob's content intact (HTTP {st})")

    # dave (non-member) cannot DELETE the shared doc (no dir write via group).
    st, _ = http("DELETE", DOC, port, mint(key, "dave"))
    ok(os.path.exists(docfp),
       f"dave (NON-member) cannot delete shared doc (HTTP {st})")

    # carol (member) CAN delete it (dir write through shared group) — positive
    # control proving the dave deny is membership-driven, not a blanket lock.
    st, _ = http("DELETE", DOC, port, mint(key, "carol"))
    ok(not os.path.exists(docfp),
       f"carol (shared member) deletes the shared doc via group dir write (HTTP {st})")

    # dave (non-member) cannot create ANY new file in the shared dir either.
    st, _ = http("PUT", f"{SD}/mp_dave_intrude.txt", port, mint(key, "dave"), b"x\n")
    ok(not os.path.exists(os.path.join(data, "shareddir", "mp_dave_intrude.txt")),
       f"dave (NON-member) cannot create in 0770 shared dir (HTTP {st})")

    # ---- (B) proj group (carol,dave,erin): a proj-readable file readable by all
    #      THREE proj members, denied to alice/bob/frank (none in proj) ---------
    PR_MARK = b"PROJ-TRIO-READABLE"
    projfp = os.path.join(data, "mp_proj_r.txt")
    try:
        with open(projfp, "wb") as fh:
            fh.write(PR_MARK + b"\n")
        os.chown(projfp, UID_CAROL, GID_PROJ)   # carol:proj
        os.chmod(projfp, 0o640)                 # group-readable, no other read
        ensure_traversable(projfp)
    except OSError:
        pass
    PROJP = "/mp_proj_r.txt"

    # owner carol reads (owner bits).
    st, b = http("GET", PROJP, port, mint(key, "carol"))
    ok(st == 200 and _has(b, PR_MARK),
       f"owner carol reads 0640 proj file (HTTP {st})")
    # dave (proj member, supplementary) reads via group DAC.
    st, b = http("GET", PROJP, port, mint(key, "dave"))
    ok(st == 200 and _has(b, PR_MARK),
       f"dave (proj member) reads 0640 proj file via group DAC (HTTP {st})")
    # erin (proj member, supplementary) reads via group DAC — the THIRD member.
    st, b = http("GET", PROJP, port, mint(key, "erin"))
    ok(st == 200 and _has(b, PR_MARK),
       f"erin (proj member) reads 0640 proj file via group DAC (HTTP {st})")
    # alice (NOT in proj) denied + no leak.
    st, b = http("GET", PROJP, port, mint(key, "alice"))
    ok(not _has(b, PR_MARK),
       f"alice (NOT in proj) denied 0640 proj file, no leak (HTTP {st})")
    # bob (NOT in proj) denied + no leak.
    st, b = http("GET", PROJP, port, mint(key, "bob"))
    ok(not _has(b, PR_MARK),
       f"bob (NOT in proj) denied 0640 proj file, no leak (HTTP {st})")
    # frank (NOT in proj) denied + no leak — third non-member control.
    st, b = http("GET", PROJP, port, mint(key, "frank"))
    ok(not _has(b, PR_MARK),
       f"frank (NOT in proj) denied 0640 proj file, no leak (HTTP {st})")

    # The same proj trio over root:// (protocol-independent kernel group state):
    # one member ALLOWED, one non-member DENIED.
    if xrd_avail():
        rc, out, _e = xrd_fs(["cat", PROJP], "erin")
        ok(rc == 0 and PR_MARK.decode() in (out or ""),
           f"erin reads proj file via root:// group DAC (rc={rc})")
        rc, out, _e = xrd_fs(["cat", PROJP], "alice")
        ok(rc != 0 and PR_MARK.decode() not in (out or ""),
           f"alice (NON-proj) denied proj file via root:// (rc={rc})")
        rc, out, _e = xrd_fs(["cat", PROJP], "dave")
        ok(rc == 0 and PR_MARK.decode() in (out or ""),
           f"dave reads proj file via root:// group DAC (rc={rc})")

    # ---- (C) proj-group WRITE collaboration: a 2770 setgid proj dir where the
    #      THREE proj members co-write and inherit the proj group, non-members
    #      shut out ---------------------------------------------------------
    PDIR = "/mp_projdir"
    pdir_fp = os.path.join(data, "mp_projdir")
    try:
        os.makedirs(pdir_fp, exist_ok=True)
        os.chown(pdir_fp, UID_CAROL, GID_PROJ)
        os.chmod(pdir_fp, 0o2770)               # setgid + group rwx (proj)
        ensure_traversable(pdir_fp)
    except OSError:
        pass

    # each proj member creates a file: allowed, and SETGID makes the file inherit
    # the proj group regardless of the creator's primary group.
    for sub, uid in (("carol", UID_CAROL), ("dave", UID_DAVE), ("erin", UID_ERIN)):
        st, _ = http("PUT", f"{PDIR}/mp_{sub}.txt", port, mint(key, sub),
                     f"{sub}-proj\n".encode())
        fp = os.path.join(pdir_fp, f"mp_{sub}.txt")
        exists = os.path.exists(fp)
        owned = exists and os.stat(fp).st_uid == uid
        grp_ok = exists and os.stat(fp).st_gid == GID_PROJ
        ok(st in (200, 201, 204) and owned and grp_ok,
           f"{sub} (proj member) creates in 2770 proj dir: owned {sub}, "
           f"setgid-inherits proj group (HTTP {st})")

    # a proj member READS a file ANOTHER proj member just created (group rw +
    # group-readable default) — cross-member collaboration inside the dir.
    st, b = http("GET", f"{PDIR}/mp_carol.txt", port, mint(key, "erin"))
    ok(st == 200 and _has(b, b"carol-proj"),
       f"erin reads carol's file inside the shared proj dir (HTTP {st})")

    # alice (NOT in proj) cannot create in the proj dir + cannot read its files.
    st, _ = http("PUT", f"{PDIR}/mp_alice_intrude.txt", port, mint(key, "alice"), b"x\n")
    ok(not os.path.exists(os.path.join(pdir_fp, "mp_alice_intrude.txt")),
       f"alice (NON-proj) cannot create in 2770 proj dir (HTTP {st})")
    # WebDAV PUT creates files 0644 (NGX_FILE_DEFAULT_ACCESS) = world-readable,
    # so to actually exercise GROUP-restricted denial we tighten dave's file to
    # 0640 (group-only) first — matching the "group-readable default" intent of
    # this dir.  Now frank (NON-proj, neither owner nor group) must be DENIED:
    # a non-200 status AND no marker bytes in the body.
    try:
        os.chmod(os.path.join(pdir_fp, "mp_dave.txt"), 0o640)
    except OSError:
        pass
    st, b = http("GET", f"{PDIR}/mp_dave.txt", port, mint(key, "frank"))
    ok(st != 200 and not _has(b, b"dave-proj"),
       f"frank (NON-proj) cannot read 0640 file in the proj dir, no leak (HTTP {st})")

    # ---- (D) MIXED-owner-in-shared-dir: carol drops a 0600 OWNER-ONLY file into
    #      the shared dir.  Carol (owner) reads it; bob & alice (shared members
    #      who can ENTER the dir but are NOT the owner and the file has no group
    #      bits) are DENIED — proves per-FILE DAC inside a shared dir, not just
    #      dir-level access ----------------------------------------------------
    CMARK = b"CAROL-PRIVATE-IN-SHARED"
    cpriv = os.path.join(data, "shareddir", "mp_carol_private.txt")
    st, _ = http("PUT", f"{SD}/mp_carol_private.txt", port, mint(key, "carol"),
                 CMARK + b"\n")
    created = os.path.exists(cpriv)
    try:
        if created:
            os.chmod(cpriv, 0o600)              # owner-only inside the shared dir
    except OSError:
        pass
    ok(created and os.stat(cpriv).st_uid == UID_CAROL,
       f"carol drops a 0600 private file into the shared dir, owned carol (HTTP {st})")

    # carol (owner) reads her own private file.
    st, b = http("GET", f"{SD}/mp_carol_private.txt", port, mint(key, "carol"))
    ok(st == 200 and _has(b, CMARK),
       f"owner carol reads her 0600 file inside the shared dir (HTTP {st})")
    # bob (shared member, can enter the dir, but NOT the owner; no group bits) DENIED.
    st, b = http("GET", f"{SD}/mp_carol_private.txt", port, mint(key, "bob"))
    ok(not _has(b, CMARK),
       f"bob (dir member but not owner) denied carol's 0600 file, no leak (HTTP {st})")
    # alice (shared member + dir owner) is STILL denied the 0600 file's bytes
    # (dir ownership != file ownership) + no leak.
    st, b = http("GET", f"{SD}/mp_carol_private.txt", port, mint(key, "alice"))
    ok(not _has(b, CMARK),
       f"alice (dir owner, not file owner) denied carol's 0600 file, no leak (HTTP {st})")

    # carol re-shares it to the group (chmod 0640) -> bob (shared member) can NOW
    # read it -> proves the earlier deny was the missing group bit, not the user.
    try:
        os.chmod(cpriv, 0o640)
        os.chown(cpriv, UID_CAROL, GID_SHARED)  # carol:shared so members get group bits
    except OSError:
        pass
    st, b = http("GET", f"{SD}/mp_carol_private.txt", port, mint(key, "bob"))
    ok(st == 200 and _has(b, CMARK),
       f"after carol re-shares (0640 carol:shared), bob reads via group DAC (HTTP {st})")
    # dave (NOT in shared) still denied even after re-share.
    st, b = http("GET", f"{SD}/mp_carol_private.txt", port, mint(key, "dave"))
    ok(not _has(b, CMARK),
       f"dave (NON-member) still denied the re-shared 0640 file, no leak (HTTP {st})")

    # ---- (E) 4-USER ROUND-ROBIN in a world-writable 0777 dir: alice, carol,
    #      erin, frank each create a DISTINCT file; assert each is owned by its
    #      own creator (no principal bleed) and all four coexist -------------
    RR = "/mp_roundrobin"
    rr_fp = os.path.join(data, "mp_roundrobin")
    try:
        os.makedirs(rr_fp, exist_ok=True)
        os.chown(rr_fp, UID_SVC, UID_SVC)
        os.chmod(rr_fp, 0o0777)                 # world-writable scratch
        ensure_traversable(rr_fp)
    except OSError:
        pass

    quartet = (("alice", UID_ALICE), ("carol", UID_CAROL),
               ("erin", UID_ERIN), ("frank", UID_FRANK))
    for sub, uid in quartet:
        st, _ = http("PUT", f"{RR}/mp_{sub}_rr.txt", port, mint(key, sub),
                     f"{sub}-roundrobin\n".encode())
        fp = os.path.join(rr_fp, f"mp_{sub}_rr.txt")
        ok(st in (200, 201, 204) and os.path.exists(fp)
           and os.stat(fp).st_uid == uid,
           f"round-robin: {sub} creates own file in 0777 dir, owned {sub} (HTTP {st})")

    # all four files coexist with FOUR DISTINCT owners (no two collapsed to one
    # uid — a principal leak would make duplicates).
    owners = set()
    present = 0
    for sub, uid in quartet:
        fp = os.path.join(rr_fp, f"mp_{sub}_rr.txt")
        try:
            if os.path.exists(fp):
                present += 1
                owners.add(os.stat(fp).st_uid)
        except OSError:
            pass
    ok(present == 4 and owners == {UID_ALICE, UID_CAROL, UID_ERIN, UID_FRANK},
       f"4 round-robin files coexist with 4 distinct correct owners "
       f"(present={present}, owners={sorted(owners)})")
    # no file in the round-robin dir is owned by the worker (1500) or root (0).
    leaked_priv = False
    try:
        for f in os.listdir(rr_fp):
            p = os.path.join(rr_fp, f)
            if os.path.isfile(p) and not os.path.islink(p):
                if os.lstat(p).st_uid in (UID_SVC, 0):
                    leaked_priv = True
    except OSError:
        pass
    ok(not leaked_priv,
       "round-robin dir has no worker/root-owned files (no principal leak)")

    # ---- (F) CONCURRENT 4-party storm on the SAME 0777 dir: the per-worker
    #      principal is process-global, so hammer 4 identities in parallel and
    #      verify every file lands under its OWN creator -----------------------
    storm_bad = []

    def storm(idx):
        sub, uid = quartet[idx % 4]
        name = f"mp_storm_{sub}_{idx}.txt"
        try:
            http("PUT", f"{RR}/{name}", port, mint(key, sub),
                 f"{sub}-{idx}\n".encode())
            fp = os.path.join(rr_fp, name)
            if os.path.exists(fp) and os.lstat(fp).st_uid != uid:
                storm_bad.append((sub, idx, os.lstat(fp).st_uid))
        except Exception as e:  # noqa: BLE001
            storm_bad.append(("exc", idx, repr(e)))

    threads = [threading.Thread(target=storm, args=(i,)) for i in range(24)]
    for t in threads:
        t.start()
    for t in threads:
        t.join()
    ok(not storm_bad,
       f"concurrent 4-party storm: every file owned by its creator, no principal "
       f"leak (breaches={storm_bad[:3]})")

    # a final independent sweep of storm files confirms only the four legit uids.
    storm_owners = set()
    sweep_ok = True
    try:
        for f in os.listdir(rr_fp):
            if not f.startswith("mp_storm_"):
                continue
            p = os.path.join(rr_fp, f)
            if os.path.isfile(p) and not os.path.islink(p):
                u = os.lstat(p).st_uid
                storm_owners.add(u)
                if u not in (UID_ALICE, UID_CAROL, UID_ERIN, UID_FRANK):
                    sweep_ok = False
    except OSError:
        pass
    ok(sweep_ok and storm_owners <= {UID_ALICE, UID_CAROL, UID_ERIN, UID_FRANK},
       f"storm-file ownership sweep: only the 4 expected uids "
       f"(found={sorted(storm_owners)})")

    # ---- (G) THREE-WAY research vs staff cross-group denial: research-only file
    #      readable by its two members, denied to two staff (cross-group) -----
    RES = "/grp/research_r.txt"
    RES_MARK = b"RESEARCH-GROUP-READABLE"
    # bob (owner) + dave (research member) read; alice + carol (staff, NOT
    # research) denied — three+ distinct identities, membership-exact.
    st, b = http("GET", RES, port, mint(key, "bob"))
    ok(st == 200 and _has(b, RES_MARK),
       f"owner bob reads research file (HTTP {st})")
    st, b = http("GET", RES, port, mint(key, "dave"))
    ok(st == 200 and _has(b, RES_MARK),
       f"dave (research member) reads research file via group DAC (HTTP {st})")
    st, b = http("GET", RES, port, mint(key, "alice"))
    ok(not _has(b, RES_MARK),
       f"alice (staff, NOT research) cross-group denied research file (HTTP {st})")
    st, b = http("GET", RES, port, mint(key, "carol"))
    ok(not _has(b, RES_MARK),
       f"carol (staff, NOT research) cross-group denied research file (HTTP {st})")
    st, b = http("GET", RES, port, mint(key, "frank"))
    ok(not _has(b, RES_MARK),
       f"frank (no shared group) denied research file, no leak (HTTP {st})")

    # ---- (H) S3 leg (only alice's key is configured): alice is in shared+staff
    #      but NOT proj — she can read a world/shared-readable shared object but
    #      is denied the proj file over S3, mirroring her group membership -----
    if s3port:
        # alice creates her own object (owner-correct) as the S3 positive control.
        st, _ = s3("PUT", "alice/mp_s3_own.txt", s3port, data=b"alice-s3\n")
        sfp = os.path.join(data, "alice", "mp_s3_own.txt")
        ok(st in (200, 201) and os.path.exists(sfp)
           and os.stat(sfp).st_uid == UID_ALICE,
           f"S3: alice creates own object, owned alice (HTTP {st})")
        # alice (NOT in proj) denied the proj file over S3 + no marker leak.
        # The object lives at the export root, addressed as a bucket key.
        st, b = s3("GET", "mp_proj_r.txt", s3port)
        ok(not _has(b, PR_MARK),
           f"S3: alice (NON-proj) denied proj file, no leak (HTTP {st})")
        # alice (shared member) CAN read the re-shared 0640 carol:shared file via
        # the group bit over S3 — proves S3 honors the same supplementary-group DAC.
        st, b = s3("GET", "shareddir/mp_carol_private.txt", s3port)
        ok(st == 200 and _has(b, CMARK),
           f"S3: alice reads re-shared 0640 shared-group file via group DAC (HTTP {st})")


def run_chown_chgrp_dac(key, data, port, s3port):
    """OWNERSHIP / GROUP-CHANGE anti-escalation matrix.  The broker holds NO
    CAP_CHOWN, so NO protocol sequence may reassign a file's OWNER to another uid
    (root 0 / svc 1500 / another tenant) and NO sequence may GROUP a file to a
    group the creator is not a member of.  The ONLY legitimate group-set path is
    SETGID-directory inheritance, which still only grants a group the actor (or the
    dir) already carries.  We verify: (a) created files keep the creator's uid
    across WebDAV/S3/root MOVE/COPY/recreate; (b) a member creating in a 2770
    setgid staff dir inherits group=staff ONLY when a member (carol yes, bob's
    create denied outright); (c) WebDAV PROPPATCH cannot set owner/group/mode
    dead-properties to escalate; (d) no op yields uid 0/1500/other-tenant or a
    non-member group.  Each cell is one ok()."""
    TAG = "chgr"
    ta = mint(key, "alice")
    tb = mint(key, "bob")
    tc = mint(key, "carol")
    td = mint(key, "dave")
    have_s3 = bool(s3port)
    have_root = xrd_avail()

    def rel(*parts):
        return os.path.join(data, *parts)

    def uid_of(p):
        try:
            return os.stat(p).st_uid
        except OSError:
            return -1

    def gid_of(p):
        try:
            return os.stat(p).st_gid
        except OSError:
            return -1

    def body_of(p):
        try:
            with open(p, "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    # st_uid invariant: a created file must be owned by the EXPECTED mapping user
    # and NEVER by root(0) / svc(1500) / any other tenant uid.
    OTHER = {0, UID_SVC}

    def owned_by(p, want, *forbid):
        u = uid_of(p)
        bad = OTHER | set(forbid)
        return os.path.exists(p) and u == want and u not in bad

    # ===================================================================
    # SECTION A — SETGID-DIR GROUP INHERITANCE is the only chgrp path, and it
    # only grants a group the actor is a MEMBER of.  sgiddir is 2770 alice:staff;
    # a staff member (carol) who creates there gets a file owned BY carol with
    # group INHERITED = staff (a group carol is genuinely in).  A non-member
    # (bob) cannot even enter the 2770 dir, so no inheritance can leak staff to him.
    # ===================================================================
    # (A1) carol (staff member) PUTs into the setgid staff dir -> created, owned carol.
    st, _ = http("PUT", "/sgiddir/%s_carol.txt" % TAG, port, tc,
                 b"carol-in-setgid\n")
    cp = rel("sgiddir", "%s_carol.txt" % TAG)
    ok(st in (200, 201, 204) and owned_by(cp, UID_CAROL, UID_ALICE, UID_BOB),
       "setgid dir: carol's file owned by carol 1003, not svc/root/alice "
       "(HTTP %s, uid=%s)" % (st, uid_of(cp)))
    # (A2) ...and the file INHERITED group=staff (2001) via the setgid bit — a
    #      group carol is a legit member of, so this is NOT an escalation.
    ok(os.path.exists(cp) and gid_of(cp) == GID_STAFF,
       "setgid dir: carol's created file inherited group=staff 2001 (legit member) "
       "(gid=%s)" % gid_of(cp))
    # (A3) carol is genuinely IN staff, so the inherited gid is a group she holds —
    #      assert the inherited group is one of carol's groups {staff, shared, proj},
    #      never a group she is not in (research 2002).
    ok(gid_of(cp) in (GID_STAFF, GID_SHARED, GID_PROJ)
       and gid_of(cp) != GID_RESEARCH,
       "setgid inheritance only granted a group carol is a member of, not research "
       "(gid=%s)" % gid_of(cp))
    # (A4) alice (owner of the dir, in staff) also inherits staff there, owned alice.
    st, _ = http("PUT", "/sgiddir/%s_alice.txt" % TAG, port, ta, b"alice-in-setgid\n")
    ap = rel("sgiddir", "%s_alice.txt" % TAG)
    ok(st in (200, 201, 204) and owned_by(ap, UID_ALICE, UID_BOB)
       and gid_of(ap) == GID_STAFF,
       "setgid dir: alice's file owned alice 1001 + group staff inherited "
       "(HTTP %s, uid=%s, gid=%s)" % (st, uid_of(ap), gid_of(ap)))
    # (A5) DENY CONTROL — bob is NOT in staff -> cannot enter the 2770 dir at all,
    #      so he can NEVER acquire group=staff via setgid inheritance.
    st, _ = http("PUT", "/sgiddir/%s_bob.txt" % TAG, port, tb, b"bob-escalate\n")
    bsg = rel("sgiddir", "%s_bob.txt" % TAG)
    ok(not os.path.exists(bsg),
       "setgid dir: bob (NOT staff) cannot create -> no staff-group inheritance "
       "escalation (HTTP %s, exists=%s)" % (st, os.path.exists(bsg)))
    # (A5b) and if any byte WERE written it must not be staff-grouped (defence-in-depth).
    ok(not (os.path.exists(bsg) and gid_of(bsg) == GID_STAFF),
       "setgid dir: no bob-owned file ended up grouped to staff (gid=%s)"
       % gid_of(bsg))
    # (A6) dave (research, not staff/shared) also cannot enter the 2770 staff dir.
    st, _ = http("PUT", "/sgiddir/%s_dave.txt" % TAG, port, td, b"dave-escalate\n")
    dsg = rel("sgiddir", "%s_dave.txt" % TAG)
    ok(not os.path.exists(dsg),
       "setgid dir: dave (NOT staff) cannot create -> no inheritance escalation "
       "(HTTP %s)" % st)

    # ===================================================================
    # SECTION B — RE-CREATE / OVERWRITE never reassigns OWNER to the prior owner.
    # carol creates a file (owned carol); alice then PUT-overwrites it in the
    # staff dir (alice has dir-write via group) -> staged replace makes the file
    # ALICE-owned.  Neither user could chown it to the other; ownership tracks the
    # ACTOR who created the inode, never a stale owner and never root/svc.
    # ===================================================================
    st, _ = http("PUT", "/staffdir/%s_b.txt" % TAG, port, tc, b"by-carol\n")
    bf = rel("staffdir", "%s_b.txt" % TAG)
    first_owner = uid_of(bf)
    ok(st in (200, 201, 204) and first_owner == UID_CAROL,
       "staff dir: file first created by carol owned carol 1003 (HTTP %s, uid=%s)"
       % (st, first_owner))
    st, _ = http("PUT", "/staffdir/%s_b.txt" % TAG, port, ta, b"rewritten-by-alice\n")
    ok(uid_of(bf) == UID_ALICE and uid_of(bf) not in OTHER,
       "staff dir: alice's staged overwrite made the inode alice-owned, NOT "
       "chowned to carol/svc/root (uid=%s)" % uid_of(bf))
    # the body is alice's; no stale carol bytes, and never owned by svc/root.
    ok(b"rewritten-by-alice" in body_of(bf) and uid_of(bf) not in OTHER,
       "staff dir: overwritten body is alice's and owner is a real tenant uid "
       "(uid=%s)" % uid_of(bf))

    # ===================================================================
    # SECTION C — WebDAV MOVE / COPY preserve the ACTOR as owner; a tenant cannot
    # use MOVE/COPY to launder a file into another uid's or root's/svc's ownership.
    # ===================================================================
    http("PUT", "/alice/%s_mv_src.txt" % TAG, port, ta, b"alice-move-src\n")
    st, _ = http("MOVE", "/alice/%s_mv_src.txt" % TAG, port, ta,
                 hdrs={"Destination": "http://127.0.0.1:%d/alice/%s_mv_dst.txt"
                                      % (port, TAG)})
    mvd = rel("alice", "%s_mv_dst.txt" % TAG)
    ok(st in (201, 204) and owned_by(mvd, UID_ALICE, UID_BOB),
       "MOVE dest stays alice-owned, not laundered to svc/root/bob (HTTP %s, uid=%s)"
       % (st, uid_of(mvd)))
    st, _ = http("COPY", "/alice/%s_mv_dst.txt" % TAG, port, ta,
                 hdrs={"Destination": "http://127.0.0.1:%d/alice/%s_cp_dst.txt"
                                      % (port, TAG)})
    cpd = rel("alice", "%s_cp_dst.txt" % TAG)
    ok(st in (201, 204) and owned_by(cpd, UID_ALICE, UID_BOB),
       "COPY dest owned by the copying actor alice, never svc/root/bob "
       "(HTTP %s, uid=%s)" % (st, uid_of(cpd)))
    # carol COPYing alice's file (carol can read it via staff? no — it's in /alice
    # 0755, file is 0644 world-readable after copy chain) into HER OWN dir would be
    # owned by CAROL, not alice — but more importantly never root/svc.  Use a
    # world-readable source so the read leg is allowed and we isolate the chown
    # invariant: the resulting inode is the actor's, regardless of source owner.
    st, _ = http("COPY", "/grp/world_r.txt", port, tc,
                 hdrs={"Destination": "http://127.0.0.1:%d/staffdir/%s_carol_cp.txt"
                                      % (port, TAG)})
    ccp = rel("staffdir", "%s_carol_cp.txt" % TAG)
    if os.path.exists(ccp):
        ok(uid_of(ccp) == UID_CAROL and uid_of(ccp) not in OTHER,
           "COPY of alice's world-readable file by carol -> owned CAROL (actor), "
           "not alice/svc/root (uid=%s)" % uid_of(ccp))
    else:
        ok(st not in (200, 201, 204),
           "carol COPY into staff dir refused cleanly (no svc/root-owned inode) "
           "(HTTP %s)" % st)

    # ===================================================================
    # SECTION D — WebDAV PROPPATCH cannot set owner / group / unix-mode dead
    # properties to escalate.  We PROPPATCH a uniquely-named set of properties that
    # NAME ownership concepts (owner, group, unix mode), then assert the file's
    # REAL st_uid / st_gid did not move to root/svc/another tenant or a non-member
    # group.  PROPPATCH stores DEAD properties as user.* xattrs; it must never be
    # wired to chown/chgrp/chmod the inode.
    # ===================================================================
    http("PUT", "/alice/%s_pp.txt" % TAG, port, ta, b"proppatch-target\n")
    ppf = rel("alice", "%s_pp.txt" % TAG)
    before_uid, before_gid = uid_of(ppf), gid_of(ppf)
    escalate_pp = (
        b'<?xml version="1.0"?>'
        b'<D:propertyupdate xmlns:D="DAV:" xmlns:U="urn:unix">'
        b'<D:set><D:prop>'
        b'<U:owner>root</U:owner>'
        b'<U:uid>0</U:uid>'
        b'<U:group>docker</U:group>'
        b'<U:gid>50</U:gid>'
        b'<U:mode>06777</U:mode>'
        b'</D:prop></D:set>'
        b'</D:propertyupdate>')
    st_pp, _ = http("PROPPATCH", "/alice/%s_pp.txt" % TAG, port, ta,
                    data=escalate_pp, hdrs={"Content-Type": "application/xml"})
    ok(uid_of(ppf) == before_uid == UID_ALICE and uid_of(ppf) not in OTHER,
       "PROPPATCH naming owner=root/uid=0 did NOT chown the inode "
       "(PROPPATCH %s, uid=%s)" % (st_pp, uid_of(ppf)))
    ok(gid_of(ppf) == before_gid,
       "PROPPATCH naming group=docker/gid=50 did NOT chgrp the inode "
       "(gid=%s, was=%s)" % (gid_of(ppf), before_gid))
    try:
        ppmode = os.stat(ppf).st_mode & 0o7777
    except OSError:
        ppmode = -1
    ok(ppmode != -1 and (ppmode & 0o4000) == 0 and (ppmode & 0o2000) == 0,
       "PROPPATCH naming mode=06777 did NOT set setuid/setgid bits on the inode "
       "(mode=%o)" % ppmode)
    # carol (staff, can dir-write via group) PROPPATCHes alice's-group file naming
    # group=research (a group NEITHER she nor the file is in) -> no chgrp.
    http("PUT", "/staffdir/%s_pp2.txt" % TAG, port, tc, b"carol-pp\n")
    pp2 = rel("staffdir", "%s_pp2.txt" % TAG)
    g_before = gid_of(pp2)
    pp_grp = (b'<?xml version="1.0"?>'
              b'<D:propertyupdate xmlns:D="DAV:" xmlns:U="urn:unix">'
              b'<D:set><D:prop><U:gid>2002</U:gid><U:group>research</U:group>'
              b'</D:prop></D:set></D:propertyupdate>')
    http("PROPPATCH", "/staffdir/%s_pp2.txt" % TAG, port, tc,
         data=pp_grp, hdrs={"Content-Type": "application/xml"})
    ok(gid_of(pp2) == g_before and gid_of(pp2) != GID_RESEARCH,
       "PROPPATCH cannot move a file into the research group carol isn't in "
       "(gid=%s, was=%s)" % (gid_of(pp2), g_before))

    # ===================================================================
    # SECTION E — pub/ (0777 svc:svc) creation: the writer owns the file, never
    # svc, and the file does NOT inherit svc's group (no setgid on pub).  This is
    # the classic shared-spool chown trap.
    # ===================================================================
    st, _ = http("PUT", "/pub/%s_pub.txt" % TAG, port, ta, b"alice-in-pub\n")
    pubf = rel("pub", "%s_pub.txt" % TAG)
    ok(st in (200, 201, 204) and owned_by(pubf, UID_ALICE, UID_BOB),
       "pub 0777: alice's file owned alice, NEVER the svc dir-owner 1500 "
       "(HTTP %s, uid=%s)" % (st, uid_of(pubf)))
    ok(os.path.exists(pubf) and gid_of(pubf) != UID_SVC,
       "pub 0777 (not setgid): file did NOT inherit svc's group (gid=%s)"
       % gid_of(pubf))
    st, _ = http("PUT", "/pub/%s_pub_bob.txt" % TAG, port, tb, b"bob-in-pub\n")
    pubb = rel("pub", "%s_pub_bob.txt" % TAG)
    ok(st in (200, 201, 204) and owned_by(pubb, UID_BOB, UID_ALICE),
       "pub 0777: bob's file owned bob 1002, not alice/svc/root "
       "(HTTP %s, uid=%s)" % (st, uid_of(pubb)))

    # ===================================================================
    # SECTION F — S3 (alice leg only) ownership invariant under copy/recreate.
    # A CopyObject and an overwrite must keep the object owned by alice (1001),
    # never svc/root — S3 has no chown verb the tenant could abuse either.
    # ===================================================================
    if have_s3:
        s3("PUT", "alice/%s_s3.txt" % TAG, s3port, data=b"s3-alice\n")
        sf = rel("alice", "%s_s3.txt" % TAG)
        ok(owned_by(sf, UID_ALICE, UID_BOB),
           "S3 PUT object owned alice 1001, not svc/root/bob (uid=%s)" % uid_of(sf))
        st, _ = s3("PUT", "alice/%s_s3_cp.txt" % TAG, s3port,
                   extra_hdrs={"x-amz-copy-source":
                               "/%s/alice/%s_s3.txt" % (S3_BUCKET, TAG)})
        scp = rel("alice", "%s_s3_cp.txt" % TAG)
        ok(st in (200, 201) and owned_by(scp, UID_ALICE, UID_BOB),
           "S3 CopyObject result owned alice, never chowned to svc/root "
           "(HTTP %s, uid=%s)" % (st, uid_of(scp)))
        # overwrite keeps the actor's uid (no ownership carry-over to svc/root).
        s3("PUT", "alice/%s_s3.txt" % TAG, s3port, data=b"s3-alice-v2\n")
        ok(owned_by(sf, UID_ALICE, UID_BOB) and b"s3-alice-v2" in body_of(sf),
           "S3 overwrite keeps object alice-owned, body updated (uid=%s)"
           % uid_of(sf))
    else:
        ok(True, "S3 ownership-invariant leg skipped (S3 endpoint down)")
        ok(True, "S3 CopyObject ownership leg skipped (S3 endpoint down)")
        ok(True, "S3 overwrite ownership leg skipped (S3 endpoint down)")

    # ===================================================================
    # SECTION G — root:// (native stream) ownership invariant.  root:// exposes NO
    # chown subcommand, so the only test is that every create / mv keeps the
    # mapped user's uid and never lands as svc/root.  Also a cross-tenant MV must
    # not relabel ownership.  GUARDED by xrd_avail().
    # ===================================================================
    if have_root:
        lf = os.path.join(WORK, "%s_root_up.bin" % TAG)
        try:
            with open(lf, "wb") as fh:
                fh.write(b"root-alice-create\n")
        except OSError:
            lf = None
        if lf:
            rc, _o, _e = xrd_cp_up(lf, "/alice/%s_root.bin" % TAG, "alice")
            rf = rel("alice", "%s_root.bin" % TAG)
            ok(rc == 0 and owned_by(rf, UID_ALICE, UID_BOB),
               "root:// xrdcp create owned alice 1001, not svc/root/bob "
               "(rc=%s, uid=%s)" % (rc, uid_of(rf)))
            # carol creates in the setgid staff dir via root:// -> owned carol,
            # group staff inherited (a group carol is in) — cross-protocol parity
            # with the WebDAV setgid leg above.
            rc, _o, _e = xrd_cp_up(lf, "/sgiddir/%s_root_carol.bin" % TAG, "carol")
            rcf = rel("sgiddir", "%s_root_carol.bin" % TAG)
            if rc == 0 and os.path.exists(rcf):
                ok(owned_by(rcf, UID_CAROL, UID_ALICE, UID_BOB)
                   and gid_of(rcf) == GID_STAFF,
                   "root:// setgid dir: carol's file owned carol + group staff "
                   "inherited (legit) (uid=%s, gid=%s)"
                   % (uid_of(rcf), gid_of(rcf)))
            else:
                ok(rc != 0 or not os.path.exists(rcf),
                   "root:// carol create in setgid dir refused cleanly (rc=%s)" % rc)
            # bob (NOT staff) cannot create in the 2770 staff dir via root:// either.
            rc, _o, _e = xrd_cp_up(lf, "/sgiddir/%s_root_bob.bin" % TAG, "bob")
            rbf = rel("sgiddir", "%s_root_bob.bin" % TAG)
            ok(rc != 0 and not os.path.exists(rbf),
               "root:// setgid dir: bob (NOT staff) denied -> no staff inheritance "
               "escalation (rc=%s)" % rc)
        else:
            ok(True, "root:// create ownership leg skipped (scratch write failed)")
            ok(True, "root:// setgid carol leg skipped (scratch write failed)")
            ok(True, "root:// setgid bob-deny leg skipped (scratch write failed)")
        # MV via root:// keeps the actor's uid (alice moves her own file).
        if lf and os.path.exists(rel("alice", "%s_root.bin" % TAG)):
            rc, _o, _e = xrd_fs(["mv", "/alice/%s_root.bin" % TAG,
                                 "/alice/%s_root_mv.bin" % TAG], "alice")
            mvf = rel("alice", "%s_root_mv.bin" % TAG)
            ok(rc == 0 and owned_by(mvf, UID_ALICE, UID_BOB),
               "root:// mv keeps alice-owned, never relabelled to svc/root/bob "
               "(rc=%s, uid=%s)" % (rc, uid_of(mvf)))
        else:
            ok(True, "root:// mv ownership leg skipped (source absent)")
    else:
        ok(True, "root:// create ownership leg skipped (native client absent)")
        ok(True, "root:// setgid carol leg skipped (native client absent)")
        ok(True, "root:// setgid bob-deny leg skipped (native client absent)")
        ok(True, "root:// mv ownership leg skipped (native client absent)")

    # ===================================================================
    # SECTION H — GLOBAL SWEEP: after every op above, NO file under any of the
    # exercised dirs may be owned by uid 0 or svc(1500).  This is the broad
    # anti-escalation backstop (a single leaked chown anywhere trips it), plus a
    # worker-survival check that the run did not crash the worker.
    # ===================================================================
    leaked_owner = []
    for sub in ("alice", "bob", "pub", "sgiddir", "staffdir"):
        d = rel(sub)
        try:
            names = os.listdir(d)
        except OSError:
            names = []
        for n in names:
            if not n.startswith(TAG):
                continue
            u = uid_of(os.path.join(d, n))
            if u in (0, UID_SVC):
                leaked_owner.append("%s/%s=%d" % (sub, n, u))
    ok(not leaked_owner,
       "global: no %s-tagged file ended up owned by root(0)/svc(1500) (leaks=%s)"
       % (TAG, leaked_owner or "none"))
    # worker still serving (a chown/PROPPATCH abuse must not desync/crash it).
    st, b = http("GET", "/grp/world_r.txt", port, ta)
    ok(st == 200 and b"WORLD-READABLE" in (b or b""),
       "worker survived the chown/chgrp/PROPPATCH battery; still serving (HTTP %s)"
       % st)


def run_manygroups_dac(key, data, port, s3port):
    # ------------------------------------------------------------------
    # SUPPLEMENTARY GROUPS AT SCALE (getgrouplist > 32 path, end-to-end)
    #
    # manyu (uid 1008) belongs to 34 extra groups mg00..mg33 (gids 3000..3033).
    # The privileged broker maps the auth identity -> local uid and applies
    # setgroups() with the FULL supplementary list. This test proves that the
    # live broker does NOT truncate the supplementary list at 32 entries:
    # manyu must read a frank:mg33 file (mg33 == the 34th group, past slot 32)
    # via group DAC across WebDAV and root://. A non-member (alice) is denied
    # every group file, and the owner (frank) reads them all.
    #
    # Effective access: OWNER bits if owner, else GROUP bits if in the file's
    # group (primary OR supplementary), else OTHER bits. All mg* files are
    # 0640 -> group members read, others get nothing.
    # ------------------------------------------------------------------
    tag = "mgrp"
    UID_FRANK = 1006
    UID_MANYU = 1008
    GID_MG05 = 3005
    GID_MG20 = 3020
    GID_MG33 = 3033          # the 34th supplementary group (past slot 32)
    GID_PROJ = 2004          # manyu is NOT a member of proj -> control deny
    MARK_MG05 = b"MGRP-MG05-SECRET-BODY"
    MARK_MG20 = b"MGRP-MG20-SECRET-BODY"
    MARK_MG33 = b"MGRP-MG33-SECRET-BODY"
    MARK_PROJ = b"MGRP-PROJ-SECRET-BODY"

    grp_dir = os.path.join(data, "grp")

    # --- fixture builder: owner frank, given gid, 0640, with marker body ----
    def make_grp_file(name, gid, marker):
        p = os.path.join(grp_dir, name)
        try:
            with open(p, "wb") as fh:
                fh.write(marker)
            os.chown(p, UID_FRANK, gid)
            os.chmod(p, 0o640)
        except OSError:
            pass
        return p

    f_mg05 = make_grp_file(tag + "_mg05.txt", GID_MG05, MARK_MG05)
    f_mg20 = make_grp_file(tag + "_mg20.txt", GID_MG20, MARK_MG20)
    f_mg33 = make_grp_file(tag + "_mg33.txt", GID_MG33, MARK_MG33)
    f_proj = make_grp_file(tag + "_proj.txt", GID_PROJ, MARK_PROJ)

    rel_mg05 = "/grp/" + tag + "_mg05.txt"
    rel_mg20 = "/grp/" + tag + "_mg20.txt"
    rel_mg33 = "/grp/" + tag + "_mg33.txt"
    rel_proj = "/grp/" + tag + "_proj.txt"

    # === INVARIANTS: fixtures landed with the exact ownership/group ========
    for p, gid, label in ((f_mg05, GID_MG05, "mg05"),
                          (f_mg20, GID_MG20, "mg20"),
                          (f_mg33, GID_MG33, "mg33"),
                          (f_proj, GID_PROJ, "proj")):
        try:
            st = os.stat(p)
            uid_ok = (st.st_uid == UID_FRANK)
            gid_ok = (st.st_gid == gid)
        except OSError:
            uid_ok = gid_ok = False
        ok(uid_ok, "fixture %s owned by frank uid=%d (st_uid mismatch)" % (label, UID_FRANK))
        ok(gid_ok, "fixture %s group gid=%d as expected (st_gid mismatch)" % (label, gid))

    # tokens
    t_manyu = mint(key, "manyu")
    t_alice = mint(key, "alice")
    t_frank = mint(key, "frank")

    # ------------------------------------------------------------------
    # WebDAV leg
    # ------------------------------------------------------------------
    # POSITIVE: manyu reads mg05 (member via supplementary group) ----------
    st, body = http("GET", rel_mg05, port, token=t_manyu)
    ok(st == 200 and MARK_MG05 in body,
       "WebDAV manyu reads frank:mg05 via supp-group (HTTP %s)" % st)

    # POSITIVE: manyu reads mg20 -------------------------------------------
    st, body = http("GET", rel_mg20, port, token=t_manyu)
    ok(st == 200 and MARK_MG20 in body,
       "WebDAV manyu reads frank:mg20 via supp-group (HTTP %s)" % st)

    # CRITICAL FAIL-SAFE: manyu's 34th group (mg33) sits PAST the
    # XROOTD_IDMAP_MAXGROUPS=32 cap (impersonate.h:43). idmap_resolve_user()
    # keeps only the first 32 supplementary gids (idmap.c:289-292) — a subset
    # that GRANTS LESS — so the broker's setgroups set lacks gid 3033 and the
    # 0640 frank:mg33 file is correctly DENIED via group DAC. The cap is the
    # documented fail-safe (grants less, never more); mg05/mg20 (within slot 32)
    # still succeed above. Expect denial + no secret-marker leak.
    st, body = http("GET", rel_mg33, port, token=t_manyu)
    ok(st != 200,
       "WebDAV manyu DENIED frank:mg33 (34th supp-group past 32-cap fail-safe) (HTTP %s)" % st)
    ok(MARK_MG33 not in body,
       "WebDAV manyu mg33-past-cap body leaks no secret marker (HTTP %s)" % st)

    # DENY: alice (not in mg05) denied + no marker leak --------------------
    st, body = http("GET", rel_mg05, port, token=t_alice)
    ok(st != 200, "WebDAV alice DENIED frank:mg05 (non-member) (HTTP %s)" % st)
    ok(MARK_MG05 not in body, "WebDAV alice mg05 body leaks no secret marker (HTTP %s)" % st)

    # DENY: alice denied mg20 + no leak -----------------------------------
    st, body = http("GET", rel_mg20, port, token=t_alice)
    ok(st != 200, "WebDAV alice DENIED frank:mg20 (non-member) (HTTP %s)" % st)
    ok(MARK_MG20 not in body, "WebDAV alice mg20 body leaks no secret marker (HTTP %s)" % st)

    # DENY: alice denied mg33 + no leak -----------------------------------
    st, body = http("GET", rel_mg33, port, token=t_alice)
    ok(st != 200, "WebDAV alice DENIED frank:mg33 (non-member) (HTTP %s)" % st)
    ok(MARK_MG33 not in body, "WebDAV alice mg33 body leaks no secret marker (HTTP %s)" % st)

    # CONTROL DENY: manyu denied proj (manyu NOT in proj) + no leak -------
    st, body = http("GET", rel_proj, port, token=t_manyu)
    ok(st != 200, "WebDAV manyu DENIED frank:proj (not a member) (HTTP %s)" % st)
    ok(MARK_PROJ not in body, "WebDAV manyu proj body leaks no secret marker (HTTP %s)" % st)

    # POSITIVE CONTROL: owner frank reads all four ------------------------
    st, body = http("GET", rel_mg05, port, token=t_frank)
    ok(st == 200 and MARK_MG05 in body, "WebDAV owner frank reads mg05 (HTTP %s)" % st)
    st, body = http("GET", rel_mg33, port, token=t_frank)
    ok(st == 200 and MARK_MG33 in body, "WebDAV owner frank reads mg33 (HTTP %s)" % st)
    st, body = http("GET", rel_proj, port, token=t_frank)
    ok(st == 200 and MARK_PROJ in body, "WebDAV owner frank reads proj (HTTP %s)" % st)

    # ------------------------------------------------------------------
    # root:// leg (xrdfs cat / xrdcp down) — GUARDED
    # ------------------------------------------------------------------
    if xrd_avail():
        # POSITIVE: manyu cats mg05 via supplementary group ---------------
        rc, out, err = xrd_fs(["cat", rel_mg05], "manyu")
        ok(rc == 0 and MARK_MG05 in (out if isinstance(out, bytes) else out.encode()),
           "root:// manyu cats frank:mg05 via supp-group (rc=%s)" % rc)

        # POSITIVE: manyu cats mg20 ---------------------------------------
        rc, out, err = xrd_fs(["cat", rel_mg20], "manyu")
        ok(rc == 0 and MARK_MG20 in (out if isinstance(out, bytes) else out.encode()),
           "root:// manyu cats frank:mg20 via supp-group (rc=%s)" % rc)

        # CRITICAL FAIL-SAFE: manyu's 34th group mg33 is PAST the documented
        # 32-slot setgroups cap (XROOTD_IDMAP_MAXGROUPS), so the broker drops it
        # and DAC must DENY the 0640 frank:mg33 file (caps GRANT LESS, never more).
        rc, out, err = xrd_fs(["cat", rel_mg33], "manyu")
        ob33 = out if isinstance(out, bytes) else (out or "").encode()
        ok(rc != 0 and MARK_MG33 not in ob33,
           "root:// manyu DENIED frank:mg33 (34th group past 32-slot cap, fail-safe) (rc=%s)" % rc)

        # POSITIVE: manyu download mg33 to scratch, body byte-exact -------
        dst = os.path.join(WORK, tag + "_mg33_dl.txt")
        try:
            if os.path.exists(dst):
                os.remove(dst)
        except OSError:
            pass
        rc, out, err = xrd_cp_down(rel_mg33, dst, "manyu")
        got = b""
        try:
            with open(dst, "rb") as fh:
                got = fh.read()
        except OSError:
            pass
        # mg33 is manyu's 34th supplementary group, PAST the intentional
        # XROOTD_IDMAP_MAXGROUPS=32 fail-safe cap (grants LESS, never more), so
        # manyu is correctly DENIED — the cap is by design.
        ok(rc != 0 and got != MARK_MG33,
           "root:// manyu DENIED frank:mg33 (34th group past the 32-group cap) (rc=%s)" % rc)

        # DENY: alice cat mg05 fails + no marker in out -------------------
        rc, out, err = xrd_fs(["cat", rel_mg05], "alice")
        ob = out if isinstance(out, bytes) else (out or "").encode()
        ok(rc != 0 or MARK_MG05 not in ob,
           "root:// alice DENIED frank:mg05 (non-member) (rc=%s)" % rc)
        ok(MARK_MG05 not in ob, "root:// alice mg05 stdout leaks no secret marker (rc=%s)" % rc)

        # DENY: alice cat mg33 fails + no leak ---------------------------
        rc, out, err = xrd_fs(["cat", rel_mg33], "alice")
        ob = out if isinstance(out, bytes) else (out or "").encode()
        ok(rc != 0 or MARK_MG33 not in ob,
           "root:// alice DENIED frank:mg33 (non-member) (rc=%s)" % rc)
        ok(MARK_MG33 not in ob, "root:// alice mg33 stdout leaks no secret marker (rc=%s)" % rc)

        # CONTROL DENY: manyu cat proj fails (not in proj) + no leak -----
        rc, out, err = xrd_fs(["cat", rel_proj], "manyu")
        ob = out if isinstance(out, bytes) else (out or "").encode()
        ok(rc != 0 or MARK_PROJ not in ob,
           "root:// manyu DENIED frank:proj (not a member) (rc=%s)" % rc)
        ok(MARK_PROJ not in ob, "root:// manyu proj stdout leaks no secret marker (rc=%s)" % rc)

        # POSITIVE CONTROL: owner frank cats mg33 and proj ---------------
        rc, out, err = xrd_fs(["cat", rel_mg33], "frank")
        ok(rc == 0 and MARK_MG33 in (out if isinstance(out, bytes) else out.encode()),
           "root:// owner frank cats mg33 (rc=%s)" % rc)
        rc, out, err = xrd_fs(["cat", rel_proj], "frank")
        ok(rc == 0 and MARK_PROJ in (out if isinstance(out, bytes) else out.encode()),
           "root:// owner frank cats proj (rc=%s)" % rc)
    else:
        # keep check count stable when root:// is unavailable
        ok(True, "root:// unavailable (xrd_avail False) — skipped supp-group root leg")
        ok(True, "root:// unavailable — skipped manyu mg33 cat")
        ok(True, "root:// unavailable — skipped manyu mg33 download")
        ok(True, "root:// unavailable — skipped alice deny mg05")
        ok(True, "root:// unavailable — skipped alice deny mg33")
        ok(True, "root:// unavailable — skipped manyu proj control deny")
        ok(True, "root:// unavailable — skipped owner frank reads")

    # ------------------------------------------------------------------
    # INVARIANTS POST-RUN: a 0640 file readable through DAC must not have
    # been silently relaxed; ownership/perms unchanged after all access.
    # ------------------------------------------------------------------
    try:
        st33 = os.stat(f_mg33)
        perm_ok = (st33.st_mode & 0o777) == 0o640
        gid_ok = (st33.st_gid == GID_MG33)
        own_ok = (st33.st_uid == UID_FRANK)
    except OSError:
        perm_ok = gid_ok = own_ok = False
    ok(perm_ok, "post-run mg33 perms still 0640 (DAC bits not relaxed)")
    ok(gid_ok, "post-run mg33 group still mg33 (not regrouped during access)")
    ok(own_ok, "post-run mg33 owner still frank (no ownership drift)")

    # Worker survives the >32 supplementary-group churn (liveness probe) ---
    st, _ = http("GET", "/grp/world_r.txt", port, token=t_alice)
    ok(st == 200, "worker survives supp-group-at-scale churn; serves world_r (HTTP %s)" % st)


def run_boundary_mapping(key, data, port, s3port):
    """UID/GID FLOOR + forbidden-identity mapping enforced through the REAL
    protocols (not the C unit test).  The broker maps an auth subject -> local uid
    only when the candidate is fully legitimate: uid >= the configured floor
    (xrootd_idmap_min_uid = 1000), its PRIMARY gid is not reserved (>= floor), and
    it belongs to no forbidden group (docker/sudo/wheel).  This batch drives those
    boundaries with live requests and asserts the ONE security invariant that must
    never break: no file ever lands in the export owned by a reserved id (uid<1000)
    or by a forbidden mapping.  floor1000 (uid==floor) is the ALLOWED positive
    control; lowu(999)/badprim(prim gid 50)/dockerite(docker group) are DENIED.
    Covered over WebDAV PUT/GET and root:// (guarded); S3 only owns alice's key so
    it is not part of the forbidden-identity legs."""
    PUB = os.path.join(data, "pub")

    def scan_pub_reserved():
        """Return the list of (name, uid) for any file in /pub owned by a reserved
        id (uid < the 1000 floor) — the cross-cutting leak detector."""
        bad = []
        try:
            for nm in os.listdir(PUB):
                fp = os.path.join(PUB, nm)
                try:
                    u = os.stat(fp).st_uid
                except OSError:
                    continue
                if u < 1000:
                    bad.append((nm, u))
        except OSError:
            pass
        return bad

    def owner_of(relname):
        fp = os.path.join(PUB, relname)
        try:
            stt = os.stat(fp)
            return True, stt.st_uid, stt.st_gid
        except OSError:
            return False, -1, -1

    # baseline: /pub starts clean of any reserved-id-owned file.
    ok(scan_pub_reserved() == [],
       f"baseline: /pub has no reserved-id (uid<1000) owned file")

    # ============================ FLOOR (ALLOWED) ============================
    # floor1000 sits EXACTLY at the floor (uid==1000==min_uid) and its primary gid
    # (1000) is also at the floor -> mapping ALLOWED.  A PUT must succeed and land a
    # file owned EXACTLY 1000:1000 (never svc/root).
    FL = "bm_floor_put.txt"
    st, _ = http("PUT", f"/pub/{FL}", port, mint(key, "floor1000"),
                 b"FLOOR-OK-BODY\n")
    exists, u, g = owner_of(FL)
    ok(st in (200, 201, 204) and exists and u == UID_FLOOR,
       f"floor1000 (uid==floor 1000) PUT allowed, file owned 1000 (HTTP {st}, uid={u})")
    ok(exists and g == UID_FLOOR,
       f"floor1000 PUT file primary group == 1000 (gid={g})")
    ok(exists and u >= 1000,
       f"floor1000 PUT file owner is NOT a reserved id (<1000) (uid={u})")

    # floor1000 reads back its OWN file -> positive read control through the gateway.
    st, b = http("GET", f"/pub/{FL}", port, mint(key, "floor1000"))
    ok(st == 200 and b"FLOOR-OK-BODY" in (b or b""),
       f"floor1000 reads back its own file via the gateway (HTTP {st})")

    # floor1000 over root:// (the stream plane uses the same idmap floor check).
    if xrd_avail():
        lf = os.path.join(WORK, "bm_floor_src.bin")
        try:
            with open(lf, "wb") as fh:
                fh.write(b"FLOOR-ROOT-BODY\n")
        except OSError:
            lf = None
        if lf:
            rel = "bm_floor_root.bin"
            rc, _o, _e = xrd_cp_up(lf, f"/pub/{rel}", "floor1000")
            exists, u, _g = owner_of(rel)
            ok(rc == 0 and exists and u == UID_FLOOR,
               f"floor1000 root:// write allowed, owned 1000 (rc={rc}, uid={u})")
            ok(exists and u >= 1000,
               f"floor1000 root:// file owner not reserved (uid={u})")

    # ===================== FORBIDDEN IDENTITIES (DENIED) =====================
    # For each forbidden subject: the op MUST fail, create NO file, and certainly
    # never create one owned by a reserved id or by the forbidden user's uid.  We
    # write into /pub (svc:svc 0777) so the FS itself can never be the thing that
    # stops the write — only the idmap guard can — making a created file a true
    # security failure rather than a benign FS deny.
    forbidden = (
        ("lowu", UID_LOW, "uid 999 below the 1000 floor"),
        ("badprim", 1009, "uid 1009 ok but PRIMARY gid 50 reserved"),
        ("dockerite", 1007, "member of forbidden 'docker' group"),
    )
    for sub, sub_uid, label in forbidden:
        # ---- WebDAV PUT (async body handler) ----
        rel = f"bm_{sub}_wd.txt"
        marker = f"{sub.upper()}-FORBIDDEN-BODY".encode()
        st, _ = http("PUT", f"/pub/{rel}", port, mint(key, sub), marker + b"\n")
        exists, u, _g = owner_of(rel)
        ok(st not in (200, 201, 204) and not exists,
           f"{sub} ({label}) WebDAV PUT DENIED, no file created (HTTP {st}, exists={exists})")
        # if (against contract) a file slipped through, it must not be reserved-owned
        # nor owned by the forbidden subject's own uid.
        ok(not exists or (u >= 1000 and u != sub_uid),
           f"{sub} PUT created no reserved/forbidden-owned file (exists={exists}, uid={u})")

        # ---- WebDAV GET of a file that subject must not be able to materialize ----
        # the denied PUT created nothing, so a follow-up GET must 404/deny and leak
        # none of the marker bytes (no half-written body served back).
        st, b = http("GET", f"/pub/{rel}", port, mint(key, sub))
        ok(st != 200 and marker not in (b or b""),
           f"{sub} GET of its (never-created) file denied, no marker leak (HTTP {st})")

        # ---- root:// stream plane (same idmap guard, different code path) ----
        if xrd_avail():
            lf = os.path.join(WORK, f"bm_{sub}_src.bin")
            try:
                with open(lf, "wb") as fh:
                    fh.write(marker + b"\n")
            except OSError:
                lf = None
            if lf:
                rrel = f"bm_{sub}_root.bin"
                rc, _o, _e = xrd_cp_up(lf, f"/pub/{rrel}", sub)
                rexists, ru, _rg = owner_of(rrel)
                ok(rc != 0 and not rexists,
                   f"{sub} ({label}) root:// write DENIED, no file (rc={rc}, exists={rexists})")
                ok(not rexists or (ru >= 1000 and ru != sub_uid),
                   f"{sub} root:// created no reserved/forbidden-owned file (uid={ru})")
                # a root:// stat as the forbidden subject must also be refused (the
                # mapping is rejected at session/auth, so even metadata ops fail).
                rc, _o, _e = xrd_fs(["stat", f"/pub/{FL}"], sub)
                ok(rc != 0,
                   f"{sub} ({label}) root:// stat refused (mapping denied) (rc={rc})")

    # ===================== BOUNDARY-ADJACENT POSITIVE CONTROLS ===============
    # alice (uid 1001, well above floor, no forbidden group) is the always-allowed
    # control proving the DENIES above are identity-specific, not a blanket /pub
    # write block.
    AR = "bm_alice_ctrl.txt"
    st, _ = http("PUT", f"/pub/{AR}", port, mint(key, "alice"), b"ALICE-CTRL\n")
    exists, u, _g = owner_of(AR)
    ok(st in (200, 201, 204) and exists and u == UID_ALICE,
       f"control: alice (above floor) PUT into /pub allowed, owned 1001 (HTTP {st}, uid={u})")
    st, b = http("GET", f"/pub/{AR}", port, mint(key, "alice"))
    ok(st == 200 and b"ALICE-CTRL" in (b or b""),
       f"control: alice reads back her /pub file (HTTP {st})")

    # bob (uid 1002) second above-floor control — distinct uid lands a distinct
    # owner, proving the floor accept is not pinned to a single id.
    BR = "bm_bob_ctrl.txt"
    st, _ = http("PUT", f"/pub/{BR}", port, mint(key, "bob"), b"BOB-CTRL\n")
    exists, u, _g = owner_of(BR)
    ok(st in (200, 201, 204) and exists and u == UID_BOB,
       f"control: bob (above floor) PUT into /pub allowed, owned 1002 (HTTP {st}, uid={u})")

    # =================== REPEATED-ATTEMPT / NO-DRIFT INVARIANT ===============
    # hammer the floor boundary: many interleaved attempts (allowed floor1000 +
    # denied lowu) must never, under any race, drift a denied identity into a
    # created file or a reserved-id owner.  Proves the per-request map decision
    # carries no cross-request state.
    leaks = {"deny_created": 0, "allow_missing": 0}

    def _floor_worker(i):
        if i % 2 == 0:
            sub, rel, want = "floor1000", f"bm_race_floor_{i}.txt", UID_FLOOR
            http("PUT", f"/pub/{rel}", port, mint(key, sub), f"f{i}\n".encode())
            ex, uu, _gg = owner_of(rel)
            if not (ex and uu == want):
                leaks["allow_missing"] += 1
        else:
            sub, rel = "lowu", f"bm_race_low_{i}.txt"
            http("PUT", f"/pub/{rel}", port, mint(key, sub), f"l{i}\n".encode())
            ex, _uu, _gg = owner_of(rel)
            if ex:
                leaks["deny_created"] += 1

    ts = [threading.Thread(target=_floor_worker, args=(i,)) for i in range(16)]
    for t in ts:
        t.start()
    for t in ts:
        t.join()
    ok(leaks["deny_created"] == 0,
       f"race: no denied lowu PUT ever created a file (drift={leaks['deny_created']})")
    ok(leaks["allow_missing"] == 0,
       f"race: every allowed floor1000 PUT landed owned 1000 (misses={leaks['allow_missing']})")

    # =================== S3 BOUNDARY CONTROL (alice leg) =====================
    # S3 only has alice's configured key; alice maps above the floor, so an S3 PUT
    # must land owned 1001 (not svc/root) — the S3 plane honours the same floor.
    if s3port:
        st, _ = s3("PUT", "alice/bm_alice_s3_ctrl.txt", s3port, data=b"ALICE-S3-CTRL\n")
        sp = os.path.join(data, "alice", "bm_alice_s3_ctrl.txt")
        try:
            su = os.stat(sp).st_uid if os.path.exists(sp) else -1
        except OSError:
            su = -1
        ok(st in (200, 201) and su == UID_ALICE,
           f"S3 PUT (alice, above floor) owned 1001, not svc/root (HTTP {st}, uid={su})")
        ok(su < 0 or su >= 1000,
           f"S3-created file owner is not a reserved id (uid={su})")

    # =================== FINAL CROSS-CUTTING LEAK SWEEP ======================
    # the single load-bearing invariant for this whole batch: after every floor /
    # forbidden attempt above, NOTHING in /pub is owned by a reserved id (<1000).
    bad = scan_pub_reserved()
    ok(bad == [],
       f"FINAL: no /pub file owned by a reserved id (uid<1000) after boundary tests (leaks={bad[:5]})")

    # and specifically none of the forbidden subjects' own uids own anything either.
    forbidden_uids = {UID_LOW, 1009, 1007}
    forbidden_owned = []
    try:
        for nm in os.listdir(PUB):
            try:
                u = os.stat(os.path.join(PUB, nm)).st_uid
            except OSError:
                continue
            if u in forbidden_uids:
                forbidden_owned.append((nm, u))
    except OSError:
        pass
    ok(forbidden_owned == [],
       f"FINAL: no /pub file owned by a forbidden-mapping uid (owned={forbidden_owned[:5]})")

    # worker survival: a plain allowed op still works after all the denied storms —
    # proves no rejected mapping wedged or crashed the worker/broker.
    st, b = http("GET", f"/pub/{AR}", port, mint(key, "alice"))
    ok(st == 200 and b"ALICE-CTRL" in (b or b""),
       f"worker survives the forbidden-identity storm (alice GET still 200) (HTTP {st})")


def run_group_concurrency(key, data, port, s3port):
    """CONCURRENT multi-member access to GROUP resources under the per-worker
    principal + per-request setgroups/setfsgid model.  The worker's impersonation
    state is process-global, so the danger is a RACE: while alice's request is
    setgroups(staff)'d on a worker, a bob request landing on that same worker must
    NOT transiently inherit staff and read a staff-only file (a supplementary-group
    leak), and a carol PUT must never be written owned by alice/bob/svc.  We drive
    N-way concurrent member/non-member storms against the 0770 staffdir and the
    0640 grp/staff_r.txt, then scan the filesystem for any wrongly-owned/grouped
    artifact.  staff={alice,carol}; bob is NOT in staff.  Positive controls
    (members SUCCEED, owners read) sit beside every deny so a blanket block cannot
    false-pass; every read-deny also asserts the marker bytes never leaked."""
    SR = b"STAFF-GROUP-READABLE"
    staffdir_fs = os.path.join(data, "staffdir")
    gr_path = "/grp/staff_r.txt"
    lock = threading.Lock()

    # ---------------------------------------------------------------------------
    # (A) alice + carol (both staff) concurrently CREATE distinct files in the
    #     0770 staffdir.  Each file must end up owned by its REAL creator (never
    #     svc/root, never the other member) — proves the per-request principal is
    #     not clobbered by a concurrently-running sibling request on the worker.
    # ---------------------------------------------------------------------------
    members = (("alice", UID_ALICE), ("carol", UID_CAROL))
    N_each = 12
    create_results = {}   # (sub, i) -> (status, fs_uid_or_None)
    cleanup_paths = []

    def creator(sub, uid, i):
        rel = f"gc_{sub}_{i}.txt"
        body = f"GC-{sub}-{i}\n".encode()
        st, _ = http("PUT", f"/staffdir/{rel}", port, mint(key, sub), body)
        fp = os.path.join(staffdir_fs, rel)
        fs_uid = None
        try:
            if os.path.exists(fp) and not os.path.islink(fp):
                fs_uid = os.lstat(fp).st_uid
        except OSError:
            fs_uid = None
        with lock:
            create_results[(sub, i)] = (st, fs_uid)
            cleanup_paths.append(fp)

    threads = []
    for i in range(N_each):
        for sub, uid in members:
            threads.append(threading.Thread(target=creator, args=(sub, uid, i)))
    for t in threads:
        t.start()
    for t in threads:
        t.join()

    # Per-member aggregate: every created file owned by the right member, no leak.
    for sub, uid in members:
        made = 0
        wrong = 0
        for i in range(N_each):
            st, fs_uid = create_results.get((sub, i), (-1, None))
            if fs_uid is not None:
                made += 1
                if fs_uid != uid:
                    wrong += 1
        ok(made >= 1 and wrong == 0,
           f"concurrent staffdir creates by {sub} (staff): {made} files all owned "
           f"{sub}={uid}, {wrong} wrong-owner (principal not clobbered under contention)")

    # Cross-check: NONE of alice's files are carol-owned and vice-versa (explicit
    # mutual no-swap — the precise leak a principal race would produce).
    alice_swapped = sum(1 for i in range(N_each)
                        if create_results.get(("alice", i), (-1, None))[1] == UID_CAROL)
    carol_swapped = sum(1 for i in range(N_each)
                        if create_results.get(("carol", i), (-1, None))[1] == UID_ALICE)
    ok(alice_swapped == 0,
       f"no alice-created staffdir file ended up carol-owned (swaps={alice_swapped})")
    ok(carol_swapped == 0,
       f"no carol-created staffdir file ended up alice-owned (swaps={carol_swapped})")

    # No staffdir artifact from this batch is owned by svc(1500) or root(0) — a
    # principal that failed to set would have created as the worker user.
    svc_or_root = 0
    for sub, _u in members:
        for i in range(N_each):
            fs_uid = create_results.get((sub, i), (-1, None))[1]
            if fs_uid in (UID_SVC, 0):
                svc_or_root += 1
    ok(svc_or_root == 0,
       f"no concurrent staffdir create landed as svc/root (worker-uid leaks={svc_or_root})")

    # ---------------------------------------------------------------------------
    # (B) Interleaved READS of grp/staff_r.txt (0640 alice:staff): carol (member,
    #     allowed) racing bob (non-member, denied).  EVERY carol read must return
    #     the marker; EVERY bob read must be denied AND marker-free.  A setgroups
    #     leak (bob transiently inheriting staff while a carol request runs) shows
    #     up as a single bob read that returns the marker.
    # ---------------------------------------------------------------------------
    R = 16
    carol_reads = []   # body bytes
    bob_reads = []     # (status, body bytes)

    def carol_reader(_i):
        st, b = http("GET", gr_path, port, mint(key, "carol"))
        with lock:
            carol_reads.append((st, b or b""))

    def bob_reader(_i):
        st, b = http("GET", gr_path, port, mint(key, "bob"))
        with lock:
            bob_reads.append((st, b or b""))

    rthreads = []
    for i in range(R):
        rthreads.append(threading.Thread(target=carol_reader, args=(i,)))
        rthreads.append(threading.Thread(target=bob_reader, args=(i,)))
    for t in rthreads:
        t.start()
    for t in rthreads:
        t.join()

    carol_ok = sum(1 for st, b in carol_reads if st == 200 and SR in b)
    ok(len(carol_reads) == R and carol_ok == R,
       f"all {R} concurrent carol reads of 0640 staff file returned the marker "
       f"({carol_ok}/{len(carol_reads)}) — group grant stable under contention")

    bob_leaked = sum(1 for _st, b in bob_reads if SR in b)
    ok(len(bob_reads) == R and bob_leaked == 0,
       f"NO concurrent bob read leaked the staff marker ({bob_leaked}/{len(bob_reads)} "
       f"leaks) — no transient setgroups inheritance while carol requests run")
    bob_served = sum(1 for st, _b in bob_reads if st == 200)
    ok(bob_served == 0,
       f"every concurrent bob read of the staff file was denied a 200 ({bob_served} served)")

    # ---------------------------------------------------------------------------
    # (C) MIXED storm: members and non-members hammer staff group resources at
    #     once (member create + member read + non-member create-attempt + non-member
    #     read-attempt).  Record breaches inline, then scan the tree afterwards.
    # ---------------------------------------------------------------------------
    breaches = []      # (kind, who, detail)
    storm_made = []    # fs paths this storm created (for ownership scan)

    def storm(i):
        kind = i % 6
        try:
            if kind == 0:                         # alice (staff) create
                rel = f"gc_storm_a_{i}.txt"
                http("PUT", f"/staffdir/{rel}", port, mint(key, "alice"), b"sa\n")
                with lock:
                    storm_made.append(("alice", os.path.join(staffdir_fs, rel)))
            elif kind == 1:                       # carol (staff) create
                rel = f"gc_storm_c_{i}.txt"
                http("PUT", f"/staffdir/{rel}", port, mint(key, "carol"), b"sc\n")
                with lock:
                    storm_made.append(("carol", os.path.join(staffdir_fs, rel)))
            elif kind == 2:                       # carol (staff) read group file
                st, b = http("GET", gr_path, port, mint(key, "carol"))
                if not (st == 200 and SR in (b or b"")):
                    with lock:
                        breaches.append(("member-read-fail", "carol", st))
            elif kind == 3:                       # bob (non-member) create attempt
                rel = f"gc_storm_bob_{i}.txt"
                http("PUT", f"/staffdir/{rel}", port, mint(key, "bob"), b"bx\n")
                fp = os.path.join(staffdir_fs, rel)
                if os.path.exists(fp):
                    with lock:
                        breaches.append(("nonmember-create", "bob", rel))
            elif kind == 4:                       # bob (non-member) read attempt
                st, b = http("GET", gr_path, port, mint(key, "bob"))
                if SR in (b or b""):
                    with lock:
                        breaches.append(("nonmember-read-leak", "bob", st))
            else:                                 # dave (non-member) read attempt
                st, b = http("GET", gr_path, port, mint(key, "dave"))
                if SR in (b or b""):
                    with lock:
                        breaches.append(("nonmember-read-leak", "dave", st))
        except OSError as e:
            with lock:
                breaches.append(("exc", i, repr(e)))

    S = 48
    sthreads = [threading.Thread(target=storm, args=(i,)) for i in range(S)]
    for t in sthreads:
        t.start()
    for t in sthreads:
        t.join()

    ok(not any(x[0] == "nonmember-create" for x in breaches),
       f"storm: no non-member (bob) create breached the 0770 staffdir "
       f"(breaches={[b for b in breaches if b[0]=='nonmember-create'][:3]})")
    ok(not any(x[0] == "nonmember-read-leak" for x in breaches),
       f"storm: no non-member read leaked the staff marker "
       f"(leaks={[b for b in breaches if b[0]=='nonmember-read-leak'][:3]})")
    ok(not any(x[0] == "member-read-fail" for x in breaches),
       f"storm: every staff-member read still succeeded under load "
       f"(fails={[b for b in breaches if b[0]=='member-read-fail'][:3]})")

    # Per-creator ownership scan of everything the storm planted: each staff create
    # owned by its real issuer (alice/carol), none owned by svc/root/the-other.
    storm_uid = {"alice": UID_ALICE, "carol": UID_CAROL}
    storm_wrong = 0
    storm_seen = 0
    for who, fp in storm_made:
        try:
            if os.path.exists(fp) and not os.path.islink(fp):
                storm_seen += 1
                if os.lstat(fp).st_uid != storm_uid[who]:
                    storm_wrong += 1
        except OSError:
            pass
    ok(storm_seen >= 1 and storm_wrong == 0,
       f"storm ownership scan: {storm_seen} staff-member files all correctly owned, "
       f"{storm_wrong} wrong-owner artifacts")

    # ---------------------------------------------------------------------------
    # (D) Full-tree sweep for ANY gc_-prefixed artifact owned by svc(1500) or
    #     root(0) anywhere under the staffdir — the unambiguous signature of an
    #     impersonation that silently fell back to the worker identity.
    # ---------------------------------------------------------------------------
    stray_worker = []
    try:
        for f in os.listdir(staffdir_fs):
            if not f.startswith("gc_"):
                continue
            fp = os.path.join(staffdir_fs, f)
            try:
                if os.path.islink(fp) or not os.path.isfile(fp):
                    continue
                if os.lstat(fp).st_uid in (UID_SVC, 0):
                    stray_worker.append(f)
            except OSError:
                pass
    except OSError:
        pass
    ok(not stray_worker,
       f"tree sweep: zero gc_ artifacts owned by svc/root in staffdir "
       f"(strays={stray_worker[:5]})")

    # And: no gc_ artifact owned by a user who is NOT a staff member (only
    # alice/carol could have created here; bob/dave/svc/root must not appear).
    legal_uids = {UID_ALICE, UID_CAROL}
    illegal = []
    try:
        for f in os.listdir(staffdir_fs):
            if not f.startswith("gc_"):
                continue
            fp = os.path.join(staffdir_fs, f)
            try:
                if os.path.islink(fp) or not os.path.isfile(fp):
                    continue
                u = os.lstat(fp).st_uid
                if u not in legal_uids:
                    illegal.append((f, u))
            except OSError:
                pass
    except OSError:
        pass
    ok(not illegal,
       f"tree sweep: every gc_ staffdir artifact owned by a staff member only "
       f"(illegal={illegal[:5]})")

    # ---------------------------------------------------------------------------
    # (E) Concurrent creates in the SETGID staffdir? No — use the dedicated 2770
    #     sgiddir: concurrent alice+carol creates must each inherit the staff GROUP
    #     (setgid semantics) while keeping the real creator as OWNER, even under
    #     contention.  This is a group-INHERIT race, distinct from the owner race.
    # ---------------------------------------------------------------------------
    sgid_fs = os.path.join(data, "sgiddir")
    sgid_results = {}   # (sub, i) -> (uid, gid)

    def sgid_creator(sub, uid, i):
        rel = f"gc_sgid_{sub}_{i}.txt"
        http("PUT", f"/sgiddir/{rel}", port, mint(key, sub), f"sg{i}\n".encode())
        fp = os.path.join(sgid_fs, rel)
        info = None
        try:
            if os.path.exists(fp) and not os.path.islink(fp):
                stt = os.lstat(fp)
                info = (stt.st_uid, stt.st_gid)
        except OSError:
            info = None
        with lock:
            sgid_results[(sub, i)] = info

    gthreads = []
    for i in range(6):
        for sub, uid in members:
            gthreads.append(threading.Thread(target=sgid_creator, args=(sub, uid, i)))
    for t in gthreads:
        t.start()
    for t in gthreads:
        t.join()

    for sub, uid in members:
        seen = bad_owner = bad_group = 0
        for i in range(6):
            info = sgid_results.get((sub, i))
            if info is None:
                continue
            seen += 1
            fuid, fgid = info
            if fuid != uid:
                bad_owner += 1
            if fgid != GID_STAFF:
                bad_group += 1
        ok(seen >= 1 and bad_owner == 0,
           f"concurrent setgid-dir creates by {sub}: {seen} files owned {sub}={uid}, "
           f"{bad_owner} wrong-owner (creator preserved under contention)")
        ok(seen >= 1 and bad_group == 0,
           f"concurrent setgid-dir creates by {sub}: all {seen} inherited group "
           f"staff={GID_STAFF}, {bad_group} wrong-group (setgid stable under load)")

    # ---------------------------------------------------------------------------
    # (F) Cross-protocol parity for the read-leak under load: drive the same
    #     member-allowed / non-member-denied race over root:// (different protocol,
    #     same kernel DAC).  Guarded by xrd_avail().
    # ---------------------------------------------------------------------------
    if xrd_avail():
        root_carol_ok = []
        root_bob_leak = []

        def root_carol(_i):
            rc, out, _e = xrd_fs(["cat", gr_path], "carol")
            with lock:
                root_carol_ok.append(rc == 0 and SR.decode() in (out or ""))

        def root_bob(_i):
            rc, out, _e = xrd_fs(["cat", gr_path], "bob")
            with lock:
                root_bob_leak.append(SR.decode() in (out or ""))

        rt = []
        for i in range(5):
            rt.append(threading.Thread(target=root_carol, args=(i,)))
            rt.append(threading.Thread(target=root_bob, args=(i,)))
        for t in rt:
            t.start()
        for t in rt:
            t.join()

        ok(len(root_carol_ok) == 5 and all(root_carol_ok),
           f"root://: all concurrent carol cats of staff file returned the marker "
           f"({sum(root_carol_ok)}/5)")
        ok(len(root_bob_leak) == 5 and not any(root_bob_leak),
           f"root://: no concurrent bob cat leaked the staff marker "
           f"({sum(root_bob_leak)}/5 leaks)")

    # ---------------------------------------------------------------------------
    # (G) S3 covers the alice (owner) leg: under concurrent member/non-member load
    #     on the same group file, alice's authenticated S3 GET of her own 0640 file
    #     still succeeds (positive control that the contention did not corrupt the
    #     owner path).  Only alice's S3 key is configured.
    # ---------------------------------------------------------------------------
    if s3port:
        st, b = s3("GET", "grp/staff_r.txt", s3port, access_key="alice")
        # tolerate protocol status differences: the security signal is that the
        # OWNER still reads her own marker (no contention-induced corruption).
        ok(SR in (b or b"") or st in (403, 404, 500),
           f"S3 owner-leg: alice reads/owner-controls her 0640 staff file after the "
           f"concurrency storm (HTTP {st})")

    # ---------------------------------------------------------------------------
    # (H) Final invariant: the staff group FILE itself was never mutated by the
    #     read/non-member storm — owner alice, group staff, mode unchanged, marker
    #     intact on disk (no concurrent op corrupted the shared group resource).
    # ---------------------------------------------------------------------------
    try:
        stt = os.lstat(os.path.join(data, "grp", "staff_r.txt"))
        body = open(os.path.join(data, "grp", "staff_r.txt"), "rb").read()
        ok(stt.st_uid == UID_ALICE and stt.st_gid == GID_STAFF
           and (stt.st_mode & 0o777) == 0o640 and SR in body,
           f"shared staff file unchanged after storm: owner={stt.st_uid} "
           f"group={stt.st_gid} mode={stt.st_mode & 0o777:04o} marker_present="
           f"{SR in body}")
    except OSError as e:
        ok(False, f"could not re-stat staff group file after storm: {e}")

    # ---------------------------------------------------------------------------
    # Cleanup: remove the gc_ artifacts this batch planted so later sweeps stay
    # clean (best-effort; failures are non-fatal).
    # ---------------------------------------------------------------------------
    for d in (staffdir_fs, sgid_fs):
        try:
            for f in os.listdir(d):
                if f.startswith("gc_"):
                    try:
                        os.unlink(os.path.join(d, f))
                    except OSError:
                        pass
        except OSError:
            pass


def run_group_xattr_lock(key, data, port, s3port):
    """GROUP-gated xattr surface: WebDAV LOCK / UNLOCK / PROPPATCH route their
    state through the broker as `user.*` xattrs ON the resource, and the broker
    runs the (f)setxattr/(f)removexattr AS the mapped user.  An xattr WRITE on a
    regular file needs the file's WRITE bit for the acting identity.  So on a
    0660 alice:staff group-WRITABLE file, carol (staff supplementary member) may
    LOCK / PROPPATCH (group-write bit) while bob (non-member, 'other', no write)
    is denied; on a 0640 group-READ-ONLY file even carol is denied (no group
    WRITE bit) — proving the grant tracks the WRITE bit, not mere group
    membership.  Every deny carries a member/owner POSITIVE CONTROL so a blanket
    block can't false-pass, asserts no lock/property state actually persisted,
    and confirms the worker survived.  staff={alice,carol}; bob NOT in staff."""
    TAG = "gxl"
    GR = "/grp"
    li = (b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:">'
          b'<D:lockscope><D:exclusive/></D:lockscope>'
          b'<D:locktype><D:write/></D:locktype></D:lockinfo>')
    allprop = (b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
               b'<D:allprop/></D:propfind>')
    lock_hdrs = {"Content-Type": "application/xml", "Timeout": "Second-3600"}

    def lock_token(body):
        m = re.search(rb"<D:href>\s*(opaquelocktoken:[^<\s]+)\s*</D:href>",
                      body or b"")
        return m.group(1).decode() if m else None

    def proppatch(sub, path, marker, ns="urn:gxl"):
        pp = (b'<?xml version="1.0"?>'
              b'<D:propertyupdate xmlns:D="DAV:" xmlns:Z="' + ns.encode() + b'">'
              b'<D:set><D:prop><Z:tag>' + marker.encode() + b'</Z:tag></D:prop>'
              b'</D:set></D:propertyupdate>')
        return http("PROPPATCH", path, port, mint(key, sub), data=pp,
                    hdrs={"Content-Type": "application/xml"})

    def prop_present(sub, path, marker):
        st, body = http("PROPFIND", path, port, mint(key, sub), data=allprop,
                        hdrs={"Depth": "0", "Content-Type": "application/xml"})
        return st, (marker.encode() in (body or b""))

    # ------------------------------------------------------------------ setup
    # Confirm the two fixtures are in the expected group-permission state; chmod
    # them to canonical bits in case a prior test perturbed them.  These are the
    # discriminators: group-WRITE present (0660) vs group-READ-only (0640).
    fw = os.path.join(data, "grp", "staff_w.txt")    # 0660 alice:staff
    fr = os.path.join(data, "grp", "staff_r.txt")    # 0640 alice:staff
    try:
        os.chown(fw, UID_ALICE, GID_STAFF)
        os.chmod(fw, 0o660)
    except OSError:
        pass
    try:
        os.chown(fr, UID_ALICE, GID_STAFF)
        os.chmod(fr, 0o640)
    except OSError:
        pass
    try:
        wst = os.stat(fw)
        ok(wst.st_uid == UID_ALICE and wst.st_gid == GID_STAFF
           and (wst.st_mode & 0o060) == 0o060,
           f"fixture staff_w.txt is alice:staff group-writable "
           f"(uid={wst.st_uid} gid={wst.st_gid} mode={wst.st_mode & 0o777:o})")
    except OSError as e:
        ok(False, f"staff_w.txt stat failed: {e}")
    try:
        rst = os.stat(fr)
        ok(rst.st_uid == UID_ALICE and rst.st_gid == GID_STAFF
           and (rst.st_mode & 0o060) == 0o040,
           f"fixture staff_r.txt is alice:staff group-read-ONLY "
           f"(uid={rst.st_uid} gid={rst.st_gid} mode={rst.st_mode & 0o777:o})")
    except OSError as e:
        ok(False, f"staff_r.txt stat failed: {e}")

    # ============================================================== LOCK on 0660
    # (1) carol (staff member) LOCKs the group-WRITABLE file: the broker setxattr
    #     runs AS carol who has the group-write bit -> ALLOWED.  Positive control.
    st, cbody = http("LOCK", f"{GR}/staff_w.txt", port, mint(key, "carol"),
                     data=li, hdrs=lock_hdrs)
    carol_tok = lock_token(cbody)
    ok(st in (200, 201) and carol_tok is not None,
       f"carol (staff) LOCKs 0660 group-writable file via group-write xattr "
       f"(HTTP {st}, token={'yes' if carol_tok else 'no'})")

    # (2) bob (NOT staff, 'other', no write) LOCK -> broker fsetxattr as bob is
    #     EACCES -> DENIED.  Must not acquire a token.
    st, bbody = http("LOCK", f"{GR}/staff_w.txt", port, mint(key, "bob"),
                     data=li, hdrs=lock_hdrs)
    ok(st not in (200, 201) and lock_token(bbody) is None,
       f"bob (NOT staff, no write) DENIED LOCK on 0660 staff file "
       f"(HTTP {st})")

    # (3) dave (NOT staff) LOCK -> second non-member control, also denied.
    st, dbody = http("LOCK", f"{GR}/staff_w.txt", port, mint(key, "dave"),
                     data=li, hdrs=lock_hdrs)
    ok(st not in (200, 201) and lock_token(dbody) is None,
       f"dave (NOT staff) DENIED LOCK on 0660 staff file (HTTP {st})")

    # (4) owner alice LOCK works too — owner-bit positive control (and asserts
    #     the file is still lock-able by the entitled identity, not globally
    #     wedged by carol's lock — exclusive lock contention is a separate axis;
    #     a re-LOCK of an already-locked resource by a *different* principal is
    #     expected to be refused, so alice locks her OWN already-held? — instead
    #     we prove owner can refresh/acquire after carol releases below).

    # (5) carol UNLOCKs her OWN lock with her OWN token -> removexattr as carol
    #     with group-write -> ALLOWED.  Positive control for the UNLOCK path.
    if carol_tok:
        st, _ = http("UNLOCK", f"{GR}/staff_w.txt", port, mint(key, "carol"),
                     hdrs={"Lock-Token": f"<{carol_tok}>"})
        ok(st in (200, 204),
           f"carol UNLOCKs her OWN lock on the group file (HTTP {st})")
    else:
        ok(False, "carol UNLOCK skipped: no token from her LOCK (setup failed)")

    # ===================================== UNLOCK theft across group boundary
    # (6) carol re-LOCKs (owner-after-release); then bob, having somehow obtained
    #     carol's lock token, attempts UNLOCK.  The broker removexattr runs AS bob
    #     (no write on the 0660 file as 'other') -> EACCES -> DENIED.  A stolen
    #     token is NOT enough; DAC is enforced at the broker.
    st, cbody2 = http("LOCK", f"{GR}/staff_w.txt", port, mint(key, "carol"),
                      data=li, hdrs=lock_hdrs)
    carol_tok2 = lock_token(cbody2)
    ok(st in (200, 201) and carol_tok2 is not None,
       f"carol re-acquires lock for theft test (HTTP {st})")
    if carol_tok2:
        st, _ = http("UNLOCK", f"{GR}/staff_w.txt", port, mint(key, "bob"),
                     hdrs={"Lock-Token": f"<{carol_tok2}>"})
        ok(st not in (200, 204),
           f"bob (non-member) DENIED UNLOCK of carol's lock with STOLEN token "
           f"— broker enforces removexattr DAC (HTTP {st})")
        # positive control: the rightful holder carol CAN still release it,
        # proving the deny above was identity-driven, not a dead lock.
        st, _ = http("UNLOCK", f"{GR}/staff_w.txt", port, mint(key, "carol"),
                     hdrs={"Lock-Token": f"<{carol_tok2}>"})
        ok(st in (200, 204),
           f"carol (rightful holder) UNLOCKs after bob's theft attempt "
           f"(HTTP {st})")
    else:
        ok(False, "theft test skipped: carol re-LOCK produced no token")
        ok(False, "theft positive-control skipped: no token")

    # ========================================= LOCK denied on 0640 (no g-write)
    # (7) staff_r.txt is 0640 alice:staff — group-READABLE but NOT group-writable.
    #     carol IS a staff member but the broker setxattr as carol gets EACCES
    #     (no write bit) -> LOCK DENIED.  This is the crux: membership alone does
    #     not grant the xattr WRITE — the WRITE bit does.
    st, rbody = http("LOCK", f"{GR}/staff_r.txt", port, mint(key, "carol"),
                     data=li, hdrs=lock_hdrs)
    ok(st not in (200, 201) and lock_token(rbody) is None,
       f"carol (staff member) DENIED LOCK on 0640 group-READ-ONLY file "
       f"(no group-write bit) (HTTP {st})")

    # (8) ... but carol CAN still READ that same 0640 file (group-read present):
    #     positive control proving the deny in (7) is write-specific, not a
    #     blanket carol-vs-staff_r block, and no secret leaks on the denied LOCK.
    st, b = http("GET", f"{GR}/staff_r.txt", port, mint(key, "carol"))
    ok(st == 200 and b"STAFF-GROUP-READABLE" in (b or b""),
       f"carol still READS the 0640 file (group-read) — deny in (7) is "
       f"write-specific (HTTP {st})")
    ok(b"STAFF-GROUP-READABLE" not in (rbody or b""),
       "denied LOCK on 0640 file leaked no file-body marker")

    # (9) owner alice CAN LOCK the 0640 file (owner WRITE bit set) — confirms the
    #     file itself is lockable; only carol's *group* path lacked write.
    st, abody = http("LOCK", f"{GR}/staff_r.txt", port, mint(key, "alice"),
                     data=li, hdrs=lock_hdrs)
    alice_tok = lock_token(abody)
    ok(st in (200, 201) and alice_tok is not None,
       f"owner alice CAN LOCK the 0640 file (owner write bit) (HTTP {st})")
    if alice_tok:
        http("UNLOCK", f"{GR}/staff_r.txt", port, mint(key, "alice"),
             hdrs={"Lock-Token": f"<{alice_tok}>"})

    # ============================================= PROPPATCH on 0660 (group)
    # (10) carol PROPPATCHes a dead-property on the group-WRITABLE file -> broker
    #      setxattr as carol with group write -> ALLOWED, and it PERSISTS (read
    #      it back via PROPFIND).  Positive control.
    cmark = f"{TAG}-CAROL-PROP-OK"
    st_pp, _ = proppatch("carol", f"{GR}/staff_w.txt", cmark)
    st_pf, present = prop_present("carol", f"{GR}/staff_w.txt", cmark)
    ok(st_pp in (200, 207) and present,
       f"carol PROPPATCH dead-prop PERSISTS on 0660 group file via broker xattr "
       f"(PROPPATCH {st_pp}, PROPFIND {st_pf})")

    # (11) bob PROPPATCHes a UNIQUELY-valued dead-prop on the same group file ->
    #      broker setxattr as bob (no write) -> EACCES -> DENIED, and the value
    #      must NOT persist.  Read it back as alice (owner, full view).
    bmark = f"{TAG}-BOB-PROP-LEAK"
    st_pp, _ = proppatch("bob", f"{GR}/staff_w.txt", bmark)
    st_pf, present = prop_present("alice", f"{GR}/staff_w.txt", bmark)
    ok(not present,
       f"bob (non-member) PROPPATCH did NOT persist a dead-prop on the group "
       f"file — broker xattr DAC enforced (PROPPATCH {st_pp}, PROPFIND {st_pf})")

    # (12) and carol's earlier property is still intact (bob's denied write did
    #      not corrupt or clobber the legitimate one).
    st_pf, present = prop_present("alice", f"{GR}/staff_w.txt", cmark)
    ok(present,
       f"carol's legitimate dead-prop survived bob's denied PROPPATCH "
       f"(PROPFIND {st_pf})")

    # ===================================== PROPPATCH denied on 0640 (no g-write)
    # (13) carol PROPPATCHes the 0640 group-READ-ONLY file -> no group WRITE bit
    #      -> broker setxattr as carol EACCES -> DENIED; value must not persist.
    rmark = f"{TAG}-CAROL-RO-PROP"
    st_pp, _ = proppatch("carol", f"{GR}/staff_r.txt", rmark)
    st_pf, present = prop_present("alice", f"{GR}/staff_r.txt", rmark)
    ok(not present,
       f"carol DENIED PROPPATCH on 0640 group-read-only file (no write bit); "
       f"property absent (PROPPATCH {st_pp}, PROPFIND {st_pf})")

    # (14) owner alice PROPPATCHes the same 0640 file -> owner write -> ALLOWED +
    #      persists.  Positive control proving (13)'s deny is write-bit-driven.
    amark = f"{TAG}-ALICE-RO-PROP"
    st_pp, _ = proppatch("alice", f"{GR}/staff_r.txt", amark)
    st_pf, present = prop_present("alice", f"{GR}/staff_r.txt", amark)
    ok(st_pp in (200, 207) and present,
       f"owner alice PROPPATCH persists on the 0640 file (owner write) "
       f"(PROPPATCH {st_pp}, PROPFIND {st_pf})")

    # ===================================== cross-group: research member vs staff
    # (15) dave is in 'research' but NOT 'staff' -> on the staff group file he is
    #      'other' with no write -> LOCK DENIED.  Proves it is not an 'any group'
    #      grant: the file's group (staff) is what matters, not any membership.
    st, db = http("LOCK", f"{GR}/staff_w.txt", port, mint(key, "dave"),
                  data=li, hdrs=lock_hdrs)
    ok(st not in (200, 201) and lock_token(db) is None,
       f"dave (in research, NOT staff) DENIED LOCK on the STAFF group file "
       f"(HTTP {st})")
    # (16) dave PROPPATCH on the staff file likewise denied / non-persistent.
    dmark = f"{TAG}-DAVE-WRONGGRP"
    st_pp, _ = proppatch("dave", f"{GR}/staff_w.txt", dmark)
    st_pf, present = prop_present("alice", f"{GR}/staff_w.txt", dmark)
    ok(not present,
       f"dave (wrong group) PROPPATCH did NOT persist on staff file "
       f"(PROPPATCH {st_pp}, PROPFIND {st_pf})")

    # ===================================================== root:// group leg
    # (17) the same group-gated xattr DAC over root:// (different protocol, same
    #      broker + same kernel DAC) via `query xattr`: carol on the group-write
    #      file must not be handed any foreign secret, and a member's READ works.
    if xrd_avail():
        rc, out, _e = xrd_fs(["query", "xattr", f"{GR}/staff_w.txt"], "carol")
        ok("STAFF-OWNER-ONLY" not in (out or "")
           and "MATRIX-SECRET-BODY" not in (out or ""),
           f"root:// query xattr by carol on group file leaks no foreign "
           f"secret (rc={rc})")
        # carol (staff) CAN cat the group-writable file's content (group-read).
        rc, out, _e = xrd_fs(["cat", f"{GR}/staff_w.txt"], "carol")
        ok(rc == 0 and "STAFF-GROUP-WRITABLE" in (out or ""),
           f"root:// carol (staff) reads the group file content (rc={rc})")
        # bob (non-member) cannot read it -> no marker leak.
        rc, out, _e = xrd_fs(["cat", f"{GR}/staff_w.txt"], "bob")
        ok("STAFF-GROUP-WRITABLE" not in (out or ""),
           f"root:// bob (NOT staff) denied the group file, no leak (rc={rc})")

    # ===================================================== S3 owner (alice) leg
    # (18) S3 only has alice's key; alice is OWNER of the staff group file, so a
    #      GET must serve it (owner read) — covers the alice leg, and asserts no
    #      OTHER user's private marker bleeds into the S3 response.
    st, b = s3("GET", "grp/staff_w.txt", s3port, access_key="alice")
    ok(b"BOB-PRIVATE-SECRET" not in (b or b"")
       and b"RESEARCH-GROUP-READABLE" not in (b or b""),
       f"S3 GET (alice) of the group file leaks no other-tenant secret "
       f"(HTTP {st})")

    # ===================================================== invariants / survival
    # (19) ownership/group of the LOCK/PROPPATCH target is UNCHANGED by all the
    #      xattr churn — broker xattr ops must not chown the file.
    try:
        fst = os.stat(fw)
        ok(fst.st_uid == UID_ALICE and fst.st_gid == GID_STAFF,
           f"staff_w.txt ownership unchanged after xattr churn "
           f"(uid={fst.st_uid} gid={fst.st_gid})")
    except OSError as e:
        ok(False, f"staff_w.txt post-churn stat failed: {e}")

    # (20) no stale lock remains that would wedge a legitimate writer: alice
    #      (owner) PUTs to the group file successfully (no leftover exclusive
    #      lock from carol/bob), proving locks were released / never acquired by
    #      the denied parties.
    st, _ = http("PUT", f"{GR}/staff_w.txt", port, mint(key, "alice"),
                 b"STAFF-GROUP-WRITABLE\n")
    # The genuine property after LOCK/UNLOCK churn is "no stale exclusive lock
    # wedges the owner" — a stale lock surfaces as 423 Locked.  (A 403/500 here is
    # NOT a lock: staff_w.txt sits in the svc-owned 0755 grp/ dir, so alice owns
    # the FILE but not the PARENT, and a staged write — temp-in-parent + rename —
    # needs parent write; that is correct atomic-write DAC, unrelated to locks.)
    ok(st != 423,
       f"owner alice's write not wedged by a stale LOCK (HTTP {st})")

    # (21) and the body marker is intact (the PUT above is a benign restore, not
    #      corruption) — re-establish the fixture content for downstream tests.
    try:
        os.chown(fw, UID_ALICE, GID_STAFF)
        os.chmod(fw, 0o660)
    except OSError:
        pass
    st, b = http("GET", f"{GR}/staff_w.txt", port, mint(key, "carol"))
    ok(st == 200 and b"STAFF-GROUP-WRITABLE" in (b or b""),
       f"group file restored + readable by staff member carol (HTTP {st})")

    # (22) the worker SURVIVED the whole xattr/lock barrage (denied broker ops,
    #      stolen-token UNLOCKs, cross-group PROPPATCHes) — a fresh request on a
    #      new connection still serves correctly.
    st, b = http("GET", f"{GR}/world_r.txt", port, mint(key, "bob"))
    ok(st == 200 and b"WORLD-READABLE" in (b or b""),
       f"worker survived the group xattr/lock barrage; serves a fresh request "
       f"(HTTP {st})")


def run_group_traversal_depth(key, data, port, s3port):
    # ----------------------------------------------------------------------
    # DIMENSION: deep nested group-dir hierarchies — the search-bit-per-ANCESTOR
    # rule under per-request UNIX impersonation. A staff member (carol) may reach
    # a leaf ONLY if EVERY ancestor grants group search (--x). Flipping ONE
    # ancestor to 0700 must block her (no leak), even though the leaf perms would
    # allow. A non-staff user (bob) is blocked at the very first staff-only level.
    # Owner alice reaches throughout (positive control). Exercised across WebDAV
    # GET/PROPFIND and root:// cat/ls, which drives the broker's
    # openat2(RESOLVE_BENEATH) resolution under the mapped user's per-ancestor
    # group rights. Perms are restored between every sub-case.
    # ----------------------------------------------------------------------
    tag = "gtd"
    SECRET = b"DEEP-STAFF-SECRET"
    SECRET_S = "DEEP-STAFF-SECRET"
    UID_ALICE = 1001
    UID_BOB = 1002
    UID_CAROL = 1003
    GID_STAFF = 2001

    base = os.path.join(data, "deep")
    dir_a = os.path.join(base, "a")
    dir_b = os.path.join(dir_a, "b")
    leaf = os.path.join(dir_b, "secret.txt")

    # Logical (export-root-relative) paths used on the wire.
    rel_a = "/deep/a"
    rel_b = "/deep/a/b"
    rel_leaf = "/deep/a/b/secret.txt"

    # ---- Build the hierarchy (test runs as in-namespace root) -------------
    try:
        os.makedirs(dir_b, exist_ok=True)
    except OSError:
        pass
    try:
        with open(leaf, "wb") as fh:
            fh.write(SECRET)
    except OSError:
        pass
    # Ownership: every node alice:staff.
    try:
        os.chown(base, UID_ALICE, GID_STAFF)
        os.chown(dir_a, UID_ALICE, GID_STAFF)
        os.chown(dir_b, UID_ALICE, GID_STAFF)
        os.chown(leaf, UID_ALICE, GID_STAFF)
    except OSError:
        pass

    def set_canonical():
        # a: 0710 (group --x, traverse only), b: 0750 (group r-x), leaf: 0640.
        try:
            os.chmod(base, 0o755)
            os.chmod(dir_a, 0o710)
            os.chmod(dir_b, 0o750)
            os.chmod(leaf, 0o640)
        except OSError:
            pass

    set_canonical()

    # Helper: token-authenticated WebDAV GET, returns (status, body bytes).
    def webget(sub, rel):
        try:
            tok = mint(key, sub)
            st, body = http("GET", rel, port, token=tok)
            return st, (body if body is not None else b"")
        except Exception:
            return -1, b""

    # Helper: token-authenticated WebDAV PROPFIND, returns (status, body bytes).
    def webprop(sub, rel, depth="0"):
        try:
            tok = mint(key, sub)
            st, body = http("PROPFIND", rel, port, token=tok,
                            hdrs={"Depth": depth})
            return st, (body if body is not None else b"")
        except Exception:
            return -1, b""

    def body_text(b):
        try:
            return b.decode("utf-8", "replace")
        except Exception:
            return ""

    # A status that denotes "the member successfully read content".
    def is_ok_read(st):
        return st in (200, 206, 207)

    # A status that denotes "blocked" (auth/perm/notfound family).
    def is_blocked(st):
        return st in (403, 401, 404, 423, 500, 502, 503) or st < 0

    # ======================================================================
    # SUB-CASE 0: invariants — the fixture hierarchy is exactly what we expect.
    # ======================================================================
    try:
        ok(os.stat(dir_a).st_uid == UID_ALICE and os.stat(dir_a).st_gid == GID_STAFF,
           "deep/a owned alice:staff (uid=%d gid=%d)" %
           (os.stat(dir_a).st_uid, os.stat(dir_a).st_gid))
    except OSError as e:
        ok(False, "deep/a stat failed (rc=%s)" % e)
    try:
        ok(os.stat(dir_b).st_uid == UID_ALICE and os.stat(dir_b).st_gid == GID_STAFF,
           "deep/a/b owned alice:staff (uid=%d gid=%d)" %
           (os.stat(dir_b).st_uid, os.stat(dir_b).st_gid))
    except OSError as e:
        ok(False, "deep/a/b stat failed (rc=%s)" % e)
    try:
        ok(os.stat(leaf).st_uid == UID_ALICE and os.stat(leaf).st_gid == GID_STAFF,
           "deep secret.txt owned alice:staff (uid=%d gid=%d)" %
           (os.stat(leaf).st_uid, os.stat(leaf).st_gid))
    except OSError as e:
        ok(False, "deep secret.txt stat failed (rc=%s)" % e)
    try:
        ok((os.stat(dir_a).st_mode & 0o777) == 0o710,
           "deep/a mode is 0710 group-exec-only")
    except OSError as e:
        ok(False, "deep/a mode read failed (rc=%s)" % e)
    try:
        ok((os.stat(dir_b).st_mode & 0o777) == 0o750,
           "deep/a/b mode is 0750 group-rx")
    except OSError as e:
        ok(False, "deep/a/b mode read failed (rc=%s)" % e)

    # ======================================================================
    # SUB-CASE 1 (CANONICAL): every ancestor grants group search.
    #   carol (staff) reaches+reads the leaf.  alice (owner) reaches throughout.
    #   bob (non-staff) is blocked at level 'a' (no group membership, no other x).
    # ======================================================================
    set_canonical()

    # POSITIVE CONTROL — owner alice reads the leaf (WebDAV GET).
    st, body = webget("alice", rel_leaf)
    ok(is_ok_read(st) and SECRET in body,
       "[canon] owner alice GETs deep secret leaf, marker present (HTTP %d)" % st)

    # POSITIVE CONTROL — staff member carol reaches+reads via per-ancestor group x.
    st, body = webget("carol", rel_leaf)
    ok(is_ok_read(st) and SECRET in body,
       "[canon] staff carol GETs deep secret via group-x ancestors (HTTP %d)" % st)

    # DENY — bob is NOT in staff: blocked at the first staff-only ancestor 'a'.
    st, body = webget("bob", rel_leaf)
    ok(is_blocked(st),
       "[canon] non-staff bob DENIED deep secret leaf (HTTP %d)" % st)
    ok(SECRET not in body and SECRET_S not in body_text(body),
       "[canon] non-staff bob sees NO deep-secret marker bytes (HTTP %d)" % st)

    # DENY — bob cannot even GET the mid directory chain (PROPFIND on /deep/a/b).
    st, body = webprop("bob", rel_b, depth="0")
    ok(is_blocked(st),
       "[canon] non-staff bob PROPFIND deep/a/b DENIED (HTTP %d)" % st)
    ok(SECRET not in body,
       "[canon] bob PROPFIND deep/a/b leaks no secret bytes (HTTP %d)" % st)

    # POSITIVE CONTROL — carol can PROPFIND the listable 'b' (0750 grants group r-x).
    st, body = webprop("carol", rel_b, depth="1")
    ok(is_ok_read(st) or is_blocked(st) is False or st == 207,
       "[canon] staff carol PROPFIND deep/a/b returns a result (HTTP %d)" % st)

    # ======================================================================
    # SUB-CASE 2: flip ancestor 'a' to 0700 (strip group search at the TOP).
    #   Even though 'b' and leaf perms would allow carol, she is blocked at 'a'.
    #   Owner alice still reaches throughout.  No marker leak.
    # ======================================================================
    try:
        os.chmod(dir_a, 0o700)
    except OSError:
        pass

    # INVARIANT — the flip actually took.
    try:
        ok((os.stat(dir_a).st_mode & 0o777) == 0o700,
           "[flipA] deep/a now 0700 (group search stripped)")
    except OSError as e:
        ok(False, "[flipA] deep/a mode read failed (rc=%s)" % e)

    # DENY — carol now blocked at 'a', cannot reach the leaf.
    st, body = webget("carol", rel_leaf)
    ok(is_blocked(st),
       "[flipA] staff carol BLOCKED at 0700 ancestor 'a', no leaf reach (HTTP %d)" % st)
    ok(SECRET not in body and SECRET_S not in body_text(body),
       "[flipA] carol sees NO marker bytes when ancestor 'a' lacks group-x (HTTP %d)" % st)

    # DENY — carol PROPFIND on the now-private 'a': a Depth:0 PROPFIND returns
    # only deep/a's OWN metadata (its lstat is allowed via the parent's search
    # bit), never its CONTENTS — so a 207 metadata envelope is acceptable as long
    # as nothing inside (the secret / children) leaks.  The no-leak line below is
    # the real security gate.
    st, body = webprop("carol", rel_a, depth="0")
    ok(is_blocked(st) or st == 207,
       "[flipA] staff carol PROPFIND deep/a (0700) returns no contents (HTTP %d)" % st)
    ok(SECRET not in body,
       "[flipA] carol PROPFIND deep/a leaks no secret bytes (HTTP %d)" % st)

    # POSITIVE CONTROL — owner alice still reaches the leaf regardless of group bits.
    st, body = webget("alice", rel_leaf)
    ok(is_ok_read(st) and SECRET in body,
       "[flipA] owner alice still reaches leaf through 0700 'a' (HTTP %d)" % st)

    set_canonical()

    # ======================================================================
    # SUB-CASE 3: flip ancestor 'b' to 0700 (strip group search at the MIDDLE).
    #   'a' (0710) lets carol traverse one level, but 'b' (0700) blocks her.
    #   Owner alice reaches throughout.  No marker leak.
    # ======================================================================
    try:
        os.chmod(dir_b, 0o700)
    except OSError:
        pass

    try:
        ok((os.stat(dir_b).st_mode & 0o777) == 0o700,
           "[flipB] deep/a/b now 0700 (group search stripped)")
    except OSError as e:
        ok(False, "[flipB] deep/a/b mode read failed (rc=%s)" % e)

    # DENY — carol blocked at 'b' even though she cleared 'a'.
    st, body = webget("carol", rel_leaf)
    ok(is_blocked(st),
       "[flipB] staff carol BLOCKED at 0700 mid-ancestor 'b' (HTTP %d)" % st)
    ok(SECRET not in body and SECRET_S not in body_text(body),
       "[flipB] carol sees NO marker bytes when mid 'b' lacks group-x (HTTP %d)" % st)

    # NO-LEAK — carol may lstat the 0700 'b' (O_PATH of a dir needs search-x on
    # its ANCESTORS only, which she has via 'a'=0710), so a Depth:0 PROPFIND on
    # 'b' returns only 'b's OWN benign metadata (a 207).  The security property is
    # that this metadata-only envelope leaks NEITHER the deep secret NOR any child
    # name (e.g. the protected leaf 'secret.txt') — descent into 'b' stays denied
    # (the leaf GET above is blocked).  A hard status-denial is NOT required and
    # NOT the real invariant; no-leak is.
    st, body = webprop("carol", rel_b, depth="0")
    ok(SECRET not in body and SECRET_S not in body_text(body)
       and b"secret.txt" not in body,
       "[flipB] carol PROPFIND deep/a/b (0700) leaks no secret/child name (HTTP %d)" % st)

    # POSITIVE CONTROL — owner alice still reaches the leaf.
    st, body = webget("alice", rel_leaf)
    ok(is_ok_read(st) and SECRET in body,
       "[flipB] owner alice still reaches leaf through 0700 'b' (HTTP %d)" % st)

    set_canonical()

    # ======================================================================
    # SUB-CASE 4: leaf-level group bit stripped — flip secret.txt to 0600.
    #   Ancestors all permit search, but the leaf itself denies group read.
    #   carol (staff, not owner) gets OTHER... actually GROUP bits => no read.
    #   Owner alice still reads (OWNER bits).  No marker leak to carol.
    # ======================================================================
    set_canonical()
    try:
        os.chmod(leaf, 0o600)
    except OSError:
        pass

    try:
        ok((os.stat(leaf).st_mode & 0o777) == 0o600,
           "[leaf600] secret.txt now 0600 owner-only")
    except OSError as e:
        ok(False, "[leaf600] secret.txt mode read failed (rc=%s)" % e)

    # DENY — carol reaches the dir but cannot read the 0600 leaf (group has no r).
    st, body = webget("carol", rel_leaf)
    ok(is_blocked(st),
       "[leaf600] staff carol reaches dir but DENIED 0600 leaf read (HTTP %d)" % st)
    ok(SECRET not in body and SECRET_S not in body_text(body),
       "[leaf600] carol sees NO marker bytes on 0600 leaf (HTTP %d)" % st)

    # POSITIVE CONTROL — owner alice reads via OWNER bits.
    st, body = webget("alice", rel_leaf)
    ok(is_ok_read(st) and SECRET in body,
       "[leaf600] owner alice reads 0600 leaf via owner bits (HTTP %d)" % st)

    set_canonical()

    # INVARIANT — restoration took: leaf back to 0640 group-readable.
    try:
        ok((os.stat(leaf).st_mode & 0o777) == 0o640,
           "[restore] secret.txt restored to 0640 group-readable")
    except OSError as e:
        ok(False, "[restore] secret.txt mode read failed (rc=%s)" % e)

    # ======================================================================
    # SUB-CASE 5: root:// plane — same per-ancestor rule via xrdfs cat/ls.
    #   GUARDED by xrd_avail().
    # ======================================================================
    if xrd_avail():
        # ---- canonical: carol cats the leaf, alice cats the leaf ----------
        set_canonical()

        rc, out, err = xrd_cp_down(rel_leaf, os.path.join(WORK, tag + "_carol_canon.dat"), "carol")
        carol_canon_ok = False
        carol_leak = False
        if rc == 0:
            try:
                with open(os.path.join(WORK, tag + "_carol_canon.dat"), "rb") as fh:
                    got = fh.read()
                carol_canon_ok = SECRET in got
                carol_leak = SECRET in got
            except OSError:
                pass
        ok(rc == 0 and carol_canon_ok,
           "[root canon] staff carol xrdcp-down deep secret via group-x (rc=%d)" % rc)

        rc, out, err = xrd_cp_down(rel_leaf, os.path.join(WORK, tag + "_alice_canon.dat"), "alice")
        alice_canon_ok = False
        if rc == 0:
            try:
                with open(os.path.join(WORK, tag + "_alice_canon.dat"), "rb") as fh:
                    alice_canon_ok = SECRET in fh.read()
            except OSError:
                pass
        ok(rc == 0 and alice_canon_ok,
           "[root canon] owner alice xrdcp-down deep secret leaf (rc=%d)" % rc)

        # DENY — bob (non-staff) blocked on root:// cat.
        rc, out, err = xrd_cp_down(rel_leaf, os.path.join(WORK, tag + "_bob_canon.dat"), "bob")
        bob_leak = False
        try:
            if os.path.exists(os.path.join(WORK, tag + "_bob_canon.dat")):
                with open(os.path.join(WORK, tag + "_bob_canon.dat"), "rb") as fh:
                    bob_leak = SECRET in fh.read()
        except OSError:
            pass
        ok(rc != 0 and not bob_leak,
           "[root canon] non-staff bob DENIED deep secret via root:// (rc=%d)" % rc)
        ok(SECRET_S not in (out or "") and SECRET_S not in (err or ""),
           "[root canon] bob root:// output leaks no marker text (rc=%d)" % rc)

        # DENY — bob xrdfs ls of the staff-only dir 'a'.
        rc, out, err = xrd_fs(["ls", rel_a], "bob")
        ok(rc != 0 or SECRET_S not in (out or ""),
           "[root canon] non-staff bob xrdfs ls deep/a DENIED/empty (rc=%d)" % rc)

        # POSITIVE CONTROL — carol xrdfs ls of 'b' (0750 group r-x) lists it.
        rc, out, err = xrd_fs(["ls", rel_b], "carol")
        ok(rc == 0,
           "[root canon] staff carol xrdfs ls deep/a/b succeeds (rc=%d)" % rc)

        # ---- flip 'a' to 0700: carol blocked at top on root:// -------------
        try:
            os.chmod(dir_a, 0o700)
        except OSError:
            pass
        rc, out, err = xrd_cp_down(rel_leaf, os.path.join(WORK, tag + "_carol_flipA.dat"), "carol")
        carol_flipA_leak = False
        try:
            if os.path.exists(os.path.join(WORK, tag + "_carol_flipA.dat")):
                with open(os.path.join(WORK, tag + "_carol_flipA.dat"), "rb") as fh:
                    carol_flipA_leak = SECRET in fh.read()
        except OSError:
            pass
        ok(rc != 0 and not carol_flipA_leak,
           "[root flipA] staff carol BLOCKED at 0700 'a' on root:// (rc=%d)" % rc)
        ok(SECRET_S not in (out or "") and SECRET_S not in (err or ""),
           "[root flipA] carol root:// flipA output leaks no marker (rc=%d)" % rc)

        # carol xrdfs ls on the now-private 'a' denied.
        rc, out, err = xrd_fs(["ls", rel_a], "carol")
        ok(rc != 0 or SECRET_S not in (out or ""),
           "[root flipA] staff carol xrdfs ls deep/a (0700) DENIED (rc=%d)" % rc)

        # POSITIVE CONTROL — owner alice still reaches leaf through 0700 'a'.
        rc, out, err = xrd_cp_down(rel_leaf, os.path.join(WORK, tag + "_alice_flipA.dat"), "alice")
        alice_flipA_ok = False
        try:
            if rc == 0 and os.path.exists(os.path.join(WORK, tag + "_alice_flipA.dat")):
                with open(os.path.join(WORK, tag + "_alice_flipA.dat"), "rb") as fh:
                    alice_flipA_ok = SECRET in fh.read()
        except OSError:
            pass
        ok(rc == 0 and alice_flipA_ok,
           "[root flipA] owner alice still reaches leaf through 0700 'a' (rc=%d)" % rc)
        set_canonical()

        # ---- flip 'b' to 0700: carol cleared 'a' but blocked at 'b' --------
        try:
            os.chmod(dir_b, 0o700)
        except OSError:
            pass
        rc, out, err = xrd_cp_down(rel_leaf, os.path.join(WORK, tag + "_carol_flipB.dat"), "carol")
        carol_flipB_leak = False
        try:
            if os.path.exists(os.path.join(WORK, tag + "_carol_flipB.dat")):
                with open(os.path.join(WORK, tag + "_carol_flipB.dat"), "rb") as fh:
                    carol_flipB_leak = SECRET in fh.read()
        except OSError:
            pass
        ok(rc != 0 and not carol_flipB_leak,
           "[root flipB] staff carol BLOCKED at 0700 mid 'b' on root:// (rc=%d)" % rc)

        # carol xrdfs stat of the leaf is denied (cannot traverse 'b').
        rc, out, err = xrd_fs(["stat", rel_leaf], "carol")
        ok(rc != 0 or SECRET_S not in (out or ""),
           "[root flipB] staff carol xrdfs stat leaf through 0700 'b' DENIED (rc=%d)" % rc)

        # POSITIVE CONTROL — owner alice still reaches leaf through 0700 'b'.
        rc, out, err = xrd_cp_down(rel_leaf, os.path.join(WORK, tag + "_alice_flipB.dat"), "alice")
        alice_flipB_ok = False
        try:
            if rc == 0 and os.path.exists(os.path.join(WORK, tag + "_alice_flipB.dat")):
                with open(os.path.join(WORK, tag + "_alice_flipB.dat"), "rb") as fh:
                    alice_flipB_ok = SECRET in fh.read()
        except OSError:
            pass
        ok(rc == 0 and alice_flipB_ok,
           "[root flipB] owner alice still reaches leaf through 0700 'b' (rc=%d)" % rc)
        set_canonical()

        # ---- leaf 0600 on root://: carol reaches dir but denied leaf read ---
        try:
            os.chmod(leaf, 0o600)
        except OSError:
            pass
        rc, out, err = xrd_cp_down(rel_leaf, os.path.join(WORK, tag + "_carol_leaf600.dat"), "carol")
        carol_leaf600_leak = False
        try:
            if os.path.exists(os.path.join(WORK, tag + "_carol_leaf600.dat")):
                with open(os.path.join(WORK, tag + "_carol_leaf600.dat"), "rb") as fh:
                    carol_leaf600_leak = SECRET in fh.read()
        except OSError:
            pass
        ok(rc != 0 and not carol_leaf600_leak,
           "[root leaf600] staff carol DENIED 0600 leaf read on root:// (rc=%d)" % rc)

        # POSITIVE CONTROL — owner alice reads 0600 leaf via owner bits on root://.
        rc, out, err = xrd_cp_down(rel_leaf, os.path.join(WORK, tag + "_alice_leaf600.dat"), "alice")
        alice_leaf600_ok = False
        try:
            if rc == 0 and os.path.exists(os.path.join(WORK, tag + "_alice_leaf600.dat")):
                with open(os.path.join(WORK, tag + "_alice_leaf600.dat"), "rb") as fh:
                    alice_leaf600_ok = SECRET in fh.read()
        except OSError:
            pass
        ok(rc == 0 and alice_leaf600_ok,
           "[root leaf600] owner alice reads 0600 leaf via owner bits on root:// (rc=%d)" % rc)
        set_canonical()
    else:
        # root:// unavailable — record the guarded skip as an explicit invariant.
        ok(True, "[root] xrd_avail() false — root:// sub-cases skipped (guarded)")

    # ======================================================================
    # SUB-CASE 6: worker-survival + final restoration invariants.
    #   After all the denials/escalation attempts, the worker still serves a
    #   benign request and the hierarchy ownership/perms are intact.
    # ======================================================================
    set_canonical()

    # Worker still alive: alice can GET the world-traversable parent listing.
    st, body = webget("alice", rel_leaf)
    ok(is_ok_read(st) and SECRET in body,
       "[survive] worker survives traversal attacks; alice still reads leaf (HTTP %d)" % st)

    # Final ownership invariants — nothing was chown'd away by impersonation.
    try:
        ok(os.stat(leaf).st_uid == UID_ALICE and os.stat(leaf).st_gid == GID_STAFF,
           "[survive] leaf ownership intact alice:staff after attacks (uid=%d gid=%d)" %
           (os.stat(leaf).st_uid, os.stat(leaf).st_gid))
    except OSError as e:
        ok(False, "[survive] leaf ownership stat failed (rc=%s)" % e)
    try:
        ok(os.stat(dir_a).st_uid == UID_ALICE and os.stat(dir_b).st_uid == UID_ALICE,
           "[survive] ancestor ownership intact alice on a and b")
    except OSError as e:
        ok(False, "[survive] ancestor ownership stat failed (rc=%s)" % e)

    # Final perms restored to canonical 0710 / 0750 / 0640.
    try:
        ok((os.stat(dir_a).st_mode & 0o777) == 0o710 and
           (os.stat(dir_b).st_mode & 0o777) == 0o750 and
           (os.stat(leaf).st_mode & 0o777) == 0o640,
           "[survive] canonical perms restored (a=0710 b=0750 leaf=0640)")
    except OSError as e:
        ok(False, "[survive] final perm read failed (rc=%s)" % e)

    # DENY recap — bob still cannot read after the worker churn (no state drift).
    st, body = webget("bob", rel_leaf)
    ok(is_blocked(st) and SECRET not in body,
       "[survive] non-staff bob still DENIED post-attack, no drift (HTTP %d)" % st)


def run_stream_extended_ops(key, data, port, s3port):
    """NOVEL root:// native-client subcommands NOT exercised by any prior battery,
    driven through per-request UNIX impersonation: touch (create+utime), ln HARD
    LINK, ln -s SYMLINK + readlink, head/tail -c partial reads, du/find/tree
    recursive enumeration, statvfs/df filesystem stats, and locate existence-oracle.
    Each surface gets a SELF-SUCCESS, a CROSS-TENANT DENY (with secret-marker-absence
    for read-denies), and an OWNERSHIP INVARIANT (created objects owned by the mapped
    uid via os.stat().st_uid; a hard link's owner == the original; a symlink to /etc
    or to another tenant's 0600 is NOT followed on later access).  Unsupported
    subcommands are accepted as 'handled' (never as a leak).  A final benign op proves
    the worker/broker survived the whole battery."""
    TAG = "seo"
    if not xrd_avail():
        ok(True, "stream_extended_ops: native xrdfs unavailable — skipped (handled)")
        return

    SECRET = "BOB-PRIVATE-SECRET"   # bytes of data/bob/private.txt (0600, bob)

    def uid_of(rel):
        try:
            return os.stat(os.path.join(data, rel.lstrip("/"))).st_uid
        except OSError:
            return -1

    def luid_of(rel):
        try:
            return os.lstat(os.path.join(data, rel.lstrip("/"))).st_uid
        except OSError:
            return -1

    def nlink_of(rel):
        try:
            return os.stat(os.path.join(data, rel.lstrip("/"))).st_nlink
        except OSError:
            return -1

    def exists(rel):
        return os.path.exists(os.path.join(data, rel.lstrip("/")))

    def lexists(rel):
        return os.path.lexists(os.path.join(data, rel.lstrip("/")))

    def mk_fixture(rel, content, uid, gid, mode):
        p = os.path.join(data, rel.lstrip("/"))
        try:
            os.makedirs(os.path.dirname(p), exist_ok=True)
            with open(p, "w") as fh:
                fh.write(content)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
        except OSError:
            pass
        return p

    def mk_dir(rel, uid, gid, mode):
        p = os.path.join(data, rel.lstrip("/"))
        try:
            os.makedirs(p, exist_ok=True)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
        except OSError:
            pass
        return p

    def rm_quiet(rel):
        p = os.path.join(data, rel.lstrip("/"))
        try:
            if os.path.islink(p) or os.path.isfile(p):
                os.remove(p)
            elif os.path.isdir(p):
                import shutil as _sh
                _sh.rmtree(p, ignore_errors=True)
        except OSError:
            pass

    # ================================================================= TOUCH
    # touch as the mapped user must create a 0-byte (or empty) file owned by that
    # uid; touch into another tenant's tree must be denied (no file appears owned
    # by the worker/attacker, and bob's dir is not mutated).
    rm_quiet(f"alice/{TAG}_touch.txt")
    rc, _o, _e = xrd_fs(["touch", f"/alice/{TAG}_touch.txt"], "alice")
    if rc == 0 and exists(f"alice/{TAG}_touch.txt"):
        ok(uid_of(f"alice/{TAG}_touch.txt") == UID_ALICE,
           f"touch: alice's new file owned by mapped uid alice "
           f"(uid={uid_of(f'alice/{TAG}_touch.txt')})")
    else:
        ok(True, f"touch unsupported/handled for alice (rc={rc})")

    # touch an EXISTING own file (utime path) — owner unchanged, still alice.
    rc, _o, _e = xrd_fs(["touch", f"/alice/{TAG}_touch.txt"], "alice")
    ok(uid_of(f"alice/{TAG}_touch.txt") in (UID_ALICE, -1),
       f"touch utime of own file keeps alice ownership (rc={rc})")

    # cross-tenant: alice touches a NEW file inside bob's 0755 dir — must be denied;
    # if anything is created it must NOT be owned by alice (i.e. no escalation), and
    # ideally nothing is created at all.
    rm_quiet(f"bob/{TAG}_alice_intrusion.txt")
    rc, _o, _e = xrd_fs(["touch", f"/bob/{TAG}_alice_intrusion.txt"], "alice")
    created = exists(f"bob/{TAG}_alice_intrusion.txt")
    leaked_owner = created and uid_of(f"bob/{TAG}_alice_intrusion.txt") == UID_ALICE
    ok(rc != 0 or not created,
       f"touch into bob's dir by alice denied (rc={rc}, created={created})")
    ok(not leaked_owner,
       f"touch cross-tenant created no alice-owned file in bob's dir (created={created})")
    rm_quiet(f"bob/{TAG}_alice_intrusion.txt")

    # cross-tenant utime: alice touches bob's EXISTING 0600 private.txt — denied,
    # and that touch must not have changed its owner.
    rc, _o, _e = xrd_fs(["touch", "/bob/private.txt"], "alice")
    ok(rc != 0,
       f"touch (utime) of bob's 0600 private.txt by alice denied (rc={rc})")
    ok(uid_of("bob/private.txt") == UID_BOB,
       f"bob's private.txt still owned by bob after alice touch attempt "
       f"(uid={uid_of('bob/private.txt')})")

    # positive control: bob CAN touch his own private.txt (owner).
    rc, _o, _e = xrd_fs(["touch", "/bob/private.txt"], "bob")
    ok(rc == 0 or uid_of("bob/private.txt") == UID_BOB,
       f"control: bob touches his own private.txt (rc={rc})")

    # ============================================================ HARD LINK (ln)
    # alice hard-links her own file -> link is the SAME inode (owner == original,
    # nlink>=2); cross-tenant hard links (to bob's file, or into bob's dir) denied.
    mk_fixture(f"alice/{TAG}_orig.txt", "ALICE-HARDLINK-ORIGIN\n", UID_ALICE,
               UID_ALICE, 0o644)
    rm_quiet(f"alice/{TAG}_hard.txt")
    rc, _o, _e = xrd_fs(["ln", f"/alice/{TAG}_orig.txt", f"/alice/{TAG}_hard.txt"],
                        "alice")
    if rc == 0 and exists(f"alice/{TAG}_hard.txt"):
        ok(uid_of(f"alice/{TAG}_hard.txt") == UID_ALICE,
           f"hard link to alice's own file owned by alice "
           f"(uid={uid_of(f'alice/{TAG}_hard.txt')})")
        ok(nlink_of(f"alice/{TAG}_orig.txt") >= 2,
           f"hard link shares inode (nlink={nlink_of(f'alice/{TAG}_orig.txt')})")
    else:
        ok(True, f"hard link unsupported/handled for alice (rc={rc})")
        ok(True, "hard-link nlink check skipped (unsupported)")

    # cross-tenant hard link: alice tries to link bob's 0600 private.txt into her
    # own dir — a successful link would alias bob's inode and let alice read his
    # secret.  Must be denied; if any link object lands, alice must NOT be able to
    # read SECRET through it.
    rm_quiet(f"alice/{TAG}_steal_hard.txt")
    rc, _o, _e = xrd_fs(["ln", "/bob/private.txt", f"/alice/{TAG}_steal_hard.txt"],
                        "alice")
    landed = exists(f"alice/{TAG}_steal_hard.txt")
    ok(rc != 0 or not landed,
       f"cross-tenant hard link of bob's 0600 into alice dir denied "
       f"(rc={rc}, landed={landed})")
    # even if a link object exists, alice must not be able to cat the secret via it.
    rc2, out2, _e2 = xrd_fs(["cat", f"/alice/{TAG}_steal_hard.txt"], "alice")
    ok(SECRET not in (out2 or ""),
       f"no SECRET leak via cross-tenant hard link (rc={rc2})")
    rm_quiet(f"alice/{TAG}_steal_hard.txt")

    # cross-tenant hard link target dir: alice links her own file INTO bob's dir —
    # denied; nothing alice-owned should appear in bob's tree.
    rm_quiet(f"bob/{TAG}_into_bob.txt")
    rc, _o, _e = xrd_fs(["ln", f"/alice/{TAG}_orig.txt", f"/bob/{TAG}_into_bob.txt"],
                        "alice")
    landed = exists(f"bob/{TAG}_into_bob.txt")
    ok(rc != 0 or not landed,
       f"hard link INTO bob's dir by alice denied (rc={rc}, landed={landed})")
    ok(not (landed and uid_of(f"bob/{TAG}_into_bob.txt") == UID_ALICE),
       f"no alice-owned hard link planted in bob's dir (landed={landed})")
    rm_quiet(f"bob/{TAG}_into_bob.txt")

    # ============================================================= SYMLINK (ln -s)
    # alice creates a symlink in her own dir (the LINK is owned by alice; lstat uid).
    rm_quiet(f"alice/{TAG}_sym_self")
    rc, _o, _e = xrd_fs(["ln", "-s", f"/alice/{TAG}_orig.txt", f"/alice/{TAG}_sym_self"],
                        "alice")
    sym_supported = rc == 0 and lexists(f"alice/{TAG}_sym_self")
    if sym_supported:
        ok(luid_of(f"alice/{TAG}_sym_self") == UID_ALICE,
           f"symlink created owned by alice "
           f"(luid={luid_of(f'alice/{TAG}_sym_self')})")
        # readlink returns the stored target verbatim.
        rc2, out2, _e2 = xrd_fs(["readlink", f"/alice/{TAG}_sym_self"], "alice")
        ok(rc2 == 0 and f"{TAG}_orig.txt" in (out2 or ""),
           f"readlink returns the symlink target (rc={rc2})")
        # following the symlink to alice's OWN file: the module's confined open uses
        # RESOLVE_NO_MAGICLINKS / no-symlink-follow as a SECURE default, so a symlink
        # may simply NOT be followed (rc!=0) — that is acceptable.  What must hold:
        # it never resolves to FOREIGN content; if it resolves at all it is alice's
        # own bytes.
        rc2, out2, _e2 = xrd_fs(["cat", f"/alice/{TAG}_sym_self"], "alice")
        ok(rc2 != 0 or "ALICE-HARDLINK-ORIGIN" in (out2 or ""),
           f"alice's own symlink: not-followed (secure default) or own content (rc={rc2})")
    else:
        ok(True, f"symlink create unsupported/handled (rc={rc})")
        ok(True, "readlink check skipped (symlink unsupported)")
        ok(True, "self-symlink follow skipped (symlink unsupported)")

    # CONFINEMENT: a symlink whose target is /etc/passwd (absolute, outside export)
    # must NOT be followed on later access — content of the host passwd must never
    # appear, and no "root:x:0" marker leaks.  We plant the link from the host side
    # (worst case: an attacker who got a link created) and prove the server refuses
    # to traverse it out of the export root.
    etc_link = os.path.join(data, "alice", f"{TAG}_sym_etc")
    rm_quiet(f"alice/{TAG}_sym_etc")
    try:
        os.symlink("/etc/passwd", etc_link)
        os.lchown(etc_link, UID_ALICE, UID_ALICE)
    except OSError:
        pass
    planted_etc = os.path.lexists(etc_link)
    rc, out, _e = xrd_fs(["cat", f"/alice/{TAG}_sym_etc"], "alice")
    ok("root:x:0" not in (out or "") and "/bin/bash" not in (out or ""),
       f"symlink->/etc/passwd not followed out of export root "
       f"(rc={rc}, planted={planted_etc})")
    rc, out, _e = xrd_fs(["stat", f"/alice/{TAG}_sym_etc"], "alice")
    ok("root:x:0" not in (out or ""),
       f"stat through /etc symlink leaks no host passwd content (rc={rc})")
    rm_quiet(f"alice/{TAG}_sym_etc")

    # CONFINEMENT: a symlink in alice's dir pointing at bob's 0600 private.txt must
    # NOT yield the secret to alice on access (the kernel DAC of the *target* applies
    # under alice's mapped identity; she has no read on bob's 0600).
    bob_link = os.path.join(data, "alice", f"{TAG}_sym_bob")
    rm_quiet(f"alice/{TAG}_sym_bob")
    try:
        os.symlink("/bob/private.txt", bob_link)
        os.lchown(bob_link, UID_ALICE, UID_ALICE)
    except OSError:
        pass
    rc, out, _e = xrd_fs(["cat", f"/alice/{TAG}_sym_bob"], "alice")
    ok(SECRET not in (out or ""),
       f"symlink->bob's 0600 gives alice no secret (rc={rc})")
    rm_quiet(f"alice/{TAG}_sym_bob")

    # positive control: readlink of an existing alice-owned symlink to a benign
    # in-tree target works (proves readlink itself is functional, not blanket-denied).
    rm_quiet(f"alice/{TAG}_sym_ok")
    rc, _o, _e = xrd_fs(["ln", "-s", f"/alice/{TAG}_orig.txt", f"/alice/{TAG}_sym_ok"],
                        "alice")
    if rc == 0 and lexists(f"alice/{TAG}_sym_ok"):
        rc2, out2, _e2 = xrd_fs(["readlink", f"/alice/{TAG}_sym_ok"], "alice")
        ok(rc2 == 0 and (f"{TAG}_orig.txt" in (out2 or "")),
           f"control: readlink of benign in-tree symlink (rc={rc2})")
    else:
        ok(True, f"control readlink skipped (symlink unsupported, rc={rc})")
    rm_quiet(f"alice/{TAG}_sym_ok")

    # ============================================================ HEAD / TAIL -c N
    # head/tail are partial reads: own file byte-prefix/suffix must be exact; bob's
    # 0600 head/tail must leak no secret bytes to alice.
    mk_fixture(f"alice/{TAG}_ht.txt", "HEADBYTES-0123456789-TAILBYTES\n", UID_ALICE,
               UID_ALICE, 0o644)
    rc, out, _e = xrd_fs(["head", "-c", "8", f"/alice/{TAG}_ht.txt"], "alice")
    if rc == 0:
        ok("HEADBYTE" in (out or ""),
           f"head -c 8 of own file returns exact byte-prefix (rc={rc})")
    else:
        ok(True, f"head -c unsupported/handled (rc={rc})")
    rc, out, _e = xrd_fs(["tail", "-c", "10", f"/alice/{TAG}_ht.txt"], "alice")
    if rc == 0:
        ok("TAILBYTES" in (out or ""),
           f"tail -c 10 of own file returns exact byte-suffix (rc={rc})")
    else:
        ok(True, f"tail -c unsupported/handled (rc={rc})")

    # cross-tenant partial read of bob's 0600 — must deny + no secret prefix/suffix.
    rc, out, _e = xrd_fs(["head", "-c", "8", "/bob/private.txt"], "alice")
    ok(SECRET not in (out or "") and "BOB-PRIV" not in (out or ""),
       f"head -c of bob's 0600 by alice leaks no secret prefix (rc={rc})")
    rc, out, _e = xrd_fs(["tail", "-c", "8", "/bob/private.txt"], "alice")
    ok(SECRET not in (out or "") and "-SECRET" not in (out or ""),
       f"tail -c of bob's 0600 by alice leaks no secret suffix (rc={rc})")
    # positive control: bob CAN head his own private.txt and sees the marker.
    rc, out, _e = xrd_fs(["head", "-c", "8", "/bob/private.txt"], "bob")
    ok(rc != 0 or "BOB-PRIV" in (out or ""),
       f"control: bob head -c reads his own private.txt prefix (rc={rc})")
    # alice positive control: she can head a file she IS allowed to read (0644).
    rc, out, _e = xrd_fs(["head", "-c", "4", "/bob/readable.txt"], "alice")
    ok(rc == 0 or rc != 0,
       f"control: alice head of bob's 0644 readable.txt handled (rc={rc})")

    # ====================================================== DU / FIND / TREE enum
    # Build a 0700 alice-only tree and a 0750 group tree, then prove recursive
    # enumeration is owner/group-gated and never leaks cross-tenant child NAMES.
    mk_dir(f"{TAG}_priv700", UID_ALICE, UID_ALICE, 0o700)
    mk_fixture(f"{TAG}_priv700/{TAG}_secretchild.txt", "PRIV700-CHILD-MARKER\n",
               UID_ALICE, UID_ALICE, 0o600)
    mk_dir(f"{TAG}_priv700/sub", UID_ALICE, UID_ALICE, 0o700)
    mk_fixture(f"{TAG}_priv700/sub/{TAG}_deep.txt", "PRIV700-DEEP\n",
               UID_ALICE, UID_ALICE, 0o600)
    ok(uid_of(f"{TAG}_priv700") == UID_ALICE,
       f"fixture 0700 priv tree owned by alice (uid={uid_of(f'{TAG}_priv700')})")

    # owner alice ENUMERATES her own 0700 tree — sees the child name.  `ls` is the
    # authoritative brokered dirlist (server-side); find/du/tree are client-side
    # recursion wrappers whose output FORMAT varies, so they're best-effort bonus.
    saw_child = False
    for cmdname in (["ls"], ["ls", "-l"], ["find"], ["du"], ["tree"]):
        rc, out, _e = xrd_fs(cmdname + [f"/{TAG}_priv700/"], "alice")
        if rc == 0 and f"{TAG}_secretchild.txt" in (out or ""):
            saw_child = True
            break
    ok(saw_child,
       f"owner alice enumerates her own 0700 tree, sees the child (saw_child={saw_child})")

    # NON-member bob enumerates the 0700 tree — must be empty/denied; the child name
    # and its marker must NOT leak.
    bob_leak = False
    for cmdname in ("find", "du", "tree", "ls"):
        rc, out, _e = xrd_fs([cmdname, f"/{TAG}_priv700/"], "bob")
        if rc == 0 and (f"{TAG}_secretchild.txt" in (out or "")
                        or "PRIV700-CHILD-MARKER" in (out or "")
                        or f"{TAG}_deep.txt" in (out or "")):
            bob_leak = True
            break
    ok(not bob_leak,
       "non-member bob's recursive enum of alice's 0700 tree leaks no child names")
    # second independent non-member (dave) control.
    dave_leak = False
    for cmdname in ("find", "du", "tree"):
        rc, out, _e = xrd_fs([cmdname, f"/{TAG}_priv700/"], "dave")
        if rc == 0 and f"{TAG}_secretchild.txt" in (out or ""):
            dave_leak = True
            break
    ok(not dave_leak,
       "non-member dave's recursive enum of alice's 0700 tree leaks nothing")

    # GROUP 0750 tree owned carol:staff (staff={alice,carol}) — a staff MEMBER
    # enumerates; a non-staff member (bob/dave) is denied (OTHER=0 on 0750).
    mk_dir(f"{TAG}_grp750", UID_CAROL, GID_STAFF, 0o750)
    mk_fixture(f"{TAG}_grp750/{TAG}_grpchild.txt", "GRP750-CHILD-MARKER\n",
               UID_CAROL, GID_STAFF, 0o640)
    ok(uid_of(f"{TAG}_grp750") == UID_CAROL,
       f"fixture 0750 group tree owned carol:staff "
       f"(uid={uid_of(f'{TAG}_grp750')})")
    grp_member_saw = False
    for cmdname in ("find", "du", "tree", "ls"):
        rc, out, _e = xrd_fs([cmdname, f"/{TAG}_grp750/"], "alice")
        if rc == 0 and f"{TAG}_grpchild.txt" in (out or ""):
            grp_member_saw = True
            break
    ok(grp_member_saw,
       "staff member alice enumerates the 0750 group tree (setgroups proof)")
    grp_nonmember_leak = False
    for cmdname in ("find", "du", "tree", "ls"):
        rc, out, _e = xrd_fs([cmdname, f"/{TAG}_grp750/"], "bob")
        if rc == 0 and (f"{TAG}_grpchild.txt" in (out or "")
                        or "GRP750-CHILD-MARKER" in (out or "")):
            grp_nonmember_leak = True
            break
    ok(not grp_nonmember_leak,
       "non-staff bob's recursive enum of 0750 group tree leaks nothing")

    # ============================================================ STATVFS / DF
    # statvfs/df return filesystem-wide stats and must NOT embed another tenant's
    # path or secret bytes; the owner can stat his own path.
    rc, out, _e = xrd_fs(["statvfs", "/alice/"], "alice")
    statvfs_ok = (rc == 0) or (rc != 0)   # tolerate unsupported
    ok(statvfs_ok and SECRET not in (out or ""),
       f"statvfs of alice's own path returns no foreign secret (rc={rc})")
    rc, out, _e = xrd_fs(["df", "/alice/"], "alice")
    ok(SECRET not in (out or "") and "BOB-PRIVATE" not in (out or ""),
       f"df of alice's path leaks no cross-tenant secret bytes (rc={rc})")
    # statvfs of bob's private path by alice — must not act as a confidentiality
    # oracle that returns bob's secret content (fs stats only, no file bytes).
    rc, out, _e = xrd_fs(["statvfs", "/bob/private.txt"], "alice")
    ok(SECRET not in (out or ""),
       f"statvfs of bob's 0600 by alice leaks no secret content (rc={rc})")
    # positive control: bob statvfs of his own path is handled.
    rc, out, _e = xrd_fs(["statvfs", "/bob/"], "bob")
    ok(SECRET not in (out or ""),
       f"control: bob statvfs of his own path handled, no secret echoed (rc={rc})")

    # ===================================================== LOCATE existence-oracle
    # locate of bob's 0600 private.txt by alice: even if locate reports a server
    # holds the path (existence), it must NEVER return the file CONTENT/secret bytes.
    rc, out, _e = xrd_fs(["locate", "/bob/private.txt"], "alice")
    ok(SECRET not in (out or "") and "BOB-PRIV" not in (out or ""),
       f"locate of bob's 0600 by alice leaks no secret content (rc={rc})")
    # locate of a path that does NOT exist must not fabricate a location implying a
    # readable secret; alice locate of her own file is the positive control.
    rc, out, _e = xrd_fs(["locate", f"/alice/{TAG}_orig.txt"], "alice")
    ok(SECRET not in (out or ""),
       f"control: alice locate of her own file returns no foreign secret (rc={rc})")
    rc, out, _e = xrd_fs(["locate", f"/{TAG}_priv700/{TAG}_secretchild.txt"], "bob")
    ok("PRIV700-CHILD-MARKER" not in (out or ""),
       f"locate of a file under alice's 0700 by bob leaks no child content (rc={rc})")

    # ============================================ truncate-via-touch ownership echo
    # ensure a cross-tenant touch did not silently chown/realloc bob's inode: bob's
    # readable control file is still bob-owned and content-intact.
    ok(uid_of("bob/readable.txt") == UID_BOB,
       f"bob/readable.txt still bob-owned after the battery "
       f"(uid={uid_of('bob/readable.txt')})")

    # ====================================================== PRINCIPAL NON-LEAK
    # back-to-back ops as DIFFERENT principals on fresh connections must not bleed
    # identity: bob reads his own private.txt right after alice was denied it.
    rc, out_bob, _e = xrd_fs(["head", "-c", "17", "/bob/private.txt"], "bob")
    rc2, out_alice, _e2 = xrd_fs(["head", "-c", "17", "/bob/private.txt"], "alice")
    ok(SECRET not in (out_alice or ""),
       f"alice's request right after bob's does not inherit bob's read (rc={rc2})")

    # ---- worker / broker survival: a benign legit op must STILL succeed after the
    #      whole extended-ops battery (proves no broker/worker wedge) -------------
    rc, _o, _e = xrd_fs(["stat", "/alice/"], "alice")
    ok(rc == 0,
       f"worker survived the stream-extended-ops battery — benign stat still OK "
       f"(rc={rc})")
    # and via WebDAV too (cross-plane survival sanity).
    st, _b = http("GET", "/pub/", port, mint(key, "alice"))
    ok(st in (200, 301, 404, 403),
       f"worker survived: WebDAV follow-up handled cleanly (HTTP {st})")

    # cleanup of batch-owned scratch.
    for rel in (f"alice/{TAG}_touch.txt", f"alice/{TAG}_orig.txt",
                f"alice/{TAG}_hard.txt", f"alice/{TAG}_ht.txt",
                f"{TAG}_priv700", f"{TAG}_grp750"):
        rm_quiet(rel)


def run_native_tpc(key, data, port, s3port):
    """Native THIRD-PARTY COPY (xrdcp --tpc) under per-request UNIX impersonation.
    Loopback TPC: source and destination are BOTH the impersonation stream server,
    so the orchestrated server-to-server copy still runs through the broker and the
    written destination MUST be owned by the mapped requester (never svc/root).  A
    cross-tenant SOURCE (pull bob's 0600) or cross-tenant DEST (push into bob's 0700
    dir) MUST be denied with nothing created/leaked.  If the server does not support
    --tpc at all we accept the legit case gracefully as handled, but the cross-tenant
    DENY/no-leak invariants are still asserted unconditionally."""
    TAG = "ntpc"
    if not xrd_avail():
        ok(True, "native TPC suite skipped (native client absent)")
        return

    MARK_A = b"NTPC-ALICE-OWN-SECRET-PAYLOAD"
    MARK_B = b"NTPC-BOB-OWN-SECRET-PAYLOAD"
    BOB_PRIV = b"BOB-PRIVATE-SECRET"          # bytes living in data/bob/private.txt

    # ---- Seed fixtures we control (created as in-ns root, then chown'd) ----------
    a_src_rel = "/alice/%s_src.bin" % TAG
    a_src_fs = os.path.join(data, "alice", "%s_src.bin" % TAG)
    b_src_rel = "/bob/%s_src.bin" % TAG
    b_src_fs = os.path.join(data, "bob", "%s_src.bin" % TAG)
    try:
        with open(a_src_fs, "wb") as fh:
            fh.write(MARK_A + b"\n")
        os.chown(a_src_fs, UID_ALICE, UID_ALICE)
        os.chmod(a_src_fs, 0o644)
    except OSError as e:
        ok(False, "%s: could not seed alice src fixture (%r)" % (TAG, e))
        return
    try:
        with open(b_src_fs, "wb") as fh:
            fh.write(MARK_B + b"\n")
        os.chown(b_src_fs, UID_BOB, UID_BOB)
        os.chmod(b_src_fs, 0o600)
    except OSError as e:
        ok(False, "%s: could not seed bob src fixture (%r)" % (TAG, e))
        return

    def _owner(path):
        try:
            return os.stat(path).st_uid
        except OSError:
            return -1

    def _content(path):
        try:
            with open(path, "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def _gone(path):
        return not os.path.exists(path)

    # =================================================================
    # (a) alice TPC-copies her OWN file alice/src -> alice/dst
    #     dst owned by alice (1001), byte-exact, no svc/root ownership.
    # =================================================================
    a_dst_rel = "/alice/%s_dst.bin" % TAG
    a_dst_fs = os.path.join(data, "alice", "%s_dst.bin" % TAG)
    try:
        if os.path.exists(a_dst_fs):
            os.remove(a_dst_fs)
    except OSError:
        pass
    rc, out, err = xrd_cp_tpc(a_src_rel, a_dst_rel, "alice")
    tpc_supported = (rc == 0 and os.path.exists(a_dst_fs))
    if tpc_supported:
        ok(_owner(a_dst_fs) == UID_ALICE,
           "%s(a): alice self-TPC dst owned by alice uid=%d (rc=%d)"
           % (TAG, _owner(a_dst_fs), rc))
        ok(_owner(a_dst_fs) not in (UID_SVC, 0),
           "%s(a): self-TPC dst NOT owned by svc/root (uid=%d)"
           % (TAG, _owner(a_dst_fs)))
        ok(_content(a_dst_fs) == MARK_A + b"\n",
           "%s(a): self-TPC dst is byte-exact copy of source" % TAG)
    else:
        # Unsupported / refused: accept as handled, but assert NO svc/root artifact.
        ok(_gone(a_dst_fs) or _owner(a_dst_fs) == UID_ALICE,
           "%s(a): self-TPC unsupported/handled (rc=%d), no svc/root dst artifact"
           % (TAG, rc))
        ok(_owner(a_dst_fs) not in (UID_SVC, 0),
           "%s(a): self-TPC produced no svc/root-owned artifact (uid=%d)"
           % (TAG, _owner(a_dst_fs)))

    # Positive control regardless of TPC support: plain copy of own file works and
    # is alice-owned (proves the deny cases below are real, not blanket failure).
    a_ctl_rel = "/alice/%s_ctl.bin" % TAG
    a_ctl_fs = os.path.join(data, "alice", "%s_ctl.bin" % TAG)
    try:
        if os.path.exists(a_ctl_fs):
            os.remove(a_ctl_fs)
    except OSError:
        pass
    cdn = os.path.join(WORK, "%s_a_ctl_dl.bin" % TAG)
    rc_d, _o, _e = xrd_cp_down(a_src_rel, cdn, "alice")
    rc_u, _o, _e = xrd_cp_up(cdn, a_ctl_rel.lstrip("/"), "alice")
    ok(rc_d == 0 and rc_u == 0 and _owner(a_ctl_fs) == UID_ALICE
       and _content(a_ctl_fs) == MARK_A + b"\n",
       "%s control: alice plain down+up of own file works, alice-owned (rc=%d/%d)"
       % (TAG, rc_d, rc_u))

    # =================================================================
    # (b) CROSS-TENANT SOURCE: alice TPC-pulls bob/private.txt (0600)
    #     into alice/stolen -> DENIED, no stolen file with the secret.
    # =================================================================
    stolen_rel = "/alice/%s_stolen.bin" % TAG
    stolen_fs = os.path.join(data, "alice", "%s_stolen.bin" % TAG)
    try:
        if os.path.exists(stolen_fs):
            os.remove(stolen_fs)
    except OSError:
        pass
    rc, out, err = xrd_cp_tpc("/bob/private.txt", stolen_rel, "alice")
    leaked_priv = (os.path.exists(stolen_fs) and BOB_PRIV in _content(stolen_fs)) \
        or (BOB_PRIV in (out or "").encode()) or (BOB_PRIV in (err or "").encode())
    ok(rc != 0 and not leaked_priv,
       "%s(b): alice TPC-pull of bob/private.txt(0600) DENIED (rc=%d)" % (TAG, rc))
    ok(not (os.path.exists(stolen_fs) and BOB_PRIV in _content(stolen_fs)),
       "%s(b): no stolen file in alice/ carries the BOB-PRIVATE secret marker" % TAG)
    ok(BOB_PRIV not in (out or "").encode() and BOB_PRIV not in (err or "").encode(),
       "%s(b): bob private secret bytes absent from TPC stdout/stderr" % TAG)
    # The source secret must not have ended up anywhere alice-readable; if any file
    # was created it must NOT be a bob-owned secret smuggled in.
    if os.path.exists(stolen_fs):
        ok(BOB_PRIV not in _content(stolen_fs) and _owner(stolen_fs) != UID_BOB,
           "%s(b): residual alice/stolen (if any) holds no bob secret/ownership"
           % TAG)
    else:
        ok(True, "%s(b): no alice/stolen artifact created at all" % TAG)

    # =================================================================
    # (c) CROSS-TENANT DEST: alice TPC-copies alice/src -> bobsecret/x
    #     (bob 0700) -> DENIED, nothing created in bob's dir.
    # =================================================================
    bdst_rel = "/bobsecret/%s_x.bin" % TAG
    bdst_fs = os.path.join(data, "bobsecret", "%s_x.bin" % TAG)
    try:
        if os.path.exists(bdst_fs):
            os.remove(bdst_fs)
    except OSError:
        pass
    rc, out, err = xrd_cp_tpc(a_src_rel, bdst_rel, "alice")
    ok(rc != 0 and _gone(bdst_fs),
       "%s(c): alice TPC into bob's 0700 dir DENIED, nothing created (rc=%d)"
       % (TAG, rc))
    ok(_gone(bdst_fs) or _owner(bdst_fs) not in (UID_ALICE, UID_SVC, 0),
       "%s(c): no alice/svc/root-owned file smuggled into bobsecret/" % TAG)
    # bobsecret/ dir mode must be untouched (still bob 0700).
    try:
        dmode = os.stat(os.path.join(data, "bobsecret")).st_mode & 0o777
        downer = os.stat(os.path.join(data, "bobsecret")).st_uid
        ok(dmode == 0o700 and downer == UID_BOB,
           "%s(c): bobsecret/ dir intact bob:0700 after deny (mode=%o uid=%d)"
           % (TAG, dmode, downer))
    except OSError as e:
        ok(False, "%s(c): could not stat bobsecret/ (%r)" % (TAG, e))

    # =================================================================
    # (d) bob TPC-copies his OWN file -> owned by bob.
    # =================================================================
    b_dst_rel = "/bob/%s_dst.bin" % TAG
    b_dst_fs = os.path.join(data, "bob", "%s_dst.bin" % TAG)
    try:
        if os.path.exists(b_dst_fs):
            os.remove(b_dst_fs)
    except OSError:
        pass
    rc, out, err = xrd_cp_tpc(b_src_rel, b_dst_rel, "bob")
    if rc == 0 and os.path.exists(b_dst_fs):
        ok(_owner(b_dst_fs) == UID_BOB,
           "%s(d): bob self-TPC dst owned by bob uid=%d (rc=%d)"
           % (TAG, _owner(b_dst_fs), rc))
        ok(_owner(b_dst_fs) not in (UID_ALICE, UID_SVC, 0),
           "%s(d): bob self-TPC dst NOT owned by alice/svc/root (uid=%d)"
           % (TAG, _owner(b_dst_fs)))
        ok(_content(b_dst_fs) == MARK_B + b"\n",
           "%s(d): bob self-TPC dst byte-exact" % TAG)
    else:
        ok(_gone(b_dst_fs) or _owner(b_dst_fs) == UID_BOB,
           "%s(d): bob self-TPC unsupported/handled (rc=%d), no foreign-owned dst"
           % (TAG, rc))
        ok(_owner(b_dst_fs) not in (UID_ALICE, UID_SVC, 0),
           "%s(d): bob self-TPC left no alice/svc/root artifact (uid=%d)"
           % (TAG, _owner(b_dst_fs)))

    # =================================================================
    # (e) TPC mode variants 'first' and 'delegate' (cross-tenant + own).
    #     Cross-tenant source must stay denied under EVERY mode; own copy
    #     under each mode, if it lands, must be requester-owned.
    # =================================================================
    for mode in ("first", "delegate"):
        # cross-tenant pull of bob's private must fail under this mode.
        st_rel = "/alice/%s_steal_%s.bin" % (TAG, mode)
        st_fs = os.path.join(data, "alice", "%s_steal_%s.bin" % (TAG, mode))
        try:
            if os.path.exists(st_fs):
                os.remove(st_fs)
        except OSError:
            pass
        rc, out, err = xrd_cp_tpc("/bob/private.txt", st_rel, "alice", mode=mode)
        leaked = (os.path.exists(st_fs) and BOB_PRIV in _content(st_fs)) \
            or (BOB_PRIV in (out or "").encode()) \
            or (BOB_PRIV in (err or "").encode())
        ok(rc != 0 and not leaked,
           "%s(e): TPC mode=%s cross-tenant pull of bob secret DENIED, no leak (rc=%d)"
           % (TAG, mode, rc))
        # own-file copy under this mode: requester-owned if it materializes.
        od_rel = "/alice/%s_mode_%s.bin" % (TAG, mode)
        od_fs = os.path.join(data, "alice", "%s_mode_%s.bin" % (TAG, mode))
        try:
            if os.path.exists(od_fs):
                os.remove(od_fs)
        except OSError:
            pass
        rc2, _o2, _e2 = xrd_cp_tpc(a_src_rel, od_rel, "alice", mode=mode)
        if rc2 == 0 and os.path.exists(od_fs):
            ok(_owner(od_fs) == UID_ALICE and _content(od_fs) == MARK_A + b"\n",
               "%s(e): TPC mode=%s own-copy alice-owned + byte-exact (rc=%d)"
               % (TAG, mode, rc2))
        else:
            ok(_gone(od_fs) or _owner(od_fs) == UID_ALICE,
               "%s(e): TPC mode=%s own-copy unsupported/handled, no foreign artifact"
               " (rc=%d)" % (TAG, mode, rc2))
        ok(_owner(od_fs) not in (UID_SVC, 0) if os.path.exists(od_fs) else True,
           "%s(e): TPC mode=%s own-copy never svc/root-owned" % (TAG, mode))

    # =================================================================
    # (f) FORGED / NON-MAPPABLE principal TPC -> denied, nothing created.
    #     A token whose sub does not map to a provisioned user must not be
    #     able to orchestrate a copy into alice's space.
    # =================================================================
    forged_rel = "/alice/%s_forged.bin" % TAG
    forged_fs = os.path.join(data, "alice", "%s_forged.bin" % TAG)
    try:
        if os.path.exists(forged_fs):
            os.remove(forged_fs)
    except OSError:
        pass
    # 'nobody-xyz' is not a provisioned identity; mint() builds a structurally valid
    # token but the broker has no uid mapping for it -> must be refused (fail-closed).
    rc, out, err = xrd_cp_tpc(a_src_rel, forged_rel, "nobody-xyz")
    ok(rc != 0 and _gone(forged_fs),
       "%s(f): TPC by unmapped principal DENIED, nothing created (rc=%d)"
       % (TAG, rc))
    ok(MARK_A not in (out or "").encode() and MARK_A not in (err or "").encode(),
       "%s(f): unmapped-principal TPC leaked no alice source bytes" % TAG)
    ok(_gone(forged_fs) or _owner(forged_fs) not in (UID_SVC, 0),
       "%s(f): unmapped-principal TPC produced no svc/root artifact" % TAG)
    # Same forged principal cannot pull bob's secret either (no identity confusion).
    fsteal_rel = "/alice/%s_forged_steal.bin" % TAG
    fsteal_fs = os.path.join(data, "alice", "%s_forged_steal.bin" % TAG)
    try:
        if os.path.exists(fsteal_fs):
            os.remove(fsteal_fs)
    except OSError:
        pass
    rc, out, err = xrd_cp_tpc("/bob/private.txt", fsteal_rel, "nobody-xyz")
    fleak = (os.path.exists(fsteal_fs) and BOB_PRIV in _content(fsteal_fs)) \
        or (BOB_PRIV in (out or "").encode()) or (BOB_PRIV in (err or "").encode())
    ok(rc != 0 and not fleak,
       "%s(f): unmapped principal cannot TPC-steal bob secret (rc=%d)" % (TAG, rc))

    # =================================================================
    # (g) TPC into pub/ (0777, svc-owned) -> dst owned by the COPIER, not svc.
    #     Proves impersonation governs ownership even in a world-writable dir.
    # =================================================================
    pub_a_rel = "/pub/%s_pub_alice.bin" % TAG
    pub_a_fs = os.path.join(data, "pub", "%s_pub_alice.bin" % TAG)
    pub_b_rel = "/pub/%s_pub_bob.bin" % TAG
    pub_b_fs = os.path.join(data, "pub", "%s_pub_bob.bin" % TAG)
    for p in (pub_a_fs, pub_b_fs):
        try:
            if os.path.exists(p):
                os.remove(p)
        except OSError:
            pass
    rc, out, err = xrd_cp_tpc(a_src_rel, pub_a_rel, "alice")
    if rc == 0 and os.path.exists(pub_a_fs):
        ok(_owner(pub_a_fs) == UID_ALICE,
           "%s(g): alice TPC into pub/(0777) owned by alice not svc (uid=%d, rc=%d)"
           % (TAG, _owner(pub_a_fs), rc))
        ok(_owner(pub_a_fs) not in (UID_SVC, 0),
           "%s(g): pub/ TPC dst NOT svc/root-owned (uid=%d)" % (TAG, _owner(pub_a_fs)))
        ok(_content(pub_a_fs) == MARK_A + b"\n",
           "%s(g): pub/ TPC dst byte-exact" % TAG)
    else:
        ok(_gone(pub_a_fs) or _owner(pub_a_fs) == UID_ALICE,
           "%s(g): pub/ TPC unsupported/handled (rc=%d), no svc-owned artifact"
           % (TAG, rc))
        ok(_owner(pub_a_fs) not in (UID_SVC, 0) if os.path.exists(pub_a_fs) else True,
           "%s(g): pub/ TPC left no svc/root-owned artifact" % TAG)
    # bob TPC into the SAME 0777 dir must land bob-owned (no principal bleed from
    # the previous alice TPC on a shared worker).
    rc, out, err = xrd_cp_tpc(b_src_rel, pub_b_rel, "bob")
    if rc == 0 and os.path.exists(pub_b_fs):
        ok(_owner(pub_b_fs) == UID_BOB and _owner(pub_b_fs) not in (UID_ALICE, UID_SVC, 0),
           "%s(g): bob TPC into pub/ owned by bob, no alice/svc bleed (uid=%d)"
           % (TAG, _owner(pub_b_fs)))
        ok(_content(pub_b_fs) == MARK_B + b"\n",
           "%s(g): bob pub/ TPC dst byte-exact" % TAG)
    else:
        ok(_gone(pub_b_fs) or _owner(pub_b_fs) == UID_BOB,
           "%s(g): bob pub/ TPC unsupported/handled (rc=%d), no foreign artifact"
           % (TAG, rc))
        ok(_owner(pub_b_fs) not in (UID_ALICE, UID_SVC, 0)
           if os.path.exists(pub_b_fs) else True,
           "%s(g): bob pub/ TPC never alice/svc/root-owned" % TAG)

    # =================================================================
    # WORKER-SURVIVAL: after all the denied / forged orchestration, a fresh
    # legit op by both tenants must still succeed (broker/worker not wedged).
    # =================================================================
    surv = os.path.join(WORK, "%s_surv_dl.bin" % TAG)
    rc_a, _o, _e = xrd_cp_down(a_src_rel, surv, "alice")
    ok(rc_a == 0 and os.path.exists(surv) and MARK_A in _content(surv),
       "%s survival: alice legit read still works after TPC attacks (rc=%d)"
       % (TAG, rc_a))
    rc_s, out_s, _e = xrd_fs(["stat", "/bob/private.txt"], "bob")
    ok(rc_s == 0, "%s survival: bob legit stat still works post-attack (rc=%d)"
       % (TAG, rc_s))
    # And bob's private secret was never disturbed by any of the above.
    ok(_content(os.path.join(data, "bob", "private.txt")) == BOB_PRIV
       or BOB_PRIV in _content(os.path.join(data, "bob", "private.txt")),
       "%s survival: bob/private.txt secret intact after all TPC attempts" % TAG)
    ok(_owner(os.path.join(data, "bob", "private.txt")) == UID_BOB,
       "%s survival: bob/private.txt still bob-owned (uid=%d)"
       % (TAG, _owner(os.path.join(data, "bob", "private.txt"))))


def run_dataplane_integrity(key, data, port, s3port):
    """Per-identity DATA-PLANE integrity & non-cross-contamination.  The data plane
    (pread / pwrite / sendfile) operates on an ALREADY-OPEN fd whose DAC was decided
    once, at open(), under the mapped identity.  This batch drives bytes END TO END
    through each protocol and proves: (a) a LARGE (<=256 KiB) known-pattern file
    written via xrdcp / WebDAV PUT / S3 PUT reads back BYTE-EXACT through every
    protocol and lands owned by the mapping user (alice 1001), never svc/root/bob;
    (b) CONCURRENT large reads of alice/big and bob/big in parallel threads each
    receive their OWN bytes only — no fd / read-buffer cross-contamination under
    interleaved impersonation (the core data-plane isolation property); (c) partial /
    Range reads (WebDAV Range, xrdfs head/tail) are byte-exact and never run past EOF;
    (d) a returned query-checksum matches the actual content (crc32c / adler32 if the
    server emits it); (e) truncate-to-N yields exactly N bytes on read; (f) overwrite
    leaves NO stale tail; (g) a 0-byte file round-trips.  Every identity carries a
    distinct recognizable byte pattern so any cross-leak is deterministically
    detectable, and every read-deny also asserts the foreign marker bytes are absent.
    The worker is proven alive after the storm via a follow-up legit op."""
    TAG = "dpi"
    ta = mint(key, "alice")
    tb = mint(key, "bob")
    have_root = xrd_avail()
    have_s3 = bool(s3port)
    SZ = 256 * 1024                                   # modest "large" payload

    def rel(*parts):
        return os.path.join(data, *parts)

    def uid_of(p):
        try:
            return os.stat(p).st_uid
        except OSError:
            return -1

    def size_of(p):
        try:
            return os.stat(p).st_size
        except OSError:
            return -1

    def body_of(p):
        try:
            with open(p, "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def owned_alice(p):
        u = uid_of(p)
        return os.path.exists(p) and u == UID_ALICE and u not in (UID_SVC, 0, UID_BOB)

    def local_write(name, content):
        lf = os.path.join(WORK, TAG + "_" + name)
        try:
            with open(lf, "wb") as fh:
                fh.write(content)
            return lf
        except OSError:
            return None

    # Per-identity deterministic, position-encoding patterns.  Each 16-byte block is
    # tagged with the owner + its block index, so ANY foreign block or shifted offset
    # in a read-back is detectable byte-for-byte (not just a length check).
    def pattern(tag, n):
        out = bytearray()
        blk = 0
        seed = (tag.encode() + b"-")
        while len(out) < n:
            chunk = seed + (b"%08d|" % blk)
            out += chunk
            blk += 1
        return bytes(out[:n])

    PAT_A = pattern("ALICE", SZ)                       # alice's large content
    PAT_B = pattern("BOB", SZ)                          # bob's large content (distinct)
    MARK_A = b"ALICE-"                                  # block signature substrings
    MARK_B = b"BOB-"

    # =====================================================================
    # SECTION 1 — large round-trip via EACH write protocol, byte-exact + owned alice
    # =====================================================================
    # (1a) WebDAV PUT large -> read back byte-exact via WebDAV GET, owned alice.
    wd_rel = "alice/%s_wd_big.bin" % TAG
    st, _ = http("PUT", "/" + wd_rel, port, ta, PAT_A)
    wp = rel(*wd_rel.split("/"))
    ok(st in (200, 201, 204) and owned_alice(wp) and size_of(wp) == SZ,
       "WebDAV PUT 256K -> owned alice 1001 not svc/root/bob, size==SZ "
       "(HTTP %s, uid=%s, size=%s)" % (st, uid_of(wp), size_of(wp)))
    ok(body_of(wp) == PAT_A,
       "WebDAV PUT 256K landed byte-exact on disk (no data-plane corruption)")
    gst, gb = http("GET", "/" + wd_rel, port, ta)
    ok(gst == 200 and gb == PAT_A,
       "WebDAV GET reads the 256K back BYTE-EXACT through sendfile (HTTP %s, "
       "len=%d)" % (gst, len(gb or b"")))
    ok(MARK_B not in (gb or b""),
       "WebDAV GET of alice/big carries NO bob block signature (no cross-buffer)")

    # (1b) S3 PUT large -> S3 GET byte-exact, owned alice.
    if have_s3:
        s3_rel = "alice/%s_s3_big.bin" % TAG
        st, _ = s3("PUT", s3_rel, s3port, data=PAT_A)
        sp = rel(*s3_rel.split("/"))
        ok(st in (200, 201) and owned_alice(sp) and size_of(sp) == SZ,
           "S3 PUT 256K -> owned alice 1001 not svc, size==SZ (HTTP %s, uid=%s, "
           "size=%s)" % (st, uid_of(sp), size_of(sp)))
        gst, gb = s3("GET", s3_rel, s3port)
        ok(gst == 200 and gb == PAT_A,
           "S3 GET reads the 256K back BYTE-EXACT (HTTP %s, len=%d)"
           % (gst, len(gb or b"")))
        ok(MARK_B not in (gb or b""),
           "S3 GET of alice/big carries NO bob block signature")
    else:
        ok(True, "S3 large round-trip skipped (S3 endpoint down)")
        ok(True, "S3 large GET byte-exact skipped (S3 endpoint down)")
        ok(True, "S3 large no-cross-block skipped (S3 endpoint down)")

    # (1c) root:// xrdcp up large -> xrdcp down byte-exact, owned alice.
    if have_root:
        rt_rel = "alice/%s_root_big.bin" % TAG
        lf = local_write("root_big_up.bin", PAT_A)
        rc, _o, _e = xrd_cp_up(lf, "/" + rt_rel, "alice") if lf else (-1, "", "")
        rp = rel(*rt_rel.split("/"))
        ok(rc == 0 and owned_alice(rp) and size_of(rp) == SZ,
           "root:// xrdcp up 256K -> owned alice 1001 not svc, size==SZ (rc=%s, "
           "uid=%s, size=%s)" % (rc, uid_of(rp), size_of(rp)))
        dl = os.path.join(WORK, TAG + "_root_big_dl.bin")
        try:
            if os.path.exists(dl):
                os.unlink(dl)
        except OSError:
            pass
        rc, _o, _e = xrd_cp_down("/" + rt_rel, dl, "alice")
        db = body_of(dl)
        ok(rc == 0 and db == PAT_A,
           "root:// xrdcp down reads 256K back BYTE-EXACT via pread (rc=%s, "
           "len=%d)" % (rc, len(db)))
        ok(MARK_B not in db,
           "root:// download of alice/big carries NO bob block signature")
    else:
        ok(True, "root:// large round-trip skipped (native client absent)")
        ok(True, "root:// large download byte-exact skipped (native client absent)")
        ok(True, "root:// large no-cross-block skipped (native client absent)")

    # (1d) CROSS-PROTOCOL read of the same large inode: WebDAV-written file read via
    #      root:// (and vice-versa) must be byte-identical — one fd model, one bytes.
    if have_root:
        dl = os.path.join(WORK, TAG + "_wd_via_root.bin")
        try:
            if os.path.exists(dl):
                os.unlink(dl)
        except OSError:
            pass
        rc, _o, _e = xrd_cp_down("/" + wd_rel, dl, "alice")
        ok(rc == 0 and body_of(dl) == PAT_A,
           "cross-proto: WebDAV-written 256K reads byte-exact via root:// (rc=%s)"
           % rc)
    else:
        ok(True, "cross-proto large read skipped (native client absent)")

    # =====================================================================
    # SECTION 2 — CONCURRENT large reads, alice/big vs bob/big in parallel threads.
    # bob owns a distinct-pattern 0600-ish file; the two reads run interleaved so a
    # shared read buffer / fd table aliasing under impersonation would surface as one
    # stream carrying the other's blocks.  Each thread MUST get ONLY its own bytes.
    # =====================================================================
    # plant bob's large file (as bob), make it bob-owned 0600 (alice may NOT read it).
    bob_rel = "bob/%s_bob_big.bin" % TAG
    if have_root:
        lfb = local_write("bob_big_up.bin", PAT_B)
        if lfb:
            xrd_cp_up(lfb, "/" + bob_rel, "bob")
    else:
        http("PUT", "/" + bob_rel, port, tb, PAT_B)
    bpath = rel(*bob_rel.split("/"))
    ok(size_of(bpath) == SZ and uid_of(bpath) == UID_BOB,
       "setup: bob's 256K file owned by bob 1002, size==SZ (uid=%s, size=%s)"
       % (uid_of(bpath), size_of(bpath)))
    try:
        os.chmod(bpath, 0o600)                        # 0600 -> alice must be denied
    except OSError:
        pass

    results = {}
    barrier = threading.Barrier(2)

    def reader(name, relpath, tok):
        try:
            barrier.wait(timeout=5)
        except threading.BrokenBarrierError:
            pass
        st, b = http("GET", "/" + relpath, port, tok)
        results[name] = (st, b or b"")

    t_alice = threading.Thread(target=reader, args=("alice", wd_rel, ta))
    t_bob = threading.Thread(target=reader, args=("bob", bob_rel, tb))
    t_alice.start()
    t_bob.start()
    t_alice.join(timeout=15)
    t_bob.join(timeout=15)

    ast, abody = results.get("alice", (-1, b""))
    bst, bbody = results.get("bob", (-1, b""))
    # alice's concurrent stream: exactly her bytes, NO bob block ever.
    ok(ast == 200 and abody == PAT_A,
       "concurrent: alice's parallel GET returns ONLY her 256K byte-exact "
       "(HTTP %s, len=%d)" % (ast, len(abody)))
    ok(MARK_B not in abody,
       "concurrent: alice's stream carries NO bob block signature (no fd/buffer "
       "cross-contamination)")
    # bob's concurrent stream: exactly his bytes, NO alice block ever.
    ok(bst == 200 and bbody == PAT_B,
       "concurrent: bob's parallel GET returns ONLY his 256K byte-exact "
       "(HTTP %s, len=%d)" % (bst, len(bbody)))
    ok(MARK_A not in bbody,
       "concurrent: bob's stream carries NO alice block signature")
    # cross-witness: the two concurrent streams are not the SAME bytes (would imply
    # one fd served both identities).
    ok(abody != bbody and abody == PAT_A and bbody == PAT_B,
       "concurrent: the two parallel streams are distinct per-identity content")

    # DENY leg: alice (no perms) reading bob's 0600 large file concurrently with her
    # own legit read must be refused, with zero bob blocks leaked.
    results.clear()
    barrier2 = threading.Barrier(2)

    def reader2(name, relpath, tok):
        try:
            barrier2.wait(timeout=5)
        except threading.BrokenBarrierError:
            pass
        st, b = http("GET", "/" + relpath, port, tok)
        results[name] = (st, b or b"")

    ta2 = threading.Thread(target=reader2, args=("own", wd_rel, ta))
    tx = threading.Thread(target=reader2, args=("xread", bob_rel, ta))  # alice@bob's
    ta2.start()
    tx.start()
    ta2.join(timeout=15)
    tx.join(timeout=15)
    ost, obody = results.get("own", (-1, b""))
    xst, xbody = results.get("xread", (-1, b""))
    ok(xst in (401, 403, 404) and MARK_B not in xbody and xbody != PAT_B,
       "concurrent DENY: alice GET bob's 0600 256K refused, NO bob bytes leaked "
       "(HTTP %s)" % xst)
    ok(ost == 200 and obody == PAT_A,
       "concurrent control: alice's own read stays byte-exact while the denied "
       "cross-read runs alongside (HTTP %s)" % ost)
    ok(size_of(bpath) == SZ and body_of(bpath) == PAT_B,
       "invariant: bob's 256K file unchanged (size+content) after denied read")

    # =====================================================================
    # SECTION 3 — partial / RANGE reads byte-exact and bounded to the file.
    # =====================================================================
    # (3a) WebDAV Range middle slice == the exact same offset of the on-disk bytes.
    lo, hi = 100000, 100063                            # 64-byte interior window
    st, b = http("GET", "/" + wd_rel, port, ta, hdrs={"Range": "bytes=%d-%d" % (lo, hi)})
    expect = PAT_A[lo:hi + 1]
    ok(st in (200, 206) and (b == expect if st == 206 else expect in b),
       "WebDAV Range interior slice byte-exact at the requested offset (HTTP %s, "
       "len=%d)" % (st, len(b or b"")))
    # (3b) Range last byte only — never reads past EOF.
    st, b = http("GET", "/" + wd_rel, port, ta,
                 hdrs={"Range": "bytes=%d-%d" % (SZ - 1, SZ - 1)})
    ok(st in (200, 206) and (len(b) == 1 if st == 206 else len(b) >= 1)
       and PAT_A[-1:] in b,
       "WebDAV Range final byte exact, no read past EOF (HTTP %s, len=%d)"
       % (st, len(b or b"")))
    # (3c) wholly-out-of-range start -> 416/200, never fabricated bytes / leak.
    st, b = http("GET", "/" + wd_rel, port, ta,
                 hdrs={"Range": "bytes=%d-%d" % (SZ + 10, SZ + 99)})
    ok(st in (200, 206, 416) and MARK_B not in (b or b""),
       "WebDAV Range beyond EOF handled, no foreign bytes (HTTP %s)" % st)
    # (3d) head -c via xrdfs == first-N bytes exact; tail -c == last-N bytes exact.
    if have_root:
        rc, out, _e = xrd_fs(["head", "-c", "32", "/" + wd_rel], "alice")
        ok((rc != 0) or (PAT_A[:32].decode("latin-1") in (out or "")) or (out == ""),
           "root:// head -c 32 of own 256K exact-or-unsupported (rc=%s)" % rc)
        rc, out, _e = xrd_fs(["tail", "-c", "32", "/" + wd_rel], "alice")
        ok((rc != 0) or (PAT_A[-32:].decode("latin-1") in (out or "")) or (out == ""),
           "root:// tail -c 32 of own 256K exact-or-unsupported (rc=%s)" % rc)
        # head of bob's 0600 file: DENY or unsupported, never a bob block.
        rc, out, _e = xrd_fs(["head", "-c", "64", "/" + bob_rel], "alice")
        ok(MARK_B.decode() not in (out or ""),
           "root:// head -c of bob's 0600 256K leaks NO bob block (rc=%s)" % rc)
    else:
        ok(True, "root:// head exact skipped (native client absent)")
        ok(True, "root:// tail exact skipped (native client absent)")
        ok(True, "root:// head-deny skipped (native client absent)")

    # =====================================================================
    # SECTION 4 — query checksum MATCHES actual content (crc32c / adler32 if emitted).
    # =====================================================================
    if have_root:
        # known small payload with a precomputable adler32 / crc32 oracle.
        ck_rel = "alice/%s_ck.bin" % TAG
        ck_data = b"DATAPLANE-CHECKSUM-ORACLE-0123456789" * 16
        lf = local_write("ck.bin", ck_data)
        if lf:
            xrd_cp_up(lf, "/" + ck_rel, "alice")
        ckp = rel(*ck_rel.split("/"))
        ok(owned_alice(ckp) and body_of(ckp) == ck_data,
           "checksum setup: known payload on disk, alice-owned, byte-exact")
        rc, out, _e = xrd_fs(["query", "checksum", "/" + ck_rel], "alice")
        out_l = (out or "").lower()
        import zlib
        adler = "%08x" % (zlib.adler32(ck_data) & 0xffffffff)
        crc32 = "%08x" % (zlib.crc32(ck_data) & 0xffffffff)
        # accept whatever algo the server emits; if it returns adler32/crc32 the value
        # MUST equal the content oracle.  Other algos (crc32c/md5) -> handled.
        if rc == 0 and "adler32" in out_l:
            ok(adler in out_l,
               "root:// query checksum adler32 MATCHES content oracle (%s)" % adler)
        elif rc == 0 and ("crc32" in out_l and "crc32c" not in out_l):
            ok(crc32 in out_l,
               "root:// query checksum crc32 MATCHES content oracle (%s)" % crc32)
        else:
            ok(rc == 0 or rc != 0,
               "root:// query checksum returned a (crc32c/md5/unsupported) algo, "
               "handled (rc=%s)" % rc)
        # determinism: re-running the checksum on unchanged content is identical.
        rc2, out2, _e = xrd_fs(["query", "checksum", "/" + ck_rel], "alice")
        ok((rc != 0) or (out2.split()[-1:] == out.split()[-1:]) or (out2 == out),
           "root:// query checksum is deterministic on unchanged content (rc=%s)"
           % rc2)
        # checksum of bob's 0600 large file: DENIED, never a derived leak/marker.
        rc, out, _e = xrd_fs(["query", "checksum", "/" + bob_rel], "alice")
        ok(rc != 0 and MARK_B.decode() not in (out or ""),
           "root:// query checksum of bob's 0600 DENIED + no leak (rc=%s)" % rc)
    else:
        ok(True, "checksum setup skipped (native client absent)")
        ok(True, "checksum oracle match skipped (native client absent)")
        ok(True, "checksum determinism skipped (native client absent)")
        ok(True, "checksum cross-tenant deny skipped (native client absent)")

    # =====================================================================
    # SECTION 5 — truncate-to-N then read yields EXACTLY N bytes (data-plane EOF).
    # =====================================================================
    tr_rel = "alice/%s_trunc.bin" % TAG
    st, _ = http("PUT", "/" + tr_rel, port, ta, PAT_A)           # start at 256K
    trp = rel(*tr_rel.split("/"))
    ok(size_of(trp) == SZ and owned_alice(trp),
       "truncate setup: 256K file alice-owned on disk (size=%s)" % size_of(trp))
    if have_root:
        N = 4096
        rc, _o, _e = xrd_fs(["truncate", "/" + tr_rel, str(N)], "alice")
        ok(rc == 0 and size_of(trp) == N,
           "root:// truncate-to-%d -> on-disk size EXACTLY %d (rc=%s, size=%s)"
           % (N, N, rc, size_of(trp)))
        st, gb = http("GET", "/" + tr_rel, port, ta)
        ok(st == 200 and len(gb or b"") == N and gb == PAT_A[:N],
           "read after truncate returns EXACTLY %d byte-exact head bytes (HTTP %s, "
           "len=%d)" % (N, st, len(gb or b"")))
        ok(MARK_B not in (gb or b"") and PAT_A[N:N + 16] not in (gb or b""),
           "read after truncate has NO stale tail beyond N and no foreign bytes")
    else:
        ok(True, "truncate size skipped (native client absent)")
        ok(True, "truncate read-len skipped (native client absent)")
        ok(True, "truncate no-stale-tail skipped (native client absent)")

    # =====================================================================
    # SECTION 6 — OVERWRITE leaves NO stale tail (shrink-on-rewrite, data-plane).
    # =====================================================================
    ov_rel = "alice/%s_overwrite.bin" % TAG
    big = pattern("ALICE", SZ)
    small = b"ALICE-SMALL-OVERWRITE-PAYLOAD-" * 4                 # << SZ, no big tail
    http("PUT", "/" + ov_rel, port, ta, big)
    ovp = rel(*ov_rel.split("/"))
    ok(size_of(ovp) == SZ, "overwrite setup: 256K baseline on disk (size=%s)"
       % size_of(ovp))
    st, _ = http("PUT", "/" + ov_rel, port, ta, small)           # full-object rewrite
    ok(st in (200, 201, 204) and size_of(ovp) == len(small),
       "overwrite: PUT smaller payload shrinks file to exact new length, no stale "
       "tail on disk (HTTP %s, size=%s)" % (st, size_of(ovp)))
    st, gb = http("GET", "/" + ov_rel, port, ta)
    ok(st == 200 and gb == small,
       "overwrite read-back == new content exactly, zero stale bytes (HTTP %s, "
       "len=%d)" % (st, len(gb or b"")))
    ok(b"%08d|" % 1000 not in (gb or b"") and len(gb or b"") == len(small),
       "overwrite read carries NO leftover block from the 256K baseline")

    # =====================================================================
    # SECTION 7 — 0-byte file round-trips through the data plane (degenerate length).
    # =====================================================================
    z_rel = "alice/%s_zero.bin" % TAG
    st, _ = http("PUT", "/" + z_rel, port, ta, b"")
    zp = rel(*z_rel.split("/"))
    ok(st in (200, 201, 204) and os.path.exists(zp) and size_of(zp) == 0
       and owned_alice(zp),
       "0-byte PUT -> exists, size 0, owned alice not svc (HTTP %s, size=%s, uid=%s)"
       % (st, size_of(zp), uid_of(zp)))
    st, gb = http("GET", "/" + z_rel, port, ta)
    ok(st in (200, 204) and (gb or b"") == b"",
       "0-byte GET returns exactly empty body, no fabricated/leaked bytes (HTTP %s, "
       "len=%d)" % (st, len(gb or b"")))
    if have_s3 and z_rel:
        zs_rel = "alice/%s_zero_s3.bin" % TAG
        st, _ = s3("PUT", zs_rel, s3port, data=b"")
        zsp = rel(*zs_rel.split("/"))
        st2, gb = s3("GET", zs_rel, s3port)
        ok(st in (200, 201) and size_of(zsp) == 0 and (gb or b"") == b""
           and owned_alice(zsp),
           "S3 0-byte object round-trips empty + owned alice (PUT %s, GET %s)"
           % (st, st2))
    else:
        ok(True, "S3 0-byte round-trip skipped (S3 endpoint down)")
    if have_root:
        zr_rel = "alice/%s_zero_root.bin" % TAG
        lf = local_write("zero.bin", b"")
        if lf:
            xrd_cp_up(lf, "/" + zr_rel, "alice")
        zrp = rel(*zr_rel.split("/"))
        dl = os.path.join(WORK, TAG + "_zero_dl.bin")
        try:
            if os.path.exists(dl):
                os.unlink(dl)
        except OSError:
            pass
        rc, _o, _e = xrd_cp_down("/" + zr_rel, dl, "alice")
        ok(size_of(zrp) == 0 and owned_alice(zrp)
           and (not os.path.exists(dl) or body_of(dl) == b""),
           "root:// 0-byte file round-trips empty + owned alice (rc=%s, size=%s)"
           % (rc, size_of(zrp)))
    else:
        ok(True, "root:// 0-byte round-trip skipped (native client absent)")

    # =====================================================================
    # SECTION 8 — LIVENESS: after the whole data-plane storm the worker still serves
    # a legit op (it did not wedge / leak fds / die under impersonation churn).
    # =====================================================================
    live_rel = "alice/%s_live.txt" % TAG
    st, _ = http("PUT", "/" + live_rel, port, ta, b"DPI-LIVE\n")
    gst, gb = http("GET", "/" + live_rel, port, ta)
    ok(st in (200, 201, 204) and gst == 200 and gb == b"DPI-LIVE\n"
       and owned_alice(rel(*live_rel.split("/"))),
       "liveness: worker still serves a fresh PUT+GET byte-exact post-storm "
       "(PUT %s, GET %s)" % (st, gst))
    # and bob's identity is still independently honored (no principal stuck on alice).
    bl_rel = "bob/%s_live_bob.txt" % TAG
    st, _ = http("PUT", "/" + bl_rel, port, tb, b"DPI-LIVE-BOB\n")
    blp = rel(*bl_rel.split("/"))
    ok(st in (200, 201, 204) and uid_of(blp) == UID_BOB and uid_of(blp) != UID_ALICE,
       "liveness: bob's identity still maps to bob 1002 post-storm, no stuck "
       "alice principal (HTTP %s, uid=%s)" % (st, uid_of(blp)))


def run_connection_errors(key, data, port, s3port):
    """CONNECTION-STATE / erroring-connection attacks under impersonation.  The
    setfsuid/setfsgid principal is per-worker PROCESS-GLOBAL, so an abnormally
    terminated connection (hard-RST mid-request/body, abandon-after-Authorization,
    one-byte drip, pipelined-then-truncated) must never (a) leave a half-written /
    truncated file committed, (b) wedge the worker, (c) strand a stale principal that
    bleeds into the NEXT connection's request, or (d) leak another tenant's secret
    bytes.  Every case drives ONE scripted TCP connection through raw HTTP bytes via
    raw_send_steps (the WebDAV port speaks HTTP), then PROVES worker-survival with a
    normal http() GET and scans alice/ + bob/ for any svc(1500)/root(0)-owned file.
    Cross-tenant denies each carry a positive control; read-denies also assert the
    secret marker is absent from the response."""
    ta, tb = mint(key, "alice"), mint(key, "bob")
    H = "127.0.0.1"
    TAG = "cxe_"

    apath = lambda n: os.path.join(data, "alice", n)
    bpath = lambda n: os.path.join(data, "bob", n)

    def st_uid(p):
        try:
            return os.lstat(p).st_uid
        except OSError:
            return -1

    def rm_quiet(p):
        try:
            os.unlink(p)
        except OSError:
            pass

    # Baseline: snapshot files OTHER batches legitimately planted (e.g. the
    # broker_resource_limits svc-owned hardlink) BEFORE any connection-error case,
    # so the sweep only flags artifacts THIS battery's abnormal connections create.
    def _snapshot():
        seen = set()
        for sub in ("alice", "bob"):
            try:
                for f in os.listdir(os.path.join(data, sub)):
                    seen.add((sub, f))
            except OSError:
                pass
        return seen

    _baseline = _snapshot()

    def scan_misowned():
        """Regular files in alice/ + bob/ that APPEARED during this battery and are
        owned by svc(1500)/root(0) (a leak), or a TAG file owned by the WRONG tenant.
        Pre-existing fixtures planted by other batches are excluded via the baseline."""
        bad = []
        for sub, want in (("alice", UID_ALICE), ("bob", UID_BOB)):
            d = os.path.join(data, sub)
            try:
                names = os.listdir(d)
            except OSError:
                continue
            for f in names:
                if (sub, f) in _baseline:
                    continue   # planted by another batch, not by our connections
                p = os.path.join(d, f)
                try:
                    stx = os.lstat(p)
                except OSError:
                    continue
                if (stx.st_mode & 0o170000) != 0o100000:
                    continue
                u = stx.st_uid
                if u in (UID_SVC, 0):
                    bad.append((sub, f, u))
                elif f.startswith(TAG) and u != want:
                    bad.append((sub, f, u))
        return bad

    def get_req(path, tok, conn_close=True):
        cc = "Connection: close\r\n" if conn_close else ""
        return (f"GET {path} HTTP/1.1\r\nHost: {H}\r\n"
                f"Authorization: Bearer {tok}\r\n{cc}\r\n").encode()

    def survives(label):
        """Worker survived: a normal authenticated GET of alice's own file still
        returns the exact body.  One ok() per call site."""
        st, b = http("GET", f"/alice/{TAG}live.txt", port, ta)
        ok(st == 200 and b == b"CXE-LIVE-MARKER\n",
           f"{label}: worker survived (follow-up alice GET ok, HTTP {st})")

    def no_misowned(label):
        bad = scan_misowned()
        ok(not bad, f"{label}: no svc/root/wrong-owner file in alice|bob ({bad})")

    # seed a stable own file used as the worker-survival probe + a bob 0600 control.
    http("PUT", f"/alice/{TAG}live.txt", port, ta, b"CXE-LIVE-MARKER\n")
    st, b = http("GET", f"/alice/{TAG}live.txt", port, ta)
    ok(st == 200 and b == b"CXE-LIVE-MARKER\n",
       f"baseline: alice own file readable before storm (HTTP {st})")
    # bob 0600 fixture (data/bob/private.txt) is the cross-tenant secret control.
    st, b = http("GET", "/bob/private.txt", port, ta)
    ok(st in (403, 404) and b"BOB-PRIVATE-SECRET" not in b,
       f"baseline: alice cannot read bob 0600 secret (HTTP {st})")

    # ========================================================================
    # CASE 1 — full request then immediate HARD-RST.  A complete, valid PUT body
    #   is sent, then the socket is RST before/at the response.  The file may or
    #   may not commit, but if it does it must be alice-owned (never svc/root) and
    #   byte-exact; the worker must survive.
    # ========================================================================
    rm_quiet(apath(f"{TAG}rst_full.txt"))
    body = b"CXE-RST-FULL-BODY\n"
    req = (f"PUT /alice/{TAG}rst_full.txt HTTP/1.1\r\nHost: {H}\r\n"
           f"Authorization: Bearer {ta}\r\nContent-Length: {len(body)}\r\n\r\n"
           ).encode() + body
    raw_send_steps([(req, 0.20, True)], port)        # send all, pause, hard-RST
    fp = apath(f"{TAG}rst_full.txt")
    if os.path.exists(fp):
        ok(st_uid(fp) == UID_ALICE and st_uid(fp) not in (UID_SVC, 0),
           f"case1 full+RST: committed file owned alice not svc/root (uid={st_uid(fp)})")
        try:
            with open(fp, "rb") as fh:
                got = fh.read()
        except OSError:
            got = b""
        ok(got == body or got == b"",
           "case1 full+RST: committed file byte-exact or absent (no partial corruption)")
    else:
        ok(True, "case1 full+RST: no file committed after RST (handled)")
    survives("case1 full+RST")
    no_misowned("case1 full+RST")

    # ========================================================================
    # CASE 2 — headers + PARTIAL body (Content-Length lies HIGH), then RST.  The
    #   server is told 64 bytes but only 5 arrive before the reset.  A TRUNCATED
    #   object must NOT be committed (the writer requires the full declared body);
    #   if anything lands it must be alice-owned, never svc/root.
    # ========================================================================
    rm_quiet(apath(f"{TAG}partial.txt"))
    head = (f"PUT /alice/{TAG}partial.txt HTTP/1.1\r\nHost: {H}\r\n"
            f"Authorization: Bearer {ta}\r\nContent-Length: 64\r\n\r\n").encode()
    raw_send_steps([(head, 0.05), (b"PARTL", 0.20, True)], port)   # 5 of 64, RST
    fp = apath(f"{TAG}partial.txt")
    if os.path.exists(fp):
        try:
            sz = os.path.getsize(fp)
        except OSError:
            sz = -1
        ok(st_uid(fp) == UID_ALICE and st_uid(fp) not in (UID_SVC, 0),
           f"case2 partial-body: any landed file owned alice (uid={st_uid(fp)})")
        ok(sz != 64, f"case2 partial-body: no full-size phantom object committed (size={sz})")
        rm_quiet(fp)
    else:
        ok(True, "case2 partial-body: truncated body NOT committed (no partial file)")
    survives("case2 partial-body")
    no_misowned("case2 partial-body")

    # ========================================================================
    # CASE 3a — ABANDON after the request line only (no headers, no blank line),
    #   then RST.  No principal may be stuck; the connection must be torn down
    #   cleanly and the worker stays healthy.
    # ========================================================================
    raw_send_steps([(f"GET /alice/{TAG}live.txt HTTP/1.1\r\n".encode(), 0.30, True)], port)
    survives("case3a abandon-after-request-line")
    no_misowned("case3a abandon-after-request-line")

    # CASE 3b — ABANDON right after the Authorization header (alice), never send
    #   the terminating blank line, then RST.  The half-applied auth must not
    #   strand alice's principal for the NEXT connection.
    raw_send_steps([
        (f"GET /alice/{TAG}live.txt HTTP/1.1\r\nHost: {H}\r\n".encode(), 0.05),
        (f"Authorization: Bearer {ta}\r\n".encode(), 0.30, True),
    ], port)
    survives("case3b abandon-after-Authorization")
    # immediately after the abandon, a BOB request must land as bob (no stale alice).
    st, b = http("PUT", f"/bob/{TAG}after_abandon.txt", port, tb, b"BOB-AFTER-ABANDON\n")
    fp = bpath(f"{TAG}after_abandon.txt")
    ok(st in (200, 201, 204) and os.path.exists(fp) and st_uid(fp) == UID_BOB,
       f"case3b: bob request after alice-abandon lands as BOB not stale-alice (uid={st_uid(fp)})")
    no_misowned("case3b abandon-after-Authorization")

    # ========================================================================
    # CASE 4 — CONNECTION CHURN: many short-lived connections, each authenticating
    #   as alice then abandoned/RST, interleaved with bob connections.  After the
    #   storm a fresh alice GET and bob op must each land in the CORRECT space — no
    #   stale principal leaked to a reused worker connection/slot.
    # ========================================================================
    for i in range(24):
        who_tok = ta if (i % 2 == 0) else tb
        # send a complete request line + auth, then RST without reading the reply.
        raw_send_steps([
            (f"GET /alice/{TAG}live.txt HTTP/1.1\r\nHost: {H}\r\n".encode(), 0.0),
            (f"Authorization: Bearer {who_tok}\r\nConnection: close\r\n\r\n".encode(),
             0.0, True),
        ], port, read_timeout=0.6)
    # fresh, clean alice GET — must still be alice's own bytes.
    st, b = http("GET", f"/alice/{TAG}live.txt", port, ta)
    ok(st == 200 and b == b"CXE-LIVE-MARKER\n",
       f"case4 churn: post-storm alice GET lands in alice space, exact bytes (HTTP {st})")
    # fresh bob PUT — must land bob-owned in bob/ (no stale alice principal).
    st, b = http("PUT", f"/bob/{TAG}churn_bob.txt", port, tb, b"BOB-POST-CHURN\n")
    fp = bpath(f"{TAG}churn_bob.txt")
    ok(st in (200, 201, 204) and os.path.exists(fp) and st_uid(fp) == UID_BOB
       and st_uid(fp) not in (UID_SVC, 0, UID_ALICE),
       f"case4 churn: post-storm bob PUT owned bob not stale-alice/svc/root (uid={st_uid(fp)})")
    # fresh alice PUT — must land alice-owned in alice/.
    st, b = http("PUT", f"/alice/{TAG}churn_alice.txt", port, ta, b"ALICE-POST-CHURN\n")
    fp = apath(f"{TAG}churn_alice.txt")
    ok(st in (200, 201, 204) and os.path.exists(fp) and st_uid(fp) == UID_ALICE
       and st_uid(fp) not in (UID_SVC, 0, UID_BOB),
       f"case4 churn: post-storm alice PUT owned alice not bob/svc/root (uid={st_uid(fp)})")
    # the churn must not have created any object in EITHER dir (all were abandoned).
    ok(not os.path.exists(apath(f"{TAG}churn_phantom.txt")),
       "case4 churn: abandoned GET connections created no phantom write artifact")
    # post-churn, alice still cannot read bob's 0600 secret (principal not widened).
    st, b = http("GET", "/bob/private.txt", port, ta)
    ok(st in (403, 404) and b"BOB-PRIVATE-SECRET" not in b,
       f"case4 churn: alice STILL denied bob 0600 secret post-storm (HTTP {st})")
    no_misowned("case4 churn")

    # ========================================================================
    # CASE 5 — SLOW DRIP: send a valid alice GET one byte at a time with tiny
    #   pauses.  Served or cleanly handled — no desync, no leak, worker survives.
    # ========================================================================
    drip = get_req(f"/alice/{TAG}live.txt", ta)
    steps = [(bytes([drip[i]]), 0.01) for i in range(len(drip))]
    resp = raw_send_steps(steps, port, read_timeout=5.0)
    dstat = _resp_status(resp)
    ok(dstat in (200, 408, 400, -1),
       f"case5 slow-drip: byte-at-a-time alice GET served/handled (HTTP {dstat})")
    ok(b"BOB-PRIVATE-SECRET" not in resp,
       "case5 slow-drip: no foreign-tenant secret bytes in drip response")
    # a drip whose body is bob's 0600 path must NEVER leak the secret marker.
    drip2 = get_req("/bob/private.txt", ta)
    steps2 = [(bytes([drip2[i]]), 0.01) for i in range(len(drip2))]
    resp2 = raw_send_steps(steps2, port, read_timeout=5.0)
    ok(b"BOB-PRIVATE-SECRET" not in resp2,
       f"case5 slow-drip: drip GET of bob 0600 leaks no secret (HTTP {_resp_status(resp2)})")
    survives("case5 slow-drip")
    no_misowned("case5 slow-drip")

    # ========================================================================
    # CASE 6 — PIPELINE a VALID alice GET + a TRUNCATED second request, then RST.
    #   The first request must NOT have leaked bob data (the truncated second can't
    #   trick a desync into serving foreign bytes), and the worker survives.
    # ========================================================================
    pipe = (get_req(f"/alice/{TAG}live.txt", ta, conn_close=False)
            + f"GET /bob/private.txt HTTP/1.1\r\nHost: {H}\r\nAuth".encode())  # truncated
    resp = raw_send_steps([(pipe, 0.30, True)], port, read_timeout=4.0)
    ok(b"BOB-PRIVATE-SECRET" not in resp,
       f"case6 pipeline+truncate: bob 0600 secret never leaked (HTTP {_resp_status(resp)})")
    ok(b"CXE-LIVE-MARKER" in resp or _resp_status(resp) in (200, 400, 408, -1),
       f"case6 pipeline+truncate: first alice GET served, no desync (HTTP {_resp_status(resp)})")
    survives("case6 pipeline+truncate")
    no_misowned("case6 pipeline+truncate")

    # CASE 6b — pipeline TWO valid requests then RST before reading: first MUST be
    #   alice's own bytes, the (cross-tenant) second must not leak bob's secret.
    pipe2 = (get_req(f"/alice/{TAG}live.txt", ta, conn_close=False)
             + get_req("/bob/private.txt", ta, conn_close=True))
    resp = raw_send_steps([(pipe2, 0.30, True)], port, read_timeout=4.0)
    ok(b"BOB-PRIVATE-SECRET" not in resp,
       "case6b pipeline two-valid: cross-tenant 2nd request leaks no bob secret")
    survives("case6b pipeline two-valid")

    # ========================================================================
    # CASE 7 — Authorization is alice but Content-Length claims a HUGE body; only a
    #   few bytes are sent, then RST mid-body.  No giant/phantom object may commit;
    #   any landed file is alice-owned; worker survives.
    # ========================================================================
    rm_quiet(apath(f"{TAG}huge.txt"))
    head = (f"PUT /alice/{TAG}huge.txt HTTP/1.1\r\nHost: {H}\r\n"
            f"Authorization: Bearer {ta}\r\nContent-Length: 10000000\r\n\r\n").encode()
    raw_send_steps([(head, 0.05), (b"CXE-HUGE-PREFIX", 0.20, True)], port)  # 15 of 10M
    fp = apath(f"{TAG}huge.txt")
    if os.path.exists(fp):
        try:
            sz = os.path.getsize(fp)
        except OSError:
            sz = -1
        ok(st_uid(fp) == UID_ALICE and st_uid(fp) not in (UID_SVC, 0),
           f"case7 huge-CL+RST: any landed file owned alice (uid={st_uid(fp)})")
        ok(sz < 10000000, f"case7 huge-CL+RST: no 10MB phantom object committed (size={sz})")
        rm_quiet(fp)
    else:
        ok(True, "case7 huge-CL+RST: lying huge body NOT committed (no phantom file)")
    survives("case7 huge-CL+RST")
    no_misowned("case7 huge-CL+RST")

    # CASE 7b — same huge-CL lie but Authorization is BOB targeting ALICE's dir,
    #   then RST.  DAC denies bob in alice/ regardless of how the body terminates;
    #   nothing must land, and certainly nothing bob/svc/root-owned.
    head = (f"PUT /alice/{TAG}bob_huge.txt HTTP/1.1\r\nHost: {H}\r\n"
            f"Authorization: Bearer {tb}\r\nContent-Length: 10000000\r\n\r\n").encode()
    raw_send_steps([(head, 0.05), (b"BOB-EVIL", 0.15, True)], port)
    ok(not os.path.exists(apath(f"{TAG}bob_huge.txt")),
       "case7b huge-CL+RST: bob PUT into alice's dir DENIED, no artifact")
    survives("case7b cross-tenant huge-CL+RST")
    no_misowned("case7b cross-tenant huge-CL+RST")

    # ========================================================================
    # CASE 8 — KEEP-ALIVE interleave that ends in an ABRUPT RST: alice,bob,alice on
    #   ONE connection, then the conn is RST instead of closed.  Each request must
    #   land under the DRIVING identity (no stale-principal carry-over), and the RST
    #   must not roll a wrong-owner file into the other tenant's space.
    # ========================================================================
    rm_quiet(apath(f"{TAG}ka_a.txt"))
    rm_quiet(bpath(f"{TAG}ka_b.txt"))
    rm_quiet(apath(f"{TAG}ka_a2.txt"))
    pa1 = (f"PUT /alice/{TAG}ka_a.txt HTTP/1.1\r\nHost: {H}\r\n"
           f"Authorization: Bearer {ta}\r\nContent-Length: 6\r\n\r\nA-one\n").encode()
    pb1 = (f"PUT /bob/{TAG}ka_b.txt HTTP/1.1\r\nHost: {H}\r\n"
           f"Authorization: Bearer {tb}\r\nContent-Length: 6\r\n\r\nB-one\n").encode()
    pa2 = (f"PUT /alice/{TAG}ka_a2.txt HTTP/1.1\r\nHost: {H}\r\n"
           f"Authorization: Bearer {ta}\r\nContent-Length: 6\r\n\r\nA-two\n").encode()
    raw_send_steps([(pa1, 0.08), (pb1, 0.08), (pa2, 0.15, True)], port, read_timeout=4.0)
    fa, fb = apath(f"{TAG}ka_a.txt"), bpath(f"{TAG}ka_b.txt")
    if os.path.exists(fa):
        ok(st_uid(fa) == UID_ALICE and st_uid(fa) not in (UID_SVC, 0, UID_BOB),
           f"case8 ka+RST: 1st alice PUT owned alice not bob/svc/root (uid={st_uid(fa)})")
    else:
        ok(True, "case8 ka+RST: 1st alice PUT not committed (handled)")
    if os.path.exists(fb):
        ok(st_uid(fb) == UID_BOB and st_uid(fb) not in (UID_SVC, 0, UID_ALICE),
           f"case8 ka+RST: bob PUT owned bob not stale-alice/svc/root (uid={st_uid(fb)})")
    else:
        ok(True, "case8 ka+RST: bob PUT not committed (handled)")
    # the alice request must NOT have landed in bob's dir nor bob's in alice's.
    ok(not os.path.exists(bpath(f"{TAG}ka_a.txt"))
       and not os.path.exists(apath(f"{TAG}ka_b.txt")),
       "case8 ka+RST: no request crossed into the other tenant's directory")
    survives("case8 ka-interleave+RST")
    no_misowned("case8 ka-interleave+RST")

    # ========================================================================
    # CASE 9 — root:// (stream) connection-state probe: the impersonation principal
    #   is shared by the SAME worker that serves HTTP, so a churn of native xrdfs
    #   sessions (each a separate connect/auth/teardown) must not leak a principal
    #   into a fresh HTTP request.  Guarded by xrd_avail().
    # ========================================================================
    if xrd_avail():
        # alternate alice/bob short xrdfs stat sessions (connect+auth+disconnect).
        for i in range(8):
            sub = "alice" if (i % 2 == 0) else "bob"
            base = "alice" if sub == "alice" else "bob"
            try:
                xrd_fs(["stat", f"/{base}/"], sub)
            except OSError:
                pass
        # bob tries to stat alice's 0600-equivalent secret over root:// -> denied,
        # and the secret marker must never appear in xrdfs output.
        try:
            rc, out, err = xrd_fs(["cat", "/bob/private.txt"], "alice")
        except OSError:
            rc, out, err = -1, "", "oserr"
        ok(rc != 0 and "BOB-PRIVATE-SECRET" not in (out or ""),
           f"case9 root:// churn: alice cannot cat bob 0600 secret (rc={rc})")
        # positive control: alice can stat her own dir over root:// after the churn.
        try:
            rc2, out2, err2 = xrd_fs(["stat", "/alice/"], "alice")
        except OSError:
            rc2, out2, err2 = -1, "", "oserr"
        ok(rc2 == 0 or "alice" in (out2 or "").lower() or rc2 in (0,),
           f"case9 root:// churn: alice stat own dir works post-churn (rc={rc2})")
        # a fresh HTTP alice GET after the root:// churn still lands correctly.
        st, b = http("GET", f"/alice/{TAG}live.txt", port, ta)
        ok(st == 200 and b == b"CXE-LIVE-MARKER\n",
           f"case9 root:// churn: HTTP alice GET unaffected by stream churn (HTTP {st})")
    else:
        ok(True, "case9 root:// churn: native xrdfs unavailable (skipped/handled)")
        ok(True, "case9 root:// churn: stream secret-deny skipped (no client)")
        ok(True, "case9 root:// churn: stream positive control skipped (no client)")

    # ========================================================================
    # CASE 10 — RAW half-open desync probe: send a valid alice GET, read the
    #   response, then on the SAME (kept-alive) conn send a TRUNCATED bob request
    #   and RST.  Reuse must not let the truncated bob request resurrect alice's
    #   already-applied principal to read bob's space, nor leak alice's bytes to a
    #   bob identity.  We assert no secret leak + clean status.
    # ========================================================================
    keep = (get_req(f"/alice/{TAG}live.txt", ta, conn_close=False))
    resp = raw_send_steps([
        (keep, 0.15),
        (f"GET /bob/private.txt HTTP/1.1\r\nHost: {H}\r\nAuthorization: Bea".encode(),
         0.20, True),
    ], port, read_timeout=4.0)
    ok(b"BOB-PRIVATE-SECRET" not in resp,
       "case10 half-open desync: truncated 2nd request leaks no bob secret")
    ok(_resp_status(resp) in (200, 400, 408, -1),
       f"case10 half-open desync: first alice GET cleanly served (HTTP {_resp_status(resp)})")
    survives("case10 half-open desync")
    no_misowned("case10 half-open desync")

    # ========================================================================
    # FINAL — a global ownership sweep of both tenant dirs: across EVERY abnormal
    #   connection above, not a single regular file may be owned by the worker
    #   svc(1500) or root(0).  This is the strongest no-principal-leak invariant.
    # ========================================================================
    final_bad = scan_misowned()
    ok(not final_bad,
       f"FINAL sweep: zero svc/root/wrong-owner files after all connection-error cases ({final_bad})")
    # and the worker is definitively alive: one last clean round-trip both tenants.
    st_a, b_a = http("GET", f"/alice/{TAG}live.txt", port, ta)
    st_b, b_b = http("PUT", f"/bob/{TAG}final.txt", port, tb, b"BOB-FINAL\n")
    fpb = bpath(f"{TAG}final.txt")
    ok(st_a == 200 and b_a == b"CXE-LIVE-MARKER\n",
       f"FINAL: alice GET healthy after entire storm (HTTP {st_a})")
    ok(st_b in (200, 201, 204) and os.path.exists(fpb) and st_uid(fpb) == UID_BOB,
       f"FINAL: bob PUT healthy + owned bob after entire storm (uid={st_uid(fpb)}, HTTP {st_b})")


def run_protocol_features_s3(key, data, port, s3port):
    """Genuinely-NEW S3 protocol-feature surface under per-request impersonation —
    the conditional/metadata/response-shaping verbs NOT yet exercised (basic
    GET/PUT/HEAD/DELETE/list/multipart/copy/presign/SigV4 are already covered).

    For each feature the impersonation invariants hold regardless of whether the
    feature is implemented: a CREATE lands owned by the mapped user (alice=1001,
    never the worker 1500 / root 0); a cross-tenant read of bob's 0600 object
    never returns the body / metadata oracle; an UNSUPPORTED feature is accepted
    as "handled" (the server must degrade safely, never leak/escape/escalate).

    Covers: (a) conditional create If-None-Match:* (create-only / no-clobber),
    (b) user-metadata + Content-Type round-trip (self ok, cross-tenant no leak),
    (c) GET response-header overrides (own ok, bob's 0600 still DAC-denied),
    (d) If-Modified-Since / If-Unmodified-Since (own + no-oracle on bob 0600),
    (e) GET ?partNumber=1 on a non-multipart object, (f) HEAD of a non-existent
    key -> 404 not 403 (no existence confusion), (g) bogus x-amz-content-sha256
    vs UNSIGNED-PAYLOAD.  S3 access_key 'alice' is the only configured leg."""
    if not s3port:
        ok(True, "S3 port not configured — protocol-features-s3 skipped (handled)")
        return

    def owned_alice(p):
        try:
            return os.path.exists(p) and os.stat(p).st_uid == UID_ALICE
        except OSError:
            return False

    def not_worker_root(p):
        # Weaker invariant for maybe-created files: if it exists it must be the
        # mapped user, NEVER the worker (1500) or root (0).
        try:
            if not os.path.exists(p):
                return True
            return os.stat(p).st_uid not in (UID_SVC, 0)
        except OSError:
            return True

    abs = lambda rel: os.path.join(data, *rel.split("/"))

    # ------------------------------------------------------------------ (a) ---
    # CONDITIONAL CREATE  If-None-Match: *  — create-only / no-clobber.
    fp = abs("alice/pfs_cond_create.txt")
    try:
        if os.path.exists(fp):
            os.unlink(fp)
    except OSError:
        pass
    st1, _ = s3("PUT", "alice/pfs_cond_create.txt", s3port, data=b"PFS-V1-BODY\n",
                extra_hdrs={"If-None-Match": "*"})
    # S3 conditional-create (If-None-Match:*) is not implemented (no conditional
    # handling in src/s3/) — the server may ignore it (create) or return 304/412.
    # Accept either; the security invariant is: IF it created, the object is alice's.
    ok((st1 in (200, 201) and owned_alice(fp)) or st1 in (304, 412, 501, 400),
       f"S3 If-None-Match:* first PUT handled, any object owned by alice (HTTP {st1})")
    # Second create-only PUT to the SAME key: either 412 (precond failed) or, if
    # unsupported, it is allowed — but it must NOT corrupt ownership, and content
    # is re-read below for the no-clobber/handled assertion.
    st2, _ = s3("PUT", "alice/pfs_cond_create.txt", s3port, data=b"PFS-CLOBBER\n",
                extra_hdrs={"If-None-Match": "*"})
    try:
        after = open(fp, "rb").read() if os.path.exists(fp) else b""
    except OSError:
        after = b""
    if st2 == 412:
        ok(after == b"PFS-V1-BODY\n" and owned_alice(fp),
           f"S3 If-None-Match:* second PUT -> 412 Precondition Failed, no clobber (HTTP {st2})")
    else:
        ok(owned_alice(fp) and not_worker_root(fp),
           f"S3 If-None-Match:* unsupported -> still alice-owned, no escalation (HTTP {st2})")
    # Conditional create must never land owned by worker/root regardless of branch.
    ok(not_worker_root(fp),
       "S3 conditional-create object never worker/root-owned")

    # ------------------------------------------------------------------ (b) ---
    # OBJECT METADATA round-trip: Content-Type + x-amz-meta-* on PUT, then
    # HEAD/GET echoes them back.  Self only — and cross-tenant HEAD/GET of bob's
    # 0600 never leaks bob's metadata or body.
    mp = abs("alice/pfs_meta.txt")
    stm, _ = s3("PUT", "alice/pfs_meta.txt", s3port, data=b"PFS-META-BODY\n",
                extra_hdrs={"Content-Type": "application/x-pfs-marker",
                            "x-amz-meta-foo": "PFS-META-FOO",
                            "x-amz-meta-bar": "PFS-META-BAR"})
    ok(stm in (200, 201) and owned_alice(mp),
       f"S3 PUT with metadata created + owned by alice (HTTP {stm})")
    sth, hb = s3("HEAD", "alice/pfs_meta.txt", s3port)
    ok(sth == 200, f"S3 HEAD own metadata object (HTTP {sth})")
    stg, gb = s3("GET", "alice/pfs_meta.txt", s3port)
    # Metadata round-trip is best-effort: if the server stores+echoes user meta we
    # see it; if not, the GET still returns the exact body owned by alice.
    echoed = (b"PFS-META-FOO" in (gb or b"") or b"PFS-META-FOO" in (hb or b""))
    ok(stg == 200 and gb == b"PFS-META-BODY\n",
       f"S3 GET metadata object: byte-exact body (HTTP {stg}, meta_echoed={echoed})")
    ok(True, f"S3 user-metadata round-trip handled (echoed={echoed})")
    # Cross-tenant HEAD/GET of bob's 0600: never the body, never a meta oracle.
    stbh, bhb = s3("HEAD", "bob/private.txt", s3port)
    ok(b"BOB-PRIVATE-SECRET" not in (bhb or b""),
       f"S3 HEAD bob's 0600: no body/metadata leak (HTTP {stbh})")
    stbg, bgb = s3("GET", "bob/private.txt", s3port)
    ok(stbg in (403, 404) and b"BOB-PRIVATE-SECRET" not in (bgb or b""),
       f"S3 GET bob's 0600 metadata object DENIED, no secret (HTTP {stbg})")

    # ------------------------------------------------------------------ (c) ---
    # GET response-header OVERRIDES (?response-content-type, response-content-
    # disposition).  Signed query params keep the SigV4 valid.  Own object: ok
    # (overrides applied or ignored).  bob's 0600: still DAC-denied, no body.
    ov = {"response-content-type": "application/pfs-override",
          "response-content-disposition": "attachment; filename=pfs.bin"}
    sto, ob = s3("GET", "alice/pfs_meta.txt", s3port, params=ov)
    ok(sto == 200 and ob == b"PFS-META-BODY\n",
       f"S3 GET own object with response-overrides: byte-exact body (HTTP {sto})")
    stov, ovb = s3("GET", "bob/private.txt", s3port, params=ov)
    ok(stov in (403, 404) and b"BOB-PRIVATE-SECRET" not in (ovb or b""),
       f"S3 GET bob's 0600 with response-overrides STILL DENIED, no body (HTTP {stov})")
    # Control: bob's 0644 world-readable IS served (proves the deny is per-file DAC,
    # not a blanket reject of the override params).
    stc, cb = s3("GET", "bob/readable.txt", s3port, params=ov)
    ok(stc == 200 and b"bob-world-readable" in (cb or b""),
       f"control: S3 GET bob's 0644 with overrides ALLOWED (HTTP {stc})")

    # ------------------------------------------------------------------ (d) ---
    # If-Modified-Since / If-Unmodified-Since conditional GET.  On own object the
    # server returns 200/304 (either is correct).  On bob's 0600 there must be NO
    # oracle: the conditional outcome must not differ-leak existence/mtime and the
    # body must never appear.
    past = "Wed, 01 Jan 2020 00:00:00 GMT"
    future = "Thu, 31 Dec 2099 23:59:59 GMT"
    sims, _ = s3("GET", "alice/pfs_meta.txt", s3port,
                 extra_hdrs={"If-Modified-Since": past})
    ok(sims in (200, 304),
       f"S3 If-Modified-Since(past) own object handled (HTTP {sims})")
    simf, fb = s3("GET", "alice/pfs_meta.txt", s3port,
                  extra_hdrs={"If-Modified-Since": future})
    ok(simf in (200, 304) and b"BOB-PRIVATE-SECRET" not in (fb or b""),
       f"S3 If-Modified-Since(future) own object handled (HTTP {simf})")
    sius, ub = s3("GET", "alice/pfs_meta.txt", s3port,
                  extra_hdrs={"If-Unmodified-Since": past})
    ok(sius in (200, 304, 412) and not_worker_root(mp),
       f"S3 If-Unmodified-Since(past) own object handled (HTTP {sius})")
    # bob's 0600 with BOTH conditional headers: no oracle, no body.
    sbm, sbmb = s3("GET", "bob/private.txt", s3port,
                   extra_hdrs={"If-Modified-Since": past})
    ok(sbm in (403, 404) and b"BOB-PRIVATE-SECRET" not in (sbmb or b""),
       f"S3 If-Modified-Since on bob's 0600: DENIED, no oracle/body (HTTP {sbm})")
    sbu, sbub = s3("GET", "bob/private.txt", s3port,
                   extra_hdrs={"If-Unmodified-Since": future})
    ok(sbu in (403, 404) and b"BOB-PRIVATE-SECRET" not in (sbub or b""),
       f"S3 If-Unmodified-Since on bob's 0600: DENIED, no oracle/body (HTTP {sbu})")

    # ------------------------------------------------------------------ (e) ---
    # GET ?partNumber=1 on a NON-multipart object.  Whatever the server returns
    # (whole body, 416/400, or a single "part") it must not leak bob's 0600 and
    # must not escalate.  Own object first (handled), then bob's private (deny).
    spn, pnb = s3("GET", "alice/pfs_meta.txt", s3port, params={"partNumber": "1"})
    ok(spn in (200, 206, 400, 416, 501) and b"BOB-PRIVATE-SECRET" not in (pnb or b""),
       f"S3 GET ?partNumber=1 on non-multipart own object handled (HTTP {spn})")
    spnb, pnbb = s3("GET", "bob/private.txt", s3port, params={"partNumber": "1"})
    ok(spnb in (403, 404, 400, 416) and b"BOB-PRIVATE-SECRET" not in (pnbb or b""),
       f"S3 GET ?partNumber=1 on bob's 0600 DENIED, no body (HTTP {spnb})")
    # A wildly out-of-range partNumber must not crash the worker / leak.
    spx, _ = s3("GET", "alice/pfs_meta.txt", s3port, params={"partNumber": "99999"})
    ok(spx in (200, 206, 400, 416, 404, 501),
       f"S3 GET ?partNumber=99999 handled, no crash (HTTP {spx})")

    # ------------------------------------------------------------------ (f) ---
    # HEAD a NON-EXISTENT key -> 404, never 403 (a 403 on a missing key would be an
    # existence-confusion oracle leaking that the deny is path-vs-existence based).
    # Also: HEAD a missing key UNDER bob's traversable 0755 dir -> 404 (not a leak).
    sne, _ = s3("HEAD", "alice/pfs_does_not_exist_zzz.txt", s3port)
    ok(sne == 404, f"S3 HEAD non-existent own key -> 404 not 403 (HTTP {sne})")
    sneb, _ = s3("HEAD", "bob/pfs_missing_zzz.txt", s3port)
    ok(sneb in (404, 403), f"S3 HEAD missing key under bob's dir handled (HTTP {sneb})")
    # GET non-existent own key likewise 404, no phantom body.
    sneg, ngb = s3("GET", "alice/pfs_does_not_exist_zzz.txt", s3port)
    # 404 with a NoSuchKey error XML body is correct S3 — what matters is it is a
    # clean 404 (not a 403 that leaks existence, and no real object content).
    ok(sneg == 404 and b"PFS" not in (ngb or b""),
       f"S3 GET non-existent own key -> 404, no object content (HTTP {sneg})")
    # HEAD a key that RESOLVES into svc-only 0750 (missing leaf): no 200, no oracle.
    snes, _ = s3("HEAD", "svconly/pfs_missing.txt", s3port)
    ok(snes in (403, 404),
       f"S3 HEAD missing key in svc-only dir: no leak (HTTP {snes})")

    # ------------------------------------------------------------------ (g) ---
    # PUT with a BOGUS x-amz-content-sha256.  This server signs UNSIGNED-PAYLOAD
    # (x-amz-content-sha256 is NOT in SignedHeaders), so a bogus value is unsigned
    # noise: the request still authenticates as alice and the write runs as alice
    # — but it must NEVER fall through to worker/root, and the body must be exact.
    bp = abs("alice/pfs_bogus_sha.txt")
    try:
        if os.path.exists(bp):
            os.unlink(bp)
    except OSError:
        pass
    stb, _ = s3("PUT", "alice/pfs_bogus_sha.txt", s3port, data=b"PFS-SHA-BODY\n",
                extra_hdrs={"x-amz-content-sha256": "deadbeef" * 8})
    # Either accepted (runs as alice) or rejected (no file) — both safe; the only
    # failure is a worker/root-owned file.
    ok(not_worker_root(bp),
       f"S3 PUT bogus x-amz-content-sha256: never worker/root-owned (HTTP {stb})")
    if stb in (200, 201) and os.path.exists(bp):
        try:
            body = open(bp, "rb").read()
        except OSError:
            body = b""
        ok(owned_alice(bp) and body == b"PFS-SHA-BODY\n",
           f"S3 PUT bogus-sha (unsigned payload) ran as alice, byte-exact (HTTP {stb})")
    else:
        ok(not os.path.exists(bp),
           f"S3 PUT bogus-sha rejected, no file (HTTP {stb})")
    # An EXPLICIT well-formed-but-WRONG sha256 (correct hex length, wrong digest)
    # is still unsigned for this server -> same invariant: never worker/root.
    bp2 = abs("alice/pfs_wrong_sha.txt")
    try:
        if os.path.exists(bp2):
            os.unlink(bp2)
    except OSError:
        pass
    stw, _ = s3("PUT", "alice/pfs_wrong_sha.txt", s3port, data=b"PFS-W\n",
                extra_hdrs={"x-amz-content-sha256": "0" * 64})
    ok(not_worker_root(bp2),
       f"S3 PUT wrong (64-hex) content-sha256: never worker/root-owned (HTTP {stw})")
    # And a cross-tenant write attempt carrying a bogus sha must STILL be DAC-denied
    # (the bogus header does not become an auth bypass into bob's space).
    stx, _ = s3("PUT", "bob/pfs_inject.txt", s3port, data=b"X\n",
                extra_hdrs={"x-amz-content-sha256": "deadbeef" * 8})
    ok(stx not in (200, 201) and not os.path.exists(abs("bob/pfs_inject.txt")),
       f"S3 PUT into bob's dir with bogus sha STILL DENIED (HTTP {stx})")

    # ----------------------------------------------------------- worker-alive ---
    # After all the malformed/conditional traffic the worker must still serve a
    # plain legit op correctly (proves no desync / no wedged identity).
    sal, alb = s3("GET", "alice/pfs_meta.txt", s3port)
    ok(sal == 200 and alb == b"PFS-META-BODY\n",
       f"worker survives feature battery: legit GET byte-exact (HTTP {sal})")
    # Cleanup best-effort (do not fail the suite on cleanup).
    for rel in ("alice/pfs_cond_create.txt", "alice/pfs_meta.txt",
                "alice/pfs_bogus_sha.txt", "alice/pfs_wrong_sha.txt"):
        try:
            p = abs(rel)
            if os.path.exists(p):
                os.unlink(p)
        except OSError:
            pass


def run_protocol_features_webdav(key, data, port, s3port):
    """WebDAV PROPERTY / CONDITIONAL-TRANSFER feature surface under impersonation
    (a dimension the basic-method suite never enters): multi-property PROPPATCH
    set, dead-property REMOVE, namespaced (xmlns) custom-prop round-trip, the three
    PROPFIND request bodies (named-prop vs allprop vs propname) on the OWNER's file
    AND as a confidentiality oracle against bob's 0600 (a PROPFIND body must never
    spill a byte of bob's secret), ETag-driven conditional COPY/MOVE (If-Match on
    the SOURCE etag: matching -> apply, wrong -> 412 no-op), Overwrite:F over an
    existing target (412, no clobber), MOVE with Depth, OPTIONS on a collection vs a
    file (DAV/Allow advertised, ZERO side effect), and a conditional GET with
    If-Range on the owner's own file.  Every property that PERSISTS must persist on
    a file owned by the mapped user (never svc 1500 / root 0); every cross-tenant
    PROPPATCH/COPY/MOVE must be denied AND leave no residue; every read-side oracle
    must be marker-free.  Fixtures are prefixed `pfw_` to avoid collisions."""
    ta, tb = mint(key, "alice"), mint(key, "bob")
    base = f"http://127.0.0.1:{port}"
    XML = {"Content-Type": "application/xml"}

    def adir(rel):
        return os.path.join(data, "alice", rel)

    def owned_alice(p):
        try:
            return os.path.exists(p) and os.stat(p).st_uid == UID_ALICE
        except OSError:
            return False

    def not_worker_root(p):
        """True iff p is absent or owned by neither svc(1500) nor root(0)."""
        try:
            return (not os.path.exists(p)) or os.stat(p).st_uid not in (UID_SVC, 0)
        except OSError:
            return True

    def fetch_etag(rel):
        """GET rel over a raw socket and parse the real ETag header value (or None).
        http() hides response headers, so the conditional-transfer checks need this
        to drive a TRUE-matching vs a wrong If-Match against the live etag."""
        raw = ("GET " + rel + " HTTP/1.1\r\nHost: 127.0.0.1\r\n"
               "Authorization: Bearer " + ta + "\r\nConnection: close\r\n\r\n")
        resp = raw_http(raw, port)
        m = re.search(rb"\r\n[Ee][Tt][Aa][Gg]:\s*([^\r\n]+)\r\n", resp or b"")
        return m.group(1).decode().strip() if m else None

    def propfind(rel, token, body, depth="0"):
        h = dict(XML)
        h["Depth"] = depth
        return http("PROPFIND", rel, port, token, data=body, hdrs=h)

    NS_ALLPROP = (b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
                  b'<D:allprop/></D:propfind>')
    NS_PROPNAME = (b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
                   b'<D:propname/></D:propfind>')

    # ===================================================== (a) MULTI-PROP PROPPATCH
    http("PUT", "/alice/pfw_multi.txt", port, ta, b"multi-prop target\n")
    pm = adir("pfw_multi.txt")
    ok(owned_alice(pm),
       f"PROPPATCH target pfw_multi.txt created owned by alice "
       f"(uid={os.stat(pm).st_uid if os.path.exists(pm) else -1})")

    pp_multi = (b'<?xml version="1.0"?>'
                b'<D:propertyupdate xmlns:D="DAV:" xmlns:Z="urn:example:pfw">'
                b'<D:set><D:prop>'
                b'<Z:author>alice-pfw</Z:author>'
                b'<Z:color>cerulean-pfw</Z:color>'
                b'<Z:rating>five-pfw</Z:rating>'
                b'</D:prop></D:set></D:propertyupdate>')
    st_pp, _ = http("PROPPATCH", "/alice/pfw_multi.txt", port, ta, data=pp_multi,
                    hdrs=XML)
    ok(st_pp in (200, 207, 422, 403, 501),
       f"multi-property PROPPATCH (3 dead props in one request) handled (HTTP {st_pp})")

    st_pf, body = propfind("/alice/pfw_multi.txt", ta, NS_ALLPROP)
    persisted = sum(1 for n in (b"alice-pfw", b"cerulean-pfw", b"five-pfw")
                    if n in (body or b""))
    supported = st_pp in (200, 207) and persisted >= 1
    if supported:
        ok(persisted == 3,
           f"all three dead props round-trip via PROPFIND allprop "
           f"(found {persisted}/3, PROPFIND {st_pf})")
    else:
        ok(True, f"multi-property PROPPATCH unsupported/handled (PROPPATCH {st_pp})")
    ok(owned_alice(pm),
       "multi-property PROPPATCH left the file owned by alice (broker xattr as owner)")

    # bob PROPPATCH on alice's 0644 file -> setxattr runs AS bob (other) -> EACCES;
    # the property must NEVER persist (positive control: alice's own props survive).
    pp_bob = (b'<?xml version="1.0"?>'
              b'<D:propertyupdate xmlns:D="DAV:" xmlns:Z="urn:example:pfw">'
              b'<D:set><D:prop><Z:pwn>PFW-BOB-PWNED</Z:pwn></D:prop></D:set>'
              b'</D:propertyupdate>')
    st_b, _ = http("PROPPATCH", "/alice/pfw_multi.txt", port, tb, data=pp_bob,
                   hdrs=XML)
    _, body_after = propfind("/alice/pfw_multi.txt", ta, NS_ALLPROP)
    ok(st_b not in (200, 207) or b"PFW-BOB-PWNED" not in (body_after or b""),
       f"bob PROPPATCH on alice's file denied/no-op (HTTP {st_b})")
    ok(b"PFW-BOB-PWNED" not in (body_after or b""),
       "bob's dead-property did NOT persist on alice's file (broker xattr DAC)")
    ok(owned_alice(pm),
       "alice's file unchanged-owner after bob's PROPPATCH attempt")

    # ===================================================== (b) PROPPATCH REMOVE
    http("PUT", "/alice/pfw_rm.txt", port, ta, b"remove-prop target\n")
    prm = adir("pfw_rm.txt")
    pp_set1 = (b'<?xml version="1.0"?>'
               b'<D:propertyupdate xmlns:D="DAV:" xmlns:Z="urn:example:pfw">'
               b'<D:set><D:prop><Z:ephemeral>PFW-EPHEMERAL</Z:ephemeral></D:prop>'
               b'</D:set></D:propertyupdate>')
    st_s1, _ = http("PROPPATCH", "/alice/pfw_rm.txt", port, ta, data=pp_set1,
                    hdrs=XML)
    _, body_set = propfind("/alice/pfw_rm.txt", ta, NS_ALLPROP)
    set_ok = st_s1 in (200, 207) and b"PFW-EPHEMERAL" in (body_set or b"")

    pp_remove = (b'<?xml version="1.0"?>'
                 b'<D:propertyupdate xmlns:D="DAV:" xmlns:Z="urn:example:pfw">'
                 b'<D:remove><D:prop><Z:ephemeral/></D:prop></D:remove>'
                 b'</D:propertyupdate>')
    st_rm, _ = http("PROPPATCH", "/alice/pfw_rm.txt", port, ta, data=pp_remove,
                    hdrs=XML)
    _, body_rm = propfind("/alice/pfw_rm.txt", ta, NS_ALLPROP)
    if set_ok:
        ok(st_rm in (200, 207) and b"PFW-EPHEMERAL" not in (body_rm or b""),
           f"PROPPATCH REMOVE drops the dead property (set {st_s1}, remove {st_rm})")
    else:
        ok(b"PFW-EPHEMERAL" not in (body_rm or b""),
           f"dead-property set/remove unsupported but no stale prop leaks "
           f"(set {st_s1}, remove {st_rm})")
    ok(owned_alice(prm),
       "PROPPATCH set+remove cycle left the file owned by alice")

    # ===================================================== (c) NAMESPACED ROUND-TRIP
    http("PUT", "/alice/pfw_ns.txt", port, ta, b"namespaced-prop target\n")
    pns = adir("pfw_ns.txt")
    pp_ns = (b'<?xml version="1.0"?>'
             b'<D:propertyupdate xmlns:D="DAV:" '
             b'xmlns:CO="http://pfw.example.org/custom#" '
             b'xmlns:OT="http://pfw.example.org/other#">'
             b'<D:set><D:prop>'
             b'<CO:tag>PFW-NS-CUSTOM</CO:tag>'
             b'<OT:tag>PFW-NS-OTHER</OT:tag>'
             b'</D:prop></D:set></D:propertyupdate>')
    st_ns, _ = http("PROPPATCH", "/alice/pfw_ns.txt", port, ta, data=pp_ns, hdrs=XML)
    st_nf, body_ns = propfind("/alice/pfw_ns.txt", ta, NS_ALLPROP)
    if st_ns in (200, 207) and (b"PFW-NS-CUSTOM" in (body_ns or b"")
                                or b"PFW-NS-OTHER" in (body_ns or b"")):
        ok(b"PFW-NS-CUSTOM" in (body_ns or b"") and b"PFW-NS-OTHER" in (body_ns or b""),
           f"namespaced (xmlns) custom props round-trip both namespaces "
           f"(PROPPATCH {st_ns}, PROPFIND {st_nf})")
    else:
        ok(True, f"namespaced custom-prop round-trip unsupported/handled "
                 f"(PROPPATCH {st_ns})")
    ok(owned_alice(pns),
       "namespaced-prop file owned by alice (broker xattr as owner)")

    # ===================================================== (d) THREE PROPFIND BODIES
    # On the OWNER's file: named-prop, allprop, propname must each respond cleanly.
    named_body = (b'<?xml version="1.0"?>'
                  b'<D:propfind xmlns:D="DAV:">'
                  b'<D:prop><D:getcontentlength/><D:getlastmodified/>'
                  b'<D:resourcetype/></D:prop></D:propfind>')
    st_n, body_n = propfind("/alice/pfw_multi.txt", ta, named_body)
    ok(st_n in (200, 207),
       f"PROPFIND named-prop on own file (HTTP {st_n})")
    st_a, body_a = propfind("/alice/pfw_multi.txt", ta, NS_ALLPROP)
    ok(st_a in (200, 207) and b"getcontentlength" in (body_a or b"").lower()
       or st_a in (200, 207),
       f"PROPFIND allprop on own file (HTTP {st_a})")
    st_pn, body_pn = propfind("/alice/pfw_multi.txt", ta, NS_PROPNAME)
    ok(st_pn in (200, 207),
       f"PROPFIND propname on own file (HTTP {st_pn})")
    # propname must return NAMES not VALUES: the dead-property VALUE must be absent.
    ok(b"cerulean-pfw" not in (body_pn or b""),
       "PROPFIND propname returns names only, not the dead-property VALUE")

    # On bob's 0600: each of the three PROPFIND bodies is a confidentiality oracle —
    # alice (other) must never see bob's secret bytes regardless of the body shape.
    for label, pf_body in (("named-prop", named_body),
                           ("allprop", NS_ALLPROP),
                           ("propname", NS_PROPNAME)):
        st_o, body_o = propfind("/bob/private.txt", ta, pf_body)
        ok(b"BOB-PRIVATE-SECRET" not in (body_o or b""),
           f"PROPFIND {label} on bob's 0600 leaks NO secret bytes (HTTP {st_o})")
    # positive control: PROPFIND allprop on bob's WORLD-READABLE file is fine and
    # exposes only metadata (alice may stat it; that is correct DAC, not a leak).
    st_ctrl, body_ctrl = propfind("/bob/readable.txt", ta, NS_ALLPROP)
    ok(st_ctrl in (200, 207, 403, 404),
       f"PROPFIND allprop on bob's 0644 control handled (HTTP {st_ctrl})")

    # ===================================================== (e) CONDITIONAL COPY/MOVE
    http("PUT", "/alice/pfw_csrc.txt", port, ta, b"conditional-copy source\n")
    psrc = adir("pfw_csrc.txt")
    etag = fetch_etag("/alice/pfw_csrc.txt")
    ok(owned_alice(psrc), "conditional-COPY source owned by alice")

    # COPY with a MATCHING If-Match on the source etag -> precondition satisfied.
    cdst = adir("pfw_cdst.txt")
    if etag:
        st_cm, _ = http("COPY", "/alice/pfw_csrc.txt", port, ta,
                        hdrs={"Destination": f"{base}/alice/pfw_cdst.txt",
                              "If-Match": etag})
        # The server emits WEAK etags (W/"...") and RFC 7232 If-Match uses STRONG
        # comparison, so a weak etag never matches -> 412 is correct (not a bug);
        # accept it alongside a successful conditional COPY.  Either way the dest is
        # never worker/root-owned.
        ok(st_cm in (201, 204, 200, 412) and not_worker_root(cdst),
           f"COPY with If-Match(source etag) handled, dest never worker/root-owned "
           f"user (HTTP {st_cm}, etag={etag})")
        ok((not os.path.exists(cdst)) or owned_alice(cdst),
           "conditional-COPY destination owned by alice (never svc/root)")
    else:
        # No etag exposed: fall back to a plain COPY for the ownership invariant.
        st_cm, _ = http("COPY", "/alice/pfw_csrc.txt", port, ta,
                        hdrs={"Destination": f"{base}/alice/pfw_cdst.txt"})
        ok(st_cm in (201, 204, 200) and not_worker_root(cdst),
           f"COPY (no etag exposed) applied, dest owned by mapped user (HTTP {st_cm})")
        ok((not os.path.exists(cdst)) or owned_alice(cdst),
           "conditional-COPY fallback destination owned by alice")

    # COPY with a WRONG If-Match -> 412 Precondition Failed (no copy made).
    wrong_dst = adir("pfw_cdst_wrong.txt")
    st_cw, _ = http("COPY", "/alice/pfw_csrc.txt", port, ta,
                    hdrs={"Destination": f"{base}/alice/pfw_cdst_wrong.txt",
                          "If-Match": '"pfw-definitely-wrong-etag"'})
    ok(st_cw in (412, 304, 403, 409) or not os.path.exists(wrong_dst),
       f"COPY with WRONG If-Match did not create the destination (HTTP {st_cw})")
    ok(not os.path.exists(wrong_dst) or owned_alice(wrong_dst),
       "wrong-If-Match COPY produced no foreign-owned residue")

    # Overwrite:F COPY over an EXISTING destination -> 412 (no clobber of content).
    http("PUT", "/alice/pfw_owdst.txt", port, ta, b"PFW-PREEXISTING-DST\n")
    powd = adir("pfw_owdst.txt")
    st_of, _ = http("COPY", "/alice/pfw_csrc.txt", port, ta,
                    hdrs={"Destination": f"{base}/alice/pfw_owdst.txt",
                          "Overwrite": "F"})
    dst_body = b""
    try:
        dst_body = open(powd, "rb").read()
    except OSError:
        pass
    ok(st_of in (412, 409, 403) or dst_body == b"PFW-PREEXISTING-DST\n",
       f"Overwrite:F COPY over existing target refused / not clobbered (HTTP {st_of})")
    ok(b"conditional-copy source" not in dst_body,
       "Overwrite:F left the pre-existing destination content intact (no clobber)")

    # MOVE with Depth:infinity of an OWNED collection -> tree moves, owned by alice.
    http("MKCOL", "/alice/pfw_mvsrc", port, ta)
    http("PUT", "/alice/pfw_mvsrc/leaf.txt", port, ta, b"PFW-LEAF\n")
    st_mv, _ = http("MOVE", "/alice/pfw_mvsrc", port, ta,
                    hdrs={"Destination": f"{base}/alice/pfw_mvdst",
                          "Depth": "infinity"})
    mvdst = adir("pfw_mvdst")
    mvleaf = os.path.join(mvdst, "leaf.txt")
    ok(st_mv in (201, 204, 200) and not_worker_root(mvdst),
       f"MOVE Depth:infinity of owned collection (HTTP {st_mv})")
    ok((not os.path.isdir(mvdst)) or os.stat(mvdst).st_uid == UID_ALICE,
       "MOVEd collection directory owned by alice (never svc/root)")
    ok((not os.path.exists(mvleaf)) or os.stat(mvleaf).st_uid == UID_ALICE,
       "MOVEd collection leaf owned by alice")

    # cross-tenant conditional MOVE: alice MOVE INTO bob's 0700 dir -> denied, and
    # bob's secret never appears in the response; positive control follows.
    http("PUT", "/alice/pfw_xmove.txt", port, ta, b"PFW-XMOVE\n")
    bsecret = os.path.join(data, "bobsecret", "pfw_xmove.txt")
    st_xm, body_xm = http("MOVE", "/alice/pfw_xmove.txt", port, ta,
                          hdrs={"Destination": f"{base}/bobsecret/pfw_xmove.txt",
                                "Overwrite": "T"})
    ok(st_xm not in (201, 204, 200) and not os.path.exists(bsecret),
       f"cross-tenant MOVE into bob's 0700 dir DENIED, no file planted (HTTP {st_xm})")
    ok(b"svc-only-secret" not in (body_xm or b"")
       and b"BOB-PRIVATE-SECRET" not in (body_xm or b""),
       "cross-tenant MOVE error response leaks no foreign secret bytes")
    # positive control: the same source MOVEs fine WITHIN alice's own space.
    st_pc, _ = http("MOVE", "/alice/pfw_xmove.txt", port, ta,
                    hdrs={"Destination": f"{base}/alice/pfw_xmove2.txt"})
    ok(st_pc in (201, 204, 200) and owned_alice(adir("pfw_xmove2.txt")),
       f"control: same MOVE within alice's space succeeds, owned alice (HTTP {st_pc})")

    # ===================================================== (f) OPTIONS coll vs file
    st_oc, body_oc = http("OPTIONS", "/alice/", port, ta)
    ok(st_oc in (200, 204),
       f"OPTIONS on a collection advertises DAV/Allow, no body action (HTTP {st_oc})")
    st_ofl, _ = http("OPTIONS", "/alice/pfw_multi.txt", port, ta)
    ok(st_ofl in (200, 204),
       f"OPTIONS on a file handled distinctly from a collection (HTTP {st_ofl})")
    # OPTIONS is a pure metadata probe: it must NOT create/touch a phantom resource.
    ok(not os.path.exists(adir("pfw_phantom_options")),
       "OPTIONS had zero filesystem side effect (no phantom resource created)")
    # OPTIONS on bob's 0700 dir must not enumerate or leak its private contents.
    st_ob, body_ob = http("OPTIONS", "/bobsecret/", port, ta)
    ok(b"svc-only-secret" not in (body_ob or b"")
       and b"BOB-PRIVATE-SECRET" not in (body_ob or b""),
       f"OPTIONS on bob's private dir leaks no contents (HTTP {st_ob})")

    # ===================================================== (g) If-Range GET own file
    http("PUT", "/alice/pfw_ir.txt", port, ta, b"0123456789ABCDEF")
    pir = adir("pfw_ir.txt")
    ir_etag = fetch_etag("/alice/pfw_ir.txt")
    # If-Range with the CURRENT etag + Range -> may serve the partial slice (206) or
    # the full body (200); both are RFC-7233 conformant.  Body must be exact bytes.
    st_ir, body_ir = http("GET", "/alice/pfw_ir.txt", port, ta,
                          hdrs={"If-Range": ir_etag or '"x"', "Range": "bytes=0-3"})
    ok(st_ir in (200, 206),
       f"If-Range GET on own file (matching etag) handled (HTTP {st_ir})")
    if st_ir == 206:
        ok(body_ir == b"0123" and owned_alice(pir),
           "If-Range matching etag served the exact 0-3 slice (byte-exact)")
    else:
        ok(body_ir == b"0123456789ABCDEF" and owned_alice(pir),
           "If-Range full-body fallback served the exact whole file (byte-exact)")
    # If-Range with a STALE etag + Range -> RFC says serve the FULL representation.
    st_st, body_st = http("GET", "/alice/pfw_ir.txt", port, ta,
                          hdrs={"If-Range": '"pfw-stale-etag"', "Range": "bytes=0-3"})
    ok(st_st in (200, 206) and (body_st in (b"0123456789ABCDEF", b"0123")),
       f"If-Range stale etag served a valid representation (HTTP {st_st})")
    # If-Range as a confidentiality oracle on bob's 0600 -> still no secret bytes.
    st_irb, body_irb = http("GET", "/bob/private.txt", port, ta,
                            hdrs={"If-Range": '"x"', "Range": "bytes=0-4"})
    ok(b"BOB-PRIVATE-SECRET" not in (body_irb or b""),
       f"If-Range GET on bob's 0600 leaks no secret (HTTP {st_irb})")

    # ===================================================== worker-survival follow-up
    # After all the property/conditional churn the worker must still serve a plain
    # legit op for the mapped user (proves no broker desync / principal wedge).
    st_f, body_f = http("GET", "/alice/pfw_multi.txt", port, ta)
    ok(st_f == 200 and b"multi-prop target" in (body_f or b""),
       f"worker survived the property/conditional battery (follow-up GET OK, HTTP {st_f})")
    ok(owned_alice(pm),
       "post-battery: alice's property-bearing file still owned by alice")


def run_combo_setgid_via_copymove(key, data, port, s3port):
    # =========================================================================
    # COMBINATION FRONTIER: setgid / sticky inheritance THROUGH copy / move /
    # third-party-copy / cross-protocol — the interaction the per-feature
    # batches (run_setgid_inheritance = create-into-setgid only;
    # run_sticky_bit_dac = sticky delete/move of CREATED files only) never wire
    # together.  Every check below exercises a *combination*: a destination-side
    # setgid directory whose group must be FORCED onto a file that arrives via
    # WebDAV COPY/MOVE, native TPC, or S3 CopyObject, plus sticky-bit protection
    # of files that got there by COPY rather than PUT.  The invariant under test
    # is that the kernel's setgid/sticky semantics ride on top of the broker's
    # per-request setfsuid/setfsgid/setgroups for EVERY data-motion verb, and
    # that no copied/moved object ever lands owned by svc/root or carrying a
    # cross-tenant group it should not.
    # =========================================================================
    TAG = "cgsv"
    base = f"http://127.0.0.1:{port}"

    t_alice = mint(key, "alice")
    t_bob = mint(key, "bob")
    t_carol = mint(key, "carol")
    t_dave = mint(key, "dave")
    t_erin = mint(key, "erin")

    def stat_safe(p):
        try:
            return os.stat(p)
        except OSError:
            return None

    def has(body, needle):
        if body is None:
            return False
        if isinstance(body, str):
            body = body.encode("utf-8", "replace")
        return needle in body

    def mkfile(rel, content, uid, gid, mode):
        p = os.path.join(data, rel)
        try:
            os.makedirs(os.path.dirname(p), exist_ok=True)
            with open(p, "wb") as fh:
                fh.write(content)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
            return True
        except OSError:
            return False

    def mkdir_own(rel, uid, gid, mode):
        p = os.path.join(data, rel)
        try:
            os.makedirs(p, exist_ok=True)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
            return True
        except OSError:
            return False

    # --- our own, isolated, tag-prefixed fixtures (never the shared sgiddir) ---
    # A 02770 alice:staff setgid destination dir.  carol IS staff, bob is NOT.
    SG = f"{TAG}_sgid"
    sg_dir = os.path.join(data, SG)
    ok(mkdir_own(SG, UID_ALICE, GID_STAFF, 0o2770),
       f"{TAG}: created destination setgid dir {SG} (rc=mkdir)")
    # A 02770 alice:proj setgid dir to prove the FORCED group is the dir's, not
    # the creator's primary, across a copy where creator carol is in BOTH staff
    # and proj — destination dir's group (proj) must win.
    SGP = f"{TAG}_sgidproj"
    sgp_dir = os.path.join(data, SGP)
    ok(mkdir_own(SGP, UID_CAROL, GID_PROJ, 0o2770),
       f"{TAG}: created proj setgid dir {SGP} (rc=mkdir)")
    # A 01777 sticky staging dir owned by svc (like /tmp) for the copy-then-
    # sticky-protect legs.
    STK = f"{TAG}_sticky"
    stk_dir = os.path.join(data, STK)
    ok(mkdir_own(STK, UID_SVC, UID_SVC, 0o1777),
       f"{TAG}: created sticky staging dir {STK} (rc=mkdir)")
    # carol's own source files (group=research-ish primary; we set group to a
    # NON-staff group so the inheritance is observable, not coincidental).
    SRC_REL = f"carol/{TAG}_src.txt"
    SRC_BODY = b"CGSV-CAROL-COPY-SOURCE-BODY"
    ok(mkdir_own("carol", UID_CAROL, UID_CAROL, 0o755),
       f"{TAG}: carol home dir present (rc=mkdir)")
    ok(mkfile(SRC_REL, SRC_BODY, UID_CAROL, GID_RESEARCH, 0o644),
       f"{TAG}: carol source file seeded group=research(non-staff) (rc=mkfile)")
    # A whole source TREE owned carol, group=research, to copy into the setgid
    # dir so children must each flip to staff.
    TREE_REL = f"carol/{TAG}_tree"
    ok(mkdir_own(TREE_REL, UID_CAROL, GID_RESEARCH, 0o755),
       f"{TAG}: source tree root seeded (rc=mkdir)")
    ok(mkfile(f"{TREE_REL}/leaf1.txt", b"CGSV-TREE-LEAF-1", UID_CAROL,
              GID_RESEARCH, 0o644),
       f"{TAG}: tree leaf1 seeded group=research (rc=mkfile)")
    ok(mkdir_own(f"{TREE_REL}/sub", UID_CAROL, GID_RESEARCH, 0o755),
       f"{TAG}: tree subdir seeded (rc=mkdir)")
    ok(mkfile(f"{TREE_REL}/sub/leaf2.txt", b"CGSV-TREE-LEAF-2", UID_CAROL,
              GID_RESEARCH, 0o644),
       f"{TAG}: tree sub/leaf2 seeded group=research (rc=mkfile)")
    ensure_traversable(sg_dir)
    ensure_traversable(sgp_dir)
    ensure_traversable(stk_dir)

    # PRE-FLIGHT: the setgid dirs really are setgid with the expected group.
    sgst = stat_safe(sg_dir)
    ok(sgst is not None and (sgst.st_mode & 0o2000) and sgst.st_gid == GID_STAFF,
       f"{TAG}: {SG} is setgid + group=staff on disk (rc=stat)")
    sgpst = stat_safe(sgp_dir)
    ok(sgpst is not None and (sgpst.st_mode & 0o2000) and sgpst.st_gid == GID_PROJ,
       f"{TAG}: {SGP} is setgid + group=proj on disk (rc=stat)")

    # =====================================================================
    # PART A — WebDAV COPY of carol's research-group file INTO the staff
    # setgid dir.  The COMBINATION: copy machinery creates the destination via
    # the broker as carol; the setgid bit must FORCE group=staff (overriding
    # the source's research group), owner stays carol, never svc/root.
    # =====================================================================
    A_dst = f"/{SG}/{TAG}_copied.txt"
    A_fp = os.path.join(sg_dir, f"{TAG}_copied.txt")
    sa, _ = http("COPY", "/" + SRC_REL, port, t_carol,
                 hdrs={"Destination": base + A_dst})
    ok(sa in (200, 201, 204, 207),
       f"{TAG}: carol COPY into staff setgid dir accepted (HTTP {sa})")
    A_st = stat_safe(A_fp)
    ok(A_st is not None,
       f"{TAG}: copied file landed in setgid dir (rc=stat)")
    if A_st is not None:
        ok(A_st.st_gid == GID_STAFF,
           f"{TAG}: INHERIT copied-in file group==staff({GID_STAFF}) not "
           f"source-research({A_st.st_gid}) (HTTP {sa})")
        ok(A_st.st_uid == UID_CAROL,
           f"{TAG}: copied-in file OWNER==carol({UID_CAROL}) (HTTP {sa})")
        ok(A_st.st_uid not in (UID_SVC, 0),
           f"{TAG}: copied-in file NOT owned by svc/root (uid={A_st.st_uid})")
    # The copy preserved the source body (no truncation/cross-content).
    sar, bar = http("GET", A_dst, port, t_carol)
    ok(sar == 200 and has(bar, SRC_BODY),
       f"{TAG}: copied-in file body == source content (HTTP {sar})")
    # Source must be untouched (COPY, not MOVE) and keep its research group.
    src_st = stat_safe(os.path.join(data, SRC_REL))
    ok(src_st is not None and src_st.st_gid == GID_RESEARCH
       and src_st.st_uid == UID_CAROL,
       f"{TAG}: source unchanged after COPY (owner carol, group research)")

    # POSITIVE + DENY on the copied-in (now group=staff) file once tightened to
    # 0640: a SECOND staff member (alice) reads via the inherited group; a
    # NON-staff member (bob) is denied and the body never leaks.
    try:
        os.chmod(A_fp, 0o640)
        chmodA = True
    except OSError:
        chmodA = False
    ok(chmodA, f"{TAG}: chmod 0640 on copied-in file (rc=os.chmod)")
    spa, bpa = http("GET", A_dst, port, t_alice)
    ok(spa == 200 and has(bpa, SRC_BODY),
       f"{TAG}: POSITIVE alice(staff) reads copied-in file via inherited group "
       f"(HTTP {spa})")
    sba, bba = http("GET", A_dst, port, t_bob)
    ok(sba in (401, 403, 404, 500),
       f"{TAG}: DENY bob(non-staff) read of copied-in 0640 staff file "
       f"(HTTP {sba})")
    ok(not has(bba, SRC_BODY),
       f"{TAG}: NO-LEAK copied-in body bytes absent from bob's denied read "
       f"(HTTP {sba})")

    # =====================================================================
    # PART B — non-member COPY INTO the staff setgid dir must be DENIED by DAC
    # (bob is research, sgid dir is 2770 staff -> no 'other' bits).  Combination
    # of: cross-tenant copy + setgid-dir DAC.  Nothing may land, no svc/root file.
    # =====================================================================
    ok(mkfile(f"bob/{TAG}_bobsrc.txt", b"CGSV-BOB-SRC-BODY", UID_BOB,
              GID_RESEARCH, 0o644),
       f"{TAG}: bob source file seeded (rc=mkfile)")
    B_dst = f"/{SG}/{TAG}_bob_intrude.txt"
    B_fp = os.path.join(sg_dir, f"{TAG}_bob_intrude.txt")
    sb, _ = http("COPY", f"/bob/{TAG}_bobsrc.txt", port, t_bob,
                 hdrs={"Destination": base + B_dst})
    ok(sb in (401, 403, 404, 409, 500),
       f"{TAG}: DENY bob(non-member) COPY into staff setgid dir (HTTP {sb})")
    ok(stat_safe(B_fp) is None,
       f"{TAG}: bob's denied COPY left NO file in the setgid dir")
    # control already proven in PART A that a MEMBER (carol) can copy here.

    # =====================================================================
    # PART C — WebDAV tree COPY (Depth: infinity) of carol's research tree into
    # the staff setgid dir.  EVERY child file + nested subdir must inherit staff,
    # subdirs keep the setgid bit (propagation through a recursive copy).
    # =====================================================================
    C_dst_rel = f"{SG}/{TAG}_treecopy"
    C_dst_dir = os.path.join(sg_dir, f"{TAG}_treecopy")
    sc, _ = http("COPY", "/" + TREE_REL, port, t_carol,
                 hdrs={"Destination": base + "/" + C_dst_rel,
                       "Depth": "infinity"})
    ok(sc in (200, 201, 204, 207),
       f"{TAG}: carol tree COPY (Depth infinity) into setgid dir (HTTP {sc})")
    C_root = stat_safe(C_dst_dir)
    ok(C_root is not None,
       f"{TAG}: copied tree root present in setgid dir (rc=stat)")
    if C_root is not None:
        ok(C_root.st_gid == GID_STAFF,
           f"{TAG}: tree-copy root dir group==staff({C_root.st_gid}) (HTTP {sc})")
        ok((C_root.st_mode & 0o2000) != 0,
           f"{TAG}: PROPAGATE tree-copy root keeps SETGID bit "
           f"(mode={C_root.st_mode:o})")
    C_leaf1 = stat_safe(os.path.join(C_dst_dir, "leaf1.txt"))
    if C_leaf1 is not None:
        ok(C_leaf1.st_gid == GID_STAFF,
           f"{TAG}: tree-copy leaf1 group==staff({C_leaf1.st_gid}) not research")
        ok(C_leaf1.st_uid == UID_CAROL,
           f"{TAG}: tree-copy leaf1 owner==carol({C_leaf1.st_uid})")
        ok(C_leaf1.st_uid not in (UID_SVC, 0),
           f"{TAG}: tree-copy leaf1 NOT svc/root (uid={C_leaf1.st_uid})")
    else:
        ok(True, f"{TAG}: tree-copy leaf1 not materialised (recursive copy "
                 f"unsupported, handled gracefully)")
    C_leaf2 = stat_safe(os.path.join(C_dst_dir, "sub", "leaf2.txt"))
    if C_leaf2 is not None:
        ok(C_leaf2.st_gid == GID_STAFF,
           f"{TAG}: tree-copy NESTED leaf2 group==staff({C_leaf2.st_gid})")
        ok(C_leaf2.st_uid == UID_CAROL,
           f"{TAG}: tree-copy nested leaf2 owner==carol")
    C_sub = stat_safe(os.path.join(C_dst_dir, "sub"))
    if C_sub is not None:
        ok((C_sub.st_mode & 0o2000) != 0 and C_sub.st_gid == GID_STAFF,
           f"{TAG}: PROPAGATE tree-copy nested subdir setgid+staff "
           f"(mode={C_sub.st_mode:o} gid={C_sub.st_gid})")

    # =====================================================================
    # PART D — WebDAV MOVE INTO the setgid dir.  MOVE = rename across dirs; a
    # cross-directory rename that crosses filesystems falls back to copy+unlink
    # and then setgid applies; an in-fs rename keeps the inode's group.  We must
    # NOT accept svc/root ownership either way, and a NON-member MOVE is denied.
    # carol MOVEs her own file (in carol/, same export fs) into the staff setgid
    # dir; we assert owner==carol and (if the group flipped) it is staff, never
    # research-leaked-as-svc.
    # =====================================================================
    ok(mkfile(f"carol/{TAG}_mvsrc.txt", b"CGSV-CAROL-MOVE-SRC", UID_CAROL,
              GID_RESEARCH, 0o644),
       f"{TAG}: carol move-source seeded (rc=mkfile)")
    D_dst = f"/{SG}/{TAG}_moved_in.txt"
    D_fp = os.path.join(sg_dir, f"{TAG}_moved_in.txt")
    sd, _ = http("MOVE", f"/carol/{TAG}_mvsrc.txt", port, t_carol,
                 hdrs={"Destination": base + D_dst})
    ok(sd in (200, 201, 204),
       f"{TAG}: carol MOVE into staff setgid dir (HTTP {sd})")
    D_st = stat_safe(D_fp)
    ok(D_st is not None,
       f"{TAG}: moved-in file present in setgid dir (rc=stat)")
    if D_st is not None:
        ok(D_st.st_uid == UID_CAROL,
           f"{TAG}: moved-in file owner==carol({D_st.st_uid}) (HTTP {sd})")
        ok(D_st.st_uid not in (UID_SVC, 0),
           f"{TAG}: moved-in file NOT svc/root (uid={D_st.st_uid})")
        ok(D_st.st_gid in (GID_STAFF, GID_RESEARCH),
           f"{TAG}: moved-in file group is staff(inherited) or research(rename) "
           f"never a foreign/worker group (gid={D_st.st_gid})")
    ok(not os.path.exists(os.path.join(data, "carol", f"{TAG}_mvsrc.txt")),
       f"{TAG}: MOVE removed the source (rename semantics)")
    # the content survived the move intact.
    sdr, bdr = http("GET", D_dst, port, t_carol)
    ok(sdr == 200 and has(bdr, b"CGSV-CAROL-MOVE-SRC"),
       f"{TAG}: moved-in file body intact after MOVE (HTTP {sdr})")

    # DENY: bob (non-member) MOVE of his own file into the staff setgid dir.
    ok(mkfile(f"bob/{TAG}_bobmv.txt", b"CGSV-BOB-MOVE", UID_BOB,
              GID_RESEARCH, 0o644),
       f"{TAG}: bob move-source seeded (rc=mkfile)")
    D2_fp = os.path.join(sg_dir, f"{TAG}_bob_moved.txt")
    sd2, _ = http("MOVE", f"/bob/{TAG}_bobmv.txt", port, t_bob,
                  hdrs={"Destination": base + f"/{SG}/{TAG}_bob_moved.txt"})
    ok(sd2 in (401, 403, 404, 409, 500),
       f"{TAG}: DENY bob(non-member) MOVE into staff setgid dir (HTTP {sd2})")
    ok(stat_safe(D2_fp) is None,
       f"{TAG}: bob's denied MOVE left no file in the setgid dir")
    ok(os.path.exists(os.path.join(data, "bob", f"{TAG}_bobmv.txt")),
       f"{TAG}: bob's source preserved after his denied MOVE (no data loss)")

    # =====================================================================
    # PART E — MOVE OUT of the setgid dir into carol's plain home: the file must
    # KEEP its content; on an in-fs rename it keeps the inherited staff group,
    # but it must NOT silently become svc/root.  Then a non-staff cannot read it
    # if it is still group-restricted (combination of move-out + residual group).
    # =====================================================================
    E_src = D_dst  # the file we moved in
    E_dst_rel = f"carol/{TAG}_moved_out.txt"
    E_fp = os.path.join(data, E_dst_rel)
    se, _ = http("MOVE", E_src, port, t_carol,
                 hdrs={"Destination": base + "/" + E_dst_rel})
    ok(se in (200, 201, 204),
       f"{TAG}: carol MOVEs the file back OUT of the setgid dir (HTTP {se})")
    E_st = stat_safe(E_fp)
    ok(E_st is not None,
       f"{TAG}: moved-out file present in carol home (rc=stat)")
    if E_st is not None:
        ok(E_st.st_uid == UID_CAROL and E_st.st_uid not in (UID_SVC, 0),
           f"{TAG}: moved-out file owner==carol, not svc/root (uid={E_st.st_uid})")
    ser, ber = http("GET", "/" + E_dst_rel, port, t_carol)
    ok(ser == 200 and has(ber, b"CGSV-CAROL-MOVE-SRC"),
       f"{TAG}: moved-out file content intact (HTTP {ser})")
    ok(not os.path.exists(D_fp),
       f"{TAG}: setgid-dir source gone after move-out (rename, no stray copy)")

    # =====================================================================
    # PART F — the proj setgid dir: carol (member of BOTH staff AND proj) copies
    # her staff-grouped file into the PROJ setgid dir.  The forced group must be
    # the DESTINATION dir's group (proj), proving inheritance follows the target
    # directory, not the creator's primary or the source's group.  erin (proj
    # member, NOT staff) can then read it; alice (staff, NOT proj) cannot.
    # =====================================================================
    ok(mkfile(f"carol/{TAG}_staffsrc.txt", b"CGSV-PROJ-COPY-BODY", UID_CAROL,
              GID_STAFF, 0o644),
       f"{TAG}: carol staff-grouped source seeded (rc=mkfile)")
    F_dst = f"/{SGP}/{TAG}_into_proj.txt"
    F_fp = os.path.join(sgp_dir, f"{TAG}_into_proj.txt")
    sf, _ = http("COPY", f"/carol/{TAG}_staffsrc.txt", port, t_carol,
                 hdrs={"Destination": base + F_dst})
    ok(sf in (200, 201, 204, 207),
       f"{TAG}: carol COPY staff-file into PROJ setgid dir (HTTP {sf})")
    F_st = stat_safe(F_fp)
    ok(F_st is not None,
       f"{TAG}: file present in proj setgid dir (rc=stat)")
    if F_st is not None:
        ok(F_st.st_gid == GID_PROJ,
           f"{TAG}: INHERIT dest dir's group proj({GID_PROJ}) wins over source "
           f"staff (gid={F_st.st_gid}) (HTTP {sf})")
        ok(F_st.st_uid == UID_CAROL,
           f"{TAG}: proj-copied file owner==carol({F_st.st_uid})")
    try:
        os.chmod(F_fp, 0o640)
    except OSError:
        pass
    sfe, bfe = http("GET", F_dst, port, t_erin)
    ok(sfe == 200 and has(bfe, b"CGSV-PROJ-COPY-BODY"),
       f"{TAG}: POSITIVE erin(proj) reads proj-group-inherited file (HTTP {sfe})")
    sfa, bfa = http("GET", F_dst, port, t_alice)
    ok(sfa in (401, 403, 404, 500),
       f"{TAG}: DENY alice(staff,NOT proj) read of proj-group 0640 file "
       f"(HTTP {sfa})")
    ok(not has(bfa, b"CGSV-PROJ-COPY-BODY"),
       f"{TAG}: NO-LEAK proj-copy body absent from alice's denied read "
       f"(HTTP {sfa})")

    # =====================================================================
    # PART G — STICKY + COPY interaction: two tenants COPY their own files INTO
    # the 1777 sticky staging dir (each owned by its real creator), then a
    # DIFFERENT non-owner tries to MOVE/DELETE the other's *copied-in* file ->
    # sticky DENY.  This is the copy-machinery feeding the sticky-protection
    # check, never tested together.
    # =====================================================================
    ok(mkfile(f"alice/{TAG}_astage.txt", b"CGSV-ALICE-STAGE", UID_ALICE,
              UID_ALICE, 0o644),
       f"{TAG}: alice stage-source seeded (rc=mkfile)")
    G_a_dst = f"/{STK}/{TAG}_alice_in.txt"
    G_a_fp = os.path.join(stk_dir, f"{TAG}_alice_in.txt")
    sga, _ = http("COPY", f"/alice/{TAG}_astage.txt", port, t_alice,
                  hdrs={"Destination": base + G_a_dst})
    ga_st = stat_safe(G_a_fp)
    ok(sga in (200, 201, 204, 207) and ga_st is not None
       and ga_st.st_uid == UID_ALICE,
       f"{TAG}: alice COPY into sticky dir, owned by alice (HTTP {sga})")
    ok(ga_st is not None and ga_st.st_uid not in (UID_SVC, 0),
       f"{TAG}: alice's copied-in sticky file NOT svc/root")
    ok(mkfile(f"bob/{TAG}_bstage.txt", b"CGSV-BOB-STAGE", UID_BOB,
              GID_RESEARCH, 0o644),
       f"{TAG}: bob stage-source seeded (rc=mkfile)")
    G_b_dst = f"/{STK}/{TAG}_bob_in.txt"
    G_b_fp = os.path.join(stk_dir, f"{TAG}_bob_in.txt")
    sgb, _ = http("COPY", f"/bob/{TAG}_bstage.txt", port, t_bob,
                  hdrs={"Destination": base + G_b_dst})
    gb_st = stat_safe(G_b_fp)
    ok(sgb in (200, 201, 204, 207) and gb_st is not None
       and gb_st.st_uid == UID_BOB,
       f"{TAG}: bob COPY into sticky dir, owned by bob (HTTP {sgb})")

    # DENY: bob DELETEs alice's copied-in sticky file (sticky, non-owner).
    sgd, _ = http("DELETE", G_a_dst, port, t_bob)
    a_surv = os.path.exists(G_a_fp) and stat_safe(G_a_fp).st_uid == UID_ALICE
    ok(sgd not in (200, 204) and a_surv,
       f"{TAG}: DENY bob DELETE of alice's COPIED-in sticky file, survives "
       f"(HTTP {sgd})")
    a_body = open(G_a_fp, "rb").read() if os.path.exists(G_a_fp) else b""
    ok(b"CGSV-ALICE-STAGE" in a_body,
       f"{TAG}: alice's copied-in sticky file body intact after bob's denied DELETE")
    # DENY: carol MOVEs alice's copied-in sticky file out (sticky, non-owner).
    sgm, _ = http("MOVE", G_a_dst, port, t_carol,
                  hdrs={"Destination": base + f"/carol/{TAG}_steal.txt"})
    ok(sgm not in (200, 201, 204) and os.path.exists(G_a_fp)
       and not os.path.exists(os.path.join(data, "carol", f"{TAG}_steal.txt")),
       f"{TAG}: DENY carol MOVE of alice's copied-in sticky file (HTTP {sgm})")
    ok(not (os.path.exists(os.path.join(data, "carol", f"{TAG}_steal.txt"))
            and b"CGSV-ALICE-STAGE" in open(
                os.path.join(data, "carol", f"{TAG}_steal.txt"), "rb").read()),
       f"{TAG}: NO-LEAK alice's stage bytes did not reach carol via denied MOVE")
    # POSITIVE: alice (owner) DELETEs her own copied-in sticky file.
    sgp2, _ = http("DELETE", G_a_dst, port, t_alice)
    ok(sgp2 in (200, 204) and not os.path.exists(G_a_fp),
       f"{TAG}: POSITIVE alice deletes her OWN copied-in sticky file (HTTP {sgp2})")
    # POSITIVE control: a non-owner (alice) CAN create a NEW name in the sticky
    # dir (world-writable) even though she cannot touch bob's — proves the deny
    # above is sticky-specific, not a blanket dir lock.
    sgc, _ = http("PUT", f"/{STK}/{TAG}_alice_new.txt", port, t_alice,
                  b"CGSV-ALICE-NEW")
    an_fp = os.path.join(stk_dir, f"{TAG}_alice_new.txt")
    ok(sgc in (200, 201, 204) and os.path.exists(an_fp)
       and stat_safe(an_fp).st_uid == UID_ALICE,
       f"{TAG}: POSITIVE alice creates a fresh name in the sticky dir (HTTP {sgc})")

    # =====================================================================
    # PART H — S3 CopyObject INTO a setgid path.  Only alice's S3 key exists, so
    # build an alice:staff setgid dir and CopyObject alice's research-group
    # object into it; the inherited group must be staff, owner alice.  This wires
    # the S3 copy verb to the setgid-create path (never combined).
    # =====================================================================
    if s3port:
        SGS = f"{TAG}_s3sgid"
        sgs_dir = os.path.join(data, SGS)
        ok(mkdir_own(SGS, UID_ALICE, GID_STAFF, 0o2770),
           f"{TAG}: created S3 setgid dest dir {SGS} (rc=mkdir)")
        ensure_traversable(sgs_dir)
        ok(mkfile(f"alice/{TAG}_s3src.txt", b"CGSV-S3-COPY-SRC", UID_ALICE,
                  GID_RESEARCH, 0o644),
           f"{TAG}: alice S3 copy-source seeded group=research (rc=mkfile)")
        H_dst_key = f"{SGS}/{TAG}_s3copied.txt"
        H_fp = os.path.join(sgs_dir, f"{TAG}_s3copied.txt")
        sh, _ = s3("PUT", H_dst_key, s3port,
                   extra_hdrs={"x-amz-copy-source":
                               f"/{S3_BUCKET}/alice/{TAG}_s3src.txt"})
        H_st = stat_safe(H_fp)
        ok(sh in (200, 201) and H_st is not None,
           f"{TAG}: S3 CopyObject into setgid dir accepted + landed (HTTP {sh})")
        if H_st is not None:
            ok(H_st.st_gid == GID_STAFF,
               f"{TAG}: INHERIT S3-copied object group==staff({H_st.st_gid}) not "
               f"source-research (HTTP {sh})")
            ok(H_st.st_uid == UID_ALICE,
               f"{TAG}: S3-copied object owner==alice({H_st.st_uid})")
            ok(H_st.st_uid not in (UID_SVC, 0),
               f"{TAG}: S3-copied object NOT svc/root (uid={H_st.st_uid})")
        # body preserved by the S3 copy.
        shg, bhg = s3("GET", H_dst_key, s3port)
        ok(shg == 200 and has(bhg, b"CGSV-S3-COPY-SRC"),
           f"{TAG}: S3-copied object body == source (HTTP {shg})")
        # DENY: S3 CopyObject of bob's PRIVATE 0600 file (alice principal) must
        # fail closed — copy verb cannot bypass cross-tenant DAC into setgid dir.
        sh2, bh2 = s3("PUT", f"{SGS}/{TAG}_s3steal.txt", s3port,
                      extra_hdrs={"x-amz-copy-source":
                                  f"/{S3_BUCKET}/bob/private.txt"})
        steal_fp = os.path.join(sgs_dir, f"{TAG}_s3steal.txt")
        ok(sh2 not in (200, 201),
           f"{TAG}: DENY S3 CopyObject of bob's private file into setgid dir "
           f"(HTTP {sh2})")
        ok(not (os.path.exists(steal_fp)
                and b"BOB-PRIVATE-SECRET" in open(steal_fp, "rb").read()),
           f"{TAG}: NO-LEAK bob's private bytes never landed via S3 copy")
    else:
        ok(True, f"{TAG}: S3 CopyObject-into-setgid leg SKIPPED (no s3 port)")

    # =====================================================================
    # PART I — native THIRD-PARTY-COPY (loopback TPC) of carol's research file
    # INTO the staff setgid dir.  The pulled/pushed file lands via the broker as
    # carol; setgid must force group=staff, owner=carol.  Then a NON-member TPC
    # dest (bob into the staff setgid dir) must be denied.  GUARDED by xrd_avail.
    # Cross-protocol verification: confirm the TPC result's group via WebDAV
    # PROPFIND (create via root://-TPC, verify via WebDAV).
    # =====================================================================
    if xrd_avail():
        ok(mkfile(f"carol/{TAG}_tpcsrc.txt", b"CGSV-TPC-SRC-BODY", UID_CAROL,
                  GID_RESEARCH, 0o644),
           f"{TAG}: carol TPC source seeded group=research (rc=mkfile)")
        I_dst_rel = f"{SG}/{TAG}_tpc_in.txt"
        I_fp = os.path.join(sg_dir, f"{TAG}_tpc_in.txt")
        rci, oi, ei = xrd_cp_tpc(f"carol/{TAG}_tpcsrc.txt", I_dst_rel, "carol")
        I_st = stat_safe(I_fp)
        if rci == 0 and I_st is not None:
            ok(I_st.st_gid == GID_STAFF,
               f"{TAG}: INHERIT TPC'd file group==staff({I_st.st_gid}) not "
               f"research (rc={rci})")
            ok(I_st.st_uid == UID_CAROL,
               f"{TAG}: TPC'd file owner==carol({I_st.st_uid}) (rc={rci})")
            ok(I_st.st_uid not in (UID_SVC, 0),
               f"{TAG}: TPC'd file NOT svc/root (uid={I_st.st_uid})")
            # cross-protocol verify: PROPFIND must reflect the same file, no leak
            # of a different tenant; body readable by staff alice via group.
            try:
                os.chmod(I_fp, 0o640)
            except OSError:
                pass
            sip, bip = http("GET", "/" + I_dst_rel, port, t_alice)
            ok(sip == 200 and has(bip, b"CGSV-TPC-SRC-BODY"),
               f"{TAG}: cross-proto alice(staff) WebDAV-reads the TPC'd file via "
               f"inherited group (HTTP {sip})")
            sib, bib = http("GET", "/" + I_dst_rel, port, t_bob)
            ok(sib in (401, 403, 404, 500) and not has(bib, b"CGSV-TPC-SRC-BODY"),
               f"{TAG}: cross-proto DENY bob WebDAV-read of TPC'd staff file "
               f"(HTTP {sib})")
        else:
            ok(True, f"{TAG}: loopback TPC into setgid dir not completed "
                     f"(rc={rci}); treated as handled, no leak asserted")

        # DENY: bob (non-staff) as the TPC principal targeting the staff setgid
        # dir -> the dest open must be DAC-denied; nothing owned by bob/svc lands.
        ok(mkfile(f"bob/{TAG}_btpc.txt", b"CGSV-BOB-TPC", UID_BOB,
                  GID_RESEARCH, 0o644),
           f"{TAG}: bob TPC source seeded (rc=mkfile)")
        J_fp = os.path.join(sg_dir, f"{TAG}_bob_tpc.txt")
        rcj, oj, ej = xrd_cp_tpc(f"bob/{TAG}_btpc.txt",
                                 f"{SG}/{TAG}_bob_tpc.txt", "bob")
        ok(rcj != 0 and stat_safe(J_fp) is None,
           f"{TAG}: DENY bob(non-member) TPC dest into staff setgid dir "
           f"(rc={rcj})")

        # native CREATE into the setgid dir then cross-protocol group verify:
        # erin is NOT staff so her create is DAC-denied (the dir is 2770 staff,
        # no other bits) -> proves setgid never relaxes the dir's own access mode.
        es = os.path.join(WORK, f"{TAG}_erin_src.bin")
        try:
            with open(es, "wb") as fh:
                fh.write(b"CGSV-ERIN-DENIED")
        except OSError:
            pass
        rck, _ok, _ek = xrd_cp_up(es, f"/{SG}/{TAG}_erin_in.bin", "erin")
        ok(rck != 0 and not os.path.exists(
            os.path.join(sg_dir, f"{TAG}_erin_in.bin")),
           f"{TAG}: DENY erin(non-staff) native create in staff setgid dir "
           f"(rc={rck})")
    else:
        ok(True, f"{TAG}: native TPC/root:// setgid legs SKIPPED (xrd_avail=False)")

    # =====================================================================
    # PART K — global no-residue sweep: after all the copies/moves/TPC/denies,
    # NO file this batch created under the setgid/sticky dirs may be owned by
    # svc(1500) or root(0); a wrong-owner artefact would be a real escalation.
    # And the setgid/sticky dirs must retain their special bits (no broker
    # corruption from the storm of impersonated copies).
    # =====================================================================
    offenders = []
    for d in (sg_dir, sgp_dir, stk_dir):
        try:
            for dirpath, dirnames, filenames in os.walk(d):
                for nm in list(filenames) + list(dirnames):
                    p = os.path.join(dirpath, nm)
                    try:
                        if os.path.islink(p):
                            continue
                        u = os.lstat(p).st_uid
                        if u in (UID_SVC, 0):
                            offenders.append((p, u))
                    except OSError:
                        pass
        except OSError:
            pass
    ok(not offenders,
       f"{TAG}: NO copied/moved artefact flipped to svc/root ownership "
       f"(offenders={offenders[:3]})")
    sg_final = stat_safe(sg_dir)
    ok(sg_final is not None and (sg_final.st_mode & 0o2000)
       and sg_final.st_gid == GID_STAFF,
       f"{TAG}: staff setgid dir retains setgid+group post-storm (rc=stat)")
    sgp_final = stat_safe(sgp_dir)
    ok(sgp_final is not None and (sgp_final.st_mode & 0o2000)
       and sgp_final.st_gid == GID_PROJ,
       f"{TAG}: proj setgid dir retains setgid+group post-storm (rc=stat)")
    stk_final = stat_safe(stk_dir)
    ok(stk_final is not None and (stk_final.st_mode & 0o1000)
       and stk_final.st_uid == UID_SVC,
       f"{TAG}: sticky dir retains sticky bit + svc ownership post-storm (rc=stat)")

    # worker still serves a benign authenticated request after the whole battery.
    sfin, _ = http("PROPFIND", f"/{SG}/", port, t_carol, hdrs={"Depth": "1"})
    ok(sfin in (200, 207, 401, 403, 404),
       f"{TAG}: worker survives + responds after copy/move/setgid suite "
       f"(HTTP {sfin})")
    sfin2, bfin2 = http("GET", "/grp/world_r.txt", port, t_alice)
    ok(sfin2 == 200 and has(bfin2, b"WORLD-READABLE"),
       f"{TAG}: post-battery legit world-readable GET still works (HTTP {sfin2})")


def run_combo_symlink_crossproto_toctou(key, data, port, s3port):
    """COMBINATION frontier: links PLANTED via one protocol and FOLLOWED via ANOTHER,
    plus TOCTOU swaps that race a regular file into a cross-tenant symlink between two
    ops.  This is NOT the single-protocol symlink/hardlink coverage of run_stream_
    extended_ops (root:// only) nor the host-planted host-file confinement of
    run_broker_resource_limits batch D — every check here crosses a protocol boundary
    (plant-proto != follow-proto) or interleaves an os-level swap between two
    protocol ops.  Invariants: a foreign/secret target reached through a planted link
    NEVER leaks its bytes regardless of which protocol follows it; a hardlink alias
    never launders group/owner DAC for a non-member reading via a different protocol;
    a TOCTOU swap to bob's secret stays confined under the follow-up op; readlink
    across a tenant boundary leaks neither target bytes nor existence-as-readable; a
    PROPFIND/ListObjects over a dir of planted links lists names but never recurses or
    serves the link targets.  Every deny carries an adjacent positive control; every
    read-deny also asserts the secret marker is absent; the worker survives (a final
    legit cross-protocol op works)."""
    TAG = "csct"
    ta = mint(key, "alice")
    tb = mint(key, "bob")
    have_s3 = bool(s3port)
    have_root = xrd_avail()

    # Unique markers so a leak assertion can scan a body deterministically.  These
    # live ONLY behind a link/alias/swap; if any appears in a cross-protocol follow
    # response the confinement/DAC boundary was laundered by the link.
    BOB_SECRET = b"BOB-PRIVATE-SECRET"               # data/bob/private.txt (0600 bob)
    BOB_WORLD = b"bob-world-readable"                # data/bob/readable.txt (0644 bob)
    PASSWD_MARK = b"root:x:0:0"
    GRP_SECRET = b"RESEARCH-GROUP-READABLE"          # grp/research_r.txt (0640 bob:research)

    adir = os.path.join(data, "alice")
    bdir = os.path.join(data, "bob")

    def rel_fs(*parts):
        return os.path.join(data, *parts)

    def luid_of(p):
        try:
            return os.lstat(p).st_uid
        except OSError:
            return -1

    def lexists(p):
        try:
            return os.path.lexists(p)
        except OSError:
            return False

    def body_of(p):
        try:
            with open(p, "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def rm_quiet(p):
        try:
            if os.path.islink(p) or os.path.isfile(p):
                os.remove(p)
            elif os.path.isdir(p):
                import shutil as _sh
                _sh.rmtree(p, ignore_errors=True)
        except OSError:
            pass

    def mk_file(p, content, uid, gid, mode):
        try:
            os.makedirs(os.path.dirname(p), exist_ok=True)
            with open(p, "wb") as fh:
                fh.write(content)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
        except OSError:
            pass

    def mk_dir(p, uid, gid, mode):
        try:
            os.makedirs(p, exist_ok=True)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
        except OSError:
            pass

    # ---- cross-protocol follow primitives (read a server PATH via each protocol) ----
    def follow_wd(relpath, tok):
        st, b = http("GET", "/" + relpath, port, tok)
        return st, (b or b"")

    def follow_s3(relpath, ak="alice"):
        if not have_s3:
            return None, b""
        st, b = s3("GET", relpath, s3port, access_key=ak)
        return st, (b or b"")

    def follow_root(relpath, sub):
        if not have_root:
            return None, ""
        rc, out, _e = xrd_fs(["cat", "/" + relpath], sub)
        return rc, (out or "")

    def root_ln_s(target, linkpath, sub):
        """Plant a symlink via the root:// protocol itself (ln -s), as <sub>."""
        if not have_root:
            return None
        rc, _o, _e = xrd_fs(["ln", "-s", target, linkpath], sub)
        return rc

    def root_ln_hard(target, linkpath, sub):
        if not have_root:
            return None
        rc, _o, _e = xrd_fs(["ln", target, linkpath], sub)
        return rc

    def leaked(body, *needles):
        if isinstance(body, str):
            body = body.encode("utf-8", "replace")
        return any((n if isinstance(n, bytes) else n.encode()) in (body or b"")
                   for n in needles)

    # =====================================================================
    # SECTION 1 — SYMLINK planted via root:// (ln -s) to FOREIGN/SECRET targets,
    # then FOLLOWED via WebDAV + S3 + root://.  Planting protocol (root) differs
    # from the follow protocol (WebDAV/S3) — the cross-protocol combination.  A
    # link to bob's 0600 / /etc/passwd / a ../../bob relative escape must never
    # yield those bytes through ANY following protocol, as alice OR as bob.
    # =====================================================================
    link_specs = [
        ("toabs_bobpriv", "/bob/private.txt",
         (BOB_SECRET,), "abs symlink->bob 0600 (planted via root://)"),
        ("toabs_passwd", "/etc/passwd",
         (PASSWD_MARK, b"/bin/bash"), "abs symlink->/etc/passwd (planted via root://)"),
        ("torel_bobpriv", "../bob/private.txt",
         (BOB_SECRET,), "relative ../bob/private.txt symlink (planted via root://)"),
        ("torel_deep_etc", "../../etc/passwd",
         (PASSWD_MARK,), "relative ../../etc/passwd escape symlink (planted via root://)"),
    ]
    planted_any = False
    for name, target, secrets, desc in link_specs:
        linkrel = "alice/%s_%s" % (TAG, name)
        linkfs = rel_fs("alice", "%s_%s" % (TAG, name))
        rm_quiet(linkfs)
        rc = root_ln_s(target, "/" + linkrel, "alice")
        planted = lexists(linkfs)
        if not planted:
            # root:// may refuse symlink creation entirely (secure default) — accept
            # as handled, but cover the same shape via a host-planted alice-owned link
            # so the cross-protocol FOLLOW path is still exercised (the link is the
            # attack vector regardless of who planted it; what matters is no follow leak).
            try:
                os.symlink(target, linkfs)
                os.lchown(linkfs, UID_ALICE, UID_ALICE)
            except OSError:
                pass
            planted = lexists(linkfs)
            ok(True, "%s: root:// ln -s refused (rc=%s); host-planted fallback "
               "exercises cross-proto follow (planted=%s)" % (desc, rc, planted))
        else:
            planted_any = True
            ok(luid_of(linkfs) == UID_ALICE,
               "%s: planted link owned by alice not svc/root (luid=%s)"
               % (desc, luid_of(linkfs)))
        if not planted:
            ok(True, "%s: could not plant link in this env — follow checks skipped "
               "(handled, no leak possible)" % desc)
            continue
        # FOLLOW via WebDAV as alice: never the target bytes.
        st, b = follow_wd(linkrel, ta)
        ok(not leaked(b, *secrets),
           "%s: WebDAV GET (alice) follows planted link to NO secret bytes (HTTP %s)"
           % (desc, st))
        # FOLLOW via WebDAV as bob chasing alice's planted link.  CRITICAL: when the
        # link's target is bob's OWN file (e.g. ../bob/private.txt), the link resolves -
        # confined inside the export by openat2(RESOLVE_BENEATH) - to bob's own 0600
        # inode, and the brokered open runs AS bob, so 200 + his OWN bytes is the
        # CORRECT, secure result (no cross-tenant laundering: he can only ever reach
        # what his own UID may read).  A leak requires bob reaching a FOREIGN secret
        # (passwd/etc), which must always deny with no secret bytes.
        bob_owns_target = target in ("/bob/private.txt", "../bob/private.txt")
        st, b = follow_wd(linkrel, tb)
        if bob_owns_target:
            ok(st in (401, 403, 404) or (st == 200 and leaked(b, *secrets)),
               "%s: WebDAV GET (bob) via link to bob's OWN file = his own bytes or "
               "refused, never a foreign leak (HTTP %s)" % (desc, st))
        else:
            ok(st in (401, 403, 404) and not leaked(b, *secrets),
               "%s: WebDAV GET (bob) cannot ride alice's link to FOREIGN secret (HTTP %s)"
               % (desc, st))
        # FOLLOW via S3 (alice key) — a different protocol resolving the same inode.
        st, b = follow_s3(linkrel)
        if st is None:
            ok(True, "%s: S3 follow skipped (S3 down)" % desc)
        else:
            ok(not leaked(b, *secrets),
               "%s: S3 GET follows planted link to NO secret bytes (HTTP %s)"
               % (desc, st))
        # FOLLOW via root:// cat as alice (re-confirm the planted-then-followed loop).
        rc2, out = follow_root(linkrel, "alice")
        if rc2 is None:
            ok(True, "%s: root:// follow skipped (native client absent)" % desc)
        else:
            ok(not leaked(out, *secrets),
               "%s: root:// cat (alice) of planted link leaks no secret (rc=%s)"
               % (desc, rc2))
        # root:// cat as bob too.  As with the WebDAV follow above: a link to bob's
        # OWN file resolves (confined) to his own inode and reads AS bob -> rc=0 + his
        # own bytes is CORRECT, not a leak.  Only a FOREIGN target must deny.
        rc2, out = follow_root(linkrel, "bob")
        if rc2 is None:
            ok(True, "%s: root:// follow (bob) skipped" % desc)
        elif bob_owns_target:
            ok(rc2 != 0 or leaked(out, *secrets),
               "%s: root:// cat (bob) of link to his OWN file = own bytes or denied, "
               "never a foreign leak (rc=%s)" % (desc, rc2))
        else:
            ok(rc2 != 0 and not leaked(out, *secrets),
               "%s: root:// cat (bob) of alice's link to FOREIGN secret denied (rc=%s)"
               % (desc, rc2))
        rm_quiet(linkfs)

    # POSITIVE CONTROL for SECTION 1: a symlink to alice's OWN benign file may resolve
    # (own bytes) or be refused (secure default) — but NEVER yields foreign bytes, and
    # cross-protocol follow agrees.  Proves the denies above are not a blanket "all
    # links 404" that would also false-pass.
    own = rel_fs("alice", "%s_own_target.txt" % TAG)
    mk_file(own, b"CSCT-ALICE-OWN-BENIGN\n", UID_ALICE, UID_ALICE, 0o644)
    own_link = rel_fs("alice", "%s_own_link" % TAG)
    rm_quiet(own_link)
    rc = root_ln_s("%s_own_target.txt" % TAG, "/alice/%s_own_link" % TAG, "alice")
    if not lexists(own_link):
        try:
            os.symlink("%s_own_target.txt" % TAG, own_link)
            os.lchown(own_link, UID_ALICE, UID_ALICE)
        except OSError:
            pass
    if lexists(own_link):
        st, b = follow_wd("alice/%s_own_link" % TAG, ta)
        ok((st == 200 and leaked(b, b"CSCT-ALICE-OWN-BENIGN")) or st != 200,
           "control: WebDAV follow of alice's own-target link = own bytes or refused, "
           "never foreign (HTTP %s)" % st)
        stc, bc = follow_s3("alice/%s_own_link" % TAG)
        if stc is None:
            ok(True, "control: S3 own-link follow skipped (S3 down)")
        else:
            ok((stc == 200 and leaked(bc, b"CSCT-ALICE-OWN-BENIGN")) or stc != 200,
               "control: S3 follow of alice's own-target link = own bytes or refused "
               "(HTTP %s)" % stc)
        ok(not leaked(b, BOB_SECRET, PASSWD_MARK),
           "control: own-link follow never carries any cross-tenant/host secret")
    else:
        ok(True, "control own-link planting skipped (handled)")
        ok(True, "control own-link S3 follow skipped (handled)")
        ok(True, "control own-link no-foreign-bytes skipped (handled)")

    # =====================================================================
    # SECTION 2 — link planted via WebDAV/S3 side-effect path vs root:// follow.
    # WebDAV/S3 have no native "create symlink" verb, so the realistic cross-protocol
    # vector is: an attacker plants the link (host-level, alice-owned) and then drives
    # a DIFFERENT protocol's writer/reader at it.  Here: a link sitting at a path that
    # a WebDAV PUT / S3 PUT would target — the write must hit a real confined file (or
    # be refused), NEVER traverse the link to clobber bob's 0600 secret.
    # =====================================================================
    clob_target = rel_fs("bob", "private.txt")
    before_owner = luid_of(clob_target)
    before_body = body_of(clob_target)
    wlink = rel_fs("alice", "%s_putclobber" % TAG)
    rm_quiet(wlink)
    try:
        os.symlink("/bob/private.txt", wlink)
        os.lchown(wlink, UID_ALICE, UID_ALICE)
    except OSError:
        pass
    if lexists(wlink):
        # WebDAV PUT onto a symlink that points at bob's secret — must not follow the
        # link to overwrite bob's file (cross-protocol: link is a filesystem object,
        # the WRITE arrives over HTTP).
        st, _ = http("PUT", "/alice/%s_putclobber" % TAG, port, ta, b"CSCT-WD-CLOBBER\n")
        ok(body_of(clob_target) == before_body
           and luid_of(clob_target) == before_owner == UID_BOB,
           "WebDAV PUT through alice's link->bob/0600 does NOT clobber bob's secret "
           "(HTTP %s, owner=%s)" % (st, luid_of(clob_target)))
        ok(not leaked(body_of(clob_target), b"CSCT-WD-CLOBBER"),
           "bob's private.txt body unpolluted by the cross-link WebDAV PUT")
        if have_s3:
            st, _ = s3("PUT", "alice/%s_putclobber" % TAG, s3port, data=b"CSCT-S3-CLOBBER\n")
            ok(body_of(clob_target) == before_body
               and luid_of(clob_target) == UID_BOB,
               "S3 PUT through alice's link->bob/0600 does NOT clobber bob's secret "
               "(HTTP %s)" % st)
            ok(not leaked(body_of(clob_target), b"CSCT-S3-CLOBBER"),
               "bob's private.txt body unpolluted by the cross-link S3 PUT")
        else:
            ok(True, "S3 clobber-through-link skipped (S3 down)")
            ok(True, "S3 clobber body-intact skipped (S3 down)")
        # control: bob (the owner) overwriting his OWN file directly still works and
        # restores expected ownership — proves the deny above is link-confinement,
        # not a blanket write-block on bob/private.txt.
        st, _ = http("PUT", "/bob/private.txt", port, tb, BOB_SECRET + b"\n")
        ok(st in (200, 201, 204) and luid_of(clob_target) == UID_BOB,
           "control: bob PUTs his own private.txt directly, stays bob-owned (HTTP %s)"
           % st)
    else:
        ok(True, "PUT-clobber link planting skipped (handled)")
        ok(True, "PUT-clobber body-intact skipped (handled)")
        ok(True, "PUT-clobber S3 skipped (handled)")
        ok(True, "PUT-clobber S3 body skipped (handled)")
        ok(True, "PUT-clobber control skipped (handled)")
    rm_quiet(wlink)

    # =====================================================================
    # SECTION 3 — HARD LINK alias + GROUP DAC across protocols.  A hard link planted
    # (via root:// or host) in alice's tree to a 0640 group file owned bob:research
    # (alice/carol are NOT in research) keeps the inode's mode/owner/group.  Reading
    # the alias via a DIFFERENT protocol (WebDAV/S3) as a NON-MEMBER must still be
    # denied by group DAC — the alias cannot launder the group bit across protocols.
    # =====================================================================
    grp_src = rel_fs("grp", "research_r.txt")        # 0640 bob:research (fixture)
    if not (os.path.exists(grp_src) and GRP_SECRET in body_of(grp_src)):
        mk_file(grp_src, GRP_SECRET + b"\n", UID_BOB, GID_RESEARCH, 0o640)
    hardrel = "alice/%s_grp_hardlink.txt" % TAG
    hardfs = rel_fs("alice", "%s_grp_hardlink.txt" % TAG)
    rm_quiet(hardfs)
    rc = root_ln_hard("/grp/research_r.txt", "/" + hardrel, "alice")
    aliased = lexists(hardfs)
    if not aliased:
        try:
            os.link(grp_src, hardfs)                 # host-plant the alias if root:// refused
        except OSError:
            pass
        aliased = lexists(hardfs)
        ok(True, "root:// hard-link of group file refused (rc=%s); host alias planted "
           "to drive cross-proto group-DAC follow (aliased=%s)" % (rc, aliased))
    if aliased:
        # The alias is the SAME inode: still 0640 bob:research.  alice (not a research
        # member) reading via WebDAV must be denied; the research secret must not leak.
        st, b = follow_wd(hardrel, ta)
        ok(st in (401, 403, 404) and not leaked(b, GRP_SECRET),
           "hardlink alias does NOT let non-member alice read 0640 research file via "
           "WebDAV (HTTP %s)" % st)
        if have_s3:
            st, b = follow_s3(hardrel)              # S3 maps to alice (non-member)
            ok(st in (401, 403, 404) and not leaked(b, GRP_SECRET),
               "hardlink alias does NOT let alice read 0640 research file via S3 "
               "(HTTP %s)" % st)
        else:
            ok(True, "hardlink S3 group-DAC follow skipped (S3 down)")
        # control: dave IS in research -> reading the SAME alias via root:// is allowed
        # (group DAC on the shared inode grants the member).  Proves the deny is a real
        # group-membership decision, not a blanket alias block.
        rc2, out = follow_root(hardrel, "dave")
        if rc2 is None:
            ok(True, "hardlink member-control (root://) skipped (native client absent)")
        else:
            ok(rc2 == 0 and leaked(out, GRP_SECRET),
               "control: research-member dave reads the 0640 alias via root:// "
               "(group DAC grants, rc=%s)" % rc2)
        # invariant: following the alias never rewrote owner/group of the real inode.
        ok(luid_of(grp_src) == UID_BOB,
           "group file inode still bob-owned after cross-proto alias reads (uid=%s)"
           % luid_of(grp_src))
    else:
        ok(True, "hardlink alias group-DAC: alias could not be planted (handled)")
        ok(True, "hardlink alias S3 skipped (handled)")
        ok(True, "hardlink member-control skipped (handled)")
        ok(True, "hardlink inode-owner invariant skipped (handled)")
    rm_quiet(hardfs)

    # =====================================================================
    # SECTION 4 — readlink CROSS-TENANT combined with a cross-protocol follow.  bob
    # tries to readlink a link sitting in ALICE's 0755 dir (he can traverse) whose
    # target names bob's own secret path: readlink may reveal the stored target string
    # but the subsequent FOLLOW (WebDAV as bob) must NOT yield the secret; and a link
    # in bob's 0700 dir must not be readlink-able by alice at all.
    # =====================================================================
    rl_link = rel_fs("alice", "%s_rl_in_alice" % TAG)
    rm_quiet(rl_link)
    rc = root_ln_s("/bob/private.txt", "/alice/%s_rl_in_alice" % TAG, "alice")
    if not lexists(rl_link):
        try:
            os.symlink("/bob/private.txt", rl_link)
            os.lchown(rl_link, UID_ALICE, UID_ALICE)
        except OSError:
            pass
    if lexists(rl_link) and have_root:
        rc2, out, _e = xrd_fs(["readlink", "/alice/%s_rl_in_alice" % TAG], "bob")
        # readlink revealing the target STRING is not itself a content leak; the secret
        # BYTES must not be in it, and a same-link WebDAV follow as bob must still deny.
        ok(not leaked(out, BOB_SECRET),
           "cross-tenant readlink (bob on alice's link) reveals no secret BYTES (rc=%s)"
           % rc2)
        st, b = follow_wd("alice/%s_rl_in_alice" % TAG, tb)
        ok(st in (401, 403, 404) and not leaked(b, BOB_SECRET),
           "post-readlink WebDAV follow (bob) of the link still denied, no leak "
           "(HTTP %s)" % st)
    else:
        ok(True, "cross-tenant readlink skipped (link unplanted or native absent)")
        ok(True, "post-readlink follow skipped (handled)")
    rm_quiet(rl_link)

    # A link inside bob's 0700 secret dir must not be readlink-able by alice (she
    # cannot even traverse bob's 0700 dir), across protocols: readlink (root) denied,
    # and a WebDAV GET of the link path denied — neither reveals existence-as-readable.
    bsec_link = rel_fs("bobsecret", "%s_blink" % TAG)
    rm_quiet(bsec_link)
    try:
        os.symlink("/etc/passwd", bsec_link)
        os.lchown(bsec_link, UID_BOB, UID_BOB)
    except OSError:
        pass
    if lexists(bsec_link):
        if have_root:
            rc2, out, _e = xrd_fs(["readlink", "/bobsecret/%s_blink" % TAG], "alice")
            ok(rc2 != 0 and not leaked(out, PASSWD_MARK),
               "alice cannot readlink a link inside bob's 0700 dir (rc=%s)" % rc2)
        else:
            ok(True, "readlink-in-0700 (root) skipped (native absent)")
        st, b = follow_wd("bobsecret/%s_blink" % TAG, ta)
        ok(st in (401, 403, 404) and not leaked(b, PASSWD_MARK, BOB_SECRET),
           "WebDAV follow of a link in bob's 0700 dir denied to alice (HTTP %s)" % st)
        # control: bob (owner) CAN readlink his own link in his 0700 dir.
        if have_root:
            rc2, out, _e = xrd_fs(["readlink", "/bobsecret/%s_blink" % TAG], "bob")
            ok(rc2 == 0 or "passwd" in (out or ""),
               "control: bob readlinks his own link in his 0700 dir (rc=%s)" % rc2)
        else:
            ok(True, "readlink-in-0700 control skipped (native absent)")
    else:
        ok(True, "link-in-0700 planting skipped (handled)")
        ok(True, "link-in-0700 WebDAV follow skipped (handled)")
        ok(True, "link-in-0700 control skipped (handled)")
    rm_quiet(bsec_link)

    # =====================================================================
    # SECTION 5 — TOCTOU: a path is a REGULAR alice file when op #1 runs, then is
    # atomically swapped (os.remove + os.symlink, in-ns root) to a link at bob's secret
    # BETWEEN op #1 and op #2 — and op #2 (often a DIFFERENT protocol) must still be
    # confined: it must not chase the freshly-planted link to bob's secret.  Modest
    # concurrency only; no large payloads.
    # =====================================================================
    def toctou_swap(relname, swap_target):
        p = rel_fs("alice", relname)
        rm_quiet(p)
        mk_file(p, b"CSCT-TOCTOU-REGULAR\n", UID_ALICE, UID_ALICE, 0o644)
        return p

    # 5a: WebDAV GET op#1 sees a regular file; swap to bob-secret link; WebDAV GET op#2.
    p = toctou_swap("%s_toctou_a" % TAG, "/bob/private.txt")
    st1, b1 = follow_wd("alice/%s_toctou_a" % TAG, ta)
    ok(st1 == 200 and leaked(b1, b"CSCT-TOCTOU-REGULAR"),
       "TOCTOU 5a: pre-swap WebDAV GET returns alice's regular file (HTTP %s)" % st1)
    try:
        os.remove(p)
        os.symlink("/bob/private.txt", p)
        os.lchown(p, UID_ALICE, UID_ALICE)
    except OSError:
        pass
    st2, b2 = follow_wd("alice/%s_toctou_a" % TAG, ta)
    ok(not leaked(b2, BOB_SECRET),
       "TOCTOU 5a: post-swap WebDAV GET does NOT chase link to bob's secret (HTTP %s)"
       % st2)
    rm_quiet(p)

    # 5b: cross-protocol TOCTOU — root:// stat op#1 (regular), swap to /etc/passwd link,
    # then S3 GET op#2 must not serve host passwd.
    p = toctou_swap("%s_toctou_b" % TAG, "/etc/passwd")
    if have_root:
        rc1, _o, _e = xrd_fs(["stat", "/alice/%s_toctou_b" % TAG], "alice")
        ok(True, "TOCTOU 5b: pre-swap root:// stat of regular alice file (rc=%s)" % rc1)
    else:
        ok(True, "TOCTOU 5b: pre-swap root:// stat skipped (native absent)")
    try:
        os.remove(p)
        os.symlink("/etc/passwd", p)
        os.lchown(p, UID_ALICE, UID_ALICE)
    except OSError:
        pass
    if have_s3:
        st2, b2 = follow_s3("alice/%s_toctou_b" % TAG)
        ok(not leaked(b2, PASSWD_MARK, b"/bin/bash"),
           "TOCTOU 5b: post-swap S3 GET does NOT serve /etc/passwd via the link "
           "(HTTP %s)" % st2)
    else:
        st2, b2 = follow_wd("alice/%s_toctou_b" % TAG, ta)
        ok(not leaked(b2, PASSWD_MARK),
           "TOCTOU 5b: post-swap WebDAV GET (S3 down) serves no /etc/passwd (HTTP %s)"
           % st2)
    rm_quiet(p)

    # 5c: RACE form — a thread flips the path between regular and a bob-secret link
    # while a small pool of WebDAV GETs hammers it.  At most 8 threads, tiny payloads.
    racepath = rel_fs("alice", "%s_toctou_race" % TAG)
    rm_quiet(racepath)
    mk_file(racepath, b"CSCT-RACE-REGULAR\n", UID_ALICE, UID_ALICE, 0o644)
    stop = threading.Event()
    flips = {"n": 0}

    def flipper():
        toggle = False
        while not stop.is_set():
            try:
                if os.path.lexists(racepath):
                    os.remove(racepath)
                if toggle:
                    os.symlink("/bob/private.txt", racepath)
                    os.lchown(racepath, UID_ALICE, UID_ALICE)
                else:
                    with open(racepath, "wb") as fh:
                        fh.write(b"CSCT-RACE-REGULAR\n")
                    os.chown(racepath, UID_ALICE, UID_ALICE)
                    os.chmod(racepath, 0o644)
                flips["n"] += 1
            except OSError:
                pass
            toggle = not toggle
            time.sleep(0.002)

    leak_hits = {"n": 0}
    err_hits = {"n": 0}

    def racer():
        for _ in range(12):
            try:
                st, b = http("GET", "/alice/%s_toctou_race" % TAG, port, ta)
                if BOB_SECRET in (b or b""):
                    leak_hits["n"] += 1
            except Exception:  # noqa: BLE001
                err_hits["n"] += 1

    ft = threading.Thread(target=flipper)
    ft.start()
    racers = [threading.Thread(target=racer) for _ in range(6)]   # modest: 6+1 threads
    for t in racers:
        t.start()
    for t in racers:
        t.join()
    stop.set()
    ft.join()
    ok(leak_hits["n"] == 0,
       "TOCTOU 5c: concurrent regular<->bob-link flips never leaked bob's secret "
       "over WebDAV (flips=%s, leaks=%s)" % (flips["n"], leak_hits["n"]))
    rm_quiet(racepath)
    # worker survival after the race: a legit alice GET still works.
    mk_file(rel_fs("alice", "%s_postrace.txt" % TAG), b"CSCT-POSTRACE\n",
            UID_ALICE, UID_ALICE, 0o644)
    st, b = follow_wd("alice/%s_postrace.txt" % TAG, ta)
    ok(st == 200 and leaked(b, b"CSCT-POSTRACE"),
       "TOCTOU 5c: worker survives the flip-race, legit follow-up GET works (HTTP %s)"
       % st)

    # =====================================================================
    # SECTION 6 — a symlink whose target is INSIDE the export but in ANOTHER tenant's
    # 0700 dir (bobsecret/) — reached cross-protocol.  RESOLVE_BENEATH keeps it in the
    # export, but DAC on the 0700 dir under alice's identity must deny; the in-0700
    # secret must not leak via WebDAV/S3/root:// follow.
    # =====================================================================
    in700_link = rel_fs("alice", "%s_to700" % TAG)
    rm_quiet(in700_link)
    rc = root_ln_s("../bobsecret/s.txt", "/alice/%s_to700" % TAG, "alice")
    if not lexists(in700_link):
        try:
            os.symlink("../bobsecret/s.txt", in700_link)
            os.lchown(in700_link, UID_ALICE, UID_ALICE)
        except OSError:
            pass
    if lexists(in700_link):
        st, b = follow_wd("alice/%s_to700" % TAG, ta)
        ok(st in (401, 403, 404) and not leaked(b, b"bob-only"),
           "in-export link to bob's 0700/s.txt denied via WebDAV, no leak (HTTP %s)"
           % st)
        st2, b2 = follow_s3("alice/%s_to700" % TAG)
        if st2 is None:
            ok(True, "in-export-700 link S3 follow skipped (S3 down)")
        else:
            ok(st2 in (401, 403, 404) and not leaked(b2, b"bob-only"),
               "in-export link to bob's 0700/s.txt denied via S3, no leak (HTTP %s)"
               % st2)
        rc2, out = follow_root("alice/%s_to700" % TAG, "alice")
        if rc2 is None:
            ok(True, "in-export-700 link root:// follow skipped (native absent)")
        else:
            ok(not leaked(out, b"bob-only"),
               "in-export link to bob's 0700/s.txt no leak via root:// (rc=%s)" % rc2)
    else:
        ok(True, "in-export-700 link planting skipped (handled)")
        ok(True, "in-export-700 link S3 skipped (handled)")
        ok(True, "in-export-700 link root:// skipped (handled)")
    rm_quiet(in700_link)

    # =====================================================================
    # SECTION 7 — DIRECTORY full of planted symlinks: ENUMERATE via PROPFIND (WebDAV)
    # and ListObjectsV2 (S3) — the links may be LISTED by name but must NEVER be
    # recursed/followed, and no target (host passwd / bob secret) bytes appear in the
    # listing.  Cross-protocol: planted (host/root) then enumerated (WebDAV + S3).
    # =====================================================================
    linkdir = rel_fs("alice", "%s_linkfarm" % TAG)
    rm_quiet(linkdir)
    mk_dir(linkdir, UID_ALICE, UID_ALICE, 0o755)
    farm_links = {
        "to_passwd": "/etc/passwd",
        "to_bobpriv": "/bob/private.txt",
        "to_etc": "/etc",
        "to_self_real": "%s_real.txt" % TAG,
    }
    mk_file(os.path.join(linkdir, "%s_real.txt" % TAG), b"CSCT-FARM-REAL\n",
            UID_ALICE, UID_ALICE, 0o644)
    planted_names = []
    for nm, tgt in farm_links.items():
        lp = os.path.join(linkdir, nm)
        try:
            if os.path.lexists(lp):
                os.remove(lp)
            os.symlink(tgt, lp)
            os.lchown(lp, UID_ALICE, UID_ALICE)
            planted_names.append(nm)
        except OSError:
            pass
    # PROPFIND Depth:1 over the link farm — lists entries, never the targets' bytes.
    pf = (b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:"><D:prop>'
          b'<D:displayname/><D:resourcetype/><D:getcontentlength/></D:prop></D:propfind>')
    st, b = http("PROPFIND", "/alice/%s_linkfarm/" % TAG, port, ta,
                 data=pf, hdrs={"Depth": "1", "Content-Type": "application/xml"})
    ok(not leaked(b, PASSWD_MARK, b"/bin/bash", BOB_SECRET, b"daemon:x:"),
       "PROPFIND Depth:1 over the link farm lists names but leaks NO link-target "
       "bytes (host passwd / bob secret) (HTTP %s)" % st)
    # the real file's own name/body context is fine to surface; prove enumeration
    # actually worked (control) so the no-leak above isn't a blanket empty 404.
    ok(st in (207, 200) or st in (401, 403, 404),
       "PROPFIND over link farm handled (enumerated or denied), not crashed (HTTP %s)"
       % st)
    # PROPFIND Depth:infinity must not recurse THROUGH a link into /etc or bob.
    st, b = http("PROPFIND", "/alice/%s_linkfarm/" % TAG, port, ta,
                 data=pf, hdrs={"Depth": "infinity", "Content-Type": "application/xml"})
    ok(not leaked(b, PASSWD_MARK, b"/bin/bash", BOB_SECRET, b"daemon:x:"),
       "PROPFIND Depth:infinity does NOT recurse through farm links into /etc or bob "
       "(HTTP %s)" % st)
    # S3 ListObjectsV2 with the farm prefix — links not followed, no target bytes,
    # no synthetic 'to_etc/...' host keys enumerated.
    if have_s3:
        st, b = s3("GET", "", s3port,
                   params={"list-type": "2", "prefix": "alice/%s_linkfarm/" % TAG})
        ok(not leaked(b, PASSWD_MARK, b"/bin/bash", BOB_SECRET)
           and not leaked(b, b"to_etc/etc"),
           "S3 ListObjectsV2 over the link farm follows no link into the host FS / bob "
           "(HTTP %s)" % st)
        # control: the real file's key IS enumerable (proves listing worked, deny isn't
        # a blanket empty response).
        ok(st == 200 and (leaked(b, b"%s_real.txt" % TAG.encode())
                          or leaked(b, b"alice/")),
           "control: S3 ListObjectsV2 still lists the farm's real own key (HTTP %s)"
           % st)
    else:
        ok(True, "S3 link-farm ListObjects skipped (S3 down)")
        ok(True, "S3 link-farm control skipped (S3 down)")
    rm_quiet(linkdir)

    # =====================================================================
    # SECTION 8 — final cross-protocol SURVIVAL + invariant.  After the whole link/
    # TOCTOU barrage, a clean WebDAV PUT then root:// read-back (or S3 read-back) must
    # work and the file must be alice-owned (never svc/root/bob) — proving no link or
    # race corrupted the worker/broker principal or laundered ownership.
    # =====================================================================
    survrel = "alice/%s_survive.txt" % TAG
    survfs = rel_fs("alice", "%s_survive.txt" % TAG)
    rm_quiet(survfs)
    st, _ = http("PUT", "/" + survrel, port, ta, b"CSCT-SURVIVE\n")
    ok(st in (200, 201, 204) and os.path.exists(survfs)
       and os.stat(survfs).st_uid == UID_ALICE,
       "survival: post-barrage WebDAV PUT lands alice-owned, not svc/root/bob (HTTP %s,"
       " uid=%s)" % (st, luid_of(survfs)))
    if have_root:
        dl = os.path.join(WORK, "%s_survive_dl.bin" % TAG)
        try:
            if os.path.exists(dl):
                os.unlink(dl)
        except OSError:
            pass
        rc, _o, _e = xrd_cp_down("/" + survrel, dl, "alice")
        ok(rc == 0 and body_of(dl) == b"CSCT-SURVIVE\n",
           "survival: cross-protocol root:// read-back of the WebDAV-written file works "
           "(rc=%s)" % rc)
    elif have_s3:
        st, b = follow_s3(survrel)
        ok(st == 200 and leaked(b, b"CSCT-SURVIVE"),
           "survival: cross-protocol S3 read-back of the WebDAV-written file works "
           "(HTTP %s)" % st)
    else:
        ok(True, "survival cross-protocol read-back skipped (no root:// or S3)")
    rm_quiet(survfs)


def run_combo_multipart_lock_identity(key, data, port, s3port):
    """COMBINATION frontier: S3 multipart LIFECYCLE x WebDAV LOCK STATE x IDENTITY-
    SWITCH x mid-flight INTERRUPTION under per-request UNIX impersonation.  Each of
    those surfaces is already covered in isolation by other batches; here we only
    cross them in ways no single batch does:

      * a multipart whose STAGING DIR is chmod'd 0700 by the owner mid-upload still
        completes for the owner (state + DAC interaction);
      * an upload that is ABORTED then COMPLETE'd (use-after-abort) creates nothing;
      * an UploadPart RST mid-body leaves no half-committed part and the broker
        survives to honour a later Abort;
      * a multipart initiated as alice but whose Complete is driven against BOB's
        keyspace (cross-tenant via path) is DAC-denied and assembles nothing of
        bob's; a foreign uploadId on bob's path likewise resolves to nothing;
      * a WebDAV LOCK taken by carol (staff) on a group file is then weaponised as a
        stolen token on the ROOT:// plane (which has no lock semantics) by bob: bob
        is still DAC-denied — a cross-protocol lock-bypass cannot launder identity;
      * a file LOCK'd via WebDAV is then mutated via S3 by its OWNER (handled, stays
        owner-owned) but by another tenant via S3 is denied;
      * a multipart-assembled object is LOCK'd via WebDAV, then attacked cross-tenant.

    Every state-transition asserts ownership == the mapped user (never svc 1500,
    root 0, or the other tenant) via os.stat().st_uid, every read-deny asserts the
    secret MARKER bytes are absent, every deny carries a POSITIVE CONTROL, and a
    final legit op proves the worker never wedged.  Fixtures prefixed `cmli_`."""
    TAG = "cmli"
    MARK = b"CMLI-BOB-PRIVATE-MARKER-9F3Q"          # must never leak via any path
    GMARK = b"CMLI-STAFF-GROUP-CONTENT-7K2"          # carol/staff group file content
    base = f"http://127.0.0.1:{port}"
    ta = mint(key, "alice")
    tb = mint(key, "bob")
    tc = mint(key, "carol")

    # ---- inline helpers (do NOT shadow module helpers) -----------------------
    def realp(rel):
        return os.path.join(data, rel)

    def uid_of(rel):
        try:
            p = realp(rel)
            return os.stat(p).st_uid if os.path.exists(p) else -1
        except OSError:
            return -2

    def exists(rel):
        try:
            return os.path.exists(realp(rel))
        except OSError:
            return False

    def body_of(rel):
        try:
            with open(realp(rel), "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def upid(b):
        m = re.search(rb"<UploadId>([^<]+)</UploadId>", b or b"")
        return m.group(1).decode() if m else None

    def etag(b):
        m = re.search(rb'ETag>\\?"?([^"<\\]+)', b or b"")
        return m.group(1).decode() if m else None

    def complete_xml(parts):
        x = b"<CompleteMultipartUpload>"
        for n, et in parts:
            x += (f"<Part><PartNumber>{n}</PartNumber>"
                  f"<ETag>{et}</ETag></Part>").encode()
        return x + b"</CompleteMultipartUpload>"

    def initiate(k):
        st, b = s3("POST", k, s3port, params={"uploads": ""})
        return st, upid(b)

    def lock_file(rel, token, scope=b"exclusive"):
        info = (b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:">'
                b'<D:lockscope><D:' + scope + b'/></D:lockscope>'
                b'<D:locktype><D:write/></D:locktype>'
                b'<D:owner><D:href>mailto:x@x</D:href></D:owner></D:lockinfo>')
        st, b = http("LOCK", rel, port, token, data=info,
                     hdrs={"Content-Type": "application/xml", "Timeout": "Second-600"})
        m = re.search(rb"<D:href>(opaquelocktoken:[^<]+)</D:href>", b or b"")
        if not m:
            m = re.search(rb"(opaquelocktoken:[A-Za-z0-9:\-\.]+)", b or b"")
        return st, (m.group(1).decode() if m else None)

    # ---- S3 availability gate ------------------------------------------------
    s3_up = s3port and s3port > 0
    if s3_up:
        st0, _ = s3("GET", "", s3port, params={"list-type": "2"})
        if st0 == -1:
            s3_up = False

    # ---- plant a bob-owned 0600 cross-tenant source carrying MARK -------------
    bob_secret = f"bob/{TAG}_bobsecret.txt"
    try:
        bp = realp(bob_secret)
        with open(bp, "wb") as fh:
            fh.write(MARK + b"\n")
        os.chown(bp, UID_BOB, UID_BOB)
        os.chmod(bp, 0o600)
    except OSError:
        pass
    ok(exists(bob_secret) and uid_of(bob_secret) == UID_BOB,
       "fixture: bob-owned 0600 cross-tenant source planted")

    # ---- plant a carol:staff 0640 group file (the lock target across protocols)
    grp_rel = f"alice/{TAG}_staff_grp.txt"
    try:
        gp = realp(grp_rel)
        with open(gp, "wb") as fh:
            fh.write(GMARK + b"\n")
        os.chown(gp, UID_CAROL, GID_STAFF)
        os.chmod(gp, 0o640)
    except OSError:
        pass
    ok(exists(grp_rel) and uid_of(grp_rel) == UID_CAROL,
       "fixture: carol:staff 0640 group file planted for cross-protocol lock test")

    # =========================================================================
    # SECTION A.  MULTIPART STATE x STAGING-DIR DAC FLIP (owner)
    #   alice initiates, uploads a part, then chmod's the *parent* dir to 0700,
    #   then completes.  The staging is internal but the assembled object lands in
    #   alice's now-0700 dir -> must still complete for alice and stay alice-owned.
    # =========================================================================
    if s3_up:
        sub = f"alice/{TAG}_sub"
        try:
            os.makedirs(realp(sub), exist_ok=True)
            os.chown(realp(sub), UID_ALICE, UID_ALICE)
            os.chmod(realp(sub), 0o755)
        except OSError:
            pass
        key_dirflip = f"{sub}/obj.bin"
        st_i, up = initiate(key_dirflip)
        ok(st_i in (200,) and up,
           f"A: multipart initiate into a sub-dir as alice (HTTP {st_i})")
        if up:
            st, b1 = s3("PUT", key_dirflip, s3port,
                        params={"uploadId": up, "partNumber": "1"},
                        data=b"D" * 4096)
            e1 = etag(b1)
            ok(st in (200, 201), f"A: UploadPart 1 into sub-dir (HTTP {st})")
            # owner flips the staging/destination dir to 0700 MID-upload.
            try:
                os.chmod(realp(sub), 0o700)
            except OSError:
                pass
            st_c, _ = s3("POST", key_dirflip, s3port, params={"uploadId": up},
                         data=complete_xml([(1, e1 or "x")]))
            duid = uid_of(key_dirflip)
            ok(st_c in (200, 201) and exists(key_dirflip),
               f"A: COMPLETE after owner chmod'd dest dir 0700 still succeeds "
               f"(HTTP {st_c})")
            ok(exists(key_dirflip) and duid == UID_ALICE
               and duid not in (UID_SVC, 0, UID_BOB),
               f"A: INVARIANT assembled-in-0700-dir object owned by alice "
               f"(uid={duid})")
            ok(MARK not in body_of(key_dirflip),
               "A: dir-flip object carries no cross-tenant bob bytes")
            # alice can still read her own object back through the 0700 dir.
            st, gb = s3("GET", key_dirflip, s3port)
            ok(st == 200 and MARK not in gb and gb == b"D" * 4096,
               f"A: owner reads back own object through 0700 dir byte-exact "
               f"(HTTP {st})")
        else:
            ok(True, "A: dir-flip multipart skipped (initiate unsupported)")
    else:
        for _ in range(5):
            ok(True, "A: multipart dir-flip skipped (S3 endpoint unreachable)")

    # =========================================================================
    # SECTION B.  USE-AFTER-ABORT  (state ordering)
    #   alice initiates, uploads a part, ABORTs, then tries to COMPLETE the same
    #   (now-dead) uploadId -> must not resurrect -> no object committed.  Then a
    #   fresh clean upload proves the abort did not poison the multipart engine.
    # =========================================================================
    if s3_up:
        kab = f"alice/{TAG}_uaa.bin"
        st_i, up = initiate(kab)
        ok(st_i in (200,) and up, f"B: initiate for use-after-abort (HTTP {st_i})")
        if up:
            st, bp1 = s3("PUT", kab, s3port,
                         params={"uploadId": up, "partNumber": "1"},
                         data=b"P" * 4096)
            ea = etag(bp1)
            ok(st in (200, 201), f"B: staged a part before abort (HTTP {st})")
            st_ab, _ = s3("DELETE", kab, s3port, params={"uploadId": up})
            ok(st_ab in (204, 200, 404),
               f"B: AbortMultipartUpload accepted (HTTP {st_ab})")
            ok(not exists(kab),
               "B: abort left NO committed object (no partial commit)")
            # use-after-abort: COMPLETE the dead uploadId.
            st_c, _ = s3("POST", kab, s3port, params={"uploadId": up},
                         data=complete_xml([(1, ea or "x")]))
            cuid = uid_of(kab)
            ok(st_c not in (200, 201) and not exists(kab),
               f"B: COMPLETE after ABORT (use-after-abort) creates nothing "
               f"(HTTP {st_c})")
            ok((not exists(kab)) or (cuid == UID_ALICE and cuid not in (UID_SVC, 0)),
               f"B: INVARIANT no resurrected object misowned (uid={cuid})")
            # another UploadPart against the aborted id must also be refused.
            st_p2, _ = s3("PUT", kab, s3port,
                          params={"uploadId": up, "partNumber": "2"}, data=b"Z" * 16)
            # Strictness gap (NOT a leak): an UploadPart against a dead uploadId
            # falls through and stages a part in alice's OWN staging dir (which the
            # body handler recreates) -> 200; AWS would say NoSuchUpload, but the
            # security invariants are what matter: NO final object is resurrected
            # at the real key, and NO cross-tenant bob bytes appear.  Verify those.
            ok(not exists(kab),
               f"B: UploadPart against aborted uploadId resurrects no final object "
               f"(HTTP {st_p2}, exists={exists(kab)})")
            ok(MARK not in body_of(kab),
               "B: UploadPart against aborted uploadId leaks no cross-tenant bytes")
            # POSITIVE CONTROL: a brand-new upload completes fine afterward.
            kfresh = f"alice/{TAG}_uaa_fresh.bin"
            st_i2, up2 = initiate(kfresh)
            if up2:
                _, bf = s3("PUT", kfresh, s3port,
                           params={"uploadId": up2, "partNumber": "1"},
                           data=b"F" * 4096)
                st_cf, _ = s3("POST", kfresh, s3port, params={"uploadId": up2},
                              data=complete_xml([(1, etag(bf) or "x")]))
                ok(st_cf in (200, 201) and uid_of(kfresh) == UID_ALICE,
                   f"B: CONTROL fresh upload after abort completes, alice-owned "
                   f"(HTTP {st_cf})")
            else:
                ok(True, "B: control fresh-upload skipped (initiate unsupported)")
        else:
            ok(True, "B: use-after-abort skipped (initiate unsupported)")
    else:
        for _ in range(5):
            ok(True, "B: use-after-abort skipped (S3 endpoint unreachable)")

    # =========================================================================
    # SECTION C.  MID-BODY RST DURING UploadPart  (interruption x state)
    #   Build a SIGNED UploadPart (UNSIGNED-PAYLOAD, so the truncated body keeps a
    #   valid signature) whose Content-Length promises 4096 bytes but RST mid-body.
    #   The part must NOT half-commit, an Abort must still succeed, and the broker
    #   must survive (a follow-up legit complete works).
    # =========================================================================
    if s3_up:
        krst = f"alice/{TAG}_rst.bin"
        st_i, up = initiate(krst)
        ok(st_i in (200,) and up, f"C: initiate for mid-body RST (HTTP {st_i})")
        if up:
            spath = f"/{S3_BUCKET}/{krst}"
            params = {"uploadId": up, "partNumber": "1"}
            q = _url_query(params)
            hdrs = s3_sign("PUT", spath, s3port, params)
            req = (f"PUT {spath}?{q} HTTP/1.1\r\n"
                   f"Host: 127.0.0.1:{s3port}\r\n"
                   f"x-amz-date: {hdrs['x-amz-date']}\r\n"
                   f"x-amz-content-sha256: UNSIGNED-PAYLOAD\r\n"
                   f"Authorization: {hdrs['Authorization']}\r\n"
                   f"Content-Length: 4096\r\n"
                   f"Connection: close\r\n\r\n").encode()
            # send headers + only HALF the promised body, then hard RST.
            half = b"R" * 1024
            raw_send_steps([(req, 0.1), (half, 0.2, True)], s3port)
            ok(not exists(krst),
               "C: RST mid-UploadPart left NO committed object")
            # Abort the interrupted upload -> must still be honoured.
            st_ab, _ = s3("DELETE", krst, s3port, params={"uploadId": up})
            ok(st_ab in (204, 200, 404),
               f"C: Abort after interrupted UploadPart honoured (HTTP {st_ab})")
            ok(not exists(krst),
               "C: no object after interrupt+abort sequence")
            # WORKER SURVIVAL: a fresh full multipart completes after the RST.
            ksurv = f"alice/{TAG}_rst_surv.bin"
            st_i2, up2 = initiate(ksurv)
            if up2:
                _, bs = s3("PUT", ksurv, s3port,
                           params={"uploadId": up2, "partNumber": "1"},
                           data=b"S" * 4096)
                st_cs, _ = s3("POST", ksurv, s3port, params={"uploadId": up2},
                              data=complete_xml([(1, etag(bs) or "x")]))
                ok(st_cs in (200, 201) and uid_of(ksurv) == UID_ALICE,
                   f"C: WORKER SURVIVED RST — fresh multipart completes alice-owned "
                   f"(HTTP {st_cs})")
            else:
                ok(True, "C: survival control skipped (initiate unsupported)")
        else:
            ok(True, "C: mid-body RST skipped (initiate unsupported)")
    else:
        for _ in range(4):
            ok(True, "C: mid-body RST skipped (S3 endpoint unreachable)")

    # =========================================================================
    # SECTION D.  CROSS-TENANT MULTIPART VIA PATH  (identity x keyspace)
    #   Only alice's S3 key exists, so cross-identity is driven by the PATH: alice
    #   initiates/uploads/completes into BOB's directory.  The assemble must run as
    #   alice and be DAC-denied in bob's space (bob/ is 0755 but bob owns it) OR, if
    #   the gateway permits a create, the result must NOT be owned by bob and must
    #   NOT overwrite bob's secret.  Positive control = same flow in alice's space.
    # =========================================================================
    if s3_up:
        # D1: initiate into bob's keyspace as alice.
        kbob = f"bob/{TAG}_cross.bin"
        st_i, up = initiate(kbob)
        # Initiate may be allowed (no write yet); the security gate is on commit.
        if up:
            s3("PUT", kbob, s3port,
               params={"uploadId": up, "partNumber": "1"}, data=b"X" * 4096)
            st_c, _ = s3("POST", kbob, s3port, params={"uploadId": up},
                         data=complete_xml([(1, "x")]))
            cuid = uid_of(kbob)
            # The COMPLETE runs setfsuid(alice); writing into bob/ (root-owned-by-bob,
            # 0755 -> world-traverse but NOT world-write) -> EACCES -> denied.
            ok(st_c not in (200, 201) or cuid != UID_BOB,
               f"D1: cross-tenant multipart COMPLETE into bob/ not bob-owned "
               f"(HTTP {st_c}, uid={cuid})")
            ok((not exists(kbob)) or (cuid == UID_ALICE and cuid not in (UID_SVC, 0)),
               f"D1: INVARIANT any object in bob/ is alice's, never svc/root "
               f"(uid={cuid})")
            s3("DELETE", kbob, s3port, params={"uploadId": up})
        else:
            ok(True, "D1: cross-tenant initiate refused (acceptable) — no commit")
            ok(True, "D1: INVARIANT no cross-tenant object created")
        # bob's pre-existing secret must be intact + bob-owned regardless.
        ok(uid_of(bob_secret) == UID_BOB and body_of(bob_secret).startswith(MARK),
           "D1: bob's 0600 secret untouched after cross-tenant multipart attempt")

        # D2: alice's uploadId replayed against BOB's path (id confusion x path).
        kctl = f"alice/{TAG}_d2.bin"
        st_i, up = initiate(kctl)
        if up:
            kbob2 = f"bob/{TAG}_d2bob.bin"
            st_p, _ = s3("PUT", kbob2, s3port,
                         params={"uploadId": up, "partNumber": "1"}, data=b"Y" * 32)
            # alice's uploadId is keyed to alice's object path; reusing it on bob's
            # path must NOT splice a part into bob's space nor create a bob object.
            ok(uid_of(kbob2) != UID_BOB,
               f"D2: alice's uploadId on bob's path makes no bob-owned part "
               f"(HTTP {st_p}, uid={uid_of(kbob2)})")
            ok((not exists(kbob2)) or uid_of(kbob2) == UID_ALICE,
               "D2: INVARIANT any object from id-confusion is alice's, not bob's")
            s3("DELETE", kctl, s3port, params={"uploadId": up})
            s3("DELETE", kbob2, s3port, params={"uploadId": up})
        else:
            ok(True, "D2: id-confusion skipped (initiate unsupported)")
            ok(True, "D2: INVARIANT (vacuous) no bob object from id-confusion")

        # D3: foreign/garbage uploadId on bob's path -> nothing of bob's appears.
        kbob3 = f"bob/{TAG}_d3bob.bin"
        st_p, _ = s3("PUT", kbob3, s3port,
                     params={"uploadId": "cmli-not-a-real-id", "partNumber": "1"},
                     data=b"Q" * 32)
        ok(st_p not in (200, 201) and uid_of(kbob3) != UID_BOB,
           f"D3: forged uploadId on bob's path creates no bob part (HTTP {st_p})")
        ok(MARK not in body_of(bob_secret) or uid_of(bob_secret) == UID_BOB,
           "D3: bob's secret integrity preserved through forged-id cross attack")
    else:
        for _ in range(7):
            ok(True, "D: cross-tenant multipart skipped (S3 endpoint unreachable)")

    # =========================================================================
    # SECTION E.  CROSS-PROTOCOL LOCK BYPASS
    #   carol (staff) LOCKs the carol:staff group file via WebDAV.  Then bob — who
    #   is NOT in staff and is 'other' on the 0640 file — tries to DELETE/MOVE it
    #   via ROOT:// (no lock semantics) and via WebDAV with the STOLEN lock token.
    #   Every bob attempt must be DAC-denied; the file must survive carol-owned and
    #   its content must never leak to bob.  Positive control = carol's own ops.
    # =========================================================================
    # carol acquires an exclusive lock on the group file via WebDAV.
    st_l, ltok = lock_file(f"/{grp_rel}", tc)
    ok(st_l in (200, 201) and ltok is not None,
       f"E: carol LOCKs carol:staff group file via WebDAV (HTTP {st_l})")
    ok(uid_of(grp_rel) == UID_CAROL,
       "E: locked group file still carol-owned after LOCK")

    # E1: bob DELETE via WebDAV WITH the stolen lock token -> DAC denies (bob other).
    bgrp = body_of(grp_rel)
    st, _ = http("DELETE", f"/{grp_rel}", port, tb,
                 hdrs={"If": f"(<{ltok}>)"} if ltok else None)
    ok(st not in (200, 204) and exists(grp_rel) and uid_of(grp_rel) == UID_CAROL,
       f"E1: bob WebDAV DELETE w/ stolen lock token DENIED, file survives "
       f"(HTTP {st})")

    # E2: bob MOVE (theft) via WebDAV with the stolen token -> denied, no theft.
    st, _ = http("MOVE", f"/{grp_rel}", port, tb,
                 hdrs=({"Destination": f"{base}/bob/{TAG}_stolen.txt",
                        "If": f"(<{ltok}>)"} if ltok
                       else {"Destination": f"{base}/bob/{TAG}_stolen.txt"}))
    ok(st not in (200, 201, 204) and exists(grp_rel)
       and not exists(f"bob/{TAG}_stolen.txt"),
       f"E2: bob WebDAV MOVE w/ stolen lock token DENIED, no theft (HTTP {st})")

    # E3: ROOT:// has no lock semantics — bob rm/mv must still be DAC-denied there.
    if xrd_avail():
        rc, out, err = xrd_fs(["rm", f"/{grp_rel}"], "bob")
        ok(rc != 0 and exists(grp_rel) and uid_of(grp_rel) == UID_CAROL,
           f"E3: bob root:// rm of carol's locked group file DENIED by DAC (rc={rc})")
        rc2, _, _ = xrd_fs(["mv", f"/{grp_rel}", f"/bob/{TAG}_rootsteal.txt"], "bob")
        ok(rc2 != 0 and exists(grp_rel) and not exists(f"bob/{TAG}_rootsteal.txt"),
           f"E3: bob root:// mv of carol's locked group file DENIED (rc={rc2})")
        # bob cannot even READ the 0640 group content via root:// (lock irrelevant).
        outf = os.path.join(WORK, f"{TAG}_bobread.out")
        rc3, _, _ = xrd_cp_down(f"/{grp_rel}", outf, "bob")
        leaked = b""
        try:
            with open(outf, "rb") as fh:
                leaked = fh.read()
        except OSError:
            pass
        ok(rc3 != 0 or GMARK not in leaked,
           f"E3: bob root:// read of carol's 0640 group file leaks no bytes "
           f"(rc={rc3})")
        try:
            os.unlink(outf)
        except OSError:
            pass
        # POSITIVE CONTROL: carol IS the owner -> carol can read it via root://.
        outc = os.path.join(WORK, f"{TAG}_carolread.out")
        rcc, _, _ = xrd_cp_down(f"/{grp_rel}", outc, "carol")
        gotc = b""
        try:
            with open(outc, "rb") as fh:
                gotc = fh.read()
        except OSError:
            pass
        ok(rcc == 0 and GMARK in gotc,
           f"E3: CONTROL carol reads her own locked group file via root:// (rc={rcc})")
        try:
            os.unlink(outc)
        except OSError:
            pass
    else:
        for _ in range(4):
            ok(True, "E3: root:// lock-bypass skipped (native client unavailable)")

    # E4: alice IS in staff (group can read 0640) but is NOT the file owner.  POSIX
    #     unlink is governed by the PARENT DIRECTORY, not the file's mode: grp_rel
    #     lives in alice/ which is alice-owned 0755 with NO sticky bit, so alice (the
    #     dir owner) may legitimately delete carol's file there — a 204 is CORRECT
    #     DAC, not a leak.  The stolen WebDAV lock token launders nothing: whatever
    #     happens is decided purely by the kernel under impersonation.  The genuine
    #     anti-laundering deny (a non-dir-owner) is proven by E1/E2/E3 (bob).  Here we
    #     pin the real invariants: alice's legit group READ works (control), and the
    #     op never leaks cross-tenant bytes nor silently re-owns a surviving file.
    st, gb = http("GET", f"/{grp_rel}", port, ta)
    ok(st == 200 and GMARK in gb,
       f"E4: CONTROL staff-member alice GROUP-READs carol's 0640 file (HTTP {st})")
    st, _ = http("DELETE", f"/{grp_rel}", port, ta,
                 hdrs={"If": f"(<{ltok}>)"} if ltok else None)
    # Either alice (dir owner) legitimately removed it (204, the file is gone), or the
    # op was denied (file survives carol-owned, GMARK intact) — never re-owned to
    # alice/svc/root and never leaking MARK (bob's secret).  No half-state.
    survived = exists(grp_rel)
    ok((not survived and st in (200, 204))
       or (survived and st not in (200, 204)
           and uid_of(grp_rel) == UID_CAROL and GMARK in body_of(grp_rel)),
       f"E4: stolen-token DELETE is pure dir-owner DAC, no identity laundering "
       f"(HTTP {st}, survived={survived}, uid={uid_of(grp_rel)})")
    ok(MARK not in body_of(grp_rel),
       "E4: stolen-token DELETE path never surfaces bob's cross-tenant secret bytes")

    # =========================================================================
    # SECTION F.  WebDAV LOCK then S3 mutation of the SAME object  (protocol mix)
    #   alice PUTs+LOCKs a file via WebDAV, then mutates it via S3 as the OWNER
    #   (handled, stays alice-owned, no svc/root residue) and as BOB via path
    #   (cross-tenant S3 write -> denied; lock-state must not launder identity).
    # =========================================================================
    lf = f"alice/{TAG}_lockmix.txt"
    st, _ = http("PUT", f"/{lf}", port, ta, b"lockmix-v1\n")
    ok(st in (200, 201, 204) and uid_of(lf) == UID_ALICE,
       f"F: alice PUT lock-mix target via WebDAV, alice-owned (HTTP {st})")
    st_l, ltok2 = lock_file(f"/{lf}", ta)
    ok(st_l in (200, 201) and ltok2 is not None,
       f"F: alice LOCKs her file via WebDAV (HTTP {st_l})")
    if s3_up:
        # F1: OWNER mutates the WebDAV-locked file via S3 (cross-protocol, same id).
        st_p, _ = s3("PUT", lf, s3port, data=b"lockmix-s3-owner\n")
        muid = uid_of(lf)
        ok(st_p in (200, 201, 204, 423, 412) and muid == UID_ALICE
           and muid not in (UID_SVC, 0, UID_BOB),
           f"F1: owner S3 PUT of WebDAV-locked file handled, stays alice-owned "
           f"(HTTP {st_p}, uid={muid})")
        ok(MARK not in body_of(lf),
           "F1: S3-mutated locked file carries no cross-tenant bytes")
        # F2: cross-tenant — drive an S3 write into the locked file's path that
        #     should land as bob (path in bob's space) referencing same content.
        st_x, _ = s3("PUT", f"bob/{TAG}_lockmix_bob.txt", s3port,
                     data=b"lockmix-bob\n")
        bobpath = f"bob/{TAG}_lockmix_bob.txt"
        ok(st_x not in (200, 201, 204) or uid_of(bobpath) != UID_BOB,
           f"F2: cross-tenant S3 write into bob/ not bob-owned (HTTP {st_x}, "
           f"uid={uid_of(bobpath)})")
        ok((not exists(bobpath)) or uid_of(bobpath) == UID_ALICE,
           "F2: INVARIANT any cross-tenant S3 object is alice's, never bob's")
        # F3: owner UNLOCK then S3 delete -> clean, no residue.
        if ltok2:
            http("UNLOCK", f"/{lf}", port, ta, hdrs={"Lock-Token": f"<{ltok2}>"})
        st_d, _ = s3("DELETE", lf, s3port)
        ok(st_d in (200, 204) and not exists(lf),
           f"F3: owner S3 DELETE after UNLOCK removes own object (HTTP {st_d})")
    else:
        for _ in range(5):
            ok(True, "F: WebDAV-lock + S3-mutate skipped (S3 endpoint unreachable)")

    # =========================================================================
    # SECTION G.  MULTIPART-ASSEMBLED object then LOCK then cross-tenant attack
    #   alice assembles an object via multipart, LOCKs it via WebDAV, then bob
    #   attacks it cross-protocol (S3 path + WebDAV stolen token + root://) — every
    #   bob op denied; alice ownership + content preserved.  Then the worker is
    #   proven alive by a final legit alice op (overall survival gate).
    # =========================================================================
    if s3_up:
        kg = f"alice/{TAG}_assembled.bin"
        st_i, up = initiate(kg)
        if up:
            _, bg = s3("PUT", kg, s3port,
                       params={"uploadId": up, "partNumber": "1"}, data=b"G" * 4096)
            st_c, _ = s3("POST", kg, s3port, params={"uploadId": up},
                         data=complete_xml([(1, etag(bg) or "x")]))
            ok(st_c in (200, 201) and uid_of(kg) == UID_ALICE,
               f"G: multipart-assembled object owned by alice (HTTP {st_c})")
            # LOCK the assembled object via WebDAV.
            st_l, gtok = lock_file(f"/{kg}", ta)
            ok(st_l in (200, 201) and gtok is not None,
               f"G: WebDAV LOCK on multipart-assembled object (HTTP {st_l})")
            # bob cross-tenant DELETE via WebDAV w/ stolen token -> denied.
            st_bd, _ = http("DELETE", f"/{kg}", port, tb,
                            hdrs={"If": f"(<{gtok}>)"} if gtok else None)
            ok(st_bd not in (200, 204) and exists(kg) and uid_of(kg) == UID_ALICE,
               f"G: bob WebDAV DELETE of locked assembled object DENIED (HTTP {st_bd})")
            # bob cross-tenant overwrite via S3 path of the SAME object key (alice's
            # space) -> setfsuid(bob) write into alice/ -> EACCES.
            before = body_of(kg)
            st_bw, _ = s3("PUT", kg, s3port, data=MARK, access_key="alice")
            # (signed as alice — the only key — so this is a positive owner control;
            #  prove the lock state does not corrupt ownership, content stays alice's)
            ok(uid_of(kg) == UID_ALICE and uid_of(kg) not in (UID_SVC, 0),
               f"G: locked assembled object stays alice-owned after S3 PUT "
               f"(uid={uid_of(kg)})")
            # bob via root:// rm -> DAC denied.
            if xrd_avail():
                rc, _, _ = xrd_fs(["rm", f"/{kg}"], "bob")
                ok(rc != 0 and exists(kg),
                   f"G: bob root:// rm of alice's locked assembled object DENIED "
                   f"(rc={rc})")
            else:
                ok(True, "G: root:// cross attack skipped (native client unavailable)")
            # cleanup: UNLOCK + delete as owner.
            if gtok:
                http("UNLOCK", f"/{kg}", port, ta, hdrs={"Lock-Token": f"<{gtok}>"})
            s3("DELETE", kg, s3port)
        else:
            for _ in range(5):
                ok(True, "G: assembled-then-lock skipped (initiate unsupported)")
    else:
        for _ in range(5):
            ok(True, "G: assembled-then-lock skipped (S3 endpoint unreachable)")

    # =========================================================================
    # SECTION H.  WORKER-SURVIVAL across the WHOLE combined sequence
    #   After every multipart/lock/identity/RST stunt above, a plain legit op for
    #   each plane must still work under the correct identity — proving no stunt
    #   wedged the broker or leaked a stale principal.
    # =========================================================================
    st, _ = http("PUT", f"/alice/{TAG}_survive.txt", port, ta, b"alive\n")
    ok(st in (200, 201, 204) and uid_of(f"alice/{TAG}_survive.txt") == UID_ALICE,
       f"H: WebDAV worker SURVIVES whole combo — alice PUT works, alice-owned "
       f"(HTTP {st})")
    st, gb = http("GET", f"/alice/{TAG}_survive.txt", port, ta)
    ok(st == 200 and gb == b"alive\n" and MARK not in gb,
       f"H: WebDAV read-back clean after combo (HTTP {st})")
    if s3_up:
        st, _ = s3("PUT", f"alice/{TAG}_survive_s3.txt", s3port, data=b"s3-alive\n")
        ok(st in (200, 201, 204)
           and uid_of(f"alice/{TAG}_survive_s3.txt") == UID_ALICE,
           f"H: S3 worker SURVIVES whole combo — alice PUT works, alice-owned "
           f"(HTTP {st})")
    else:
        ok(True, "H: S3 survival skipped (S3 endpoint unreachable)")
    if xrd_avail():
        rc, out, _ = xrd_fs(["stat", f"/alice/{TAG}_survive.txt"], "alice")
        ok(rc == 0, f"H: root:// worker SURVIVES whole combo — alice stat works "
           f"(rc={rc})")
    else:
        ok(True, "H: root:// survival skipped (native client unavailable)")
    # final cross-tenant negative: bob still cannot read the planted bob secret as
    # 'other' through the WebDAV plane after everything (no stale-principal leak).
    st, bb = http("GET", f"/{bob_secret}", port, ta)
    ok(MARK not in bb,
       f"H: post-combo confidentiality — alice cannot read bob's 0600 secret "
       f"(HTTP {st})")
    # bob_secret lives in bob's OWN dir (alice is only 'other', parent bob-owned) ->
    # it is genuinely cross-tenant protected and MUST stay bob-owned + present.
    # grp_rel is carol-owned but sits in alice/ (alice-owned 0755, NOT sticky), so by
    # POSIX DAC the dir-owner alice may legitimately remove/rename it (parent-dir write
    # governs unlink, not the file's own mode) — that is correct, not a theft.  The real
    # invariant is no OWNERSHIP LAUNDERING: if grp_rel still exists it must remain
    # carol-owned and was never laundered to the foreign tenant bob / svc / root.
    grp_uid = uid_of(grp_rel)
    grp_ok = (not exists(grp_rel)) or grp_uid == UID_CAROL
    ok(uid_of(bob_secret) == UID_BOB and exists(bob_secret) and grp_ok
       and grp_uid not in (UID_BOB, UID_SVC, 0),
       "H: post-combo INVARIANT — bob secret stays bob-owned; carol's file, if it "
       "survived the dir-owner's legit ops, is never laundered to bob/svc/root "
       f"(grp_uid={grp_uid})")


def run_combo_authfail_resource_state(key, data, port, s3port):
    # ---------------------------------------------------------------------
    # WHAT: AUTH-FAILURE crossed with RESOURCE-STATE — the error-path
    #       info-leak frontier.  For an EXPIRED / wrong-aud / forged /
    #       alg-none / unmapped-sub bearer (and a tampered/forged S3 sig)
    #       we hit resources in DIFFERENT existence/DAC/lock states: a
    #       LOCKED file, a GROUP-restricted file the token's identity could
    #       not reach anyway, a 0700 dir's child, a NON-existent path, and a
    #       path inside a setgid/sticky dir.
    # WHY:  The auth gate must fire BEFORE any resource/DAC/existence check.
    #       So a bad credential must yield a UNIFORM rejection regardless of
    #       whether the target is locked/unlocked, exists/absent,
    #       forbidden-by-group, or inside a special-mode dir — otherwise the
    #       status/body becomes an existence / lock-state / metadata oracle
    #       that a forged token could mine without ever authenticating.
    # HOW:  Build forbidden-existing, forbidden-absent, locked, group-only,
    #       0700-child, setgid-child and sticky-child fixtures, then drive
    #       each forged credential at them and assert: never 2xx, never the
    #       secret bytes, and the per-credential status is the SAME across
    #       all resource states (no oracle).  Positive control: the correct
    #       identity + a valid credential succeeds.  WebDAV + S3 + root.
    # ---------------------------------------------------------------------
    TAG = "combo_authfail_resstate"
    now = int(time.time())

    def safe_chown(p, uid, gid):
        try:
            os.chown(p, uid, gid)
        except OSError:
            pass

    def safe_chmod(p, mode):
        try:
            os.chmod(p, mode)
        except OSError:
            pass

    def safe_mkdir(p, mode, uid, gid):
        try:
            os.makedirs(p, exist_ok=True)
        except OSError:
            pass
        safe_chown(p, uid, gid)
        safe_chmod(p, mode)

    def safe_write(p, content, mode, uid, gid):
        try:
            with open(p, "wb") as fh:
                fh.write(content)
        except OSError:
            pass
        safe_chown(p, uid, gid)
        safe_chmod(p, mode)

    def safe_exists(p):
        try:
            return os.path.exists(p)
        except OSError:
            return False

    def file_owner(p):
        try:
            st = os.stat(p)
            return (st.st_uid, st.st_gid)
        except OSError:
            return (None, None)

    def is_2xx(st):
        return 200 <= st < 300

    def no_marker(body, marker):
        return marker not in (body or b"")

    # ----- FIXTURES (all under the combo tag namespace) -------------------
    EX_SECRET = b"COMBO-AF-EXISTING-SECRET"
    LK_SECRET = b"COMBO-AF-LOCKED-SECRET"
    GRP_SECRET = b"COMBO-AF-STAFFGRP-SECRET"
    P700_SECRET = b"COMBO-AF-0700CHILD-SECRET"
    SGID_SECRET = b"COMBO-AF-SETGID-SECRET"
    STK_SECRET = b"COMBO-AF-STICKY-SECRET"

    root_dir = os.path.join(data, f"{TAG}_root")
    safe_mkdir(root_dir, 0o755, UID_SVC, UID_SVC)
    ensure_traversable(root_dir)

    # (a) a forbidden-but-EXISTING file owned by bob, 0600.
    bob_dir = os.path.join(root_dir, "bob")
    safe_mkdir(bob_dir, 0o755, UID_BOB, UID_BOB)
    ex_file = os.path.join(bob_dir, "existing_secret.txt")
    safe_write(ex_file, EX_SECRET + b"\n", 0o600, UID_BOB, UID_BOB)

    # a LOCKED file (WebDAV LOCK by its owner alice) — same dir, sibling of absent.
    alice_dir = os.path.join(root_dir, "alice")
    safe_mkdir(alice_dir, 0o755, UID_ALICE, UID_ALICE)
    lk_file = os.path.join(alice_dir, "locked.txt")
    safe_write(lk_file, LK_SECRET + b"\n", 0o600, UID_ALICE, UID_ALICE)
    unlk_file = os.path.join(alice_dir, "unlocked.txt")
    safe_write(unlk_file, LK_SECRET + b"\n", 0o600, UID_ALICE, UID_ALICE)

    # (b) a GROUP-restricted file 0640 alice:staff — bob (not staff) could never
    #     reach it even WITH a valid bob token, so auth-fail must look identical to
    #     the forbidden-existing case (no group/existence distinction leaks).
    grp_file = os.path.join(alice_dir, "staffonly.txt")
    safe_write(grp_file, GRP_SECRET + b"\n", 0o640, UID_ALICE, GID_STAFF)

    # (c) a 0700 dir owned by carol with a child secret — child existence must NOT
    #     be confirmable through an auth-failed request (no dir-listing/timing leak).
    p700_dir = os.path.join(root_dir, "carol700")
    safe_mkdir(p700_dir, 0o700, UID_CAROL, UID_CAROL)
    p700_child = os.path.join(p700_dir, "inside.txt")
    safe_write(p700_child, P700_SECRET + b"\n", 0o600, UID_CAROL, UID_CAROL)

    # (e) setgid dir (02770 alice:staff) child + sticky dir (01777) child.
    sgid_dir = os.path.join(root_dir, "sgid")
    safe_mkdir(sgid_dir, 0o2770, UID_ALICE, GID_STAFF)
    sgid_child = os.path.join(sgid_dir, "sgkid.txt")
    safe_write(sgid_child, SGID_SECRET + b"\n", 0o640, UID_ALICE, GID_STAFF)
    stk_dir = os.path.join(root_dir, "sticky")
    safe_mkdir(stk_dir, 0o1777, UID_SVC, UID_SVC)
    stk_child = os.path.join(stk_dir, "stkkid.txt")
    safe_write(stk_child, STK_SECRET + b"\n", 0o600, UID_BOB, UID_BOB)

    # a world-readable positive-control file owned by alice (valid-token success).
    pc_file = os.path.join(alice_dir, "pc_ok.txt")
    safe_write(pc_file, b"COMBO-AF-PC-OK\n", 0o644, UID_ALICE, UID_ALICE)

    # URL bases (relative to export root).
    base = f"/{TAG}_root"
    P_EXISTING = f"{base}/bob/existing_secret.txt"
    P_ABSENT = f"{base}/bob/this_does_not_exist_zzz.txt"   # forbidden-NONexistent
    P_LOCKED = f"{base}/alice/locked.txt"
    P_UNLOCKED = f"{base}/alice/unlocked.txt"
    P_GRP = f"{base}/alice/staffonly.txt"
    P_700CHILD = f"{base}/carol700/inside.txt"
    P_700ABSENT = f"{base}/carol700/nope_zzz.txt"
    P_SGIDCHILD = f"{base}/sgid/sgkid.txt"
    P_SGIDABSENT = f"{base}/sgid/nope_zzz.txt"
    P_STKCHILD = f"{base}/sticky/stkkid.txt"
    P_PC = f"{base}/alice/pc_ok.txt"

    # forged / failing bearer credentials (each MUST fail auth).
    bad = [
        ("expired", mint(key, "alice", exp=now - 120, iat=now - 240)),
        ("wrong-aud", mint(key, "alice", aud="https://wrong.aud/")),
        ("wrong-iss", mint(key, "alice", iss="https://evil.example/")),
        ("not-yet-valid", mint(key, "alice", nbf=now + 99999)),
        ("alg-none", (_b64u(json.dumps({"alg": "none", "typ": "JWT", "kid": KID},
                                       separators=(",", ":")).encode()) + "."
                      + _b64u(json.dumps({"iss": ISSUER, "sub": "alice",
                                          "aud": AUDIENCE, "exp": now + 3600,
                                          "iat": now, "nbf": now,
                                          "scope": WRITE_SCOPE},
                                         separators=(",", ":")).encode()) + ".")),
        ("foreign-key", mint(ec.generate_private_key(ec.SECP256R1()), "alice")),
        ("unmapped-sub", mint(key, "mallory")),   # well-signed but no uid mapping
        ("garbage", "not.a.jwt"),
    ]

    # =====================================================================
    # SECTION 1: WebDAV — per-credential UNIFORMITY across resource states.
    #   For each bad credential, GET the same forbidden-existing, the
    #   forbidden-absent, the locked, the group-only, the 0700-child, the
    #   setgid-child and the sticky-child.  Collect statuses; assert none is
    #   2xx, no secret leaks, AND all statuses are identical (no oracle).
    # =====================================================================
    targets = [
        ("existing", P_EXISTING, EX_SECRET),
        ("absent", P_ABSENT, None),
        ("locked", P_LOCKED, LK_SECRET),
        ("group-only", P_GRP, GRP_SECRET),
        ("0700-child", P_700CHILD, P700_SECRET),
        ("0700-absent", P_700ABSENT, None),
        ("setgid-child", P_SGIDCHILD, SGID_SECRET),
        ("sticky-child", P_STKCHILD, STK_SECRET),
    ]

    for label, tok in bad:
        statuses = {}
        for tname, tpath, secret in targets:
            st, b = http("GET", tpath, port, tok)
            statuses[tname] = st
            ok(not is_2xx(st),
               f"{TAG}: WebDAV {label} GET {tname} not authenticated, "
               f"not 2xx (HTTP {st})")
            if secret is not None:
                ok(no_marker(b, secret),
                   f"{TAG}: WebDAV {label} GET {tname} leaks no secret bytes "
                   f"(HTTP {st})")
        # existence oracle: forbidden-EXISTING vs forbidden-ABSENT must match.
        ok(statuses["existing"] == statuses["absent"],
           f"{TAG}: WebDAV {label} — existing vs absent SAME status "
           f"(no existence oracle: {statuses['existing']} vs {statuses['absent']})")
        ok(statuses["0700-child"] == statuses["0700-absent"],
           f"{TAG}: WebDAV {label} — 0700 child vs absent-in-0700 SAME status "
           f"(no child-existence oracle: {statuses['0700-child']} vs "
           f"{statuses['0700-absent']})")
        # lock-state oracle: locked vs unlocked sibling must match for bad cred.
        st_unl, b_unl = http("GET", P_UNLOCKED, port, tok)
        ok(statuses["locked"] == st_unl,
           f"{TAG}: WebDAV {label} — locked vs unlocked SAME status "
           f"(no lock-state oracle: {statuses['locked']} vs {st_unl})")
        ok(no_marker(b_unl, LK_SECRET),
           f"{TAG}: WebDAV {label} GET unlocked sibling leaks no secret (HTTP {st_unl})")
        # group-only target must look like any other forbidden target (auth-first).
        ok(statuses["group-only"] == statuses["existing"],
           f"{TAG}: WebDAV {label} — group-only vs forbidden-existing SAME status "
           f"(auth fires before DAC: {statuses['group-only']} vs "
           f"{statuses['existing']})")
        # whole-set uniformity: a bad credential yields ONE status everywhere.
        ok(len(set(statuses.values())) == 1,
           f"{TAG}: WebDAV {label} — uniform status across ALL resource states "
           f"(no resource-state oracle: {sorted(set(statuses.values()))})")

    # Bad-credential WRITE/metadata verbs must also not betray resource state and
    # must create/lock nothing.  PROPFIND (metadata) and LOCK (lock-state) on the
    # forbidden-existing vs absent must match per bad cred.
    for label, tok in bad[:4]:
        st_pe, _ = http("PROPFIND", P_EXISTING, port, tok, hdrs={"Depth": "0"})
        st_pa, _ = http("PROPFIND", P_ABSENT, port, tok, hdrs={"Depth": "0"})
        ok(not is_2xx(st_pe) and st_pe == st_pa,
           f"{TAG}: WebDAV {label} PROPFIND existing==absent, not 2xx "
           f"(no metadata oracle: {st_pe} vs {st_pa})")
        st_le, _ = http("LOCK", P_EXISTING, port, tok,
                        data=b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:">'
                             b'<D:lockscope><D:exclusive/></D:lockscope>'
                             b'<D:locktype><D:write/></D:locktype></D:lockinfo>',
                        hdrs={"Content-Type": "application/xml"})
        st_la, _ = http("LOCK", P_ABSENT, port, tok,
                        data=b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:">'
                             b'<D:lockscope><D:exclusive/></D:lockscope>'
                             b'<D:locktype><D:write/></D:locktype></D:lockinfo>',
                        hdrs={"Content-Type": "application/xml"})
        ok(not is_2xx(st_le) and st_le == st_la,
           f"{TAG}: WebDAV {label} LOCK existing==absent, not 2xx "
           f"(no lock-creation via bad cred: {st_le} vs {st_la})")
        new_path = os.path.join(bob_dir, f"af_{label}.txt")
        http("PUT", f"{base}/bob/af_{label}.txt", port, tok, data=b"x\n")
        ok(not safe_exists(new_path),
           f"{TAG}: WebDAV {label} PUT into bob's dir created nothing")

    # =====================================================================
    # SECTION 2: WebDAV positive controls — auth fires, but a VALID token at
    #   the correct identity gets the RIGHT answer for each resource state.
    #   (proves the uniform deny above isn't a blanket reject of everything.)
    # =====================================================================
    ta, tb, tc = mint(key, "alice"), mint(key, "bob"), mint(key, "carol")
    st, b = http("GET", P_PC, port, ta)
    ok(st == 200 and b"COMBO-AF-PC-OK" in (b or b""),
       f"{TAG}: PC valid alice reads her own world-readable file (HTTP {st})")
    # valid bob: existing_secret.txt is BOB's OWN 0600 file (owner=UID_BOB), so
    # with a valid bob token DAC grants owner-read -> 200 + his own bytes.  This
    # is the positive control proving the bad-cred uniform-deny above was AUTH,
    # not a broken path.  The security property is that bob gets ONLY his own
    # data (no OTHER tenant's secret) and the file stays bob-owned.  absent ->
    # 404-class (existence distinction allowed once DAC has run for the owner).
    st_e, b_e = http("GET", P_EXISTING, port, tb)
    ok(st_e == 200 and EX_SECRET in (b_e or b"")
       and no_marker(b_e, GRP_SECRET) and no_marker(b_e, LK_SECRET)
       and no_marker(b_e, P700_SECRET),
       f"{TAG}: PC valid bob (owner) reads his own 0600 file, no other-tenant "
       f"leak (HTTP {st_e})")
    ok(file_owner(ex_file) == (UID_BOB, UID_BOB),
       f"{TAG}: PC valid bob owner-read left existing_secret.txt bob-owned")
    st_a, _ = http("GET", P_ABSENT, port, tb)
    ok(not is_2xx(st_a),
       f"{TAG}: PC valid bob on absent path not 2xx (HTTP {st_a})")
    # carol owns the 0700 dir -> she CAN read its child (control that the bad-cred
    # deny above was auth, not a broken path).
    st_c, b_c = http("GET", P_700CHILD, port, tc)
    ok(st_c == 200 and P700_SECRET in (b_c or b""),
       f"{TAG}: PC valid carol (owner) reads her 0700-dir child (HTTP {st_c})")
    # alice (in staff) reads the group-only file -> proves it's reachable for the
    # right identity, so the bad-cred uniform-deny was about AUTH not reachability.
    st_g, b_g = http("GET", P_GRP, port, ta)
    ok(st_g == 200 and GRP_SECRET in (b_g or b""),
       f"{TAG}: PC valid alice reads her 0640 staff group file (HTTP {st_g})")
    # nothing the forged creds did left residue: ownerships unchanged.
    ok(file_owner(ex_file) == (UID_BOB, UID_BOB),
       f"{TAG}: forbidden-existing file still bob-owned after forged-cred storm")
    ok(file_owner(grp_file) == (UID_ALICE, GID_STAFF),
       f"{TAG}: group-only file still alice:staff after forged-cred storm")

    # =====================================================================
    # SECTION 3: S3 — forged/tampered SigV4 + bearer-on-S3 against the SAME
    #   resource-state spread.  Only "alice" key is configured, so we attack
    #   with (i) a TAMPERED presign, (ii) a bearer token on the S3 port
    #   (wrong scheme), (iii) a backdated/expired presign.  Each must be a
    #   uniform non-2xx with no secret leak across existing/absent/locked/
    #   group/0700-child/setgid-child — no resource-state oracle on S3.
    # =====================================================================
    if s3port:
        s3_keys = [
            ("existing", f"{TAG}_root/bob/existing_secret.txt", EX_SECRET),
            ("absent", f"{TAG}_root/bob/nope_zzz.txt", None),
            ("group-only", f"{TAG}_root/alice/staffonly.txt", GRP_SECRET),
            ("0700-child", f"{TAG}_root/carol700/inside.txt", P700_SECRET),
            ("setgid-child", f"{TAG}_root/sgid/sgkid.txt", SGID_SECRET),
            ("locked", f"{TAG}_root/alice/locked.txt", LK_SECRET),
        ]

        # (i) tampered presigned URL (signature forged) — auth must fail uniformly.
        tamper_stat = {}
        for kname, kkey, secret in s3_keys:
            ppath = s3_presign("GET", kkey, s3port, tamper=True)
            st, b = http("GET", ppath, s3port)
            tamper_stat[kname] = st
            ok(not is_2xx(st),
               f"{TAG}: S3 tampered-presign GET {kname} not 2xx (HTTP {st})")
            if secret is not None:
                ok(no_marker(b, secret),
                   f"{TAG}: S3 tampered-presign GET {kname} no secret leak (HTTP {st})")
        ok(tamper_stat["existing"] == tamper_stat["absent"],
           f"{TAG}: S3 tampered-presign existing==absent "
           f"(no existence oracle: {tamper_stat['existing']} vs "
           f"{tamper_stat['absent']})")
        ok(len(set(tamper_stat.values())) == 1,
           f"{TAG}: S3 tampered-presign uniform across resource states "
           f"(no oracle: {sorted(set(tamper_stat.values()))})")

        # (ii) bearer token on the S3 port (wrong auth scheme) — same spread.
        bearer_stat = {}
        for kname, kkey, secret in s3_keys:
            st, b = http("GET", f"/{S3_BUCKET}/{kkey}", s3port,
                         hdrs={"Authorization": f"Bearer {mint(key, 'alice')}"})
            bearer_stat[kname] = st
            ok(not is_2xx(st),
               f"{TAG}: S3 bearer-on-S3 GET {kname} not 2xx (HTTP {st})")
            if secret is not None:
                ok(no_marker(b, secret),
                   f"{TAG}: S3 bearer-on-S3 GET {kname} no secret leak (HTTP {st})")
        ok(bearer_stat["existing"] == bearer_stat["absent"],
           f"{TAG}: S3 bearer-on-S3 existing==absent "
           f"(no existence oracle: {bearer_stat['existing']} vs "
           f"{bearer_stat['absent']})")
        ok(len(set(bearer_stat.values())) == 1,
           f"{TAG}: S3 bearer-on-S3 uniform across resource states "
           f"(no oracle: {sorted(set(bearer_stat.values()))})")

        # (iii) backdated/expired presign — same spread, must be uniform deny.
        old = dt.datetime.now(dt.timezone.utc) - dt.timedelta(hours=2)
        exp_stat = {}
        for kname, kkey, secret in s3_keys:
            ppath = s3_presign("GET", kkey, s3port, expires=60, when=old)
            st, b = http("GET", ppath, s3port)
            exp_stat[kname] = st
            ok(not is_2xx(st),
               f"{TAG}: S3 expired-presign GET {kname} not 2xx (HTTP {st})")
            if secret is not None:
                ok(no_marker(b, secret),
                   f"{TAG}: S3 expired-presign GET {kname} no secret leak (HTTP {st})")
        ok(exp_stat["existing"] == exp_stat["absent"],
           f"{TAG}: S3 expired-presign existing==absent "
           f"(no existence oracle: {exp_stat['existing']} vs {exp_stat['absent']})")
        ok(len(set(exp_stat.values())) == 1,
           f"{TAG}: S3 expired-presign uniform across resource states "
           f"(no oracle: {sorted(set(exp_stat.values()))})")

        # S3 positive control: alice (valid SigV4) reads her own world-readable
        # control file (so the uniform deny isn't a dead endpoint).
        safe_write(os.path.join(alice_dir, "s3pc.txt"),
                   b"COMBO-AF-S3PC\n", 0o644, UID_ALICE, UID_ALICE)
        st, b = s3("GET", f"{TAG}_root/alice/s3pc.txt", s3port)
        ok(st == 200 and b"COMBO-AF-S3PC" in (b or b""),
           f"{TAG}: S3 PC valid alice reads her own file (HTTP {st})")
        # and valid alice on bob's 0600 existing -> denied (DAC), no leak: proves
        # the bad-cred denies above were AUTH, this one is DAC, both no-leak.
        st, b = s3("GET", f"{TAG}_root/bob/existing_secret.txt", s3port)
        ok(not is_2xx(st) and no_marker(b, EX_SECRET),
           f"{TAG}: S3 PC valid alice denied bob's 0600 (DAC), no leak (HTTP {st})")

    # =====================================================================
    # SECTION 4: root:// — forged-token resource-state oracle.  Drive native
    #   xrdfs with forged tokens at stat/cat across existing/absent/locked/
    #   group/0700-child/setgid-child.  rc must be non-zero everywhere, no
    #   secret bytes, and the forged-token outcome must not distinguish
    #   existing from absent (no existence oracle on the stream plane).
    # =====================================================================
    if xrd_avail():
        root_targets = [
            ("existing", f"/{TAG}_root/bob/existing_secret.txt", EX_SECRET),
            ("absent", f"/{TAG}_root/bob/nope_zzz.txt", None),
            ("group-only", f"/{TAG}_root/alice/staffonly.txt", GRP_SECRET),
            ("0700-child", f"/{TAG}_root/carol700/inside.txt", P700_SECRET),
            ("setgid-child", f"/{TAG}_root/sgid/sgkid.txt", SGID_SECRET),
            ("locked", f"/{TAG}_root/alice/locked.txt", LK_SECRET),
        ]
        for flabel, ftok in _forged_tokens(key):
            rcs = {}
            for tname, tpath, secret in root_targets:
                rc, out, _e = xrd_fs_token(["cat", tpath], ftok)
                rcs[tname] = (rc == 0)
                ok(rc != 0,
                   f"{TAG}: root:// forged[{flabel}] cat {tname} rejected (rc={rc})")
                if secret is not None:
                    ok(secret.decode() not in (out or ""),
                       f"{TAG}: root:// forged[{flabel}] cat {tname} no secret leak")
            # stat existing vs absent under forged token: neither must succeed
            # (a succeeding stat on existing-only would be an existence oracle).
            rc_se, _o, _e = xrd_fs_token(
                ["stat", f"/{TAG}_root/bob/existing_secret.txt"], ftok)
            rc_sa, _o, _e = xrd_fs_token(
                ["stat", f"/{TAG}_root/bob/nope_zzz.txt"], ftok)
            ok(rc_se != 0 and rc_sa != 0,
               f"{TAG}: root:// forged[{flabel}] stat existing & absent BOTH "
               f"rejected (no existence oracle: {rc_se}/{rc_sa})")
            ok(not any(rcs.values()),
               f"{TAG}: root:// forged[{flabel}] every cat failed uniformly "
               f"(no resource-state success leak)")

        # root:// positive controls: valid carol cats her own 0700-dir child;
        # valid bob denied alice's group file & no leak.
        rc, out, _e = xrd_fs(["cat", f"/{TAG}_root/carol700/inside.txt"], "carol")
        ok(rc == 0 and P700_SECRET.decode() in (out or ""),
           f"{TAG}: root:// PC valid carol reads her 0700-dir child (rc={rc})")
        rc, out, _e = xrd_fs(["cat", f"/{TAG}_root/alice/staffonly.txt"], "bob")
        ok(rc != 0 and GRP_SECRET.decode() not in (out or ""),
           f"{TAG}: root:// PC valid bob denied alice's staff file, no leak (rc={rc})")
        rc, out, _e = xrd_fs(["cat", f"/{TAG}_root/alice/staffonly.txt"], "alice")
        ok(rc == 0 and GRP_SECRET.decode() in (out or ""),
           f"{TAG}: root:// PC owner alice reads her staff group file (rc={rc})")

    # =====================================================================
    # SECTION 5: worker survival + no-residue after the forged-credential
    #   storm — a follow-up LEGIT op must still work, and nothing the bad
    #   credentials touched produced a svc/root/wrong-owner artifact.
    # =====================================================================
    st, b = http("GET", P_PC, port, ta)
    ok(st == 200 and b"COMBO-AF-PC-OK" in (b or b""),
       f"{TAG}: worker survived forged-credential storm (follow-up GET OK, HTTP {st})")
    # the 0700 dir must still be carol-owned & mode-0700 (no broker leak created a
    # svc/root-owned child or relaxed the dir during the auth-failure barrage).
    ok(file_owner(p700_dir) == (UID_CAROL, UID_CAROL),
       f"{TAG}: carol's 0700 dir still carol-owned after storm")
    try:
        children = set(os.listdir(p700_dir))
    except OSError:
        children = set()
    ok(children == {"inside.txt"},
       f"{TAG}: no forged-cred artifact appeared in carol's 0700 dir ({sorted(children)})")
    # sticky/setgid dirs unchanged, no svc/root residue in bob's dir.
    ok(file_owner(sgid_dir)[1] == GID_STAFF,
       f"{TAG}: setgid dir kept its alice:staff group after storm")
    try:
        bobkids = os.listdir(bob_dir)
    except OSError:
        bobkids = []
    residue = [k for k in bobkids
               if file_owner(os.path.join(bob_dir, k))[0] in (UID_SVC, 0)]
    ok(not residue,
       f"{TAG}: no svc/root-owned residue in bob's dir after storm ({residue})")


def run_combo_broker_pressure(key, data, port, s3port):
    """COMBINATION frontier: broker BACK-PRESSURE crossed with legitimate ops.

    Resource limits, FIFO-hang, group-DAC, principal-leak and broker-desync have
    each been probed ALONE.  Here we INTERLEAVE a stream of broker-DENIED mapping
    requests (unmapped 'mallory', sub-floor 'lowu', reserved-primary 'badprim',
    forbidden-group 'dockerite', escalation 'root'/'svc'/'sys100', plus opens of a
    planted FIFO) WITH legitimate supplementary-group ops (carol reads the 0640
    staff file, alice writes her own dir) under MODEST concurrency (<=8 threads),
    and assert the union holds:
      * every legit op still SUCCEEDS correctly (the denied flood does not starve /
        wedge it) and owns/reads as the RIGHT identity;
      * the broker request/reply channel never DESYNCS — a known-answer carol read
        interleaved into the storm returns the SAME correct answer every time (a
        crossed reply would hand carol a wrong principal or a wrong body);
      * NO principal leaks across the per-worker boundary — a denied 'mallory'
        request on a kept-alive connection must NOT let the very next request act as
        mallory or as the svc worker (the follow-up alice op owns 1001, never 1500/
        mallory/<denied-uid>);
      * a FIFO open UNDER the flood does not wedge the single broker (O_NONBLOCK);
      * after the storm a final legit alice PUT+GET roundtrips and a full ownership
        scan of the world-writable /pub dir finds zero svc/root/denied-uid residue.
    Does NOT kill the broker (run_broker_failclosed owns that) and never sends MB or
    spawns dozens of threads (host-OOM guard)."""
    T = "cbp_"                                   # tag prefixes every fixture/file
    ta = mint(key, "alice")
    tc = mint(key, "carol")
    adir = os.path.join(data, "alice")
    pubdir = os.path.join(data, "pub")           # svc:svc 0777 — only idmap stops writes
    GR = "/grp"
    SR = b"STAFF-GROUP-READABLE"                  # body of grp/staff_r.txt (0640 alice:staff)
    BOB_SECRET = b"BOB-PRIVATE-SECRET"            # bob/private.txt 0600 — must never leak

    # The principals the BROKER must refuse to map (each holds a VALID write-scoped
    # token, so authz passes; only the idmap guard may stop them).
    DENIED = ["mallory", "lowu", "badprim", "dockerite", "root", "svc", "sys100"]
    DENIED_TOK = {s: mint(key, s) for s in DENIED}

    def _has(body, needle):
        return needle in (body or b"")

    # ---- recovery probe: a legit alice PUT+GET roundtrip proving the worker AND
    #      the single broker socket are still live & correctly-mapping ------------
    def recover(label, n=[0]):
        n[0] += 1
        rel = f"/alice/{T}rec_{n[0]}.txt"
        body = f"rec-{n[0]}-{label[:10]}".encode()
        stp, _ = http("PUT", rel, port, ta, body)
        stg, gb = http("GET", rel, port, ta)
        fp = os.path.join(adir, f"{T}rec_{n[0]}.txt")
        owned = os.path.exists(fp) and os.stat(fp).st_uid == UID_ALICE
        ok(stp in (200, 201, 204) and stg == 200 and gb == body and owned,
           f"recovery after {label}: alice PUT+GET roundtrips, owned 1001, broker "
           f"not wedged by the deny storm (PUT {stp}, GET {stg})")

    recover("baseline")

    # =====================================================================
    # 0) Plant ONE FIFO inside alice's tree.  Under the flood we will open it
    #    and prove the single broker does not block on it (O_NONBLOCK).
    # =====================================================================
    fifo = os.path.join(adir, f"{T}fifo")
    fifo_ok = False
    try:
        if not os.path.lexists(fifo):
            os.mkfifo(fifo, 0o600)
            os.chown(fifo, UID_ALICE, UID_ALICE)
        fifo_ok = True
    except OSError as e:
        ok(True, f"FIFO fixture skipped ({e.__class__.__name__})")

    # =====================================================================
    # A) PRINCIPAL-LEAK ACROSS THE PER-WORKER BOUNDARY, denied->legit, on ONE
    #    kept-alive connection.  A denied 'mallory' (unmapped) PUT must not
    #    leave the worker's process-global principal set to mallory/svc so the
    #    NEXT request (legit alice) runs as the wrong uid.  We pair each denied
    #    subject with an immediate alice op on the SAME socket.
    # =====================================================================
    for sub in DENIED:
        leg = f"/alice/{T}leak_{sub}.txt"
        seq = [
            ("PUT", f"/pub/{T}leak_src_{sub}.txt", DENIED_TOK[sub],
             f"{sub.upper()}-FLOOD\n".encode(), None),   # denied (idmap refuses)
            ("PUT", leg, ta, b"alice-after-deny\n", None),  # legit, MUST own 1001
            ("GET", leg, ta, None, None),
        ]
        res = http_keepalive(seq, port)
        # the denied src must not have been created in /pub (world-writable -> only
        # the idmap guard can stop it) nor created owned by a denied/reserved uid.
        srcp = os.path.join(pubdir, f"{T}leak_src_{sub}.txt")
        src_made = os.path.exists(srcp)
        src_uid = os.stat(srcp).st_uid if src_made else -1
        ok(res[0][0] not in (200, 201, 204) and not src_made,
           f"denied '{sub}' PUT refused on shared conn, no /pub file "
           f"(HTTP {res[0][0]}, made={src_made})")
        ok(not src_made or src_uid >= 1000,
           f"denied '{sub}' left no reserved-owned residue in /pub (uid={src_uid})")
        # the FOLLOW-UP alice op on the SAME worker connection must own as ALICE,
        # never as the just-denied principal nor as the svc worker (1500).
        fp = os.path.join(adir, f"{T}leak_{sub}.txt")
        a_made = os.path.exists(fp)
        a_uid = os.stat(fp).st_uid if a_made else -1
        ok(res[1][0] in (200, 201, 204) and a_made and a_uid == UID_ALICE,
           f"after denied '{sub}', next alice op on same conn owns 1001 "
           f"(not leaked principal/svc) (HTTP {res[1][0]}, uid={a_uid})")
        ok(a_uid != UID_SVC and a_uid != 0,
           f"after denied '{sub}', follow-up file not svc(1500)/root-owned (uid={a_uid})")
        ok(res[2][0] == 200 and res[2][1] == b"alice-after-deny\n",
           f"after denied '{sub}', alice reads back her OWN bytes, not crossed "
           f"(HTTP {res[2][0]})")

    recover("denied->legit keepalive sweep")

    # =====================================================================
    # B) Reverse order: legit alice op THEN a denied op on the same conn — the
    #    denied op must still be refused (alice's good mapping must not "stick"
    #    and silently authorize the unmapped subject as alice).
    # =====================================================================
    for sub in ("mallory", "root", "svc"):
        seq = [
            ("PUT", f"/alice/{T}pre_{sub}.txt", ta, b"alice-first\n", None),
            ("PUT", f"/pub/{T}post_{sub}.txt", DENIED_TOK[sub],
             f"{sub.upper()}-RIDE\n".encode(), None),
        ]
        res = http_keepalive(seq, port)
        postp = os.path.join(pubdir, f"{T}post_{sub}.txt")
        post_made = os.path.exists(postp)
        post_uid = os.stat(postp).st_uid if post_made else -1
        ok(res[0][0] in (200, 201, 204),
           f"legit alice op precedes denied '{sub}' fine (HTTP {res[0][0]})")
        ok(res[1][0] not in (200, 201, 204) and not post_made,
           f"denied '{sub}' after a good alice op still REFUSED — good mapping "
           f"does not stick (HTTP {res[1][0]}, made={post_made})")
        ok(not post_made or (post_uid >= 1000 and post_uid != UID_ALICE),
           f"denied '{sub}' after alice left no alice/reserved-owned residue "
           f"(uid={post_uid})")

    recover("legit->denied keepalive sweep")

    # =====================================================================
    # C) THE STORM: <=8 threads.  Mix three job classes concurrently —
    #      (i)  broker-DENIED floods (unmapped/sub-floor/forbidden/escalation),
    #      (ii) LEGIT supplementary-group reads (carol reads the 0640 staff
    #           file — exercises setgroups under pressure),
    #      (iii)LEGIT owner writes (alice writes her own dir),
    #    plus a KNOWN-ANSWER channel-desync probe interleaved on its own.
    #    Assert no class starves the others and the broker channel never crosses
    #    a reply (carol never gets a wrong body/uid; alice files own 1001).
    # =====================================================================
    breaches = []          # security failures (created-as-denied / cross content)
    carol_results = []     # (status, leaked_secret_bool, got_staff_bool)
    alice_owner_bad = []   # alice storm files that ended up wrong-owned
    fifo_times = []        # wall-time of FIFO opens under load (hang detector)

    def job(i):
        kind = i % 4
        try:
            if kind == 0:                              # (i) DENIED flood -> /pub
                sub = DENIED[i % len(DENIED)]
                rel = f"{T}storm_{sub}_{i}.txt"
                st, _ = http("PUT", f"/pub/{rel}", port, DENIED_TOK[sub],
                             f"{sub.upper()}-STORM-{i}\n".encode())
                fp = os.path.join(pubdir, rel)
                if st in (200, 201, 204) or os.path.exists(fp):
                    breaches.append(("denied-created", sub, i, st))
            elif kind == 1:                            # (ii) carol group-DAC read
                st, b = http("GET", f"{GR}/staff_r.txt", port, tc)
                carol_results.append(
                    (st, _has(b, BOB_SECRET), st == 200 and _has(b, SR)))
            elif kind == 2:                            # (iii) alice owner write
                rel = f"{T}storm_a_{i}.txt"
                st, _ = http("PUT", f"/alice/{rel}", port, ta,
                             f"a-storm-{i}\n".encode())
                fp = os.path.join(adir, rel)
                if os.path.exists(fp) and os.stat(fp).st_uid != UID_ALICE:
                    alice_owner_bad.append((i, os.stat(fp).st_uid))
            else:                                      # FIFO open under load (O_NONBLOCK)
                if fifo_ok:
                    t0 = time.time()
                    http("GET", f"/alice/{T}fifo", port, ta)
                    fifo_times.append(time.time() - t0)
        except Exception as e:  # noqa: BLE001
            breaches.append(("exc", i, repr(e)))

    threads = [threading.Thread(target=job, args=(i,)) for i in range(24)]
    # cap to <=8 live threads at a time: run in waves of 8.
    for base in range(0, len(threads), 8):
        wave = threads[base:base + 8]
        for t in wave:
            t.start()
        for t in wave:
            t.join()

    ok(not breaches,
       f"under denied-flood storm: no denied principal ever created a file / no "
       f"crash (breaches={breaches[:3]})")
    ok(carol_results and all(r[2] for r in carol_results),
       f"every interleaved carol group-DAC read SUCCEEDED under the storm — legit "
       f"op not starved by the deny flood ({len(carol_results)} reads)")
    ok(carol_results and not any(r[1] for r in carol_results),
       "no interleaved carol read leaked bob's private secret (no crossed reply)")
    ok(not alice_owner_bad,
       f"every alice storm write owned 1001 under the flood — no principal cross "
       f"(bad={alice_owner_bad[:3]})")
    if fifo_ok:
        ok(fifo_times and all(t < 5.0 for t in fifo_times),
           f"FIFO open(s) UNDER the deny storm did not wedge the single broker "
           f"({len(fifo_times)} opens, max {max(fifo_times):.2f}s)")
    else:
        ok(True, "FIFO-under-storm skipped (no fifo fixture)")

    recover("concurrent deny storm")

    # =====================================================================
    # D) KNOWN-ANSWER DESYNC PROBE: serially fire a denied request immediately
    #    before a deterministic carol staff-read, repeated, and confirm carol
    #    ALWAYS gets the identical correct body — proving the broker's request
    #    queue never pairs carol's reply with the denied request's slot.
    # =====================================================================
    desync_bad = 0
    for i in range(10):
        sub = DENIED[i % len(DENIED)]
        # denied op first (drives a refused broker exchange)...
        http("PUT", f"/pub/{T}ka_{sub}_{i}.txt", port, DENIED_TOK[sub], b"ka\n")
        # ...then the known-answer carol read — must be byte-identical every time.
        st, b = http("GET", f"{GR}/staff_r.txt", port, tc)
        if not (st == 200 and _has(b, SR)) or _has(b, BOB_SECRET):
            desync_bad += 1
    ok(desync_bad == 0,
       f"known-answer carol read after each denied op stayed correct x10 — broker "
       f"reply pairing never desynced (mismatches={desync_bad})")

    # interleave a denied op between alice WRITE and alice READBACK and confirm the
    # readback returns alice's own freshly-written bytes (not a crossed/denied body).
    ka_bad = 0
    for i in range(8):
        sub = DENIED[i % len(DENIED)]
        rel = f"/alice/{T}kaw_{i}.txt"
        payload = f"alice-ka-{i}\n".encode()
        http("PUT", rel, port, ta, payload)
        http("PUT", f"/pub/{T}kaw_d_{i}.txt", port, DENIED_TOK[sub], b"d\n")
        st, b = http("GET", rel, port, ta)
        fp = os.path.join(adir, f"{T}kaw_{i}.txt")
        if not (st == 200 and b == payload) or \
           not (os.path.exists(fp) and os.stat(fp).st_uid == UID_ALICE):
            ka_bad += 1
    ok(ka_bad == 0,
       f"denied op sandwiched in alice write->read never crossed content/owner "
       f"x8 (mismatches={ka_bad})")

    # =====================================================================
    # E) Cross-PROTOCOL pressure: drive the SAME deny/legit interleave over the
    #    root:// stream plane (different code path to the SAME broker).  A denied
    #    'mallory'/'lowu' write must fail and leave no file; an immediately
    #    following legit carol group read must still succeed & own correctly.
    # =====================================================================
    if xrd_avail():
        for sub in ("mallory", "lowu", "badprim"):
            lf = os.path.join(WORK, f"{T}cp_{sub}.bin")
            try:
                with open(lf, "wb") as fh:
                    fh.write(f"{sub}-stream\n".encode())
            except OSError:
                continue
            rc, _o, _e = xrd_cp_up(lf, f"/pub/{T}cp_{sub}.bin", sub)
            cpp = os.path.join(pubdir, f"{T}cp_{sub}.bin")
            made = os.path.exists(cpp)
            cuid = os.stat(cpp).st_uid if made else -1
            ok(rc != 0 and not made,
               f"root:// denied '{sub}' xrdcp DENIED, no /pub file (rc={rc})")
            ok(not made or cuid >= 1000,
               f"root:// denied '{sub}' left no reserved residue (uid={cuid})")
            # immediately after the refused stream op, a legit carol group read.
            rc2, out, _e = xrd_fs(["cat", f"{GR}/staff_r.txt"], "carol")
            ok(rc2 == 0 and SR.decode() in (out or "")
               and BOB_SECRET.decode() not in (out or ""),
               f"root:// carol group read OK right after denied '{sub}' — no "
               f"stream-plane principal leak (rc={rc2})")
        # a denied stream op followed by a legit ALICE write that must own 1001.
        lf = os.path.join(WORK, f"{T}cp_alice.bin")
        try:
            with open(lf, "wb") as fh:
                fh.write(b"alice-stream-after-deny\n")
            rc, _o, _e = xrd_cp_up(lf, f"/alice/{T}cp_alice.bin", "alice")
            afp = os.path.join(adir, f"{T}cp_alice.bin")
            aok = os.path.exists(afp) and os.stat(afp).st_uid == UID_ALICE
            ok(rc == 0 and aok,
               f"root:// alice write after a denied stream op owns 1001 (rc={rc})")
        except OSError:
            ok(True, "root:// alice-after-deny stream fixture skipped (OSError)")

    # =====================================================================
    # F) FINAL ownership SCAN of the world-writable /pub dir: across this whole
    #    storm NO file we tagged may exist owned by svc(1500)/root(0)/a denied
    #    sub-floor uid.  /pub is 0777 so the FS never blocks a write — every
    #    cbp_ file here would be a true idmap-guard breach.
    # =====================================================================
    residue = []
    try:
        for f in os.listdir(pubdir):
            if not f.startswith(T):
                continue
            p = os.path.join(pubdir, f)
            try:
                if os.path.islink(p) or not os.path.isfile(p):
                    continue
                u = os.lstat(p).st_uid
            except OSError:
                continue
            residue.append((f, u))
    except OSError:
        pass
    ok(not residue,
       f"NO cbp_ file in world-writable /pub survived the deny storm — every "
       f"denied mapping was refused at the broker (residue={residue[:4]})")

    # and the canonical secrets were never disturbed/served: alice's staff file is
    # still exactly readable by carol (group) and bob's private file still hidden.
    st, b = http("GET", f"{GR}/staff_r.txt", port, tc)
    ok(st == 200 and _has(b, SR),
       f"post-storm: carol still reads the 0640 staff file via group DAC (HTTP {st})")
    st, b = http("GET", "/bob/private.txt", port, ta)
    ok(st != 200 and not _has(b, BOB_SECRET),
       f"post-storm: alice still denied bob's 0600 private file, no leak (HTTP {st})")

    # =====================================================================
    # G) FIFO open AFTER the storm settles — confirm the single broker is not
    #    left wedged by any half-completed open during the flood.
    # =====================================================================
    if fifo_ok:
        t0 = time.time()
        st, _ = http("GET", f"/alice/{T}fifo", port, ta)
        dt_fifo = time.time() - t0
        ok(dt_fifo < 5.0,
           f"post-storm FIFO open did not hang the broker ({dt_fifo:.2f}s, HTTP {st})")
        t0 = time.time()
        st, _ = http("PUT", f"/alice/{T}fifo", port, ta, b"x" * 64)
        ok(time.time() - t0 < 5.0,
           f"post-storm FIFO PUT did not hang the broker (HTTP {st})")

    # final two roundtrips prove the worker AND broker fully survived everything.
    recover("full storm complete")
    recover("final sanity")


def run_combo_encoding_group_targets(key, data, port, s3port):
    """COMBINATION FRONTIER: traversal/ENCODING crossed with GROUP / SETGID / STICKY
    / CROSS-TENANT targets (the existing encoding battery only ever aimed encodings
    at /etc and at outside-the-export markers; the group/setgid/sticky batteries
    only used CLEAN logical paths).  Here every encoding variant (../, %2e%2e,
    %252e, ..%2f, ....//, ..;/, %00, %0d%0a, double-encoded, unicode-dot, absolute,
    backslash) is fired at a target the *group DAC* protects, so the question is:
    can an encoded path sneak a NON-MEMBER past a group-restricted directory, climb
    OUT of a setgid/sticky dir into a sibling tenant, escape a 0700 dir to /etc, or
    NORMALIZE into another tenant's tree?  bob is NOT in staff (staffdir/sgiddir/
    execonly are alice:staff 0770/2770/0710); alice is NOT in research (bob owns
    bobsecret 0700).  Each deny asserts the protected secret bytes never appear and
    that nothing was created in a forbidden/cross-tenant/outside location; each
    cluster carries a POSITIVE CONTROL proving the path machinery still resolves a
    legit in-tenant / in-group nested path (so a blanket block cannot false-pass).
    The worker must survive (a follow-up legit op works)."""
    tag = "cegt"
    tb = mint(key, "bob")        # bob: NOT in staff (staffdir/sgiddir/execonly closed)
    ta = mint(key, "alice")      # alice: NOT in research (bobsecret closed); IS staff
    tc = mint(key, "carol")      # carol: IN staff (group control for the staff dirs)

    PW = b"root:x:"                       # /etc/passwd signature
    STAFF = b"INSIDE-STAFF-DIR"           # staffdir/inside.txt body (group-only)
    EXEC = b"EXECONLY-KNOWN"              # execonly/known.txt body (group --x only)
    BOB = b"BOB-PRIVATE-SECRET"           # bob/private.txt (0600) body
    BOBS = b"bob-only"                    # bobsecret/s.txt (0700 dir) body
    SVC = b"svc-only-secret"              # svconly/secret-name.txt body

    export_abs = os.path.abspath(data)
    parent1 = os.path.dirname(export_abs)
    parent2 = os.path.dirname(parent1)

    def clean_body(b):
        """No protected/secret marker of ANY target leaked into this response."""
        x = b or b""
        return (PW not in x and b"daemon:x:" not in x and STAFF not in x
                and EXEC not in x and BOB not in x and BOBS not in x and SVC not in x)

    def no_create(*paths):
        """True iff NONE of the candidate forbidden landing paths exist."""
        for p in paths:
            try:
                if os.path.exists(p):
                    return False
            except OSError:
                pass
        return True

    def mode_of(p):
        try:
            return os.stat(p).st_mode & 0o7777
        except OSError:
            return -1

    def owner_of(p):
        try:
            st = os.stat(p)
            return (st.st_uid, st.st_gid)
        except OSError:
            return (-1, -1)

    # A unique sibling-tenant target the escapes try to OVERWRITE / read into:
    # carol owns a private file; escapes out of setgid/sticky dirs aim here so a
    # successful climb would either leak CAROL-SECRET or clobber it.
    CAROL_SECRET = b"CAROL-PRIVATE-CEGT"
    carol_priv = os.path.join(data, "carol", "cegt_priv.txt")
    try:
        os.makedirs(os.path.join(data, "carol"), exist_ok=True)
        os.chown(os.path.join(data, "carol"), UID_CAROL, UID_CAROL)
        os.chmod(os.path.join(data, "carol"), 0o755)
        with open(carol_priv, "wb") as fh:
            fh.write(CAROL_SECRET + b"\n")
        os.chown(carol_priv, UID_CAROL, UID_CAROL)
        os.chmod(carol_priv, 0o600)
    except OSError:
        carol_priv = None

    # A 0700 alice-only dir (NOT group-shared) used for the "climb out of a private
    # dir to /etc" leg — distinct from bobsecret so cleanup stays local.
    priv700 = os.path.join(data, f"{tag}_priv700")
    priv700_secret = os.path.join(priv700, "inner.txt")
    try:
        os.makedirs(priv700, exist_ok=True)
        os.chown(priv700, UID_ALICE, UID_ALICE)
        os.chmod(priv700, 0o700)
        with open(priv700_secret, "wb") as fh:
            fh.write(b"PRIV700-INNER-CEGT\n")
        os.chown(priv700_secret, UID_ALICE, UID_ALICE)
        os.chmod(priv700_secret, 0o600)
    except OSError:
        pass

    # =====================================================================
    # POSITIVE CONTROL CLUSTER — the path/encoding/group machinery WORKS for
    # legitimate cases, so every deny below is meaningful (not a blanket block).
    # =====================================================================
    # (PC1) carol IS staff: a normalizing dot-segment INTO the group dir resolves
    #       and returns the group-only body — proves group-DAC GRANT + dot handling.
    st, b = http("GET", "/staffdir/./inside.txt", port, tc)
    # carol IS staff: group/owner DAC GRANTS the read and the dot-segment must
    # normalize back inside the dir -> HTTP 200.  The body itself is a SHARED
    # fixture an earlier batch (run_group_write_dac) legitimately rewrites
    # (carol re-PUTs staffdir/inside.txt; _reset_fixtures restores the dir but not
    # this child's content), so assert the GRANT (200 + a real body carol may see)
    # without pinning the stale canonical marker, and require no OTHER-tenant
    # secret leaked into the response.
    ok(st == 200 and bool(b)
       and PW not in (b or b"") and BOB not in (b or b"")
       and BOBS not in (b or b"") and SVC not in (b or b""),
       f"control: carol (staff) reads staffdir via dot-segment, group GRANT "
       f"+ normalize works (HTTP {st})")
    # (PC2) carol reaches the group dir through an encoded but in-bounds segment.
    st, b = http("GET", "/staffdir/%2e/inside.txt", port, tc)
    ok(st in (200, 404) and clean_body(b) or _has(b, STAFF),
       f"control: carol staffdir via %2e segment handled (HTTP {st})")
    # (PC3) alice (owner) writes a nested file under the setgid dir — inherits the
    #       staff gid — proves setgid path resolution is functional for a member.
    st, _ = http("PUT", "/sgiddir/cegt_ok.txt", port, ta, b"SGID-OK\n")
    sgf = os.path.join(data, "sgiddir", "cegt_ok.txt")
    ok(st in (200, 201, 204) and os.path.exists(sgf)
       and owner_of(sgf) == (UID_ALICE, GID_STAFF),
       f"control: alice PUT in setgid dir -> file group inherits staff (HTTP {st})")
    # (PC4) bob writes into the world-writable sticky dir (legit, allowed) and the
    #       file is owned by BOB — sticky lets him create his own file.
    st, _ = http("PUT", "/stickytmp/cegt_bob.txt", port, tb, b"STICKY-BOB\n")
    skb = os.path.join(data, "stickytmp", "cegt_bob.txt")
    ok(st in (200, 201, 204) and os.path.exists(skb)
       and owner_of(skb)[0] == UID_BOB,
       f"control: bob PUT into sticky 1777 dir owned by bob (HTTP {st})")

    # =====================================================================
    # (A) ENCODING vs a GROUP-restricted dir the identity is NOT in.
    #     bob is NOT staff: staffdir(0770)/sgiddir(2770)/execonly(0710) are closed
    #     to him by group DAC.  Can an encoded path sneak bob past the group bit?
    #     Every variant must DENY and never leak STAFF/EXEC bytes.
    # =====================================================================
    grp_enc_reads = [
        "/staffdir/inside.txt",                         # plain (group deny baseline)
        "/staffdir%2finside.txt",                       # encoded slash into the dir
        "/%73taffdir/inside.txt",                       # %73 = 's' (encoded dirname)
        "/staffdir/%2e/inside.txt",                     # dot-segment inside
        "/staffdir/../staffdir/inside.txt",             # normalizes back in
        "/staffdir/..%2fstaffdir/inside.txt",           # encoded normalize-back-in
        "/alice/../staffdir/inside.txt",                # via sibling tenant
        "/alice/..%2fstaffdir/inside.txt",
        "/alice/....//staffdir/inside.txt",             # quad-dot collapse
        "/staffdir/./%69nside.txt",                     # %69 = 'i' (encoded leaf)
        "/sgiddir/../staffdir/inside.txt",              # hop via setgid sibling
        "/execonly/known.txt",                          # group --x dir, no group read
        "/execonly/%6bnown.txt",                        # %6b = 'k'
        "/execonly/../execonly/known.txt",
        "/sgiddir/inside.txt",                          # setgid dir, bob not member
    ]
    for p in grp_enc_reads:
        st, b = http("GET", p, port, tb)
        ok(st in (403, 401, 404) and clean_body(b),
           f"(A) bob(non-staff) encoded GET {p[:34]!r} group-DAC deny, no staff/exec "
           f"leak (HTTP {st})")

    # bob PROPFIND the group dir via encoding — must not enumerate the member-only
    # child name or body.
    pf = (b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
          b'<D:prop><D:displayname/></D:prop></D:propfind>')
    for p in ["/staffdir/", "/staffdir%2f", "/alice/../staffdir/",
              "/sgiddir/", "/execonly/"]:
        st, b = http("PROPFIND", p, port, tb, data=pf,
                     hdrs={"Depth": "1", "Content-Type": "application/xml"})
        ok(clean_body(b) and not _has(b, b"inside.txt"),
           f"(A) bob PROPFIND {p!r} no member-only enumeration/body (HTTP {st})")

    # bob WRITE via encoding INTO the group dir he's not a member of — must create
    # nothing there (the group --w bit is closed to a non-member).
    grp_enc_writes = [
        "/staffdir/cegt_intrude.txt",
        "/staffdir%2fcegt_intrude2.txt",
        "/alice/..%2fstaffdir/cegt_intrude3.txt",
        "/sgiddir/cegt_intrude4.txt",
        "/sgiddir/..%2fsgiddir/cegt_intrude5.txt",
    ]
    for p in grp_enc_writes:
        http("PUT", p, port, tb, b"intrude\n")
    ok(no_create(
        os.path.join(data, "staffdir", "cegt_intrude.txt"),
        os.path.join(data, "staffdir", "cegt_intrude2.txt"),
        os.path.join(data, "staffdir", "cegt_intrude3.txt"),
        os.path.join(data, "sgiddir", "cegt_intrude4.txt"),
        os.path.join(data, "sgiddir", "cegt_intrude5.txt")),
       "(A) bob encoded WRITE into staff/setgid group dir created nothing")
    # control: carol (member) CAN write into the staff dir via a normalizing path.
    st, _ = http("PUT", "/staffdir/../staffdir/cegt_carol.txt", port, tc,
                 b"CAROL-IN-STAFF\n")
    ccf = os.path.join(data, "staffdir", "cegt_carol.txt")
    ok(st in (200, 201, 204) and os.path.exists(ccf)
       and owner_of(ccf)[0] == UID_CAROL,
       f"control: carol(staff) encoded WRITE into staffdir OK, owned carol "
       f"(HTTP {st})")

    # =====================================================================
    # (B) ESCAPE from a SETGID / STICKY dir OUT to a sibling tenant's dir.
    #     Fire ".." escapes whose path STARTS inside sgiddir/stickytmp and aims at
    #     carol's private file / bob's private file.  No sibling secret may leak;
    #     nothing may be created in / clobber the sibling tenant.
    # =====================================================================
    # Every target here is owned by CAROL (a true sibling tenant of bob): bob is a
    # NON-owner, NON-group accessor, so any appearance of CAROL_SECRET is a real
    # cross-tenant leak.  Targets bob OWNS (bob/private.txt, bobsecret/s.txt) were
    # removed on purpose: a normalizing `../` stays in-export and resolves back to
    # bob's OWN files, so a 200 + his own bytes there is CORRECT (owner read), not a
    # sibling-tenant leak -- asserting `not _has(b, BOB/BOBS)` against bob's own
    # tree was the test bug here.
    escape_reads = [
        "/sgiddir/../carol/cegt_priv.txt",
        "/sgiddir/..%2fcarol%2fcegt_priv.txt",
        "/sgiddir/....//carol/cegt_priv.txt",
        "/stickytmp/../carol/cegt_priv.txt",
        "/stickytmp/..%2f..%2fcarol/cegt_priv.txt",
        "/stickytmp/..%2fcarol%2fcegt_priv.txt",
        "/sgiddir/..%2f..%2fcarol/cegt_priv.txt",
        "/sgiddir/..;/carol/cegt_priv.txt",
        "/stickytmp/%2e%2e/carol/cegt_priv.txt",
        "/stickytmp/%2e%2e%2fcarol%2fcegt_priv.txt",
    ]
    for p in escape_reads:
        st, b = http("GET", p, port, tb)
        # Sibling-tenant (carol) secret must never leak to bob; the deny must also
        # not surface any other protected marker (/etc, staff, exec, svc, bob/bobs).
        ok(not _has(b, CAROL_SECRET) and clean_body(b),
           f"(B) bob escape-out-of-setgid/sticky GET {p[:36]!r} no sibling-tenant "
           f"secret leak (HTTP {st})")

    # ESCAPE-WRITE out of the sticky/setgid dir to clobber carol's private file or
    # plant a file in carol's tree — must NOT modify carol's file nor create there.
    # All write escapes aim at CAROL's tree (a sibling tenant bob has no access to).
    # The old "/stickytmp/../bob/cegt_plant3.txt" leg was dropped: it normalizes to
    # bob's OWN /bob/ dir (0755, bob-owned), where bob CAN legitimately create a
    # file -- that is correct ownership, not a sibling-tenant plant, so asserting
    # no_create on bob/cegt_plant3.txt false-failed.
    escape_writes = [
        ("/stickytmp/../carol/cegt_priv.txt", b"CLOBBERED\n"),
        ("/stickytmp/..%2fcarol%2fcegt_priv.txt", b"CLOBBERED\n"),
        ("/sgiddir/../carol/cegt_plant.txt", b"PLANT\n"),
        ("/sgiddir/..%2fcarol%2fcegt_plant2.txt", b"PLANT\n"),
        ("/stickytmp/..%2f..%2fcarol%2fcegt_plant3.txt", b"PLANT\n"),
    ]
    for p, d in escape_writes:
        http("PUT", p, port, tb, d)
    # carol's secret intact (not clobbered through the escape)?
    if carol_priv:
        try:
            still = open(carol_priv, "rb").read()
            ok(CAROL_SECRET in still and owner_of(carol_priv)[0] == UID_CAROL,
               "(B) carol's private file intact + still carol-owned after escape "
               "writes (no setgid/sticky clobber)")
        except OSError:
            ok(False, "(B) carol private file unreadable after escape writes")
    ok(no_create(os.path.join(data, "carol", "cegt_plant.txt"),
                 os.path.join(data, "carol", "cegt_plant2.txt"),
                 os.path.join(data, "carol", "cegt_plant3.txt")),
       "(B) escape-write out of setgid/sticky planted nothing in sibling tenant")
    # control: bob deleting HIS OWN sticky file is allowed (sticky lets owner rm).
    st, _ = http("DELETE", "/stickytmp/cegt_bob.txt", port, tb)
    ok(st in (200, 204, 404)
       and not os.path.exists(os.path.join(data, "stickytmp", "cegt_bob.txt")),
       f"control: bob DELETEs his OWN sticky file (sticky owner-rm allowed) "
       f"(HTTP {st})")
    # sticky NEGATIVE: bob may NOT delete alice's file in the sticky dir, even via
    # a normalizing path (sticky bit: only file/dir owner removes).
    st, _ = http("DELETE", "/stickytmp/../stickytmp/alice_owned.txt", port, tb)
    apath = os.path.join(data, "stickytmp", "alice_owned.txt")
    ok(os.path.exists(apath) and owner_of(apath)[0] == UID_ALICE,
       f"(B) bob CANNOT delete alice's file in sticky dir via normalizing path "
       f"(sticky enforced) (HTTP {st})")

    # =====================================================================
    # (C) CLIMB from a 0700 dir OUT to /etc/passwd.  Path begins inside a private
    #     dir (alice's 0700 / bob's 0700 bobsecret) and climbs out with encoding.
    #     /etc/passwd must never be read; bobsecret body must never leak to alice.
    # =====================================================================
    climb_reads_alice = [
        f"/{tag}_priv700/../../../../etc/passwd",
        f"/{tag}_priv700/..%2f..%2f..%2f..%2fetc%2fpasswd",
        f"/{tag}_priv700/....//....//....//etc/passwd",
        f"/{tag}_priv700/..;/..;/..;/etc/passwd",
        f"/{tag}_priv700/%2e%2e/%2e%2e/%2e%2e/etc/passwd",
        f"/{tag}_priv700/inner.txt%00/../../../etc/passwd",
    ]
    for p in climb_reads_alice:
        st, b = http("GET", p, port, ta)
        ok(clean_body(b),
           f"(C) alice climb out of own 0700 dir {p[:34]!r} no /etc leak (HTTP {st})")
    # alice climbs out of HER 0700 dir aiming at bob's 0700 bobsecret -> denied.
    climb_cross = [
        f"/{tag}_priv700/../bobsecret/s.txt",
        f"/{tag}_priv700/..%2fbobsecret%2fs.txt",
        "/bobsecret/../bobsecret/s.txt",                # normalize within bob's 0700
        "/bobsecret/%2e%2e/bobsecret/s.txt",
        "/alice/../bobsecret/s.txt",
    ]
    for p in climb_cross:
        st, b = http("GET", p, port, ta)
        ok(not _has(b, BOBS) and clean_body(b),
           f"(C) alice climb into bob's 0700 dir {p[:34]!r} no bob-secret leak "
           f"(HTTP {st})")
    # control: alice reads her OWN file inside her 0700 dir via a normalizing path.
    st, b = http("GET", f"/{tag}_priv700/../{tag}_priv700/inner.txt", port, ta)
    ok(st in (200, 404) and not _has(b, BOBS) and PW not in (b or b""),
       f"control: alice reads own 0700-dir file via normalize (owner allowed) "
       f"(HTTP {st})")

    # =====================================================================
    # (D) NORMALIZE INTO ANOTHER TENANT'S TREE: a path that, after collapsing,
    #     points at a sibling tenant's PRIVATE file — across protocols.  The
    #     normalization must not become an authorization bypass; per-file/dir DAC
    #     still applies under the MAPPED identity.
    # =====================================================================
    normalize_into = [
        "/alice/foo/../../bob/private.txt",
        "/alice/a/b/../../../bob/private.txt",
        "/alice/%2e%2e/bob/private.txt",
        "/alice/..%2fbob%2fprivate.txt",
        "/alice/./../bob/private.txt",
        "/staffdir/../bob/private.txt",
        "/sgiddir/../bobsecret/s.txt",
        "/alice/x/..%2f..%2fcarol/cegt_priv.txt",
        "/alice/foo/../../svconly/secret-name.txt",
    ]
    for p in normalize_into:
        st, b = http("GET", p, port, ta)
        ok(not _has(b, BOB) and not _has(b, BOBS) and not _has(b, CAROL_SECRET)
           and not _has(b, SVC) and PW not in (b or b""),
           f"(D) alice normalize-into-sibling GET {p[:34]!r} no cross-tenant/svc "
           f"leak (HTTP {st})")
    # control: bob (the OWNER) reads bob/private.txt via the SAME normalizing shape
    #          -> proves the normalize itself resolves; the deny above was DAC, not
    #          a path-rejection.
    st, b = http("GET", "/bob/foo/../../bob/private.txt", port, tb)
    ok(st in (200, 404) and (st == 404 or _has(b, BOB)),
       f"control: bob reads own private.txt via normalizing path (owner DAC) "
       f"(HTTP {st})")

    # WebDAV MOVE/COPY Destination that normalizes into a group/sibling target:
    # bob tries to MOVE his own file so it lands inside the staff group dir or in
    # carol's tree — must not land there.
    http("PUT", "/bob/cegt_movesrc.txt", port, tb, b"MOVE-SRC-CEGT\n")
    dest_norm = [
        f"http://127.0.0.1:{port}/bob/../staffdir/cegt_moved.txt",
        f"http://127.0.0.1:{port}/bob/..%2fstaffdir%2fcegt_moved2.txt",
        f"http://127.0.0.1:{port}/bob/../carol/cegt_moved3.txt",
        f"http://127.0.0.1:{port}/sgiddir/cegt_moved4.txt",
    ]
    for d in dest_norm:
        http("COPY", "/bob/cegt_movesrc.txt", port, tb, hdrs={"Destination": d})
    ok(no_create(os.path.join(data, "staffdir", "cegt_moved.txt"),
                 os.path.join(data, "staffdir", "cegt_moved2.txt"),
                 os.path.join(data, "carol", "cegt_moved3.txt"),
                 os.path.join(data, "sgiddir", "cegt_moved4.txt")),
       "(D) bob COPY Destination normalizing into staff/carol/setgid created "
       "nothing there")
    # control: in-tenant COPY for bob still works + owned by bob.
    st, _ = http("COPY", "/bob/cegt_movesrc.txt", port, tb,
                 hdrs={"Destination": f"http://127.0.0.1:{port}/bob/cegt_copyok.txt"})
    cpok = os.path.join(data, "bob", "cegt_copyok.txt")
    ok(st in (200, 201, 204) and os.path.exists(cpok)
       and owner_of(cpok)[0] == UID_BOB,
       f"control: bob in-tenant COPY OK, owned bob (HTTP {st})")

    # =====================================================================
    # (E) S3 key + copy-source ENCODING vs group/sticky/cross-tenant targets
    #     (signed as alice; alice is staff so use a target alice's group does NOT
    #     reach — research/bob — and the svc-only dir).
    # =====================================================================
    if s3port:
        s3_grp_keys = [
            "staffdir/inside.txt",                       # alice IS staff -> may read
            "execonly/known.txt",                        # group --x: dir not readable
            "bobsecret/s.txt",                           # bob 0700: deny
            "bobsecret%2fs.txt",
            "alice/../bobsecret/s.txt",
            "sgiddir/../bobsecret/s.txt",
            "..%2f..%2f..%2fetc%2fpasswd",
            "stickytmp/../carol/cegt_priv.txt",
            "stickytmp/..%2fcarol%2fcegt_priv.txt",
            "sgiddir/..%2fbob%2fprivate.txt",
        ]
        for k in s3_grp_keys:
            st, b = s3("GET", k, s3port)
            # NOTE: the S3 access key is alice (uid 1001).  alice IS staff, so
            # staffdir/inside.txt MAY legitimately return; and alice OWNS
            # execonly/known.txt (0640 alice:staff, owner-read), so reading EXEC for
            # THAT key is an owner read, NOT a leak.  The invariant is "no FORBIDDEN
            # secret of a NON-reachable target leaks" — a cross-tenant/group-non-member
            # secret (bob/carol/svc/etc) or EXEC surfacing through an ENCODED ESCAPE
            # into the alice-owned file from some other dir.
            owns_exec = (k == "execonly/known.txt")   # alice owns this 0640 file
            forbidden_leak = (_has(b, BOBS) or _has(b, BOB) or _has(b, CAROL_SECRET)
                              or _has(b, SVC) or PW in (b or b"")
                              or (not owns_exec and _has(b, EXEC)))
            ok(not forbidden_leak,
               f"(E) S3 GET enc key {k[:30]!r} no forbidden group/tenant/svc leak "
               f"(HTTP {st})")

        # S3 PUT encoded keys aimed at the group/sticky/cross-tenant dirs as alice —
        # the ones alice's identity may NOT write (bob's tree, svconly) create
        # nothing; nothing escapes the export.
        s3_put_keys = [
            "bobsecret/cegt_s3.txt",
            "bob/..%2fbob%2fcegt_s3b.txt",
            "svconly/cegt_s3c.txt",
            "..%2f..%2fCEGT_S3_OUT.txt",
            "carol/..%2fcarol%2fcegt_s3d.txt",
        ]
        for k in s3_put_keys:
            s3("PUT", k, s3port, data=b"s3-intrude\n")
        ok(no_create(
            os.path.join(data, "bobsecret", "cegt_s3.txt"),
            os.path.join(data, "svconly", "cegt_s3c.txt"),
            os.path.join(parent1, "CEGT_S3_OUT.txt"),
            os.path.join(parent2, "CEGT_S3_OUT.txt")),
           "(E) S3 encoded PUT into bob-0700/svconly/outside created nothing "
           "forbidden")

        # S3 CopyObject copy-source ENCODING that climbs out of one dir into a
        # group/sibling secret — the destination must not contain the secret bytes.
        cs_variants = [
            f"/{S3_BUCKET}/sgiddir/..%2fbobsecret%2fs.txt",
            f"/{S3_BUCKET}/stickytmp/../carol/cegt_priv.txt",
            f"/{S3_BUCKET}/alice/..%2fbob%2fprivate.txt",
            f"/{S3_BUCKET}/execonly/known.txt",
            f"/{S3_BUCKET}/..%2f..%2f..%2fetc%2fpasswd",
        ]
        for i, cs in enumerate(cs_variants):
            dstkey = f"alice/cegt_cs_{i}.bin"
            st, _ = s3("PUT", dstkey, s3port,
                       extra_hdrs={"x-amz-copy-source": cs})
            dpath = os.path.join(data, "alice", f"cegt_cs_{i}.bin")
            # The signer is alice (uid 1001).  copy-source execonly/known.txt is
            # alice's OWN 0640 file (owner-read), so copying EXEC from THAT clean
            # source into alice's own tree is a legit owner copy, NOT exfil.  EXEC is
            # only a violation if it lands via an ENCODED ESCAPE source (a ..%2f climb
            # out of another dir) rather than the direct owner key.
            owns_src = (cs == f"/{S3_BUCKET}/execonly/known.txt")
            leaked = False
            try:
                if os.path.exists(dpath):
                    c = open(dpath, "rb").read()
                    leaked = (BOBS in c or BOB in c or CAROL_SECRET in c or PW in c
                              or (not owns_src and EXEC in c))
            except OSError:
                leaked = False
            ok(not leaked,
               f"(E) S3 CopyObject enc src {cs[len(S3_BUCKET)+2:][:24]!r} did not "
               f"exfil group/tenant secret (HTTP {st})")

        # S3 control: alice's OWN nested encoded key round-trips + owned by alice.
        st, _ = s3("PUT", "alice/cegt_s3ok.txt", s3port, data=b"S3-CEGT-OK\n")
        st2, b = s3("GET", "alice/cegt_s3ok.txt", s3port)
        ok(st in (200, 201) and st2 == 200 and _has(b, b"S3-CEGT-OK"),
           f"control: S3 alice own key round-trips (HTTP {st}/{st2})")
        okp = os.path.join(data, "alice", "cegt_s3ok.txt")
        ok(os.path.exists(okp) and owner_of(okp)[0] == UID_ALICE,
           "control: S3-created object owned by alice")

    # =====================================================================
    # (F) root:// (stream) stat/cat/mkdir ENCODING vs group/setgid/sticky/sibling.
    # =====================================================================
    if not xrd_avail():
        ok(True, "(F) root:// combo-encoding skipped (native client absent)")
    else:
        # bob (non-staff) stat/cat the staff group dir via normalizing paths -> deny,
        # no staff body.
        root_grp = [
            "/staffdir/inside.txt",
            "/staffdir/../staffdir/inside.txt",
            "/sgiddir/../staffdir/inside.txt",
            "/execonly/known.txt",
            "/alice/../staffdir/inside.txt",
        ]
        for p in root_grp:
            rc, out, _e = xrd_fs(["cat", p], "bob")
            ok(rc != 0 and "INSIDE-STAFF-DIR" not in (out or "")
               and "EXECONLY-KNOWN" not in (out or ""),
               f"(F) root:// bob(non-staff) cat {p[:30]!r} group-DAC deny, no "
               f"staff/exec leak (rc={rc})")

        # alice climbs out of setgid/sticky into bob's 0700 + /etc -> deny.
        root_climb = [
            "/sgiddir/../bobsecret/s.txt",
            "/stickytmp/../bob/private.txt",
            f"/{tag}_priv700/../../../../etc/passwd",
            "/sgiddir/..%2f..%2f..%2fetc%2fpasswd",
        ]
        for p in root_climb:
            rc, out, _e = xrd_fs(["cat", p], "alice")
            ok(rc != 0 and "bob-only" not in (out or "")
               and "BOB-PRIVATE-SECRET" not in (out or "")
               and "root:x:" not in (out or ""),
               f"(F) root:// alice climb-out {p[:30]!r} deny, no bob/etc leak "
               f"(rc={rc})")

        # bob mkdir via normalize INTO the staff group dir -> creates nothing.
        xrd_fs(["mkdir", "/staffdir/../staffdir/cegt_rootdir"], "bob")
        xrd_fs(["mkdir", "/sgiddir/cegt_rootdir2"], "bob")
        ok(no_create(os.path.join(data, "staffdir", "cegt_rootdir"),
                     os.path.join(data, "sgiddir", "cegt_rootdir2")),
           "(F) root:// bob mkdir into staff/setgid group dir created nothing")

        # root:// stat a sibling tenant's private file via normalize -> deny, but
        # the path itself is valid (control proves owner can stat it).
        rc, _o, _e = xrd_fs(["stat", "/alice/../bobsecret/s.txt"], "alice")
        ok(rc != 0,
           f"(F) root:// alice stat into bob's 0700 via normalize denied (rc={rc})")
        rc, _o, _e = xrd_fs(["stat", "/bobsecret/s.txt"], "bob")
        ok(rc == 0,
           f"control: root:// bob (owner) stats own bobsecret file (rc={rc})")

        # root:// control: alice mkdir + write under HER setgid-member dir works and
        # the new dir inherits the staff gid (setgid + member, encoded-normalize).
        rc, _o, _e = xrd_fs(["mkdir", "/sgiddir/../sgiddir/cegt_member"], "alice")
        memd = os.path.join(data, "sgiddir", "cegt_member")
        ok(rc == 0 and os.path.isdir(memd) and owner_of(memd)[1] == GID_STAFF,
           f"control: root:// alice(staff) mkdir under setgid dir inherits staff gid "
           f"(rc={rc})")

    # =====================================================================
    # (G) GRAND INVARIANTS — nothing landed in any forbidden/outside location, the
    #     protected fixtures are byte-intact + correctly owned, worker SURVIVES.
    # =====================================================================
    ok(no_create(
        os.path.join(parent1, "CEGT_S3_OUT.txt"),
        os.path.join(parent2, "CEGT_S3_OUT.txt"),
        "/etc/CEGT_S3_OUT.txt"),
       "(G) GRAND INVARIANT: no attack file landed outside the export root")
    # staff group dir still owned alice:staff at mode 0770 (no encoding flipped it).
    ok(owner_of(os.path.join(data, "staffdir")) == (UID_ALICE, GID_STAFF)
       and mode_of(os.path.join(data, "staffdir")) == 0o770,
       "(G) staffdir still alice:staff 0770 after the encoding battery")
    # setgid bit still set on sgiddir (no op stripped it).
    ok(mode_of(os.path.join(data, "sgiddir")) == 0o2770,
       "(G) sgiddir setgid bit (02770) intact after the battery")
    # sticky bit still set on stickytmp.
    ok(mode_of(os.path.join(data, "stickytmp")) == 0o1777,
       "(G) stickytmp sticky bit (01777) intact after the battery")
    # bob's private file untouched + still owned bob.
    bpriv = os.path.join(data, "bob", "private.txt")
    try:
        ok(open(bpriv, "rb").read() == b"BOB-PRIVATE-SECRET\n"
           and owner_of(bpriv)[0] == UID_BOB,
           "(G) bob/private.txt byte-intact + still bob-owned (no encoded write hit "
           "it)")
    except OSError:
        ok(False, "(G) bob/private.txt unreadable post-battery")
    # carol's private file untouched.
    if carol_priv:
        try:
            ok(open(carol_priv, "rb").read() == CAROL_SECRET + b"\n",
               "(G) carol private file byte-intact (no setgid/sticky escape clobber)")
        except OSError:
            ok(False, "(G) carol private file unreadable post-battery")

    # Worker SURVIVES the whole combination battery: a fresh legit op still works
    # and lands owned by the mapped user (no crash / no principal corruption).
    st, _ = http("PUT", "/alice/cegt_survive.txt", port, ta, b"CEGT-SURVIVE\n")
    sp = os.path.join(data, "alice", "cegt_survive.txt")
    ok(st in (200, 201, 204) and os.path.exists(sp)
       and owner_of(sp)[0] == UID_ALICE,
       f"(G) worker SURVIVES battery: legit alice PUT owned by alice (HTTP {st})")
    st, b = http("GET", "/alice/cegt_survive.txt", port, ta)
    ok(st == 200 and _has(b, b"CEGT-SURVIVE"),
       f"(G) worker SURVIVES battery: legit GET round-trips (HTTP {st})")
    # and a group-DAC GRANT still works post-battery (carol reads staffdir).
    # staffdir/inside.txt is a SHARED fixture an earlier batch legitimately
    # rewrites (carol re-PUT), and _reset_fixtures restores the dir but not this
    # child's content -> assert the GRANT (carol still gets 200 + a real body)
    # without pinning the stale canonical marker, and no OTHER-tenant secret leaks.
    st, b = http("GET", "/staffdir/inside.txt", port, tc)
    ok(st == 200 and bool(b)
       and PW not in (b or b"") and BOB not in (b or b"")
       and BOBS not in (b or b"") and SVC not in (b or b""),
       f"(G) post-battery group GRANT still works: carol reads staffdir (HTTP {st})")

    # Cleanup the local fixtures we planted so later batteries see a clean tree.
    for p in (priv700_secret, os.path.join(priv700, "x")):
        try:
            if os.path.exists(p):
                os.remove(p)
        except OSError:
            pass
    try:
        if os.path.isdir(priv700):
            os.rmdir(priv700)
    except OSError:
        pass


def run_combo_concurrent_crossproto(key, data, port, s3port):
    """CONCURRENT cross-PROTOCOL access to the SAME physical resource.  Concurrency
    and cross-protocol are each covered in isolation by earlier batches; the COMBO
    here is the two together: while one protocol mutates an inode, ANOTHER protocol
    (different code path, different worker code, possibly a still-open data-plane fd)
    touches the SAME inode under a possibly-DIFFERENT identity.  Every check asserts
    a real property of that interleaving: (i) a reader sees a CONSISTENT whole value
    (old-or-new, never torn/half/cross), (ii) the surviving inode is owned by a REAL
    mapped writer (never svc 1500 / root 0 / the wrong tenant), and (iii) per-identity
    byte patterns prove the per-worker principal + already-open fd never aliases one
    tenant's bytes onto another's request.  <=8 threads, payloads <=64 KiB."""
    TAG = "ccxp"
    ta, tb = mint(key, "alice"), mint(key, "bob")
    have_s3 = bool(s3port)
    have_root = xrd_avail()

    def rel(*parts):
        return os.path.join(data, *parts)

    def uid_of(p):
        try:
            return os.stat(p).st_uid
        except OSError:
            return -1

    def gid_of(p):
        try:
            return os.stat(p).st_gid
        except OSError:
            return -1

    def body_of(p):
        try:
            with open(p, "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def real_writer(p):
        """Inode owned by an actual mapped writer, never worker/root."""
        u = uid_of(p)
        return os.path.exists(p) and u in (UID_ALICE, UID_BOB) and u not in (UID_SVC, 0)

    # Detectable per-identity byte patterns: a whole body is a single repeated tag,
    # so a torn/spliced read is detectable as a mix of two distinct tag bytes.
    def whole(tag, n):
        unit = (tag + "-CCXP-WHOLE|").encode()
        return (unit * ((n // len(unit)) + 1))[:n]

    SZ = 48 * 1024                                   # <=64 KiB payload
    A_OLD = whole("AAAA-OLD", SZ)
    A_NEW = whole("AAAA-NEW", SZ)
    B_VAL = whole("BBBB-BOB", SZ)

    def is_whole(buf, *candidates):
        """buf is byte-identical to ONE candidate whole value (never torn/mixed)."""
        return any(buf == c for c in candidates)

    def torn_markers(buf):
        """Count how many distinct identity tags appear -> >1 means a torn/cross read."""
        seen = set()
        for tag in (b"AAAA-OLD", b"AAAA-NEW", b"BBBB-BOB"):
            if tag in buf:
                seen.add(tag)
        return seen

    # ===================================================================
    # (a) alice WebDAV-PUTs X while bob root://-reads X (X starts 0644).
    #     bob must see a CONSISTENT whole version (old or new), X stays
    #     owned by its owner, and no torn/cross bytes ever surface.
    # ===================================================================
    relx = "alice/%s_a_x.txt" % TAG
    fpx = rel("alice", "%s_a_x.txt" % TAG)
    # seed the file with the OLD whole value, mode 0644 (group/other readable so a
    # cross-protocol reader is a real read, not a DAC deny masking the race).
    st, _ = http("PUT", "/" + relx, port, ta, A_OLD)
    try:
        if os.path.exists(fpx):
            os.chmod(fpx, 0o644)
    except OSError:
        pass
    ok(st in (200, 201, 204) and uid_of(fpx) == UID_ALICE,
       "(a) seed alice/X 0644 owned by alice before cross-proto race (HTTP %s, uid=%s)"
       % (st, uid_of(fpx)))

    if have_root:
        reads = []          # whole buffers bob's root:// reads observed
        rerr = []
        torn = []

        def a_writer():
            for _ in range(4):
                try:
                    http("PUT", "/" + relx, port, ta, A_NEW)
                    http("PUT", "/" + relx, port, ta, A_OLD)
                except Exception as e:        # noqa: BLE001
                    rerr.append(repr(e))

        def a_reader(i):
            dl = os.path.join(WORK, "%s_a_dl_%d.bin" % (TAG, i))
            try:
                if os.path.exists(dl):
                    os.unlink(dl)
            except OSError:
                pass
            rc, _o, _e = xrd_cp_down("/" + relx, dl, "bob")
            if rc == 0:
                b = body_of(dl)
                reads.append(b)
                if len(torn_markers(b)) > 1:
                    torn.append(len(b))

        threads = [threading.Thread(target=a_writer)]
        threads += [threading.Thread(target=a_reader, args=(i,)) for i in range(5)]
        for t in threads:
            t.start()
        for t in threads:
            t.join()

        ok(not torn,
           "(a) bob root:// read during alice WebDAV-PUT never torn/mixed (torn=%s)"
           % torn[:2])
        ok(all(is_whole(b, A_OLD, A_NEW) for b in reads),
           "(a) every successful bob read is a CONSISTENT whole version (n=%d)"
           % len(reads))
        ok(uid_of(fpx) == UID_ALICE and uid_of(fpx) not in (UID_SVC, 0),
           "(a) X stays owned by alice after concurrent cross-proto race (uid=%s)"
           % uid_of(fpx))
        ok(is_whole(body_of(fpx), A_OLD, A_NEW),
           "(a) X on disk is a whole writer value after the race (no half-write)")
    else:
        ok(True, "(a) root:// reader skipped (native client absent)")
        ok(True, "(a) consistency skipped (native client absent)")
        ok(True, "(a) ownership skipped (native client absent)")
        ok(True, "(a) disk-whole skipped (native client absent)")

    # cross-tenant twist on (a): while alice rewrites X, bob WebDAV-GET of a 0600
    # sibling secret must still be denied (the concurrent benign read must not open a
    # window that leaks a sibling secret under the racing principal).
    rels = "alice/%s_a_secret.txt" % TAG
    fps = rel("alice", "%s_a_secret.txt" % TAG)
    SECRET = b"CCXP-A-SIBLING-SECRET-" + b"S" * 256
    http("PUT", "/" + rels, port, ta, SECRET)
    try:
        if os.path.exists(fps):
            os.chmod(fps, 0o600)
    except OSError:
        pass
    leaked_a = []

    def a_secret_probe():
        for _ in range(6):
            stp, bp = http("GET", "/" + rels, port, tb)
            if stp == 200 or SECRET in (bp or b""):
                leaked_a.append(stp)

    def a_noise():
        for _ in range(6):
            http("PUT", "/" + relx, port, ta, A_NEW)

    t1 = threading.Thread(target=a_secret_probe)
    t2 = threading.Thread(target=a_noise)
    t1.start(); t2.start(); t1.join(); t2.join()
    ok(not leaked_a,
       "(a) bob's 0600-secret GET stays denied under concurrent alice write-noise")
    ok(SECRET[:24] not in body_of(fpx),
       "(a) sibling secret bytes never bleed into the raced file X")

    # ===================================================================
    # (b) alice S3-PUTs an object while alice WebDAV-GETs it: SAME identity,
    #     TWO protocols, ONE inode -> no torn read, ownership stays alice.
    # ===================================================================
    if have_s3:
        relb = "alice/%s_b_obj.txt" % TAG
        fpb = rel("alice", "%s_b_obj.txt" % TAG)
        s3("PUT", relb, s3port, data=A_OLD)         # seed
        gtorn = []
        greads = []
        gerr = []

        def b_s3_writer():
            for _ in range(4):
                try:
                    s3("PUT", relb, s3port, data=A_NEW)
                    s3("PUT", relb, s3port, data=A_OLD)
                except Exception as e:    # noqa: BLE001
                    gerr.append(repr(e))

        def b_wd_reader(i):
            stg, bg = http("GET", "/" + relb, port, ta)
            if stg == 200 and bg:
                greads.append(bg)
                if len(torn_markers(bg)) > 1:
                    gtorn.append(len(bg))

        threads = [threading.Thread(target=b_s3_writer)]
        threads += [threading.Thread(target=b_wd_reader, args=(i,)) for i in range(5)]
        for t in threads:
            t.start()
        for t in threads:
            t.join()

        ok(not gtorn,
           "(b) alice WebDAV-GET during alice S3-PUT never torn (torn=%s)" % gtorn[:2])
        ok(all(is_whole(b, A_OLD, A_NEW) for b in greads),
           "(b) every WebDAV read of the S3-written object is whole (n=%d)" % len(greads))
        ok(uid_of(fpb) == UID_ALICE and uid_of(fpb) not in (UID_SVC, 0),
           "(b) cross-proto same-identity object stays alice-owned (uid=%s)"
           % uid_of(fpb))
        ok(is_whole(body_of(fpb), A_OLD, A_NEW),
           "(b) S3/WebDAV-raced object on disk is a whole value (no torn S3 write)")
        ok(not gerr, "(b) no exceptions during S3-write/WebDAV-read race (%s)" % gerr[:2])
    else:
        for _m in ("torn", "whole", "owner", "disk", "noerr"):
            ok(True, "(b) S3/WebDAV cross-proto race skipped (%s; S3 down)" % _m)

    # ===================================================================
    # (c) root:// WRITE + S3 READ on the SAME path concurrently by the SAME
    #     identity (alice) -> data consistent, no fd aliasing (a still-open
    #     root data-plane fd must not feed the S3 reader stale/foreign bytes).
    # ===================================================================
    if have_root and have_s3:
        relc = "alice/%s_c_path.bin" % TAG
        fpc = rel("alice", "%s_c_path.bin" % TAG)
        s3("PUT", relc, s3port, data=A_OLD)         # seed via S3
        lf_new = os.path.join(WORK, "%s_c_new.bin" % TAG)
        lf_old = os.path.join(WORK, "%s_c_old.bin" % TAG)
        try:
            with open(lf_new, "wb") as fh:
                fh.write(A_NEW)
            with open(lf_old, "wb") as fh:
                fh.write(A_OLD)
        except OSError:
            pass
        ctorn = []
        creads = []

        def c_root_writer():
            for _ in range(4):
                xrd_cp_up(lf_new, "/" + relc, "alice")
                xrd_cp_up(lf_old, "/" + relc, "alice")

        def c_s3_reader(i):
            stc, bc = s3("GET", relc, s3port, access_key="alice")
            if stc == 200 and bc:
                creads.append(bc)
                if len(torn_markers(bc)) > 1:
                    ctorn.append(len(bc))

        threads = [threading.Thread(target=c_root_writer)]
        threads += [threading.Thread(target=c_s3_reader, args=(i,)) for i in range(5)]
        for t in threads:
            t.start()
        for t in threads:
            t.join()

        ok(not ctorn,
           "(c) S3 read during root:// write never torn/fd-aliased (torn=%s)"
           % ctorn[:2])
        ok(all(is_whole(b, A_OLD, A_NEW) for b in creads),
           "(c) every S3 read of root-written path is a whole value (n=%d)"
           % len(creads))
        ok(B_VAL not in b"".join(creads),
           "(c) no foreign-tenant bytes ever fed to the S3 reader (no fd aliasing)")
        ok(uid_of(fpc) == UID_ALICE and uid_of(fpc) not in (UID_SVC, 0),
           "(c) root-write/S3-read same path stays alice-owned (uid=%s)" % uid_of(fpc))
        ok(is_whole(body_of(fpc), A_OLD, A_NEW),
           "(c) final inode is a whole writer value (root data-plane fd not torn)")
    else:
        for _m in ("torn", "whole", "noforeign", "owner", "disk"):
            ok(True, "(c) root-write/S3-read race skipped (%s; deps down)" % _m)

    # ===================================================================
    # (d) alice writes /pub/shared via WebDAV while bob writes it via root://
    #     (pub is 0777) -> final file owned by ONE real writer (never svc/root),
    #     content is exactly one writer's WHOLE value (no interleaved bytes).
    # ===================================================================
    reld = "pub/%s_d_shared.bin" % TAG
    fpd = rel("pub", "%s_d_shared.bin" % TAG)
    lf_bob = os.path.join(WORK, "%s_d_bob.bin" % TAG)
    if have_root:
        try:
            with open(lf_bob, "wb") as fh:
                fh.write(B_VAL)
        except OSError:
            pass
    derr = []

    def d_wd_alice():
        for _ in range(5):
            try:
                http("PUT", "/" + reld, port, ta, A_NEW)
            except Exception as e:        # noqa: BLE001
                derr.append(repr(e))

    def d_root_bob():
        for _ in range(5):
            xrd_cp_up(lf_bob, "/" + reld, "bob")

    dthreads = [threading.Thread(target=d_wd_alice)]
    if have_root:
        dthreads.append(threading.Thread(target=d_root_bob))
    for t in dthreads:
        t.start()
    for t in dthreads:
        t.join()

    if os.path.exists(fpd):
        du = uid_of(fpd)
        db = body_of(fpd)
        ok(du in (UID_ALICE, UID_BOB) and du not in (UID_SVC, 0),
           "(d) pub/shared raced by two protocols owned by ONE real writer (uid=%s)" % du)
        cands = [A_NEW] + ([B_VAL] if have_root else [])
        ok(is_whole(db, *cands),
           "(d) pub/shared content is exactly one writer's WHOLE value (no interleave)")
        ok(len(torn_markers(db)) <= 1,
           "(d) pub/shared never carries two writers' bytes spliced together")
        # owner must MATCH the winning content (no svc inode wearing a writer's bytes).
        if db == A_NEW:
            ok(du == UID_ALICE, "(d) winner=alice content -> alice-owned (uid=%s)" % du)
        elif have_root and db == B_VAL:
            ok(du == UID_BOB, "(d) winner=bob content -> bob-owned (uid=%s)" % du)
        else:
            ok(False, "(d) pub/shared content is not a recognized whole writer value")
    else:
        ok(False, "(d) pub/shared file missing after two-protocol storm")
        ok(False, "(d) content skipped (missing)")
        ok(False, "(d) splice skipped (missing)")
        ok(False, "(d) owner-content-match skipped (missing)")
    ok(not derr, "(d) no exceptions during WebDAV/root pub/shared race (%s)" % derr[:2])

    # ===================================================================
    # (e) concurrent reads of DIFFERENT tenants' files via DIFFERENT protocols:
    #     each thread must get ITS OWN tenant's bytes, ZERO cross-contamination.
    #     This is the core impersonation isolation property under cross-proto load.
    # ===================================================================
    # plant alice/bob 0644 files with per-tenant whole bodies.
    rel_ae = "alice/%s_e_alice.txt" % TAG
    rel_be = "bob/%s_e_bob.txt" % TAG
    fp_ae, fp_be = rel("alice", "%s_e_alice.txt" % TAG), rel("bob", "%s_e_bob.txt" % TAG)
    http("PUT", "/" + rel_ae, port, ta, A_NEW)
    http("PUT", "/" + rel_be, port, tb, B_VAL)
    for fp in (fp_ae, fp_be):
        try:
            if os.path.exists(fp):
                os.chmod(fp, 0o644)
        except OSError:
            pass
    ok(uid_of(fp_ae) == UID_ALICE and uid_of(fp_be) == UID_BOB,
       "(e) per-tenant fixtures owned correctly before cross-read storm")

    cross = []          # records (who, wrong-bytes-seen)
    mism = []           # records (who, status, len)

    def e_wd_alice():
        for _ in range(4):
            ste, be = http("GET", "/" + rel_ae, port, ta)
            if ste == 200:
                if be != A_NEW:
                    mism.append(("wd-alice", ste, len(be or b"")))
                if B_VAL[:16] in (be or b""):
                    cross.append(("wd-alice", "saw-bob"))

    def e_s3_alice():
        if not have_s3:
            return
        for _ in range(4):
            ste, be = s3("GET", rel_ae.replace("alice/", "alice/"), s3port,
                         access_key="alice")
            if ste == 200:
                if be != A_NEW:
                    mism.append(("s3-alice", ste, len(be or b"")))
                if B_VAL[:16] in (be or b""):
                    cross.append(("s3-alice", "saw-bob"))

    def e_wd_bob():
        for _ in range(4):
            ste, be = http("GET", "/" + rel_be, port, tb)
            if ste == 200:
                if be != B_VAL:
                    mism.append(("wd-bob", ste, len(be or b"")))
                if A_NEW[:16] in (be or b""):
                    cross.append(("wd-bob", "saw-alice"))

    def e_root_bob():
        if not have_root:
            return
        for i in range(3):
            dl = os.path.join(WORK, "%s_e_root_%d.bin" % (TAG, i))
            try:
                if os.path.exists(dl):
                    os.unlink(dl)
            except OSError:
                pass
            rc, _o, _e = xrd_cp_down("/" + rel_be, dl, "bob")
            if rc == 0:
                be = body_of(dl)
                if be != B_VAL:
                    mism.append(("root-bob", rc, len(be)))
                if A_NEW[:16] in be:
                    cross.append(("root-bob", "saw-alice"))

    ethreads = [
        threading.Thread(target=e_wd_alice),
        threading.Thread(target=e_wd_bob),
        threading.Thread(target=e_s3_alice),
        threading.Thread(target=e_root_bob),
    ]
    for t in ethreads:
        t.start()
    for t in ethreads:
        t.join()

    ok(not cross,
       "(e) cross-protocol concurrent reads: ZERO cross-tenant contamination (%s)"
       % cross[:3])
    ok(not mism,
       "(e) every reader got exactly ITS OWN tenant's whole bytes (mismatch=%s)"
       % mism[:3])
    # explicit per-leg controls so a blanket failure cannot false-pass.
    ste, be = http("GET", "/" + rel_ae, port, ta)
    ok(ste == 200 and be == A_NEW and B_VAL[:16] not in be,
       "(e) WebDAV alice read = alice bytes, no bob bytes (HTTP %s)" % ste)
    ste, be = http("GET", "/" + rel_be, port, tb)
    ok(ste == 200 and be == B_VAL and A_NEW[:16] not in be,
       "(e) WebDAV bob read = bob bytes, no alice bytes (HTTP %s)" % ste)
    if have_s3:
        ste, be = s3("GET", rel_ae, s3port, access_key="alice")
        ok(ste == 200 and be == A_NEW and B_VAL[:16] not in be,
           "(e) S3 alice read = alice bytes, no bob bytes (HTTP %s)" % ste)
    else:
        ok(True, "(e) S3 alice-read control skipped (S3 down)")
    if have_root:
        dl = os.path.join(WORK, "%s_e_ctrl.bin" % TAG)
        try:
            if os.path.exists(dl):
                os.unlink(dl)
        except OSError:
            pass
        rc, _o, _e = xrd_cp_down("/" + rel_be, dl, "bob")
        ok(rc == 0 and body_of(dl) == B_VAL and A_NEW[:16] not in body_of(dl),
           "(e) root:// bob read = bob bytes, no alice bytes (rc=%s)" % rc)
    else:
        ok(True, "(e) root:// bob-read control skipped (native client absent)")

    # cross-tenant DENY under the same concurrent storm: bob reading alice's 0600
    # secret via WebDAV while the (e) storm runs must STILL be denied (isolation is
    # not just "right bytes" but also "no access where DAC forbids it").
    http("PUT", "/" + rels, port, ta, SECRET)
    try:
        if os.path.exists(fps):
            os.chmod(fps, 0o600)
    except OSError:
        pass
    eleak = []

    def e_storm_noise():
        for _ in range(6):
            http("GET", "/" + rel_ae, port, ta)
            if have_s3:
                s3("GET", rel_be.replace("bob/", "bob/"), s3port, access_key="alice")

    def e_secret_probe():
        for _ in range(6):
            stp, bp = http("GET", "/" + rels, port, tb)
            if stp == 200 or SECRET[:24] in (bp or b""):
                eleak.append(stp)

    t1 = threading.Thread(target=e_storm_noise)
    t2 = threading.Thread(target=e_secret_probe)
    t1.start(); t2.start(); t1.join(); t2.join()
    ok(not eleak,
       "(e) bob's 0600-secret stays denied under concurrent cross-proto read storm")

    # positive control for the deny: alice CAN read her own secret (the deny above is
    # a real DAC deny, not a server-wide outage that would false-pass the negative).
    sta, ba = http("GET", "/" + rels, port, ta)
    ok(sta == 200 and SECRET[:24] in (ba or b""),
       "(e) control: alice reads her own secret post-storm (HTTP %s)" % sta)

    # ===================================================================
    # (f) WORKER-SURVIVAL after all the cross-proto concurrency: a follow-up legit
    #     op across each protocol still works AND lands with correct ownership (the
    #     per-worker principal was fully reset; no stale fd/identity wedged a worker).
    # ===================================================================
    relf = "alice/%s_f_after.txt" % TAG
    fpf = rel("alice", "%s_f_after.txt" % TAG)
    stf, _ = http("PUT", "/" + relf, port, ta, b"CCXP-AFTER-WEBDAV\n")
    ok(stf in (200, 201, 204) and uid_of(fpf) == UID_ALICE,
       "(f) survival: WebDAV PUT works + alice-owned after the storm (HTTP %s, uid=%s)"
       % (stf, uid_of(fpf)))
    stf, bf = http("GET", "/" + relf, port, ta)
    ok(stf == 200 and bf == b"CCXP-AFTER-WEBDAV\n",
       "(f) survival: WebDAV GET returns correct whole bytes (HTTP %s)" % stf)

    if have_s3:
        stf, _ = s3("PUT", "alice/%s_f_s3.txt" % TAG, s3port, data=b"CCXP-AFTER-S3\n")
        fpf3 = rel("alice", "%s_f_s3.txt" % TAG)
        ok(stf in (200, 201) and uid_of(fpf3) == UID_ALICE,
           "(f) survival: S3 PUT works + alice-owned after the storm (HTTP %s, uid=%s)"
           % (stf, uid_of(fpf3)))
    else:
        ok(True, "(f) survival S3 skipped (S3 down)")

    if have_root:
        rc, out, _e = xrd_fs(["stat", "/" + relf], "alice")
        ok(rc == 0, "(f) survival: root:// stat works after the storm (rc=%s)" % rc)
        # and a fresh root write is alice-owned (principal fully reset).
        lf = os.path.join(WORK, "%s_f_root.bin" % TAG)
        try:
            with open(lf, "wb") as fh:
                fh.write(b"CCXP-AFTER-ROOT\n")
        except OSError:
            pass
        rc, _o, _e = xrd_cp_up(lf, "/alice/%s_f_root.bin" % TAG, "alice")
        fpr = rel("alice", "%s_f_root.bin" % TAG)
        ok(rc == 0 and uid_of(fpr) == UID_ALICE and uid_of(fpr) not in (UID_SVC, 0),
           "(f) survival: root:// write works + alice-owned (rc=%s, uid=%s)"
           % (rc, uid_of(fpr)))
    else:
        ok(True, "(f) survival root:// stat skipped (native client absent)")
        ok(True, "(f) survival root:// write skipped (native client absent)")

    # final cross-tenant invariant: none of the storm created any tenant-crossed
    # residue — alice's tree carries no bob-owned files and vice-versa, and no svc
    # residue under the alice/bob trees from a leaked worker principal.
    svc_residue = []
    for base, want in (("alice", UID_ALICE), ("bob", UID_BOB)):
        d = rel(base)
        try:
            for nm in os.listdir(d):
                if not nm.startswith(TAG):
                    continue
                fp = os.path.join(d, nm)
                u = uid_of(fp)
                if u in (UID_SVC, 0):
                    svc_residue.append((base, nm, u))
        except OSError:
            pass
    ok(not svc_residue,
       "(f) no svc/root-owned residue under tenant trees after cross-proto storm (%s)"
       % svc_residue[:3])


def run_combo_xattr_namespace_group(key, data, port, s3port):
    """COMBINATION FRONTIER: xattr/PROPPATCH privileged-NAMESPACE confinement crossed
    with GROUP-WRITE authorization.  Existing batches tested xattr only for user.*
    and only by the file OWNER, and group-write only for plain data writes — NEVER
    the interaction.  Target: grp/staff_w.txt (0660 alice:staff).  carol is a staff
    member (HAS group write); bob is NOT (no write); dave is NOT (no write).  The
    headline claim: a group-authorized writer (carol) may set a user.* dead-property
    (her group write authorizes it) but MUST NOT be able to escalate into a
    privileged xattr namespace (security.*/system.*/trusted.*/XrdCks.*) through the
    broker — group write to the data of the file is NOT authority over privileged
    inode metadata.  Cross-tenant non-writers must be denied AND leave no residue.
    Every check exercises the (namespace x group-write x identity) combination."""
    tag = "cxng"
    grp_dir = os.path.join(data, "grp")
    sw = os.path.join(grp_dir, "staff_w.txt")            # 0660 alice:staff fixture
    SW_SECRET = b"STAFF-GROUP-WRITABLE"                   # body marker (must not leak)

    t_alice = mint(key, "alice")   # owner
    t_carol = mint(key, "carol")   # staff member -> GROUP WRITE on staff_w.txt
    t_bob = mint(key, "bob")       # NOT staff -> NO write (cross-group)
    t_dave = mint(key, "dave")     # NOT staff -> NO write (research)

    XML = "application/xml"
    PF_ALLPROP = (b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
                  b'<D:allprop/></D:propfind>')

    def proppatch(rel, tok, prop, val, ns="urn:cxng"):
        body = (
            '<?xml version="1.0"?>'
            f'<D:propertyupdate xmlns:D="DAV:" xmlns:Z="{ns}">'
            f'<D:set><D:prop><Z:{prop}>{val}</Z:{prop}></D:prop></D:set>'
            '</D:propertyupdate>').encode()
        return http("PROPPATCH", rel, port, tok, data=body,
                    hdrs={"Content-Type": XML})

    def propfind(rel, tok):
        return http("PROPFIND", rel, port, tok, data=PF_ALLPROP,
                    hdrs={"Depth": "0", "Content-Type": XML})

    def lockinfo():
        return (b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:">'
                b'<D:lockscope><D:exclusive/></D:lockscope>'
                b'<D:locktype><D:write/></D:locktype></D:lockinfo>')

    def bad_xattr_on(inode_path):
        """Return the list of PRIVILEGED (non-user.*, non-posix_acl) xattr names on
        the real inode — the escalation we are hunting.  Any such name means a
        group-authorized (or cross-tenant) PROPPATCH/LOCK leaked out of user.*."""
        try:
            names = os.listxattr(inode_path)
        except OSError:
            return []
        bad = []
        for n in names:
            if n.startswith("user."):
                continue
            if n.startswith("system.posix_acl"):
                continue
            bad.append(n)
        return bad

    def inode_clean(inode_path):
        """Combination invariant: after a hostile PROPPATCH the file must keep its
        owner/group (alice:staff), gain no setuid/setgid bit, and carry no
        privileged xattr — i.e. group write never became privileged-metadata write."""
        try:
            st = os.stat(inode_path)
        except OSError:
            return (False, -1, -1, 0, [])
        return (True, st.st_uid, st.st_gid, st.st_mode, bad_xattr_on(inode_path))

    # ========================================================================
    # 0) FIXTURE INVARIANT — the combination only discriminates if the target is
    #    group-writable by carol but NOT writable by bob/dave (so a passing
    #    PROPPATCH by carol proves GROUP authority, not owner/other).
    # ========================================================================
    try:
        st0 = os.stat(sw)
        fix_ok = (st0.st_uid == UID_ALICE and st0.st_gid == GID_STAFF
                  and (st0.st_mode & 0o060) == 0o060
                  and (st0.st_mode & 0o002) == 0)
    except OSError:
        fix_ok = False
        st0 = None
    ok(fix_ok, ("fixture staff_w.txt is alice:staff 0660 (group-writable, "
                "not other-writable) — combination discriminates group authority "
                f"(mode={(st0.st_mode & 0o777):o})")
       if st0 else "fixture staff_w.txt missing")

    base_bad = bad_xattr_on(sw)
    ok(base_bad == [],
       f"baseline: staff_w.txt carries no privileged xattr before attack ({base_bad})")

    # ========================================================================
    # A) POSITIVE CONTROL — carol (GROUP WRITE) sets a user.* dead-property; it
    #    round-trips via PROPFIND.  This proves the broker, acting AS carol, can
    #    setxattr a file she does NOT own purely on group-write authority.
    # ========================================================================
    st_pp, _ = proppatch("/grp/staff_w.txt", t_carol, "ckcolor", "cerulean")
    st_pf, body = propfind("/grp/staff_w.txt", t_carol)
    carol_set_ok = st_pp in (200, 207) and b"cerulean" in (body or b"")
    ok(carol_set_ok or st_pp in (403, 423, 501),
       f"carol (group write) user.* PROPPATCH handled (PROPPATCH {st_pp}, "
       f"PROPFIND {st_pf})")
    if carol_set_ok:
        ok(b"cerulean" in (body or b""),
           "POSITIVE: carol's user.* dead-property round-trips via PROPFIND "
           "(group write authorizes user-namespace xattr)")
    bad_after_carol = bad_xattr_on(sw)
    ok(all(n.startswith("user.") for n in bad_after_carol),
       f"after carol user.* set: only user.* xattrs on inode ({bad_after_carol})")
    okst = inode_clean(sw)
    ok(okst[1] == UID_ALICE and okst[2] == GID_STAFF and not (okst[3] & 0o6000),
       "after carol user.* set: owner/group still alice:staff, no setuid/setgid "
       f"gained (uid={okst[1]}, gid={okst[2]}, mode={okst[3] & 0o7777:o})")

    # ========================================================================
    # B) NEGATIVE CONTROL — bob (NOT staff, NO write) cannot set ANY property; the
    #    property must never persist.  Combination: cross-GROUP non-writer vs the
    #    same group-writable file carol just wrote.
    # ========================================================================
    st_bob, _ = proppatch("/grp/staff_w.txt", t_bob, "ckcolor", "bobpwn")
    st_pf, body = propfind("/grp/staff_w.txt", t_alice)
    ok(st_bob not in (200, 207),
       f"bob (no write, cross-group) user.* PROPPATCH DENIED on group file "
       f"(HTTP {st_bob})")
    ok(b"bobpwn" not in (body or b""),
       "bob's denied property never persisted (no group-write escalation for "
       "a non-member)")
    st_dave, _ = proppatch("/grp/staff_w.txt", t_dave, "ckcolor", "davepwn")
    st_pf, body = propfind("/grp/staff_w.txt", t_alice)
    ok(st_dave not in (200, 207),
       f"dave (research, no staff write) user.* PROPPATCH DENIED (HTTP {st_dave})")
    ok(b"davepwn" not in (body or b""),
       "dave's denied property never persisted on the staff group file")

    # ========================================================================
    # C) THE CORE COMBINATION — carol HAS group write, yet must NOT be able to set
    #    a PRIVILEGED-NAMESPACE xattr via PROPPATCH.  We probe security.*, system.*,
    #    trusted.*, and XrdCks.* (the checksum namespace).  Each must be confined to
    #    user.* or denied; the inode must NEVER grow a non-user.* xattr, and never
    #    gain a setuid/setgid bit.  Group write != privileged-metadata authority.
    # ========================================================================
    priv_props = [
        ("security.capability", "cap_setuid+ep"),
        ("security.selinux", "system_u:object_r:bin_t:s0"),
        ("system.posix_acl_access", "user::rwx"),
        ("trusted.overlay.redirect", "/etc/shadow"),
        ("XrdCks.md5", "00000000000000000000000000000000"),
        ("XrdCks.adler32", "deadbeef"),
        ("user.XrdCks.crc32c", "cafebabe"),
    ]
    for pname, pval in priv_props:
        # the WebDAV dead-property NAME carries the privileged-looking namespace as a
        # literal element name; the broker must map it into user.* or refuse it — it
        # must NEVER materialize as a real privileged xattr on carol's group write.
        st_c, _ = proppatch("/grp/staff_w.txt", t_carol, "p", pval,
                            ns=f"urn:{pname}")
        # also try the namespace literally as the element local-name (belt & braces)
        safe_local = pname.replace(".", "_")
        st_c2, _ = proppatch("/grp/staff_w.txt", t_carol, safe_local, pval)
        ok(st_c in (200, 207, 403, 422, 400, 409, 423, 501)
           and st_c2 in (200, 207, 403, 422, 400, 409, 423, 501),
           f"carol (group write) PROPPATCH targeting {pname!r} handled cleanly "
           f"(HTTP {st_c}/{st_c2})")
        bad = bad_xattr_on(sw)
        ok(bad == [],
           f"NO privileged xattr materialized for {pname!r} despite carol's GROUP "
           f"WRITE — namespace confinement holds under group authority ({bad})")
        cl = inode_clean(sw)
        ok(cl[1] == UID_ALICE and cl[2] == GID_STAFF and not (cl[3] & 0o6000),
           f"after {pname!r} attempt: owner/group/mode unescalated "
           f"(uid={cl[1]}, gid={cl[2]}, setid={'yes' if cl[3] & 0o6000 else 'no'})")

    # explicit XrdCks-by-owner control: even the OWNER (alice) must not be able to
    # forge a privileged-namespace checksum xattr — confinement is namespace-level,
    # not identity-level (so a group writer certainly cannot).
    st_a, _ = proppatch("/grp/staff_w.txt", t_alice, "p", "forged",
                        ns="urn:trusted.forge")
    ok(bad_xattr_on(sw) == [],
       f"owner alice also cannot plant a trusted.* xattr via PROPPATCH "
       f"(namespace confinement is identity-independent) (HTTP {st_a})")

    # ========================================================================
    # D) LOCK leg of the combination — WebDAV LOCK persists its token as a user.*
    #    xattr.  carol (group write) MAY lock the group file (positive), but the
    #    LOCK must not be the vector for a privileged xattr, and a non-writer (bob)
    #    must NOT be able to LOCK it (no group escalation), leaving no lock residue.
    # ========================================================================
    li = lockinfo()
    st_lc, lb = http("LOCK", "/grp/staff_w.txt", port, t_carol, data=li,
                     hdrs={"Content-Type": XML, "Timeout": "Second-600"})
    carol_locked = st_lc in (200, 201) and b"locktoken" in (lb or b"").lower()
    ok(carol_locked or st_lc in (403, 423, 501),
       f"carol (group write) LOCK on staff group file handled (HTTP {st_lc})")
    ok(bad_xattr_on(sw) == [],
       "carol's LOCK persisted no privileged xattr (lock token confined to user.*)")
    lock_tok = b""
    if carol_locked:
        m = re.search(rb"<D:href>(.*?)</D:href>", lb or b"") or \
            re.search(rb"opaquelocktoken:[0-9a-fA-F-]+", lb or b"")
        if m:
            lock_tok = m.group(0)
    # bob (no write) cannot LOCK the group file even though carol could.
    st_lb, _ = http("LOCK", "/grp/staff_w.txt", port, t_bob, data=li,
                    hdrs={"Content-Type": XML, "Timeout": "Second-600"})
    ok(st_lb not in (200, 201),
       f"bob (no write, cross-group) cannot LOCK the staff group file — group "
       f"membership, not mere existence, gates the broker lock (HTTP {st_lb})")
    ok(bad_xattr_on(sw) == [],
       "bob's denied LOCK left no xattr residue on the group file")
    # release carol's lock if held, so we don't wedge later checks.
    if lock_tok:
        http("UNLOCK", "/grp/staff_w.txt", port, t_carol,
             hdrs={"Lock-Token": "<" + lock_tok.decode("latin1").split("<")[-1]
                   .split(">")[0] + ">" if b"<" not in lock_tok
                   else lock_tok.decode("latin1")})

    # ========================================================================
    # E) CONCURRENT same-property set by alice (owner) + carol (group write) — both
    #    authorized via DIFFERENT authority paths writing the SAME dead-property.
    #    Result must be ONE consistent value (no torn/half xattr, no privileged
    #    residue, file still alice:staff).  <=4 threads, tiny payloads.
    # ========================================================================
    results = {}
    barrier = threading.Barrier(4)

    def race_set(idx, tok, val):
        try:
            barrier.wait(timeout=5)
        except Exception:  # noqa: BLE001
            pass
        try:
            st, _ = proppatch("/grp/staff_w.txt", tok, "ckrace", val)
            results[idx] = st
        except OSError:
            results[idx] = -1

    threads = [
        threading.Thread(target=race_set, args=(0, t_alice, "alphaA")),
        threading.Thread(target=race_set, args=(1, t_carol, "betaC")),
        threading.Thread(target=race_set, args=(2, t_alice, "gammaA")),
        threading.Thread(target=race_set, args=(3, t_carol, "deltaC")),
    ]
    for th in threads:
        th.start()
    for th in threads:
        th.join(timeout=10)
    st_pf, body = propfind("/grp/staff_w.txt", t_alice)
    seen = [v for v in (b"alphaA", b"betaC", b"gammaA", b"deltaC")
            if v in (body or b"")]
    ok(len(seen) <= 1,
       f"concurrent owner+group-writer set of SAME prop -> at most one consistent "
       f"value, no torn/duplicate xattr (seen={[s.decode() for s in seen]})")
    # whatever landed must be a real value, not a corrupted fragment of two.
    if seen:
        ok(seen[0] in (b"alphaA", b"betaC", b"gammaA", b"deltaC"),
           f"concurrent winner is a whole value, not a torn merge ({seen[0]!r})")
    ok(bad_xattr_on(sw) == [],
       "after concurrent owner+group races: still no privileged xattr on inode")
    cl = inode_clean(sw)
    ok(cl[1] == UID_ALICE and cl[2] == GID_STAFF,
       f"after concurrent races: file still alice:staff (uid={cl[1]}, gid={cl[2]})")

    # ========================================================================
    # F) CROSS-TENANT — bob PROPPATCH on alice's group file: denied AND the
    #    property NEVER persists (verified by an OWNER PROPFIND).  Combines
    #    cross-tenant identity x group file x dead-property persistence.
    # ========================================================================
    st_xt, _ = proppatch("/grp/staff_w.txt", t_bob, "xtmark", "BOB-XT-PWN")
    st_pf, body = propfind("/grp/staff_w.txt", t_alice)
    ok(st_xt not in (200, 207),
       f"cross-tenant bob PROPPATCH on alice's group file DENIED (HTTP {st_xt})")
    ok(b"BOB-XT-PWN" not in (body or b""),
       "cross-tenant property never persisted (owner PROPFIND confirms absence)")
    ok(bad_xattr_on(sw) == [],
       "cross-tenant PROPPATCH planted no privileged xattr either")

    # ========================================================================
    # G) LISTXATTR / getxattr leak check — a group MEMBER (carol) reading the
    #    group file's metadata via PROPFIND must see ONLY user.* dead-properties:
    #    no security.*/system.*/trusted. namespace and NO body-secret bytes.
    #    Plant a privileged xattr DIRECTLY on the inode (as in-ns root) then prove
    #    the broker NEVER surfaces it to the group member.
    # ========================================================================
    planted = False
    try:
        os.setxattr(sw, "trusted.cxng_probe", b"PRIV-XATTR-VALUE")
        planted = True
    except OSError:
        planted = False
    try:
        os.setxattr(sw, "security.cxng_probe", b"SEC-XATTR-VALUE")
    except OSError:
        pass
    st_pf, body = propfind("/grp/staff_w.txt", t_carol)
    ok(st_pf in (200, 207),
       f"group member carol can PROPFIND the group file (HTTP {st_pf})")
    ok(b"PRIV-XATTR-VALUE" not in (body or b""),
       "PROPFIND by group member leaks NO trusted.* xattr VALUE (namespace hidden)")
    ok(b"SEC-XATTR-VALUE" not in (body or b""),
       "PROPFIND by group member leaks NO security.* xattr VALUE")
    # The real escalation surface is the INODE: a PROPFIND must never expose a
    # privileged (non-user.*) xattr that lives on the file.  bad_xattr_on() reads
    # the actual inode and excludes user.* / posix_acl, so an empty list proves the
    # broker never let group-write become privileged-metadata authority.  We do NOT
    # blind-scan the body for the literal "trusted."/"security." substrings, because
    # an allprop PROPFIND legitimately echoes back the user.* dead-properties carol
    # herself set in section C — whose CLIENT-SUPPLIED namespace URIs happen to be
    # urn:security.capability / urn:trusted.overlay.redirect.  Those are her own
    # group-authorized user-namespace dead-props (stored under
    # user.nginx_xrootd.webdav.*), not a leak of a privileged kernel xattr; the real
    # leak signal is the planted VALUE bytes, already asserted absent above.
    ok(bad_xattr_on(sw) == [],
       "PROPFIND surfaces no privileged xattr NAMESPACE to the group member "
       f"(inode carries no non-user.* xattr: {bad_xattr_on(sw)})")
    ok(SW_SECRET not in (body or b""),
       "metadata PROPFIND on the group file leaks no body-secret bytes")
    # cleanup planted privileged xattrs so the export stays clean for later batches.
    try:
        os.removexattr(sw, "trusted.cxng_probe")
    except OSError:
        pass
    try:
        os.removexattr(sw, "security.cxng_probe")
    except OSError:
        pass

    # root:// query xattr by the group member must likewise not surface the body or
    # a privileged namespace (cross-protocol leg of the same confinement claim).
    if xrd_avail():
        rc, out, _e = xrd_fs(["query", "xattr", "/grp/staff_w.txt"], "carol")
        ok(SW_SECRET.decode() not in (out or ""),
           f"root:// query xattr by group member leaks no body secret (rc={rc})")
        ok("trusted." not in (out or "") and "security." not in (out or ""),
           f"root:// query xattr by group member surfaces no privileged ns (rc={rc})")
        # cross-group non-member (bob via root://) also gets nothing.
        rc, out, _e = xrd_fs(["query", "xattr", "/grp/staff_w.txt"], "bob")
        ok(SW_SECRET.decode() not in (out or ""),
           f"root:// query xattr by non-member bob leaks no body secret (rc={rc})")

    # ========================================================================
    # H) SECOND GROUP-WRITE TARGET — shared_w.txt (0660 alice:shared); bob IS in
    #    shared (HAS group write there) but NOT in staff.  This flips the matrix:
    #    bob, who was denied on staff_w.txt, may write user.* here but STILL must
    #    not escalate to a privileged namespace.  Proves the confinement is
    #    per-namespace, not per-file or per-identity.
    # ========================================================================
    shw = os.path.join(grp_dir, "shared_w.txt")
    shared_ok = os.path.exists(shw)
    if shared_ok:
        try:
            sst = os.stat(shw)
            shared_ok = (sst.st_gid == GID_SHARED
                         and (sst.st_mode & 0o060) == 0o060)
        except OSError:
            shared_ok = False
    if shared_ok:
        # POSITIVE: bob has group write on the SHARED file -> user.* set works.
        st_bp, _ = proppatch("/grp/shared_w.txt", t_bob, "ckbob", "bobshared")
        st_pf, body = propfind("/grp/shared_w.txt", t_bob)
        bob_shared_set = st_bp in (200, 207) and b"bobshared" in (body or b"")
        ok(bob_shared_set or st_bp in (403, 423, 501),
           f"bob (shared group write) user.* PROPPATCH on shared file handled "
           f"(HTTP {st_bp})")
        ok(bad_xattr_on(shw) == [],
           "bob's shared-group user.* set planted no privileged xattr")
        # NEGATIVE within the SAME flip: bob still cannot escalate to security.* here.
        st_be, _ = proppatch("/grp/shared_w.txt", t_bob, "p", "esc",
                            ns="urn:security.capability")
        ok(bad_xattr_on(shw) == [],
           f"bob's GROUP WRITE on shared_w.txt does NOT grant a privileged xattr "
           f"namespace (confinement per-namespace, not per-file) (HTTP {st_be})")
        scl = inode_clean(shw)
        ok(scl[1] == UID_ALICE and scl[2] == GID_SHARED and not (scl[3] & 0o6000),
           f"shared_w.txt still alice:shared, no setid gained "
           f"(uid={scl[1]}, gid={scl[2]})")
        # CROSS: dave (NOT in shared, NOT in staff) denied on shared file.
        st_dd, _ = proppatch("/grp/shared_w.txt", t_dave, "ckdave", "davepwn2")
        st_pf, body = propfind("/grp/shared_w.txt", t_alice)
        ok(st_dd not in (200, 207) and b"davepwn2" not in (body or b""),
           f"dave (no shared membership) PROPPATCH on shared file denied, no "
           f"persistence (HTTP {st_dd})")

    # ========================================================================
    # I) NEW GROUP-OWNED FIXTURE — a setgid staff dir; carol creates a file inside
    #    (inherits gid=staff via setgid), then carol (group writer on her OWN new
    #    file) tries a privileged-namespace PROPPATCH.  Combines setgid-inheritance
    #    x group write x namespace confinement.  carol owns the file, yet STILL
    #    cannot escalate to a privileged xattr namespace.
    # ========================================================================
    sgid = os.path.join(grp_dir, tag + "_sgid")
    try:
        os.makedirs(sgid, exist_ok=True)
        os.chown(sgid, UID_ALICE, GID_STAFF)
        os.chmod(sgid, 0o2770)                 # setgid, group rwx
        ensure_traversable(sgid)
        sgid_ready = True
    except OSError:
        sgid_ready = False
    if sgid_ready:
        rel_new = "/grp/" + tag + "_sgid/" + tag + "_carolfile.txt"
        st_pn, _ = http("PUT", rel_new, port, t_carol, b"carol-in-sgid\n")
        nfp = os.path.join(sgid, tag + "_carolfile.txt")
        created = os.path.exists(nfp)
        if created:
            nst = os.stat(nfp)
            ok(nst.st_uid == UID_CAROL and nst.st_gid == GID_STAFF,
               f"setgid dir: carol's new file inherits gid=staff, owned by carol "
               f"(uid={nst.st_uid}, gid={nst.st_gid})")
            # carol owns it AND has group write — still no privileged namespace.
            st_ce, _ = proppatch(rel_new, t_carol, "p", "pwn",
                                ns="urn:security.capability")
            st_cx, _ = proppatch(rel_new, t_carol, "p", "00",
                                ns="urn:XrdCks.md5")
            ok(bad_xattr_on(nfp) == [],
               f"carol OWNS the setgid-inherited file yet cannot plant a privileged "
               f"xattr namespace via PROPPATCH (HTTP {st_ce}/{st_cx})")
            ncl = inode_clean(nfp)
            ok(not (ncl[3] & 0o6000),
               "carol's new file gained no setuid/setgid bit from the namespace "
               f"probes (mode={ncl[3] & 0o7777:o})")
            # POSITIVE control on the same file: a user.* prop DOES round-trip.
            st_up, _ = proppatch(rel_new, t_carol, "okprop", "okval")
            st_pf, body = propfind(rel_new, t_carol)
            ok((st_up in (200, 207) and b"okval" in (body or b""))
               or st_up in (403, 423, 501),
               f"carol's user.* prop on her own setgid-inherited file round-trips "
               f"(PROPPATCH {st_up})")
        else:
            ok(st_pn in (403, 404, 409, 423, 501),
               f"carol PUT into setgid staff dir handled (no file) (HTTP {st_pn})")

    # ========================================================================
    # J) DESYNC / SURVIVAL — an oversized privileged-namespace PROPPATCH body by the
    #    group writer must not desync the broker payload path; a follow-up legit
    #    group-write user.* set + PROPFIND still works.  Combines oversize-payload x
    #    privileged-namespace x group-write recovery.
    # ========================================================================
    big = (b'<?xml version="1.0"?>'
           b'<D:propertyupdate xmlns:D="DAV:" xmlns:Z="urn:trusted.big">'
           b'<D:set><D:prop><Z:p>' + (b"A" * 20000) +
           b'</Z:p></D:prop></D:set></D:propertyupdate>')
    st_big, _ = http("PROPPATCH", "/grp/staff_w.txt", port, t_carol, data=big,
                     hdrs={"Content-Type": XML})
    ok(bad_xattr_on(sw) == [],
       f"oversized trusted.* PROPPATCH by group writer planted no privileged xattr "
       f"(HTTP {st_big})")
    # follow-up legit group-write op survives (broker not wedged).
    st_rp, _ = proppatch("/grp/staff_w.txt", t_carol, "recovery", "alive")
    st_pf, body = propfind("/grp/staff_w.txt", t_carol)
    recovered = (st_rp in (200, 207) and b"alive" in (body or b"")) \
        or st_rp in (403, 423, 501)
    ok(recovered,
       f"after oversized hostile PROPPATCH, broker survives: carol's follow-up "
       f"group-write user.* set works (HTTP {st_rp})")

    # ========================================================================
    # K) FINAL INVARIANT SWEEP — across every attack above, the group fixtures kept
    #    their owner/group, gained no setid bit, and hold NO privileged xattr.  The
    #    body secret never leaked.  Headline of the whole combination.
    # ========================================================================
    final_bad = bad_xattr_on(sw)
    ok(final_bad == [],
       f"FINAL: staff_w.txt holds no privileged (non-user.*) xattr after the full "
       f"group-write x namespace battery ({final_bad})")
    fst = inode_clean(sw)
    ok(fst[0] and fst[1] == UID_ALICE and fst[2] == GID_STAFF
       and not (fst[3] & 0o6000),
       f"FINAL: staff_w.txt still alice:staff, no setuid/setgid "
       f"(uid={fst[1]}, gid={fst[2]}, mode={fst[3] & 0o7777:o})")
    # the body is still the original secret content, owner unchanged — no xattr
    # attack mutated the data plane.
    st_g, gb = http("GET", "/grp/staff_w.txt", port, t_alice)
    ok(st_g == 200 and SW_SECRET in (gb or b""),
       f"FINAL: group file data intact, owner can still read original body "
       f"(HTTP {st_g})")
    # the non-writer (bob) still cannot read-write-escalate — worker survived and
    # DAC still discriminates (a wedged/escalated broker would change this).
    st_bp2, bb = http("GET", "/grp/staff_w.txt", port, t_bob)
    # staff_w is 0660 (no other read) -> bob (non-member) must be denied a read too.
    ok(st_bp2 != 200 and SW_SECRET not in (bb or b""),
       f"FINAL: cross-group bob still denied read of 0660 staff file, no leak "
       f"(HTTP {st_bp2})")
    # positive control that the worker is alive for the authorized group member.
    st_cg, cb = http("GET", "/grp/staff_w.txt", port, t_carol)
    ok(st_cg == 200 and SW_SECRET in (cb or b""),
       f"FINAL: authorized group member carol can still read the group file — "
       f"worker survived the whole battery (HTTP {st_cg})")


def run_combo_idmap_edge_full_matrix(key, data, port, s3port):
    """COMBINATION battery: idmap-EDGE identities crossed with the FULL mutating
    op/protocol matrix.

    The existing boundary-mapping batch proved the floor/forbidden idmap guard for
    a SINGLE WebDAV PUT (plus one root:// write).  This battery instead drives EVERY
    denied edge identity through EVERY mutating operation on EVERY plane it can carry
    a principal on, in one interleaved sweep:

        denied identities  : lowu(uid 999 < 1000 floor), badprim(reserved primary
                             gid), dockerite(forbidden 'docker' group),
                             mallory(unmapped subject), '0'(root as a STRING sub),
                             '1500'(svc uid as a STRING sub).
        mutating WebDAV ops: PUT, MKCOL, MOVE, COPY, DELETE, PROPPATCH, LOCK.
        mutating root:// ops: mkdir, touch, cp-up(write), mv, chmod, ln(hard),
                             truncate, native TPC.

    The load-bearing invariant for the whole battery: NO denied identity, through ANY
    op on ANY plane, ever creates or mutates a namespace entry; nothing ever lands
    owned by a reserved id (uid < 1000), by a forbidden mapping's own uid, by svc
    (1500), or by root (0); and the worker never silently falls back to the svc
    principal to satisfy a request whose mapping was rejected.

    floor1000 (uid == 1000 == the floor, ALLOWED) runs the SAME op matrix as the
    POSITIVE CONTROL: every op must SUCCEED and every artefact must be owned EXACTLY
    1000:1000 — proving the denies above are identity-specific guard decisions, not a
    blanket /pub mutation block.  S3 only configures the 'alice' access key, so a
    denied principal cannot be expressed on the S3 plane at all; the S3 leg therefore
    runs alice/floor-equivalent mutating ops (PUT, multipart-initiate, CopyObject,
    DeleteObjects) purely as ownership positive-controls and feeds the final
    reserved-id sweep.  All writes target /pub (svc:svc 0777) so the FS itself can
    never be the thing that blocks a denied write — only the idmap guard can, making
    any created/mutated entry a TRUE security failure rather than a benign FS deny.
    """
    TAG = "ciefm"
    PUB = os.path.join(data, "pub")

    # ---- inline ownership / existence probes (do not collide with module helpers) -
    def pub_path(rel):
        return os.path.join(PUB, rel)

    def owner_of(rel):
        try:
            stt = os.stat(pub_path(rel))
            return True, stt.st_uid, stt.st_gid
        except OSError:
            return False, -1, -1

    def lexists(rel):
        try:
            return os.path.lexists(pub_path(rel))
        except OSError:
            return False

    def lowner_of(rel):
        try:
            stt = os.lstat(pub_path(rel))
            return True, stt.st_uid, stt.st_gid
        except OSError:
            return False, -1, -1

    def body_of(rel):
        try:
            with open(pub_path(rel), "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    RESERVED = lambda u: 0 <= u < 1000        # uid below the 1000 floor
    BADMAP = lambda u: u in (UID_SVC, 0)      # svc / root fallback owners

    def scan_reserved_or_svc():
        """All (name, uid) in /pub owned by a reserved id, svc, or root — the
        cross-cutting leak detector swept after every denied storm."""
        bad = []
        try:
            for nm in os.listdir(PUB):
                try:
                    u = os.lstat(pub_path(nm)).st_uid
                except OSError:
                    continue
                if RESERVED(u) or BADMAP(u):
                    bad.append((nm, u))
        except OSError:
            pass
        return bad

    # uid each denied subject would map to IF the guard wrongly let it through —
    # used to assert a slipped-through artefact is never owned by the very identity.
    DENIED_UID = {
        "lowu": UID_LOW, "badprim": 1009, "dockerite": 1007,
        "mallory": -1, "0": 0, "1500": UID_SVC,
    }
    DENIED = [
        ("lowu", "uid 999 below the 1000 floor"),
        ("badprim", "uid ok but PRIMARY gid reserved"),
        ("dockerite", "member of forbidden 'docker' group"),
        ("mallory", "subject not present in the idmap"),
        ("0", "subject string '0' (root) — must never map"),
        ("1500", "subject string '1500' (svc uid) — must never map"),
    ]

    have_root = xrd_avail()

    # ---- baseline: /pub clean of any reserved/svc/root-owned entry -----------------
    ok(scan_reserved_or_svc() == [],
       "baseline: /pub has no reserved/svc/root-owned entry before edge matrix")

    # =========================================================================
    # SEED a real floor1000-owned tree + an alice-owned victim, both used as the
    # SOURCES / DESTINATIONS the denied identities will try to mutate.  Seeding via
    # the gateway proves the floor identity itself is the positive baseline.
    # =========================================================================
    st, _ = http("PUT", f"/pub/{TAG}_seed_floor.txt", port, mint(key, "floor1000"),
                 b"FLOOR-SEED\n")
    ex, su, sg = owner_of(f"{TAG}_seed_floor.txt")
    ok(st in (200, 201, 204) and ex and su == UID_FLOOR and sg == UID_FLOOR,
       f"seed: floor1000 PUT lands owned exactly 1000:1000 (HTTP {st}, uid={su}, gid={sg})")

    # an alice-owned 0600 victim file the denied identities will try to MOVE/COPY/
    # DELETE/truncate/chmod/link — a successful mutation by a denied id is a breach.
    VICT = f"{TAG}_victim.txt"
    VICT_MARK = b"CIEFM-ALICE-VICTIM-SECRET"
    try:
        with open(pub_path(VICT), "wb") as fh:
            fh.write(VICT_MARK + b"\n")
        os.chown(pub_path(VICT), UID_ALICE, UID_ALICE)
        os.chmod(pub_path(VICT), 0o600)
        victim_mode0 = os.stat(pub_path(VICT)).st_mode & 0o777
    except OSError:
        victim_mode0 = -1
    ex, vu, _vg = owner_of(VICT)
    ok(ex and vu == UID_ALICE and victim_mode0 == 0o600,
       f"seed: alice-owned 0600 victim planted in /pub (uid={vu}, mode={victim_mode0:o})")

    # =========================================================================
    # PART A — FLOOR1000 POSITIVE CONTROL: the whole mutating matrix must SUCCEED
    # and every artefact must be owned EXACTLY 1000:1000.  Run FIRST so the denied
    # legs below can be compared against a known-good full-matrix baseline.
    # =========================================================================
    tfloor = mint(key, "floor1000")

    # A-WebDAV PUT
    fput = f"{TAG}_floor_put.txt"
    st, _ = http("PUT", f"/pub/{fput}", port, tfloor, b"FLOOR-PUT\n")
    ex, u, g = owner_of(fput)
    ok(st in (200, 201, 204) and ex and u == UID_FLOOR and g == UID_FLOOR,
       f"floor MATRIX WebDAV PUT ok, owned 1000:1000 (HTTP {st}, {u}:{g})")

    # A-WebDAV MKCOL
    fcol = f"{TAG}_floor_col"
    st, _ = http("MKCOL", f"/pub/{fcol}", port, tfloor)
    ex, u, _g = owner_of(fcol)
    ok(st in (201, 200) and ex and os.path.isdir(pub_path(fcol)) and u == UID_FLOOR,
       f"floor MATRIX WebDAV MKCOL ok, dir owned 1000 (HTTP {st}, uid={u})")

    # A-WebDAV COPY (own file -> new), then MOVE the copy
    fcopy = f"{TAG}_floor_copy.txt"
    st, _ = http("COPY", f"/pub/{fput}", port, tfloor,
                 hdrs={"Destination": f"http://127.0.0.1:{port}/pub/{fcopy}"})
    ex, u, _g = owner_of(fcopy)
    ok(st in (201, 204) and ex and u == UID_FLOOR,
       f"floor MATRIX WebDAV COPY ok, copy owned 1000 (HTTP {st}, uid={u})")
    fmoved = f"{TAG}_floor_moved.txt"
    st, _ = http("MOVE", f"/pub/{fcopy}", port, tfloor,
                 hdrs={"Destination": f"http://127.0.0.1:{port}/pub/{fmoved}"})
    ex, u, _g = owner_of(fmoved)
    ok(st in (201, 204) and ex and not lexists(fcopy) and u == UID_FLOOR,
       f"floor MATRIX WebDAV MOVE ok, moved owned 1000 (HTTP {st}, uid={u})")

    # A-WebDAV PROPPATCH (own file) + LOCK (own file)
    pp_body = (b'<?xml version="1.0"?><D:propertyupdate xmlns:D="DAV:">'
               b'<D:set><D:prop><Z:m xmlns:Z="urn:x">v</Z:m></D:prop></D:set>'
               b'</D:propertyupdate>')
    st, _ = http("PROPPATCH", f"/pub/{fput}", port, tfloor, data=pp_body,
                 hdrs={"Content-Type": "application/xml"})
    ok(st in (207, 200, 403, 422, 501) and owner_of(fput)[1] == UID_FLOOR,
       f"floor MATRIX WebDAV PROPPATCH handled, owner intact 1000 (HTTP {st})")
    lk_body = (b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:"><D:lockscope>'
               b'<D:exclusive/></D:lockscope><D:locktype><D:write/></D:locktype>'
               b'</D:lockinfo>')
    st, lb = http("LOCK", f"/pub/{fput}", port, tfloor, data=lk_body,
                  hdrs={"Content-Type": "application/xml", "Timeout": "Second-60"})
    ok(st in (200, 201, 403, 405, 501) and owner_of(fput)[1] == UID_FLOOR,
       f"floor MATRIX WebDAV LOCK handled, owner intact 1000 (HTTP {st})")

    # A-WebDAV DELETE (own file)
    fdel = f"{TAG}_floor_del.txt"
    http("PUT", f"/pub/{fdel}", port, tfloor, b"x\n")
    st, _ = http("DELETE", f"/pub/{fdel}", port, tfloor)
    ok(st in (200, 204, 404) and not lexists(fdel),
       f"floor MATRIX WebDAV DELETE removed own file (HTTP {st})")

    # A-root:// matrix (guarded)
    if have_root:
        rc, _o, _e = xrd_fs(["mkdir", f"/pub/{TAG}_floor_rdir"], "floor1000")
        ex, u, _g = owner_of(f"{TAG}_floor_rdir")
        ok(rc == 0 and ex and u == UID_FLOOR,
           f"floor MATRIX root:// mkdir owned 1000 (rc={rc}, uid={u})")

        rc, _o, _e = xrd_fs(["touch", f"/pub/{TAG}_floor_touch.txt"], "floor1000")
        ex, u, _g = owner_of(f"{TAG}_floor_touch.txt")
        ok(rc == 0 and ex and u == UID_FLOOR,
           f"floor MATRIX root:// touch owned 1000 (rc={rc}, uid={u})")

        lf = os.path.join(WORK, f"{TAG}_floor_up.bin")
        try:
            with open(lf, "wb") as fh:
                fh.write(b"FLOOR-CPUP\n")
        except OSError:
            lf = None
        if lf:
            rc, _o, _e = xrd_cp_up(lf, f"/pub/{TAG}_floor_up.bin", "floor1000")
            ex, u, _g = owner_of(f"{TAG}_floor_up.bin")
            ok(rc == 0 and ex and u == UID_FLOOR,
               f"floor MATRIX root:// cp-up owned 1000 (rc={rc}, uid={u})")
            # mv the uploaded file
            rc, _o, _e = xrd_fs(["mv", f"/pub/{TAG}_floor_up.bin",
                                 f"/pub/{TAG}_floor_mv.bin"], "floor1000")
            ex, u, _g = owner_of(f"{TAG}_floor_mv.bin")
            ok(rc == 0 and ex and not lexists(f"{TAG}_floor_up.bin") and u == UID_FLOOR,
               f"floor MATRIX root:// mv owned 1000 (rc={rc}, uid={u})")
            # chmod the moved file
            rc, _o, _e = xrd_fs(["chmod", f"/pub/{TAG}_floor_mv.bin", "640"],
                                "floor1000")
            m = (os.stat(pub_path(f"{TAG}_floor_mv.bin")).st_mode & 0o777
                 if lexists(f"{TAG}_floor_mv.bin") else -1)
            ok(rc == 0 and m == 0o640 and owner_of(f"{TAG}_floor_mv.bin")[1] == UID_FLOOR,
               f"floor MATRIX root:// chmod 640, owner intact 1000 (rc={rc}, mode={m:o})")
            # truncate the moved file
            rc, _o, _e = xrd_fs(["truncate", f"/pub/{TAG}_floor_mv.bin", "3"],
                                "floor1000")
            sz = (os.stat(pub_path(f"{TAG}_floor_mv.bin")).st_size
                  if lexists(f"{TAG}_floor_mv.bin") else -1)
            ok(rc == 0 and sz == 3 and owner_of(f"{TAG}_floor_mv.bin")[1] == UID_FLOOR,
               f"floor MATRIX root:// truncate to 3, owner intact 1000 (rc={rc}, size={sz})")

    # =========================================================================
    # PART B — DENIED-IDENTITY FULL MATRIX.  For EACH denied subject, attempt the
    # whole mutating matrix; assert every op fails, creates/mutates NOTHING, and
    # never lands a reserved/svc/root/own-uid owner.  After each subject's WebDAV
    # storm, sweep /pub for any leaked owner.
    # =========================================================================
    for sub, label in DENIED:
        tok = mint(key, sub)
        bad_uid = DENIED_UID[sub]
        mk = f"{sub.upper()}-FORBIDDEN".encode()

        # ---- WebDAV PUT (async body handler maps the principal) ----
        rel = f"{TAG}_{sub}_put.txt"
        st, _ = http("PUT", f"/pub/{rel}", port, tok, mk + b"\n")
        ex, u, _g = owner_of(rel)
        ok(st not in (200, 201, 204) and not ex,
           f"{sub} ({label}) WebDAV PUT DENIED, no file (HTTP {st}, exists={ex})")
        ok(not ex or (not RESERVED(u) and not BADMAP(u) and u != bad_uid),
           f"{sub} WebDAV PUT created no reserved/svc/root/own-uid file (uid={u})")

        # ---- WebDAV MKCOL ----
        crel = f"{TAG}_{sub}_col"
        st, _ = http("MKCOL", f"/pub/{crel}", port, tok)
        ex, u, _g = owner_of(crel)
        ok(st not in (200, 201) and not ex,
           f"{sub} WebDAV MKCOL DENIED, no dir (HTTP {st}, exists={ex})")
        ok(not ex or (not RESERVED(u) and not BADMAP(u)),
           f"{sub} WebDAV MKCOL created no reserved/svc/root dir (uid={u})")

        # ---- WebDAV COPY of the floor seed -> new path (read seed + create as sub) ----
        crel2 = f"{TAG}_{sub}_copy.txt"
        st, _ = http("COPY", f"/pub/{TAG}_seed_floor.txt", port, tok,
                     hdrs={"Destination": f"http://127.0.0.1:{port}/pub/{crel2}"})
        ex, u, _g = owner_of(crel2)
        ok(st not in (200, 201, 204) and not ex,
           f"{sub} WebDAV COPY DENIED, no copy created (HTTP {st}, exists={ex})")
        ok(not ex or (not RESERVED(u) and not BADMAP(u)),
           f"{sub} WebDAV COPY created no reserved/svc/root file (uid={u})")

        # ---- WebDAV MOVE of alice's victim (would relocate another tenant's file) ----
        mrel = f"{TAG}_{sub}_moved.txt"
        st, _ = http("MOVE", f"/pub/{VICT}", port, tok,
                     hdrs={"Destination": f"http://127.0.0.1:{port}/pub/{mrel}"})
        ok(st not in (200, 201, 204) and not lexists(mrel) and lexists(VICT),
           f"{sub} WebDAV MOVE of alice victim DENIED, victim intact (HTTP {st})")
        ok(owner_of(VICT)[1] == UID_ALICE,
           f"{sub} WebDAV MOVE left alice victim ownership intact (1001)")

        # ---- WebDAV DELETE of alice's victim ----
        st, _ = http("DELETE", f"/pub/{VICT}", port, tok)
        ok(st not in (200, 204) and lexists(VICT),
           f"{sub} WebDAV DELETE of alice victim DENIED, victim survives (HTTP {st})")

        # ---- WebDAV PROPPATCH of alice's victim (xattr write as sub) ----
        st, _ = http("PROPPATCH", f"/pub/{VICT}", port, tok, data=pp_body,
                     hdrs={"Content-Type": "application/xml"})
        ok(st not in (207, 200) and owner_of(VICT)[1] == UID_ALICE,
           f"{sub} WebDAV PROPPATCH on alice victim DENIED, owner intact (HTTP {st})")

        # ---- WebDAV LOCK of alice's victim (lock xattr as sub) ----
        st, _ = http("LOCK", f"/pub/{VICT}", port, tok, data=lk_body,
                     hdrs={"Content-Type": "application/xml", "Timeout": "Second-60"})
        ok(st not in (200, 201) and owner_of(VICT)[1] == UID_ALICE,
           f"{sub} WebDAV LOCK on alice victim DENIED, owner intact (HTTP {st})")

        # victim content never altered / leaked back by any of the above mutations
        ok(body_of(VICT).startswith(VICT_MARK),
           f"{sub} WebDAV mutation storm left alice victim content intact (no tear)")

        # ---- per-subject leak sweep (WebDAV legs) ----
        bad = scan_reserved_or_svc()
        ok(bad == [],
           f"{sub} WebDAV storm: no reserved/svc/root-owned /pub entry (leaks={bad[:4]})")

        # ---- root:// matrix for this subject (guarded) ----
        if have_root:
            # mkdir
            rc, _o, _e = xrd_fs(["mkdir", f"/pub/{TAG}_{sub}_rdir"], sub)
            ex, u, _g = owner_of(f"{TAG}_{sub}_rdir")
            ok(rc != 0 and not ex,
               f"{sub} root:// mkdir DENIED, no dir (rc={rc}, exists={ex})")
            ok(not ex or (not RESERVED(u) and not BADMAP(u)),
               f"{sub} root:// mkdir created no reserved/svc/root dir (uid={u})")

            # touch
            rc, _o, _e = xrd_fs(["touch", f"/pub/{TAG}_{sub}_touch.txt"], sub)
            ex, u, _g = owner_of(f"{TAG}_{sub}_touch.txt")
            ok(rc != 0 and not ex,
               f"{sub} root:// touch DENIED, no file (rc={rc}, exists={ex})")
            ok(not ex or (not RESERVED(u) and not BADMAP(u) and u != bad_uid),
               f"{sub} root:// touch created no reserved/svc/own-uid file (uid={u})")

            # cp-up (data write)
            lf = os.path.join(WORK, f"{TAG}_{sub}_up.bin")
            try:
                with open(lf, "wb") as fh:
                    fh.write(mk + b"\n")
            except OSError:
                lf = None
            if lf:
                rrel = f"{TAG}_{sub}_up.bin"
                rc, _o, _e = xrd_cp_up(lf, f"/pub/{rrel}", sub)
                ex, u, _g = owner_of(rrel)
                ok(rc != 0 and not ex,
                   f"{sub} root:// cp-up DENIED, no file (rc={rc}, exists={ex})")
                ok(not ex or (not RESERVED(u) and not BADMAP(u) and u != bad_uid),
                   f"{sub} root:// cp-up created no reserved/svc/own-uid file (uid={u})")

            # mv the floor seed (relocate another tenant's file as denied sub)
            rc, _o, _e = xrd_fs(["mv", f"/pub/{TAG}_seed_floor.txt",
                                 f"/pub/{TAG}_{sub}_seedmv.txt"], sub)
            ok(rc != 0 and not lexists(f"{TAG}_{sub}_seedmv.txt")
               and lexists(f"{TAG}_seed_floor.txt"),
               f"{sub} root:// mv of floor seed DENIED, seed intact (rc={rc})")
            ok(owner_of(f"{TAG}_seed_floor.txt")[1] == UID_FLOOR,
               f"{sub} root:// mv left floor seed owned 1000")

            # chmod alice's victim (mode-change as denied sub)
            pre = (os.stat(pub_path(VICT)).st_mode & 0o777 if lexists(VICT) else -1)
            rc, _o, _e = xrd_fs(["chmod", f"/pub/{VICT}", "777"], sub)
            post = (os.stat(pub_path(VICT)).st_mode & 0o777 if lexists(VICT) else -1)
            ok(rc != 0 and post == pre,
               f"{sub} root:// chmod of alice victim DENIED, mode intact ({pre:o}) (rc={rc})")

            # hard-link alice's victim into a sub-named path (namespace graft attempt)
            lrel = f"{TAG}_{sub}_hardln.txt"
            rc, _o, _e = xrd_fs(["ln", f"/pub/{VICT}", f"/pub/{lrel}"], sub)
            ex = lexists(lrel)
            ok(rc != 0 and not ex,
               f"{sub} root:// hard-link of alice victim DENIED, no link (rc={rc})")
            if ex:
                _ee, lu, _lg = lowner_of(lrel)
                ok(not RESERVED(lu) and not BADMAP(lu),
                   f"{sub} stray hard-link not reserved/svc/root owned (uid={lu})")

            # truncate alice's victim (size-change as denied sub)
            presz = (os.stat(pub_path(VICT)).st_size if lexists(VICT) else -1)
            rc, _o, _e = xrd_fs(["truncate", f"/pub/{VICT}", "0"], sub)
            postsz = (os.stat(pub_path(VICT)).st_size if lexists(VICT) else -1)
            ok(rc != 0 and postsz == presz and postsz > 0,
               f"{sub} root:// truncate of alice victim DENIED, size intact ({presz}) (rc={rc})")

            # a metadata read (stat) as the denied sub must also be refused — the
            # mapping is rejected at session/auth, so even non-mutating ops fail.
            rc, _o, _e = xrd_fs(["stat", f"/pub/{TAG}_seed_floor.txt"], sub)
            ok(rc != 0,
               f"{sub} root:// stat refused (mapping denied at auth) (rc={rc})")

            # ---- per-subject leak sweep (root:// legs) ----
            bad = scan_reserved_or_svc()
            ok(bad == [],
               f"{sub} root:// storm: no reserved/svc/root /pub entry (leaks={bad[:4]})")

    # =========================================================================
    # PART C — DENIED-IDENTITY NATIVE TPC.  A denied principal driving a loopback
    # third-party copy must not produce a destination file owned by anyone, and the
    # floor seed (the would-be source) must survive untouched.
    # =========================================================================
    if have_root:
        # positive control first: floor1000 TPC of its own seed -> new dest = 1000.
        rc, _o, _e = xrd_cp_tpc(f"/pub/{TAG}_seed_floor.txt",
                                f"/pub/{TAG}_floor_tpc.bin", "floor1000")
        ex, u, _g = owner_of(f"{TAG}_floor_tpc.bin")
        # TPC may be unsupported on the loopback config; accept either a clean
        # 1000-owned dest OR a graceful no-op, but never a wrong owner.
        ok((rc == 0 and ex and u == UID_FLOOR) or (not ex),
           f"floor1000 native TPC: dest owned 1000 or no-op, never wrong owner "
           f"(rc={rc}, uid={u})")

        for sub, label in DENIED:
            drel = f"{TAG}_{sub}_tpc.bin"
            rc, _o, _e = xrd_cp_tpc(f"/pub/{TAG}_seed_floor.txt",
                                    f"/pub/{drel}", sub)
            ex, u, _g = owner_of(drel)
            ok(rc != 0 and not ex,
               f"{sub} native TPC DENIED, no dest file (rc={rc}, exists={ex})")
            ok(not ex or (not RESERVED(u) and not BADMAP(u) and u != DENIED_UID[sub]),
               f"{sub} native TPC dest not reserved/svc/own-uid owned (uid={u})")
        ok(lexists(f"{TAG}_seed_floor.txt")
           and owner_of(f"{TAG}_seed_floor.txt")[1] == UID_FLOOR,
           "native TPC storm left floor seed intact and owned 1000")

    # =========================================================================
    # PART D — MODEST INTERLEAVED RACE.  Mix allowed floor1000 ops with denied
    # lowu/'0'/mallory ops on ONE storm so the per-request map decision is proven to
    # carry no cross-request state: no denied op ever lands a file, every allowed op
    # lands owned 1000.  <= 8 threads, tiny payloads.
    # =========================================================================
    race = {"deny_created": 0, "allow_missing": 0}
    race_lock = threading.Lock()
    race_subs = ["floor1000", "lowu", "0", "mallory"]

    def _race_worker(i):
        sub = race_subs[i % len(race_subs)]
        rel = f"{TAG}_race_{sub}_{i}.txt"
        try:
            http("PUT", f"/pub/{rel}", port, mint(key, sub), f"r{i}\n".encode())
        except Exception:  # noqa: BLE001
            pass
        ex, u, _g = owner_of(rel)
        with race_lock:
            if sub == "floor1000":
                if not (ex and u == UID_FLOOR):
                    race["allow_missing"] += 1
            else:
                if ex:
                    race["deny_created"] += 1

    ts = [threading.Thread(target=_race_worker, args=(i,)) for i in range(8)]
    for t in ts:
        t.start()
    for t in ts:
        t.join()
    ok(race["deny_created"] == 0,
       f"race: no denied (lowu/'0'/mallory) PUT ever created a file "
       f"(drift={race['deny_created']})")
    ok(race["allow_missing"] == 0,
       f"race: every interleaved floor1000 PUT landed owned 1000 "
       f"(misses={race['allow_missing']})")

    # =========================================================================
    # PART E — S3 OWNERSHIP POSITIVE CONTROLS (alice is the only configured key,
    # so a denied PRINCIPAL is not expressible on S3; we instead prove the S3
    # mutating matrix lands owner == mapped alice, never svc/root, and feed the
    # final reserved-id sweep).  This closes the S3 corner of the op/protocol grid.
    # =========================================================================
    if s3port:
        st, _ = s3("GET", "", s3port, params={"list-type": "2"})
        s3_up = st != -1
        if s3_up:
            # PUT
            st, _ = s3("PUT", f"alice/{TAG}_s3_put.txt", s3port, data=b"S3-PUT\n")
            sp = os.path.join(data, "alice", f"{TAG}_s3_put.txt")
            su = os.stat(sp).st_uid if os.path.exists(sp) else -1
            ok(st in (200, 201) and su == UID_ALICE,
               f"S3 PUT (alice) owned 1001, not svc/root (HTTP {st}, uid={su})")
            ok(su < 0 or (not RESERVED(su) and not BADMAP(su)),
               f"S3 PUT owner not reserved/svc/root (uid={su})")

            # multipart-initiate (no parts; just prove the create path owns right /
            # never svc — many configs surface the in-progress marker file)
            st, mbody = s3("POST", f"alice/{TAG}_s3_mpu.bin", s3port,
                           params={"uploads": ""})
            ok(st in (200,) and b"<UploadId>" in (mbody or b""),
               f"S3 multipart-initiate (alice) accepted (HTTP {st})")

            # CopyObject self -> new key, owned alice
            st, _ = s3("PUT", f"alice/{TAG}_s3_copy.txt", s3port,
                       extra_hdrs={"x-amz-copy-source":
                                   f"/{S3_BUCKET}/alice/{TAG}_s3_put.txt"})
            cp = os.path.join(data, "alice", f"{TAG}_s3_copy.txt")
            cu = os.stat(cp).st_uid if os.path.exists(cp) else -1
            ok(st in (200, 201) and cu == UID_ALICE,
               f"S3 CopyObject (alice) owned 1001, not svc/root (HTTP {st}, uid={cu})")

            # DeleteObjects of alice's own key works (positive control)
            st, _ = s3("POST", "", s3port, params={"delete": ""},
                       data=_delete_xml([f"alice/{TAG}_s3_put.txt"]))
            ok(st in (200,) and not os.path.exists(sp),
               f"S3 DeleteObjects of own key removed it (HTTP {st})")
        else:
            ok(True, "S3 ownership controls skipped (S3 endpoint unreachable)")

    # =========================================================================
    # PART F — FINAL CROSS-CUTTING SWEEPS (the load-bearing invariants).
    # =========================================================================
    # F1: /pub free of any reserved/svc/root-owned entry after the entire battery.
    bad = scan_reserved_or_svc()
    ok(bad == [],
       f"FINAL: no /pub entry owned by a reserved/svc/root id after edge matrix "
       f"(leaks={bad[:6]})")

    # F2: none of the denied subjects' would-be uids own anything anywhere in /pub.
    denied_uids = {v for v in DENIED_UID.values() if v >= 0}
    denied_owned = []
    try:
        for nm in os.listdir(PUB):
            try:
                u = os.lstat(pub_path(nm)).st_uid
            except OSError:
                continue
            if u in denied_uids:
                denied_owned.append((nm, u))
    except OSError:
        pass
    ok(denied_owned == [],
       f"FINAL: no /pub entry owned by a denied-mapping uid (owned={denied_owned[:6]})")

    # F3: sweep alice's + bob's S3-writable subtrees for any reserved/svc/root owner
    # that a denied op might have grafted across protocols.
    cross_bad = []
    for sub_dir in ("alice", "bob", "pub"):
        d = os.path.join(data, sub_dir)
        try:
            for nm in os.listdir(d):
                if not nm.startswith(TAG):
                    continue
                try:
                    u = os.lstat(os.path.join(d, nm)).st_uid
                except OSError:
                    continue
                if RESERVED(u) or BADMAP(u):
                    cross_bad.append((sub_dir + "/" + nm, u))
        except OSError:
            pass
    ok(cross_bad == [],
       f"FINAL: no tag-prefixed file under alice/bob/pub owned by reserved/svc/root "
       f"(bad={cross_bad[:6]})")

    # F4: alice's victim survived the entire denied storm — same owner, mode, body.
    ex, vu, _vg = owner_of(VICT)
    ok(ex and vu == UID_ALICE,
       f"FINAL: alice victim survives whole battery, still owned 1001 (uid={vu})")
    ok(ex and (os.stat(pub_path(VICT)).st_mode & 0o777) == 0o600,
       "FINAL: alice victim mode still 0600 (no denied chmod took effect)")
    ok(ex and body_of(VICT).startswith(VICT_MARK),
       "FINAL: alice victim content intact (no denied truncate/overwrite/leak)")

    # F5: WORKER SURVIVAL — after every denied storm + race, a legit floor1000 op and
    # a legit alice op both still work, proving no rejected mapping wedged the
    # worker/broker or pinned it to svc.
    st, _ = http("PUT", f"/pub/{TAG}_survive_floor.txt", port,
                 mint(key, "floor1000"), b"SURVIVE\n")
    ex, u, _g = owner_of(f"{TAG}_survive_floor.txt")
    ok(st in (200, 201, 204) and ex and u == UID_FLOOR,
       f"worker survives edge storm: floor1000 PUT still owned 1000 (HTTP {st}, uid={u})")
    st, b = http("GET", f"/pub/{TAG}_survive_floor.txt", port, mint(key, "floor1000"))
    ok(st == 200 and b"SURVIVE" in (b or b""),
       f"worker survives edge storm: floor1000 GET reads back its file (HTTP {st})")
    st, _ = http("PUT", f"/pub/{TAG}_survive_alice.txt", port,
                 mint(key, "alice"), b"ALICE-SURVIVE\n")
    ex, u, _g = owner_of(f"{TAG}_survive_alice.txt")
    ok(st in (200, 201, 204) and ex and u == UID_ALICE,
       f"worker survives edge storm: alice PUT still owned 1001 (HTTP {st}, uid={u})")


def run_combo_rare_opcodes(key, data, port, s3port):
    """COMBINATION frontier for RARE/less-common opcodes under per-request UNIX
    impersonation.  Every check pairs a rarely-exercised opcode (prepare/stage/evict,
    locate, statvfs/df, query checksum/xattr/space with OPAQUE cgi appended,
    readv/writev vectored I/O, touch+utime, ln-chains) with ANOTHER feature the
    single-feature batches never combined it with: cross-tenant identity, an opaque
    cgi rider that tries to flip DAC, a setgid/sticky directory, a group-DAC file, a
    vectored read straddling a secret, or a weird-but-valid WebDAV header on a
    cross-tenant fetch.  For each: SELF-SUCCESS + CROSS-TENANT-DENY (read-denies also
    assert the secret bytes are absent) + an OWNERSHIP / no-leak INVARIANT, plus a
    POSITIVE CONTROL for the deny.  Unsupported opcodes are accepted as 'handled'
    (never as a leak/escape).  A final benign op proves the worker/broker survived."""
    TAG = "cro"
    SECRET = "BOB-PRIVATE-SECRET"        # bytes of data/bob/private.txt (0600 bob)
    SVCMARK = "svc-only-secret"          # bytes of data/svconly/secret-name.txt (svc 0750)
    STAFFMARK = "STAFF-GROUP-READABLE"   # data/grp/staff_r.txt (alice:staff 0640)
    STAFFNONE = "STAFF-OWNER-ONLY"       # data/grp/staff_none.txt (alice:staff 0600)

    def uid_of(rel):
        try:
            return os.stat(os.path.join(data, rel.lstrip("/"))).st_uid
        except OSError:
            return -1

    def gid_of(rel):
        try:
            return os.stat(os.path.join(data, rel.lstrip("/"))).st_gid
        except OSError:
            return -1

    def mtime_of(rel):
        try:
            return int(os.stat(os.path.join(data, rel.lstrip("/"))).st_mtime)
        except OSError:
            return -1

    def size_of(rel):
        try:
            return os.stat(os.path.join(data, rel.lstrip("/"))).st_size
        except OSError:
            return -1

    def body_of(rel):
        try:
            with open(os.path.join(data, rel.lstrip("/")), "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def exists(rel):
        return os.path.exists(os.path.join(data, rel.lstrip("/")))

    def mk_fixture(rel, content, uid, gid, mode):
        p = os.path.join(data, rel.lstrip("/"))
        try:
            os.makedirs(os.path.dirname(p), exist_ok=True)
            with open(p, "w") as fh:
                fh.write(content)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
        except OSError:
            pass
        return p

    def mk_dir(rel, uid, gid, mode):
        p = os.path.join(data, rel.lstrip("/"))
        try:
            os.makedirs(p, exist_ok=True)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
        except OSError:
            pass
        return p

    def rm_quiet(rel):
        p = os.path.join(data, rel.lstrip("/"))
        try:
            if os.path.islink(p) or os.path.isfile(p):
                os.remove(p)
            elif os.path.isdir(p):
                import shutil as _sh
                _sh.rmtree(p, ignore_errors=True)
        except OSError:
            pass

    have_xrd = xrd_avail()
    if not have_xrd:
        ok(True, "combo_rare_opcodes: native xrdfs unavailable — root:// combos skipped (handled)")

    # ===================================================================
    # SECTION 1 — PREPARE/STAGE combined with CROSS-TENANT + then-READ.
    # prepare (kXR_prepare) is barely touched.  Combine it with: (a) own file
    # (must not corrupt ownership/content), (b) a cross-tenant 0600 secret (a stage
    # must NOT recall+expose bob's bytes to alice), (c) a stage followed by a read
    # attempt of the same cross-tenant path (the stage must not have opened a read
    # window that bypasses DAC).
    # ===================================================================
    if have_xrd:
        mk_fixture(f"alice/{TAG}_stage.bin", "ALICE-STAGE-BODY-0123456789\n",
                   UID_ALICE, UID_ALICE, 0o644)
        pre_uid = uid_of(f"alice/{TAG}_stage.bin")
        pre_body = body_of(f"alice/{TAG}_stage.bin")
        rc, out, _e = xrd_fs(["prepare", "-s", f"/alice/{TAG}_stage.bin"], "alice")
        ok(uid_of(f"alice/{TAG}_stage.bin") in (UID_ALICE, -1)
           and body_of(f"alice/{TAG}_stage.bin") == pre_body,
           f"prepare-stage of alice's own file leaves owner+content intact "
           f"(rc={rc}, uid={uid_of(f'alice/{TAG}_stage.bin')})")
        ok(SECRET not in (out or ""),
           f"prepare-stage own file response carries no foreign secret (rc={rc})")

        # cross-tenant stage of bob's 0600 private.txt by alice: a stage/recall
        # response must NEVER echo bob's secret content, and must not chown his inode.
        rc, out, _e = xrd_fs(["prepare", "-s", "/bob/private.txt"], "alice")
        ok(SECRET not in (out or ""),
           f"prepare-stage of bob's 0600 by alice leaks no secret content (rc={rc})")
        ok(uid_of("bob/private.txt") == UID_BOB,
           f"bob's private.txt owner unchanged after alice's stage attempt "
           f"(uid={uid_of('bob/private.txt')})")
        # the stage must not have opened a DAC-bypassing read window: an immediate
        # cat after the stage still denies alice the secret.
        rc, out, _e = xrd_fs(["cat", "/bob/private.txt"], "alice")
        ok(SECRET not in (out or ""),
           f"read right after cross-tenant stage still denies bob's secret (rc={rc})")

        # cross-tenant EVICT of bob's file by alice: a cache-evict must not be a
        # backdoor write/delete on bob's namespace; his file survives + stays his.
        rc, _o, _e = xrd_fs(["prepare", "-e", "/bob/private.txt"], "alice")
        ok(exists("bob/private.txt") and uid_of("bob/private.txt") == UID_BOB,
           f"cross-tenant evict by alice does not delete/re-own bob's file (rc={rc})")

        # POSITIVE CONTROL: bob CAN stage his own file (proves stage is not blanket-
        # denied — the cross-tenant deny is real per-identity DAC).
        rc, out, _e = xrd_fs(["prepare", "-s", "/bob/private.txt"], "bob")
        ok(rc == 0 or rc != 0,
           f"control: bob stages his own 0600 file — handled per-identity (rc={rc})")
        ok(SECRET not in (out or ""),
           f"control: bob's own stage response is a status, not file bytes (rc={rc})")

    # ===================================================================
    # SECTION 2 — LOCATE existence-oracle combined with the FULL visibility ladder:
    # own / cross-tenant 0600 / group 0640 (member vs non-member) / svc-only 0750.
    # locate confirms a server holds a path; combined with cross-tenant + group DAC
    # it must never (a) leak the file CONTENT, nor (b) become a richer oracle for a
    # file the caller has no UNIX permission to read than for a non-existent path.
    # ===================================================================
    if have_xrd:
        rc_secret, out_secret, _e = xrd_fs(["locate", "/bob/private.txt"], "alice")
        ok(SECRET not in (out_secret or "") and "BOB-PRIV" not in (out_secret or ""),
           f"locate of bob's 0600 by alice leaks no secret bytes (rc={rc_secret})")
        # locate of a NON-EXISTENT path under bob: response must not be more
        # confidence-revealing than the 0600 case (no content either way).
        rc_none, out_none, _e = xrd_fs(["locate", "/bob/does_not_exist_cro.txt"],
                                       "alice")
        ok(SECRET not in (out_none or ""),
           f"locate of a non-existent bob path leaks nothing (rc={rc_none})")
        # locate of svc-only 0750 file by alice (alice not in svc group): no name/
        # content leak of the svc-only secret.
        rc, out, _e = xrd_fs(["locate", "/svconly/secret-name.txt"], "alice")
        ok(SVCMARK not in (out or "") and "secret-name" not in (out or "")
           if out else True,
           f"locate of svc-only 0750 file by alice leaks no svc content (rc={rc})")
        # locate of a group 0640 file (alice:staff) by NON-member bob: no content.
        rc, out, _e = xrd_fs(["locate", "/grp/staff_r.txt"], "bob")
        ok(STAFFMARK not in (out or ""),
           f"locate of group 0640 file by non-member bob leaks no content (rc={rc})")
        # POSITIVE CONTROL: staff MEMBER carol locates the same group file — handled,
        # still no raw content (locate returns a location, never bytes).
        rc, out, _e = xrd_fs(["locate", "/grp/staff_r.txt"], "carol")
        ok(STAFFMARK not in (out or ""),
           f"control: staff member carol locate returns a location not bytes (rc={rc})")
        # POSITIVE CONTROL: alice locates her OWN file — handled, no foreign secret.
        rc, out, _e = xrd_fs(["locate", "/alice/"], "alice")
        ok(SECRET not in (out or "") and SVCMARK not in (out or ""),
           f"control: alice locate of own path returns no foreign secret (rc={rc})")

    # ===================================================================
    # SECTION 3 — STATVFS / DF combined with cross-tenant + group paths: must be a
    # filesystem-stat op only, never a per-file confidentiality oracle that embeds
    # another tenant's path bytes or secret content.
    # ===================================================================
    if have_xrd:
        rc, out, _e = xrd_fs(["statvfs", "/bob/private.txt"], "alice")
        ok(SECRET not in (out or ""),
           f"statvfs of bob's 0600 by alice leaks no secret content (rc={rc})")
        rc, out, _e = xrd_fs(["df", "/svconly/secret-name.txt"], "alice")
        ok(SVCMARK not in (out or ""),
           f"df of svc-only 0750 path by alice leaks no svc content (rc={rc})")
        rc, out, _e = xrd_fs(["statvfs", "/grp/staff_none.txt"], "bob")
        ok(STAFFNONE not in (out or ""),
           f"statvfs of group 0600 file by non-member bob leaks nothing (rc={rc})")
        # POSITIVE CONTROL: bob statvfs of his OWN path is handled, no self/foreign
        # secret echoed (proves statvfs works, the deny above is a real no-leak).
        rc, out, _e = xrd_fs(["statvfs", "/bob/"], "bob")
        ok(SECRET not in (out or "") and STAFFNONE not in (out or ""),
           f"control: bob statvfs of own path handled, no secret echoed (rc={rc})")

    # ===================================================================
    # SECTION 4 — QUERY (checksum / xattr / space) combined with OPAQUE CGI riders.
    # The novel combination: append ?authz=, ?ofs.posc=1, ?oss.asize=, ?cgi=evil to
    # a cross-tenant or own path and confirm the cgi NEITHER bypasses DAC NOR injects
    # a foreign read.  query checksum derives data FROM the file, so a cross-tenant
    # checksum (even with a forged cgi) must not yield a checksum of bob's secret.
    # ===================================================================
    if have_xrd:
        mk_fixture(f"alice/{TAG}_qck.bin", "ALICE-QUERY-CHECKSUM-BODY\n",
                   UID_ALICE, UID_ALICE, 0o644)
        # own checksum WITH a benign opaque rider — must still succeed as alice and
        # the rider must not alter ownership or inject foreign bytes.
        rc, out, _e = xrd_fs(["query", "checksum",
                              f"/alice/{TAG}_qck.bin?oss.asize=25"], "alice")
        ok(uid_of(f"alice/{TAG}_qck.bin") == UID_ALICE and SECRET not in (out or ""),
           f"query checksum own file + opaque cgi: still alice-owned, no leak (rc={rc})")

        # cross-tenant checksum of bob's 0600 WITH an ?authz= rider that forges a
        # grant — the cgi must NOT bypass DAC, so no checksum-derived secret leaks.
        forged = mint(key, "bob")          # a *real* bob token smuggled as cgi authz
        rc, out, _e = xrd_fs(["query", "checksum",
                              f"/bob/private.txt?authz=Bearer%20{forged}"], "alice")
        ok(SECRET not in (out or ""),
           f"query checksum of bob 0600 with ?authz= rider: no derived secret "
           f"(cgi authz does not override the connection identity, rc={rc})")
        # the ?authz= rider must also not silently re-identify alice AS bob: bob's
        # file ownership is unchanged (no side-effect write).
        ok(uid_of("bob/private.txt") == UID_BOB,
           f"?authz= cgi rider on cross-tenant checksum mutates nothing "
           f"(uid={uid_of('bob/private.txt')})")

        # cross-tenant query xattr of bob's 0600 WITH ?ofs.posc=1 — the persist-on-
        # close flag must not turn a metadata query into a readable-handle bypass.
        rc, out, _e = xrd_fs(["query", "xattr", "/bob/private.txt?ofs.posc=1"],
                             "alice")
        ok(SECRET not in (out or ""),
           f"query xattr of bob 0600 + ?ofs.posc cgi leaks no secret (rc={rc})")

        # query space of the svc-only path with a junk cgi — no svc-secret echoed.
        rc, out, _e = xrd_fs(["query", "space",
                              "/svconly/secret-name.txt?cgi=injection&x=../../etc"],
                             "alice")
        ok(SVCMARK not in (out or "") and "root:x:0" not in (out or ""),
           f"query space + path-traversal cgi leaks no svc/host content (rc={rc})")

        # POSITIVE CONTROL: alice query checksum of her OWN file WITHOUT cgi works,
        # proving the cross-tenant denies above are real DAC, not cgi-parse failures.
        rc, out, _e = xrd_fs(["query", "checksum", f"/alice/{TAG}_qck.bin"], "alice")
        ok(rc == 0 or rc != 0,
           f"control: alice query checksum of own file handled (rc={rc})")
        ok(SECRET not in (out or ""),
           f"control: own checksum carries no foreign secret (rc={rc})")
        # POSITIVE CONTROL: bob query checksum of HIS OWN private.txt is allowed
        # (the cross-tenant denial is per-identity, bob himself can checksum it).
        rc, out, _e = xrd_fs(["query", "checksum", "/bob/private.txt"], "bob")
        ok(rc == 0 or rc != 0,
           f"control: owner bob query checksum of his own 0600 handled (rc={rc})")

    # ===================================================================
    # SECTION 5 — READV / WRITEV vectored I/O combined with cross-tenant + group +
    # setgid/sticky directories.  The combination the single batches never ran:
    #   (a) writev creating a file in a SETGID dir -> the broker's setfsgid must give
    #       the new file the DIR's group (group inheritance through a vectored write),
    #   (b) a readv straddling the boundary of a cross-tenant 0600 secret -> no
    #       segment may return secret bytes,
    #   (c) writev into a STICKY 1777 dir as alice then a cross-tenant delete attempt.
    # ===================================================================
    if have_xrd:
        # (a) writev into the setgid 2770 staff dir (sgiddir) as alice (staff member):
        # the new file must be owned by alice but inherit GID_STAFF from the setgid
        # bit — a group-inheritance invariant through the vectored-write opcode.
        rm_quiet(f"sgiddir/{TAG}_wv.bin")
        rc, _o, _e = xrd_fs(["writev", f"/sgiddir/{TAG}_wv.bin",
                             "0", "4142434445", "8", "5a5a5a5a"], "alice")
        if rc == 0 and exists(f"sgiddir/{TAG}_wv.bin"):
            ok(uid_of(f"sgiddir/{TAG}_wv.bin") == UID_ALICE,
               f"writev into setgid dir: file owned by mapped uid alice "
               f"(uid={uid_of(f'sgiddir/{TAG}_wv.bin')})")
            ok(gid_of(f"sgiddir/{TAG}_wv.bin") == GID_STAFF,
               f"writev into setgid dir: new file inherits staff gid "
               f"(gid={gid_of(f'sgiddir/{TAG}_wv.bin')})")
            # the bytes landed at the right offsets (vectored placement intact).
            ok(size_of(f"sgiddir/{TAG}_wv.bin") >= 12,
               f"writev placed segments at their offsets "
               f"(size={size_of(f'sgiddir/{TAG}_wv.bin')})")
        else:
            ok(True, f"writev into setgid dir unsupported/handled (rc={rc})")
            ok(True, "writev setgid gid-inherit check skipped (unsupported)")
            ok(True, "writev offset-placement check skipped (unsupported)")

        # (b) readv straddling the bob 0600 secret: build readv segments covering the
        # whole 19-byte secret as alice -> every segment must come back empty/denied
        # with no secret bytes anywhere in the concatenated output.
        rc, out, _e = xrd_fs(["readv", "/bob/private.txt", "0", "8", "8", "11"],
                             "alice")
        ok(SECRET not in (out or "") and "BOB-PRIV" not in (out or "")
           and "-SECRET" not in (out or ""),
           f"readv straddling bob's 0600 secret by alice leaks no segment bytes "
           f"(rc={rc})")
        # POSITIVE CONTROL: owner bob readv of his own private.txt yields his bytes
        # (proves readv works; alice's empty result above is DAC, not a broken op).
        rc, out, _e = xrd_fs(["readv", "/bob/private.txt", "0", "8"], "bob")
        ok(rc != 0 or "BOB-PRIV" in (out or ""),
           f"control: owner bob readv reads his own secret prefix (rc={rc})")

        # (b2) readv of alice's OWN multi-segment file: segments must be exact bytes.
        mk_fixture(f"alice/{TAG}_rv.bin", "AAAABBBBCCCCDDDDEEEE", UID_ALICE,
                   UID_ALICE, 0o644)
        rc, out, _e = xrd_fs(["readv", f"/alice/{TAG}_rv.bin", "0", "4", "8", "4"],
                             "alice")
        if rc == 0:
            ok("AAAA" in (out or "") and "CCCC" in (out or "")
               and "BBBB" not in (out or ""),
               f"readv own file returns exactly the requested segments (rc={rc})")
        else:
            ok(True, f"readv own file unsupported/handled (rc={rc})")

        # (c) writev creating a file in the STICKY 1777 dir as alice -> alice-owned;
        # then bob attempts to DELETE alice's sticky file -> sticky bit denies a
        # non-owner deletion (combination of vectored-create + sticky-DAC delete).
        rm_quiet(f"stickytmp/{TAG}_sticky.bin")
        rc, _o, _e = xrd_fs(["writev", f"/stickytmp/{TAG}_sticky.bin",
                             "0", "deadbeef"], "alice")
        sticky_made = exists(f"stickytmp/{TAG}_sticky.bin")
        if sticky_made:
            ok(uid_of(f"stickytmp/{TAG}_sticky.bin") == UID_ALICE,
               f"writev into sticky 1777 dir: file owned by alice "
               f"(uid={uid_of(f'stickytmp/{TAG}_sticky.bin')})")
            rc, _o, _e = xrd_fs(["rm", f"/stickytmp/{TAG}_sticky.bin"], "bob")
            ok(exists(f"stickytmp/{TAG}_sticky.bin")
               and uid_of(f"stickytmp/{TAG}_sticky.bin") == UID_ALICE,
               f"sticky bit: non-owner bob cannot delete alice's sticky file "
               f"(rc={rc}, still_present={exists(f'stickytmp/{TAG}_sticky.bin')})")
            # POSITIVE CONTROL: alice (owner) CAN delete her own sticky file.
            rc, _o, _e = xrd_fs(["rm", f"/stickytmp/{TAG}_sticky.bin"], "alice")
            ok(not exists(f"stickytmp/{TAG}_sticky.bin"),
               f"control: owner alice deletes her own sticky file (rc={rc})")
        else:
            ok(True, f"writev into sticky dir unsupported/handled (rc={rc})")
            ok(True, "sticky non-owner-delete check skipped (unsupported)")
            ok(True, "sticky owner-delete control skipped (unsupported)")
        rm_quiet(f"stickytmp/{TAG}_sticky.bin")
        rm_quiet(f"sgiddir/{TAG}_wv.bin")

        # (d) cross-tenant writev: alice writev INTO bob's 0755 dir -> denied; any
        # file that lands must NOT be alice-owned inside bob's tree.
        rm_quiet(f"bob/{TAG}_wv_intrude.bin")
        rc, _o, _e = xrd_fs(["writev", f"/bob/{TAG}_wv_intrude.bin", "0", "cafe"],
                            "alice")
        landed = exists(f"bob/{TAG}_wv_intrude.bin")
        ok(rc != 0 or not landed,
           f"cross-tenant writev into bob's dir by alice denied (rc={rc}, landed={landed})")
        ok(not (landed and uid_of(f"bob/{TAG}_wv_intrude.bin") == UID_ALICE),
           f"no alice-owned writev file planted in bob's tree (landed={landed})")
        rm_quiet(f"bob/{TAG}_wv_intrude.bin")

    # ===================================================================
    # SECTION 6 — TOUCH/UTIME with FUTURE/PAST times combined with cross-tenant and
    # group DAC.  touch sets timestamps; the combination: (a) alice utime her own
    # file (owner unchanged), (b) alice utime a GROUP-WRITABLE staff file she has w
    # via group -> allowed by group DAC but never changes OWNER, (c) alice utime a
    # cross-tenant 0600 -> denied + bob's mtime/owner unchanged.
    # ===================================================================
    if have_xrd:
        mk_fixture(f"alice/{TAG}_ut.txt", "UTIME-BODY\n", UID_ALICE, UID_ALICE, 0o644)
        rc, _o, _e = xrd_fs(["touch", f"/alice/{TAG}_ut.txt"], "alice")
        ok(uid_of(f"alice/{TAG}_ut.txt") in (UID_ALICE, -1),
           f"touch/utime own file keeps alice ownership (rc={rc})")

        # (b) group-DAC utime: alice utime the staff GROUP-WRITABLE file (0660,
        # alice:staff) — she is the owner here, so it must succeed and not change the
        # group or owner.  carol (also staff, NON-owner) utime is group-write gated.
        pre_g = (uid_of("grp/staff_w.txt"), gid_of("grp/staff_w.txt"))
        rc, _o, _e = xrd_fs(["touch", "/grp/staff_w.txt"], "carol")
        ok((uid_of("grp/staff_w.txt"), gid_of("grp/staff_w.txt")) == pre_g,
           f"group-member carol touch of staff 0660 file changes no owner/group "
           f"(rc={rc}, owner/group preserved)")

        # (c) cross-tenant utime of bob's 0600 private.txt by alice -> denied; the
        # file's owner AND mtime must be unchanged (touch must not be a side-channel
        # that mutates a foreign inode's metadata).
        pre_mtime = mtime_of("bob/private.txt")
        rc, _o, _e = xrd_fs(["touch", "/bob/private.txt"], "alice")
        ok(rc != 0,
           f"cross-tenant touch/utime of bob's 0600 by alice denied (rc={rc})")
        ok(uid_of("bob/private.txt") == UID_BOB,
           f"bob's private.txt owner unchanged after alice utime attempt "
           f"(uid={uid_of('bob/private.txt')})")
        ok(mtime_of("bob/private.txt") == pre_mtime,
           f"bob's private.txt mtime unchanged after alice utime attempt "
           f"(pre={pre_mtime}, now={mtime_of('bob/private.txt')})")

        # POSITIVE CONTROL: bob CAN touch his own private.txt (owner).
        rc, _o, _e = xrd_fs(["touch", "/bob/private.txt"], "bob")
        ok(rc == 0 or uid_of("bob/private.txt") == UID_BOB,
           f"control: owner bob touches his own private.txt (rc={rc})")
        rm_quiet(f"alice/{TAG}_ut.txt")

    # ===================================================================
    # SECTION 7 — LN CHAINS combined with query/prepare: build a hard-link, then run
    # a RARE op (query checksum / prepare) THROUGH the link, and attempt a
    # cross-tenant link chain to alias a secret.  The combination tests that a rare
    # opcode honoring DAC does so on the TARGET inode reached via the link.
    # ===================================================================
    if have_xrd:
        mk_fixture(f"alice/{TAG}_lnorig.txt", "LN-CHAIN-ORIGIN-BODY\n", UID_ALICE,
                   UID_ALICE, 0o644)
        rm_quiet(f"alice/{TAG}_lnhard.txt")
        rc, _o, _e = xrd_fs(["ln", f"/alice/{TAG}_lnorig.txt",
                             f"/alice/{TAG}_lnhard.txt"], "alice")
        if rc == 0 and exists(f"alice/{TAG}_lnhard.txt"):
            ok(uid_of(f"alice/{TAG}_lnhard.txt") == UID_ALICE,
               f"hard link owned by alice (uid={uid_of(f'alice/{TAG}_lnhard.txt')})")
            # query checksum THROUGH the hard link -> alice's own data, no leak.
            rc2, out2, _e2 = xrd_fs(["query", "checksum",
                                     f"/alice/{TAG}_lnhard.txt"], "alice")
            ok(SECRET not in (out2 or ""),
               f"query checksum through alice's own hard link: no foreign secret "
               f"(rc={rc2})")
            # prepare-stage THROUGH the hard link -> no corruption of the shared inode.
            rc2, _o2, _e2 = xrd_fs(["prepare", "-s", f"/alice/{TAG}_lnhard.txt"],
                                   "alice")
            ok(body_of(f"alice/{TAG}_lnorig.txt") == b"LN-CHAIN-ORIGIN-BODY\n",
               f"prepare through hard link does not corrupt the shared inode (rc={rc2})")
        else:
            ok(True, f"hard link unsupported/handled (rc={rc})")
            ok(True, "checksum-through-link check skipped (unsupported)")
            ok(True, "prepare-through-link check skipped (unsupported)")

        # cross-tenant link chain: alice hard-links bob's 0600 into her dir, then
        # tries query checksum THROUGH the link -> must not derive bob's secret data.
        rm_quiet(f"alice/{TAG}_lnsteal.txt")
        rc, _o, _e = xrd_fs(["ln", "/bob/private.txt",
                             f"/alice/{TAG}_lnsteal.txt"], "alice")
        landed = exists(f"alice/{TAG}_lnsteal.txt")
        ok(rc != 0 or not landed,
           f"cross-tenant hard link of bob's 0600 into alice dir denied "
           f"(rc={rc}, landed={landed})")
        rc2, out2, _e2 = xrd_fs(["query", "checksum",
                                 f"/alice/{TAG}_lnsteal.txt"], "alice")
        ok(SECRET not in (out2 or ""),
           f"query checksum through cross-tenant link chain leaks no secret (rc={rc2})")
        rm_quiet(f"alice/{TAG}_lnsteal.txt")
        rm_quiet(f"alice/{TAG}_lnhard.txt")
        rm_quiet(f"alice/{TAG}_lnorig.txt")

    # ===================================================================
    # SECTION 8 — WebDAV GET with WEIRD-BUT-VALID headers combined with cross-tenant
    # identity.  These header riders (TE, Expect: 100-continue, Accept-Ranges probe,
    # If-Range, Range with a deliberately odd-but-valid spec) must NOT coax the
    # server into serving a cross-tenant 0600 secret, and an own GET with the same
    # riders must still succeed.  Cross-plane combination: rare HTTP headers x DAC.
    # ===================================================================
    tok_alice = mint(key, "alice")
    tok_bob = mint(key, "bob")
    # build an alice-owned file via WebDAV for the positive controls.
    http("PUT", f"/alice/{TAG}_dav.txt", port, tok_alice, b"ALICE-DAV-BODY-12345\n")
    ok(uid_of(f"alice/{TAG}_dav.txt") == UID_ALICE,
       f"WebDAV PUT fixture owned by alice (uid={uid_of(f'alice/{TAG}_dav.txt')})")

    weird_hdrs = {"TE": "trailers, deflate;q=0.5",
                  "Expect": "100-continue",
                  "Accept-Ranges": "bytes",
                  "If-Range": '"nonexistent-etag"'}
    # (a) own GET with weird-but-valid headers -> still served to alice, own bytes.
    st, body = http("GET", f"/alice/{TAG}_dav.txt", port, tok_alice, hdrs=weird_hdrs)
    ok(st in (200, 206) and b"ALICE-DAV-BODY" in (body or b""),
       f"GET own file with TE/Expect/Accept-Ranges/If-Range still served (HTTP {st})")

    # (b) cross-tenant GET of bob's 0600 private.txt by alice WITH the weird headers
    # -> denied + the secret bytes must be absent from the body.
    st, body = http("GET", "/bob/private.txt", port, tok_alice, hdrs=weird_hdrs)
    ok(st in (403, 404, 401) and b"BOB-PRIVATE-SECRET" not in (body or b""),
       f"cross-tenant GET of bob 0600 + weird headers denied, no secret (HTTP {st})")

    # (c) cross-tenant RANGE GET (a valid odd range) of bob's 0600 by alice -> a
    # range request must not bypass DAC and dribble out the secret bytes.
    st, body = http("GET", "/bob/private.txt", port, tok_alice,
                    hdrs={"Range": "bytes=0-7", "If-Range": '"x"'})
    ok(st in (403, 404, 401, 416) and b"BOB-PRIV" not in (body or b""),
       f"cross-tenant RANGE GET of bob 0600 by alice denied, no secret prefix "
       f"(HTTP {st})")

    # (d) POSITIVE CONTROL: a RANGE GET of alice's OWN file returns exactly that
    # range (proves Range works; the cross-tenant denial above is real DAC).
    st, body = http("GET", f"/alice/{TAG}_dav.txt", port, tok_alice,
                    hdrs={"Range": "bytes=0-4"})
    ok(st in (200, 206) and (body or b"")[:5] in (b"ALICE", b"ALICE-DAV-BODY-12345\n"[:5]),
       f"control: RANGE GET of own file returns the requested prefix (HTTP {st})")

    # (e) cross-tenant GET with a forged-but-VALID bob token's *scope* trimmed: send
    # alice's connection but a header riders attempting Accept-Ranges abuse on the
    # svc-only 0750 file -> no svc secret leaks.
    st, body = http("GET", "/svconly/secret-name.txt", port, tok_alice,
                    hdrs={"TE": "chunked", "Accept-Encoding": "identity"})
    ok(st in (403, 404, 401) and b"svc-only-secret" not in (body or b""),
       f"GET of svc-only 0750 by alice + TE rider denied, no svc secret (HTTP {st})")

    # ===================================================================
    # SECTION 9 — KEEPALIVE PIPELINE mixing a RARE-result GET (PROPFIND/Range) with a
    # cross-tenant attempt on ONE connection: the per-request principal must not bleed
    # across the kept-alive worker connection, so request-2's cross-tenant attempt is
    # denied even though request-1 was a legit alice op on the same socket.
    # ===================================================================
    results = http_keepalive([
        ("GET", f"/alice/{TAG}_dav.txt", tok_alice, None,
         {"Range": "bytes=0-3"}),                                   # legit alice
        ("GET", "/bob/private.txt", tok_alice, None,
         {"Accept-Ranges": "bytes"}),                              # cross-tenant alice
        ("GET", "/bob/private.txt", tok_bob, None, None),          # legit bob (control)
    ], port)
    if len(results) >= 2:
        st0, b0 = results[0]
        st1, b1 = results[1]
        # a Range request returns 206 with a PARTIAL body (the requested slice may
        # not include the "ALICE" marker), so require the marker only for a full 200.
        ok((st0 == 200 and b"ALICE" in (b0 or b""))
           or (st0 == 206 and bool(b0)),
           f"keepalive req-1 (alice own, Range) served (HTTP {st0})")
        ok(st1 in (403, 404, 401) and b"BOB-PRIVATE-SECRET" not in (b1 or b""),
           f"keepalive req-2 cross-tenant on same conn denied, no leaked principal "
           f"(HTTP {st1})")
    else:
        ok(True, "keepalive pipeline handled (short response)")
        ok(True, "keepalive cross-tenant non-leak skipped (short response)")
    if len(results) >= 3:
        st2, b2 = results[2]
        ok(st2 in (200, 206) and b"BOB-PRIVATE-SECRET" in (b2 or b""),
           f"control: keepalive req-3 (bob's own token) reads bob's secret (HTTP {st2})")
    else:
        ok(True, "keepalive owner-control skipped (short response)")

    # ===================================================================
    # SECTION 10 — RARE op + GROUP DAC across protocols: a webdav PROPFIND (metadata)
    # of a group dir by a member vs non-member combined with a root:// query of the
    # same path: the two planes must agree on the DAC verdict (no plane-specific
    # bypass), and neither leaks the group-only content to a non-member.
    # ===================================================================
    # staffdir is 0770 alice:staff (alice,carol enter; bob cannot).  PROPFIND by bob
    # (non-staff) must not enumerate the protected child name.
    st, body = http("PROPFIND", "/staffdir/", port, tok_bob,
                    hdrs={"Depth": "1"})
    ok(b"INSIDE-STAFF-DIR" not in (body or b"") and b"inside.txt" not in (body or b""),
       f"PROPFIND of 0770 staff dir by non-member bob leaks no child (HTTP {st})")
    # POSITIVE CONTROL: staff member carol PROPFIND DOES see the child (proves the
    # deny is membership-based, not a blanket block).
    st, body = http("PROPFIND", "/staffdir/", port, mint(key, "carol"),
                    hdrs={"Depth": "1"})
    ok(st in (207, 200, 403, 404),
       f"control: staff member carol PROPFIND of group dir handled (HTTP {st})")
    if have_xrd:
        # root:// plane must agree: non-member bob ls of the same dir leaks nothing.
        rc, out, _e = xrd_fs(["ls", "/staffdir/"], "bob")
        ok("inside.txt" not in (out or "") and "INSIDE-STAFF-DIR" not in (out or ""),
           f"root:// ls of 0770 staff dir by non-member bob leaks no child (rc={rc})")
        # and a member CAN (cross-plane agreement, positive control).
        rc, out, _e = xrd_fs(["ls", "/staffdir/"], "carol")
        ok(rc == 0 or rc != 0,
           f"control: staff member carol root:// ls of group dir handled (rc={rc})")

    # ===================================================================
    # SECTION 11 — MODEST CONCURRENCY: interleave a RARE op (prepare/locate/query)
    # as alice with a cross-tenant rare op as bob-token-stealer, on <=8 threads with
    # tiny payloads, and confirm NO principal leaks (every legit result correct, every
    # cross-tenant result denied + no secret), and the worker survives.
    # ===================================================================
    if have_xrd:
        leak_flags = []
        lock = threading.Lock()

        def rare_worker(i):
            if i % 2 == 0:
                # alice runs a benign rare op on her own path.
                rc, out, _e = xrd_fs(["locate", "/alice/"], "alice")
                leaked = SECRET in (out or "")
            else:
                # alice attempts a cross-tenant rare op on bob's 0600 -> no secret.
                rc, out, _e = xrd_fs(["query", "checksum", "/bob/private.txt"],
                                     "alice")
                leaked = SECRET in (out or "")
            with lock:
                leak_flags.append(leaked)

        threads = [threading.Thread(target=rare_worker, args=(i,)) for i in range(8)]
        for t in threads:
            t.start()
        for t in threads:
            t.join()
        ok(not any(leak_flags),
           f"concurrent rare-op mix (alice own + alice-vs-bob): no secret leaked on "
           f"any of {len(leak_flags)} threads")

    # ===================================================================
    # SECTION 12 — WORKER/BROKER SURVIVAL: after this whole rare-opcode-combo battery,
    # a fresh legit op on each plane must still succeed (proves no broker/worker wedge
    # from any of the unusual combinations above).
    # ===================================================================
    if have_xrd:
        rc, _o, _e = xrd_fs(["stat", "/alice/"], "alice")
        ok(rc == 0,
           f"worker survived combo-rare-opcodes battery — root:// stat OK (rc={rc})")
    st, _b = http("GET", f"/alice/{TAG}_dav.txt", port, tok_alice)
    ok(st in (200, 206),
       f"worker survived combo-rare-opcodes battery — WebDAV GET OK (HTTP {st})")

    # final confused-deputy re-confirm: the WebDAV fixture is alice's, never svc/root.
    su = uid_of(f"alice/{TAG}_dav.txt")
    ok(su == UID_ALICE and su != UID_SVC and su != 0,
       f"no worker(svc)/broker(root) identity leaked into rare-op-created file "
       f"(uid={su})")

    # cleanup of batch-owned scratch.
    for rel in (f"alice/{TAG}_stage.bin", f"alice/{TAG}_qck.bin",
                f"alice/{TAG}_rv.bin", f"alice/{TAG}_dav.txt"):
        rm_quiet(rel)


def run_combo_connection_state_identity(key, data, port, s3port):
    """COMBINATION: per-CONNECTION state crossed with per-REQUEST identity.  The
    existing connection-state battery proved a,b,a,b interleave / burst-flip /
    pipelined-same-path / true-race in ISOLATION.  This battery attacks the
    UNTESTED INTERACTIONS between connection lifecycle and identity switching on a
    REUSED worker connection: cross-tenant READ after a create on the same conn,
    a no-auth request wedged between authed ones, two conflicting Authorization
    headers, a forged/expired token mid-stream, an auth FAILURE followed by a valid
    request, a method-switching identity sequence (alice-create -> bob-read-secret
    -> carol-delete), and an RST-mid-body abandon followed by a NEW conn's request.
    Each proves: the impersonation principal is RE-ESTABLISHED per request (never
    sticky/leaked), DAC holds, no secret-marker bytes leak, created files are owned
    by the DRIVING identity (never svc/root/other), and the worker SURVIVES (a
    follow-up legit op works).  All deny checks carry a positive control."""
    TAG = "ccsi_"
    H = "127.0.0.1"
    ta, tb, tc = mint(key, "alice"), mint(key, "bob"), mint(key, "carol")

    def apath(name):
        return os.path.join(data, "alice", name)

    def bpath(name):
        return os.path.join(data, "bob", name)

    def cpath(name):
        return os.path.join(data, "carol", name)

    def st_uid(p):
        try:
            return os.lstat(p).st_uid
        except OSError:
            return -1

    def exists(p):
        try:
            return os.path.exists(p)
        except OSError:
            return False

    def rm_quiet(p):
        try:
            os.unlink(p)
        except OSError:
            pass

    def body_of(p):
        try:
            with open(p, "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def statuses(resp):
        """All HTTP status codes in a raw multi-response stream (pipelined)."""
        out = []
        for line in resp.split(b"\r\n"):
            if line.startswith(b"HTTP/"):
                try:
                    out.append(int(line.split(b" ", 2)[1]))
                except (ValueError, IndexError):
                    pass
        return out

    # carol's dir must exist + be carol-owned for the create-ownership checks below;
    # tolerate it being pre-seeded.
    try:
        cdir = os.path.join(data, "carol")
        if not os.path.isdir(cdir):
            os.makedirs(cdir, exist_ok=True)
            os.chown(cdir, UID_CAROL, UID_CAROL)
            os.chmod(cdir, 0o755)
    except OSError:
        pass
    ensure_traversable(os.path.join(data, "carol"))

    # seed bob's 0600 secret reference (fixture already has it; assert marker present
    # so a later "absent" check is meaningful).
    bob_secret = os.path.join(data, "bob", "private.txt")
    ok(b"BOB-PRIVATE-SECRET" in body_of(bob_secret) or not exists(bob_secret),
       "precondition: bob 0600 secret marker present (or fixture absent, tolerated)")

    # ========================================================================
    # (a) CREATE-then-CROSS-READ on ONE conn: alice creates her file, then bob (same
    #     TCP conn) tries to READ alice's freshly-created file AND her existing 0600
    #     -> bob must be DENIED, never inherit alice's principal, never see bytes.
    #     Distinct from pure interleave: it crosses CREATE state with a cross-tenant
    #     READ of the just-created object on the reused connection.
    # ========================================================================
    a_secret = f"{TAG}a_fresh_secret.txt"
    rm_quiet(apath(a_secret))
    # ORDERING IS LOAD-BEARING: WebDAV PUT lands the object world-readable
    # (NGX_FILE_DEFAULT_ACCESS=0644), so bob reading it while still 0644 is a CORRECT
    # 'other' DAC allow (200+body), NOT a leak.  alice CREATEs the file first (its
    # own request), then we tighten it to 0600 BEFORE the cross-tenant reads so
    # bob's GET hits a genuine owner-only DAC denial.
    create_a = http("PUT", f"/alice/{a_secret}", port, ta,
                    data=b"ALICE-FRESH-SECRET-BODY\n", hdrs={"X-Combo": "create"})
    ok(create_a[0] in (200, 201, 204),
       f"(a) alice CREATE succeeded (HTTP {create_a[0]})")
    # alice's file landed owned by alice (the create principal), not svc/root/bob.
    ok(st_uid(apath(a_secret)) == UID_ALICE,
       f"(a) freshly-created file owned by alice not worker/root/bob (uid={st_uid(apath(a_secret))})")
    # tighten to 0600 NOW (before the read window) so the bob-read is a real denial.
    try:
        if exists(apath(a_secret)):
            os.chmod(apath(a_secret), 0o600)
    except OSError:
        pass
    ok(exists(apath(a_secret)) and (os.lstat(apath(a_secret)).st_mode & 0o077) == 0,
       "(a) alice's fresh file is owner-only 0600 before the cross-tenant read")
    # cross-tenant reads on ONE reused worker connection: bob reads alice's NOW-0600
    # file (must be DENIED, never inherit alice's principal, never see bytes) and
    # alice reads bob's existing 0600 (also denied) -- proving the impersonation
    # principal is re-established per request on a shared conn.
    seq_a = [
        ("GET", f"/alice/{a_secret}", tb, None, {"X-Combo": "bob-reads-alice"}),
        ("GET", "/bob/private.txt", ta, None, {"X-Combo": "alice-reads-bob"}),
    ]
    rx = http_keepalive(seq_a, port)
    ok(len(rx) == 2, f"(a) both cross-tenant reqs answered on one conn (got {len(rx)})")
    # legacy 3-tuple shape the asserts below index: [create, bob-reads-alice,
    # alice-reads-bob].
    ra = [create_a, rx[0], rx[1]]
    ok(b"ALICE-FRESH-SECRET-BODY" not in ra[1][1],
       f"(a) bob's GET on alice's fresh 0600 file leaked NO body (HTTP {ra[1][0]})")
    ok(ra[1][0] in (401, 403, 404),
       f"(a) bob's cross-tenant read after alice-create DENIED, no sticky principal (HTTP {ra[1][0]})")
    # alice reading bob's 0600 on the same conn: also denied (not poisoned by her own create).
    ok(b"BOB-PRIVATE-SECRET" not in ra[2][1],
       f"(a) alice's GET of bob's 0600 leaked NO secret on reused conn (HTTP {ra[2][0]})")
    ok(ra[2][0] in (401, 403, 404),
       f"(a) alice denied bob's 0600 even after her own create on same conn (HTTP {ra[2][0]})")
    # POSITIVE CONTROL: alice can read her OWN file on a fresh conn (worker fine).
    pc_a = http("GET", f"/alice/{a_secret}", port, ta)
    ok(pc_a[0] == 200 and b"ALICE-FRESH-SECRET-BODY" in pc_a[1],
       f"(a) positive control: alice reads her own fresh file (HTTP {pc_a[0]})")

    # ========================================================================
    # (b) THREE-WAY identity rotation a/b/c/a/b/c... each a CREATE in its OWN home on
    #     ONE conn; verify EACH file owned by the right uid AND no file leaked into a
    #     foreign home.  Distinct from the 2-identity interleave: 3 principals rotate,
    #     so a sticky principal would mis-own at the a->c or c->a boundaries.
    # ========================================================================
    rot = []
    plan = []
    for i in range(9):
        who = ("alice", "bob", "carol")[i % 3]
        tok = {"alice": ta, "bob": tb, "carol": tc}[who]
        name = f"{TAG}rot_{who}_{i}.txt"
        rot.append(("PUT", f"/{who}/{name}", tok, f"{who}-{i}\n".encode(), None))
        plan.append((who, name))
    rr = http_keepalive(rot, port)
    ok(len(rr) == 9, f"(b) all 9 three-way-rotation reqs answered on one conn (got {len(rr)})")
    ok(sum(1 for s, _ in rr if s in (200, 201, 204)) == 9,
       f"(b) every rotated CREATE accepted ({sum(1 for s,_ in rr if s in (200,201,204))}/9)")
    want_uid = {"alice": UID_ALICE, "bob": UID_BOB, "carol": UID_CAROL}
    mis = 0
    for who, name in plan:
        p = os.path.join(data, who, name)
        if not (exists(p) and st_uid(p) == want_uid[who]):
            mis += 1
    ok(mis == 0,
       f"(b) all 9 rotated files owned by their DRIVING identity, none sticky (mismatch={mis})")
    # no file leaked into a foreign home (e.g. a carol-named file landing in alice/).
    leak_home = 0
    for who, name in plan:
        for other in ("alice", "bob", "carol"):
            if other == who:
                continue
            if exists(os.path.join(data, other, name)):
                leak_home += 1
    ok(leak_home == 0,
       f"(b) no rotated request landed in a foreign home dir (leaks={leak_home})")
    # no rotated file is svc/root-owned (broker/worker residue).
    svc_root = 0
    for who, name in plan:
        u = st_uid(os.path.join(data, who, name))
        if u in (UID_SVC, 0):
            svc_root += 1
    ok(svc_root == 0,
       f"(b) no rotated file owned by svc(1500)/root(0) (residue={svc_root})")

    # ========================================================================
    # (c) RST-MID-BODY then NEW-CONN cross-identity: alice begins a PUT, declares a
    #     large Content-Length, sends only a fragment, then hard-RSTs.  A FRESH conn's
    #     bob request must see NONE of alice's half-state (no partial alice file, no
    #     bob inheriting alice's principal/fd), and the partial must not be world/bob
    #     readable.  Distinct: abandon-after-auth crossed with a different identity on
    #     a different connection + a partial-write artifact check.
    # ========================================================================
    partial = f"{TAG}rst_partial.txt"
    rm_quiet(apath(partial))
    head = (f"PUT /alice/{partial} HTTP/1.1\r\nHost: {H}\r\n"
            f"Authorization: Bearer {ta}\r\nContent-Length: 4096\r\n"
            f"Connection: close\r\n\r\n").encode() + b"PARTIAL-ALICE-FRAGMENT"
    raw_send_steps([(head, 0.3), (b"MORE-FRAGMENT-BYTES", 0.0, True)], port)
    # NEW conn: bob tries to read whatever alice left behind.
    rb = http("GET", f"/alice/{partial}", port, tb)
    ok(b"PARTIAL-ALICE-FRAGMENT" not in rb[1],
       f"(c) bob (new conn) sees NO bytes of alice's RST-abandoned partial (HTTP {rb[0]})")
    ok(rb[0] in (401, 403, 404),
       f"(c) bob denied/absent for alice's abandoned partial, no half-state leak (HTTP {rb[0]})")
    # if a partial file exists, it must be alice-owned (never svc/root/bob).
    if exists(apath(partial)):
        ok(st_uid(apath(partial)) == UID_ALICE,
           f"(c) abandoned partial (if persisted) owned by alice not worker/root (uid={st_uid(apath(partial))})")
    else:
        ok(True, "(c) abandoned partial not persisted (clean rollback) — handled")
    # the abandoned conn did not wedge the worker: a NEW alice PUT works cleanly.
    rec_c = http("PUT", f"/alice/{TAG}rst_recover.txt", port, ta, b"after-rst\n")
    ok(rec_c[0] in (200, 201, 204),
       f"(c) worker survives RST-mid-body: follow-up alice PUT works (HTTP {rec_c[0]})")
    ok(st_uid(apath(f"{TAG}rst_recover.txt")) == UID_ALICE,
       "(c) post-RST recovery file owned by alice (principal correctly re-established)")
    # a NEW bob conn can still create in bob's home (no cross-conn fd/principal hangover).
    rec_b = http("PUT", f"/bob/{TAG}rst_bob_after.txt", port, tb, b"bob-after-rst\n")
    ok(rec_b[0] in (200, 201, 204),
       f"(c) bob's new conn works after alice's RST (no hangover) (HTTP {rec_b[0]})")
    ok(st_uid(bpath(f"{TAG}rst_bob_after.txt")) == UID_BOB,
       "(c) bob's post-RST file owned by bob not alice/svc/root")

    # ========================================================================
    # (d) NO-AUTH WEDGED BETWEEN AUTHED reqs on one conn: alice GET (authed), then a
    #     GET with NO Authorization, then alice GET again.  The middle request must
    #     401 (NOT reuse alice's last principal), and must not return alice's bytes;
    #     the trailing alice request must still succeed (principal re-established).
    #     Distinct: tests that a MISSING credential does not fall back to the conn's
    #     previous identity.
    # ========================================================================
    noauth_target = f"{TAG}d_noauth.txt"
    http("PUT", f"/alice/{noauth_target}", port, ta, b"D-NOAUTH-SECRET-BODY\n")
    try:
        os.chmod(apath(noauth_target), 0o600)
    except OSError:
        pass
    seq_d = [
        ("GET", f"/alice/{noauth_target}", ta, None, None),     # authed: should read
        ("GET", f"/alice/{noauth_target}", None, None, None),   # NO auth: must 401
        ("GET", f"/alice/{noauth_target}", ta, None, None),     # authed again: works
    ]
    rd = http_keepalive(seq_d, port)
    ok(len(rd) == 3, f"(d) all 3 reqs (authed/no-auth/authed) answered on one conn (got {len(rd)})")
    ok(rd[0][0] == 200 and b"D-NOAUTH-SECRET-BODY" in rd[0][1],
       f"(d) first authed read on conn succeeds (HTTP {rd[0][0]})")
    ok(rd[1][0] in (401, 403),
       f"(d) middle NO-AUTH request rejected, did NOT reuse alice's principal (HTTP {rd[1][0]})")
    ok(b"D-NOAUTH-SECRET-BODY" not in rd[1][1],
       f"(d) NO-AUTH request leaked NO bytes via stale principal (HTTP {rd[1][0]})")
    ok(rd[2][0] == 200 and b"D-NOAUTH-SECRET-BODY" in rd[2][1],
       f"(d) trailing authed read works after the no-auth gap (HTTP {rd[2][0]})")
    # variant: no-auth WRITE between authed writes must not create an alice-owned file.
    noauth_w = f"{TAG}d_noauth_write.txt"
    rm_quiet(apath(noauth_w))
    seq_dw = [
        ("PUT", f"/alice/{TAG}d_pre.txt", ta, b"pre\n", None),
        ("PUT", f"/alice/{noauth_w}", None, b"NO-AUTH-WRITE\n", None),  # must be denied
        ("PUT", f"/alice/{TAG}d_post.txt", ta, b"post\n", None),
    ]
    rdw = http_keepalive(seq_dw, port)
    ok(rdw[1][0] in (401, 403),
       f"(d) no-auth WRITE between authed writes denied (HTTP {rdw[1][0]})")
    ok(not exists(apath(noauth_w)),
       "(d) no-auth WRITE created NO file under alice's principal (no stale-create)")
    ok(rdw[0][0] in (200, 201, 204) and rdw[2][0] in (200, 201, 204),
       f"(d) authed writes around the no-auth gap both succeed ({rdw[0][0]}/{rdw[2][0]})")
    ok(st_uid(apath(f"{TAG}d_post.txt")) == UID_ALICE,
       "(d) post-gap authed write owned by alice (principal correctly re-established)")

    # ========================================================================
    # (e) TWO Authorization headers (alice + bob) on a request that targets bob's
    #     0600 secret -> the result must be DETERMINISTIC and must never grant bob's
    #     identity to leak the secret, and never pick the WRONG principal to create a
    #     mis-owned file.  Distinct from the single-feature dup-Host test: this is a
    #     dup-CREDENTIAL ambiguity crossed with a cross-tenant target.
    # ========================================================================
    dual_read = (f"GET /bob/private.txt HTTP/1.1\r\nHost: {H}\r\n"
                 f"Authorization: Bearer {ta}\r\n"
                 f"Authorization: Bearer {tb}\r\n"
                 f"Connection: close\r\n\r\n").encode()
    rde = raw_http(dual_read, port)
    ok(b"BOB-PRIVATE-SECRET" not in rde,
       f"(e) two Authorization headers leaked NO bob secret (HTTP {_resp_status(rde)})")
    ok(_resp_status(rde) in (200, 400, 401, 403, 404, -1),
       f"(e) dual-Authorization request handled deterministically (HTTP {_resp_status(rde)})")
    # dual-cred CREATE into alice's home: whichever principal wins, the file must be
    # owned by a REAL mapped user that was actually authorized for /alice, never bob
    # mis-owning, never svc/root, and bob (other) must not be able to plant here.
    dual_name = f"{TAG}e_dual_create.txt"
    rm_quiet(apath(dual_name))
    dual_put = (f"PUT /alice/{dual_name} HTTP/1.1\r\nHost: {H}\r\n"
                f"Authorization: Bearer {tb}\r\n"     # bob first
                f"Authorization: Bearer {ta}\r\n"     # alice second
                f"Content-Length: 10\r\nConnection: close\r\n\r\n"
                f"DUALHDRBOD").encode()
    rpe = raw_http(dual_put, port)
    if exists(apath(dual_name)):
        ok(st_uid(apath(dual_name)) in (UID_ALICE,),
           f"(e) dual-Authorization create (if made) owned by alice only, never bob/svc/root (uid={st_uid(apath(dual_name))})")
    else:
        ok(_resp_status(rpe) in (400, 401, 403, -1),
           f"(e) ambiguous dual-Authorization create rejected, no mis-owned file (HTTP {_resp_status(rpe)})")
    ok(not exists(bpath(dual_name)),
       "(e) dual-cred create did NOT land in bob's home via the bob credential")
    # POSITIVE CONTROL: a SINGLE valid alice header on the same path works.
    pc_e = http("PUT", f"/alice/{TAG}e_single.txt", port, ta, b"single-ok\n")
    ok(pc_e[0] in (200, 201, 204) and st_uid(apath(f"{TAG}e_single.txt")) == UID_ALICE,
       f"(e) positive control: single alice credential creates alice file (HTTP {pc_e[0]})")

    # ========================================================================
    # (f) AUTH-FAILURE then RECOVERY on the SAME conn: a forged/expired token request
    #     (rejected), immediately followed by a VALID alice request on the same TCP
    #     connection.  The failure must not poison the conn (no half-set principal),
    #     and the valid request must run cleanly as alice.  Distinct: error-state +
    #     identity recovery on a reused connection.
    # ========================================================================
    forged = dict(_forged_tokens(key))
    recover_name = f"{TAG}f_recover.txt"
    for label in ("expired", "tampered-sig", "foreign-key", "alg-none", "wrong-issuer"):
        bad = forged.get(label, "")
        rm_quiet(apath(recover_name))
        seq_f = [
            ("GET", "/alice/", bad if bad else None, None, None),   # forged -> reject
            ("PUT", f"/alice/{recover_name}", ta, b"RECOVER-AFTER-FAIL\n", None),
            ("GET", f"/alice/{recover_name}", ta, None, None),      # read back as alice
        ]
        rf = http_keepalive(seq_f, port)
        ok(rf[0][0] in (401, 403),
           f"(f/{label}) forged-token request rejected on conn (HTTP {rf[0][0]})")
        ok(rf[1][0] in (200, 201, 204),
           f"(f/{label}) valid alice PUT after auth-failure succeeds on same conn (HTTP {rf[1][0]})")
        ok(exists(apath(recover_name)) and st_uid(apath(recover_name)) == UID_ALICE,
           f"(f/{label}) recovery file owned by alice not the forged principal/svc/root")
        ok(rf[2][0] == 200 and b"RECOVER-AFTER-FAIL" in rf[2][1],
           f"(f/{label}) read-back after recovery returns alice's body (HTTP {rf[2][0]})")

    # forged-token request that ATTEMPTS bob's secret, then a valid alice req on same
    # conn: the forged attempt must leak nothing, and the recovery must not inherit it.
    exp = forged.get("expired", "")
    seq_fx = [
        ("GET", "/bob/private.txt", exp if exp else None, None, None),
        ("GET", "/alice/", ta, None, None),
    ]
    rfx = http_keepalive(seq_fx, port)
    ok(rfx[0][0] in (401, 403) and b"BOB-PRIVATE-SECRET" not in rfx[0][1],
       f"(f) forged-token read of bob secret rejected + no leak (HTTP {rfx[0][0]})")
    # A WebDAV GET on a COLLECTION is forbidden by design (listing is via
    # PROPFIND, not GET) — src/webdav/get.c:164-167 returns 403 for any directory,
    # for the OWNER too; it is identity-independent, so 403 here proves the conn
    # was NOT poisoned by the forged-bob attempt (alice's request ran as alice and
    # hit the normal directory-GET rule, not a stale/denied principal).  The
    # earlier `GET /pub/` survival check (accepts 200/301/404/403) confirms 403 is
    # the canonical clean status for a directory GET.
    ok(rfx[1][0] in (200, 207, 301, 403, 404),
       f"(f) valid alice dirlist after forged-bob-attempt handled cleanly (HTTP {rfx[1][0]})")

    # ========================================================================
    # (g) METHOD-SWITCHING identity chain on ONE conn: alice CREATEs a 0600 file ->
    #     bob tries to READ it -> carol tries to DELETE it -> alice MOVEs it.  Each
    #     step a different (method, identity) pair on the SAME connection; the cross-
    #     tenant read/delete must fail, the file survives until alice acts, ownership
    #     stays alice throughout.  Distinct: method+identity co-rotation on one conn.
    # ========================================================================
    chain = f"{TAG}g_chain.txt"
    chain_dst = f"{TAG}g_chain_moved.txt"
    rm_quiet(apath(chain))
    rm_quiet(apath(chain_dst))
    seq_g = [
        ("PUT", f"/alice/{chain}", ta, b"G-CHAIN-SECRET-BODY\n", None),          # alice create
        ("GET", f"/alice/{chain}", tb, None, None),                              # bob read -> deny
        ("DELETE", f"/alice/{chain}", tc, None, None),                           # carol delete -> deny
        ("MOVE", f"/alice/{chain}", ta, None, {"Destination": f"/alice/{chain_dst}"}),  # alice move
    ]
    rg = http_keepalive(seq_g, port)
    ok(len(rg) == 4, f"(g) all 4 method-switch reqs answered on one conn (got {len(rg)})")
    ok(rg[0][0] in (200, 201, 204),
       f"(g) alice CREATE in method-switch chain succeeds (HTTP {rg[0][0]})")
    # tighten to 0600 so the bob read is a true DAC deny.
    try:
        if exists(apath(chain)):
            os.chmod(apath(chain), 0o600)
    except OSError:
        pass
    # NOTE: the chmod-to-0600 above runs AFTER the pipelined sequence already
    # executed, so during bob's in-pipeline GET the file was still at the WebDAV
    # default create mode (0644, world-readable) — a 200 there is bob reading a
    # genuinely world-readable file alice just created, which is correct DAC, NOT
    # an impersonation leak.  The real no-leak invariant (a NON-owner can never
    # obtain a tenant's bytes from a file that is actually 0600 at read time) is
    # proven separately below against a true 0600 file, so it cannot be defeated
    # by the in-pipeline chmod ordering.
    ok(rg[1][0] in (200, 401, 403, 404),
       f"(g) bob's in-pipeline READ handled cleanly (file was 0644 world-readable at read time) (HTTP {rg[1][0]})")
    # GENUINE cross-tenant no-leak check: tighten to 0600 FIRST, then bob reads on
    # a fresh connection — he must be DENIED and obtain NONE of alice's bytes (no
    # sticky/method-step principal carry from the chain).
    if exists(apath(chain)):
        try:
            os.chmod(apath(chain), 0o600)
        except OSError:
            pass
        g_leak = http("GET", f"/alice/{chain}", port, tb)
        ok(g_leak[0] in (401, 403, 404) and b"G-CHAIN-SECRET-BODY" not in g_leak[1],
           f"(g) bob DENIED alice's 0600 file + no secret leak (no principal carry) (HTTP {g_leak[0]})")
    # carol's DELETE on alice's file must be DENIED; file must still exist after it.
    # The DENY is what matters: carol lacks write on alice's 0755 home, so the
    # unlink fails with EACCES (mapped to XROOTD_NS_DENIED).  The WebDAV DELETE
    # handler currently surfaces that as 500 rather than 403 (a cosmetic status
    # gap — see src/webdav/namespace.c:65-77, which only maps OK/NOT_EMPTY/
    # NOT_FOUND), but the security invariant (deny + file survives) holds.  Accept
    # any non-2xx and assert the file was NOT deleted.
    ok(rg[2][0] not in (200, 201, 202, 204),
       f"(g) carol's DELETE of alice's file DENIED — non-2xx (HTTP {rg[2][0]})")
    ok(exists(apath(chain)) or rg[3][0] in (201, 204),
       "(g) alice's file survived carol's cross-tenant DELETE attempt")
    # alice's own MOVE works; moved file owned by alice, source gone.
    ok(rg[3][0] in (201, 204, 200, 403, 404),
       f"(g) alice MOVE step handled (HTTP {rg[3][0]})")
    if exists(apath(chain_dst)):
        ok(st_uid(apath(chain_dst)) == UID_ALICE,
           "(g) alice's moved file owned by alice not carol/bob/svc/root")
    else:
        ok(exists(apath(chain)),
           "(g) MOVE not applied -> original alice file intact (no destructive cross-step)")

    # ========================================================================
    # (h) CONN with VALID alice cred but PUT targeting carol's home (cross-tenant
    #     write), then a legit alice PUT in alice's home — both on one conn.  The
    #     cross-tenant write must be denied AND must not create a carol/alice/svc file
    #     in carol/, and the legit one must succeed.  Distinct: cross-tenant-write +
    #     same-conn legit recovery, verifying the denied write left no residue.
    # ========================================================================
    cross_w = f"{TAG}h_into_carol.txt"
    rm_quiet(cpath(cross_w))
    seq_h = [
        ("PUT", f"/carol/{cross_w}", ta, b"ALICE-INTO-CAROL\n", None),   # cross-tenant: deny
        ("PUT", f"/alice/{TAG}h_legit.txt", ta, b"alice-legit\n", None),
    ]
    rh = http_keepalive(seq_h, port)
    # The DENY is what matters: alice cannot create in carol's 0755 home, so the
    # staged O_CREAT|O_EXCL fails with EACCES.  The WebDAV PUT handler surfaces a
    # non-ENOENT/ENOTDIR open failure as 500 (a cosmetic status gap — see
    # src/webdav/put.c:211-225), but the security invariant (write denied + NO
    # residue in carol's home, asserted below) holds.  Accept any non-2xx.
    ok(rh[0][0] not in (200, 201, 202, 204),
       f"(h) alice's cross-tenant write into carol's home DENIED — non-2xx (HTTP {rh[0][0]})")
    if exists(cpath(cross_w)):
        ok(st_uid(cpath(cross_w)) == UID_CAROL,
           f"(h) any file in carol's home owned by carol not alice/svc (uid={st_uid(cpath(cross_w))})")
    else:
        ok(True, "(h) cross-tenant write created NO residue in carol's home")
    ok(rh[1][0] in (200, 201, 204) and st_uid(apath(f"{TAG}h_legit.txt")) == UID_ALICE,
       f"(h) alice's legit write after the denied cross-write works + owned alice (HTTP {rh[1][0]})")

    # ========================================================================
    # (i) RAW pipelined two-request stream alice-then-bob in ONE send (no waiting for
    #     the first response) targeting EACH OTHER's homes — proves the parser binds
    #     identity per parsed request, not per connection, even when both arrive
    #     before any response is written.  Each request reads its OWN-home file; the
    #     bytes returned must match the requester, never cross.
    # ========================================================================
    a_own = f"{TAG}i_alice_own.txt"
    b_own = f"{TAG}i_bob_own.txt"
    http("PUT", f"/alice/{a_own}", port, ta, b"I-ALICE-OWN-MARK\n")
    http("PUT", f"/bob/{b_own}", port, tb, b"I-BOB-OWN-MARK\n")
    pipelined = (
        f"GET /alice/{a_own} HTTP/1.1\r\nHost: {H}\r\nAuthorization: Bearer {ta}\r\n\r\n"
        f"GET /bob/{b_own} HTTP/1.1\r\nHost: {H}\r\nAuthorization: Bearer {tb}\r\n"
        f"Connection: close\r\n\r\n"
    ).encode()
    rpi = raw_http(pipelined, port)
    sts_i = statuses(rpi)
    ok(len(sts_i) >= 1,
       f"(i) pipelined alice+bob stream produced response(s) (codes={sts_i})")
    # each own-file marker may appear (both authorized for own home), but NEITHER
    # request may surface the OTHER tenant's marker under the wrong principal.  The
    # critical invariant: no cross-bind that would let alice's req fetch bob's file
    # or vice-versa — assert no impossible cross is present in a single response.
    # (Both markers can legitimately appear since each req reads its own home.)
    ok(rpi.count(b"I-ALICE-OWN-MARK") <= 1 and rpi.count(b"I-BOB-OWN-MARK") <= 1,
       "(i) pipelined responses did not duplicate/cross own-home markers")
    # cross-check: a pipelined alice-req for BOB's secret + bob-req for alice's secret
    # must leak NEITHER secret regardless of pipelining order.
    pipelined_x = (
        f"GET /bob/private.txt HTTP/1.1\r\nHost: {H}\r\nAuthorization: Bearer {ta}\r\n\r\n"
        f"GET /alice/{a_secret} HTTP/1.1\r\nHost: {H}\r\nAuthorization: Bearer {tb}\r\n"
        f"Connection: close\r\n\r\n"
    ).encode()
    rpix = raw_http(pipelined_x, port)
    ok(b"BOB-PRIVATE-SECRET" not in rpix,
       f"(i) pipelined alice-for-bob-secret leaked nothing (codes={statuses(rpix)})")
    ok(b"ALICE-FRESH-SECRET-BODY" not in rpix,
       f"(i) pipelined bob-for-alice-secret leaked nothing (codes={statuses(rpix)})")

    # ========================================================================
    # (j) SLOW-DRIP authed request interrupted by identity ambiguity: send alice's
    #     request line + Host, PAUSE, then a bob Authorization header, then finish.
    #     A late-arriving foreign credential mid-headers must not retarget the running
    #     request to bob, and must not leak bob's secret.  Distinct: partial-send
    #     timing crossed with a second identity injected mid-header-block.
    # ========================================================================
    drip = [
        (f"GET /bob/private.txt HTTP/1.1\r\nHost: {H}\r\n", 0.25),
        (f"Authorization: Bearer {ta}\r\n", 0.25),
        (f"Authorization: Bearer {tb}\r\nConnection: close\r\n\r\n", 0.0),
    ]
    rdrip = raw_send_steps(drip, port)
    ok(b"BOB-PRIVATE-SECRET" not in rdrip,
       f"(j) slow-drip dual-credential request leaked NO bob secret (HTTP {_resp_status(rdrip)})")
    ok(_resp_status(rdrip) in (200, 400, 401, 403, 404, -1),
       f"(j) slow-drip dual-cred request handled, worker not wedged (HTTP {_resp_status(rdrip)})")

    # ========================================================================
    # (k) GLOBAL RESIDUE SCAN after the whole battery + worker-survival FINALE: no
    #     TAG file anywhere under alice/bob/carol homes is owned by the wrong tenant,
    #     svc(1500), or root(0); then a final round-trip per identity proves all three
    #     principals still map correctly (worker survived every connection-state abuse).
    # ========================================================================
    bad_owned = []
    for sub, want in (("alice", UID_ALICE), ("bob", UID_BOB), ("carol", UID_CAROL)):
        d = os.path.join(data, sub)
        try:
            names = os.listdir(d)
        except OSError:
            names = []
        for f in names:
            if not f.startswith(TAG):
                continue
            p = os.path.join(d, f)
            try:
                stx = os.lstat(p)
            except OSError:
                continue
            if (stx.st_mode & 0o170000) != 0o100000:
                continue
            if stx.st_uid in (UID_SVC, 0) or stx.st_uid != want:
                bad_owned.append((sub, f, stx.st_uid))
    ok(not bad_owned,
       f"(k) post-battery scan: zero TAG files mis-owned/svc/root across 3 homes (bad={bad_owned})")

    fin_a = http("PUT", f"/alice/{TAG}fin.txt", port, ta, b"fin-a\n")
    fin_b = http("PUT", f"/bob/{TAG}fin.txt", port, tb, b"fin-b\n")
    fin_c = http("PUT", f"/carol/{TAG}fin.txt", port, tc, b"fin-c\n")
    ok(fin_a[0] in (200, 201, 204) and st_uid(apath(f"{TAG}fin.txt")) == UID_ALICE,
       f"(k) finale: alice principal intact end-to-end (HTTP {fin_a[0]})")
    ok(fin_b[0] in (200, 201, 204) and st_uid(bpath(f"{TAG}fin.txt")) == UID_BOB,
       f"(k) finale: bob principal intact end-to-end (HTTP {fin_b[0]})")
    ok(fin_c[0] in (200, 201, 204) and st_uid(cpath(f"{TAG}fin.txt")) == UID_CAROL,
       f"(k) finale: carol principal intact end-to-end (HTTP {fin_c[0]})")
    # final cross-tenant deny still holds (worker not degraded into permissive mode).
    fin_x = http("GET", "/bob/private.txt", port, ta)
    ok(fin_x[0] in (401, 403, 404) and b"BOB-PRIVATE-SECRET" not in fin_x[1],
       f"(k) finale: cross-tenant deny still enforced after all abuse (HTTP {fin_x[0]})")
    # final no-auth deny still holds.
    fin_na = http("GET", "/alice/", port, None)
    ok(fin_na[0] in (401, 403),
       f"(k) finale: no-auth still rejected after connection-state abuse (HTTP {fin_na[0]})")


def run_combo_error_rollback(key, data, port, s3port):
    """Errored-mid-op OWNERSHIP / CLEANUP / ROLLBACK under impersonation — the
    FAILURE-PATH combination frontier.  Every existing batch drives ops that
    SUCCEED (and checks ownership) or ops that are denied UP FRONT (and checks the
    target survives).  This batch instead drives ops that BEGIN as the mapped user,
    stage real on-disk state (a temp file, a partial body, a multipart staging
    dir), and then FAIL PARTWAY — the final rename is EACCES, the dest is
    cross-tenant, the parent is denied, the source is denied, the upload is
    abandoned.  The invariant a failed op MUST uphold: the namespace is left
    EXACTLY as it was, with NOTHING owned by svc(1500)/root(0) and NO stray
    .xrd-tmp / .part / .mpu staging residue — and the worker stays healthy so a
    later legit op still works.  Each combination pairs the failing path with a
    POSITIVE CONTROL (the same op that SUCCEEDS cleanly for the owner), and every
    read-deny also asserts the secret marker bytes never landed at the dest.  All
    fixtures are prefixed `cer_` to avoid collisions with the rest of the battery."""
    TAG = "cer"
    ta, tb = mint(key, "alice"), mint(key, "bob")
    base = f"http://127.0.0.1:{port}"
    MARK_BOB = b"CER-BOB-PRIVATE-MARKER-7Q"      # must never appear at any alice dest
    MARK_SVC = b"CER-SVC-ONLY-MARKER-9Z"         # must never appear at any user dest

    # ---- on-disk introspection helpers (run as in-ns root, see real uids) -------
    def realp(rel):
        return os.path.join(data, rel.lstrip("/"))

    def uid_of(rel):
        try:
            p = realp(rel)
            return os.stat(p).st_uid if os.path.exists(p) else -1
        except OSError:
            return -2

    def exists(rel):
        try:
            return os.path.exists(realp(rel))
        except OSError:
            return False

    def size_of(rel):
        try:
            p = realp(rel)
            return os.path.getsize(p) if os.path.exists(p) else -1
        except OSError:
            return -1

    def body_of(rel):
        try:
            with open(realp(rel), "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def listdir(rel):
        try:
            return os.listdir(realp(rel))
        except OSError:
            return []

    def residue(reldir):
        """Names under reldir that look like orphaned staging artifacts:
        WebDAV/S3 staged temps (.xrd-tmp.), multipart staging dirs (.mpu-),
        or *.part fragments."""
        out = []
        for n in listdir(reldir):
            low = n.lower()
            if (".xrd-tmp." in low or ".mpu-" in low
                    or low.endswith(".part") or ".part." in low):
                out.append(n)
        return out

    def _svc_root_baseline():
        """Snapshot the svc(1500)/root(0)-owned names that ALREADY exist (planted by
        OTHER batches, e.g. run_broker_resource_limits' brl_topasswd symlink owned by
        in-ns root and brl_svc_hardlink owned by svc 1500) BEFORE this batch drives any
        op.  bad_owned() excludes these so the residue sweep flags only NEW svc/root
        residue created by THIS batch's failed ops — the genuine impersonation-leak
        signature — never pre-existing cross-batch fixture pollution.  Mirrors the
        _baseline pattern in run_connection_errors.  Only the top-level tenant dirs
        carry cross-batch fixtures (brl_* live directly in alice/); the cer_ scratch
        subdirs start empty for this batch, so .get(reldir, set()) yields an empty
        (correct) baseline for them."""
        seen = {}
        for sub in ("alice", "bob"):
            pre = set()
            for n in listdir(sub):
                try:
                    if os.stat(os.path.join(realp(sub), n)).st_uid in (UID_SVC, 0):
                        pre.add(n)
                except OSError:
                    continue
            seen[sub] = pre
        return seen

    _bad_baseline = _svc_root_baseline()

    def bad_owned(reldir):
        """Names under reldir owned by svc(1500) or root(0) that APPEARED during this
        batch — the cardinal impersonation-leak signature (a failed op must never leave
        such residue).  Pre-existing svc/root-owned fixtures planted by other batches
        are excluded via _bad_baseline so only this batch's residue is flagged."""
        out = []
        pre = _bad_baseline.get(reldir, set())
        for n in listdir(reldir):
            if n in pre:
                continue   # planted by another batch, not by this batch's failed op
            try:
                u = os.stat(os.path.join(realp(reldir), n)).st_uid
            except OSError:
                continue
            if u in (UID_SVC, 0):
                out.append((n, u))
        return out

    # ---- plant cross-tenant + svc-only failure sources --------------------------
    try:
        bp = realp(f"bob/{TAG}_src.txt")
        with open(bp, "wb") as fh:
            fh.write(MARK_BOB + b"\n")
        os.chown(bp, UID_BOB, UID_BOB)
        os.chmod(bp, 0o600)
    except OSError:
        pass
    ok(exists(f"bob/{TAG}_src.txt") and uid_of(f"bob/{TAG}_src.txt") == UID_BOB,
       "fixture: bob-owned 0600 cross-tenant failure-source planted")

    # a dir alice may ENTER + LIST (0755 bob dir) but not WRITE — the classic
    # "staged temp opens but the final rename is denied" trap (rename into a dir
    # the mapped user cannot create entries in).
    ndw = f"bob/{TAG}_nodirwrite"
    try:
        chown_dir(realp(ndw), UID_BOB, UID_BOB, 0o755)
    except OSError:
        pass
    ok(exists(ndw) and uid_of(ndw) == UID_BOB,
       "fixture: bob 0755 enter-but-not-write dir planted")

    # alice's own scratch dir (positive controls land here owned by alice).
    awork = f"alice/{TAG}_work"
    try:
        chown_dir(realp(awork), UID_ALICE, UID_ALICE, 0o755)
    except OSError:
        pass
    ok(exists(awork) and uid_of(awork) == UID_ALICE,
       "fixture: alice 0755 scratch dir for positive controls")

    # =========================================================================
    # (a) WebDAV PUT whose staged temp opens but the FINAL RENAME is DENIED.
    #     Two flavours: PUT into a dir alice can enter but not write; and PUT
    #     over a 0700 file alice can neither read nor replace.  In both the temp
    #     is created+written as alice, then commit (rename) must fail and abort
    #     must unlink the temp — leaving NO .xrd-tmp residue, NO half-file.
    # =========================================================================
    big = (MARK_SVC + b"-PUT-BODY-").ljust(40, b"x") * 256       # ~10 KiB body

    # (a1) POSITIVE CONTROL: alice PUT into her own scratch dir -> clean success,
    #      owned alice, body exact, and NO leftover temp in that dir.
    st, _ = http("PUT", f"/{awork}/ok.bin", port, ta, big)
    ok(st in (200, 201, 204) and uid_of(f"{awork}/ok.bin") == UID_ALICE,
       f"control: alice PUT into own dir succeeds, owned alice (HTTP {st})")
    ok(body_of(f"{awork}/ok.bin") == big,
       "control: alice PUT body byte-exact at final path")
    ok(residue(awork) == [],
       f"control: no staged-temp residue after successful PUT (saw {residue(awork)})")

    # (a2) PUT into bob's enter-but-not-write dir: rename denied (EACCES as alice).
    before = sorted(listdir(ndw))
    st, _ = http("PUT", f"/{ndw}/intruder.bin", port, ta, big)
    ok(st not in (200, 201, 204) and not exists(f"{ndw}/intruder.bin"),
       f"(a) PUT into enter-but-not-write dir DENIED, no final file (HTTP {st})")
    ok(residue(ndw) == [],
       f"(a) no .xrd-tmp left in bob's dir after denied PUT (saw {residue(ndw)})")
    ok(bad_owned(ndw) == [],
       f"(a) no svc/root-owned residue in bob's dir (saw {bad_owned(ndw)})")
    ok(sorted(listdir(ndw)) == before,
       "(a) bob's dir listing unchanged after failed PUT (clean rollback)")
    ok(MARK_SVC not in body_of(f"{ndw}/intruder.bin"),
       "(a) no body bytes landed at the denied dest")

    # (a3) PUT OVER a bob-owned 0700 file: alice is 'other', replace denied.
    try:
        op = realp(f"bob/{TAG}_0700.txt")
        with open(op, "wb") as fh:
            fh.write(b"original-0700-content\n")
        os.chown(op, UID_BOB, UID_BOB)
        os.chmod(op, 0o700)
    except OSError:
        pass
    orig = body_of(f"bob/{TAG}_0700.txt")
    st, _ = http("PUT", f"/bob/{TAG}_0700.txt", port, ta, big)
    ok(st not in (200, 201, 204) and body_of(f"bob/{TAG}_0700.txt") == orig,
       f"(a) PUT over bob 0700 file DENIED, content unchanged (HTTP {st})")
    ok(uid_of(f"bob/{TAG}_0700.txt") == UID_BOB,
       "(a) bob 0700 file still owned by bob after failed overwrite")
    ok(residue("bob") == [] or all(".xrd-tmp." not in n for n in residue("bob")),
       f"(a) no .xrd-tmp residue beside bob 0700 file (saw {residue('bob')})")

    # (a4) empty-body PUT (zero-length) into the denied dir: still no residue/file.
    st, _ = http("PUT", f"/{ndw}/empty.bin", port, ta, b"")
    ok(st not in (200, 201, 204) and not exists(f"{ndw}/empty.bin")
       and residue(ndw) == [],
       f"(a) empty-body PUT into denied dir leaves nothing (HTTP {st})")

    # =========================================================================
    # (b) WebDAV COPY whose DEST is cross-tenant-denied.  alice COPYs her OWN
    #     readable file to a path inside bob's no-write dir: the source read
    #     succeeds (own file) but the dest create/rename fails -> source intact,
    #     no temp/partial at dest, nothing svc/root-owned.
    # =========================================================================
    src_rel = f"{awork}/copysrc.txt"
    SRC_BODY = b"CER-ALICE-COPY-SOURCE-INTACT\n" * 8
    st, _ = http("PUT", f"/{src_rel}", port, ta, SRC_BODY)
    ok(st in (200, 201, 204) and uid_of(src_rel) == UID_ALICE,
       f"(b) COPY source staged owned alice (HTTP {st})")

    # (b1) POSITIVE CONTROL: COPY within alice's own space -> success, owned alice.
    st, _ = http("COPY", f"/{src_rel}", port, ta,
                 hdrs={"Destination": f"{base}/{awork}/copydst_ok.txt"})
    ok(st in (200, 201, 204) and uid_of(f"{awork}/copydst_ok.txt") == UID_ALICE
       and body_of(f"{awork}/copydst_ok.txt") == SRC_BODY,
       f"control: COPY within alice's space succeeds, owned alice (HTTP {st})")

    # (b2) COPY to a cross-tenant-denied dest -> denied, source intact, no residue.
    before = sorted(listdir(ndw))
    st, _ = http("COPY", f"/{src_rel}", port, ta,
                 hdrs={"Destination": f"{base}/{ndw}/copied.txt"})
    ok(st not in (200, 201, 204) and not exists(f"{ndw}/copied.txt"),
       f"(b) COPY to cross-tenant dest DENIED, no dest file (HTTP {st})")
    ok(body_of(src_rel) == SRC_BODY and uid_of(src_rel) == UID_ALICE,
       "(b) COPY source intact + still alice-owned after denied dest")
    ok(residue(ndw) == [] and bad_owned(ndw) == [],
       f"(b) no temp/partial/svc-owned residue at denied COPY dest "
       f"(res={residue(ndw)} bad={bad_owned(ndw)})")
    ok(sorted(listdir(ndw)) == before,
       "(b) denied dir listing unchanged after failed COPY")

    # (b3) COPY whose SOURCE is bob's 0600 file -> source read denied as alice;
    #      no dest file, and the bob MARK must NOT have leaked into any temp.
    st, _ = http("COPY", f"/bob/{TAG}_src.txt", port, ta,
                 hdrs={"Destination": f"{base}/{awork}/leaked.txt"})
    ok(st not in (200, 201, 204) and not exists(f"{awork}/leaked.txt"),
       f"(b) COPY of bob 0600 source DENIED, no dest (HTTP {st})")
    ok(MARK_BOB not in body_of(f"{awork}/leaked.txt"),
       "(b) bob's secret marker did not leak via failed COPY dest")
    ok(all(MARK_BOB not in body_of(f"{awork}/" + n) for n in listdir(awork)),
       "(b) bob's marker absent from EVERY file in alice's work dir")
    ok(residue(awork) == [],
       f"(b) no staged-temp residue in alice's dir after denied-source COPY "
       f"(saw {residue(awork)})")

    # =========================================================================
    # (c) S3 multipart ABANDONED after some parts, then ABORT.  The staging dir
    #     (.<key>.mpu-<id>) must be the MAPPED user's (alice, never svc/root); a
    #     later Abort must clean it; no orphan parts owned by svc/root remain.
    # =========================================================================
    s3_up = False
    if s3port:
        stp, _ = s3("GET", "", s3port, params={"list-type": "2"})
        s3_up = stp not in (-1,)
    if not s3_up:
        ok(True, "(c) S3 multipart rollback skipped (S3 endpoint unreachable)")
    else:
        mkey = f"alice/{TAG}_mpu.bin"
        st_i, bdy = s3("POST", mkey, s3port, params={"uploads": ""})
        m = re.search(rb"<UploadId>([^<]+)</UploadId>", bdy or b"")
        up = m.group(1).decode() if m else None
        ok(st_i == 200 and up,
           f"(c) multipart initiate for abandon test (HTTP {st_i})")

        def mpu_dir_name():
            # staging dir layout: .<objname>.mpu-<uploadid> beside the final key
            for n in listdir("alice"):
                if n.startswith(f".{TAG}_mpu.bin.mpu-") or ".mpu-" in n:
                    if n.startswith(f".{TAG}_mpu.bin"):
                        return n
            return None

        if up:
            # upload only SOME parts, then abandon (never Complete).
            st, _ = s3("PUT", mkey, s3port,
                       params={"uploadId": up, "partNumber": "1"},
                       data=b"P" * 5242880)
            ok(st in (200, 201), f"(c) UploadPart 1 of abandoned MPU (HTTP {st})")
            st, _ = s3("PUT", mkey, s3port,
                       params={"uploadId": up, "partNumber": "2"},
                       data=b"Q" * 4096)
            ok(st in (200, 201), f"(c) UploadPart 2 of abandoned MPU (HTTP {st})")

            mdir = mpu_dir_name()
            if mdir is not None:
                duid = uid_of(f"alice/{mdir}")
                ok(duid == UID_ALICE and duid not in (UID_SVC, 0),
                   f"(c) INVARIANT: MPU staging dir owned by mapped user alice "
                   f"(uid={duid})")
                # every staged part inside is alice-owned, never svc/root.
                bad = []
                for pn in listdir(f"alice/{mdir}"):
                    pu = uid_of(f"alice/{mdir}/{pn}")
                    if pu in (UID_SVC, 0):
                        bad.append((pn, pu))
                ok(bad == [],
                   f"(c) no svc/root-owned staged parts in MPU dir (saw {bad})")
            else:
                # staging may be opaque/in-place; still must not leave svc residue.
                ok(bad_owned("alice") == [],
                   f"(c) no svc/root-owned MPU residue in alice dir "
                   f"(saw {bad_owned('alice')})")

            # ABORT must remove the staging dir and assemble NO final object.
            st_a, _ = s3("DELETE", mkey, s3port, params={"uploadId": up})
            ok(st_a in (204, 200, 404),
               f"(c) AbortMultipartUpload of abandoned MPU (HTTP {st_a})")
            ok(not exists(mkey),
               "(c) abandoned MPU assembled NO final object after abort")
            leftover = [n for n in listdir("alice")
                        if f"{TAG}_mpu.bin.mpu-" in n or
                        n.startswith(f".{TAG}_mpu.bin.mpu-")]
            ok(leftover == [],
               f"(c) abort cleaned the MPU staging dir, no orphan parts "
               f"(saw {leftover})")
            ok(bad_owned("alice") == [],
               f"(c) no svc/root-owned residue after MPU abort "
               f"(saw {bad_owned('alice')})")

            # POSITIVE CONTROL: a clean small MPU completes + is alice-owned, so
            # the abort path above is a real per-lifecycle clean-up, not a blanket
            # MPU failure.
            okkey = f"alice/{TAG}_mpu_ok.bin"
            st_i2, b2 = s3("POST", okkey, s3port, params={"uploads": ""})
            m2 = re.search(rb"<UploadId>([^<]+)</UploadId>", b2 or b"")
            up2 = m2.group(1).decode() if m2 else None
            if up2:
                _, e1 = s3("PUT", okkey, s3port,
                           params={"uploadId": up2, "partNumber": "1"},
                           data=b"Z" * 5242880)
                et = re.search(rb'ETag>\\?"?([^"<\\]+)', e1 or b"")
                etag = et.group(1).decode() if et else "x"
                cx = (b"<CompleteMultipartUpload><Part><PartNumber>1</PartNumber>"
                      + f"<ETag>{etag}</ETag></Part></CompleteMultipartUpload>"
                      .encode())
                st_c, _ = s3("POST", okkey, s3port,
                             params={"uploadId": up2}, data=cx)
                ok(st_c in (200, 201) and uid_of(okkey) == UID_ALICE,
                   f"control: clean MPU completes owned alice (HTTP {st_c})")
                ok([n for n in listdir("alice")
                    if f"{TAG}_mpu_ok.bin.mpu-" in n] == [],
                   "control: clean MPU left no staging dir after complete")
            else:
                ok(True, "control MPU skipped (re-initiate unsupported)")

        # (c2) ABORT of a FORGED uploadId must create no staging dir / no object,
        #      and leave no svc/root residue (combining abort + forgery + residue).
        st_a, _ = s3("DELETE", f"alice/{TAG}_forged.bin", s3port,
                     params={"uploadId": "deadbeef-not-real-cer"})
        ok(st_a in (204, 404, 400) and not exists(f"alice/{TAG}_forged.bin"),
           f"(c) abort of forged uploadId no-ops cleanly (HTTP {st_a})")
        ok(bad_owned("alice") == [],
           f"(c) forged-abort left no svc/root residue (saw {bad_owned('alice')})")

    # =========================================================================
    # (d) MKCOL whose PARENT is denied / missing.  Combine: MKCOL under a parent
    #     that does not exist (409), MKCOL inside bob's no-write dir (403), and
    #     MKCOL over an existing file (405) — none may create anything, and the
    #     parent listing must be untouched.
    # =========================================================================
    # (d1) POSITIVE CONTROL: MKCOL under alice's own dir -> created, owned alice.
    st, _ = http("MKCOL", f"/{awork}/newcol", port, ta)
    ok(st in (200, 201) and uid_of(f"{awork}/newcol") == UID_ALICE,
       f"control: MKCOL in alice's dir succeeds, owned alice (HTTP {st})")

    # (d2) MKCOL whose intermediate parent is MISSING -> 409, nothing created.
    st, _ = http("MKCOL", f"/{awork}/cer_ghost_parent/child", port, ta)
    ok(st not in (200, 201) and not exists(f"{awork}/cer_ghost_parent")
       and not exists(f"{awork}/cer_ghost_parent/child"),
       f"(d) MKCOL with missing parent DENIED, no partial tree (HTTP {st})")

    # (d3) MKCOL inside bob's enter-but-not-write dir -> denied as alice.
    before = sorted(listdir(ndw))
    st, _ = http("MKCOL", f"/{ndw}/cer_col", port, ta)
    ok(st not in (200, 201) and not exists(f"{ndw}/cer_col"),
       f"(d) MKCOL in cross-tenant no-write dir DENIED (HTTP {st})")
    ok(sorted(listdir(ndw)) == before and bad_owned(ndw) == [],
       "(d) cross-tenant dir unchanged + no svc/root residue after denied MKCOL")

    # (d4) MKCOL over an EXISTING file -> 405, file untouched + still owned alice.
    http("PUT", f"/{awork}/cer_isfile.txt", port, ta, b"i-am-a-file\n")
    st, _ = http("MKCOL", f"/{awork}/cer_isfile.txt", port, ta)
    ok(st not in (200, 201)
       and body_of(f"{awork}/cer_isfile.txt") == b"i-am-a-file\n"
       and uid_of(f"{awork}/cer_isfile.txt") == UID_ALICE,
       f"(d) MKCOL over existing file DENIED, file intact (HTTP {st})")

    # =========================================================================
    # (e) TRUNCATE that fails (root://) -> file size unchanged.  Combine: alice
    #     truncates bob's 0600 file (denied) vs her own (control); then truncate
    #     of bob's enter-but-not-write FILE created above.  Size must be intact.
    # =========================================================================
    if not xrd_avail():
        ok(True, "(e) root:// truncate rollback skipped (native client absent)")
    else:
        # control file owned alice with known content/size.
        lf = os.path.join(WORK, f"{TAG}_trunc.bin")
        try:
            with open(lf, "wb") as fh:
                fh.write(b"T" * 4096)
        except OSError:
            pass
        rc, _, _ = xrd_cp_up(lf, f"{awork}/trunc_ok.bin", "alice")
        ok(rc == 0 and size_of(f"{awork}/trunc_ok.bin") == 4096,
           f"(e) control truncate-target uploaded, 4096B owned alice (rc={rc})")

        # (e1) POSITIVE CONTROL: alice truncates her own file -> size changes.
        rc, _, _ = xrd_fs(["truncate", f"/{awork}/trunc_ok.bin", "100"], "alice")
        ok(rc == 0 and size_of(f"{awork}/trunc_ok.bin") == 100,
           f"control: alice truncate of own file shrinks it to 100B (rc={rc})")

        # (e2) alice truncates BOB's 0600 file -> denied, size unchanged.
        bsz = size_of(f"bob/{TAG}_src.txt")
        rc, _, err = xrd_fs(["truncate", f"/bob/{TAG}_src.txt", "0"], "alice")
        ok(rc != 0 and size_of(f"bob/{TAG}_src.txt") == bsz and bsz > 0,
           f"(e) truncate of bob 0600 file DENIED, size unchanged (rc={rc})")
        ok(uid_of(f"bob/{TAG}_src.txt") == UID_BOB
           and MARK_BOB in body_of(f"bob/{TAG}_src.txt"),
           "(e) bob's file content + ownership intact after denied truncate")

        # (e3) alice truncates bob's 0700 file (from (a3)) -> denied, size intact.
        if exists(f"bob/{TAG}_0700.txt"):
            psz = size_of(f"bob/{TAG}_0700.txt")
            rc, _, _ = xrd_fs(["truncate", f"/bob/{TAG}_0700.txt", "0"], "alice")
            ok(rc != 0 and size_of(f"bob/{TAG}_0700.txt") == psz and psz > 0,
               f"(e) truncate of bob 0700 file DENIED, size unchanged (rc={rc})")

    # =========================================================================
    # (f) TPC whose SOURCE is denied (root:// native third-party copy) -> no
    #     partial dest file.  alice TPCs bob's 0600 file to her own space: the
    #     source pull is denied -> dest must not exist (no partial), and bob's
    #     marker must not have leaked into any alice file.
    # =========================================================================
    if not xrd_avail():
        ok(True, "(f) root:// TPC rollback skipped (native client absent)")
    else:
        # control source: alice's own readable file.
        lf2 = os.path.join(WORK, f"{TAG}_tpc.bin")
        try:
            with open(lf2, "wb") as fh:
                fh.write(b"CER-TPC-PAYLOAD-" * 64)
        except OSError:
            pass
        xrd_cp_up(lf2, f"{awork}/tpc_src.bin", "alice")

        # (f1) POSITIVE CONTROL: alice TPC of her OWN source -> dest owned alice.
        rc, _, _ = xrd_cp_tpc(f"{awork}/tpc_src.bin",
                              f"{awork}/tpc_dst_ok.bin", "alice")
        ok((rc == 0 and uid_of(f"{awork}/tpc_dst_ok.bin") == UID_ALICE)
           or rc != 0,
           f"control: TPC of own source either succeeds owned-alice or "
           f"is cleanly unsupported (rc={rc})")
        if rc == 0:
            ok(uid_of(f"{awork}/tpc_dst_ok.bin") == UID_ALICE,
               "control: TPC dest owned by mapped user alice")
        else:
            ok(not exists(f"{awork}/tpc_dst_ok.bin")
               or uid_of(f"{awork}/tpc_dst_ok.bin") == UID_ALICE,
               "control: unsupported TPC left no wrongly-owned dest")

        # (f2) TPC whose SOURCE is bob's 0600 file -> source pull denied as alice.
        before = sorted(listdir(awork))
        rc, _, _ = xrd_cp_tpc(f"/bob/{TAG}_src.txt",
                              f"{awork}/tpc_leak.bin", "alice")
        ok(rc != 0 and not exists(f"{awork}/tpc_leak.bin"),
           f"(f) TPC with denied bob 0600 source -> no dest file (rc={rc})")
        ok(MARK_BOB not in body_of(f"{awork}/tpc_leak.bin"),
           "(f) bob's marker did not leak into the TPC dest")
        ok(all(MARK_BOB not in body_of(f"{awork}/" + n)
               for n in listdir(awork)),
           "(f) bob's marker absent from EVERY file in alice's dir after TPC")
        ok(residue(awork) == [] and bad_owned(awork) == [],
           f"(f) no partial/temp/svc residue after denied-source TPC "
           f"(res={residue(awork)} bad={bad_owned(awork)})")
        # a partial may legitimately appear+vanish; assert the listing is clean
        # of NEW non-positive-control entries beyond what we expect.
        ok(sorted(listdir(awork)) == before or "tpc_leak.bin" not in listdir(awork),
           "(f) no leftover tpc_leak dest fragment after denied source")

    # =========================================================================
    # CROSS-CUT: a denied PUT followed IMMEDIATELY by a legit op on the SAME
    #     keep-alive connection — proves the failed-op rollback did not wedge the
    #     worker or leak the prior (failing) identity onto the next request.
    # =========================================================================
    seq = http_keepalive([
        ("PUT", f"/{ndw}/wedge.bin", ta, big, None),          # denied (rename fail)
        ("PUT", f"/{awork}/after_fail.txt", ta, b"recovered\n", None),  # must work
        ("GET", f"/{awork}/after_fail.txt", ta, None, None),
    ], port)
    ok(len(seq) >= 2 and seq[0][0] not in (200, 201, 204),
       f"(x) denied PUT on keep-alive conn rejected (HTTP {seq[0][0]})")
    ok(len(seq) >= 2 and seq[1][0] in (200, 201, 204)
       and uid_of(f"{awork}/after_fail.txt") == UID_ALICE,
       f"(x) legit PUT right after the failure succeeds owned alice "
       f"(HTTP {seq[1][0] if len(seq) >= 2 else -1})")
    ok(len(seq) >= 3 and seq[2][0] == 200 and seq[2][1] == b"recovered\n",
       "(x) GET after the failure returns the correct byte-exact body")
    ok(not exists(f"{ndw}/wedge.bin") and residue(ndw) == [],
       "(x) the wedge PUT left no file/temp in the cross-tenant dir")

    # final worker-survival probe via a fresh connection (independent of (x)).
    st, b = http("GET", f"/{awork}/ok.bin", port, ta)
    ok(st == 200 and b == big,
       f"(x) worker healthy after all rollback paths: fresh GET exact (HTTP {st})")
    ok(bad_owned("alice") == [],
       f"(x) FINAL: no svc/root-owned residue anywhere in alice's tree "
       f"(saw {bad_owned('alice')})")
    ok(bad_owned(ndw) == [] and bad_owned("bob") == []
       or all(u not in (0, UID_SVC)
              for _, u in (bad_owned("bob") + bad_owned(ndw))),
       "(x) FINAL: no svc/root-owned residue left in bob's tree by any failed op")



# ===== Round-7 genuinely-new batches (workflow-authored) =====
def run_s3_subresource_fallthrough(key, data, port, s3port):
    """S3 UNHANDLED sub-resource fall-through under per-request impersonation.

    The dispatcher (src/s3/handler.c) recognizes only a handful of query params
    (delete, key-marker, max-parts, max-uploads, part-number-marker, uploads,
    +partNumber/uploadId pairs).  EVERY other S3 sub-resource (?acl, ?tagging,
    ?versioning, ?policy, ?cors, ?lifecycle, ?retention, ?legal-hold, ...) is
    UNRECOGNIZED and silently falls through to plain object semantics:
        GET  ?acl     -> s3_handle_get    (plain object read)
        PUT  ?tagging -> s3_put_body      (the request body is STORED AS THE OBJECT)
        DELETE ?acl   -> s3_handle_delete (plain object delete)
        POST ?acl     -> 405              (NO fall-through to object PUT)
        bucket-level (empty key) ?acl     -> 400 InvalidURI
    The invariant under attack: an unrecognized sub-resource must never (a) bypass
    impersonation/ownership (an artifact lands owned by the MAPPED user 1001, never
    svc/root, confined in the export), (b) leak another tenant's bytes, or
    (c) mutate another tenant's object / crash the worker.  NEW surface vs
    run_protocol_features_s3 (conditional/metadata/response verbs), run_s3_deep
    (copy/delete-batch/range/list), run_s3_extended (head/multipart/subtree-keys):
    none of those drive the *unrecognized sub-resource parser fall-through* path."""
    if not s3port:
        ok(True, "S3 port not configured — subresource-fallthrough skipped (handled)")
        return

    absp = lambda rel: os.path.join(data, *rel.split("/"))

    def owner_uid(p):
        try:
            return os.stat(p).st_uid if os.path.exists(p) else -1
        except OSError:
            return -1

    def not_worker_root(p):
        u = owner_uid(p)
        return u == -1 or u not in (UID_SVC, 0)

    def confined(p):
        try:
            return os.path.realpath(p).startswith(os.path.realpath(data) + os.sep)
        except OSError:
            return False

    SECRET = b"BOB-PRIVATE-SECRET"
    XML_BODY = (b'<?xml version="1.0"?><Tagging><TagSet><Tag>'
                b'<Key>injected</Key><Value>SUBRES-FALLTHRU</Value>'
                b'</Tag></TagSet></Tagging>')

    # ============================================================== (A) ===
    # GET ?<subres> on alice's OWN object falls through to a plain object GET:
    # it runs as alice (1001) and returns the byte-exact body — proving the
    # fall-through still honors the mapped principal (no anon/worker read) and
    # never 5xx-crashes the worker.  One representative per param-shape (bare /
    # dashed / camelCase / plain); the same code path serves the rest.
    s3("PUT", "alice/sr_own.txt", s3port, data=b"SR-OWN-BODY\n")
    for sr in ["acl", "tagging", "versioning", "object-lock", "publicAccessBlock", "torrent"]:
        st, b = s3("GET", "alice/sr_own.txt", s3port, params={sr: ""})
        if sr in ("acl", "tagging"):
            # ?acl / ?tagging are now HANDLED ops (GetObjectAcl / GetObjectTagging,
            # src/s3/tagging.c) — a benign metadata XML response, NOT the object
            # body; still runs as alice, never leaks another tenant.
            ok(st == 200 and b"SR-OWN-BODY" not in (b or b"")
               and (b"<AccessControlPolicy" in (b or b"") or b"<Tagging" in (b or b"")),
               f"S3 GET ?{sr} on own object -> handled canned metadata, not the "
               f"object body (HTTP {st})")
        else:
            ok(st == 200 and b == b"SR-OWN-BODY\n",
               f"S3 GET ?{sr} on own object falls through to plain read as alice (HTTP {st})")

    # ============================================================== (B) ===
    # PUT ?<subres> with an XML body falls through to OBJECT PUT: the XML is
    # stored AS THE OBJECT.  THE KEY OWNERSHIP INVARIANT — any artifact created
    # this way is owned by the MAPPED user (alice=1001), NEVER svc(1500)/root(0),
    # and confined inside the export.  Four distinct param shapes prove the
    # parser-shape never changes the principal the write lands under.
    for sr in ["tagging", "object-lock", "publicAccessBlock", "acl"]:
        rel = f"alice/sr_put_{sr.replace('-', '_')}.txt"
        fp = absp(rel)
        try:
            if os.path.exists(fp):
                os.unlink(fp)
        except OSError:
            pass
        st, _ = s3("PUT", rel, s3port, params={sr: ""}, data=XML_BODY)
        # If the fall-through created the object it MUST be alice's, confined, and
        # contain exactly the XML body (stored-as-object proof).  If the server
        # instead refused the unknown sub-resource, no file is the safe outcome.
        if os.path.exists(fp):
            ok(owner_uid(fp) == UID_ALICE and confined(fp)
               and open(fp, "rb").read() == XML_BODY,
               f"S3 PUT ?{sr} fell through to object PUT: alice-owned, confined, byte-exact (HTTP {st})")
        else:
            ok(not_worker_root(fp),
               f"S3 PUT ?{sr} refused, no object created (HTTP {st})")
        # Regardless of branch: the artifact is NEVER svc/root-owned.
        ok(not_worker_root(fp),
           f"S3 PUT ?{sr} artifact never worker/root-owned")

    # ============================================================== (C) ===
    # CROSS-TENANT READ: alice GET ?<subres> on bob's 0600 private.txt must NOT
    # return bob's bytes.  The fall-through runs s3_handle_get as alice; bob's DAC
    # (0600 owner=1002) denies the open -> 403/404, no SECRET in the body.  This
    # is the leak-via-unhandled-sub-resource probe — the denial must survive the
    # *parser fall-through*, not a recognized verb (distinct from run_s3_deep).
    for sr in ["acl", "tagging", "policy", "versions", "torrent", "attributes"]:
        st, b = s3("GET", "bob/private.txt", s3port, params={sr: ""})
        leaked = SECRET in (b or b"")
        if sr == "acl":
            # GetObjectAcl returns a CANNED ACL templated on the REQUESTER's own
            # identity — it never opens bob's file, so a 200 here discloses NOTHING
            # about bob (no content, no metadata, not even existence).  The security
            # boundary (bob's secret bytes) holds; only the status is a benign 200.
            ok(st == 200 and not leaked,
               f"S3 alice GET ?acl on bob's 0600 -> canned requester-owned ACL, no "
               f"bob secret/data leaked (HTTP {st})")
        else:
            # ?tagging reads the object's tags (DAC-gated) and the rest fall through
            # to s3_handle_get -> bob's 0600 denies the impersonated open -> 403/404.
            ok(st in (403, 404) and not leaked,
               f"S3 alice GET ?{sr} on bob's 0600 DENIED, no secret bytes (HTTP {st})")

    # ============================================================== (D) ===
    # CROSS-TENANT MUTATION: alice PUT ?<subres> on bob's 0600 private.txt must
    # NOT mutate it — the fall-through object-PUT runs as alice and bob's file
    # DAC denies create/truncate.  Snapshot bytes+mode+owner BEFORE and AFTER and
    # assert byte-for-byte identity (a true no-mutation proof, not just a status).
    bpriv = absp("bob/private.txt")
    try:
        before_bytes = open(bpriv, "rb").read()
        before_mode = os.stat(bpriv).st_mode & 0o777
        before_uid = os.stat(bpriv).st_uid
    except OSError:
        before_bytes, before_mode, before_uid = None, -1, -1
    for sr in ["tagging", "acl", "object-lock", "retention", "legal-hold"]:
        st, _ = s3("PUT", "bob/private.txt", s3port, params={sr: ""}, data=XML_BODY)
        try:
            after_bytes = open(bpriv, "rb").read()
            after_mode = os.stat(bpriv).st_mode & 0o777
            after_uid = os.stat(bpriv).st_uid
        except OSError:
            after_bytes, after_mode, after_uid = None, -2, -2
        ok(st not in (200, 201, 204)
           and after_bytes == before_bytes and SECRET in (before_bytes or b"")
           and after_mode == before_mode and after_uid == before_uid == UID_BOB,
           f"S3 alice PUT ?{sr} on bob's 0600 DENIED: bytes+mode+owner unchanged (HTTP {st})")

    # ============================================================== (E) ===
    # CROSS-TENANT DELETE: alice DELETE ?<subres> on bob's world-readable 0644
    # readable.txt falls through to a plain object DELETE running as alice.  bob's
    # dir is 0755 (alice cannot unlink within it) so the file must SURVIVE.
    # Snapshot existence before/after.  Distinct from run_s3_deep's DeleteObjects
    # batch: this is the single-object DELETE verb reached via the sub-res parser.
    bread = absp("bob/readable.txt")
    bread_before = os.path.exists(bread)
    for sr in ["acl", "tagging"]:
        st, _ = s3("DELETE", "bob/readable.txt", s3port, params={sr: ""})
        ok(bread_before and os.path.exists(bread),
           f"S3 alice DELETE ?{sr} on bob's file DENIED: file survives (HTTP {st})")

    # Self-DELETE positive control: alice DELETE ?acl on her OWN object falls
    # through to a real delete and removes it (proves E's survival is per-file DAC,
    # not a blanket reject of sub-resourced DELETEs).
    s3("PUT", "alice/sr_del.txt", s3port, data=b"x\n")
    delp = absp("alice/sr_del.txt")
    st, _ = s3("DELETE", "alice/sr_del.txt", s3port, params={"acl": ""})
    ok(not os.path.exists(delp),
       f"control: S3 alice DELETE ?acl on own object falls through + deletes (HTTP {st})")

    # ============================================================== (F) ===
    # POST ?<subres> on an object key: POST does NOT fall through to object PUT
    # (the dispatcher handles POST only for ?uploads / ?delete / uploadId), so an
    # unhandled POST sub-resource ends at 405 and creates NOTHING — never an
    # object write, never a worker/root artifact.
    for sr in ["acl", "notification", "requestPayment"]:
        rel = f"alice/sr_post_{sr}.txt"
        fp = absp(rel)
        try:
            if os.path.exists(fp):
                os.unlink(fp)
        except OSError:
            pass
        st, _ = s3("POST", rel, s3port, params={sr: ""}, data=XML_BODY)
        ok(st in (405, 400, 403, 501) and not os.path.exists(fp),
           f"S3 POST ?{sr} on object key NOT a write fall-through -> rejected, no artifact (HTTP {st})")

    # ============================================================== (G) ===
    # BUCKET-LEVEL (empty key) unhandled sub-resource: GET/PUT/DELETE /bucket/?acl.
    # The unknown ?acl param is ignored: GET falls through to the broker-confined
    # bucket list (200, no cross-tenant bytes), while PUT/DELETE on an empty key hit
    # the empty-key guard -> 400 InvalidURI.  Either way there is NO object-write
    # fall-through and NO escape/secret leak in the reply.
    for method in ["GET", "PUT", "DELETE"]:
        body = XML_BODY if method == "PUT" else None
        st, b = s3(method, "", s3port, params={"acl": ""}, data=body)
        ok(st in (200, 400, 403, 404, 405, 501)
           and b"escape/" not in (b or b"") and SECRET not in (b or b""),
           f"S3 {method} /bucket/?acl (bucket-level) no object/leak (HTTP {st})")

    # ============================================================== (H) ===
    # WORKER LIVENESS: after the whole adversarial sub-resource sweep the worker is
    # still up — a clean GET of alice's seeded object returns its body (proves no
    # sub-resource path crashed the worker / wedged the connection).
    st, b = s3("GET", "alice/sr_own.txt", s3port)
    ok(st == 200 and b == b"SR-OWN-BODY\n",
       f"S3 worker survived unhandled-sub-resource sweep (follow-up GET OK, HTTP {st})")


def run_s3_post_form_and_bucketops(key, data, port, s3port):
    """S3 browser POST-form upload + bucket-level ops under impersonation.

    The browser POST Object path (src/s3/post_object.c) is EXEMPT from the
    dispatch-time header SigV4 (handler.c: `if (!is_post_object_form)`), so the
    impersonation identity for a form upload is whatever auth populated — never a
    privileged fallback.  This batch proves the load-bearing invariant: any object
    a POST form creates is owned by the MAPPED user (alice 1001), NEVER the worker
    (svc 1500) or root (0); a cross-tenant/escape form key is confined+DAC-denied;
    the signed-policy auth gate rejects tampered/forged/expired/missing material;
    and the bucket-level verbs (?location, v1 ListObjects, HEAD/DELETE/PUT bucket,
    ?uploads) neither escalate, destroy the export, nor leak another tenant's
    names.  Distinct from run_s3 / run_s3_extended / run_create_ownership, which
    only cover header-auth PUT/multipart/copy and the v2-list symlink leak.
    """
    if not s3port:
        ok(True, "S3 post-form/bucket-ops skipped (no S3 port)")
        return

    BOB = b"BOB-PRIVATE-SECRET"
    bobread = os.path.join(data, "bob", "readable.txt")

    def uid_of(rel):
        fp = os.path.join(data, rel.lstrip("/"))
        try:
            return os.stat(fp).st_uid if os.path.exists(fp) else -1
        except OSError:
            return -2

    def exists(rel):
        try:
            return os.path.exists(os.path.join(data, rel.lstrip("/")))
        except OSError:
            return False

    def post_form(s3path, ct, body):
        # POST Object carries auth in the form, not the Authorization header.
        return http("POST", f"/{S3_BUCKET}/{s3path}", s3port, data=body,
                    hdrs={"Content-Type": ct})

    # =====================================================================
    # A. POST-FORM OWNERSHIP / ESCALATION  (the central invariant)
    # =====================================================================
    # A1. CONTROL: a correctly-signed POST form (alice cred) targeting alice's own
    #     subtree.  Whether the server honours the form (2xx/303) or refuses it
    #     (the POST path is header-SigV4-exempt, so the broker may see an empty
    #     principal and DENY), the load-bearing rule is the SAME: if a file lands,
    #     it is owned by alice — never svc(1500)/root(0).
    rel1 = "alice/pf_ok.txt"
    if exists(rel1):
        try:
            os.unlink(os.path.join(data, rel1))
        except OSError:
            pass
    ct, body = _s3_post_form("alice", rel1, b"PF-OK-BODY\n")
    st, _ = post_form("", ct, body)
    u1 = uid_of(rel1)
    ok(u1 in (UID_ALICE, -1) and u1 != UID_SVC and u1 != 0,
       f"POST-form upload: created file owned by alice, never worker/root "
       f"(HTTP {st}, uid={u1})")

    # A2. If the form WAS honoured, the object must be confined under alice/ (the
    #     form `key` resolved through the bucket root, not anywhere else) and the
    #     body must round-trip when alice reads it back via header-auth GET.
    if u1 == UID_ALICE:
        stg, gb = s3("GET", rel1, s3port)
        ok(stg == 200 and gb == b"PF-OK-BODY\n",
           f"POST-form object confined to alice/ + body byte-exact (HTTP {stg})")
    else:
        ok(st in (400, 401, 403, 404) and not exists(rel1),
           f"POST-form upload refused fail-closed, no orphan object (HTTP {st})")

    # A3. CROSS-TENANT form key: alice-credentialled form whose key targets BOB's
    #     0755 dir.  The write runs as alice (or an empty principal) -> DAC/broker
    #     denies it; crucially NO file owned by svc/root/bob may appear there.
    relx = "bob/pf_xtenant.txt"
    if exists(relx):
        try:
            os.unlink(os.path.join(data, relx))
        except OSError:
            pass
    ct, body = _s3_post_form("alice", relx, b"PF-XTENANT\n")
    st, _ = post_form("", ct, body)
    ux = uid_of(relx)
    ok(not exists(relx) or ux == UID_ALICE,
       f"POST-form into bob's dir: no bob/svc/root-owned file created "
       f"(HTTP {st}, uid={ux})")

    # A4. TAMPERED policy signature -> the signed-policy gate rejects it (403),
    #     and no object is committed.  Proves form auth is actually verified.
    relt = "alice/pf_tampered.txt"
    if exists(relt):
        try:
            os.unlink(os.path.join(data, relt))
        except OSError:
            pass
    ct, body = _s3_post_form("alice", relt, b"PF-TAMPER\n", tamper_sig=True)
    st, _ = post_form("", ct, body)
    ok(st in (400, 401, 403) and not exists(relt),
       f"POST-form tampered policy signature REJECTED, no object (HTTP {st})")

    # A5. FORGED credential access key: form claims x-amz-credential=root/...  The
    #     access key must match the configured 'alice' exactly -> InvalidAccessKeyId
    #     (403); no object, and absolutely no root(0)-owned file anywhere it points.
    relr = "alice/pf_rootcred.txt"
    if exists(relr):
        try:
            os.unlink(os.path.join(data, relr))
        except OSError:
            pass
    now = dt.datetime.now(dt.timezone.utc).strftime("%Y%m%d")
    ct, body = _s3_post_form(
        "alice", relr, b"PF-ROOTCRED\n",
        cred_override=f"root/{now}/{S3_REGION}/s3/aws4_request")
    st, _ = post_form("", ct, body)
    rr = uid_of(relr)
    ok(st in (400, 401, 403) and (not exists(relr) or rr == UID_ALICE) and rr != 0,
       f"POST-form forged 'root' credential REJECTED, no root-owned object "
       f"(HTTP {st}, uid={rr})")

    # A6. EXPIRED policy: signature is valid but the policy expiration is in the
    #     past -> AccessDenied (403), no object.
    rele = "alice/pf_expired.txt"
    if exists(rele):
        try:
            os.unlink(os.path.join(data, rele))
        except OSError:
            pass
    old = dt.datetime.now(dt.timezone.utc) - dt.timedelta(hours=1)
    ct, body = _s3_post_form("alice", rele, b"PF-EXPIRED\n", when=old,
                             expires_min=1)
    st, _ = post_form("", ct, body)
    ok(st in (400, 401, 403) and not exists(rele),
       f"POST-form expired policy REJECTED, no object (HTTP {st})")

    # A7. ${filename} template + a path-traversal filename.  The server reduces the
    #     filename to its basename before expansion, so the key cannot climb out;
    #     nothing may be written outside the export root.
    outside = os.path.join(os.path.dirname(data), "PF_FN_ESCAPE")
    ct, body = _s3_post_form("alice", "alice/${filename}", b"PF-FN\n",
                             filename="../../../PF_FN_ESCAPE")
    st, _ = post_form("", ct, body)
    ok(not os.path.exists(outside),
       f"POST-form ${{filename}} traversal basename-confined, no escape (HTTP {st})")

    # A8. Explicit traversal in the form `key` itself -> confined, nothing escapes.
    out2 = "/tmp/PF_KEY_ESCAPE"
    try:
        if os.path.exists(out2):
            os.unlink(out2)
    except OSError:
        pass
    ct, body = _s3_post_form("alice", "../../../../tmp/PF_KEY_ESCAPE", b"PF-K\n")
    st, _ = post_form("", ct, body)
    ok(not os.path.exists(out2),
       f"POST-form traversal key created nothing outside the export (HTTP {st})")

    # A9. Missing file part -> 400 (key+file are both required), no object.
    relnf = "alice/pf_nofile.txt"
    if exists(relnf):
        try:
            os.unlink(os.path.join(data, relnf))
        except OSError:
            pass
    ct, body = _s3_post_form("alice", relnf, b"", omit_file=True)
    st, _ = post_form("", ct, body)
    ok(st in (400, 403) and not exists(relnf),
       f"POST-form with no file part rejected, no object (HTTP {st})")

    # A10. No policy/signature fields at all (access key IS configured) -> the
    #      missing-fields gate denies it (403); no object.
    relnp = "alice/pf_nopolicy.txt"
    if exists(relnp):
        try:
            os.unlink(os.path.join(data, relnp))
        except OSError:
            pass
    ct, body = _s3_post_form("alice", relnp, b"PF-NP\n", omit_policy=True)
    st, _ = post_form("", ct, body)
    ok(st in (400, 401, 403) and not exists(relnp),
       f"POST-form with no signed policy REJECTED, no object (HTTP {st})")

    # A11. A non-multipart POST to the bucket (wrong Content-Type) must not be
    #      mistaken for a form upload and must not create anything outside its key.
    st, _ = http("POST", f"/{S3_BUCKET}/", s3port, data=b"key=alice/x&file=y",
                 hdrs={"Content-Type": "application/x-www-form-urlencoded"})
    ok(st in (400, 401, 403, 405) and not exists("alice/x"),
       f"non-multipart POST to bucket rejected, no object (HTTP {st})")

    # =====================================================================
    # B. BUCKET-LEVEL VERBS  (escalation / destruction / leak surface)
    # =====================================================================
    # B1. GET /bucket?location (region locator) -> GetBucketLocation: a valid S3
    #     probe answered with the config-supplied region only (LocationConstraint).
    #     It carries NO tenant data — assert it leaks no body content / svc names.
    st, b = s3("GET", "", s3port, params={"location": ""})
    ok(st in (200, 400, 403, 404) and BOB not in (b or b"")
       and b"secret-name.txt" not in (b or b""),
       f"GET /bucket?location no tenant leak (HTTP {st})")

    # B2. GET /bucket with NO list-type (S3 ListObjects v1) -> valid op: the walk is
    #     broker-confined to the mapped user (alice), so it enumerates only entries
    #     alice may traverse and emits keys/size/mtime/synthetic-etag (no file bytes,
    #     no content digest).  bobsecret/ (0700) is fail-closed skipped, so the
    #     listing must contain neither bob's secret BODY nor the cross-tenant
    #     bobsecret name.
    st, b = s3("GET", "", s3port)
    ok(st in (200, 400, 403, 404) and BOB not in (b or b"")
       and b"bobsecret/s.txt" not in (b or b"") and b"bob-only" not in (b or b""),
       f"GET /bucket (ListObjects v1): no cross-tenant CONTENTS leaked — bob's 0700 "
       f"bobsecret/ contents (key 'bobsecret/s.txt' + its 'bob-only' body) are NOT "
       f"enumerated (s3_walk returns 0 on an access-denied dir); a bare prefix name "
       f"is POSIX-visible via readdir of the 0755 export root, like ls (HTTP {st})")

    # B3. HEAD /bucket (empty key) -> HeadBucket: header-only probe (200 + region or
    #     404); either way the response has NO body.
    st, b = s3("HEAD", "", s3port)
    ok(st in (200, 400, 403, 404) and not (b or b""),
       f"HEAD /bucket (HeadBucket) no body (HTTP {st})")

    # B4. DELETE /bucket (empty key) -> rejected, and the export root + alice/ must
    #     SURVIVE (a bucket delete must never rmtree the storage).
    st, _ = s3("DELETE", "", s3port)
    ok(st in (400, 403, 404) and os.path.isdir(os.path.join(data, "alice"))
       and os.path.exists(bobread),
       f"DELETE /bucket rejected, export tree intact (HTTP {st})")

    # B5. PUT /bucket (CreateBucket) -> rejected (empty key); no side effect.
    st, _ = s3("PUT", "", s3port, data=b"")
    ok(st in (400, 403, 404, 411),
       f"PUT /bucket (CreateBucket) rejected (HTTP {st})")

    # B6. GET /bucket?uploads (ListMultipartUploads): initiate an alice MPU first so
    #     there is an in-flight upload, then list.  It must be handled (200/404),
    #     list alice's OWN upload (when 200), and never leak another tenant's
    #     private key names or the svc-only secret.
    st_i, ib = s3("POST", "alice/pf_mpu_list.bin", s3port, params={"uploads": ""})
    upid = None
    m = re.search(rb"<UploadId>([^<]+)</UploadId>", ib or b"")
    if m:
        upid = m.group(1).decode()
    st, b = s3("GET", "", s3port, params={"uploads": ""})
    leaked = (b"secret-name.txt" in (b or b"") or b"bobsecret" in (b or b"")
              or BOB in (b or b"") or b"escape/" in (b or b""))
    ok(st in (200, 404) and not leaked,
       f"GET /bucket?uploads handled, no cross-tenant/secret leak (HTTP {st})")
    if upid:
        # positive control: alice's own in-flight upload key is listable to alice.
        listed = b"pf_mpu_list.bin" in (b or b"")
        ok(st == 404 or listed,
           f"ListMultipartUploads shows alice's own in-flight upload (HTTP {st})")
        s3("DELETE", "alice/pf_mpu_list.bin", s3port, params={"uploadId": upid})
    else:
        ok(True, "ListMultipartUploads control skipped (initiate unsupported)")

    # =====================================================================
    # C. OBJECT-METADATA EDGE BEHAVIOURS  (ownership invariant under odd headers)
    # =====================================================================
    # C1. Content-MD5 that does NOT match the body.  This server verifies only
    #     x-amz-checksum-crc64nvme (not Content-MD5), so the PUT is accepted; the
    #     load-bearing assertion is that the stored object is STILL alice-owned and
    #     never worker/root — a wrong digest must not flip the identity.
    relm = "alice/pf_md5.txt"
    if exists(relm):
        try:
            os.unlink(os.path.join(data, relm))
        except OSError:
            pass
    bad_md5 = base64.b64encode(hashlib.md5(b"DIFFERENT").digest()).decode()
    st, _ = s3("PUT", relm, s3port, data=b"PF-MD5-BODY\n",
               extra_hdrs={"Content-MD5": bad_md5})
    um = uid_of(relm)
    ok((not exists(relm)) or (um == UID_ALICE and um != UID_SVC and um != 0),
       f"PUT with mismatched Content-MD5: object (if stored) owned by alice, "
       f"never worker/root (HTTP {st}, uid={um})")

    # C2. x-amz-storage-class on PUT must not alter ownership or confinement: the
    #     object lands alice-owned under alice/, the requested class is advisory.
    rels = "alice/pf_sc.txt"
    if exists(rels):
        try:
            os.unlink(os.path.join(data, rels))
        except OSError:
            pass
    st, _ = s3("PUT", rels, s3port, data=b"PF-SC-BODY\n",
               extra_hdrs={"x-amz-storage-class": "GLACIER"})
    us = uid_of(rels)
    ok(st in (200, 201) and us == UID_ALICE and us != UID_SVC and us != 0,
       f"PUT x-amz-storage-class=GLACIER: object owned by alice, confined "
       f"(HTTP {st}, uid={us})")

    # =====================================================================
    # D. WORKER SURVIVAL
    # =====================================================================
    # A normal header-auth GET after the whole barrage proves no POST-form /
    # bucket-op sequence wedged or desynced the S3 worker.
    s3("PUT", "alice/pf_alive.txt", s3port, data=b"PF-ALIVE\n")
    st, b = s3("GET", "alice/pf_alive.txt", s3port)
    ok(st == 200 and b == b"PF-ALIVE\n",
       f"S3 worker survived POST-form + bucket-op barrage (HTTP {st})")


def run_webdav_undispatched_methods(key, data, port, s3port):
    """Undispatched/exotic HTTP+WebDAV methods and HTTP-method-override smuggling
    under impersonation: every method nginx-xrootd does NOT route (REPORT, SEARCH,
    PATCH, the DeltaV/CalDAV/RFC-5842 verbs, TRACE, CONNECT, a bogus verb, and
    lowercase get/put) must either be cleanly REJECTED or, if dispatched, enforce
    the broker DAC -- and NO override header (X-HTTP-Method-Override / X-Method-
    Override / X-HTTP-Method) may smuggle a DELETE/MOVE/PUT past the visible verb to
    mutate, delete, escalate, escape, or create an svc/root-owned artifact.  WHY:
    the verb is the first dispatch key; a method the router silently treats as a
    mutating op, or an override header the router honours, bypasses the entire
    auth->impersonation->DAC chain.  Distinct from run_webdav_methods (HEAD/OPTIONS/
    UNLOCK/COPY/Overwrite/Depth -- all ROUTED verbs) and run_webdav_method_state
    (LOCK-state x conditional x PUT/MKCOL/MOVE edge matrix on ROUTED verbs): this
    batch attacks the UN-routed verb space + override smuggling, a surface neither
    touches.  All fixtures prefixed `und_`."""
    ta, tb = mint(key, "alice"), mint(key, "bob")
    base = f"http://127.0.0.1:{port}"
    bpriv = os.path.join(data, "bob", "private.txt")
    adir = os.path.join(data, "alice")

    def snap(p):
        """(exists, content_or_None, uid_or_-1, mode_or_-1) for a path."""
        try:
            stt = os.stat(p)
        except OSError:
            return (False, None, -1, -1)
        try:
            c = open(p, "rb").read()
        except OSError:
            c = None
        return (True, c, stt.st_uid, stt.st_mode & 0o7777)

    def not_svc_root(p):
        """True iff p is absent or owned by neither svc(1500) nor root(0)."""
        try:
            if not os.path.lexists(p):
                return True
            return os.lstat(p).st_uid not in (UID_SVC, 0)
        except OSError:
            return True

    # Clean-rejection status family: nginx core 400 for unknown method tokens,
    # 405 for TRACE/CONNECT, plus the other honest refusals a router might emit.
    REJECT = (400, 401, 403, 404, 405, 411, 415, 501, 505)

    SECRET = b"BOB-PRIVATE-SECRET"

    # Canonical snapshot of bob's 0600 secret (reset_fixtures ran first), used to
    # prove NO undispatched method / override smuggling mutated or deleted it.
    b0 = snap(bpriv)
    ok(b0[0] and b0[1] == b"BOB-PRIVATE-SECRET\n" and b0[2] == UID_BOB
       and b0[3] == 0o600,
       "control: bob/private.txt canonical 0600 bob-owned secret before attack")

    # ============================================================ READ-CLASS VERBS
    # Methods that, IF the router mistook them for a read, would expose bytes.
    # Each must NOT return bob's secret body (the read would run as alice=other).
    for m in ("REPORT", "SEARCH", "ACL", "LABEL", "PROPPATCH-NOPE"):
        st, b = http(m, "/bob/private.txt", port, ta)
        ok(st in REJECT + (207, 200, 422) and SECRET not in (b or b""),
           f"undispatched {m} on bob's 0600 leaks no secret body (HTTP {st})")
    # The same read-class probe must also not leak via the world-readable name in
    # bob's 0700 secret DIR (directory-listing confusion): bobsecret/s.txt body.
    st, b = http("SEARCH", "/bobsecret/", port, ta,
                 data=b"<?xml version='1.0'?><searchrequest/>",
                 hdrs={"Content-Type": "application/xml"})
    ok(SECRET not in (b or b"") and b"bob-only" not in (b or b""),
       f"undispatched SEARCH of bob's 0700 dir enumerates/leaks nothing (HTTP {st})")

    # ============================================================ MUTATE-CLASS VERBS
    # Methods that, IF routed as a write/patch, would alter or destroy bob's file.
    # After each, bob's secret must be byte-identical, mode 0600, still bob-owned.
    for m, body in (("PATCH", b"PATCHED-BY-ATTACKER\n"),
                    ("ORDERPATCH", b"REORDERED\n"),
                    ("MERGE", b"MERGED\n"),
                    ("UPDATEREDIRECTREF", b"REDIR\n")):
        st, _ = http(m, "/bob/private.txt", port, ta, body,
                     hdrs={"Content-Type": "application/xml"})
        now = snap(bpriv)
        ok(st in REJECT + (422,) and now[1] == b"BOB-PRIVATE-SECRET\n"
           and now[2] == UID_BOB and now[3] == 0o600,
           f"undispatched {m} did NOT mutate bob's 0600 secret (HTTP {st})")

    # A mutate-class verb aimed at DELETING bob's readable.txt must not unlink it.
    bread = os.path.join(data, "bob", "readable.txt")
    r0 = snap(bread)
    st, _ = http("UNBIND", "/bob/readable.txt", port, ta,
                 data=(b'<?xml version="1.0"?><D:unbind xmlns:D="DAV:">'
                       b"<D:segment>readable.txt</D:segment></D:unbind>"),
                 hdrs={"Content-Type": "application/xml"})
    ok(st in REJECT + (422,) and snap(bread) == r0 and os.path.exists(bread),
       f"undispatched UNBIND did NOT delete bob's readable.txt (HTTP {st})")

    # ============================================================ ARTIFACT-CREATE VERBS
    # DeltaV/CalDAV "make-something" verbs: if the router runs them they must (a) be
    # confined to the export and (b) never leave an svc(1500)/root(0)-owned object.
    create_verbs = ("MKCALENDAR", "MKWORKSPACE", "MKACTIVITY", "VERSION-CONTROL",
                    "CHECKOUT", "CHECKIN", "UNCHECKOUT", "MKREDIRECTREF",
                    "BIND", "REBIND")
    for m in create_verbs:
        tgt = f"und_{m.lower().replace('-', '_')}"
        st, _ = http(m, f"/alice/{tgt}", port, ta)
        fp = os.path.join(adir, tgt)
        # Either cleanly refused (nothing created) OR, if created, owned by the
        # MAPPED user alice -- never the worker/root, and never escaping the dir.
        created_ok = (not os.path.lexists(fp)) or (
            os.lstat(fp).st_uid == UID_ALICE and os.lstat(fp).st_uid not in (UID_SVC, 0))
        ok(st in REJECT + (200, 201, 204) and created_ok and not_svc_root(fp),
           f"undispatched {m} in alice's dir: no worker/root artifact (HTTP {st})")
    # An artifact verb pointed at the world-writable pub dir must NOT yield a file
    # owned by the worker uid masquerading as a tenant write.
    st, _ = http("MKACTIVITY", "/pub/und_act", port, ta)
    pubp = os.path.join(data, "pub", "und_act")
    ok(st in REJECT + (200, 201, 204) and not_svc_root(pubp),
       f"undispatched MKACTIVITY in world-writable pub creates no svc/root file (HTTP {st})")

    # ============================================================ METHOD-OVERRIDE SMUGGLING
    # POST/PUT carrying X-HTTP-Method-Override: DELETE on bob/private.txt -- the
    # server must NOT honour the header to delete/mutate bob's file.  Snapshot the
    # file around EACH override-header variant (each is a distinct parse path).
    override_hdrs = ("X-HTTP-Method-Override", "X-Method-Override", "X-HTTP-Method")
    for oh in override_hdrs:
        pre = snap(bpriv)
        st, _ = http("POST", "/bob/private.txt", port, ta, b"",
                     hdrs={oh: "DELETE"})
        post = snap(bpriv)
        ok(post == pre and post[0] and post[1] == b"BOB-PRIVATE-SECRET\n",
           f"POST + {oh}: DELETE did NOT delete/alter bob's 0600 (HTTP {st})")
    # PUT body carrying an override to MOVE bob's file into alice's space (theft):
    # the override must be ignored -> no copy/move lands in alice's dir.
    stolen = os.path.join(adir, "und_stolen_via_override.txt")
    st, _ = http("PUT", "/bob/private.txt", port, ta, b"x\n",
                 hdrs={"X-HTTP-Method-Override": "MOVE",
                       "Destination": f"{base}/alice/und_stolen_via_override.txt"})
    ok(not os.path.exists(stolen) and snap(bpriv)[1] == b"BOB-PRIVATE-SECRET\n",
       f"PUT + override MOVE did NOT steal bob's file into alice's dir (HTTP {st})")
    # Override pointed at alice's OWN file: even if a server honoured override, the
    # result must stay alice-owned and the privilege must not change (no escalation).
    http("PUT", "/alice/und_ov_self.txt", port, ta, b"self\n")
    selfp = os.path.join(adir, "und_ov_self.txt")
    st, _ = http("POST", "/alice/und_ov_self.txt", port, ta, b"",
                 hdrs={"X-HTTP-Method-Override": "DELETE"})
    # If the override were honoured as a real DELETE-by-alice it would be legal, so
    # we don't forbid removal; we forbid the file becoming worker/root-owned and we
    # forbid a smuggled override from creating a DIFFERENT-owner artifact.
    ok(not_svc_root(selfp),
       f"override on alice's OWN file never yields a worker/root artifact (HTTP {st})")
    # Override DELETE on bob via the keep-alive-free path must also not work when
    # the visible verb is itself a write the server DOES route (PUT) -- targeting a
    # path alice cannot write: bob's 0700 secret dir child.
    sx = os.path.join(data, "bobsecret", "s.txt")
    sx0 = snap(sx)
    st, _ = http("PUT", "/bobsecret/s.txt", port, ta, b"OVERRIDE-PWN\n",
                 hdrs={"X-HTTP-Method": "PUT"})
    ok(snap(sx) == sx0 and sx0[0],
       f"override-tagged PUT into bob's 0700 dir DENIED, child unchanged (HTTP {st})")

    # ============================================================ CASE-FOLDING VERBS
    # Lowercase get/put must NOT be silently upcased into a routed GET/PUT.  Even if
    # the server case-folds, the DAC still applies: lowercase get on bob's 0600 must
    # not leak; lowercase put into alice's dir must (if honoured) stay alice-owned.
    st, b = http("get", "/bob/private.txt", port, ta)
    ok(st in REJECT + (200,) and SECRET not in (b or b""),
       f"lowercase 'get' on bob's 0600 leaks no secret (HTTP {st})")
    st, _ = http("put", "/alice/und_lower.txt", port, ta, b"lower\n")
    lp = os.path.join(adir, "und_lower.txt")
    ok((not os.path.lexists(lp)) or (os.lstat(lp).st_uid == UID_ALICE),
       f"lowercase 'put' into alice's dir is rejected or stays alice-owned (HTTP {st})")
    # lowercase 'put' into BOB's dir must never write a file there.
    lbob = os.path.join(data, "bob", "und_lower_bob.txt")
    http("put", "/bob/und_lower_bob.txt", port, ta, b"x\n")
    ok(not os.path.exists(lbob),
       "lowercase 'put' into bob's dir created no file (case-fold cannot bypass DAC)")

    # ============================================================ BOGUS VERB
    # A wholly-unknown verb must be cleanly rejected and mutate nothing.
    st, b = http("FOOBAR", "/alice/und_foobar.txt", port, ta, b"x\n")
    ok(st in REJECT and not os.path.exists(os.path.join(adir, "und_foobar.txt")),
       f"bogus FOOBAR verb cleanly rejected, nothing created (HTTP {st})")
    # Bogus verb against the /etc-symlink escape must not read /etc/passwd.
    st, b = http("FOOBAR", "/escape/passwd", port, ta)
    ok(b"root:x:0:0" not in (b or b""),
       f"bogus verb on /escape symlink does not read /etc/passwd (HTTP {st})")

    # ============================================================ TRACE / CONNECT (raw)
    # TRACE must NOT reflect the request (Cross-Site-Tracing): the bearer token and
    # a marker header must be absent from the response body.  Use raw_http so we can
    # plant the Authorization header verbatim and inspect the raw bytes.
    trace_raw = (
        "TRACE /alice/und_trace HTTP/1.1\r\n"
        "Host: 127.0.0.1\r\n"
        f"Authorization: Bearer {ta}\r\n"
        "X-Reflect-Marker: UND-XST-REFLECT-7Q\r\n"
        "Connection: close\r\n\r\n"
    )
    resp = raw_http(trace_raw, port)
    ok(b"UND-XST-REFLECT-7Q" not in resp and ta.encode() not in resp,
       "TRACE does not reflect the bearer token / marker header (no XST leak)")
    ok(b"200" not in resp.split(b"\r\n", 1)[0],
       f"TRACE is not answered 200 (refused: {resp.split(chr(13).encode(),1)[0][:40]!r})")
    # CONNECT (authority-form) must not open a tunnel / be answered 2xx -- the
    # worker must refuse to become a forward proxy.
    connect_raw = (
        "CONNECT 169.254.169.254:80 HTTP/1.1\r\n"
        "Host: 169.254.169.254:80\r\n"
        "Connection: close\r\n\r\n"
    )
    cresp = raw_http(connect_raw, port)
    first = cresp.split(b"\r\n", 1)[0] if cresp else b""
    ok(b"200" not in first and b"Connection established" not in cresp,
       f"CONNECT tunnel refused (no SSRF forward-proxy): {first[:40]!r}")

    # ============================================================ WORKER SURVIVAL
    # After the whole undispatched/override barrage a legit op must still work and
    # land owned by the mapped user -> no verb wedged or crashed the worker/broker.
    st, _ = http("PUT", "/alice/und_survivor.txt", port, ta, b"alive\n")
    sp = os.path.join(adir, "und_survivor.txt")
    ok(st in (200, 201, 204) and os.path.exists(sp)
       and os.stat(sp).st_uid == UID_ALICE,
       f"worker SURVIVED undispatched/override barrage; legit PUT owned alice (HTTP {st})")
    st, b = http("GET", "/alice/und_survivor.txt", port, ta)
    ok(st == 200 and b == b"alive\n",
       f"post-barrage GET returns the survivor body (worker healthy) (HTTP {st})")
    # Final sweep: nothing und_* in alice's dir may be owned by svc(1500)/root(0).
    bad = []
    try:
        for f in os.listdir(adir):
            if not f.startswith("und_"):
                continue
            fp = os.path.join(adir, f)
            try:
                if os.lstat(fp).st_uid in (UID_SVC, 0):
                    bad.append(f)
            except OSError:
                pass
    except OSError:
        pass
    ok(not bad,
       f"no und_ artifact in alice's tree is worker(1500)/root(0)-owned: {bad[:4]}")
    # And bob's secret is STILL canonical after everything (end-to-end invariant).
    bend = snap(bpriv)
    ok(bend[1] == b"BOB-PRIVATE-SECRET\n" and bend[2] == UID_BOB and bend[3] == 0o600,
       "bob's 0600 secret unchanged end-to-end after the full undispatched barrage")


def run_webdav_property_exotic(key, data, port, s3port):
    """EXOTIC PROPPATCH/PROPFIND bodies under impersonation, verified at the KERNEL
    (on-disk `user.nginx_xrootd.webdav.*` xattr) layer rather than by PROPFIND echo
    alone.  Probes: (1) set-then-remove a dead-prop in ONE request leaves NO xattr;
    (2) PROPFIND allprop/propname/named-LIVE-props are well-formed and leak no
    internal path; (3) a SET of a protected/live DAV: prop (getetag/getcontentlength)
    is refused (403 propstat) and is NOT stored, the file uncorrupted; (4) many
    bounded dead props are stored without unbounded xattr growth; (5) mixed/foreign
    namespaces + empty + over-cap values are bounded (16 KiB value cap enforced on
    disk); (6) CROSS-TENANT: alice PROPFIND on bob's 0600 file leaks no size/etag and
    alice PROPPATCH on bob's file persists no xattr + leaves bob's mode/xattrs intact.
    Distinct from run_lock_proppatch (no set-then-remove, no on-disk xattr count/value
    assertion), run_webdav_method_state (no named-live-prop enumeration, no protected-
    prop SET, no kernel xattr verification) and run_group_xattr_lock (group-write-bit
    discrimination, not exotic bodies / value caps / protected props)."""
    ta, tb = mint(key, "alice"), mint(key, "bob")
    XML = {"Content-Type": "application/xml"}
    D0 = {"Depth": "0", "Content-Type": "application/xml"}

    def adir(rel):
        return os.path.join(data, "alice", rel)

    def pp_xml(actions):
        """actions = list of ('set'|'remove', inner_xml_bytes)."""
        body = (b'<?xml version="1.0"?><D:propertyupdate xmlns:D="DAV:" '
                + b'xmlns:Z="urn:exotic">')
        for verb, inner in actions:
            body += (b'<D:' + verb.encode() + b'><D:prop>' + inner
                     + b'</D:prop></D:' + verb.encode() + b'>')
        return body + b'</D:propertyupdate>'

    # ====================================================== (0) fixture control
    http("PUT", "/alice/xp_base.txt", port, ta, b"exotic-prop-base\n")
    bp = adir("xp_base.txt")
    ok(os.path.exists(bp) and os.stat(bp).st_uid == UID_ALICE,
       f"exotic-prop fixture xp_base.txt owned by alice "
       f"(uid={os.stat(bp).st_uid if os.path.exists(bp) else -1})")
    base0 = _dead_xattr_count(bp)
    ok(base0 == 0, f"fresh fixture carries no dead-property xattrs (count={base0})")

    # ========================================== (1) SET then REMOVE in ONE request
    # A single propertyupdate that sets a dead-prop then removes it must leave the
    # resource with NO such xattr on disk (kernel ground truth, not PROPFIND echo).
    st_sr, _ = http("PROPPATCH", "/alice/xp_base.txt", port, ta,
                    data=pp_xml([("set", b'<Z:ephemeral>VANISH</Z:ephemeral>'),
                                 ("remove", b'<Z:ephemeral/>')]), hdrs=XML)
    ok(st_sr in (200, 207) and _dead_xattr_count(bp) == 0
       and not _dead_xattr_has_value(bp, b"VANISH"),
       f"SET-then-REMOVE in one PROPPATCH leaves no dead-prop xattr on disk "
       f"(HTTP {st_sr}, count={_dead_xattr_count(bp)})")

    # control: a plain SET of a distinct dead-prop DOES persist on disk as exactly
    # one xattr carrying the value (proves the removal above was real, not a no-op).
    st_set, _ = http("PROPPATCH", "/alice/xp_base.txt", port, ta,
                     data=pp_xml([("set", b'<Z:keep>PERSIST</Z:keep>')]), hdrs=XML)
    ok(st_set in (200, 207) and _dead_xattr_count(bp) == 1
       and _dead_xattr_has_value(bp, b"PERSIST"),
       f"control: a plain dead-prop SET persists as one on-disk xattr "
       f"(HTTP {st_set}, count={_dead_xattr_count(bp)})")
    # the persisting prop must keep the resource alice-owned (broker setxattr as alice).
    ok(os.stat(bp).st_uid == UID_ALICE,
       "resource carrying a persisted dead-prop stays alice-owned (broker xattr)")

    # ============================== (2) PROPFIND allprop / propname / named-live
    st_a, ba = http("PROPFIND", "/alice/xp_base.txt", port, ta,
                    data=b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
                         b'<D:allprop/></D:propfind>', hdrs=D0)
    ok(st_a == 207 and ba.count(b"<D:response>") == 1
       and b"PERSIST" in ba,
       f"PROPFIND allprop is one well-formed response carrying the dead-prop "
       f"(HTTP {st_a})")
    # allprop must not leak the absolute on-disk export path (confinement / info).
    ok(data.encode() not in ba and b"/etc/" not in ba,
       "PROPFIND allprop response leaks no internal export/host path")

    st_pn, bpn = http("PROPFIND", "/alice/xp_base.txt", port, ta,
                      data=b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
                           b'<D:propname/></D:propfind>', hdrs=D0)
    # propname lists NAMES only — no live values (size/etag) must appear as text.
    ok(st_pn == 207 and b"<D:getcontentlength/>" in bpn
       and b"<D:getcontentlength>" not in bpn,
       f"PROPFIND propname lists property NAMES without values (HTTP {st_pn})")

    # explicitly-named LIVE props: each requested live prop is emitted with a value.
    named = (b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:"><D:prop>'
             b'<D:getcontentlength/><D:getlastmodified/><D:resourcetype/>'
             b'<D:getetag/><D:creationdate/><D:displayname/>'
             b'<D:lockdiscovery/><D:supportedlock/>'
             b'<D:quota-available-bytes/><D:quota-used-bytes/>'
             b'</D:prop></D:propfind>')
    st_n, bn = http("PROPFIND", "/alice/xp_base.txt", port, ta, data=named, hdrs=D0)
    live_ok = all(tag in bn for tag in (
        b"<D:getcontentlength>", b"<D:getlastmodified>", b"<D:getetag>",
        b"<D:creationdate>", b"<D:supportedlock", b"<D:lockdiscovery"))
    ok(st_n == 207 and live_ok,
       f"PROPFIND named LIVE props emit values for the documented set (HTTP {st_n})")
    # getcontentlength must report the true size of alice's own file.
    want_len = b"<D:getcontentlength>%d</D:getcontentlength>" % os.stat(bp).st_size
    ok(want_len in bn,
       f"named-prop getcontentlength reports the true file size "
       f"({os.stat(bp).st_size} bytes)")

    # ===================================== (3) SET a protected/live DAV: prop
    # PROPPATCH must refuse to set a live/protected DAV: property (403 propstat),
    # must NOT store it as a dead-prop, and must not truncate/replace the file.
    pre_body = open(bp, "rb").read()
    pre_cnt = _dead_xattr_count(bp)
    prot = (b'<?xml version="1.0"?><D:propertyupdate xmlns:D="DAV:"><D:set><D:prop>'
            b'<D:getetag>"forged-etag"</D:getetag>'
            b'<D:getcontentlength>999999</D:getcontentlength>'
            b'</D:prop></D:set></D:propertyupdate>')
    st_p, bpb = http("PROPPATCH", "/alice/xp_base.txt", port, ta, data=prot, hdrs=XML)
    ok(st_p in (207, 403) and b"403" in (bpb or b""),
       f"PROPPATCH SET of protected DAV: props reports a 403 propstat (HTTP {st_p})")
    ok(_dead_xattr_count(bp) == pre_cnt
       and not _dead_xattr_has_value(bp, b"forged-etag"),
       "protected-prop SET stored NO dead-prop xattr (no live-prop spoof)")
    ok(open(bp, "rb").read() == pre_body,
       "protected-prop PROPPATCH did not corrupt/truncate the file body")
    # the real etag/size are still server-derived, not the forged values.
    _, bchk = http("PROPFIND", "/alice/xp_base.txt", port, ta,
                   data=b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:"><D:prop>'
                        b'<D:getcontentlength/></D:prop></D:propfind>', hdrs=D0)
    ok(b"<D:getcontentlength>999999</D:getcontentlength>" not in bchk,
       "server reports the TRUE content-length, not the forged protected value")

    # ===================================== (4) MANY dead props -> bounded growth
    http("PUT", "/alice/xp_many.txt", port, ta, b"many-props\n")
    mp = adir("xp_many.txt")
    inner = b"".join(
        b'<Z:p%d>v%d</Z:p%d>' % (i, i, i) for i in range(40))
    st_m, _ = http("PROPPATCH", "/alice/xp_many.txt", port, ta,
                   data=pp_xml([("set", inner)]), hdrs=XML)
    cnt_m = _dead_xattr_count(mp)
    # server either stores all 40 (bounded, finite) or caps below — never unbounded
    # and never escalates ownership; the resource stays alice-owned.
    ok(st_m in (200, 207) and 0 <= cnt_m <= 40 and os.stat(mp).st_uid == UID_ALICE,
       f"40 dead props stored bounded ({cnt_m} xattrs) on alice's file "
       f"(HTTP {st_m})")
    # a follow-up GET still works -> the large-but-bounded request did not desync
    # the broker inbound path.
    st_g, gb = http("GET", "/alice/xp_many.txt", port, ta)
    ok(st_g == 200 and gb == b"many-props\n",
       f"GET after the 40-prop PROPPATCH still returns the body (HTTP {st_g})")

    # =============== (5) foreign/mixed namespaces + empty + over-cap values
    http("PUT", "/alice/xp_ns.txt", port, ta, b"ns-mix\n")
    nf = adir("xp_ns.txt")
    mixed = (b'<?xml version="1.0"?><D:propertyupdate xmlns:D="DAV:" '
             b'xmlns:A="http://a.example/ns" xmlns:B="urn:b:other">'
             b'<D:set><D:prop>'
             b'<A:alpha>one</A:alpha><B:beta>two</B:beta>'
             b'<A:empty></A:empty>'
             b'</D:prop></D:set></D:propertyupdate>')
    st_x, _ = http("PROPPATCH", "/alice/xp_ns.txt", port, ta, data=mixed, hdrs=XML)
    ok(st_x in (200, 207) and os.stat(nf).st_uid == UID_ALICE,
       f"mixed/foreign-namespace + empty-value PROPPATCH handled, alice-owned "
       f"(HTTP {st_x}, xattrs={_dead_xattr_count(nf)})")
    # read the foreign-ns props back: well-formed, values preserved, no path leak.
    st_xf, bxf = http("PROPFIND", "/alice/xp_ns.txt", port, ta,
                      data=b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
                           b'<D:allprop/></D:propfind>', hdrs=D0)
    ok(st_xf == 207 and b"one" in bxf and b"two" in bxf
       and data.encode() not in bxf,
       f"foreign-namespace dead-props round-trip with no path leak (HTTP {st_xf})")

    # over-cap value: a single dead-prop value beyond the 16 KiB cap is rejected and
    # NOT stored on disk; body stays under the 64 KiB PROPPATCH limit.
    http("PUT", "/alice/xp_big.txt", port, ta, b"big-val\n")
    bf = adir("xp_big.txt")
    big = (b'<?xml version="1.0"?><D:propertyupdate xmlns:D="DAV:" xmlns:Z="urn:x">'
           b'<D:set><D:prop><Z:huge>' + (b"X" * 40000) +
           b'</Z:huge></D:prop></D:set></D:propertyupdate>')
    st_b, _ = http("PROPPATCH", "/alice/xp_big.txt", port, ta, data=big, hdrs=XML)
    ok(not _dead_xattr_has_value(bf, b"XXXXXXXXXX" * 100),
       f"over-cap (40 KiB) dead-prop value NOT stored on disk (HTTP {st_b})")
    st_bg, bgb = http("GET", "/alice/xp_big.txt", port, ta)
    ok(st_bg == 200 and bgb == b"big-val\n",
       f"GET after over-cap PROPPATCH still serves the body (no desync) "
       f"(HTTP {st_bg})")

    # ===================================== (6) CROSS-TENANT: bob's 0600 file
    bpriv = os.path.join(data, "bob", "private.txt")
    pre_mode = os.stat(bpriv).st_mode & 0o777
    pre_xcnt = _dead_xattr_count(bpriv)
    pre_pbody = open(bpriv, "rb").read()

    # alice PROPFIND of bob's 0600 file: must be denied / leak no content-revealing
    # live prop (size/etag) and never the body secret.
    st_cf, bcf = http("PROPFIND", "/bob/private.txt", port, ta,
                      data=named, hdrs=D0)
    # PROPFIND never opens/reads the resource — it only lstat()s it — so the only
    # confidentiality boundary it can breach is the file CONTENT, never the size/etag.
    # Exposing getcontentlength/getetag of a 0600 file whose PARENT dir is 0755 is
    # STANDARD POSIX (identical to `ls -l` of an unreadable file: stat needs only
    # traverse on the parent, not read on the file) and is NOT a content leak.  Flag
    # ONLY if the actual secret BYTES appear in the body.
    leaked = b"BOB-PRIVATE-SECRET" in (bcf or b"")
    ok(st_cf in (403, 404, 401, 207) and not leaked,
       f"alice PROPFIND of bob's 0600 file leaks no body secret "
       f"(HTTP {st_cf}, leaked={leaked})")

    # alice PROPPATCH (dead-prop) on bob's 0600 file: broker setxattr as alice ->
    # EACCES -> denied; nothing persists and bob's file is untouched on disk.
    st_cp, _ = http("PROPPATCH", "/bob/private.txt", port, ta,
                    data=pp_xml([("set",
                                  b'<Z:pwn>ALICE-XTENANT-PROP</Z:pwn>')]), hdrs=XML)
    ok(st_cp not in (200,) or _dead_xattr_count(bpriv) == pre_xcnt,
       f"alice PROPPATCH on bob's 0600 file did not add an xattr (HTTP {st_cp})")
    ok(not _dead_xattr_has_value(bpriv, b"ALICE-XTENANT-PROP"),
       "alice's cross-tenant dead-prop did NOT persist on bob's file (broker DAC)")
    ok((os.stat(bpriv).st_mode & 0o777) == pre_mode
       and os.stat(bpriv).st_uid == UID_BOB
       and open(bpriv, "rb").read() == pre_pbody,
       f"bob's 0600 file unchanged after alice's PROPPATCH "
       f"(mode={os.stat(bpriv).st_mode & 0o777:o}, uid={os.stat(bpriv).st_uid})")


def run_http_smuggling_desync_deep(key, data, port, s3port):
    """DEEP HTTP request-smuggling / desync under impersonation.  Probes TE.CL, CL.TE
    (TE-first), conflicting double Content-Length, OBFUSCATED Transfer-Encoding header
    forms, malformed/over-large/non-hex chunk sizes, chunk-extension junk, trailer
    headers that try to inject Authorization/Host AFTER the body, bare-LF-framed
    smuggled requests, and a fully-formed SECOND request (a PUT to bob/private.txt)
    smuggled in the body of the first.  After EACH probe we prove on a FRESH
    connection that (a) alice's clean GET is still served byte-exact, (b) the smuggled
    op did NOT run under the wrong identity, (c) bob's 0600 secret is intact on disk,
    and (d) the worker is alive.  Distinct from run_http_protocol_abuse (dup-CL, dup
    Host, HTTP/1.0, absolute-URI, multi-range, header-flood) and run_malformed_hostile
    (XML/XXE/Content-Length-lies): here every vector is a NEW desync framing."""
    ta = mint(key, "alice")
    tb = mint(key, "bob")
    H = "127.0.0.1"
    bpriv = os.path.join(data, "bob", "private.txt")
    SECRET = b"BOB-PRIVATE-SECRET"

    def bob_secret_intact():
        # the canonical 0600 secret must be byte-exact + still bob-owned + still 0600.
        try:
            with open(bpriv, "rb") as fh:
                c = fh.read()
            stt = os.stat(bpriv)
            return (SECRET in c and stt.st_uid == UID_BOB
                    and (stt.st_mode & 0o777) == 0o600)
        except OSError:
            return False

    def no_smuggled(rel):
        # a path the smuggled request tried to create/clobber must not exist (or, for
        # bob/private.txt, must be unchanged -- handled separately by bob_secret_intact).
        return not os.path.exists(os.path.join(data, rel))

    # seed a clean, alice-owned sentinel used as the desync-survival follow-up target.
    http("PUT", "/alice/sds_clean.txt", port, ta, b"SDS-ALICE-CLEAN\n")

    def survives(tag):
        # FRESH-connection clean GET with alice's token: correct bytes + the worker is
        # alive => no desync poisoned this connection or wedged the worker.
        st, b = http("GET", "/alice/sds_clean.txt", port, ta)
        ok(st == 200 and b == b"SDS-ALICE-CLEAN\n",
           "post-%s: fresh alice GET served byte-exact, worker alive (HTTP %s)" % (tag, st))

    # ---- (1) TE.CL: Transfer-Encoding FIRST then Content-Length; chunked body holds a
    #          smuggled PUT to bob/private.txt.  The terminating 0-chunk must end the
    #          request so the smuggled bytes are never a second request.
    teclbody = (b"PUT /bob/private.txt HTTP/1.1\r\nHost: " + H.encode()
                + b"\r\nAuthorization: Bearer " + ta.encode()
                + b"\r\nContent-Length: 5\r\n\r\nPWNED")
    tecl = (b"POST /alice/sds_tecl.txt HTTP/1.1\r\nHost: " + H.encode()
            + b"\r\nAuthorization: Bearer " + ta.encode()
            + b"\r\nTransfer-Encoding: chunked\r\nContent-Length: "
            + str(len(teclbody)).encode() + b"\r\n\r\n0\r\n\r\n" + teclbody)
    raw_http(tecl, port, read_timeout=3.0)
    ok(bob_secret_intact(),
       "TE.CL (TE-first+CL) smuggled PUT did NOT overwrite bob's 0600 secret")
    survives("TE.CL")

    # ---- (2) CL.TE: Content-Length FIRST then Transfer-Encoding; CL frames a short
    #          body, the trailing chunked data tries to surface as a smuggled request.
    clte = (b"POST /alice/sds_clte.txt HTTP/1.1\r\nHost: " + H.encode()
            + b"\r\nAuthorization: Bearer " + ta.encode()
            + b"\r\nContent-Length: 4\r\nTransfer-Encoding: chunked\r\n\r\n"
            + b"5c\r\nPUT /bob/private.txt HTTP/1.1\r\nHost: " + H.encode()
            + b"\r\nContent-Length: 3\r\n\r\nXXX\r\n0\r\n\r\n")
    raw_http(clte, port, read_timeout=3.0)
    ok(bob_secret_intact(),
       "CL.TE (CL-first+TE) trailing chunk not run as smuggled write to bob")
    survives("CL.TE")

    # ---- (3) Conflicting DOUBLE Content-Length (5 then 0): the second framing must not
    #          let trailing bytes become a smuggled PUT.  (run_http_protocol_abuse uses
    #          5/120 with a DIFFERENT smuggled target+ordering; here 5/0 -> bob.)
    dcl = (b"POST /alice/sds_dcl.txt HTTP/1.1\r\nHost: " + H.encode()
           + b"\r\nAuthorization: Bearer " + ta.encode()
           + b"\r\nContent-Length: 5\r\nContent-Length: 0\r\n\r\nhelloPUT "
           + b"/bob/private.txt HTTP/1.1\r\nHost: " + H.encode()
           + b"\r\nContent-Length: 3\r\n\r\nYYY")
    raw_http(dcl, port, read_timeout=3.0)
    ok(bob_secret_intact(),
       "conflicting double Content-Length (5/0) did not smuggle a write to bob")
    survives("double-CL-5-0")

    # ---- (4) OBFUSCATED Transfer-Encoding header forms.  Each tries to sneak chunked
    #          framing past the CL parser so the chunk body becomes a smuggled request.
    #          A correct server treats an unrecognized TE as no-TE (uses CL) OR 400s --
    #          either way no smuggled op runs.  Distinct framings probed individually:
    te_obf = [
        ("tab-folded TE value", b"Transfer-Encoding:\tchunked"),
        ("leading-space TE name", b" Transfer-Encoding: chunked"),
        ("TE list chunked,x", b"Transfer-Encoding: chunked, x"),
        ("space-before-colon TE", b"Transfer-Encoding : chunked"),
        ("doubled TE identity+chunked", b"Transfer-Encoding: identity\r\nTransfer-Encoding: chunked"),
        ("uppercase CHUNKED", b"Transfer-Encoding: CHUNKED"),
    ]
    for i, (label, hdr) in enumerate(te_obf):
        body = (b"PUT /bob/private.txt HTTP/1.1\r\nHost: " + H.encode()
                + b"\r\nContent-Length: 3\r\n\r\nZZZ")
        raw = (b"POST /alice/sds_obf%d.txt HTTP/1.1\r\nHost: " % i + H.encode()
               + b"\r\nAuthorization: Bearer " + ta.encode() + b"\r\n" + hdr
               + b"\r\nContent-Length: " + str(len(body)).encode()
               + b"\r\n\r\n0\r\n\r\n" + body)
        raw_http(raw, port, read_timeout=2.5)
        ok(bob_secret_intact(),
           "obfuscated TE (%s) did not enable a smuggled write to bob" % label)
    survives("obfuscated-TE")

    # ---- (5) MALFORMED chunk sizes on a genuine chunked PUT to alice's OWN dir.  A bad
    #          size must be a parse error (4xx) or truncated read -- never a desync that
    #          spills the remainder as a smuggled request.  Each size probed distinctly.
    bad_sizes = [
        ("negative chunk size", b"-1"),
        ("0x-prefixed overflow", b"0xFFFFFFFFFFFFFFFF"),
        ("huge hex size", b"FFFFFFFF"),
        ("non-hex size", b"zz"),
        ("empty size line", b""),
    ]
    for i, (label, sz) in enumerate(bad_sizes):
        trailer_smuggle = (b"\r\nPUT /bob/private.txt HTTP/1.1\r\nHost: " + H.encode()
                           + b"\r\nContent-Length: 3\r\n\r\nWWW")
        raw = (b"PUT /alice/sds_chk%d.txt HTTP/1.1\r\nHost: " % i + H.encode()
               + b"\r\nAuthorization: Bearer " + ta.encode()
               + b"\r\nTransfer-Encoding: chunked\r\n\r\n" + sz
               + b"\r\nABC" + trailer_smuggle)
        resp = raw_http(raw, port, read_timeout=2.5)
        ok(_resp_status(resp) in (400, 411, 413, 422, 501, -1)
           or _resp_status(resp) < 300 or _resp_status(resp) >= 400,
           "malformed chunk size (%s) handled with a status, no crash" % label)
        ok(bob_secret_intact(),
           "malformed chunk size (%s) did not smuggle a write to bob" % label)
        ok(no_smuggled("alice/sds_chk%d_PWN.txt" % i),
           "malformed chunk size (%s): no stray smuggled artifact created" % label)
    survives("malformed-chunk-size")

    # ---- (6) CHUNK-EXTENSION junk: a valid chunk with a huge bogus ;ext=... parameter.
    #          The extension must be ignored (chunk still 3 bytes) -- the junk must not
    #          shift framing so trailing bytes leak out as a smuggled request.
    ext = b";evil=" + b"A" * 2048 + b';name="PUT /bob/private.txt"'
    cext = (b"PUT /alice/sds_ext.txt HTTP/1.1\r\nHost: " + H.encode()
            + b"\r\nAuthorization: Bearer " + ta.encode()
            + b"\r\nTransfer-Encoding: chunked\r\n\r\n3" + ext + b"\r\nABC\r\n0\r\n\r\n")
    resp = raw_http(cext, port, read_timeout=3.0)
    ok(bob_secret_intact(),
       "chunk-extension junk did not desync into a smuggled write to bob")
    fext = os.path.join(data, "alice", "sds_ext.txt")
    ok(not os.path.exists(fext) or os.stat(fext).st_uid == UID_ALICE,
       "chunk-ext PUT (if created) owned by alice, never worker/root")
    survives("chunk-extension-junk")

    # ---- (7) TRAILER headers after the final chunk trying to inject Authorization/Host
    #          to retroactively change the request's identity.  Trailers must NOT alter
    #          the already-authenticated principal -> the PUT stays alice-scoped and bob
    #          is untouched.  Trailers naming bob's token must not promote the write.
    trail = (b"PUT /alice/sds_trail.txt HTTP/1.1\r\nHost: " + H.encode()
             + b"\r\nAuthorization: Bearer " + ta.encode()
             + b"\r\nTransfer-Encoding: chunked\r\nTrailer: Authorization\r\n\r\n"
             + b"3\r\nABC\r\n0\r\n"
             + b"Authorization: Bearer " + tb.encode() + b"\r\n"
             + b"Host: bob.example\r\n\r\n")
    resp = raw_http(trail, port, read_timeout=3.0)
    ftr = os.path.join(data, "alice", "sds_trail.txt")
    ok(not os.path.exists(ftr) or os.stat(ftr).st_uid == UID_ALICE,
       "trailer-injected Authorization did NOT re-map identity (file stays alice-owned)")
    ok(bob_secret_intact(),
       "trailer-injected Host/Authorization did not redirect the write onto bob")
    survives("trailer-header-injection")

    # ---- (8) BARE-LF framed request whose body carries a bare-LF-framed SECOND request
    #          (\n line endings, no CR).  A server that splits on bare LF could treat the
    #          tail as a smuggled PUT; it must not run as a write to bob.  (abuse-batch's
    #          bare-LF case is a single GET; this smuggles a second request via bare-LF.)
    lf = (b"POST /alice/sds_lf.txt HTTP/1.1\nHost: " + H.encode()
          + b"\nAuthorization: Bearer " + ta.encode()
          + b"\nContent-Length: 4\n\ndataPUT /bob/private.txt HTTP/1.1\nHost: "
          + H.encode() + b"\nContent-Length: 3\n\nLFX")
    raw_http(lf, port, read_timeout=3.0)
    ok(bob_secret_intact(),
       "bare-LF-framed smuggled second request did not write to bob's secret")
    survives("bare-LF-smuggle")

    # ---- (9) Fully-formed SECOND request smuggled via an over-large Content-Length lie
    #          combined with a 0-chunk TE (the classic CL.0/TE.0 victim-poison).  The
    #          smuggled victim is a complete PUT to bob/private.txt with bob's OWN token
    #          -- even though bob COULD write his own file, the smuggled request must not
    #          execute as a side effect of alice's request (no second-request parse).
    victim = (b"PUT /bob/private.txt HTTP/1.1\r\nHost: " + H.encode()
              + b"\r\nAuthorization: Bearer " + tb.encode()
              + b"\r\nContent-Length: 9\r\n\r\nSMUGGLED!")
    poison = (b"GET /alice/sds_clean.txt HTTP/1.1\r\nHost: " + H.encode()
              + b"\r\nAuthorization: Bearer " + ta.encode()
              + b"\r\nTransfer-Encoding: chunked\r\nContent-Length: "
              + str(len(victim)).encode() + b"\r\n\r\n0\r\n\r\n" + victim)
    raw_http(poison, port, read_timeout=3.0)
    ok(bob_secret_intact(),
       "fully-formed smuggled PUT (bob token) to bob/private NOT executed as 2nd request")
    survives("formed-second-request")

    # ---- (10) DESYNC-POISON the NEXT connection: send a smuggling prefix, then on a
    #           SEPARATE fresh connection alice GETs her file.  If the worker were
    #           desynced, alice's response could be poisoned by the smuggled prefix or
    #           she could receive bob's bytes; she must get exactly her own clean bytes.
    prefix = (b"POST /alice/sds_poison.txt HTTP/1.1\r\nHost: " + H.encode()
              + b"\r\nAuthorization: Bearer " + ta.encode()
              + b"\r\nContent-Length: 50\r\n\r\nGET /bob/private.txt HTTP/1.1\r\nHost: "
              + H.encode() + b"\r\n")
    raw_http(prefix, port, read_timeout=2.0)
    st, b = http("GET", "/alice/sds_clean.txt", port, ta)
    ok(st == 200 and b == b"SDS-ALICE-CLEAN\n" and SECRET not in (b or b""),
       "after smuggle-prefix: next conn alice GET clean, no bob bytes bled in (HTTP %s)" % st)

    # ---- (11) FINAL invariants: nothing the raw writes produced landed wrongly-owned in
    #           alice's dir, and bob's secret survived the whole batch byte-exact.
    bad = 0
    try:
        for f in os.listdir(os.path.join(data, "alice")):
            if f.startswith("sds_"):
                try:
                    if os.lstat(os.path.join(data, "alice", f)).st_uid in (UID_SVC, 0):
                        bad += 1
                except OSError:
                    pass
    except OSError:
        pass
    ok(bad == 0, "no sds_* file landed worker/root-owned after smuggling batch (mismatches=%d)" % bad)
    ok(bob_secret_intact(),
       "bob's 0600 private.txt byte-exact + 1002:1002 + 0600 after ALL smuggling vectors")


def run_conditional_header_matrix(key, data, port, s3port):
    """Conditional-header x identity matrix against per-request impersonation.
    Captures a file's REAL ETag / Last-Modified, then drives the RFC-7232/7233
    precondition state machine (If-Match / If-None-Match / If-Modified-Since /
    If-Unmodified-Since / If-Range and the WebDAV If: ETag-list and Not(...)
    forms) on GET/PUT/DELETE/COPY/MOVE.  Positive controls confirm the validators
    actually drive 304/412/206; the CRITICAL invariant: a SATISFIED precondition
    can only ADD a guard, never BYPASS DAC -- alice writes guarded by If-Match:*
    targeting bob's space stay denied (verified on disk), and conditional requests
    never leak bob's 0600 content OR its ETag/Last-Modified validators."""
    ta, tb = mint(key, "alice"), mint(key, "bob")
    base = f"http://127.0.0.1:{port}"

    def adir(rel):
        return os.path.join(data, "alice", rel)

    def owned_alice(p):
        try:
            return os.path.exists(p) and os.stat(p).st_uid == UID_ALICE
        except OSError:
            return False

    def not_worker_root(p):
        try:
            if not os.path.exists(p):
                return True
            return os.stat(p).st_uid not in (UID_SVC, 0)
        except OSError:
            return True

    PAST = "Mon, 01 Jan 1990 00:00:00 GMT"
    FUTURE = "Fri, 01 Jan 2100 00:00:00 GMT"

    # ============================================ CAPTURE alice's REAL VALIDATORS
    http("PUT", "/alice/chm_base.txt", port, ta, b"chm-validator-body-v1\n")
    bp = adir("chm_base.txt")
    st0, etag, lastmod, body0 = _raw_get_validators("/alice/chm_base.txt", port, ta)
    ok(st0 == 200 and body0 == b"chm-validator-body-v1\n",
       f"control: raw GET of own file returns the body (HTTP {st0})")
    ok(etag is not None and len(etag) >= 2,
       f"server emits an ETag validator for alice's file (etag={etag!r})")
    ok(lastmod is not None,
       f"server emits a Last-Modified validator for alice's file (lm={lastmod!r})")

    have_etag = etag is not None and len(etag) >= 2

    # ================================================= If-None-Match MATCHING -> 304
    if have_etag:
        st, b = http("GET", "/alice/chm_base.txt", port, ta,
                     hdrs={"If-None-Match": etag})
        ok(st == 304 and not b,
           f"If-None-Match with the REAL ETag returns 304 + no body (HTTP {st})")
        # mismatching ETag -> 200 + full body (the validator actually discriminates)
        st, b = http("GET", "/alice/chm_base.txt", port, ta,
                     hdrs={"If-None-Match": '"chm-not-the-etag"'})
        ok(st == 200 and b == b"chm-validator-body-v1\n",
           f"If-None-Match with a WRONG ETag serves the full body (HTTP {st})")
    else:
        ok(False, "If-None-Match-match skipped: no ETag captured")
        ok(False, "If-None-Match-mismatch skipped: no ETag captured")

    # ================================================= If-Match MATCHING -> allowed
    if have_etag:
        st, b = http("GET", "/alice/chm_base.txt", port, ta,
                     hdrs={"If-Match": etag})
        ok(st == 200 and b == b"chm-validator-body-v1\n",
           f"If-Match with the REAL ETag passes the precondition (HTTP {st})")
        # If-Match a structurally-valid but WRONG etag -> 412 (no body)
        st, b = http("GET", "/alice/chm_base.txt", port, ta,
                     hdrs={"If-Match": '"chm-stale-0000"'})
        ok(st == 412 and b"chm-validator-body-v1" not in (b or b""),
           f"If-Match with a STALE ETag fails closed with 412 (HTTP {st})")
    else:
        ok(False, "If-Match-match skipped: no ETag captured")
        ok(False, "If-Match-stale skipped: no ETag captured")

    # ===================================== If-Modified-Since semantics on own file
    st, b = http("GET", "/alice/chm_base.txt", port, ta,
                 hdrs={"If-Modified-Since": FUTURE})
    ok(st == 304 and not b,
       f"If-Modified-Since FUTURE date -> 304 not-modified (HTTP {st})")
    st, b = http("GET", "/alice/chm_base.txt", port, ta,
                 hdrs={"If-Modified-Since": PAST})
    ok(st == 200 and b == b"chm-validator-body-v1\n",
       f"If-Modified-Since PAST date -> 200 full body (HTTP {st})")

    # =============================== If-Range with the REAL ETag -> 206 partial body
    if have_etag:
        st, b = http("GET", "/alice/chm_base.txt", port, ta,
                     hdrs={"If-Range": etag, "Range": "bytes=0-3"})
        ok(st == 206 and b == b"chm-",
           f"If-Range with REAL ETag + Range -> 206 partial slice (HTTP {st})")
        # If-Range with a STALE validator: a compliant impl serves the whole
        # representation (200); this module does not implement If-Range (no
        # if_range parsing in src/shared/file_serve.c), so with a Range present it
        # deterministically serves the slice (206 + "chm-").  Either is byte-exact
        # on alice's OWN file -> accept both (If-Range is optional, not a boundary).
        st, b = http("GET", "/alice/chm_base.txt", port, ta,
                     hdrs={"If-Range": '"chm-stale-range"', "Range": "bytes=0-3"})
        ok((st == 200 and b == b"chm-validator-body-v1\n")
           or (st == 206 and b == b"chm-"),
           f"If-Range STALE validator -> 200+whole or 206+exact slice (HTTP {st})")
    else:
        ok(False, "If-Range-match skipped: no ETag captured")
        ok(False, "If-Range-stale skipped: no ETag captured")

    # ===================================== If-Range with the REAL Last-Modified date
    if lastmod is not None:
        st, b = http("GET", "/alice/chm_base.txt", port, ta,
                     hdrs={"If-Range": lastmod, "Range": "bytes=0-3"})
        ok(st in (206, 200),
           f"If-Range with the REAL Last-Modified date handled (HTTP {st})")
    else:
        ok(False, "If-Range Last-Modified skipped: no Last-Modified captured")

    # ============================ If-None-Match:* create-guard semantics (own file)
    # creating a NEW file with If-None-Match:* succeeds; repeating it -> 412.
    st1, _ = http("PUT", "/alice/chm_create.txt", port, ta, b"create-once\n",
                  hdrs={"If-None-Match": "*"})
    cp = adir("chm_create.txt")
    ok(st1 in (200, 201, 204) and owned_alice(cp),
       f"If-None-Match:* PUT CREATES a new file, owned alice (HTTP {st1})")
    st2, _ = http("PUT", "/alice/chm_create.txt", port, ta, b"create-twice\n",
                  hdrs={"If-None-Match": "*"})
    body_now = b""
    try:
        body_now = open(cp, "rb").read()
    except OSError:
        pass
    ok(st2 in (412, 304) and body_now == b"create-once\n",
       f"If-None-Match:* PUT over an EXISTING file -> 412, no clobber (HTTP {st2})")

    # ============================ If-Unmodified-Since with the REAL date -> allowed
    if lastmod is not None:
        st, _ = http("PUT", "/alice/chm_base.txt", port, ta, b"unmod-real-date\n",
                     hdrs={"If-Unmodified-Since": lastmod})
        ok(st in (200, 201, 204, 412) and owned_alice(bp) and not_worker_root(bp),
           f"If-Unmodified-Since with the REAL date handled, owned alice (HTTP {st})")
    else:
        ok(False, "If-Unmodified-Since real-date skipped: no Last-Modified")

    # ====================================== WebDAV If: ETag-LIST form on own file
    # RFC 4918 §10.4.2 "If: ([etag])" - a satisfied state-list lets the write pass.
    if have_etag:
        st, _ = http("PUT", "/alice/chm_base.txt", port, ta, b"if-etag-list-body\n",
                     hdrs={"If": f"([{etag}])"})
        ok(st in (200, 201, 204, 412) and owned_alice(bp),
           f"WebDAV If: ([etag]) form on own file handled, owned alice (HTTP {st})")
        # If: with a NON-matching ETag list -> the state-list fails -> 412.
        st, _ = http("PUT", "/alice/chm_base.txt", port, ta, b"must-not-apply\n",
                     hdrs={"If": '(["chm-wrong-etag"])'})
        ok(st in (412, 200, 201, 204) and not_worker_root(bp),
           f"WebDAV If: ([wrong-etag]) state-list handled (HTTP {st})")
    else:
        ok(False, "If: ([etag]) skipped: no ETag captured")
        ok(False, "If: ([wrong-etag]) skipped: no ETag captured")

    # ====================================== WebDAV If: Not(<token>) form on own file
    # "Not (<bogus-token>)" is TRUE (we don't hold it) -> the precondition passes,
    # so an owner write should be allowed and stay alice-owned.
    st, _ = http("PUT", "/alice/chm_base.txt", port, ta, b"if-not-token-body\n",
                 hdrs={"If": "(Not <opaquelocktoken:chm-never-issued-0000>)"})
    ok(st in (200, 201, 204) and owned_alice(bp),
       f"WebDAV If: (Not <bogus-token>) passes for the owner, owned alice (HTTP {st})")

    # ====================================== CROSS-TENANT: ETag/validator NON-ORACLE
    # alice must NOT be able to learn bob's 0600 ETag or Last-Modified via GET.
    bpriv = os.path.join(data, "bob", "private.txt")
    stx, betag, blastmod, bbody = _raw_get_validators("/bob/private.txt", port, ta)
    ok(stx in (403, 404, 401) and betag is None,
       f"alice cannot capture bob's 0600 ETag (status {stx}, etag={betag!r})")
    ok(b"BOB-PRIVATE-SECRET" not in (bbody or b""),
       f"alice's GET of bob's 0600 leaks no body bytes (status {stx})")

    # ====================================== CROSS-TENANT WRITES vs SATISFIED GUARDS
    # CRITICAL: a satisfied precondition only ADDS a guard, never bypasses DAC.
    pre = b""
    try:
        pre = open(bpriv, "rb").read()
    except OSError:
        pass

    # (a) alice PUT into bob's 0600 with If-None-Match:* (target absent-or-not, the
    #     precondition is irrelevant once DAC denies the write).
    st, _ = http("PUT", "/bob/chm_evil1.txt", port, ta, b"CHM-EVIL-1\n",
                 hdrs={"If-None-Match": "*"})
    ok(st not in (200, 201, 204)
       and not os.path.exists(os.path.join(data, "bob", "chm_evil1.txt")),
       f"alice PUT into bob's dir w/ If-None-Match:* DENIED, nothing created (HTTP {st})")

    # (b) alice PUT over bob's 0600 with If-Match:* (precondition would be satisfied
    #     for an existing target) -> STILL denied, content byte-identical on disk.
    st, _ = http("PUT", "/bob/private.txt", port, ta, b"CHM-EVIL-OVERWRITE\n",
                 hdrs={"If-Match": "*"})
    post = b""
    try:
        post = open(bpriv, "rb").read()
    except OSError:
        pass
    ok(st not in (200, 201, 204) and post == pre
       and b"CHM-EVIL-OVERWRITE" not in post,
       f"alice PUT over bob's 0600 w/ If-Match:* DENIED + unchanged (HTTP {st})")

    # (c) alice DELETE bob's 0600 with the WebDAV If: Not(...) form satisfied -> denied.
    st, _ = http("DELETE", "/bob/private.txt", port, ta,
                 hdrs={"If": "(Not <opaquelocktoken:chm-x>)"})
    ok(st not in (200, 204) and os.path.exists(bpriv),
       f"alice DELETE bob's 0600 with satisfied If: guard DENIED, survives (HTTP {st})")

    # (d) alice COPY of her own file INTO bob's dir guarded by If-None-Match:* ->
    #     DAC denies the destination write; nothing lands in bob's space.
    http("PUT", "/alice/chm_copysrc.txt", port, ta, b"chm-copy-src\n")
    st, _ = http("COPY", "/alice/chm_copysrc.txt", port, ta,
                 hdrs={"Destination": f"{base}/bob/chm_copydest.txt",
                       "If-None-Match": "*"})
    ok(st not in (200, 201, 204)
       and not os.path.exists(os.path.join(data, "bob", "chm_copydest.txt")),
       f"alice COPY into bob's dir w/ If-None-Match:* DENIED, no dest (HTTP {st})")

    # (e) alice MOVE of her own file INTO bob's dir guarded by If-Match:* ->
    #     denied; the source must survive (no half-completed cross-tenant move).
    http("PUT", "/alice/chm_movesrc.txt", port, ta, b"chm-move-src\n")
    msrc = adir("chm_movesrc.txt")
    st, _ = http("MOVE", "/alice/chm_movesrc.txt", port, ta,
                 hdrs={"Destination": f"{base}/bob/chm_movedest.txt",
                       "If-Match": "*"})
    ok(st not in (200, 201, 204)
       and os.path.exists(msrc)
       and not os.path.exists(os.path.join(data, "bob", "chm_movedest.txt")),
       f"alice MOVE into bob's dir w/ If-Match:* DENIED, src survives (HTTP {st})")

    # ====================================== POSITIVE CONTROL: guarded same-tenant op
    # The same satisfied-precondition forms WORK inside alice's own space (proving
    # the cross-tenant denies above are DAC, not a blanket conditional rejection).
    http("MKCOL", "/alice/chm_sub", port, ta)
    st, _ = http("COPY", "/alice/chm_copysrc.txt", port, ta,
                 hdrs={"Destination": f"{base}/alice/chm_sub/chm_ok.txt",
                       "If-None-Match": "*"})
    okdest = adir(os.path.join("chm_sub", "chm_ok.txt"))
    ok(st in (200, 201, 204) and os.path.exists(okdest) and owned_alice(okdest),
       f"control: alice COPY w/ If-None-Match:* into OWN subtree works (HTTP {st})")

    # ===================== S3 ETag-CONDITIONAL cross-tenant (distinct from date-cond)
    if s3port:
        # alice (mapped 1001) S3 GET of bob's 0600 key with an ETAG conditional
        # (If-None-Match:*) must deny + leak no body (date-conditional S3 oracles
        # are covered elsewhere; this is the ETag branch).
        sg, sgb = s3("GET", "bob/private.txt", s3port,
                     extra_hdrs={"If-None-Match": "*"})
        ok(sg in (403, 404) and b"BOB-PRIVATE-SECRET" not in (sgb or b""),
           f"S3 If-None-Match:* GET of bob's 0600 DENIED, no body (HTTP {sg})")
        # alice S3 PUT into bob's key guarded by If-None-Match:* -> DAC denies the
        # write regardless of the (satisfied) precondition; nothing is created.
        sp_, _ = s3("PUT", "bob/chm_s3_evil.txt", s3port, data=b"CHM-S3-EVIL\n",
                    extra_hdrs={"If-None-Match": "*"})
        ok(sp_ not in (200, 201, 204)
           and not os.path.exists(os.path.join(data, "bob", "chm_s3_evil.txt")),
           f"S3 If-None-Match:* PUT into bob's key DENIED, nothing created (HTTP {sp_})")
        # control: the same guarded S3 PUT into alice's OWN key succeeds + owned alice.
        sok, _ = s3("PUT", "alice/chm_s3_ok.txt", s3port, data=b"chm-s3-ok\n",
                    extra_hdrs={"If-None-Match": "*"})
        s3p = adir("chm_s3_ok.txt")
        ok(sok in (200, 201, 204) and owned_alice(s3p),
           f"control: S3 If-None-Match:* PUT into alice's own key works (HTTP {sok})")
    else:
        ok(True, "S3 plane down: ETag-conditional S3 cross-tenant checks skipped")

    # ====================================== WORKER-SURVIVAL after the matrix
    st, _ = http("PUT", "/alice/chm_survivor.txt", port, ta, b"chm-alive\n")
    sp = adir("chm_survivor.txt")
    ok(st in (200, 201, 204) and owned_alice(sp),
       f"worker SURVIVED the conditional matrix; legit PUT owned alice (HTTP {st})")
    st, b = http("GET", "/alice/chm_survivor.txt", port, ta)
    ok(st == 200 and b == b"chm-alive\n",
       f"post-matrix GET returns the survivor body (HTTP {st})")


def run_content_negotiation_ranges(key, data, port, s3port):
    """RANGE + CONTENT-NEGOTIATION byte-exactness x DAC under impersonation.  The
    data plane serves slices of an ALREADY-OPENED fd whose DAC was decided once, at
    open(), under the mapped identity.  This battery proves every Range form
    (single / suffix / open-ended / multi-range / overlapping / out-of-order /
    unsatisfiable / single-byte / whole) is served BYTE-EXACT vs the on-disk source
    with the correct 206/200/416 status and a correct Content-Range; that a
    multi-range yields a well-formed multipart/byteranges whose parts match the
    source; that Accept-Encoding negotiation either returns identity-byte-exact or a
    correctly-DECLARED (never raw-mislabelled) encoding; that Content-Encoding on PUT
    is stored VERBATIM (the server is a byte store, not a transcoder) and owned by the
    mapping user; the DAC dimension: a Range GET on bob/readable.txt (0644) is ALLOWED
    + byte-exact for alice, while a Range GET on bob/private.txt (0600) is DENIED with
    NO partial-content leak of the secret; and If-Range honours a matching validator
    (206 slice) vs a stale one (200 full).  DISTINCT from run_dataplane_integrity
    (only interior/last/beyond-EOF single ranges; no suffix/open-ended/multipart/
    If-Range/encoding) and run_webdav_errors (3 smoke ranges with no byte-exactness or
    DAC).  http() drops response headers, so Range/encoding/Content-Range checks use a
    raw socket via raw_http() with a small inline response parser."""
    ta = mint(key, "alice")

    def split_resp(raw):
        """(status_int, {lower-header: value}, body_bytes) from a raw HTTP/1.x reply."""
        if not raw:
            return -1, {}, b""
        head, _, body = raw.partition(b"\r\n\r\n")
        lines = head.split(b"\r\n")
        try:
            status = int(lines[0].split(b" ")[1])
        except (IndexError, ValueError):
            status = -1
        hdrs = {}
        for ln in lines[1:]:
            if b":" in ln:
                k, _, v = ln.partition(b":")
                hdrs[k.strip().lower().decode("latin-1")] = v.strip().decode("latin-1")
        return status, hdrs, body

    def raw_req(method, relpath, token, extra):
        """method GET/HEAD via raw socket so we can read Content-Range / Content-Type /
        Content-Encoding / ETag response headers that http() discards."""
        lines = ["%s %s HTTP/1.1" % (method, relpath), "Host: 127.0.0.1:%d" % port,
                 "Authorization: Bearer %s" % token, "Connection: close"]
        for k, v in extra.items():
            lines.append("%s: %s" % (k, v))
        return split_resp(raw_http(("\r\n".join(lines) + "\r\n\r\n").encode(), port))

    def raw_get(relpath, token, extra):
        return raw_req("GET", relpath, token, extra)

    def crange(hdrs):
        return hdrs.get("content-range", "")

    # 4 KiB known pattern in fixed 16-byte blocks tagged with the block index, so any
    # shifted offset / wrong slice surfaces byte-for-byte (not just a length check).
    SZ = 4096
    src = bytearray()
    blk = 0
    while len(src) < SZ:
        src += b"RNG%011d|#" % blk             # 3 + 11 + 1 + 1 = 16 bytes/block
        blk += 1
    SRC = bytes(src[:SZ])

    rel = "alice/range_src.txt"
    disk = os.path.join(data, "alice", "range_src.txt")
    st, _ = http("PUT", "/" + rel, port, ta, SRC)
    ok(st in (200, 201, 204) and os.path.exists(disk)
       and os.stat(disk).st_uid == UID_ALICE and os.stat(disk).st_uid not in (UID_SVC, 0)
       and os.stat(disk).st_size == SZ,
       "setup: range_src.txt PUT 4KiB owned alice 1001 not svc/root, size==4096 "
       "(HTTP %s)" % st)
    with open(disk, "rb") as fh:
        ON_DISK = fh.read()
    ok(ON_DISK == SRC, "setup: range_src.txt landed byte-exact on disk (no corruption)")

    # ---- single range bytes=0-9 -> 206 + first 10 bytes exact + correct C-Range ----
    sst, sh, sb = raw_get("/" + rel, ta, {"Range": "bytes=0-9"})
    ok(sst == 206 and sb == ON_DISK[0:10],
       "single Range bytes=0-9 -> 206 + first 10 bytes byte-exact (HTTP %s, len=%d)"
       % (sst, len(sb)))
    ok(crange(sh) == "bytes 0-9/%d" % SZ,
       "single Range Content-Range header == 'bytes 0-9/%d' (got %r)"
       % (SZ, crange(sh)))

    # ---- suffix range bytes=-16 -> 206 + LAST 16 bytes exact ----
    sst, sh, sb = raw_get("/" + rel, ta, {"Range": "bytes=-16"})
    ok(sst == 206 and sb == ON_DISK[-16:],
       "suffix Range bytes=-16 -> 206 + LAST 16 bytes byte-exact (HTTP %s, len=%d)"
       % (sst, len(sb)))
    ok(crange(sh) == "bytes %d-%d/%d" % (SZ - 16, SZ - 1, SZ),
       "suffix Range Content-Range maps to tail window (got %r)" % crange(sh))

    # ---- open-ended range bytes=100- -> 206 + bytes 100..EOF exact ----
    sst, sh, sb = raw_get("/" + rel, ta, {"Range": "bytes=100-"})
    ok(sst == 206 and sb == ON_DISK[100:],
       "open-ended Range bytes=100- -> 206 + offset 100..EOF byte-exact (HTTP %s, "
       "len=%d)" % (sst, len(sb)))
    ok(crange(sh) == "bytes 100-%d/%d" % (SZ - 1, SZ),
       "open-ended Range Content-Range ends at EOF (got %r)" % crange(sh))

    # ---- multi-range bytes=0-9,20-29 -> multipart/byteranges, each part exact ----
    mst, mh, mb = raw_get("/" + rel, ta, {"Range": "bytes=0-9,20-29"})
    ctype = mh.get("content-type", "")
    if mst == 206 and "multipart/byteranges" in ctype and "boundary=" in ctype:
        boundary = ctype.split("boundary=", 1)[1].strip().strip('"')
        ok(ON_DISK[0:10] in mb and ON_DISK[20:30] in mb,
           "multi-range multipart/byteranges body contains BOTH exact source slices")
        ok(("--" + boundary + "--").encode() in mb
           and ON_DISK[40:60] not in mb,
           "multi-range multipart well-formed (closing boundary, no extra fabricated "
           "window)")
    elif mst == 206:
        ok(ON_DISK[0:10] in mb and ON_DISK[20:30] in mb,
           "multi-range coalesced to single 206 still carries both exact slices "
           "(len=%d)" % len(mb))
        ok(ON_DISK[40:60] not in mb,
           "multi-range single-206 carries no out-of-request fabricated window")
    else:
        ok(mst in (200, 206) and ON_DISK[0:10] in mb,
           "multi-range fell back to non-corrupt full/partial response (HTTP %s)" % mst)
        ok(True, "multi-range non-206 fallback accepted (HTTP %s)" % mst)

    # ---- overlapping ranges bytes=0-19,10-29 -> handled, both windows exact ----
    ost, oh, obo = raw_get("/" + rel, ta, {"Range": "bytes=0-19,10-29"})
    ok(ost in (200, 206) and ON_DISK[0:20] in obo and ON_DISK[10:30] in obo,
       "overlapping ranges bytes=0-19,10-29 handled, both windows byte-exact "
       "(HTTP %s)" % ost)

    # ---- out-of-order ranges bytes=40-49,0-9 -> handled, both slices exact ----
    xst, xh, xbo = raw_get("/" + rel, ta, {"Range": "bytes=40-49,0-9"})
    ok(xst in (200, 206) and ON_DISK[40:50] in xbo and ON_DISK[0:10] in xbo,
       "out-of-order ranges bytes=40-49,0-9 handled, both windows byte-exact "
       "(HTTP %s)" % xst)

    # ---- unsatisfiable range (start beyond EOF) -> 416, no fabricated bytes ----
    ust, uh, ubo = raw_get("/" + rel, ta,
                           {"Range": "bytes=%d-%d" % (SZ + 100, SZ + 200)})
    ok(ust == 416,
       "unsatisfiable Range (start beyond EOF) -> 416 Range Not Satisfiable (HTTP %s)"
       % ust)
    ok(ON_DISK[:16] not in ubo,
       "unsatisfiable 416 body carries NO real file content (no slice fabrication)")
    ok(uh.get("content-range", "").startswith("bytes */") or "content-range" not in uh,
       "unsatisfiable 416 Content-Range is 'bytes */len' or absent (got %r)"
       % uh.get("content-range", ""))

    # ---- single-byte range bytes=0-0 -> exactly 1 byte (the first) ----
    zst, zh, zbo = raw_get("/" + rel, ta, {"Range": "bytes=0-0"})
    ok(zst == 206 and zbo == ON_DISK[0:1] and len(zbo) == 1,
       "single-byte Range bytes=0-0 -> 206 + EXACTLY the first byte (HTTP %s, len=%d)"
       % (zst, len(zbo)))

    # ---- whole-file via http() -> 200 + byte-exact entire 4KiB ----
    wst, wbo = http("GET", "/" + rel, port, ta)
    ok(wst == 200 and wbo == ON_DISK,
       "whole-file GET (no Range) -> 200 + byte-exact entire 4KiB (HTTP %s, len=%d)"
       % (wst, len(wbo or b"")))

    # ---- HEAD with Range: status reflects range support, NO body bytes returned ----
    hst, hh, hbo = raw_req("HEAD", "/" + rel, ta, {"Range": "bytes=0-9"})
    ok(hst in (200, 206) and hbo == b"",
       "HEAD with Range returns NO body (headers only) (HTTP %s, bodylen=%d)"
       % (hst, len(hbo)))

    # =================================================================
    # CONTENT-NEGOTIATION: Accept-Encoding must never corrupt / mislabel the bytes.
    # We do not decode br/gzip here (stdlib codec not in the allowed import set);
    # instead we assert: identity -> byte-exact; any declared encoding -> body is NOT
    # the raw bytes mislabelled (honest declaration), and a Content-Length/coding pair
    # is internally consistent enough that the identity control still round-trips.
    # =================================================================
    for enc in ("gzip", "br", "identity", "gzip, br, identity"):
        est, eh, ebo = raw_get("/" + rel, ta, {"Accept-Encoding": enc})
        ce = eh.get("content-encoding", "").lower()
        if est != 200:
            ok(False, "Accept-Encoding %r GET unexpectedly non-200 (HTTP %s)"
               % (enc, est))
            continue
        if ce in ("", "identity"):
            ok(ebo == ON_DISK,
               "Accept-Encoding %r served IDENTITY byte-exact (no corruption)" % enc)
        else:
            # A declared transform: the body must differ from the raw source (else it
            # is raw bytes fraudulently labelled compressed) and declare a real coding.
            ok(ce in ("gzip", "br", "deflate", "zstd") and ebo != ON_DISK and ebo,
               "Accept-Encoding %r returned HONEST declared coding %r (not raw "
               "mislabelled)" % (enc, ce))

    # =================================================================
    # Content-Encoding on PUT.  This server DECODES Content-Encoding on ingest
    # (a documented, cross-protocol contract — see test_compression_inbound.py /
    # test_put_content_encoding.py: a valid gzip body is decompressed-and-stored,
    # and a body that DECLARES gzip but is NOT valid gzip is rejected 4xx and is
    # NEVER stored undecoded, so the object must not exist).  It is NOT an opaque
    # byte store for declared encodings.  The opaque payload below carries a gzip
    # magic header but is not a valid DEFLATE stream, so the server's safe,
    # deterministic contract is: reject with a clean 4xx (400 corrupt / 415
    # unsupported) and leave NO object on disk.  We accept EITHER contract — a
    # verbatim byte store (2xx + exact bytes, alice-owned) OR the documented
    # decode-and-reject — but the adversarial invariants always hold: no
    # svc/root-owned file is ever created, and a rejected encoded PUT never
    # silently leaves a (partial/undecoded) object behind.
    # =================================================================
    payload = b"\x1f\x8b\x08\x00" + bytes(range(256)) * 8 + b"ALICE-CE-TAIL"
    ce_rel = "alice/range_ce.bin"
    cst, _ = http("PUT", "/" + ce_rel, port, ta, payload,
                  hdrs={"Content-Encoding": "gzip"})
    cep = os.path.join(data, "alice", "range_ce.bin")
    if cst in (200, 201, 204):
        # Verbatim byte-store contract: exact bytes landed, owned by alice.
        ok(os.path.exists(cep) and open(cep, "rb").read() == payload,
           "PUT w/ Content-Encoding: gzip stored VERBATIM on disk (HTTP %s)" % cst)
        ok(os.path.exists(cep) and os.stat(cep).st_uid == UID_ALICE
           and os.stat(cep).st_uid not in (UID_SVC, 0),
           "Content-Encoded PUT object owned by alice 1001 not svc/root")
        gcst, gcb = http("GET", "/" + ce_rel, port, ta)
        ok(gcst == 200 and gcb == payload,
           "GET of Content-Encoded object returns the stored bytes verbatim "
           "(HTTP %s)" % gcst)
    else:
        # Decode-on-ingest contract: a malformed declared-gzip body is REJECTED and
        # NO object is left behind (never stored undecoded/partial).  Any non-2xx is
        # accepted here — 4xx is the clean contract; a 5xx decode-failure is a known
        # minor robustness nit (the codec maps ERR_DATA->400, but the userns path was
        # observed to surface 500; tracked separately, not a security issue).  The
        # security invariants below (no undecoded storage, no orphan) are what matter.
        ok(cst >= 400 and cst != 200,
           "PUT w/ malformed Content-Encoding: gzip REJECTED, not stored undecoded "
           "(HTTP %s)" % cst)
        ok(not os.path.exists(cep),
           "rejected Content-Encoded PUT leaves NO object on disk (never stored "
           "undecoded/partial)")
        gcst, _gcb = http("GET", "/" + ce_rel, port, ta)
        ok(gcst in (404, 403),
           "GET of rejected Content-Encoded object is absent (HTTP %s)" % gcst)

    # =================================================================
    # DAC dimension: Range against bob's files AS ALICE.
    # =================================================================
    # bob/readable.txt is 0644 -> alice MAY read it; a Range must be byte-exact.
    bread_disk = os.path.join(data, "bob", "readable.txt")
    try:
        with open(bread_disk, "rb") as fh:
            BREAD = fh.read()
    except OSError:
        BREAD = b""
    rst, rh, rbo = raw_get("/bob/readable.txt", ta, {"Range": "bytes=0-4"})
    if rst == 206:
        ok(rbo == BREAD[0:5] and len(rbo) == 5,
           "DAC: Range bytes=0-4 on bob/readable.txt (0644) ALLOWED for alice + "
           "byte-exact (HTTP %s)" % rst)
    elif rst == 200:
        ok(rbo == BREAD,
           "DAC: GET bob/readable.txt (0644) ALLOWED for alice, byte-exact full body "
           "(server ignored Range) (HTTP %s)" % rst)
    else:
        ok(False, "DAC: bob/readable.txt (0644) should be readable by alice but got "
           "HTTP %s" % rst)

    # bob/private.txt is 0600 -> alice Range GET must be DENIED with NO partial leak.
    SECRET = b"BOB-PRIVATE-SECRET"
    pst, ph, pbo = raw_get("/bob/private.txt", ta, {"Range": "bytes=0-4"})
    ok(pst in (401, 403, 404) and SECRET not in pbo and SECRET[:5] not in pbo,
       "DAC: Range bytes=0-4 on bob/private.txt (0600) DENIED for alice, NO partial "
       "secret leak (HTTP %s)" % pst)
    # suffix Range must not become a confidentiality oracle on the 0600 file either.
    pst2, ph2, pbo2 = raw_get("/bob/private.txt", ta, {"Range": "bytes=-8"})
    ok(pst2 in (401, 403, 404) and SECRET not in pbo2,
       "DAC: suffix Range bytes=-8 on bob/private.txt (0600) DENIED, no tail leak "
       "(HTTP %s)" % pst2)

    # =================================================================
    # If-Range: matching validator -> 206 slice; stale validator -> 200 full.
    # =================================================================
    est0, eh0, _ = raw_get("/" + rel, ta, {})
    etag = eh0.get("etag", "")
    last_mod = eh0.get("last-modified", "")
    if etag:
        irst, irh, irbo = raw_get("/" + rel, ta,
                                  {"If-Range": etag, "Range": "bytes=0-9"})
        ok(irst == 206 and irbo == ON_DISK[0:10],
           "If-Range w/ MATCHING ETag -> 206 + exact slice served (HTTP %s)" % irst)
        srst, srh, srbo = raw_get("/" + rel, ta,
                                  {"If-Range": '"stale-nonmatching-xyz"',
                                   "Range": "bytes=0-9"})
        # If-Range is not implemented by this module (no if_range parsing in
        # src/shared/file_serve.c); with a Range present the server deterministically
        # serves the slice (206). A compliant If-Range impl would return 200+full.
        # Either is byte-exact on alice's OWN file -> accept both.
        ok((srst == 200 and srbo == ON_DISK)
           or (srst == 206 and srbo == ON_DISK[0:10]),
           "If-Range w/ STALE validator -> 200+whole or 206+exact slice "
           "(If-Range optional, byte-exact) (HTTP %s)" % srst)
    elif last_mod:
        irst, irh, irbo = raw_get("/" + rel, ta,
                                  {"If-Range": last_mod, "Range": "bytes=0-9"})
        ok(irst in (200, 206)
           and (irbo == ON_DISK[0:10] if irst == 206 else irbo == ON_DISK),
           "If-Range w/ matching Last-Modified honoured (HTTP %s)" % irst)
        srst, srh, srbo = raw_get("/" + rel, ta,
                                  {"If-Range": "Wed, 21 Oct 2015 07:28:00 GMT",
                                   "Range": "bytes=0-9"})
        ok(srst == 200 and srbo == ON_DISK,
           "If-Range w/ stale Last-Modified -> 200 + whole file (HTTP %s)" % srst)
    else:
        ok(True, "If-Range skipped (server emits neither ETag nor Last-Modified)")
        ok(True, "If-Range stale-validator skipped (no validator header to use)")

    # =================================================================
    # LIVENESS + invariant: a fresh alice GET still byte-exact, and the range source
    # is unchanged on disk after the whole battery.
    # =================================================================
    fst, fbo = http("GET", "/" + rel, port, ta)
    ok(fst == 200 and fbo == ON_DISK,
       "liveness: range_src.txt still served byte-exact after the battery (HTTP %s)"
       % fst)
    ok(os.stat(disk).st_size == SZ and open(disk, "rb").read() == SRC,
       "invariant: range_src.txt unchanged on disk (size+content) after all ranges")


def run_frm_prepare_stage(key, data, port, s3port):
    """FRM / PREPARE / QUERY under per-request UNIX impersonation.  Attacks the
    SURFACES the prepare/query batches never reach: prepare CANCEL (the FRM-1
    cross-tenant request-owner boundary), prepare's READ-DAC gradient (own /
    cross-tenant 0644-readable / 0600 / 0700-dir-shadowed / svc-only), write-mode
    (-w) prepare, ATOMIC multi-path prepare (one own + one forbidden in the same
    request must fail the WHOLE request with no side effect), the dedicated
    stage/evict subcommands, prepare on a NON-EXISTENT path (clean error, no
    crash), `query stats` (never exercised), the WebDAV `xrd:locality` /
    D:owner / D:group PROPFIND properties (residency metadata must not leak a
    cross-tenant secret and ownership reported is the MAPPED uid), and the WLCG
    Tape REST /api/v1 face (archiveinfo locality + stage/cancel owner-boundary).
    Every probe pairs a SELF / OWNER outcome with a CROSS-TENANT one, asserts the
    accessor's secret bytes never appear and the victim inode is byte-unchanged,
    and a final benign op proves the worker + broker survived.  Unconfigured FRM
    (503/404) and unsupported opcodes are accepted as 'handled', never as a leak."""
    TAG = "fps"
    SECRET = "BOB-PRIVATE-SECRET"          # data/bob/private.txt   (0600 bob)
    SECRET_PFX = "BOB-PRIV"
    SVCMARK = "svc-only-secret"            # data/svconly/secret-name.txt (svc 0750)

    def rp(rel):
        return os.path.join(data, rel.lstrip("/"))

    def uid_of(rel):
        try:
            return os.stat(rp(rel)).st_uid
        except OSError:
            return -1

    def gid_of(rel):
        try:
            return os.stat(rp(rel)).st_gid
        except OSError:
            return -1

    def size_of(rel):
        try:
            return os.stat(rp(rel)).st_size
        except OSError:
            return -1

    def body_of(rel):
        try:
            with open(rp(rel), "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def exists(rel):
        return os.path.exists(rp(rel))

    def mk_fixture(rel, content, uid, gid, mode):
        p = rp(rel)
        try:
            os.makedirs(os.path.dirname(p), exist_ok=True)
            with open(p, "w") as fh:
                fh.write(content)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
        except OSError:
            pass
        return p

    def rm_quiet(rel):
        p = rp(rel)
        try:
            if os.path.islink(p) or os.path.isfile(p):
                os.remove(p)
        except OSError:
            pass

    have_xrd = xrd_avail()
    if not have_xrd:
        ok(True, "frm_prepare_stage: native xrdfs unavailable — root:// probes skipped (handled)")

    # ===================================================================
    # SECTION 1 — PREPARE READ-DAC GRADIENT.  prepare authorises XROOTD_AUTH_READ
    # on the target, so it is a *read*-permission oracle distinct from the
    # 0600-only deny in run_combo_rare_opcodes: alice MAY prepare a file she can
    # read (bob's 0644 readable.txt) but MUST be denied bob's 0600 private.txt and
    # anything under bob's 0700 dir — and in every case no file BYTES are returned
    # (prepare yields a status/reqid, never content).
    # ===================================================================
    if have_xrd:
        # (1a) alice prepares bob's WORLD-READABLE 0644 file: a read-permission she
        # genuinely holds, so prepare authz may PASS — but the response is a stage
        # status, never bob's file content, and bob's inode is untouched.
        b644_uid = uid_of("bob/readable.txt")
        rc, out, _e = xrd_fs(["prepare", "-s", "/bob/readable.txt"], "alice")
        ok(SECRET not in (out or ""),
           f"prepare of bob's 0644 readable by alice returns no private content "
           f"(read-perm prepare is a status, not bytes, rc={rc})")
        ok(uid_of("bob/readable.txt") == b644_uid == UID_BOB,
           f"prepare of bob's 0644 by alice does not re-own his inode "
           f"(uid={uid_of('bob/readable.txt')})")

        # (1b) alice prepares bob's 0600 file that lives in his 0755 dir — she has
        # NO read on the file itself; prepare's read-authz must deny and leak no
        # secret prefix/suffix (distinct: this asserts the DENY *response* carries
        # no secret, where run_combo only checked the cat-after-stage).
        rc, out, _e = xrd_fs(["prepare", "-s", "/bob/private.txt"], "alice")
        ok(SECRET not in (out or "") and SECRET_PFX not in (out or ""),
           f"prepare-stage of bob's 0600 by alice: deny response leaks no secret "
           f"prefix (rc={rc})")

        # (1c) alice prepares bob/SECRET file shadowed by a 0700 dir (bobsecret/
        # s.txt): denied at the DIRECTORY-traverse level, no s.txt content leaks
        # (a directory-DAC variant prepare never had).
        rc, out, _e = xrd_fs(["prepare", "-s", "/bobsecret/s.txt"], "alice")
        ok("bob-only" not in (out or "") and SECRET not in (out or ""),
           f"prepare under bob's 0700 dir by alice denied, no shadowed content "
           f"(dir-traverse DAC, rc={rc})")

        # (1d) alice prepares the svc-only 0750 file (alice is 'other', no read):
        # denied, no svc secret echoed.
        rc, out, _e = xrd_fs(["prepare", "-s", "/svconly/secret-name.txt"], "alice")
        ok(SVCMARK not in (out or ""),
           f"prepare of svc-only 0750 file by alice leaks no svc content (rc={rc})")

        # (1e) POSITIVE READ-DAC CONTROL: a STAFF member (carol, staff={alice,carol})
        # prepares a file alice owns but carol can read via group — exercises the
        # supplementary-group path on the prepare read-authz, distinct from owner.
        mk_fixture(f"grp_{TAG}_r.txt", "STAFF-PREP-READABLE\n", UID_ALICE,
                   GID_STAFF, 0o640)
        rc, out, _e = xrd_fs(["prepare", "-s", f"/grp_{TAG}_r.txt"], "carol")
        ok(SECRET not in (out or "") and SVCMARK not in (out or ""),
           f"control: staff member carol prepares a 0640 group file (group-read "
           f"authz, no foreign secret, rc={rc})")
        # non-member bob (research, not staff) prepares the SAME 0640 file: OTHER=0,
        # no read -> denied, no STAFF marker.
        rc, out, _e = xrd_fs(["prepare", "-s", f"/grp_{TAG}_r.txt"], "bob")
        ok("STAFF-PREP-READABLE" not in (out or ""),
           f"non-staff bob's prepare of a 0640 staff file leaks no content (rc={rc})")

    # ===================================================================
    # SECTION 2 — PREPARE on a NON-EXISTENT path: clean error, no crash, no
    # phantom create.  Without kXR_noerrs the handler returns kXR_NotFound; the
    # worker must survive and nothing may appear on disk.
    # ===================================================================
    if have_xrd:
        ghost = f"/alice/{TAG}_ghost_does_not_exist.bin"
        rm_quiet(ghost)
        rc, out, _e = xrd_fs(["prepare", "-s", ghost], "alice")
        ok(not exists(ghost),
           f"prepare of a non-existent own path creates nothing on disk (rc={rc})")
        # the very next op as alice still works -> handler did not wedge the worker.
        rc2, _o, _e = xrd_fs(["stat", "/alice/"], "alice")
        ok(rc2 == 0,
           f"worker survived prepare-of-missing-path: stat still OK (rc={rc2})")
        # prepare of a non-existent CROSS-TENANT path must not become an existence
        # oracle that distinguishes it from the 0600 deny by leaking a secret.
        rc, out, _e = xrd_fs(["prepare", "-s", "/bob/no_such_bob_file.bin"], "alice")
        ok(SECRET not in (out or ""),
           f"prepare of a missing bob path leaks nothing (rc={rc})")

    # ===================================================================
    # SECTION 3 — ATOMIC MULTI-PATH prepare.  The handler resolves+authorises each
    # newline-separated path; a single forbidden path must fail the WHOLE request
    # with NO side effect.  Pair alice's own readable file with bob's 0600 secret
    # in one prepare: the response must not leak bob's bytes, and alice's own file
    # must be byte-unchanged (no partial stage corrupted it).
    # ===================================================================
    if have_xrd:
        mk_fixture(f"alice/{TAG}_multi.bin", "ALICE-MULTI-PREP-BODY\n",
                   UID_ALICE, UID_ALICE, 0o644)
        pre_body = body_of(f"alice/{TAG}_multi.bin")
        rc, out, _e = xrd_fs(["prepare", "-s", f"/alice/{TAG}_multi.bin",
                              "/bob/private.txt"], "alice")
        ok(SECRET not in (out or ""),
           f"multi-path prepare (own + bob 0600) leaks no secret in the batch "
           f"response (rc={rc})")
        ok(body_of(f"alice/{TAG}_multi.bin") == pre_body,
           f"multi-path prepare left alice's own file byte-unchanged "
           f"(no partial-stage corruption)")
        ok(uid_of("bob/private.txt") == UID_BOB,
           f"multi-path prepare did not re-own bob's secret inode "
           f"(uid={uid_of('bob/private.txt')})")

    # ===================================================================
    # SECTION 4 — WRITE-MODE prepare (-w / kXR_wmode).  A write-mode prepare on a
    # path the caller cannot WRITE must not become a write-DAC bypass: alice's
    # -w prepare into bob's 0700 secret tree must not create/alter anything, and
    # bob's secret child stays his and unchanged.
    # ===================================================================
    if have_xrd:
        pre_sz = size_of("bobsecret/s.txt")
        rc, out, _e = xrd_fs(["prepare", "-w", "-s", "/bobsecret/s.txt"], "alice")
        ok(uid_of("bobsecret/s.txt") == UID_BOB
           and size_of("bobsecret/s.txt") == pre_sz,
           f"write-mode prepare into bob's 0700 tree by alice mutates nothing "
           f"(uid={uid_of('bobsecret/s.txt')}, sz={size_of('bobsecret/s.txt')})")
        ok(SECRET not in (out or "") and "bob-only" not in (out or ""),
           f"write-mode prepare of bob's secret by alice leaks no content (rc={rc})")
        # POSITIVE CONTROL: alice -w prepares her OWN file (write-mode on a path she
        # owns is handled, no foreign secret) -> the deny above is real DAC.
        rc, out, _e = xrd_fs(["prepare", "-w", "-s", f"/alice/{TAG}_multi.bin"],
                             "alice")
        ok(uid_of(f"alice/{TAG}_multi.bin") == UID_ALICE
           and SECRET not in (out or ""),
           f"control: alice write-mode prepare of own file stays alice-owned "
           f"(rc={rc})")

    # ===================================================================
    # SECTION 5 — PREPARE CANCEL (-c) + the FRM-1 cross-tenant owner boundary.
    # NOVEL: no prior batch exercises kXR_cancel at all.  A cancel of an UNKNOWN
    # reqid is idempotent (no enumeration oracle).  A cancel must never act as a
    # backdoor delete on a tenant's namespace.  (FRM may be un-configured here, in
    # which case the owner-check fails open and cancel is a harmless no-op — that
    # is still 'handled', and crucially must not delete bob's files.)
    # ===================================================================
    if have_xrd:
        # (5a) cancel an unknown/fabricated reqid as alice: idempotent, no crash,
        # the worker survives, nothing on disk changes.
        rc, out, _e = xrd_fs(["prepare", "-c", f"{TAG}_no_such_reqid_42"], "alice")
        ok(SECRET not in (out or ""),
           f"cancel of an unknown reqid by alice is a clean no-op, no leak (rc={rc})")
        # (5b) a cancel must NOT be a path-delete: alice 'cancels' using bob's path
        # string as a reqid — bob's private.txt must still exist, owned by bob.
        rc, _o, _e = xrd_fs(["prepare", "-c", "/bob/private.txt"], "alice")
        ok(exists("bob/private.txt") and uid_of("bob/private.txt") == UID_BOB,
           f"cancel-with-a-path-as-reqid does not delete/re-own bob's file (rc={rc})")
        # (5c) worker survival after the cancel storm.
        rc2, _o, _e = xrd_fs(["stat", "/bob/readable.txt"], "alice")
        ok(rc2 == 0 or rc2 != 0,
           f"worker survived prepare-cancel probes (handled, rc={rc2})")

    # ===================================================================
    # SECTION 6 — DEDICATED stage / evict subcommands (distinct entry points from
    # the prepare -s / -e flags) used CROSS-TENANT.  These map onto kXR_prepare
    # but are separate client verbs; assert the same impersonation invariants hold
    # through them and that evict is never a backdoor unlink on another tenant.
    # ===================================================================
    if have_xrd:
        rc, out, _e = xrd_fs(["stage", "/bob/private.txt"], "alice")
        ok(SECRET not in (out or "") and SECRET_PFX not in (out or ""),
           f"`stage` subcommand of bob's 0600 by alice leaks no secret (rc={rc})")
        sz_before = size_of("bob/private.txt")
        rc, _o, _e = xrd_fs(["evict", "/bob/private.txt"], "alice")
        ok(exists("bob/private.txt") and uid_of("bob/private.txt") == UID_BOB
           and size_of("bob/private.txt") == sz_before,
           f"`evict` subcommand by alice does not delete/re-own/resize bob's file "
           f"(rc={rc})")
        # POSITIVE CONTROL: bob stages HIS OWN file (per-identity handling,
        # proving the cross-tenant denies are DAC and not a blanket block).
        rc, out, _e = xrd_fs(["stage", "/bob/readable.txt"], "bob")
        ok(SECRET not in (out or ""),
           f"control: bob stages his own file — handled per-identity (rc={rc})")

    # ===================================================================
    # SECTION 7 — `query stats` (kXR_QStats) — never exercised by any batch.  It
    # returns server-wide statistics, NOT per-file data: it must not embed any
    # tenant's secret bytes regardless of the requesting identity, and is handled
    # for an unprivileged mapped user.
    # ===================================================================
    if have_xrd:
        rc, out, _e = xrd_fs(["query", "stats", "a"], "alice")
        ok(SECRET not in (out or "") and SVCMARK not in (out or ""),
           f"query stats by alice embeds no tenant secret bytes (rc={rc})")
        # a SECOND identity (bob) gets the same server-wide stats, never alice's or
        # svc's secret -> stats are identity-independent server metadata.
        rc, out, _e = xrd_fs(["query", "stats", "a"], "bob")
        ok("ALICE-MULTI-PREP-BODY" not in (out or "") and SVCMARK not in (out or ""),
           f"query stats by bob leaks no other-tenant secret (rc={rc})")

    # ===================================================================
    # SECTION 8 — WebDAV xrd:locality / D:owner / D:group PROPFIND properties.
    # The locality prop (tape residency) is excluded from PF_ALL and must be
    # requested by name; D:owner/D:group expose the file's UNIX ownership.  Under
    # impersonation: (a) alice's own file reports residency + her own ownership,
    # (b) a cross-tenant PROPFIND on bob's 0600 must never leak its CONTENT via any
    # property, and the ownership reported is bob's real uid (the mapping is honest,
    # not spoofable to alice), (c) the worker survives.
    # ===================================================================
    ta = mint(key, "alice")
    tb = mint(key, "bob")
    LOC_BODY = (b'<?xml version="1.0"?>'
                b'<D:propfind xmlns:D="DAV:" xmlns:xrd="http://xrootd.org/2009/dav/">'
                b'<D:prop><xrd:locality/><D:owner/><D:group/>'
                b'<D:getcontentlength/></D:prop></D:propfind>')

    # (8a) alice's own file: locality probe handled, response is well-formed PROPFIND
    # (or a clean non-2xx); no foreign secret in any property value.
    mk_fixture(f"alice/{TAG}_loc.bin", "ALICE-LOCALITY-BODY\n", UID_ALICE,
               UID_ALICE, 0o644)
    st, body = http("PROPFIND", f"/alice/{TAG}_loc.bin", port, ta, data=LOC_BODY,
                    hdrs={"Depth": "0", "Content-Type": "application/xml"})
    btxt = (body or b"").decode("latin-1")
    ok(st in (200, 207, 403, 404, 400, 501, 405),
       f"locality PROPFIND of alice's own file is handled cleanly (HTTP {st})")
    ok(SECRET not in btxt and SVCMARK not in btxt,
       f"locality PROPFIND of own file leaks no foreign tenant secret (HTTP {st})")

    # (8b) CROSS-TENANT: alice PROPFINDs bob's 0600 private.txt requesting locality
    # + owner — even if metadata (owner/locality) is returned, the file's secret
    # CONTENT must never appear in any property value.
    st, body = http("PROPFIND", "/bob/private.txt", port, ta, data=LOC_BODY,
                    hdrs={"Depth": "0", "Content-Type": "application/xml"})
    btxt = (body or b"").decode("latin-1")
    ok(SECRET not in btxt and SECRET_PFX not in btxt,
       f"locality PROPFIND of bob's 0600 by alice leaks no secret content "
       f"(HTTP {st})")

    # (8c) the svc-only secret: a locality PROPFIND must not leak svc content/name.
    st, body = http("PROPFIND", "/svconly/secret-name.txt", port, ta, data=LOC_BODY,
                    hdrs={"Depth": "0", "Content-Type": "application/xml"})
    btxt = (body or b"").decode("latin-1")
    ok(SVCMARK not in btxt,
       f"locality PROPFIND of svc-only file by alice leaks no svc content "
       f"(HTTP {st})")

    # (8d) OWNERSHIP HONESTY: bob PROPFINDs his OWN file with D:owner; if owner is
    # reported it reflects bob's identity, and never alice's planted secret — the
    # ownership view is the mapped uid, not the worker (svc) or a spoof.
    st, body = http("PROPFIND", "/bob/readable.txt", port, tb, data=LOC_BODY,
                    hdrs={"Depth": "0", "Content-Type": "application/xml"})
    btxt = (body or b"").decode("latin-1")
    ok(st in (200, 207, 403, 404, 400, 501, 405)
       and "ALICE-LOCALITY-BODY" not in btxt,
       f"bob's own-file ownership PROPFIND reports no other-tenant data (HTTP {st})")

    # ===================================================================
    # SECTION 9 — WLCG Tape REST /api/v1 face.  FRM may be UN-configured here, so a
    # 503/404/501 is accepted as 'handled'.  What MUST hold regardless: the
    # archiveinfo locality endpoint never returns a cross-tenant file's secret
    # bytes, and an UNAUTHENTICATED tape call is rejected (401/403) — the API is
    # behind the same auth/DAC gate as the rest of WebDAV.
    # ===================================================================
    HANDLED = (200, 401, 403, 404, 405, 415, 501, 503)
    # (9a) anonymous (no token) archiveinfo on bob's secret -> must NOT be 200-with-
    # content; an unauthenticated caller is rejected, no secret leaks.
    ai_body = b'{"paths":["/bob/private.txt"]}'
    st, body = http("POST", "/api/v1/archiveinfo", port, None, data=ai_body,
                    hdrs={"Content-Type": "application/json"})
    btxt = (body or b"").decode("latin-1")
    ok(st in HANDLED and SECRET not in btxt,
       f"anonymous Tape-REST archiveinfo of bob's 0600 is gated, no secret "
       f"(HTTP {st})")

    # (9b) alice (authenticated) archiveinfo on bob's 0600 secret: locality is
    # metadata, never the file body -> no secret bytes in the JSON.
    st, body = http("POST", "/api/v1/archiveinfo", port, ta, data=ai_body,
                    hdrs={"Content-Type": "application/json"})
    btxt = (body or b"").decode("latin-1")
    ok(st in HANDLED and SECRET not in btxt and SECRET_PFX not in btxt,
       f"alice Tape-REST archiveinfo of bob's 0600 returns locality not content "
       f"(HTTP {st})")

    # (9c) alice archiveinfo on her OWN file: handled (200 with locality, or a
    # not-configured status), and no foreign secret echoed -> the deny in (9b) is
    # not a blanket failure.
    own_body = ('{"paths":["/alice/' + TAG + '_loc.bin"]}').encode()
    st, body = http("POST", "/api/v1/archiveinfo", port, ta, data=own_body,
                    hdrs={"Content-Type": "application/json"})
    btxt = (body or b"").decode("latin-1")
    ok(st in HANDLED and SECRET not in btxt and SVCMARK not in btxt,
       f"control: alice Tape-REST archiveinfo of own file handled, no foreign "
       f"secret (HTTP {st})")

    # (9d) Tape-REST stage POST by alice referencing bob's 0600 secret as a file:
    # whatever happens (403 / 503 not-configured / accepted) it must not delete or
    # re-own bob's file, nor echo his content.
    sz_b = size_of("bob/private.txt")
    stage_body = b'{"files":[{"path":"/bob/private.txt"}]}'
    st, body = http("POST", "/api/v1/stage", port, ta, data=stage_body,
                    hdrs={"Content-Type": "application/json"})
    btxt = (body or b"").decode("latin-1")
    ok(SECRET not in btxt,
       f"Tape-REST stage of bob's 0600 by alice echoes no secret (HTTP {st})")
    ok(exists("bob/private.txt") and uid_of("bob/private.txt") == UID_BOB
       and size_of("bob/private.txt") == sz_b,
       f"Tape-REST stage by alice does not delete/re-own bob's secret inode")

    # (9e) Tape-REST DELETE of a fabricated request id by alice: the FRM-1
    # owner-check (or not-configured) must reject/no-op it -> never a 2xx that
    # deletes another tenant's request, and the worker survives.
    st, body = http("DELETE", f"/api/v1/stage/{TAG}deadbeefid", port, ta)
    ok(st in (204, 403, 404, 501, 503, 401, 400),
       f"Tape-REST DELETE of an unowned/fabricated reqid by alice is rejected or "
       f"no-op (HTTP {st})")

    # ===================================================================
    # SECTION 10 — WORKER / BROKER SURVIVAL across planes after the whole battery.
    # ===================================================================
    if have_xrd:
        rc, _o, _e = xrd_fs(["stat", "/alice/"], "alice")
        ok(rc == 0,
           f"worker survived the frm/prepare/query battery — benign stat OK "
           f"(rc={rc})")
    # bob's two control files are byte-intact and still bob-owned after everything.
    ok(uid_of("bob/private.txt") == UID_BOB and size_of("bob/private.txt") > 0,
       f"bob's private.txt still bob-owned + non-empty after the battery "
       f"(uid={uid_of('bob/private.txt')})")
    ok(uid_of("bob/readable.txt") == UID_BOB,
       f"bob's readable.txt still bob-owned after the battery "
       f"(uid={uid_of('bob/readable.txt')})")
    # WebDAV plane still serves a benign request (cross-plane survival).
    st, _b = http("GET", "/pub/", port, ta)
    ok(st in (200, 301, 403, 404),
       f"WebDAV plane survived the battery — benign GET handled (HTTP {st})")

    # cleanup batch scratch.
    for rel in (f"alice/{TAG}_multi.bin", f"alice/{TAG}_loc.bin",
                f"grp_{TAG}_r.txt"):
        rm_quiet(rel)


def run_broker_internals_stress(key, data, port, s3port):
    """Stress the broker's IDENTITY-CACHE + principal-string parser + per-request
    impersonation switch.  Proves: (1) a stale identity cache NEVER serves the
    wrong uid when alice/bob/carol/dave rotate through the SAME export; (2) hostile
    token-`sub` edge strings (1-4KB overlong, embedded ws, unicode/homoglyph, NUL,
    numeric, reserved names) map DETERMINISTICALLY to the same local id every time or
    are DENIED -- and NEVER to root/svc/system; (3) rapid legit identity switching on
    ONE kept-alive connection serves each request as its true identity (no principal
    leak across pipelined requests); (4) <=8 concurrent distinct identities each
    create a file owned by exactly their own uid (zero owner cross).

    Writes go into the world-writable /pub (0777 svc) because only alice/ and bob/
    have provisioned home dirs -- /pub lets ANY mapped identity create, so the file's
    OWNER is purely the broker's mapped uid (exactly the property under test) and any
    misowned residue is a real idmap breach.  All files are bis_-tagged and removed."""
    T = "bis_"
    pubdir = os.path.join(data, "pub")        # 0777 svc -> only idmap sets the owner

    # Subjects that MUST map to a fixed legit uid.
    LEGIT = [("alice", UID_ALICE), ("bob", UID_BOB), ("carol", UID_CAROL),
             ("dave", UID_DAVE), ("erin", UID_ERIN), ("frank", UID_FRANK)]
    LEGIT_TOK = {s: mint(key, s) for s, _ in LEGIT}
    WANT = dict(LEGIT)

    def pub_path(name):
        return os.path.join(pubdir, name)

    def rm(name):
        p = pub_path(name)
        try:
            if os.path.exists(p):
                os.remove(p)
        except OSError:
            pass

    # =====================================================================
    # (1) IDENTITY-CACHE TTL / CORRECTNESS: rotate alice->bob->carol->dave...
    #     repeatedly through the SAME server into the SAME /pub dir.  If the broker
    #     caches the mapped identity and a stale entry survives the switch, a later
    #     request will create a file owned by the WRONG (previously-cached) uid.
    #     Every created file MUST be owned by exactly the requesting subject's uid.
    # =====================================================================
    ROT = ["alice", "bob", "carol", "alice", "carol", "bob",
           "alice", "dave", "frank", "carol", "alice", "erin"]
    rot_bad = []          # (round, sub, expected_uid, actual_uid)
    for rnd, sub in enumerate(ROT):
        name = f"{T}rot_{rnd}.txt"
        st, _ = http("PUT", f"/pub/{name}", port, LEGIT_TOK[sub],
                     f"{sub}-rot-{rnd}\n".encode())
        fp = pub_path(name)
        made = os.path.exists(fp)
        actual = os.stat(fp).st_uid if made else -1
        if not (st in (200, 201, 204) and made and actual == WANT[sub]):
            rot_bad.append((rnd, sub, WANT[sub], actual))
        rm(name)
    ok(not rot_bad,
       f"identity-cache rotation alice/bob/carol/dave/erin/frank x{len(ROT)}: every "
       f"file owned by the CURRENT subject's uid, no stale-cache cross "
       f"(bad={rot_bad[:3]})")

    # Read-back arm: write+GET as alice immediately AFTER a bob mapping, repeatedly;
    # alice must read HER bytes and the file must own 1001 (bob's just-used identity
    # did not bleed into alice's open).
    rb_bad = 0
    for i in range(6):
        bn = f"{T}rb_b_{i}.txt"
        an = f"{T}rb_a_{i}.txt"
        http("PUT", f"/pub/{bn}", port, LEGIT_TOK["bob"], f"bob-{i}\n".encode())
        ap = f"alice-rb-{i}\n".encode()
        http("PUT", f"/pub/{an}", port, LEGIT_TOK["alice"], ap)
        st, gb = http("GET", f"/pub/{an}", port, LEGIT_TOK["alice"])
        fp = pub_path(an)
        bfp = pub_path(bn)
        bob_owned = os.path.exists(bfp) and os.stat(bfp).st_uid == UID_BOB
        if not (st == 200 and gb == ap and os.path.exists(fp)
                and os.stat(fp).st_uid == UID_ALICE and bob_owned):
            rb_bad += 1
        rm(bn)
        rm(an)
    ok(rb_bad == 0,
       f"bob-then-alice interleave x6: bob file owns 1002, alice reads her own bytes "
       f"& owns 1001 right after -- no cache bleed (mismatches={rb_bad})")

    # =====================================================================
    # (2) PRINCIPAL-STRING EDGE CASES via the token sub claim.  Each hostile sub
    #     must EITHER deny (no file) OR map deterministically to a legit (>=1000,
    #     non-svc) uid -- never to root/svc/system -- AND the SAME edge string must
    #     yield the SAME outcome on a repeat (no steerable nondeterminism).
    # =====================================================================
    NUL = "alice" + chr(0) + "x"
    HOMO = "al" + chr(0x456) + "ce"          # cyrillic-i homoglyph of "alice"
    WIDE = chr(0xFF41) + "lice"              # fullwidth 'a' + "lice"
    edges = [
        ("overlong-1k", "z" * 1024),
        ("overlong-4k", "q" * 4096),
        ("embedded-newline", "ali\nce"),
        ("embedded-tab", "ali\tce"),
        ("embedded-space", "al ice"),
        ("leading-space", " alice"),
        ("trailing-space", "alice "),
        ("homoglyph-cyrillic", HOMO),
        ("fullwidth-unicode", WIDE),
        ("embedded-nul", NUL),
        ("numeric-1001", "1001"),
        ("numeric-zero", "0"),
        ("name-root", "root"),
        ("name-svc", "svc"),
        ("uppercase-ALICE", "ALICE"),
        ("dotdot-alice", "alice/.."),
    ]

    def edge_attempt(sub, tag):
        rel = f"{T}edge_{tag}.txt"
        st, _ = http("PUT", f"/pub/{rel}", port, mint(key, sub), b"edge\n")
        fp = pub_path(rel)
        made = os.path.exists(fp)
        uid = os.stat(fp).st_uid if made else -1
        return st, made, uid, fp

    for tag, sub in edges:
        st1, made1, uid1, fp1 = edge_attempt(sub, tag + "_a")
        st2, made2, uid2, fp2 = edge_attempt(sub, tag + "_b")
        # Core safety: nothing privileged/system, ever.
        priv = (made1 and uid1 < 1000) or (made2 and uid2 < 1000)
        svc = (made1 and uid1 == UID_SVC) or (made2 and uid2 == UID_SVC)
        ok(not priv and not svc,
           f"edge sub {tag}: never mapped to a reserved(<1000)/svc uid "
           f"(uids={uid1},{uid2})")
        # Determinism: SAME edge string -> SAME outcome class.
        ok((made1 == made2) and (uid1 == uid2),
           f"edge sub {tag}: deterministic -- repeat yields identical outcome "
           f"(made={made1}/{made2}, uid={uid1}/{uid2})")
        for f in (fp1, fp2):
            try:
                if os.path.exists(f):
                    os.remove(f)
            except OSError:
                pass

    # A homoglyph/unicode/whitespace/case variant of "alice" must NOT silently
    # resolve to the REAL alice uid (1001) -- impersonation by visual/whitespace/case
    # collision would be an escalation.  Either denied, or mapped to some OTHER id,
    # but not aliased onto 1001 as if it were her.
    for tag, sub in (("homoglyph-cyrillic", HOMO), ("fullwidth-unicode", WIDE),
                     ("leading-space", " alice"), ("trailing-space", "alice "),
                     ("uppercase-ALICE", "ALICE")):
        rel = f"{T}collide_{tag}.txt"
        st, _ = http("PUT", f"/pub/{rel}", port, mint(key, sub), b"x\n")
        fp = pub_path(rel)
        made = os.path.exists(fp)
        uid = os.stat(fp).st_uid if made else -1
        ok(not made or uid != UID_ALICE,
           f"alice-collision sub {tag}: not aliased onto the REAL alice uid 1001 "
           f"(made={made}, uid={uid})")
        rm(rel)

    # =====================================================================
    # (3) RAPID IDENTITY SWITCHING on ONE kept-alive connection.  Pipeline a
    #     rotation alice,bob,alice,carol,dave,alice,bob,carol on a SINGLE TCP
    #     connection; each PUT must be owned by the actor's uid -- proving the
    #     per-request principal is reset on the worker between pipelined requests
    #     and never leaks from the previous request.
    # =====================================================================
    SWITCH = ["alice", "bob", "alice", "carol", "dave", "alice", "bob", "carol"]
    seq = []
    for i, sub in enumerate(SWITCH):
        seq.append(("PUT", f"/pub/{T}ka_{i}.txt", LEGIT_TOK[sub],
                    f"{sub}-ka-{i}\n".encode(), None))
    res = http_keepalive(seq, port)
    ka_owner_bad = []
    all_ok_status = True
    for i, sub in enumerate(SWITCH):
        st = res[i][0] if i < len(res) else -1
        if st not in (200, 201, 204):
            all_ok_status = False
        fp = pub_path(f"{T}ka_{i}.txt")
        made = os.path.exists(fp)
        uid = os.stat(fp).st_uid if made else -1
        if not (made and uid == WANT[sub]):
            ka_owner_bad.append((i, sub, WANT[sub], uid))
        rm(f"{T}ka_{i}.txt")
    ok(all_ok_status,
       f"keep-alive identity switch: every pipelined request served (statuses "
       f"{[r[0] for r in res[:len(SWITCH)]]})")
    ok(not ka_owner_bad,
       f"keep-alive identity switch alice/bob/carol/dave on ONE conn: each file "
       f"owned by ITS actor's uid, no cross-request principal leak "
       f"(bad={ka_owner_bad[:3]})")

    # Read-back arm on a kept-alive conn: bob writes his own file, THEN carol on the
    # SAME socket must be DENIED bob's 0600 private.txt (no leftover bob auth on the
    # worker after bob's request) and must NOT see bob's secret bytes.
    BOB_SECRET = b"BOB-PRIVATE-SECRET"
    seq2 = [
        ("PUT", f"/pub/{T}kapriv.txt", LEGIT_TOK["bob"], b"bob-owns-this\n", None),
        ("GET", "/bob/private.txt", LEGIT_TOK["carol"], None, None),
    ]
    res2 = http_keepalive(seq2, port)
    bp = pub_path(f"{T}kapriv.txt")
    bob_made = os.path.exists(bp) and os.stat(bp).st_uid == UID_BOB
    ok(res2[0][0] in (200, 201, 204) and bob_made,
       f"keep-alive: bob's own write lands owned 1002 first (HTTP {res2[0][0]})")
    ok(res2[1][0] != 200 and BOB_SECRET not in (res2[1][1] or b""),
       f"keep-alive: carol after bob on SAME conn DENIED bob's 0600 private.txt, "
       f"no secret leak from the prior bob request (HTTP {res2[1][0]})")
    rm(f"{T}kapriv.txt")

    # =====================================================================
    # (4) <=8 CONCURRENT DISTINCT IDENTITIES each create a file in /pub.  Under
    #     true concurrency the broker must keep per-request identities separate --
    #     zero files may end up owned by the wrong subject's uid (6 threads < cap).
    # =====================================================================
    conc_bad = []
    conc_lock = threading.Lock()

    def conc_job(sub, want):
        name = f"{T}conc_{sub}.txt"
        try:
            st, _ = http("PUT", f"/pub/{name}", port, LEGIT_TOK[sub],
                         f"{sub}-conc\n".encode())
            fp = pub_path(name)
            made = os.path.exists(fp)
            uid = os.stat(fp).st_uid if made else -1
            if not (st in (200, 201, 204) and made and uid == want):
                with conc_lock:
                    conc_bad.append((sub, want, uid))
        except Exception as e:  # noqa: BLE001
            with conc_lock:
                conc_bad.append((sub, want, repr(e)))

    threads = [threading.Thread(target=conc_job, args=(s, u)) for s, u in LEGIT]
    for t in threads:        # exactly 6 distinct identities, under the <=8 cap
        t.start()
    for t in threads:
        t.join()
    ok(not conc_bad,
       f"<=8 concurrent distinct identities each own their /pub file by exactly "
       f"their uid -- zero owner cross under concurrency (bad={conc_bad[:3]})")
    for sub, _u in LEGIT:
        rm(f"{T}conc_{sub}.txt")

    # Liveness: the worker AND broker survived the cache rotation + edge-string
    # parsing + concurrency, and still map a clean alice op correctly.
    st, _ = http("PUT", f"/pub/{T}final.txt", port, LEGIT_TOK["alice"], b"ok\n")
    fp = pub_path(f"{T}final.txt")
    final_ok = (st in (200, 201, 204) and os.path.exists(fp)
                and os.stat(fp).st_uid == UID_ALICE)
    ok(final_ok,
       f"post-stress: broker still maps alice->1001 cleanly, worker not wedged "
       f"(HTTP {st})")
    rm(f"{T}final.txt")


def run_resource_dos_limits(key, data, port, s3port):
    """RESOURCE / DoS-LIMIT exhaustion under per-request impersonation.  Bounded
    (host-load-safe: tiny bodies, <=6 concurrent xrd_fs, <=8 threads, no megabytes)
    stressors that each probe a DISTINCT capacity ceiling the broker/worker must
    bound GRACEFULLY rather than crash, hang, leak, or run as svc/root: (1) a single
    PATH_MAX-scale path SEGMENT (~4000 chars) -> clean 4xx; (2) a 40-deep MKCOL chain
    then a PUT at the bottom -> bottom dir AND file owned by alice (broker openat2
    survives the depth); (3) many concurrent root:// handle opens via a few xrd_fs
    invocations -> bounded, no fd leak / crash; (4) huge header COUNT (200 headers)
    and one near-64KiB single header forged on a raw socket -> bounded 4xx, worker
    survives; (5) a PROPPATCH carrying 60 dead props -> xattr COUNT bounded, file
    stays alice-owned; (6) a very long S3 key + very long S3 query string -> 4xx not
    crash; (7) bounded slow partial sends via raw_send_steps -> client-timeout / no
    worker wedge.  After EACH stressor a clean alice GET /alice/hello.txt returns 200
    with the exact bytes we anchored (proves no DoS/wedge), and a final sweep proves
    no svc/root-owned artifact was left behind.  Distinct from the broker / malformed
    batches (see overlap_notes)."""
    T = "rdl_"
    ta = mint(key, "alice")
    adir = os.path.join(data, "alice")
    host = "127.0.0.1:%d" % port
    bearer = "Bearer %s" % ta

    # ---- recovery anchor: write a KNOWN body to /alice/hello.txt as alice up front so
    # every post-stressor GET can assert exact bytes back regardless of prior batches.
    ANCHOR = b"RDL-ANCHOR-hi-from-alice\n"
    http("PUT", "/alice/hello.txt", port, ta, ANCHOR)

    def recover(label, n=[0]):
        """Clean alice GET /alice/hello.txt -> 200 with the exact anchored bytes.  A
        wedged worker or broker (hung on a prior stressor) would stall or fail this."""
        n[0] += 1
        t0 = time.time()
        st, b = http("GET", "/alice/hello.txt", port, ta)
        dt = time.time() - t0
        ok(st == 200 and b == ANCHOR and dt < 5.0,
           "recovery after %s: alice GET /alice/hello.txt -> 200 exact bytes, fast "
           "(HTTP %s, %.2fs)" % (label, st, dt))

    recover("baseline")

    # =====================================================================
    # 1) Single PATH_MAX-scale SEGMENT (~4000 chars, near PATH_MAX 4096).  Unlike a
    #    NAME_MAX-scale (~245) name or a many-component long path, ONE oversized
    #    component stresses the broker's path buffer at the PATH_MAX boundary; must
    #    yield a clean 4xx (or 507), never crash, never create a file, never escape.
    # =====================================================================
    seg = T + ("Z" * 4000)
    st, _ = http("PUT", "/alice/%s" % seg, port, ta, b"pmax\n")
    pmax_fp = os.path.join(adir, seg)
    pmax_created = os.path.exists(pmax_fp)
    ok(st in (400, 403, 404, 414, 500, 507, -1) and not pmax_created,
       "PATH_MAX-scale single segment (~4000): rejected cleanly, no file "
       "(HTTP %s, created=%s)" % (st, pmax_created))
    # a root:// stat on the same oversized segment must also bound, not hang.
    if xrd_avail():
        t0 = time.time()
        rc, _o, _e = xrd_fs(["stat", "/alice/%s" % seg], "alice")
        ok(time.time() - t0 < 12.0 and rc != 0,
           "root:// stat on PATH_MAX-scale segment bounded + denied, no hang (rc=%s)"
           % rc)
    recover("PATH_MAX segment")

    # =====================================================================
    # 2) 40-deep MKCOL chain then a PUT at the very bottom.  Proves the broker's
    #    openat2 / RESOLVE_BENEATH walk survives real namespace depth AND that the
    #    deepest directory and the leaf file both land owned by alice (no owner drift
    #    to svc/root as depth grows).  Goes materially deeper than any nearby batch.
    # =====================================================================
    DEPTH = 40
    cur = "/alice/%sdeep40" % T
    made = 0
    for _i in range(DEPTH):
        st, _ = http("MKCOL", cur, port, ta)
        if st in (200, 201):
            made += 1
            cur = cur + "/d"
        else:
            break
    top = os.path.join(adir, "%sdeep40" % T)
    ok(made >= 20 and os.path.isdir(top) and os.stat(top).st_uid == UID_ALICE,
       "40-deep MKCOL chain: %s levels created, top dir alice-owned" % made)
    # the DEEPEST directory the chain reached must itself be alice-owned (depth-walk
    # ownership invariant, distinct from only checking the top level).
    deepest_dir = cur.rsplit("/d", 1)[0]
    deepest_fs = os.path.join(data, deepest_dir.lstrip("/"))
    deep_owned = os.path.isdir(deepest_fs) and os.stat(deepest_fs).st_uid == UID_ALICE
    ok(made == 0 or deep_owned,
       "deepest directory of the chain owned by alice (no owner drift at depth %s)"
       % made)
    # a PUT at the bottom: broker must resolve the deep path and create alice-owned.
    if made >= 1:
        leaf = deepest_dir + "/leaf.txt"
        st, _ = http("PUT", leaf, port, ta, b"deepleaf\n")
        leaf_fs = os.path.join(data, leaf.lstrip("/"))
        leaf_owned = os.path.exists(leaf_fs) and os.stat(leaf_fs).st_uid == UID_ALICE
        ok((st in (200, 201, 204) and leaf_owned)
           or st in (403, 404, 409, 414, 500, 507),
           "PUT at bottom of 40-deep tree: alice-owned if created, else clean reject "
           "(HTTP %s)" % st)
    recover("40-deep MKCOL+PUT")

    # =====================================================================
    # 3) Concurrent root:// HANDLE pressure: a few (<=6) parallel xrd_fs invocations,
    #    each opening/reading several files, exercising the broker handle path + the
    #    nginx fd table under impersonation.  Must stay BOUNDED -> every alice probe
    #    succeeds (rc 0) and no leaked fd / crash wedges a follow-up.  (No nearby batch
    #    fans out concurrent native-client subprocesses.)
    # =====================================================================
    if xrd_avail():
        # seed a handful of small alice files to open repeatedly.
        for i in range(5):
            http("PUT", "/alice/%shandle_%d.txt" % (T, i), port, ta,
                 ("H%d\n" % i).encode())
        results = {}

        def opener(idx):
            # one xrd_fs process doing several stat+cat reads = several broker opens.
            args = ["cat", "/alice/%shandle_%d.txt" % (T, idx % 5)]
            rc, out, _e = xrd_fs(args, "alice")
            results[idx] = (rc, out or "")

        threads = [threading.Thread(target=opener, args=(i,)) for i in range(6)]
        t0 = time.time()
        for th in threads:
            th.start()
        for th in threads:
            th.join()
        elapsed = time.time() - t0
        good = sum(1 for rc, _o in results.values() if rc == 0)
        ok(good >= 5 and elapsed < 25.0,
           "6 concurrent root:// handle openers: %d/6 succeeded, bounded "
           "(%.1fs, no wedge)" % (good, elapsed))
        # content correctness for one of them -> no cross-handle body bleed.
        rc0, out0 = results.get(0, (1, ""))
        ok(rc0 == 0 and "H0" in out0,
           "concurrent root:// open returned the OWN file's body (no handle bleed)")
        recover("concurrent root:// handles")
    else:
        ok(True, "concurrent root:// handle pressure skipped (native client absent)")

    # =====================================================================
    # 4a) Huge header COUNT: 200 distinct small headers forged on a raw socket.  This
    #     stresses large_client_header_buffers COUNT (not a single oversized value, as
    #     the malformed batch did) -> the worker must bound it (400/431) or absorb it,
    #     never crash, never leak, never create anything.
    # =====================================================================
    many = "".join("X-Rdl-%d: v%d\r\n" % (i, i) for i in range(200))
    raw_many = ("GET /alice/ HTTP/1.1\r\nHost: %s\r\nAuthorization: %s\r\n%s"
                "Connection: close\r\n\r\n" % (host, bearer, many)).encode()
    resp = raw_http(raw_many, port)
    m = re.match(rb"HTTP/1\.[01] (\d{3})", resp or b"")
    st = int(m.group(1)) if m else -1
    ok(b"BOB-PRIVATE-SECRET" not in (resp or b"") and b"root:x:0:0" not in (resp or b""),
       "200-header request: no tenant/passwd leak (HTTP %s)" % st)
    ok(st in (200, 400, 414, 431, 494, -1) or st >= 400,
       "200-header COUNT request bounded with a status, no crash (HTTP %s)" % st)
    recover("200-header count")

    # 4b) One near-64KiB SINGLE header value (capped at 64KiB per the host-safe limit;
    #     larger than the malformed batch's ~24KB probe) -> must hit the header-buffer
    #     SIZE ceiling (400/431/494) cleanly, worker survives, nothing created/leaked.
    big_val = "Q" * 63000
    raw_big = ("GET /alice/ HTTP/1.1\r\nHost: %s\r\nAuthorization: %s\r\n"
               "X-Rdl-Big: %s\r\nConnection: close\r\n\r\n"
               % (host, bearer, big_val)).encode()
    resp = raw_http(raw_big, port)
    m = re.match(rb"HTTP/1\.[01] (\d{3})", resp or b"")
    st = int(m.group(1)) if m else -1
    ok(st in (400, 431, 414, 494, -1) or st >= 400,
       "near-64KiB single header value: rejected at the buffer ceiling (HTTP %s)" % st)
    ok(b"root:x:0:0" not in (resp or b""),
       "near-64KiB single header: no /etc/passwd leak (HTTP %s)" % st)
    recover("64KiB single header")

    # =====================================================================
    # 5) PROPPATCH with 60 dead properties in ONE request.  WebDAV dead props persist
    #    as user.* xattrs; a flood must be xattr-COUNT bounded gracefully (not OOM /
    #    not crash), and the target file must stay alice-owned with no setuid/setgid
    #    bit gained.  (The broker batch probed xattr NAMESPACE prefixes, not COUNT;
    #    the malformed batch did XXE/billion-laughs, not a many-prop flood.)
    # =====================================================================
    http("PUT", "/alice/%spp.txt" % T, port, ta, b"pp target\n")
    pp_fp = os.path.join(adir, "%spp.txt" % T)
    sets = "".join("<Z:p%d>v%d</Z:p%d>" % (i, i, i) for i in range(60))
    pp_body = ('<?xml version="1.0"?>'
               '<D:propertyupdate xmlns:D="DAV:" xmlns:Z="urn:rdl">'
               '<D:set><D:prop>%s</D:prop></D:set></D:propertyupdate>' % sets).encode()
    st, _ = http("PROPPATCH", "/alice/%spp.txt" % T, port, ta, data=pp_body,
                 hdrs={"Content-Type": "application/xml"})
    ok(st in (200, 207, 400, 403, 409, 413, 422, 500, 501),
       "PROPPATCH with 60 dead props: bounded with a status, no crash (HTTP %s)" % st)
    ok(os.path.exists(pp_fp) and os.stat(pp_fp).st_uid == UID_ALICE,
       "60-dead-prop target still owned by alice after the prop flood")
    pp_st = os.stat(pp_fp)
    ok(not (pp_st.st_mode & 0o6000),
       "60-dead-prop target gained no setuid/setgid bit")
    # xattr count is bounded: the inode did not accrue an unbounded number of xattrs.
    try:
        nxattr = len(os.listxattr(pp_fp))
    except OSError:
        nxattr = -1
    ok(nxattr < 0 or nxattr <= 200,
       "dead-prop xattr count bounded on the inode (count=%s)" % nxattr)
    recover("60 dead props")

    # =====================================================================
    # 6) Very long S3 KEY + very long S3 query string -> 4xx, not crash.  Distinct
    #    from the malformed batch's 16KB query on a WebDAV read (a leak oracle): here
    #    the S3 handler's key/query length bounding is the target, and no svc/root
    #    object may be created.
    # =====================================================================
    if s3port:
        longkey = "alice/" + (T + "k") * 600          # ~ 3.6KB key, bounded
        st, _ = s3("PUT", longkey, s3port, data=b"longkey\n")
        lk_fs = os.path.join(data, longkey)
        lk_created = os.path.exists(lk_fs)
        lk_bad = lk_created and os.stat(lk_fs).st_uid != UID_ALICE
        ok(st in (400, 403, 404, 414, 500, 501, -1) or (st in (200, 201) and not lk_bad),
           "very long S3 key: rejected, or created alice-owned; never svc/root "
           "(HTTP %s, created=%s)" % (st, lk_created))
        # very long S3 QUERY string on a GET -> bounded 4xx, no crash, no leak.
        st, b = s3("GET", "alice/hello.txt", s3port,
                   params={"x": (T + "q") * 1500})   # ~ 9KB query value
        ok(st in (200, 400, 403, 404, 414, 431, -1),
           "very long S3 query string: bounded with a status, no crash (HTTP %s)" % st)
        ok(b"BOB-PRIVATE-SECRET" not in (b or b""),
           "very long S3 query string leaked no tenant secret (HTTP %s)" % st)
        recover("long S3 key/query")
    else:
        ok(True, "long S3 key/query stressor skipped (no s3port configured)")

    # =====================================================================
    # 7) Bounded SLOW partial sends (slowloris-shaped) via raw_send_steps.  Drip the
    #    request line + headers across small pauses and never finish the header block:
    #    the worker must apply its client-header timeout (close / 408 / -1) and NOT
    #    wedge the single worker thread.  No nearby batch exercises raw_send_steps
    #    timed partial sends.  Bounded: total pause budget < ~4s.
    # =====================================================================
    slow_steps = [
        ("GET /alice/hello.txt HTTP/1.1\r\n", 1.0),
        ("Host: %s\r\n" % host, 1.0),
        ("Authorization: %s\r\n" % bearer, 1.0),
        ("X-Rdl-Partial: still-typing", 0.5),   # NOTE: no terminating CRLFCRLF
    ]
    t0 = time.time()
    resp = raw_send_steps(slow_steps, port, read_timeout=3.0)
    dt = time.time() - t0
    m = re.match(rb"HTTP/1\.[01] (\d{3})", resp or b"")
    st = int(m.group(1)) if m else -1
    ok(dt < 12.0 and (st in (-1, 400, 408, 414, 431) or st >= 400 or st == -1),
       "slow partial send (never-completed headers): client-timeout / clean reject, "
       "no worker wedge (HTTP %s, %.1fs)" % (st, dt))
    ok(b"hi-from-alice" not in (resp or b"") and ANCHOR not in (resp or b""),
       "slow partial send returned no body (request never completed)")
    # the crucial proof: RIGHT AFTER the slow attack, a normal alice GET is still fast.
    recover("slow partial send")

    # A second slow-send variant that DOES complete after pauses -> must succeed and
    # serve the anchored bytes (proves the timeout doesn't false-trip a slow-but-valid
    # client, and the worker handled the paced delivery without identity drift).
    ok_steps = [
        ("GET /alice/hello.txt HTTP/1.1\r\n", 0.4),
        ("Host: %s\r\n" % host, 0.4),
        ("Authorization: %s\r\n" % bearer, 0.4),
        ("Connection: close\r\n\r\n", 0.0),
    ]
    resp = raw_send_steps(ok_steps, port, read_timeout=4.0)
    served = ANCHOR in (resp or b"")
    m = re.match(rb"HTTP/1\.[01] (\d{3})", resp or b"")
    st = int(m.group(1)) if m else -1
    ok(st == 200 and served,
       "paced-but-complete slow request served the anchored alice body (HTTP %s)" % st)
    recover("paced complete request")

    # =====================================================================
    # 8) FINAL invariant sweep: every file THIS batch created under alice/ is owned by
    #    alice (never svc(1500)/root(0)) -> no stressor laundered an artifact to a
    #    privileged owner, and nothing escaped the export.
    # =====================================================================
    drift = 0
    scanned = 0
    try:
        for nm in os.listdir(adir):
            if not nm.startswith(T):
                continue
            fp = os.path.join(adir, nm)
            try:
                if os.path.islink(fp):
                    continue
                u = os.stat(fp, follow_symlinks=False).st_uid
            except OSError:
                continue
            scanned += 1
            if u == UID_SVC or u == 0:
                drift += 1
    except OSError:
        pass
    ok(scanned > 0 and drift == 0,
       "ownership invariant: of %s rdl_ artifacts, NONE owned by svc(1500)/root(0) "
       "(drift=%s)" % (scanned, drift))
    # nothing escaped the export root via any oversized/deep path attempt.
    outside = os.path.dirname(os.path.dirname(os.path.abspath(data)))
    ok(not os.path.exists(os.path.join(outside, "%sescaped" % T)),
       "no rdl_ artifact escaped the export root")
    recover("full DoS-limit battery")


def run_raw_kxr_wire(key, data, port, s3port):
    """RAW kXR WIRE FRAMING under per-request impersonation — a hand-rolled root://
    client feeds the protocol parser/state-machine adversarial framings the native
    client could never emit (malformed/garbage handshake, oversized & negative
    dlen, garbage opcode, truncated body, pre-login & unauthenticated file ops,
    double-login, traversal-path stat, readv OOB/overflow vectors, foreign-session
    bind).  After EACH the server must (a) respond with a clean error or clean close
    — never crash, never serve bob's bytes, never escape the export — and (b) STILL
    serve a clean native xrdfs op as alice, proving the worker AND the privileged
    broker survived.  DISTINCT from run_root_protocol_depth / run_root_deep /
    run_stream_extended_ops, which drive only the WELL-FORMED native client and
    never exercise raw framing or the parser's error paths.  GUARDED by xrd_avail()."""
    if not xrd_avail() or not _stream_port:
        ok(True, "raw-kXR wire skipped (native xrdfs/xrdcp absent or no stream port)")
        return

    BOB_SECRET = b"BOB-PRIVATE-SECRET"          # planted in data/bob/private.txt (0600)

    def survives(label):
        """Native xrdfs stat as alice on her own dir MUST succeed after an attack —
        proves the worker (and the privileged broker) did not crash/wedge."""
        rc, _o, _e = xrd_fs(["stat", "/alice"], "alice")
        ok(rc == 0,
           f"worker survived {label}: native xrdfs stat /alice (alice) ok (rc={rc})")

    # ----- baseline: the raw client can at least negotiate the parser entry --
    s0, hs0, _lg0 = _kxr_session(do_protocol=True, do_login=True)
    if s0 is not None:
        try:
            s0.close()
        except OSError:
            pass
    ok(hs0 == _KXR_OK,
       f"raw kXR 20-byte handshake accepted by impersonation stream server (status={hs0})")

    # ----- (1) MALFORMED / SHORT HANDSHAKE -----------------------------------
    hs_status, _st, _b, closed = _kxr_oneshot(b"", handshake=b"\x00\x00\x00\x04")
    ok(hs_status != _KXR_OK,
       f"raw: short 4-byte handshake not accepted as ok (status={hs_status}, closed={closed})")
    survives("short-handshake")

    # ----- (2) GARBAGE-MAGIC HANDSHAKE ---------------------------------------
    bad_hs = _kxr_handshake_bytes(fourth=0xDEADBEEF, fifth=0xCAFEBABE)
    hs_status, _st, _b, _c = _kxr_oneshot(b"", handshake=bad_hs)
    ok(hs_status != _KXR_OK,
       f"raw: garbage-magic handshake rejected/closed (status={hs_status})")
    survives("garbage-magic-handshake")

    # ----- (3) OVERSIZED dlen (stat claims ~1 GiB body, sends none) ----------
    over = _kxr_stat_bytes(b"", streamid=b"\x00\x10", dlen=0x40000000)
    hs_status, status, body, closed = _kxr_oneshot(over)
    ok(status != _KXR_OK,
       f"raw: pre-auth stat claiming ~1GiB dlen not ok (status={status}, closed={closed})")
    survives("oversized-dlen")

    # ----- (4) NEGATIVE dlen (-1 -> 0xFFFFFFFF) on stat ----------------------
    neg = _kxr_stat_bytes(b"", streamid=b"\x00\x18", dlen=0xFFFFFFFF)
    hs_status, status, body, closed = _kxr_oneshot(neg)
    ok(status != _KXR_OK,
       f"raw: stat with negative/huge dlen (-1) not ok (status={status}, closed={closed})")
    survives("negative-dlen")

    # ----- (5) OPCODE OUT OF VALID RANGE -------------------------------------
    garbage_op = struct.pack("!2sH16sI", b"\x00\x11", 9999, b"\x00" * 16, 0)
    hs_status, status, body, closed = _kxr_oneshot(garbage_op)
    ok(status != _KXR_OK,
       f"raw: out-of-range opcode 9999 rejected/closed (status={status}, closed={closed})")
    survives("garbage-opcode")

    # ----- (6) FILE OP BEFORE LOGIN (pre-login stat of a real cross-tenant path)
    pre = _kxr_stat_bytes(b"/bob/private.txt", streamid=b"\x00\x12")
    hs_status, status, body, closed = _kxr_oneshot(pre)
    ok(status != _KXR_OK,
       f"raw: stat BEFORE login rejected, no metadata served (status={status})")
    ok(BOB_SECRET not in body,
       "raw: pre-login stat body carries no bob secret bytes")
    survives("pre-login-stat")

    # ----- (7) UNAUTHENTICATED (anon-login, NO kXR_auth) stat of bob file ----
    s, _hs, lg = _kxr_session(do_login=True)
    if s is not None and lg == _KXR_OK:
        status, body = _kxr_send_recv(s, _kxr_stat_bytes(b"/bob/private.txt"))
        ok(status != _KXR_OK,
           f"raw: anon-login (unauthenticated) stat of bob file NOT ok (status={status})")
        ok(BOB_SECRET not in body,
           "raw: unauthenticated stat returns no bob secret bytes")
        try:
            s.close()
        except OSError:
            pass
    else:
        ok(True, "raw kXR session not established; unauthenticated-stat check skipped")
        ok(True, "raw kXR session not established; unauthenticated-leak check skipped")
    survives("unauthenticated-stat")

    # ----- (8) DOUBLE LOGIN on one connection --------------------------------
    s, _hs, _lg = _kxr_session(do_login=True)
    if s is not None:
        status2, _b2 = _kxr_send_recv(s, _kxr_login_bytes(streamid=b"\x00\x13"))
        # Any deterministic outcome (error / ignore / close) is acceptable; the
        # invariant is no crash — proven by the survives() follow-up.
        ok(True, f"raw: second kXR_login on one connection handled (status={status2})")
        try:
            s.close()
        except OSError:
            pass
    else:
        ok(True, "raw kXR session not established; double-login check skipped")
    survives("double-login")

    # ----- (9) TRAVERSAL PATH via raw stat (../../../../etc/passwd) -----------
    trav = _kxr_stat_bytes(b"/alice/../../../../etc/passwd", streamid=b"\x00\x14")
    hs_status, status, body, closed = _kxr_oneshot(trav)
    ok(status != _KXR_OK,
       f"raw: traversal stat ../../etc/passwd not served (status={status})")
    ok(b"root:" not in body and b"/bin/" not in body and b"daemon:" not in body,
       "raw: traversal stat body has no /etc/passwd content")
    survives("traversal-stat")

    # ----- (10) TRUNCATED BODY (login claims 64-byte cred, sends 4) ----------
    trunc = _kxr_login_bytes(streamid=b"\x00\x15")[:-4] + struct.pack("!I", 64) \
        + b"\xAA\xBB\xCC\xDD"
    hs_status, status, body, closed = _kxr_oneshot(trunc)
    ok(status != _KXR_OK or closed,
       f"raw: login claiming 64-byte body but sending 4 -> not ok (status={status}, closed={closed})")
    survives("truncated-body")

    # ----- (11) readv with OOB / overflowing segments (pre-auth) -------------
    # ClientReadVRequest: streamid[2] requestid[2] reserved[15] pathid[1] dlen[4]
    # + one read_list element {fhandle[4], rlen[int32], offset[int64]} whose
    # offset/len are at the int boundary on a bogus handle.
    rl = struct.pack("!4siq", b"\xFF\xFF\xFF\xFF", 0x7FFFFFFF, 0x7FFFFFFFFFFFFFFF)
    readv = struct.pack("!2sH15sBI", b"\x00\x16", _KXR_READV, b"\x00" * 15, 0,
                        len(rl)) + rl
    hs_status, status, body, closed = _kxr_oneshot(readv)
    ok(status != _KXR_OK,
       f"raw: readv with overflowing offset/len on bogus handle not ok (status={status})")
    survives("readv-overflow")

    # ----- (12) kXR_bind to a FOREIGN / garbage session id -------------------
    bind = struct.pack("!2sH16sI", b"\x00\x17", _KXR_BIND, b"\xFF" * 16, 0)
    s, _hs, _lg = _kxr_session(do_login=True)
    if s is not None:
        status, body = _kxr_send_recv(s, bind)
        ok(status != _KXR_OK,
           f"raw: kXR_bind to foreign/garbage sessid not granted (status={status})")
        try:
            s.close()
        except OSError:
            pass
    else:
        ok(True, "raw kXR session not established; foreign-bind check skipped")
    survives("foreign-bind")

    # ----- final: a clean native data round-trip still works as alice --------
    rc, _out, _e = xrd_fs(["ls", "/alice"], "alice")
    ok(rc == 0,
       f"raw: after all adversarial framings, native xrdfs ls /alice (alice) ok (rc={rc})")


def run_header_injection_matrix(key, data, port, s3port):
    """HEADER / CRLF / HOST / DESTINATION / COPY-SOURCE injection matrix under
    impersonation.  Distinct from the malformed/http-abuse/confinement batches: those
    cover encoded-CRLF-in-PATH, NUL-in-header, dup-Host(relative-URI), absolute-URI to a
    foreign host, oversized header VALUE/COUNT, and CLEAN Destination/copy-source DAC
    denials.  HERE the payload lives in the Destination: / x-amz-copy-source: VALUE and
    in the response-header surface: CRLF response-splitting, cross-host + traversal +
    percent-encoded-CRLF in COPY/MOVE/CopyObject (verified byte-for-byte on bob's 0600
    file on disk), Host-header confusion (missing / mismatched-on-absolute-URI / two
    Host on an absolute-URI line), obs-fold continuation, NUL in a header value other
    than the smuggle-classic, oversized request TARGET (not header), Expect:100-continue
    with no body, Connection-header games, and DUPLICATE auth (Bearer + SigV4 together).
    Every case: no response-splitting/reflection, no escape, no cross-tenant mutation,
    worker survives."""
    ta, tb = mint(key, "alice"), mint(key, "bob")
    H = "127.0.0.1:%d" % port
    BOB = b"BOB-PRIVATE-SECRET"
    bpriv = os.path.join(data, "bob", "private.txt")
    outside = os.path.join(os.path.dirname(data), "HIM_ESCAPE_SENTINEL")

    # baseline snapshot of bob's 0600 file (just restored by _reset_fixtures): every
    # Destination/copy-source injection below must leave it byte-identical on disk.
    try:
        bob0 = open(bpriv, "rb").read()
        bst0 = os.stat(bpriv)
    except OSError:
        bob0, bst0 = None, None

    def bob_untouched():
        if bob0 is None:
            return True
        try:
            s = os.stat(bpriv)
            return (open(bpriv, "rb").read() == bob0 and s.st_uid == bst0.st_uid
                    and (s.st_mode & 0o777) == (bst0.st_mode & 0o777))
        except OSError:
            return False

    def no_split(resp):
        # a response must contain at most ONE status line and never reflect our marker
        # as a header (response-splitting / header-injection).
        r = resp or b""
        return (r.count(b"HTTP/1.") <= 1 and b"X-Injected" not in r
                and b"x-injected" not in r and b"HIM-SPLIT" not in r)

    def status(resp):
        m = re.match(rb"HTTP/1\.[01] (\d{3})", resp or b"")
        return int(m.group(1)) if m else -1

    def worker_alive(tag):
        st, b = http("GET", "/alice/him_probe.txt", port, ta)
        # the probe file is (re)created just below; survival = a clean own round-trip.
        ok(st in (200, 201, 204, 404) and b"BOB-PRIVATE-SECRET" not in (b or b""),
           "worker survived %s (follow-up alice GET HTTP %s)" % (tag, st))

    # seed an own file used as a benign COPY/MOVE source (so a "valid source" can't
    # be the reason a copy is refused -- only the malicious Destination is).
    http("PUT", "/alice/him_src.txt", port, ta, b"HIM-COPY-SOURCE-BODY\n")
    http("PUT", "/alice/him_probe.txt", port, ta, b"HIM-PROBE\n")

    # ============================================================ Destination: CRLF ===
    # CRLF injected INTO the Destination header value: must not split the response and
    # must not create a file at the smuggled tail.  raw_http (urllib would reject \r\n).
    dst_crlf = (b"COPY /alice/him_src.txt HTTP/1.1\r\nHost: " + H.encode()
                + b"\r\nAuthorization: Bearer " + ta.encode()
                + b"\r\nDestination: http://" + H.encode()
                + b"/alice/him_crlf.txt\r\nX-Injected: HIM-SPLIT\r\n"
                + b"Connection: close\r\n\r\n")
    resp = raw_http(dst_crlf, port)
    ok(no_split(resp),
       "Destination CRLF: no response-split / no injected header reflected (HTTP %s)"
       % status(resp))

    # percent-encoded CRLF (%0d%0a) inside Destination value -- urllib accepts the
    # literal percents; server must NOT decode them into a real header split, and the
    # weird target must not land outside alice.
    st, _ = http("COPY", "/alice/him_src.txt", port, ta,
                 hdrs={"Destination":
                       "http://%s/alice/him_pe%%0d%%0aX-Injected:%%201.txt" % H})
    ok(not os.path.exists(outside) and bob_untouched(),
       "Destination percent-encoded-CRLF: no escape, bob 0600 untouched (HTTP %s)" % st)

    # ====================================================== Destination: cross-host ===
    # Destination authority pointing at a FOREIGN host (COPY): the server must confine
    # to its own export (treat as same-export path or reject) -- never proxy-write off
    # box and never mutate bob.
    st, _ = http("COPY", "/alice/him_src.txt", port, ta,
                 hdrs={"Destination": "http://evil.example:9999/bob/private.txt"})
    ok(bob_untouched() and not os.path.exists(outside),
       "Destination cross-host authority COPY: bob's 0600 NOT overwritten (HTTP %s)"
       % st)

    # Destination scheme/host pointing at bob's file (same host) via COPY of alice's
    # own readable source -- the WRITE leg runs as alice -> EACCES on bob's dir/file.
    st, _ = http("COPY", "/alice/him_src.txt", port, ta,
                 hdrs={"Destination": "http://%s/bob/private.txt" % H})
    ok(st not in (200, 201, 204) and bob_untouched(),
       "Destination -> bob/private.txt: alice COPY DENIED, secret unchanged (HTTP %s)"
       % st)

    # ====================================================== Destination: traversal ===
    # ../ traversal in the Destination path must not write outside the export root.
    for dval, tag in [
        ("http://%s/../HIM_ESCAPE_SENTINEL" % H, "../-after-host"),
        ("http://%s/alice/../../HIM_ESCAPE_SENTINEL" % H, "deep-../"),
        ("/../HIM_ESCAPE_SENTINEL", "path-only-../"),
    ]:
        st, _ = http("COPY", "/alice/him_src.txt", port, ta, hdrs={"Destination": dval})
        ok(not os.path.exists(outside),
           "Destination traversal (%s) blocked, no file outside export (HTTP %s)"
           % (tag, st))

    # MOVE with a traversal Destination must neither escape NOR consume the source.
    st, _ = http("MOVE", "/alice/him_src.txt", port, ta,
                 hdrs={"Destination": "http://%s/../HIM_ESCAPE_SENTINEL" % H})
    ok(not os.path.exists(outside)
       and os.path.exists(os.path.join(data, "alice", "him_src.txt")),
       "MOVE traversal Destination: no escape, source intact (HTTP %s)" % st)
    worker_alive("destination-injection")

    # =========================================================== Host-header attacks ===
    # (a) MISSING Host on HTTP/1.1 -> 400 (nginx requires it); no leak.
    miss = (b"GET /bob/private.txt HTTP/1.1\r\nAuthorization: Bearer " + ta.encode()
            + b"\r\nConnection: close\r\n\r\n")
    resp = raw_http(miss, port)
    ok(BOB not in (resp or b"") and no_split(resp),
       "missing Host (HTTP/1.1): no bob leak, handled (HTTP %s)" % status(resp))

    # (b) absolute-URI request line with a Host header that MISMATCHES the URI
    #     authority -- must still confine to the local export; bob never leaks.
    mism = (b"GET http://evil.example/alice/him_probe.txt HTTP/1.1\r\nHost: "
            + H.encode() + b"\r\nAuthorization: Bearer " + ta.encode()
            + b"\r\nConnection: close\r\n\r\n")
    resp = raw_http(mism, port)
    ok(BOB not in (resp or b""),
       "absolute-URI + mismatched Host: no bob leak (HTTP %s)" % status(resp))

    # (c) TWO Host headers on an absolute-URI line -> ambiguous authority must 400 /
    #     not be resolved into a foreign read of bob.
    two = (b"GET http://" + H.encode() + b"/alice/him_probe.txt HTTP/1.1\r\nHost: "
           + H.encode() + b"\r\nHost: evil.example\r\nAuthorization: Bearer "
           + ta.encode() + b"\r\nConnection: close\r\n\r\n")
    resp = raw_http(two, port)
    ok(BOB not in (resp or b"") and no_split(resp),
       "two Host headers on absolute-URI: handled, no leak (HTTP %s)" % status(resp))

    # =========================================================== obs-fold continuation ==
    # obsolete line-folding (a header continued on a folded line) is forbidden by
    # RFC7230; nginx must reject (400) or not honour the fold as an Authorization, and
    # certainly must not fold a smuggled Authorization granting bob.
    fold = (b"GET /bob/private.txt HTTP/1.1\r\nHost: " + H.encode()
            + b"\r\nX-Fold: value\r\n\tAuthorization: Bearer " + tb.encode()
            + b"\r\nConnection: close\r\n\r\n")
    resp = raw_http(fold, port)
    ok(BOB not in (resp or b"") and no_split(resp),
       "obs-fold header continuation: folded Authorization not honoured, no leak "
       "(HTTP %s)" % status(resp))

    # ============================================================ NUL in header value ===
    # NUL inside the Authorization VALUE (distinct from the X-Evil NUL the malformed
    # batch tests): must not be truncated into a valid bearer that reads bob.
    nul = (b"GET /bob/private.txt HTTP/1.1\r\nHost: " + H.encode()
           + b"\r\nAuthorization: Bearer " + ta.encode()
           + b"\x00 extra\r\nConnection: close\r\n\r\n")
    resp = raw_http(nul, port)
    ok(BOB not in (resp or b""),
       "NUL in Authorization value: not truncated into a granting token (HTTP %s)"
       % status(resp))

    # ============================================================ oversized request TARGET
    # an oversized request TARGET (URI), not a header value (the malformed batch did a
    # 24KB header VALUE; http-abuse did a 200-header COUNT) -> 414 / 400, no crash.
    big_uri = (b"GET /alice/" + b"A" * 18000 + b" HTTP/1.1\r\nHost: " + H.encode()
               + b"\r\nAuthorization: Bearer " + ta.encode()
               + b"\r\nConnection: close\r\n\r\n")
    resp = raw_http(big_uri, port)
    ok(status(resp) in (414, 400, 404, 494, -1) or status(resp) >= 400,
       "oversized request TARGET rejected (HTTP %s)" % status(resp))

    # ============================================================ Expect: 100-continue ==
    # Expect:100-continue with NO following body on a PUT: the worker must not hang
    # forever waiting and must not create an alice file from a body that never came.
    exp = (b"PUT /alice/him_expect.txt HTTP/1.1\r\nHost: " + H.encode()
           + b"\r\nAuthorization: Bearer " + ta.encode()
           + b"\r\nExpect: 100-continue\r\nContent-Length: 10\r\n"
           + b"Connection: close\r\n\r\n")
    resp = raw_send_steps([(exp, 1.2)], port, read_timeout=3.0)
    expfp = os.path.join(data, "alice", "him_expect.txt")
    expbad = os.path.exists(expfp) and os.stat(expfp).st_uid != UID_ALICE
    ok(not expbad and no_split(resp),
       "Expect:100-continue then no body: no hang/desync, no svc/root file "
       "(HTTP %s)" % status(resp))

    # ============================================================ Connection-header games
    # a Connection header that names a hop-by-hop header to strip (Connection:
    # Authorization) must NOT cause the server to drop Authorization and then serve
    # bob's file unauthenticated.
    conn = (b"GET /bob/private.txt HTTP/1.1\r\nHost: " + H.encode()
            + b"\r\nAuthorization: Bearer " + ta.encode()
            + b"\r\nConnection: Authorization, close\r\n\r\n")
    resp = raw_http(conn, port)
    ok(BOB not in (resp or b""),
       "Connection: Authorization (strip-auth game): no anonymous bob read (HTTP %s)"
       % status(resp))
    worker_alive("host-conn-games")

    # ============================================================ DUPLICATE auth ========
    # Bearer (alice) AND a SigV4 Authorization in ONE WebDAV request: the server must
    # pick ONE scheme deterministically and never both-grant.  Whatever it picks, a
    # read of bob's 0600 must be denied (alice has no DAC; SigV4 here is malformed for
    # the WebDAV endpoint anyway) and bob's file is never mutated.  urllib collapses
    # duplicate header names, so forge BOTH an AWS4 line and a Bearer line on a raw
    # socket to actually present dual auth.
    sig = s3_sign("GET", "/%s/bob/private.txt" % S3_BUCKET, port)["Authorization"]
    dual = (b"GET /bob/private.txt HTTP/1.1\r\nHost: " + H.encode()
            + b"\r\nAuthorization: Bearer " + ta.encode()
            + b"\r\nAuthorization: " + sig.encode()
            + b"\r\nConnection: close\r\n\r\n")
    resp = raw_http(dual, port)
    ok(BOB not in (resp or b""),
       "dual Bearer+SigV4 Authorization (WebDAV): never both-grant, bob denied "
       "(HTTP %s)" % status(resp))
    ok(bob_untouched(),
       "after dual-auth WebDAV probe: bob's 0600 unchanged on disk")

    # ==================================================================== S3 copy-source
    if s3port:
        # x-amz-copy-source with CRLF injected: CopyObject source-read runs as the
        # signer (alice); the CRLF must not split / inject and bob must not be touched.
        st, _ = s3("PUT", "alice/him_cs1.bin", s3port,
                   extra_hdrs={"x-amz-copy-source":
                               "/%s/bob/private.txt\r\nX-Injected: HIM-SPLIT"
                               % S3_BUCKET})
        ok(st not in (200, 201) and bob_untouched()
           and not os.path.exists(os.path.join(data, "alice", "him_cs1.bin")),
           "S3 copy-source CRLF: rejected, bob untouched, no alice artifact (HTTP %s)"
           % st)

        # x-amz-copy-source with ../ traversal into /etc -- must not read /etc/passwd
        # nor escape the export.
        st, b = s3("PUT", "alice/him_cs2.bin", s3port,
                   extra_hdrs={"x-amz-copy-source":
                               "/%s/../../../../etc/passwd" % S3_BUCKET})
        ok(b"root:x:0:0" not in (b or b"")
           and not os.path.exists(os.path.join(data, "alice", "him_cs2.bin")),
           "S3 copy-source ../etc/passwd traversal: no leak, no artifact (HTTP %s)"
           % st)

        # x-amz-copy-source pointing at a DIFFERENT bucket name (cross-bucket authority)
        # -- with only one bucket configured this must not resolve to a host path.
        st, _ = s3("PUT", "alice/him_cs3.bin", s3port,
                   extra_hdrs={"x-amz-copy-source": "/otherbucket/bob/private.txt"})
        ok(bob_untouched()
           and not os.path.exists(os.path.join(data, "alice", "him_cs3.bin")),
           "S3 copy-source foreign-bucket: no cross-bucket read, bob untouched "
           "(HTTP %s)" % st)

        # DUPLICATE auth on S3: a valid SigV4 line AND a Bearer line -- the S3 endpoint
        # must authenticate via SigV4 only and never let the Bearer escalate; a GET of
        # bob's 0600 stays denied.
        sg = dict(s3_sign("GET", "/%s/bob/private.txt" % S3_BUCKET, s3port))
        sg["X-Bearer-Smuggle"] = "Bearer %s" % tb   # bob bearer as a side header
        st, b = http("GET", "/%s/bob/private.txt" % S3_BUCKET, s3port, hdrs=sg)
        ok(st not in (200,) and BOB not in (b or b""),
           "S3 SigV4(alice) + smuggled bob-bearer: no escalation, bob denied (HTTP %s)"
           % st)
        worker_alive("s3-copy-source")
    else:
        ok(True, "S3 copy-source / dual-auth injection skipped (no s3port)")

    # final: bob's protected file survived the ENTIRE matrix byte-for-byte.
    ok(bob_untouched(),
       "FINAL: bob's 0600 private.txt byte-identical + 0600 after full injection matrix")


def run_tpc_pull_push_matrix(key, data, port, s3port):
    """Native xrdcp --tpc loopback MATRIX under per-request UNIX impersonation.
    Distinct from run_native_tpc (owner/0700-dest/unmapped) and from
    run_combo_setgid_via_copymove (setgid-group inheritance through copy/TPC):
    this batch proves the ORTHOGONAL DAC dimensions of a third-party copy ---
    (1) cross-tenant WRITE into a 0755 dir the orchestrator does NOT own (no
    'other' write bit) is denied; (2) cross-tenant READ of a 0644 WORLD-readable
    source IS allowed and lands owner==orchestrator, byte-exact (a POSITIVE
    cross-tenant leg, not a denial); (3) GROUP-mediated read through TPC: a
    research-group member (dave) may pull a 0640 research file, a non-member
    (carol) may not, with no secret bytes on disk; (4) the push-side mode
    'second' (vs first/delegate already covered) still obeys DAC; (5) a
    NONEXISTENT source yields a clean error with NO partial destination file;
    (6) pub/(0777) artifacts created by carol/dave (orchestrators distinct from
    the alice/bob pair already tested) are owned by the COPIER, never svc/root.
    The invariant: a TPC is just a delegated open+read+write, so every endpoint
    obeys the orchestrator's impersonated identity --- the world bit grants,
    the missing other-write bit and the group boundary both deny."""
    TAG = "tppm"
    if not xrd_avail():
        ok(True, "%s: TPC pull/push matrix SKIPPED (native client absent)" % TAG)
        return

    MARK_C = b"TPPM-CAROL-OWN-PAYLOAD"
    MARK_D = b"TPPM-DAVE-OWN-PAYLOAD"
    BOB_PUB = b"bob-world-readable"          # bytes living in data/bob/readable.txt
    RES_BODY = b"RESEARCH-GROUP-READABLE"    # bytes in data/grp/research_r.txt (0640)
    BOB_PRIV = b"BOB-PRIVATE-SECRET"

    def _owner(p):
        try:
            return os.stat(p).st_uid
        except OSError:
            return -1

    def _gid(p):
        try:
            return os.stat(p).st_gid
        except OSError:
            return -1

    def _content(p):
        try:
            with open(p, "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def _gone(p):
        return not os.path.exists(p)

    def _rm(p):
        try:
            if os.path.exists(p):
                os.remove(p)
        except OSError:
            pass

    # ---- seed orchestrator-owned sources we control (carol + dave) -------------
    c_src_rel = "/carol/%s_src.bin" % TAG
    c_src_fs = os.path.join(data, "carol", "%s_src.bin" % TAG)
    d_src_rel = "/dave/%s_src.bin" % TAG
    d_src_fs = os.path.join(data, "dave", "%s_src.bin" % TAG)
    seeded = True
    for home, uid, fs, body in (("carol", UID_CAROL, c_src_fs, MARK_C),
                                ("dave", UID_DAVE, d_src_fs, MARK_D)):
        try:
            os.makedirs(os.path.join(data, home), exist_ok=True)
            os.chown(os.path.join(data, home), uid, uid)
            os.chmod(os.path.join(data, home), 0o755)
            with open(fs, "wb") as fh:
                fh.write(body + b"\n")
            os.chown(fs, uid, uid)
            os.chmod(fs, 0o644)
        except OSError as e:
            seeded = False
            ok(False, "%s: could not seed %s source fixture (%r)" % (TAG, home, e))
    if not seeded:
        return
    ensure_traversable(os.path.join(data, "carol"))
    ensure_traversable(os.path.join(data, "dave"))

    # =====================================================================
    # (1) CROSS-TENANT WRITE into bob/ (0755 bob-owned).  Unlike the 0700
    #     bobsecret/ case (run_native_tpc c), bob/ is *traversable+readable*
    #     by others but carries NO 'other' write bit, so a TPC dest open by
    #     alice (not the owner, not bob's group) must be DENIED.  This isolates
    #     the "world-traversable but not world-writable" deny path.
    # =====================================================================
    b755_rel = "/bob/%s_intrude.bin" % TAG
    b755_fs = os.path.join(data, "bob", "%s_intrude.bin" % TAG)
    _rm(b755_fs)
    rc, out, err = xrd_cp_tpc(c_src_rel, b755_rel, "alice")
    ok(rc != 0 and _gone(b755_fs),
       "%s(1): alice TPC-write into bob/(0755,not-owner) DENIED, nothing created "
       "(rc=%d)" % (TAG, rc))
    ok(_gone(b755_fs) or _owner(b755_fs) not in (UID_ALICE, UID_SVC, 0),
       "%s(1): no alice/svc/root file smuggled into bob/ via denied TPC" % TAG)
    # bob/ dir mode + ownership untouched by the denied dest open.
    bdmode = os.stat(os.path.join(data, "bob")).st_mode & 0o777
    ok(bdmode == 0o755 and _owner(os.path.join(data, "bob")) == UID_BOB,
       "%s(1): bob/ dir intact bob:0755 after denied TPC (mode=%o)" % (TAG, bdmode))

    # =====================================================================
    # (2) CROSS-TENANT READ of a 0644 WORLD-readable source IS ALLOWED.
    #     alice TPC-pulls bob/readable.txt -> alice/ok.  Distinct POSITIVE
    #     cross-tenant leg: the world read bit legitimately grants the pull,
    #     dst must end up alice-owned + byte-exact (proving TPC honours the
    #     'other' read bit, not a blanket cross-tenant block).  And critically
    #     this is NOT bob's 0600 secret --- no private bytes appear.
    # =====================================================================
    ok_dst_rel = "/alice/%s_pub_pull.bin" % TAG
    ok_dst_fs = os.path.join(data, "alice", "%s_pub_pull.bin" % TAG)
    _rm(ok_dst_fs)
    rc, out, err = xrd_cp_tpc("/bob/readable.txt", ok_dst_rel, "alice")
    if rc == 0 and os.path.exists(ok_dst_fs):
        ok(_owner(ok_dst_fs) == UID_ALICE,
           "%s(2): alice TPC-pull of bob world-readable(0644) lands alice-owned "
           "uid=%d (rc=%d)" % (TAG, _owner(ok_dst_fs), rc))
        ok(_owner(ok_dst_fs) not in (UID_BOB, UID_SVC, 0),
           "%s(2): world-read pull dst NOT bob/svc/root-owned (uid=%d)"
           % (TAG, _owner(ok_dst_fs)))
        ok(BOB_PUB in _content(ok_dst_fs),
           "%s(2): world-read pull dst is byte-exact copy of bob/readable.txt" % TAG)
        ok(BOB_PRIV not in _content(ok_dst_fs),
           "%s(2): world-read pull carried NO bob private-secret bytes" % TAG)
    else:
        # If the server cannot TPC at all, accept gracefully but never with a
        # foreign-owned artifact, and never with the private secret leaked.
        ok(_gone(ok_dst_fs) or _owner(ok_dst_fs) == UID_ALICE,
           "%s(2): world-read TPC unsupported/handled (rc=%d), no foreign artifact"
           % (TAG, rc))
        ok(BOB_PRIV not in _content(ok_dst_fs),
           "%s(2): world-read TPC (handled) leaked no bob private secret" % TAG)

    # =====================================================================
    # (3) GROUP-MEDIATED READ through TPC.  grp/research_r.txt is bob:research
    #     0640 (no other bits).  research = {bob, dave}.  dave is a MEMBER so
    #     his TPC-pull is granted *by group*; carol is NOT in research so her
    #     identical pull must be DENIED with the body never reaching disk.
    #     This is the group dimension neither prior batch tests on the READ
    #     side of a TPC (combo only forced group on the WRITE/setgid side).
    # =====================================================================
    res_rel = "/grp/research_r.txt"
    dave_ok_rel = "/dave/%s_grp_pull.bin" % TAG
    dave_ok_fs = os.path.join(data, "dave", "%s_grp_pull.bin" % TAG)
    _rm(dave_ok_fs)
    rc, out, err = xrd_cp_tpc(res_rel, dave_ok_rel, "dave")
    if rc == 0 and os.path.exists(dave_ok_fs):
        ok(RES_BODY in _content(dave_ok_fs) and _owner(dave_ok_fs) == UID_DAVE,
           "%s(3): dave(research member) TPC-pull of 0640 group file ALLOWED, "
           "dave-owned + byte-exact (rc=%d)" % (TAG, rc))
        ok(_owner(dave_ok_fs) not in (UID_BOB, UID_SVC, 0),
           "%s(3): dave's group-read pull dst NOT bob/svc/root-owned (uid=%d)"
           % (TAG, _owner(dave_ok_fs)))
    else:
        ok(_gone(dave_ok_fs) or _owner(dave_ok_fs) == UID_DAVE,
           "%s(3): dave group-read TPC unsupported/handled (rc=%d), no foreign dst"
           % (TAG, rc))
    # carol is NOT in research -> her pull of the SAME 0640 file is denied and
    # the research body never lands in carol's space.
    carol_steal_rel = "/carol/%s_grp_steal.bin" % TAG
    carol_steal_fs = os.path.join(data, "carol", "%s_grp_steal.bin" % TAG)
    _rm(carol_steal_fs)
    rc, out, err = xrd_cp_tpc(res_rel, carol_steal_rel, "carol")
    cleaked = (os.path.exists(carol_steal_fs) and RES_BODY in _content(carol_steal_fs)) \
        or (RES_BODY in (out or "").encode()) or (RES_BODY in (err or "").encode())
    ok(rc != 0 and not cleaked,
       "%s(3): carol(non-research) TPC-pull of 0640 research file DENIED, no leak "
       "(rc=%d)" % (TAG, rc))
    ok(not (os.path.exists(carol_steal_fs) and RES_BODY in _content(carol_steal_fs)),
       "%s(3): no carol file holds the research-group body bytes" % TAG)

    # =====================================================================
    # (4) PUSH-SIDE mode 'second' (the orchestration mode NOT exercised by
    #     run_native_tpc, which used first/delegate).  The mode only changes
    #     which endpoint drives the data pull; DAC must hold identically.
    #     Own-file copy under mode=second -> requester-owned if it lands; the
    #     cross-tenant private pull under mode=second stays denied.
    # =====================================================================
    sec_own_rel = "/carol/%s_sec_own.bin" % TAG
    sec_own_fs = os.path.join(data, "carol", "%s_sec_own.bin" % TAG)
    _rm(sec_own_fs)
    rc, out, err = xrd_cp_tpc(c_src_rel, sec_own_rel, "carol", mode="second")
    if rc == 0 and os.path.exists(sec_own_fs):
        ok(_owner(sec_own_fs) == UID_CAROL and _content(sec_own_fs) == MARK_C + b"\n",
           "%s(4): mode=second carol own-copy carol-owned + byte-exact (rc=%d)"
           % (TAG, rc))
        ok(_owner(sec_own_fs) not in (UID_SVC, 0),
           "%s(4): mode=second own-copy never svc/root-owned (uid=%d)"
           % (TAG, _owner(sec_own_fs)))
    else:
        ok(_gone(sec_own_fs) or _owner(sec_own_fs) == UID_CAROL,
           "%s(4): mode=second own-copy unsupported/handled (rc=%d), no foreign dst"
           % (TAG, rc))
    sec_steal_rel = "/carol/%s_sec_steal.bin" % TAG
    sec_steal_fs = os.path.join(data, "carol", "%s_sec_steal.bin" % TAG)
    _rm(sec_steal_fs)
    rc, out, err = xrd_cp_tpc("/bob/private.txt", sec_steal_rel, "carol", mode="second")
    sleaked = (os.path.exists(sec_steal_fs) and BOB_PRIV in _content(sec_steal_fs)) \
        or (BOB_PRIV in (out or "").encode()) or (BOB_PRIV in (err or "").encode())
    ok(rc != 0 and not sleaked,
       "%s(4): mode=second cross-tenant pull of bob/private.txt(0600) DENIED, no "
       "leak (rc=%d)" % (TAG, rc))

    # =====================================================================
    # (5) NONEXISTENT SOURCE -> clean error, NO partial destination file.
    #     A TPC whose source open fails (ENOENT) must not leave a 0-byte or
    #     partial dst behind in the orchestrator's own space.
    # =====================================================================
    miss_rel = "/carol/%s_does_not_exist_%d.bin" % (TAG, int(time.time()))
    miss_dst_rel = "/carol/%s_miss_dst.bin" % TAG
    miss_dst_fs = os.path.join(data, "carol", "%s_miss_dst.bin" % TAG)
    _rm(miss_dst_fs)
    rc, out, err = xrd_cp_tpc(miss_rel, miss_dst_rel, "carol")
    ok(rc != 0,
       "%s(5): TPC of a nonexistent source fails cleanly (rc=%d)" % (TAG, rc))
    ok(_gone(miss_dst_fs),
       "%s(5): nonexistent-source TPC left NO partial destination file" % TAG)

    # =====================================================================
    # (6) pub/(0777) artifacts created by carol and dave (orchestrators
    #     DISTINCT from the alice/bob pair run_native_tpc(g) already proved):
    #     each lands owned by the COPIER, never svc/root, and dave's copy after
    #     carol's shows no principal bleed on the shared worker.
    # =====================================================================
    pub_c_rel = "/pub/%s_pub_carol.bin" % TAG
    pub_c_fs = os.path.join(data, "pub", "%s_pub_carol.bin" % TAG)
    pub_d_rel = "/pub/%s_pub_dave.bin" % TAG
    pub_d_fs = os.path.join(data, "pub", "%s_pub_dave.bin" % TAG)
    _rm(pub_c_fs)
    _rm(pub_d_fs)
    rc, out, err = xrd_cp_tpc(c_src_rel, pub_c_rel, "carol")
    if rc == 0 and os.path.exists(pub_c_fs):
        ok(_owner(pub_c_fs) == UID_CAROL and _owner(pub_c_fs) not in (UID_SVC, 0),
           "%s(6): carol TPC into pub/(0777) owned by carol not svc (uid=%d)"
           % (TAG, _owner(pub_c_fs)))
    else:
        ok(_gone(pub_c_fs) or (_owner(pub_c_fs) == UID_CAROL
                               and _owner(pub_c_fs) not in (UID_SVC, 0)),
           "%s(6): carol pub/ TPC unsupported/handled (rc=%d), no svc/root artifact"
           % (TAG, rc))
    rc, out, err = xrd_cp_tpc(d_src_rel, pub_d_rel, "dave")
    if rc == 0 and os.path.exists(pub_d_fs):
        ok(_owner(pub_d_fs) == UID_DAVE
           and _owner(pub_d_fs) not in (UID_CAROL, UID_SVC, 0),
           "%s(6): dave TPC into same pub/ owned by dave, no carol/svc bleed "
           "(uid=%d)" % (TAG, _owner(pub_d_fs)))
        ok(_content(pub_d_fs) == MARK_D + b"\n",
           "%s(6): dave pub/ TPC dst byte-exact (no carol content bleed)" % TAG)
    else:
        ok(_gone(pub_d_fs) or _owner(pub_d_fs) == UID_DAVE,
           "%s(6): dave pub/ TPC unsupported/handled (rc=%d), no foreign artifact"
           % (TAG, rc))

    # =====================================================================
    # SURVIVAL + secret-integrity: after the whole matrix the broker/worker is
    # not wedged, and none of bob's protected fixtures were disturbed by any
    # denied dest-open / cross-tenant pull above.
    # =====================================================================
    surv = os.path.join(WORK, "%s_surv_dl.bin" % TAG)
    _rm(surv)
    rc_c, _o, _e = xrd_cp_down(c_src_rel, surv, "carol")
    ok(rc_c == 0 and os.path.exists(surv) and MARK_C in _content(surv),
       "%s survival: carol legit read still works after the matrix (rc=%d)"
       % (TAG, rc_c))
    ok(_content(os.path.join(data, "bob", "private.txt")).startswith(BOB_PRIV)
       and _owner(os.path.join(data, "bob", "private.txt")) == UID_BOB,
       "%s survival: bob/private.txt secret + ownership intact after matrix" % TAG)
    ok(_owner(os.path.join(data, "grp", "research_r.txt")) == UID_BOB
       and (os.stat(os.path.join(data, "grp", "research_r.txt")).st_gid == GID_RESEARCH),
       "%s survival: grp/research_r.txt still bob:research after group-deny" % TAG)


def run_multistep_lifecycle_invariants(key, data, port, s3port):
    """MULTI-STEP LIFECYCLE END-STATE INVARIANTS under per-request UNIX impersonation.

    Every other combo batch asserts properties PER STEP (run_combo_setgid_via_copymove
    checks the group on each copied/moved file; run_combo_multipart_lock_identity checks
    each interrupted-multipart/lock transition; run_combo_error_rollback checks each
    FAILED op leaves no residue).  This batch instead drives chains that SUCCEED all the
    way through and asserts a single invariant at the END of the whole chain — the
    property that only holds once every step has run.  Each sequence ends in a DISTINCT
    end-state observation: ownership stability across a verb chain, child ownership after
    a whole-collection MOVE, clean recursive-DELETE end-state, byte-exact ordered
    multipart assembly, setgid inheritance for a freshly CREATED (not copied) file,
    a non-empty rmdir that must FAIL and leave the subtree wholly intact, overwrite
    idempotency (replace not append, single inode), and a rename-chain leaving exactly
    one inode.  All fixtures prefixed `msli_` to avoid collisions with the battery."""
    TAG = "msli"
    base = f"http://127.0.0.1:{port}"
    ta = mint(key, "alice")
    tb = mint(key, "bob")
    tc = mint(key, "carol")

    # ---- on-disk introspection (runs as in-ns root, sees true uid/gid/mode) ----
    def realp(rel):
        return os.path.join(data, rel.lstrip("/"))

    def st_of(rel):
        try:
            p = realp(rel)
            return os.stat(p) if os.path.exists(p) else None
        except OSError:
            return None

    def exists(rel):
        try:
            return os.path.exists(realp(rel))
        except OSError:
            return False

    def body_of(rel):
        try:
            with open(realp(rel), "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def has(body, needle):
        if body is None:
            return False
        if isinstance(body, str):
            body = body.encode("utf-8", "replace")
        return needle in body

    # =====================================================================
    # SEQ 1 — alice CREATE -> alice tighten to 0600 -> bob GET.
    # END-STATE INVARIANT: after the successful create+chmod chain the file is
    # still alice-owned at 0600 AND a cross-tenant reader (bob) gets zero bytes.
    # (Distinct from rollback: every step here SUCCEEDS; the invariant is the
    # post-tighten ownership+confidentiality end-state, not a failed-op cleanup.)
    # =====================================================================
    S1_REL = f"alice/{TAG}_s1_tighten.txt"
    S1_MARK = b"MSLI-S1-ALICE-CONFIDENTIAL-7Q"
    http("DELETE", "/" + S1_REL, port, ta)
    c1, _ = http("PUT", "/" + S1_REL, port, ta, S1_MARK)
    ok(c1 in (200, 201, 204), f"{TAG}/s1: alice PUT creates her file (HTTP {c1})")
    pp1, _ = http("PROPPATCH", "/" + S1_REL, port, ta,
                  data=b'<?xml version="1.0"?><D:propertyupdate xmlns:D="DAV:"'
                       b' xmlns:Z="urn:x"><D:set><D:prop><Z:tag>t1</Z:tag>'
                       b'</D:prop></D:set></D:propertyupdate>',
                  hdrs={"Content-Type": "application/xml"})
    try:
        os.chmod(realp(S1_REL), 0o600)
        chm1 = True
    except OSError:
        chm1 = False
    ok(chm1, f"{TAG}/s1: 0600 tighten applied (os.chmod)")
    sb1, bb1 = http("GET", "/" + S1_REL, port, tb)   # bob: cross-tenant reader
    s1 = st_of(S1_REL)
    # The terminal invariant: alice-owned 0600 AND bob denied AND no marker leak.
    ok(s1 is not None and s1.st_uid == UID_ALICE
       and (s1.st_mode & 0o777) == 0o600
       and s1.st_uid not in (UID_SVC, 0)
       and sb1 in (401, 403, 404, 500) and not has(bb1, S1_MARK),
       f"{TAG}/s1 INVARIANT: after create+proppatch+tighten the file is "
       f"alice:0600 and bob's read is denied+empty "
       f"(uid={getattr(s1,'st_uid',None)} HTTP_bob={sb1})")

    # =====================================================================
    # SEQ 2 — alice MKCOL coll -> PUT 3 distinct files into it -> MOVE the WHOLE
    # collection to a new path.
    # END-STATE INVARIANT: at the NEW path every child is still alice-owned with
    # byte-exact content, and NOTHING remains at the OLD path.  (setgid batch
    # COPYs single files into a setgid dir; this is a plain whole-collection MOVE
    # whose invariant is child-ownership + content survival across the rename.)
    # =====================================================================
    C_OLD = f"alice/{TAG}_s2_coll"
    C_NEW = f"alice/{TAG}_s2_moved"
    http("DELETE", "/" + C_OLD, port, ta)
    http("DELETE", "/" + C_NEW, port, ta)
    mk2, _ = http("MKCOL", "/" + C_OLD, port, ta)
    ok(mk2 in (200, 201), f"{TAG}/s2: alice MKCOL collection (HTTP {mk2})")
    kids = {"a.txt": b"MSLI-S2-CHILD-A", "b.txt": b"MSLI-S2-CHILD-BB",
            "c.txt": b"MSLI-S2-CHILD-CCC"}
    put_all = True
    for nm, bd in kids.items():
        pc, _ = http("PUT", f"/{C_OLD}/{nm}", port, ta, bd)
        put_all = put_all and pc in (200, 201, 204)
    ok(put_all, f"{TAG}/s2: alice PUT 3 children into the collection")
    mv2, _ = http("MOVE", "/" + C_OLD, port, ta,
                  hdrs={"Destination": base + "/" + C_NEW, "Depth": "infinity"})
    ok(mv2 in (200, 201, 204),
       f"{TAG}/s2: alice MOVE whole collection to new path (HTTP {mv2})")
    # Terminal invariant over ALL children at the destination.
    all_ok = True
    for nm, bd in kids.items():
        cs = st_of(f"{C_NEW}/{nm}")
        if cs is None or cs.st_uid != UID_ALICE or cs.st_uid in (UID_SVC, 0):
            all_ok = False
        if body_of(f"{C_NEW}/{nm}") != bd:
            all_ok = False
    ok(all_ok,
       f"{TAG}/s2 INVARIANT: every moved child is alice-owned with byte-exact "
       f"content at the new path (not svc/root)")
    ok(not exists(C_OLD),
       f"{TAG}/s2 INVARIANT: old collection path fully gone after MOVE (rename, "
       f"no stray copy left behind)")

    # =====================================================================
    # SEQ 3 — alice MKCOL -> PUT a file -> recursive DELETE the collection.
    # END-STATE INVARIANT: the whole subtree is gone AND the parent dir contains
    # no svc/root-owned residue from the delete (a successful recursive delete
    # leaves a clean namespace — distinct from rollback's *failed*-op residue).
    # =====================================================================
    D_COLL = f"alice/{TAG}_s3_del"
    http("DELETE", "/" + D_COLL, port, ta)
    mk3, _ = http("MKCOL", "/" + D_COLL, port, ta)
    ok(mk3 in (200, 201), f"{TAG}/s3: alice MKCOL deletable collection (HTTP {mk3})")
    http("PUT", f"/{D_COLL}/inner.txt", port, ta, b"MSLI-S3-INNER")
    http("MKCOL", f"/{D_COLL}/sub", port, ta)
    http("PUT", f"/{D_COLL}/sub/deep.txt", port, ta, b"MSLI-S3-DEEP")
    seeded3 = exists(f"{D_COLL}/inner.txt") and exists(f"{D_COLL}/sub/deep.txt")
    ok(seeded3, f"{TAG}/s3: collection populated with nested children")
    # The WebDAV module implements NON-recursive collection DELETE
    # (src/webdav/namespace.c sets opts.require_empty_dir = 1): a DELETE of a
    # non-empty collection is refused with 409 Conflict and leaves the subtree
    # wholly intact (no partial wipe) — same policy as S3 BucketNotEmpty.  This
    # is the documented/tested contract (test_webdav_delete_lock_security.py:
    # test_delete_nonempty_collection_returns_409).  Assert that refusal, then
    # walk the documented happy path (empty depth-first, then drop the now-empty
    # collection) to reach the SAME clean end-state this invariant checks.
    dl3_busy, _ = http("DELETE", "/" + D_COLL, port, ta)
    ok(dl3_busy == 409,
       f"{TAG}/s3: alice DELETE of NON-empty collection refused 409 Conflict "
       f"(non-recursive WebDAV policy; HTTP {dl3_busy})")
    http("DELETE", f"/{D_COLL}/sub/deep.txt", port, ta)
    http("DELETE", f"/{D_COLL}/sub", port, ta)
    http("DELETE", f"/{D_COLL}/inner.txt", port, ta)
    dl3, _ = http("DELETE", "/" + D_COLL, port, ta)
    ok(dl3 in (200, 204), f"{TAG}/s3: alice DELETE now-empty collection (HTTP {dl3})")
    # scan alice/ for any new svc/root-owned entry matching this seq's prefix.
    leftover = []
    try:
        for n in os.listdir(realp("alice")):
            if not n.startswith(f"{TAG}_s3"):
                continue
            try:
                u = os.stat(os.path.join(realp("alice"), n)).st_uid
            except OSError:
                continue
            if u in (UID_SVC, 0):
                leftover.append((n, u))
    except OSError:
        pass
    ok(not exists(D_COLL) and not leftover,
       f"{TAG}/s3 INVARIANT: recursive DELETE removed the whole subtree and "
       f"left no svc/root residue (leftover={leftover})")

    # =====================================================================
    # SEQ 4 — S3 multipart: alice initiate -> upload part 1 -> part 2 -> complete.
    # END-STATE INVARIANT: the final object is alice-owned, its bytes are the
    # ORDERED concatenation part1||part2 (assembly correctness), and a
    # cross-tenant (bob) GET is denied with no marker leak.  (multipart_lock
    # batch covers abort/RST/cross-tenant-complete; this is a CLEAN 2-part
    # complete whose invariant is ordered byte-exact assembly as the end-state.)
    # =====================================================================
    if not s3port:
        ok(True, f"{TAG}/s4: S3 port down — multipart-assembly invariant skipped")
    else:
        # confirm S3 plane is answering before driving the lifecycle.
        s4live, _ = s3("GET", "", s3port, params={"list-type": "2"})
        if s4live == -1:
            ok(True, f"{TAG}/s4: S3 not answering — assembly invariant skipped")
        else:
            S4_KEY = f"alice/{TAG}_s4_mpu.bin"
            P1 = b"MSLI-S4-PART-ONE-".ljust(64, b"1") * 80    # ~5 KiB, distinct
            P2 = b"MSLI-S4-PART-TWO-".ljust(64, b"2") * 80    # ~5 KiB, distinct
            s3("DELETE", S4_KEY, s3port)
            ini, ib = s3("POST", S4_KEY, s3port, params={"uploads": ""})
            m = re.search(rb"<UploadId>([^<]+)</UploadId>", ib or b"")
            if ini in (200, 201) and m:
                up = m.group(1).decode()
                pe = []
                pok = True
                for n, pb in ((1, P1), (2, P2)):
                    ps, pbody = s3("PUT", S4_KEY, s3port,
                                   params={"uploadId": up, "partNumber": str(n)},
                                   data=pb)
                    et = re.search(rb'ETag>\\?"?([^"<\\]+)', pbody or b"")
                    pe.append((n, et.group(1).decode() if et else "etag"))
                    pok = pok and ps in (200, 201)
                ok(pok, f"{TAG}/s4: alice uploaded 2 distinct multipart parts")
                cx = b"<CompleteMultipartUpload>"
                for n, et in pe:
                    cx += (f"<Part><PartNumber>{n}</PartNumber>"
                           f"<ETag>{et}</ETag></Part>").encode()
                cx += b"</CompleteMultipartUpload>"
                cs, _ = s3("POST", S4_KEY, s3port, params={"uploadId": up}, data=cx)
                fst = st_of(S4_KEY)
                disk = body_of(S4_KEY)
                # ordered-assembly invariant: exact P1||P2, alice-owned.
                ok(cs in (200, 201) and fst is not None
                   and fst.st_uid == UID_ALICE and fst.st_uid not in (UID_SVC, 0)
                   and disk == (P1 + P2),
                   f"{TAG}/s4 INVARIANT: completed object is alice-owned and bytes "
                   f"== ordered part1||part2 ({len(disk)}=={len(P1)+len(P2)}? "
                   f"complete={cs})")
                # cross-tenant denial of the assembled object (bob as accessor).
                bs, bb = s3("GET", S4_KEY, s3port, access_key="bob")
                ok(bs in (401, 403, 404) and not has(bb, b"MSLI-S4-PART"),
                   f"{TAG}/s4 INVARIANT: bob cross-tenant GET of alice's assembled "
                   f"object is denied with no part-marker leak (HTTP {bs})")
                s3("DELETE", S4_KEY, s3port)
            else:
                ok(False, f"{TAG}/s4: multipart initiate failed (HTTP {ini})")

    # =====================================================================
    # SEQ 5 — alice CREATE a fresh file (PUT) directly INSIDE a 02770 alice:staff
    # setgid dir, then tighten to 0640.
    # END-STATE INVARIANT: the freshly-CREATED (not copied/moved) file inherits
    # group=staff and owner=alice; a SECOND staff member (carol) can then read it
    # via the inherited group while a NON-staff tenant (bob) is denied.  (setgid
    # batch only inherits through COPY/MOVE/TPC; this proves inheritance on the
    # plain create path as a lifecycle end-state with a positive+negative probe.)
    # =====================================================================
    SG = f"{TAG}_s5_sgid"
    sg_dir = realp(SG)
    try:
        os.makedirs(sg_dir, exist_ok=True)
        os.chown(sg_dir, UID_ALICE, GID_STAFF)
        os.chmod(sg_dir, 0o2770)
        ensure_traversable(sg_dir)
        sgmade = True
    except OSError:
        sgmade = False
    sgst = st_of(SG)
    ok(sgmade and sgst is not None and (sgst.st_mode & 0o2000)
       and sgst.st_gid == GID_STAFF,
       f"{TAG}/s5: 02770 alice:staff setgid dir present on disk")
    S5_REL = f"{SG}/{TAG}_s5_created.txt"
    S5_MARK = b"MSLI-S5-STAFF-GROUP-CREATED-3K"
    c5, _ = http("PUT", "/" + S5_REL, port, ta, S5_MARK)
    ok(c5 in (200, 201, 204),
       f"{TAG}/s5: alice CREATEs a fresh file inside the setgid dir (HTTP {c5})")
    s5 = st_of(S5_REL)
    ok(s5 is not None and s5.st_gid == GID_STAFF and s5.st_uid == UID_ALICE
       and s5.st_uid not in (UID_SVC, 0),
       f"{TAG}/s5 INVARIANT: freshly-created file INHERITS group=staff and is "
       f"owned by alice (uid={getattr(s5,'st_uid',None)} "
       f"gid={getattr(s5,'st_gid',None)})")
    try:
        os.chmod(realp(S5_REL), 0o640)
    except OSError:
        pass
    rc5, rb5 = http("GET", "/" + S5_REL, port, tc)   # carol = staff member
    bc5, bb5 = http("GET", "/" + S5_REL, port, tb)   # bob = NOT staff
    ok(rc5 == 200 and has(rb5, S5_MARK)
       and bc5 in (401, 403, 404, 500) and not has(bb5, S5_MARK),
       f"{TAG}/s5 INVARIANT: created-file's inherited staff group grants carol "
       f"(member) but denies bob (non-member) — group is real, not cosmetic "
       f"(carol={rc5} bob={bc5})")

    # =====================================================================
    # SEQ 6 — alice mkdir chain top/mid/leaf -> PUT a file in leaf -> attempt to
    # rmdir the NON-EMPTY mid directory.
    # END-STATE INVARIANT: the rmdir is REFUSED (ENOTEMPTY) and the ENTIRE subtree
    # (top, mid, leaf, the file) survives unchanged + alice-owned.  (Distinct from
    # rollback's staging-residue: here the failure is a directory-removal refusal
    # whose invariant is tree-INTACTNESS, not absence of temp files.)
    # =====================================================================
    A = "alice"
    TOP = f"/{A}/{TAG}_s6_top"
    MID = TOP + "/mid"
    LEAF = MID + "/leaf"
    xrd_fs(["rm", LEAF + "/f.bin"], "alice")
    xrd_fs(["rmdir", LEAF], "alice")
    xrd_fs(["rmdir", MID], "alice")
    xrd_fs(["rmdir", TOP], "alice")
    r_top, _, _ = xrd_fs(["mkdir", TOP], "alice")
    r_mid, _, _ = xrd_fs(["mkdir", MID], "alice")
    r_leaf, _, _ = xrd_fs(["mkdir", LEAF], "alice")
    ok(r_top == 0 and r_mid == 0 and r_leaf == 0,
       f"{TAG}/s6: alice built 3-level mkdir chain (rc={r_top},{r_mid},{r_leaf})")
    pl6, _ = http("PUT", LEAF + "/f.bin", port, ta, b"MSLI-S6-LEAF-FILE")
    ok(pl6 in (200, 201, 204) and exists(f"{A}/{TAG}_s6_top/mid/leaf/f.bin"),
       f"{TAG}/s6: file planted in the leaf directory (HTTP {pl6})")
    rrc, _, rerr = xrd_fs(["rmdir", MID], "alice")     # mid is NON-empty
    # Terminal invariant: rmdir refused AND every level + the file still present
    # and alice-owned (nothing partially removed, nothing reparented to svc/root).
    lvl = [st_of(f"{A}/{TAG}_s6_top"), st_of(f"{A}/{TAG}_s6_top/mid"),
           st_of(f"{A}/{TAG}_s6_top/mid/leaf"),
           st_of(f"{A}/{TAG}_s6_top/mid/leaf/f.bin")]
    tree_intact = all(s is not None and s.st_uid == UID_ALICE
                      and s.st_uid not in (UID_SVC, 0) for s in lvl)
    ok(rrc != 0 and tree_intact,
       f"{TAG}/s6 INVARIANT: rmdir of non-empty dir REFUSED (rc={rrc}) and the "
       f"full subtree (top/mid/leaf/f.bin) survives intact + alice-owned")

    # =====================================================================
    # SEQ 7 — alice PUT v1 -> PUT v2 OVER the same path (overwrite) -> PUT v3.
    # END-STATE INVARIANT: exactly ONE file at the path holding the LATEST body
    # (replace, not append), still alice-owned, with size == len(v3) and no stray
    # .xrd-tmp / .part residue beside it.  (Idempotent-overwrite end-state; no
    # other combo batch asserts replace-not-append + single-inode terminal state.)
    # =====================================================================
    S7_REL = f"alice/{TAG}_s7_overwrite.txt"
    http("DELETE", "/" + S7_REL, port, ta)
    v1 = b"MSLI-S7-VERSION-ONE"
    v2 = b"MSLI-S7-VERSION-TWO-LONGER-BODY"
    v3 = b"MSLI-S7-V3"
    o1, _ = http("PUT", "/" + S7_REL, port, ta, v1)
    o2, _ = http("PUT", "/" + S7_REL, port, ta, v2)
    o3, _ = http("PUT", "/" + S7_REL, port, ta, v3)
    ok(o1 in (200, 201, 204) and o2 in (200, 201, 204) and o3 in (200, 201, 204),
       f"{TAG}/s7: alice PUT same path three times ({o1},{o2},{o3})")
    s7 = st_of(S7_REL)
    disk7 = body_of(S7_REL)
    # residue scan in alice/ for this seq (overwrite must not strand temps).
    res7 = []
    try:
        for n in os.listdir(realp("alice")):
            low = n.lower()
            if n.startswith(f"{TAG}_s7") and (".xrd-tmp." in low
                                              or low.endswith(".part")
                                              or ".part." in low):
                res7.append(n)
    except OSError:
        pass
    ok(s7 is not None and disk7 == v3 and len(disk7) == len(v3)
       and s7.st_uid == UID_ALICE and s7.st_uid not in (UID_SVC, 0)
       and not res7,
       f"{TAG}/s7 INVARIANT: overwrite REPLACED content (==v3, size {len(disk7)}) "
       f"as a single alice-owned inode with no temp residue (res={res7})")

    # =====================================================================
    # SEQ 8 — alice PUT -> MOVE to path2 -> MOVE to path3 (rename chain within
    # alice's own tree).
    # END-STATE INVARIANT: exactly ONE inode exists, at the FINAL path, alice-owned
    # with intact content; NEITHER intermediate path retains a copy (no inode
    # leakage across a chain of renames).  (Distinct from setgid's single MOVE: the
    # invariant here is no-stray-copy across MULTIPLE chained renames.)
    # =====================================================================
    P1R = f"alice/{TAG}_s8_p1.txt"
    P2R = f"alice/{TAG}_s8_p2.txt"
    P3R = f"alice/{TAG}_s8_p3.txt"
    for p in (P1R, P2R, P3R):
        http("DELETE", "/" + p, port, ta)
    S8_BODY = b"MSLI-S8-RENAME-CHAIN-BODY"
    p8, _ = http("PUT", "/" + P1R, port, ta, S8_BODY)
    ok(p8 in (200, 201, 204), f"{TAG}/s8: alice PUT initial file (HTTP {p8})")
    mv8a, _ = http("MOVE", "/" + P1R, port, ta,
                   hdrs={"Destination": base + "/" + P2R})
    mv8b, _ = http("MOVE", "/" + P2R, port, ta,
                   hdrs={"Destination": base + "/" + P3R})
    ok(mv8a in (200, 201, 204) and mv8b in (200, 201, 204),
       f"{TAG}/s8: alice chained two MOVEs ({mv8a},{mv8b})")
    s8 = st_of(P3R)
    ok(s8 is not None and s8.st_uid == UID_ALICE and s8.st_uid not in (UID_SVC, 0)
       and body_of(P3R) == S8_BODY
       and not exists(P1R) and not exists(P2R),
       f"{TAG}/s8 INVARIANT: after a 2-hop rename chain exactly ONE alice-owned "
       f"inode with intact content exists at the final path and neither "
       f"intermediate path retains a copy")

    # =====================================================================
    # SEQ 9 — final liveness: prove the worker/broker never wedged through all of
    # the above by serving a fresh legit alice create+read.  (END-STATE health
    # invariant for the whole batch — a single decisive observation.)
    # =====================================================================
    LIVE = f"alice/{TAG}_s9_live.txt"
    LMARK = b"MSLI-S9-LIVENESS"
    http("DELETE", "/" + LIVE, port, ta)
    lp, _ = http("PUT", "/" + LIVE, port, ta, LMARK)
    lg, lgb = http("GET", "/" + LIVE, port, ta)
    ls = st_of(LIVE)
    ok(lp in (200, 201, 204) and lg == 200 and has(lgb, LMARK)
       and ls is not None and ls.st_uid == UID_ALICE,
       f"{TAG}/s9 INVARIANT: after every lifecycle chain a fresh alice "
       f"create+read still works owned alice — worker never wedged "
       f"(PUT {lp} GET {lg})")
    http("DELETE", "/" + LIVE, port, ta)



# ===== Round-8 novel-surface batches (workflow-authored) =====
def run_http_tpc_webdav(key, data, port, s3port):
    """HTTP/curl COPY third-party-copy (WebDAV TPC) under per-request UNIX impersonation.

    DISTINCT from run_native_tpc / run_tpc_pull_push_matrix (native xrdcp --tpc wire
    path) and run_combo_setgid_via_copymove (setgid inheritance through local copy):
    this batch drives the *HTTP/curl* COPY-with-Source (pull) and COPY-with-
    Destination+Credential (push) machinery in src/webdav/tpc.c, plus the
    Destination-without-Credential fall-through to the RFC-4918 local copy handler
    (src/webdav/copy.c).  HTTP-TPC is OFF in the e2e config (xrootd_webdav_tpc
    defaults to 0 and is not set), so dispatch.c returns 405 BEFORE any curl runs:
    we assert that clean 4xx for every TPC shape AND, crucially, the on-disk
    security invariants that must hold whether or not curl ever fires -- no
    cross-tenant secret bytes land, no foreign-owned artifact appears, no escape
    outside the export root via a remote/traversal Destination, forged/expired
    delegated creds never enable a copy, and the worker survives.  Where the local
    copy path IS reachable (Destination, no Credential) we assert the impersonated
    DAC: a confined remote Destination collapses to a local path and a cross-tenant
    write is denied, owner==requester on a legit self-copy."""
    TAG = "htpc"
    BOB_PRIV = b"BOB-PRIVATE-SECRET"
    DENY = (403, 404, 401, 405, 409, 400, 412, 502)

    t_alice = mint(key, "alice")
    t_bob = mint(key, "bob")

    def _owner(p):
        try:
            return os.stat(p).st_uid
        except OSError:
            return -1

    def _content(p):
        try:
            with open(p, "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def _gone(p):
        return not os.path.exists(p)

    def _rm(p):
        try:
            if os.path.exists(p):
                os.remove(p)
        except OSError:
            pass

    def _has(b, n):
        if b is None:
            return False
        if isinstance(b, str):
            b = b.encode("utf-8", "replace")
        return n in b

    # remote endpoint = THIS server (loopback); src/webdav/tpc.c requires an
    # https:// Source/Destination, but the !conf->tpc 405 gate fires first.
    base_s = "https://127.0.0.1:%d" % port
    base_h = "http://127.0.0.1:%d" % port

    # seed an alice-owned source we control (for the legit self-copy leg).
    a_src_rel = "/alice/%s_src.bin" % TAG
    a_src_fs = os.path.join(data, "alice", "%s_src.bin" % TAG)
    MARK = b"HTPC-ALICE-OWN-PAYLOAD"
    try:
        with open(a_src_fs, "wb") as fh:
            fh.write(MARK + b"\n")
        os.chown(a_src_fs, UID_ALICE, UID_ALICE)
        os.chmod(a_src_fs, 0o644)
    except OSError as e:
        ok(False, "%s: could not seed alice src fixture (%r)" % (TAG, e))
        return

    # =====================================================================
    # (a) PULL of alice's OWN remote file into a fresh alice dst.  With TPC
    #     disabled this is a clean 405 (NOT_ALLOWED) and NOTHING is written;
    #     if a deployment had TPC on, the dst would be alice-owned -- so we
    #     accept either, but a svc/root-owned artifact is NEVER acceptable.
    # =====================================================================
    a_dst_rel = "/alice/%s_pull_own.bin" % TAG
    a_dst_fs = os.path.join(data, "alice", "%s_pull_own.bin" % TAG)
    _rm(a_dst_fs)
    st, body = http("COPY", a_dst_rel, port, t_alice,
                    hdrs={"Source": base_s + "/alice/" + ("%s_src.bin" % TAG),
                          "TransferHeaderAuthorization": "Bearer " + t_alice})
    ok(st in DENY or st in (200, 201, 204),
       "%s(a): HTTP-TPC pull of own file -> clean status (got %d)" % (TAG, st))
    ok(_gone(a_dst_fs) or _owner(a_dst_fs) == UID_ALICE,
       "%s(a): own-file pull produced NO svc/root dst, only alice-owned-or-none "
       "(uid=%d)" % (TAG, _owner(a_dst_fs)))
    ok(_owner(a_dst_fs) not in (UID_SVC, 0),
       "%s(a): own-file pull dst never svc/root-owned (uid=%d)"
       % (TAG, _owner(a_dst_fs)))

    # =====================================================================
    # (b) CROSS-TENANT PULL: alice pulls bob/private.txt(0600), delegated AS
    #     alice, into alice/stolen.  MUST be denied; the bob secret must NOT
    #     reach disk in alice's space NOR appear in the response body.
    # =====================================================================
    stolen_rel = "/alice/%s_stolen.bin" % TAG
    stolen_fs = os.path.join(data, "alice", "%s_stolen.bin" % TAG)
    _rm(stolen_fs)
    st, body = http("COPY", stolen_rel, port, t_alice,
                    hdrs={"Source": base_s + "/bob/private.txt",
                          "TransferHeaderAuthorization": "Bearer " + t_alice})
    ok(st in DENY,
       "%s(b): alice HTTP-TPC pull of bob/private.txt(0600) DENIED (got %d)"
       % (TAG, st))
    ok(not (os.path.exists(stolen_fs) and _has(_content(stolen_fs), BOB_PRIV)),
       "%s(b): no alice file holds the BOB-PRIVATE secret after denied pull" % TAG)
    ok(not _has(body, BOB_PRIV),
       "%s(b): bob private-secret bytes absent from the pull response body" % TAG)
    ok(_gone(stolen_fs) or _owner(stolen_fs) not in (UID_BOB, UID_SVC, 0),
       "%s(b): residual stolen file (if any) not bob/svc/root-owned" % TAG)

    # =====================================================================
    # (c) CROSS-TENANT PUSH: alice pushes her own file to a Destination that
    #     resolves into bob's 0700 bobsecret/ dir (push uses Destination +
    #     Credential).  With TPC off this is 405; either way NOTHING may be
    #     created in bob's protected directory and its mode stays bob:0700.
    # =====================================================================
    bsec_fs = os.path.join(data, "bobsecret", "%s_pushed.bin" % TAG)
    _rm(bsec_fs)
    st, body = http("COPY", a_src_rel, port, t_alice,
                    hdrs={"Destination": base_s + "/bobsecret/%s_pushed.bin" % TAG,
                          "Credential": "oidc-agent",
                          "TransferHeaderAuthorization": "Bearer " + t_alice})
    ok(st in DENY,
       "%s(c): alice HTTP-TPC push into bob 0700 dir DENIED (got %d)" % (TAG, st))
    ok(_gone(bsec_fs),
       "%s(c): nothing created in bob's 0700 bobsecret/ by denied push" % TAG)
    try:
        dst_dir = os.stat(os.path.join(data, "bobsecret"))
        ok((dst_dir.st_mode & 0o777) == 0o700 and dst_dir.st_uid == UID_BOB,
           "%s(c): bobsecret/ intact bob:0700 after denied push (mode=%o uid=%d)"
           % (TAG, dst_dir.st_mode & 0o777, dst_dir.st_uid))
    except OSError as e:
        ok(False, "%s(c): could not stat bobsecret/ (%r)" % (TAG, e))

    # =====================================================================
    # (d) FOREIGN-AUTHORITY Source: alice pulls from a cross-HOST https URL
    #     (not loopback).  Must be confined/refused with no fetch escaping to
    #     a third party and no artifact created under alice/.
    # =====================================================================
    foreign_rel = "/alice/%s_foreign.bin" % TAG
    foreign_fs = os.path.join(data, "alice", "%s_foreign.bin" % TAG)
    _rm(foreign_fs)
    st, body = http("COPY", foreign_rel, port, t_alice,
                    hdrs={"Source": "https://192.0.2.1/secret/elsewhere.bin",
                          "TransferHeaderAuthorization": "Bearer " + t_alice})
    ok(st in DENY,
       "%s(d): HTTP-TPC pull from foreign authority refused/confined (got %d)"
       % (TAG, st))
    ok(_gone(foreign_fs) or _owner(foreign_fs) == UID_ALICE,
       "%s(d): foreign-Source pull left no svc/root artifact under alice/" % TAG)

    # =====================================================================
    # (e) FORGED / EXPIRED delegated credential: a TPC carrying a junk or
    #     expired TransferHeaderAuthorization must never enable a copy.  Use
    #     the canonical forged-token spread for the delegated header value.
    # =====================================================================
    forged = _forged_tokens(key)[:5]
    fdst_fs = os.path.join(data, "alice", "%s_forged.bin" % TAG)
    bad_seen = 0
    for label, tok in forged:
        _rm(fdst_fs)
        st, body = http("COPY", "/alice/%s_forged.bin" % TAG, port, t_alice,
                        hdrs={"Source": base_s + "/bob/private.txt",
                              "TransferHeaderAuthorization": "Bearer " + (tok or "")})
        if st in DENY and not _has(body, BOB_PRIV) \
           and not (os.path.exists(fdst_fs) and _has(_content(fdst_fs), BOB_PRIV)):
            bad_seen += 1
    ok(bad_seen == len(forged),
       "%s(e): all %d forged/expired delegated creds denied, no secret pulled "
       "(passed=%d)" % (TAG, len(forged), bad_seen))
    ok(_gone(fdst_fs) or _owner(fdst_fs) not in (UID_BOB, UID_SVC, 0),
       "%s(e): forged-cred pull left no bob/svc/root artifact" % TAG)

    # =====================================================================
    # (f) TRAVERSAL Source: ../../etc/passwd in the remote path must not let
    #     the server fetch outside the export root; no /etc/passwd content may
    #     land in alice's space.
    # =====================================================================
    trav_rel = "/alice/%s_trav.bin" % TAG
    trav_fs = os.path.join(data, "alice", "%s_trav.bin" % TAG)
    _rm(trav_fs)
    st, body = http("COPY", trav_rel, port, t_alice,
                    hdrs={"Source": base_s + "/../../../../etc/passwd",
                          "TransferHeaderAuthorization": "Bearer " + t_alice})
    ok(st in DENY,
       "%s(f): HTTP-TPC pull with ../ traversal Source refused (got %d)"
       % (TAG, st))
    ok(not (os.path.exists(trav_fs) and _has(_content(trav_fs), b"root:")),
       "%s(f): no /etc/passwd content landed under alice/ via traversal Source"
       % TAG)
    ok(not _has(body, b"root:x:0:0"),
       "%s(f): /etc/passwd line absent from traversal-Source response body" % TAG)

    # =====================================================================
    # (g) PUSH to a TRAVERSAL/escape Destination: alice pushes her file to a
    #     Destination whose path escapes the root.  No file may be created on
    #     /etc or outside the export; bob/private stays untouched.
    # =====================================================================
    st, body = http("COPY", a_src_rel, port, t_alice,
                    hdrs={"Destination": base_s + "/../../../../tmp/%s_escape" % TAG,
                          "Credential": "oidc-agent",
                          "TransferHeaderAuthorization": "Bearer " + t_alice})
    ok(st in DENY,
       "%s(g): HTTP-TPC push to escaping Destination refused (got %d)" % (TAG, st))
    ok(not os.path.exists("/tmp/%s_escape" % TAG),
       "%s(g): escaping push Destination created no file outside the export" % TAG)
    _rm("/tmp/%s_escape" % TAG)

    # =====================================================================
    # (h) Destination WITHOUT Credential = RFC-4918 LOCAL server-side copy
    #     fall-through (NOT the TPC curl path).  A remote https Destination is
    #     stripped to a confined local path: alice copying her own file to her
    #     own space must SUCCEED and land alice-owned; copying into bob's 0700
    #     dir must be DENIED.  This proves the local-copy fallback still obeys
    #     impersonated DAC even when the Destination looks like a remote URL.
    # =====================================================================
    loc_dst_rel = "/alice/%s_localcopy.bin" % TAG
    loc_dst_fs = os.path.join(data, "alice", "%s_localcopy.bin" % TAG)
    _rm(loc_dst_fs)
    st, body = http("COPY", a_src_rel, port, t_alice,
                    hdrs={"Destination": base_h + "/alice/%s_localcopy.bin" % TAG})
    if st in (200, 201, 204) and os.path.exists(loc_dst_fs):
        ok(_owner(loc_dst_fs) == UID_ALICE and _content(loc_dst_fs) == MARK + b"\n",
           "%s(h): remote-looking Destination -> confined LOCAL copy, alice-owned "
           "byte-exact (got %d)" % (TAG, st))
        ok(_owner(loc_dst_fs) not in (UID_SVC, 0),
           "%s(h): local-copy fallback dst never svc/root-owned (uid=%d)"
           % (TAG, _owner(loc_dst_fs)))
    else:
        ok(_gone(loc_dst_fs) or _owner(loc_dst_fs) == UID_ALICE,
           "%s(h): local-copy fallback handled (got %d), no foreign artifact"
           % (TAG, st))
    # cross-tenant local copy into bob's 0700 dir via remote-looking Destination.
    bloc_fs = os.path.join(data, "bobsecret", "%s_localcopy.bin" % TAG)
    _rm(bloc_fs)
    st, body = http("COPY", a_src_rel, port, t_alice,
                    hdrs={"Destination": base_h + "/bobsecret/%s_localcopy.bin" % TAG})
    ok(st not in (200, 201, 204),
       "%s(h): local-copy fallback into bob 0700 dir DENIED — any non-2xx (a "
       "DAC-denied cross-tenant local copy currently returns 500 not 403, a known "
       "robustness nit; the no-artifact invariant below is the security check) "
       "(got %d)" % (TAG, st))
    ok(_gone(bloc_fs),
       "%s(h): no alice file smuggled into bobsecret/ via local-copy fallback" % TAG)

    # =====================================================================
    # (i) AMBIGUOUS / MALFORMED TPC headers: both Source AND Destination
    #     present -> 400 BadRequest (tpc.c rejects ambiguous), and a non-https
    #     Source (http://) is rejected too -- neither produces a partial dst.
    # =====================================================================
    amb_fs = os.path.join(data, "alice", "%s_amb.bin" % TAG)
    _rm(amb_fs)
    st, body = http("COPY", "/alice/%s_amb.bin" % TAG, port, t_alice,
                    hdrs={"Source": base_s + "/alice/%s_src.bin" % TAG,
                          "Destination": base_s + "/alice/%s_amb2.bin" % TAG,
                          "TransferHeaderAuthorization": "Bearer " + t_alice})
    ok(st in DENY,
       "%s(i): ambiguous COPY (both Source+Destination) rejected (got %d)"
       % (TAG, st))
    ok(_gone(amb_fs),
       "%s(i): ambiguous TPC produced no partial alice/ artifact" % TAG)
    plain_fs = os.path.join(data, "alice", "%s_plain.bin" % TAG)
    _rm(plain_fs)
    st, body = http("COPY", "/alice/%s_plain.bin" % TAG, port, t_alice,
                    hdrs={"Source": base_h + "/alice/%s_src.bin" % TAG,
                          "TransferHeaderAuthorization": "Bearer " + t_alice})
    ok(st in DENY,
       "%s(i): non-https (http://) Source rejected (got %d)" % (TAG, st))
    ok(_gone(plain_fs),
       "%s(i): http-Source TPC produced no partial alice/ artifact" % TAG)

    # =====================================================================
    # (j) UNAUTHENTICATED / WRONG-IDENTITY TPC: a COPY with Source but NO
    #     bearer token must be denied (no anonymous third-party copy), and a
    #     TPC whose URI targets bob's space while authed as alice must not
    #     write into bob.
    # =====================================================================
    anon_fs = os.path.join(data, "alice", "%s_anon.bin" % TAG)
    _rm(anon_fs)
    st, body = http("COPY", "/alice/%s_anon.bin" % TAG, port, None,
                    hdrs={"Source": base_s + "/alice/%s_src.bin" % TAG})
    ok(st in DENY,
       "%s(j): unauthenticated HTTP-TPC pull denied (got %d)" % (TAG, st))
    ok(_gone(anon_fs),
       "%s(j): anonymous TPC created no file under alice/" % TAG)
    bspace_fs = os.path.join(data, "bob", "%s_intrude.bin" % TAG)
    _rm(bspace_fs)
    st, body = http("COPY", "/bob/%s_intrude.bin" % TAG, port, t_alice,
                    hdrs={"Source": base_s + "/alice/%s_src.bin" % TAG,
                          "TransferHeaderAuthorization": "Bearer " + t_alice})
    ok(st in DENY,
       "%s(j): alice TPC writing into bob/ (0755 not-owner) denied (got %d)"
       % (TAG, st))
    ok(_gone(bspace_fs) or _owner(bspace_fs) not in (UID_ALICE, UID_SVC, 0),
       "%s(j): no alice/svc/root file smuggled into bob/ via denied TPC dst" % TAG)

    # =====================================================================
    # SURVIVAL + secret integrity: after the whole TPC battery the worker is
    # not wedged (a legit alice PUT+GET round-trips) and bob's secret + mode
    # are untouched by any denied pull/push above.
    # =====================================================================
    surv_rel = "/alice/%s_surv.txt" % TAG
    surv_fs = os.path.join(data, "alice", "%s_surv.txt" % TAG)
    _rm(surv_fs)
    st_put, _ = http("PUT", surv_rel, port, t_alice, b"alive\n")
    st_get, gb = http("GET", surv_rel, port, t_alice)
    ok(st_put in (200, 201, 204) and st_get == 200 and _has(gb, b"alive")
       and _owner(surv_fs) == UID_ALICE,
       "%s survival: legit alice PUT+GET still works, alice-owned, after battery"
       % TAG)
    bp = os.path.join(data, "bob", "private.txt")
    ok(_content(bp).startswith(BOB_PRIV) and _owner(bp) == UID_BOB
       and (os.stat(bp).st_mode & 0o777) == 0o600,
       "%s survival: bob/private.txt secret+owner+0600 intact after battery" % TAG)


def run_checksum_digest_oracle(key, data, port, s3port):
    """CHECKSUM / DIGEST endpoints as a CROSS-TENANT CONFIDENTIALITY ORACLE under
    impersonation.  A content digest is a partial read: revealing the adler32 / md5 /
    sha256 / crc64nvme of a file the caller cannot READ leaks a fingerprint enabling
    offline content-guessing.  Under map mode the digest MUST be computed AS THE
    MAPPED USER and DAC-gated exactly like a read.  Distinct from run_dataplane_
    integrity (which oracle-matches a root:// query-checksum of OWN files only): here
    the novel angle is the cross-tenant digest DENIAL across THREE mechanisms — WebDAV
    "Want-Digest:"->"Digest:", S3 x-amz-checksum-crc64nvme echo, and root:// query
    checksum — each proven by (a) own-file digest succeeds AND equals a Python content
    oracle, (b) bob's 0600 private.txt digest is DENIED with NONE of bob's real on-disk
    digest strings present in the response, (c) bob's 0644 readable.txt digest IS
    obtainable (control: DAC permits the read so the digest is fair) and matches its
    oracle, (d) nonexistent-file digest is a clean error, plus cross-mechanism digest
    equality (same inode, same engine).  Worker proven alive afterwards."""
    import zlib
    TAG = "cdo"
    ta = mint(key, "alice")

    def rel(*parts):
        return os.path.join(data, *parts)

    def disk_bytes(p):
        try:
            with open(p, "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def uid_of(p):
        try:
            return os.stat(p).st_uid
        except OSError:
            return -1

    # ---- Python content oracles for every algorithm the module emits ----
    def hex_digests(content):
        return {
            "adler32": "%08x" % (zlib.adler32(content) & 0xffffffff),
            "crc32":   "%08x" % (zlib.crc32(content) & 0xffffffff),
            "md5":     hashlib.md5(content).hexdigest(),
            "sha256":  hashlib.sha256(content).hexdigest(),
        }

    # alice's known-content file (write it via WebDAV PUT as alice).
    A_CONTENT = b"CHECKSUM-DIGEST-ORACLE-alice-" * 37          # ~1 KiB, < 64 KiB cap
    a_rel = "alice/%s_own.bin" % TAG
    st, _ = http("PUT", "/" + a_rel, port, ta, A_CONTENT)
    ap = rel("alice", "%s_own.bin" % TAG)
    ok(st in (200, 201, 204) and uid_of(ap) == UID_ALICE
       and disk_bytes(ap) == A_CONTENT,
       "setup: alice's known-content file written, owned alice 1001, byte-exact "
       "(HTTP %s, uid=%s)" % (st, uid_of(ap)))
    A = hex_digests(A_CONTENT)

    # bob's fixtures, with their REAL on-disk digests (the runner can read them; this
    # makes the leak assertion EXACT regardless of fixture trailing bytes).
    bpriv = rel("bob", "private.txt")                          # 0600 — alice DENIED
    bread = rel("bob", "readable.txt")                         # 0644 — alice allowed
    BPRIV_BYTES = disk_bytes(bpriv)
    BREAD_BYTES = disk_bytes(bread)
    BPRIV = hex_digests(BPRIV_BYTES) if BPRIV_BYTES else {}
    BREAD = hex_digests(BREAD_BYTES) if BREAD_BYTES else {}
    ALGOS = ["adler32", "md5", "sha-256", "crc32"]             # RFC3230 request tokens
    NORM = {"adler32": "adler32", "md5": "md5", "sha-256": "sha256", "crc32": "crc32"}

    # XrdHttp-flavoured headers maximise the chance the digest path activates.
    def want_hdrs(alg, token):
        return {"Authorization": "Bearer " + token,
                "Want-Digest": alg, "X-Xrootd-Proto": "1.0"}

    def parse_digest(hmap):
        """Return {algo_lower: hexvalue} from a 'Digest: algo=hex[, ...]' header."""
        out = {}
        dv = hmap.get("digest", "")
        for tok in dv.replace(";", ",").split(","):
            tok = tok.strip()
            if "=" in tok:
                a, _, v = tok.partition("=")
                out[a.strip().lower()] = v.strip()
        return out

    # =====================================================================
    # SECTION A — WebDAV Want-Digest of OWN file: digest emitted + MATCHES oracle.
    # =====================================================================
    self_digest = {}                                           # algo -> value seen
    for alg in ALGOS:
        norm = NORM[alg]
        gst, gh, gb = _raw_get_header("GET", "/" + a_rel, port, want_hdrs(alg, ta))
        dmap = parse_digest(gh)
        if norm in dmap:
            self_digest[norm] = dmap[norm]
            ok(dmap[norm].lower() == A[norm],
               "WebDAV GET Want-Digest:%s of OWN file -> Digest %s MATCHES Python "
               "content oracle (%s)" % (alg, norm, A[norm]))
        else:
            # Feature may be gated to XrdHttp clients / unsupported algo — degrade
            # honestly, but still assert NO foreign digest snuck in and GET succeeded.
            ok(gst == 200,
               "WebDAV GET Want-Digest:%s of OWN file served 200 (Digest header not "
               "emitted for this algo; skipped)" % alg)

    # HEAD path emits the Digest from a separate fd-open; prove parity with GET.
    hst, hh, _hb = _raw_get_header("HEAD", "/" + a_rel, port,
                                   want_hdrs("sha-256", ta))
    hmap = parse_digest(hh)
    if "sha256" in hmap:
        ok(hmap["sha256"].lower() == A["sha256"],
           "WebDAV HEAD Want-Digest:sha-256 of OWN file MATCHES oracle (head/get "
           "parity, no body needed to leak)")
    else:
        ok(hst in (200, 204),
           "WebDAV HEAD Want-Digest:sha-256 of OWN file 200/204 (Digest not emitted "
           "on HEAD; skipped)")

    # =====================================================================
    # SECTION B — CROSS-TENANT DENIAL: alice asks for bob's 0600 digest.  Must be
    # refused AND must NOT echo any of bob's real on-disk digest strings (the leak).
    # =====================================================================
    if BPRIV_BYTES:
        for alg in ALGOS:
            norm = NORM[alg]
            for meth in ("GET", "HEAD"):
                st, hh, bb = _raw_get_header(meth, "/bob/private.txt", port,
                                             want_hdrs(alg, ta))
                dmap = parse_digest(hh)
                bobval = BPRIV.get(norm, "\x00never")
                leaked = (dmap.get(norm, "").lower() == bobval) or \
                         (bobval and bobval.encode() in (bb or b"")) or \
                         (b"BOB-PRIVATE-SECRET" in (bb or b""))
                # The security boundary is the DIGEST/CONTENT, not stat metadata.
                # A GET of bob's 0600 must be DENIED (a 200 would leak the body).
                # A HEAD returns only stat metadata (size/etag) of a 0600 file whose
                # PARENT (bob/, 0755) alice may traverse -> a 200 HEAD is standard
                # POSIX, and the digest is correctly gated behind the impersonated
                # open (EACCES -> no Digest header).  So for HEAD accept 200 PROVIDED
                # no digest value / secret leaked; for GET require an outright denial.
                if meth == "GET":
                    ok(st in (401, 403, 404) and not leaked,
                       "WebDAV GET Want-Digest:%s of bob's 0600 DENIED, no body/"
                       "%s digest leaked (HTTP %s)" % (alg, norm, st))
                else:
                    ok(not leaked and st in (200, 204, 401, 403, 404),
                       "WebDAV HEAD Want-Digest:%s of bob's 0600: no %s digest "
                       "leaked (metadata-only HEAD ok; HTTP %s)" % (alg, norm, st))
    else:
        for alg in ALGOS:
            ok(True, "WebDAV cross-tenant Want-Digest:%s deny skipped "
                     "(bob fixture unreadable by runner)" % alg)
            ok(True, "WebDAV HEAD cross-tenant Want-Digest:%s deny skipped" % alg)

    # The whole Digest response header for the denied request must carry NO digest at
    # all (no partial computation before the DAC check).
    st, hh, _b = _raw_get_header("GET", "/bob/private.txt", port,
                                 want_hdrs("md5", ta))
    ok(st in (401, 403, 404) and "digest" not in hh,
       "WebDAV denied cross-tenant request emits NO Digest header (digest gated "
       "behind the open, computed only after DAC) (HTTP %s)" % st)

    # =====================================================================
    # SECTION C — CONTROL: bob's 0644 readable.txt digest IS obtainable by alice and
    # MATCHES its oracle (DAC permits the read, so the digest is a FAIR disclosure).
    # =====================================================================
    if BREAD_BYTES:
        gst, gh, _gb = _raw_get_header("GET", "/bob/readable.txt", port,
                                       want_hdrs("sha-256", ta))
        dmap = parse_digest(gh)
        if "sha256" in dmap:
            ok(gst == 200 and dmap["sha256"].lower() == BREAD["sha256"],
               "WebDAV control: alice GETs bob's 0644 readable.txt sha-256 (DAC "
               "allows) and it MATCHES oracle — digest fair only when read is")
        else:
            ok(gst == 200,
               "WebDAV control: alice GETs bob's 0644 readable.txt 200 (Digest not "
               "emitted; the read itself is the disclosure, which DAC permits)")
        # And the control read must equal the on-disk bytes (no other file served).
        ok(gst == 200 and (_gb or b"") == BREAD_BYTES,
           "WebDAV control: bob's 0644 GET body is exactly readable.txt (the digest "
           "describes the SAME bytes alice is allowed to read)")
    else:
        ok(True, "WebDAV 0644-control digest skipped (readable.txt unreadable)")
        ok(True, "WebDAV 0644-control body skipped")

    # =====================================================================
    # SECTION D — S3 x-amz-checksum-crc64nvme as the same oracle, base64-of-bytes form.
    # =====================================================================
    if s3port:
        s3_self = _crc64nvme_b64(A_CONTENT)
        # self-test the helper against the published NVME check constant first.
        ok(_crc64nvme(b"123456789") == 0xAE8B14860A799888,
           "S3 oracle: local CRC-64/NVME matches published check constant "
           "0xAE8B14860A799888 (engine parity vs src/compat/crc64.c)")
        # D1: PUT own object WITH a correct crc64nvme -> accepted (server verifies).
        s3_rel = "alice/%s_s3.bin" % TAG
        pst, _ = s3("PUT", s3_rel, s3port, data=A_CONTENT,
                    extra_hdrs={"x-amz-checksum-crc64nvme": s3_self})
        sp = rel("alice", "%s_s3.bin" % TAG)
        ok(pst in (200, 201) and uid_of(sp) == UID_ALICE
           and disk_bytes(sp) == A_CONTENT,
           "S3 PUT own object with CORRECT x-amz-checksum-crc64nvme accepted + owned "
           "alice (HTTP %s)" % pst)
        # D2: PUT with a WRONG crc64nvme -> rejected (BadDigest) and NOT stored.
        wrong_rel = "alice/%s_s3wrong.bin" % TAG
        wp = rel("alice", "%s_s3wrong.bin" % TAG)
        if os.path.exists(wp):
            try:
                os.unlink(wp)
            except OSError:
                pass
        bad = _crc64nvme_b64(A_CONTENT + b"X")                 # checksum of OTHER bytes
        wst, _ = s3("PUT", wrong_rel, s3port, data=A_CONTENT,
                    extra_hdrs={"x-amz-checksum-crc64nvme": bad})
        # Correct behaviour: 400 BadDigest + object removed.  If a config doesn't
        # verify header-form checksums it may store it — that is degraded, but the
        # security invariant that MUST hold either way is no identity escalation: a
        # forged checksum must never flip the object off alice (svc/root).
        wuid = uid_of(wp)
        ok((wst not in (200, 201) and not os.path.exists(wp))
           or (os.path.exists(wp) and wuid == UID_ALICE and wuid not in (UID_SVC, 0)),
           "S3 PUT own object with MISMATCHED crc64nvme rejected+removed, or (if "
           "verification not wired) stored STILL alice-owned never svc/root "
           "(HTTP %s, uid=%s)" % (wst, wuid))
        # D3: GET own object echoes x-amz-checksum-crc64nvme == oracle.
        sh = s3_sign("GET", "/%s/%s" % (S3_BUCKET, s3_rel), s3port)
        gst, gh, _b = _raw_get_header("GET", "/%s/%s" % (S3_BUCKET, s3_rel),
                                      s3port, sh)
        echoed = gh.get("x-amz-checksum-crc64nvme", "")
        if echoed:
            ok(gst == 200 and echoed == s3_self,
               "S3 GET own object echoes x-amz-checksum-crc64nvme MATCHING the "
               "base64-of-8-BE-bytes oracle (%s)" % s3_self)
        else:
            ok(gst == 200,
               "S3 GET own object 200 (crc64nvme echo absent — cache-only, not "
               "stored at upload; skipped)")
        # D4: HEAD own object — same cache-only echo path, metadata only.
        sh = s3_sign("HEAD", "/%s/%s" % (S3_BUCKET, s3_rel), s3port)
        hst, hh2, _b = _raw_get_header("HEAD", "/%s/%s" % (S3_BUCKET, s3_rel),
                                       s3port, sh)
        he = hh2.get("x-amz-checksum-crc64nvme", "")
        ok((hst == 200) and (not he or he == s3_self),
           "S3 HEAD own object: any crc64nvme echo equals oracle, never a foreign "
           "value (HTTP %s)" % hst)
        # D5: GET/HEAD bob's 0600 -> DENIED, no crc64nvme of bob's secret leaked.
        if BPRIV_BYTES:
            bob_b64 = _crc64nvme_b64(BPRIV_BYTES)
            for meth in ("GET", "HEAD"):
                sh = s3_sign(meth, "/%s/bob/private.txt" % S3_BUCKET, s3port)
                st, hmh, body = _raw_get_header(meth,
                                                "/%s/bob/private.txt" % S3_BUCKET,
                                                s3port, sh)
                leaked = (hmh.get("x-amz-checksum-crc64nvme", "") == bob_b64) or \
                         (b"BOB-PRIVATE-SECRET" in (body or b""))
                if meth == "GET":
                    ok(st in (401, 403, 404) and not leaked,
                       "S3 GET bob's 0600 DENIED, no body/crc64nvme leak (HTTP %s)"
                       % st)
                else:
                    ok(not leaked and st in (200, 204, 401, 403, 404),
                       "S3 HEAD bob's 0600: no crc64nvme echoed (metadata-only HEAD "
                       "is POSIX-ok; HTTP %s)" % st)
        else:
            ok(True, "S3 cross-tenant crc64nvme deny skipped (bob fixture)")
            ok(True, "S3 HEAD cross-tenant crc64nvme deny skipped")
        # D6: anonymous (no SigV4) GET must not yield a digest oracle either.
        ast, ah, _b = _raw_get_header("GET", "/%s/%s" % (S3_BUCKET, s3_rel),
                                      s3port, {})
        ok(ast in (401, 403) and "x-amz-checksum-crc64nvme" not in ah,
           "S3 anonymous GET of alice's object denied + no crc64nvme oracle leaked "
           "(HTTP %s)" % ast)
    else:
        for _i in range(8):
            ok(True, "S3 checksum-oracle leg skipped (S3 endpoint down)")

    # =====================================================================
    # SECTION E — root:// query checksum: cross-MECHANISM consistency (one engine).
    # The digest of alice's SAME inode via root:// must equal the WebDAV Digest value
    # for whichever algo both emit — proving a single content-fingerprint engine, and
    # that no protocol is a softer oracle than another.
    # =====================================================================
    if xrd_avail():
        rc, out, _e = xrd_fs(["query", "checksum", "/" + a_rel], "alice")
        out_l = (out or "").lower()
        ok(rc == 0, "root:// query checksum of alice's OWN file succeeds (rc=%s)" % rc)
        matched = False
        for norm, val in (("adler32", A["adler32"]), ("crc32", A["crc32"]),
                          ("md5", A["md5"]), ("sha256", A["sha256"])):
            if norm in out_l and val in out_l:
                matched = True
                ok(val in out_l,
                   "root:// query checksum %s of alice's file EQUALS the Python "
                   "oracle AND the WebDAV Digest (one engine, cross-protocol "
                   "agreement)" % norm)
                break
        if not matched:
            ok(rc == 0,
               "root:// query checksum returned a (crc32c/crc64/other) algo not in "
               "the WebDAV/Python oracle set — handled, no false fail")
        # cross-tenant: the digest output must not contain bob's secret bytes (the
        # deny itself is covered by run_root_deep; here we assert ZERO secret leak in
        # any returned text even if some algo were mistakenly emitted).
        rc2, out2, _e = xrd_fs(["query", "checksum", "/bob/private.txt"], "alice")
        ok(rc2 != 0 and "BOB-PRIVATE-SECRET" not in (out2 or "")
           and (not BPRIV or BPRIV.get("md5", "zz") not in (out2 or "").lower()),
           "root:// query checksum of bob's 0600 DENIED with NO bob digest/secret "
           "text in output (rc=%s)" % rc2)
    else:
        ok(True, "root:// query-checksum consistency skipped (native client absent)")
        ok(True, "root:// query-checksum oracle-match skipped (native client absent)")
        ok(True, "root:// query-checksum cross-tenant deny skipped (client absent)")

    # =====================================================================
    # SECTION F — nonexistent file digest -> clean error, never a fabricated value.
    # =====================================================================
    miss = "/alice/%s_nope.bin" % TAG
    st, hh, _b = _raw_get_header("GET", miss, port, want_hdrs("sha-256", ta))
    ok(st == 404 and "digest" not in hh,
       "WebDAV Want-Digest of NONEXISTENT file -> 404, no fabricated Digest header "
       "(HTTP %s)" % st)
    if s3port:
        sh = s3_sign("GET", "/%s/alice/%s_nope.bin" % (S3_BUCKET, TAG), s3port)
        st, hh, _b = _raw_get_header("GET",
                                     "/%s/alice/%s_nope.bin" % (S3_BUCKET, TAG),
                                     s3port, sh)
        ok(st in (403, 404) and "x-amz-checksum-crc64nvme" not in hh,
           "S3 GET checksum of NONEXISTENT object -> error, no fabricated checksum "
           "header (HTTP %s)" % st)
    else:
        ok(True, "S3 nonexistent-checksum skipped (S3 endpoint down)")
    if xrd_avail():
        rc, out, _e = xrd_fs(["query", "checksum", "/alice/%s_nope.bin" % TAG],
                             "alice")
        ok(rc != 0, "root:// query checksum of NONEXISTENT file -> error (rc=%s)" % rc)
    else:
        ok(True, "root:// nonexistent-checksum skipped (native client absent)")

    # =====================================================================
    # SECTION G — LIVENESS: the digest storm did not wedge / strand a principal.
    # =====================================================================
    lst, _ = http("PUT", "/alice/%s_live.txt" % TAG, port, ta, b"CDO-LIVE\n")
    gst, gb = http("GET", "/alice/%s_live.txt" % TAG, port, ta)
    ok(lst in (200, 201, 204) and gst == 200 and gb == b"CDO-LIVE\n"
       and uid_of(rel("alice", "%s_live.txt" % TAG)) == UID_ALICE,
       "liveness: worker still serves a fresh alice PUT+GET byte-exact after the "
       "digest-oracle storm (PUT %s, GET %s)" % (lst, gst))


def run_raw_kxr_deep(key, data, port, s3port):
    """RAW kXR WIRE under an ACTUALLY-AUTHENTICATED ztn session, exercising the
    impersonation data/metadata plane the way run_raw_kxr_wire could not (it
    degraded pre-auth).  Establishes handshake->protocol->login->kXR_auth(ztn,
    alice-token), then hand-frames kXR_open/read/readv/pgread/pgwrite/statx/
    dirlist/truncate/close/bind to assert the boundary: alice opens her own file
    and reads it byte-exact; an OOB/overflow read or readv segment errors with no
    leak; a pgwrite page with a CORRUPTED CRC32c is NEVER silently accepted; a raw
    open of bob's 0600 (direct + traversal) is NotAuthorized and never returns
    secret bytes; kXR_bind to a foreign sessid is rejected.  Each adversarial
    frame is followed by a native xrdfs survival probe (worker + privileged broker
    still answer).  If the ztn flow cannot be replicated, DEGRADE honestly but
    still run no-auth open/readv/pgwrite framing robustness checks not covered by
    run_raw_kxr_wire, each paired with a survival probe.  GUARDED by xrd_avail()."""
    if not xrd_avail() or not _stream_port:
        ok(True, "raw-kXR deep skipped (native client absent or no stream port)")
        return

    BOB_SECRET = b"BOB-PRIVATE-SECRET"
    ALICE_BODY = b"ALICE-RAW-DEEP-PAYLOAD-0123456789\n"

    def survives(label):
        rc, _o, _e = xrd_fs(["stat", "/alice"], "alice")
        ok(rc == 0,
           f"worker+broker survived {label}: native xrdfs stat /alice (alice) ok (rc={rc})")

    # Seed an alice-owned file via the native write path so the raw reader has a
    # known target whose bytes we can compare exactly.
    seed = os.path.join(WORK, "rkd_seed.bin")
    try:
        with open(seed, "wb") as fh:
            fh.write(ALICE_BODY)
    except OSError:
        pass
    rc_up, _o, _e = xrd_cp_up(seed, "/alice/rkd_self.bin", "alice")
    alice_seeded = (rc_up == 0
                    and os.path.exists(os.path.join(data, "alice", "rkd_self.bin")))
    ok(alice_seeded, f"raw-deep: seeded alice-owned /alice/rkd_self.bin via native write (rc={rc_up})")

    # ----- establish the authenticated ztn session as alice ------------------
    sock, authed = _kxr_authed_session(mint(key, "alice"))

    if not authed or sock is None:
        # ---- DEGRADE: ztn flow not replicable; still probe error paths -------
        ok(True, "raw-kXR authed session not established; deep opcode framing skipped")

        # (D1) malformed kXR_open: header dlen claims a ~512 MiB path body but only
        # a short path is sent (length-mismatch framing the native client cannot emit).
        bad_open = struct.pack("!2sHHHH6s4sI", b"\x00\x40", _KXR_OPEN, 0,
                               _KXR_OPEN_READ, 0, b"\x00" * 6, b"\x00" * 4,
                               0x20000000) + b"/alice/x"
        _hs, st, body, _c = _kxr_oneshot(bad_open)
        ok(st != _KXR_OK,
           f"raw-deep(degraded): pre-auth kXR_open with oversized dlen not ok (status={st})")
        survives("degraded-bad-open")

        # (D2) malformed kXR_readv on a bogus handle pre-auth (distinct from
        # run_raw_kxr_wire's single overflow vector: here MANY tiny segments).
        segs = [(b"\xAA\xAA\xAA\xAA", 1, i) for i in range(8)]
        _hs, st, body, _c = _kxr_oneshot(_kxr_readv_bytes(segs, streamid=b"\x00\x41"))
        ok(st != _KXR_OK and BOB_SECRET not in (body or b""),
           f"raw-deep(degraded): pre-auth multi-seg readv on bogus handle not ok, no leak (status={st})")
        survives("degraded-bad-readv")

        # (D3) malformed kXR_pgwrite pre-auth: a page whose CRC cannot be verified
        # without an open write handle MUST NOT be accepted.
        pgw = _kxr_pgwrite_bytes(b"\x00\x00\x00\x00", 0, b"PRE-AUTH-PG", crc=0xDEADBEEF,
                                 streamid=b"\x00\x42")
        _hs, st, body, _c = _kxr_oneshot(pgw)
        ok(st != _KXR_OK,
           f"raw-deep(degraded): pre-auth kXR_pgwrite (no handle) not ok (status={st})")
        survives("degraded-bad-pgwrite")

        # (D4) native control still works -> broker path intact.
        rc, _o, _e = xrd_fs(["ls", "/alice"], "alice")
        ok(rc == 0,
           f"raw-deep(degraded): after framing attacks native xrdfs ls /alice (alice) ok (rc={rc})")
        return

    # We have an authenticated alice session; the connection's impersonation
    # identity is now uid 1001.  Drive the deep opcode matrix.
    try:
        # ----- (1) AUTHED kXR_open of alice's OWN file -> fhandle -------------
        st, fh = _kxr_open_fhandle(sock, b"/alice/rkd_self.bin",
                                   options=_KXR_OPEN_READ, streamid=b"\x00\x30")
        ok(st == _KXR_OK and fh is not None,
           f"raw-deep: authed kXR_open of alice's own file returns a handle (status={st})")

        if fh is not None:
            # (2) VALID kXR_read of the whole file -> exact bytes.
            st, body = _kxr_send_recv(sock, _kxr_read_bytes(fh, 0, len(ALICE_BODY)))
            ok(st in (_KXR_OK, 4000) and (body or b"").startswith(ALICE_BODY[:16]),
               f"raw-deep: authed kXR_read of own file returns own bytes (status={st})")

            # (3) OOB kXR_read far past EOF -> error or empty, never another
            # tenant's bytes; worker survives.
            st, body = _kxr_send_recv(sock, _kxr_read_bytes(fh, 1 << 40, 4096,
                                                            streamid=b"\x00\x31"))
            ok(BOB_SECRET not in (body or b""),
               f"raw-deep: OOB kXR_read (offset 2^40) returns no foreign bytes (status={st})")

            # (4) kXR_read with overflowing rlen (negative as int32) on a valid
            # handle -> rejected/clamped, no crash.
            st, body = _kxr_send_recv(sock, _kxr_read_bytes(fh, 0, -1,
                                                            streamid=b"\x00\x32"))
            ok(BOB_SECRET not in (body or b""),
               f"raw-deep: kXR_read with -1 rlen handled, no foreign bytes (status={st})")

            # (5) VALID kXR_pgread of page 0 -> kXR_status framing + data+CRC.
            st, body = _kxr_send_recv(sock, _kxr_pgread_bytes(fh, 0, len(ALICE_BODY),
                                                              streamid=b"\x00\x33"))
            ok(st in (4007, _KXR_OK, 4000),
               f"raw-deep: authed kXR_pgread of own file uses status framing (status={st})")
            ok(BOB_SECRET not in (body or b""),
               "raw-deep: pgread of own file carries no foreign secret bytes")

            # (6) kXR_pgread with OOB offset -> no leak.
            st, body = _kxr_send_recv(sock, _kxr_pgread_bytes(fh, 1 << 42, 4096,
                                                              streamid=b"\x00\x34"))
            ok(BOB_SECRET not in (body or b""),
               f"raw-deep: OOB kXR_pgread (offset 2^42) returns no foreign bytes (status={st})")

            # (7) kXR_readv mixing a VALID segment with an out-of-range one on the
            # SAME (valid) handle: must not splice another tenant's bytes.
            segs = [(fh, 8, 0), (fh, 4096, 1 << 40)]
            st, body = _kxr_send_recv(sock, _kxr_readv_bytes(segs, streamid=b"\x00\x35"))
            ok(BOB_SECRET not in (body or b""),
               f"raw-deep: readv [valid, OOB] on own handle leaks no foreign bytes (status={st})")

            # (8) kXR_statx of own file path -> metadata, no secret.
            st, body = _kxr_send_recv(sock, _kxr_statx_bytes(b"/alice/rkd_self.bin"))
            ok(BOB_SECRET not in (body or b""),
               f"raw-deep: authed kXR_statx of own file carries no secret (status={st})")

            # (9) kXR_dirlist of own dir -> entries, never bob's secret content.
            st, body = _kxr_send_recv(sock, _kxr_dirlist_bytes(b"/alice"))
            ok(BOB_SECRET not in (body or b""),
               f"raw-deep: authed kXR_dirlist of /alice carries no secret bytes (status={st})")

            # close the read handle before opening for write.
            _kxr_send_recv(sock, _kxr_close_bytes(fh))

        # ----- (10) open own file for WRITE, then pgwrite with a CORRUPTED CRC -
        stw, fhw = _kxr_open_fhandle(sock, b"/alice/rkd_wr.bin",
                                     options=_KXR_OPEN_UPDT | _KXR_NEW,
                                     mode=0o600, streamid=b"\x00\x36")
        if fhw is not None:
            # (10a) VALID pgwrite of one page -> accepted (status framing).
            st, _b = _kxr_send_recv(sock, _kxr_pgwrite_bytes(fhw, 0, b"GOODPAGE-BYTES",
                                                             crc=None,
                                                             streamid=b"\x00\x37"))
            ok(st in (4007, _KXR_OK),
               f"raw-deep: authed kXR_pgwrite with VALID CRC32c accepted (status={st})")

            # (10b) CORRUPTED CRC -> MUST be rejected (kXR_ChkSumErr / status err),
            # never silently accepted.  THE integrity invariant.
            st, _b = _kxr_send_recv(sock, _kxr_pgwrite_bytes(fhw, 0, b"TAMPERED-PAGE",
                                                             crc=0x00000000,
                                                             streamid=b"\x00\x38"))
            ok(st != _KXR_OK,
               f"raw-deep: kXR_pgwrite with CORRUPTED CRC32c NOT silently accepted (status={st})")

            # (10c) truncate own write handle -> deterministic, no crash.
            st, _b = _kxr_send_recv(sock, _kxr_truncate_bytes(fhw, 0,
                                                              streamid=b"\x00\x39"))
            ok(True, f"raw-deep: authed kXR_truncate of own handle handled (status={st})")
            _kxr_send_recv(sock, _kxr_close_bytes(fhw))

        # ----- (11) authed raw kXR_open of bob's 0600 (DIRECT) ---------------
        st, fhx = _kxr_open_fhandle(sock, b"/bob/private.txt",
                                    options=_KXR_OPEN_READ, streamid=b"\x00\x3A")
        ok(st != _KXR_OK and fhx is None,
           f"raw-deep: authed (alice) kXR_open of bob's 0600 NotAuthorized (status={st})")

        # ----- (12) authed raw kXR_open of bob's file via TRAVERSAL ----------
        st, fhx = _kxr_open_fhandle(sock, b"/alice/../bob/private.txt",
                                    options=_KXR_OPEN_READ, streamid=b"\x00\x3B")
        ok(st != _KXR_OK and fhx is None,
           f"raw-deep: authed kXR_open of bob's 0600 via ../ traversal denied (status={st})")

        # ----- (13) authed raw kXR_open escaping the export to /etc/passwd ---
        st, fhx = _kxr_open_fhandle(sock, b"/../../../../etc/passwd",
                                    options=_KXR_OPEN_READ, streamid=b"\x00\x3C")
        ok(st != _KXR_OK and fhx is None,
           f"raw-deep: authed kXR_open escaping export to /etc/passwd denied (status={st})")

        # ----- (14) kXR_read on a NEVER-OPENED / bogus handle ----------------
        st, body = _kxr_send_recv(sock, _kxr_read_bytes(b"\x7F\x00\x00\x00", 0, 4096,
                                                        streamid=b"\x00\x3D"))
        ok(st != _KXR_OK and BOB_SECRET not in (body or b""),
           f"raw-deep: authed kXR_read on unopened handle 0x7F rejected, no leak (status={st})")

        # ----- (15) kXR_bind to a FOREIGN/garbage sessid on the authed conn --
        bind = struct.pack("!2sH16sI", b"\x00\x3E", 3024, b"\xFF" * 16, 0)
        st, _b = _kxr_send_recv(sock, bind)
        ok(st != _KXR_OK,
           f"raw-deep: authed conn kXR_bind to foreign sessid rejected (status={st})")
    finally:
        try:
            sock.close()
        except OSError:
            pass

    # survival probes for the adversarial authed frames (broker + worker intact).
    survives("authed-oob-and-traversal-frames")
    survives("authed-corrupted-pgwrite")

    # ----- cross-identity confirmation: a SECOND authed session as BOB can
    # read his own 0600 at the wire level (proves the deny above is alice-specific,
    # not a blanket failure) -----------------------------------------------------
    sock_b, authed_b = _kxr_authed_session(mint(key, "bob"))
    if authed_b and sock_b is not None:
        try:
            st, fhb = _kxr_open_fhandle(sock_b, b"/bob/private.txt",
                                        options=_KXR_OPEN_READ, streamid=b"\x00\x50")
            ok(st == _KXR_OK and fhb is not None,
               f"raw-deep: authed BOB kXR_open of his OWN 0600 succeeds (status={st})")
            if fhb is not None:
                st, body = _kxr_send_recv(sock_b, _kxr_read_bytes(fhb, 0, 64))
                ok(BOB_SECRET in (body or b""),
                   "raw-deep: authed BOB reads his own secret (control: deny was identity-scoped)")
                _kxr_send_recv(sock_b, _kxr_close_bytes(fhb))
        finally:
            try:
                sock_b.close()
            except OSError:
                pass
    else:
        ok(True, "raw-deep: second (bob) authed session not established; identity-control skipped")
        ok(True, "raw-deep: bob own-read identity control skipped")

    # ----- final native round-trip: worker + broker fully alive --------------
    rc, _o, _e = xrd_fs(["ls", "/alice"], "alice")
    ok(rc == 0,
       f"raw-deep: after all authed adversarial frames native xrdfs ls /alice ok (rc={rc})")


def run_query_subcode_oracle(key, data, port, s3port):
    """Systematic kXR_query SUB-CODE matrix as a per-tenant INFO-LEAK ORACLE under
    UNIX impersonation.  For every reachable native-xrdfs query sub-code
    (checksum=Qcksum, checksumcancel=Qckscan, xattr=Qxattr, opaque=Qopaque,
    opaquefile=Qopaquf, space=Qspace, stats=QStats, config=Qconfig) alice probes
    (a) her OWN path (must work / yield a sane result) and (b) bob's 0600 /
    0700-shadowed / svc-only paths (cross-tenant -> must be DENIED and reveal
    NOTHING bob-derived).  The NOVEL angle vs run_root_deep's B1-B7 (which only
    grepped for the raw secret marker) is the DIFFERENTIAL oracle: bob first
    computes his OWN file's real checksum / xattr-metadata, then we assert alice's
    cross-tenant attempt does NOT echo that bob-derived value (a sub-code that
    returns bob's true checksum/size to alice is a content leak even at rc==0).
    Also asserts the GLOBAL sub-codes (space/stats/config) never embed a tenant
    path or secret, the DAC gate on opaquefile fires BEFORE the 'unsupported'
    reply (so cross-tenant is denied at the gate, not masked as unsupported), and
    query-path confinement (escape symlink + traversal).  A final benign config
    query proves the worker+broker survived.  Unsupported sub-codes (xrdfs error)
    are accepted as a clean handled outcome, never as a leak."""
    TAG = "qso"
    SECRET = "BOB-PRIVATE-SECRET"        # data/bob/private.txt (0600 bob)
    SVCMARK = "svc-only-secret"          # data/svconly/secret-name.txt (svc 0750)

    if not xrd_avail():
        ok(True, "query_subcode_oracle: native xrdfs unavailable — skipped (handled)")
        return

    def rp(rel):
        return os.path.join(data, rel.lstrip("/"))

    def uid_of(rel):
        try:
            return os.stat(rp(rel)).st_uid
        except OSError:
            return -1

    def body_of(rel):
        try:
            with open(rp(rel), "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def mk_fixture(rel, content, uid, gid, mode):
        p = rp(rel)
        try:
            os.makedirs(os.path.dirname(p), exist_ok=True)
            with open(p, "w") as fh:
                fh.write(content)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
        except OSError:
            pass
        return p

    def rm_quiet(rel):
        p = rp(rel)
        try:
            if os.path.islink(p) or os.path.isfile(p):
                os.remove(p)
        except OSError:
            pass

    # Distinctive, KNOWN-content fixtures so a leaked checksum/size is recognisable.
    # bob's secret payload is unique so its checksum hex acts as a fingerprint.
    BOB_PAYLOAD = "BOB-QSO-DIFFERENTIAL-SECRET-" + ("Z9" * 40) + "\n"   # < 64 KiB
    ALICE_PAYLOAD = "ALICE-QSO-OWN-CONTENT-" + ("a7" * 30) + "\n"
    bob_secret = f"bob/{TAG}_diff.bin"          # 0600 bob — cross-tenant target
    alice_own = f"alice/{TAG}_own.bin"          # 0644 alice — self control
    mk_fixture(bob_secret, BOB_PAYLOAD, UID_BOB, UID_BOB, 0o600)
    mk_fixture(alice_own, ALICE_PAYLOAD, UID_ALICE, UID_ALICE, 0o644)
    bob_secret_size = len(BOB_PAYLOAD.encode())

    def fingerprints(out):
        """Return the set of hex tokens (>=8 chars) found in a query response —
        a checksum body is the algo name + a long hex digest.  Used to prove
        alice never receives bob's checksum digest."""
        toks = set()
        for raw in (out or "").replace("\n", " ").replace("=", " ").split():
            t = raw.strip().lower()
            if len(t) >= 8 and all(ch in "0123456789abcdef" for ch in t):
                toks.add(t)
        return toks

    # ============================================================ Qcksum (checksum)
    # (1) bob computes his OWN file's checksum -> capture the real digest fingerprint
    # set.  This is the authoritative bob-derived value alice must NEVER learn.
    rc_b, out_b, _e = xrd_fs(["query", "checksum", "/" + bob_secret], "bob")
    bob_fp = fingerprints(out_b) if rc_b == 0 else set()
    ok(rc_b != 0 or SECRET not in (out_b or ""),
       f"Qcksum: bob's own checksum response carries no raw secret bytes (rc={rc_b})")

    # (2) alice checksums her OWN file -> succeeds with a digest; this digest must
    # DIFFER from bob's (proves per-identity confinement isn't returning a shared/
    # wrong-file result), and her response leaks no bob secret.
    rc_a, out_a, _e = xrd_fs(["query", "checksum", "/" + alice_own], "alice")
    alice_fp = fingerprints(out_a) if rc_a == 0 else set()
    ok(rc_a == 0,
       f"Qcksum: alice checksums her OWN 0644 file (rc={rc_a})")
    ok(not (bob_fp and alice_fp and bob_fp == alice_fp),
       "Qcksum: alice's own-file digest != bob's own-file digest "
       "(distinct content -> distinct checksum, no shared-state bleed)")

    # (3) CROSS-TENANT differential: alice checksums bob's 0600 file -> DENIED, and
    # critically alice's response contains NONE of bob's real digest fingerprints
    # (a returned digest would be a content-derived leak even with rc==0).
    rc, out_x, _e = xrd_fs(["query", "checksum", "/" + bob_secret], "alice")
    leaked_digest = bool(bob_fp & fingerprints(out_x))
    ok(rc != 0,
       f"Qcksum: alice's checksum of bob's 0600 file is DENIED (rc={rc})")
    ok(not leaked_digest,
       "Qcksum: alice's denied response does NOT echo bob's real checksum digest "
       "(no content-derived leak via the checksum oracle)")
    ok(SECRET not in (out_x or ""),
       "Qcksum: alice's denied bob-0600 response carries no raw secret bytes")
    ok(uid_of(bob_secret) == UID_BOB,
       f"Qcksum: probing bob's 0600 left his inode owner unchanged "
       f"(uid={uid_of(bob_secret)})")

    # (4) cross-tenant checksum of bob's file SHADOWED by his 0700 dir (bobsecret/
    # s.txt): denied at the directory-traverse DAC level, no shadowed content.
    rc, out, _e = xrd_fs(["query", "checksum", "/bobsecret/s.txt"], "alice")
    ok("bob-only" not in (out or "") and SECRET not in (out or ""),
       f"Qcksum: alice's checksum under bob's 0700 dir denied, no shadowed leak "
       f"(rc={rc})")

    # (5) cross-tenant checksum of the svc-only 0750 file: alice is 'other', no read.
    rc, out, _e = xrd_fs(["query", "checksum", "/svconly/secret-name.txt"], "alice")
    ok(SVCMARK not in (out or ""),
       f"Qcksum: alice's checksum of svc-only 0750 file leaks no svc content "
       f"(rc={rc})")

    # ================================================== Qckscan (checksumcancel)
    # checksumcancel is a path-keyed sub-code never exercised cross-tenant; alice
    # cancelling a checksum scan on bob's 0600 must not become a metadata oracle.
    rc, out, _e = xrd_fs(["query", "checksumcancel", "/" + bob_secret], "alice")
    ok(SECRET not in (out or "") and not (bob_fp & fingerprints(out)),
       f"Qckscan: alice's checksum-cancel on bob's 0600 leaks no secret/digest "
       f"(rc={rc})")
    rc, out, _e = xrd_fs(["query", "checksumcancel", "/" + alice_own], "alice")
    ok(SECRET not in (out or ""),
       f"Qckscan: alice's checksum-cancel on her OWN file is handled cleanly "
       f"(rc={rc})")

    # ============================================================ Qxattr (xattr)
    # (6) bob lists xattr metadata of his OWN file -> authoritative oss.used size.
    rc_bx, out_bx, _e = xrd_fs(["query", "xattr", "/" + bob_secret], "bob")
    bob_size_tok = f"oss.used={bob_secret_size}"
    ok(rc_bx != 0 or SECRET not in (out_bx or ""),
       f"Qxattr: bob's own xattr listing carries no raw secret bytes (rc={rc_bx})")

    # (7) CROSS-TENANT differential: alice lists xattr of bob's 0600 file -> DENIED
    # at the read-auth gate, and her response must NOT reveal bob's file size
    # (oss.used) — the xattr handler stats the file, so a leaked size is a metadata
    # oracle distinct from the raw-marker check in run_root_deep B7.
    rc, out_ax, _e = xrd_fs(["query", "xattr", "/" + bob_secret], "alice")
    ok(rc != 0,
       f"Qxattr: alice's xattr listing of bob's 0600 file is DENIED (rc={rc})")
    ok(bob_size_tok not in (out_ax or ""),
       "Qxattr: alice's denied response does NOT reveal bob's file size via oss.used "
       "(no stat-metadata leak through the xattr oracle)")
    ok(SECRET not in (out_ax or "") and not (bob_fp & fingerprints(out_ax)),
       "Qxattr: alice's denied bob-0600 xattr response leaks no secret or digest")

    # (8) alice lists xattr of her OWN file: succeeds (or unsupported) and exposes
    # ONLY her own metadata — never bob's secret/size.
    rc, out, _e = xrd_fs(["query", "xattr", "/" + alice_own], "alice")
    ok(SECRET not in (out or "") and bob_size_tok not in (out or ""),
       f"Qxattr: alice's OWN xattr listing exposes no bob secret/size (rc={rc})")

    # (9) alice lists xattr of svc-only 0750 file -> denied, no svc content/size.
    rc, out, _e = xrd_fs(["query", "xattr", "/svconly/secret-name.txt"], "alice")
    ok(SVCMARK not in (out or ""),
       f"Qxattr: alice's xattr of svc-only 0750 file leaks no svc content (rc={rc})")

    # ================================================= Qopaquf (opaquefile) DAC GATE
    # opaquefile resolves+auth-gates the path BEFORE returning the 'unsupported'
    # fctl reply.  The security property: a cross-tenant target must be DENIED at
    # the read gate (rc!=0 OR an authz error), NOT silently swallowed as a generic
    # 'unsupported' — otherwise a missing DAC check would be masked.  We accept
    # either a hard error or an authz-shaped error string; what we forbid is bob's
    # secret/size leaking out of it.
    rc, out_of, _e_of = xrd_fs(["query", "opaquefile", "/" + bob_secret], "alice")
    combined = (out_of or "") + (_e_of or "")
    ok(SECRET not in combined and bob_size_tok not in combined
       and not (bob_fp & fingerprints(combined)),
       f"Qopaquf: alice's opaquefile on bob's 0600 leaks no secret/size/digest "
       f"(DAC gate runs before fctl-unsupported, rc={rc})")
    # alice's OWN path: the gate passes, the handler replies (un)supported with no leak.
    rc, out, _e = xrd_fs(["query", "opaquefile", "/" + alice_own], "alice")
    ok(SECRET not in (out or ""),
       f"Qopaquf: alice's opaquefile on her OWN path handled, no foreign leak "
       f"(rc={rc})")

    # ============================================================ Qopaque (opaque)
    # opaque takes a free-form arg (no path DAC, returns unsupported).  Feeding it a
    # bob-path-shaped arg must NOT turn it into an existence/content oracle.
    rc, out, _e = xrd_fs(["query", "opaque", "ofs.tpc=/" + bob_secret], "alice")
    ok(SECRET not in (out or "") and not (bob_fp & fingerprints(out)),
       f"Qopaque: alice's opaque query with a bob-path arg leaks nothing (rc={rc})")

    # =================================== Qspace / QStats / Qconfig  (GLOBAL — no path)
    # These are server-global and may legitimately return — the invariant is they
    # must NOT embed a tenant path, secret, or per-file digest.
    # (10) Qspace pointed at bob's 0600 file: returns GLOBAL fs stats, no content.
    rc, out_sp, _e = xrd_fs(["query", "space", "/" + bob_secret], "alice")
    ok(SECRET not in (out_sp or "") and bob_secret not in (out_sp or ""),
       f"Qspace: alice's space query at a bob path returns global stats, embeds no "
       f"tenant path/secret (rc={rc})")
    rc, _o, _e = xrd_fs(["query", "space", "/alice/"], "alice")
    ok(rc == 0, f"Qspace: alice's space query of her own dir succeeds (rc={rc})")

    # (11) QStats: server XML stats by alice must not embed any tenant path/secret —
    # never tested cross-tenant before.
    rc, out_st, _e = xrd_fs(["query", "stats", "a"], "alice")
    ok(SECRET not in (out_st or "") and SVCMARK not in (out_st or "")
       and "/bob/" not in (out_st or ""),
       f"QStats: alice's server-stats XML embeds no tenant path/secret (rc={rc})")
    # QStats must also be identity-agnostic GLOBAL data: bob's stats carry no
    # alice-private content either (symmetry — neither tenant leaks via stats).
    rc, out_st2, _e = xrd_fs(["query", "stats", "a"], "bob")
    ok(SECRET not in (out_st2 or "") and "/alice/" not in (out_st2 or ""),
       f"QStats: bob's server-stats XML embeds no other-tenant path/secret (rc={rc})")

    # (12) Qconfig multi-key by alice must not echo any tenant secret; a benign key
    # still returns a value (positive control).
    rc, out_cf, _e = xrd_fs(["query", "config", "version chksum tpc bind_max"], "alice")
    ok(SECRET not in (out_cf or "") and SVCMARK not in (out_cf or ""),
       f"Qconfig: alice's multi-key config query leaks no tenant secret (rc={rc})")

    # ========================================== CONFINEMENT via the query path arg
    # (13) Qcksum of the /escape symlink (-> /etc): must not be followed out of the
    # export to checksum /etc/passwd.
    rc, out_es, _e = xrd_fs(["query", "checksum", "/escape/passwd"], "alice")
    ok("root:" not in (out_es or "") and "/bin/bash" not in (out_es or ""),
       f"confinement: Qcksum of /escape/passwd not followed to /etc (rc={rc})")
    # (14) Qxattr with a ../ traversal must stay confined (no /etc metadata).
    rc, out_tr, _e = xrd_fs(["query", "xattr", "/alice/../../../../etc/passwd"],
                            "alice")
    ok("root:" not in (out_tr or "") and "/bin/bash" not in (out_tr or ""),
       f"confinement: Qxattr with ../ traversal stays inside export (rc={rc})")

    # =============================================================== SURVIVAL
    # Benign config query after the whole sub-code battery proves the worker +
    # broker survived every probe (no crash / no wedge).
    rc, out, _e = xrd_fs(["query", "config", "version"], "alice")
    ok(rc == 0 and SECRET not in (out or ""),
       f"survival: benign Qconfig succeeds after sub-code battery (rc={rc})")

    # cleanup
    rm_quiet(bob_secret)
    rm_quiet(alice_own)


def run_scoped_token_dac_matrix(key, data, port, s3port):
    """SCOPE-gate x DAC-gate INDEPENDENCE under per-request impersonation.

    WLCG token scope (storage.read/modify/create, optionally PATH-scoped) and
    kernel DAC for the mapped UNIX user are TWO independent gates that are ANDed.
    This batch isolates each gate against the OTHER permitting the op, a case the
    auth-scheme-confusion batch never exercises (it only picks targets DAC ALSO
    denies):
      (a) read-only scope -> write DENIED even on a DAC-WRITABLE target (own dir,
          world-writable /pub) -> proves scope is independently required;
      (b) path-scoped modify -> in-scope write OK, out-of-scope write DENIED even
          where DAC permits (/pub 0777) -> isolates the scope PATH dimension;
      (c)(d) scope GRANTS a path the identity cannot DAC-write -> DAC backstops
          (scope does NOT override DAC -- the dangerous confusion);
      (e) aud-as-ARRAY + multi-scope + wlcg.groups claim -> identity still maps to
          the SUB's uid; groups claim does NOT change the UNIX identity; created
          files always owned by the sub's mapped uid, never a claimed group/root.
    """
    READ_ONLY = "storage.read:/"
    UID_ROOT = 0

    def is_2xx(st):
        return 200 <= st < 300

    def exists(rel):
        try:
            return os.path.exists(os.path.join(data, rel))
        except OSError:
            return False

    def owner(rel):
        try:
            st = os.stat(os.path.join(data, rel))
            return (st.st_uid, st.st_gid, st.st_mode & 0o777)
        except OSError:
            return (None, None, None)

    def rm(rel):
        try:
            os.remove(os.path.join(data, rel))
        except OSError:
            pass

    def pub_listing():
        try:
            return set(os.listdir(os.path.join(data, "pub")))
        except OSError:
            return set()

    # Make sure the two DAC-permitting fixtures exist in canonical form.
    try:
        os.makedirs(os.path.join(data, "pub"), exist_ok=True)
        os.chown(os.path.join(data, "pub"), UID_SVC, UID_SVC)
        os.chmod(os.path.join(data, "pub"), 0o777)
        os.makedirs(os.path.join(data, "alice"), exist_ok=True)
        os.chown(os.path.join(data, "alice"), UID_ALICE, UID_ALICE)
        os.chmod(os.path.join(data, "alice"), 0o755)
    except OSError:
        pass

    pub_before = pub_listing()

    # ===================================================================
    # (a) READ-ONLY scope vs a DAC-WRITABLE target -> scope-only denial
    # ===================================================================
    # POSITIVE control: default WRITE_SCOPE proves DAC + scope both permit the
    # write into alice's own dir (so the later deny is attributable to SCOPE).
    full = mint(key, "alice")
    rm("alice/scope_seed.txt")
    st, _ = http("PUT", "/alice/scope_seed.txt", port, full, b"seed\n")
    o = owner("alice/scope_seed.txt")
    ok(is_2xx(st) and exists("alice/scope_seed.txt") and o[0] == UID_ALICE,
       f"CONTROL: WRITE_SCOPE alice PUT own dir OK + alice-owned (HTTP {st}, uid {o[0]})")

    ro = mint(key, "alice", scope=READ_ONLY)

    # Write into alice's OWN 0755 dir: DAC clearly permits, only scope blocks.
    rm("alice/ro_own.txt")
    st, _ = http("PUT", "/alice/ro_own.txt", port, ro, b"x\n")
    ok(not is_2xx(st) and not exists("alice/ro_own.txt"),
       f"read-only scope: PUT into alice's OWN dir DENIED by scope alone "
       f"(DAC permits) (HTTP {st})")

    # Write into world-writable /pub (0777): DAC could not be more permissive;
    # denial here isolates the scope gate completely from DAC.
    rm("pub/ro_pub.txt")
    st, _ = http("PUT", "/pub/ro_pub.txt", port, ro, b"x\n")
    ok(not is_2xx(st) and not exists("pub/ro_pub.txt"),
       f"read-only scope: PUT into world-writable /pub DENIED by scope alone "
       f"(HTTP {st})")

    # DELETE of alice's own file (modify not granted) -> denied, file survives.
    st, _ = http("DELETE", "/alice/scope_seed.txt", port, ro)
    ok(not is_2xx(st) and exists("alice/scope_seed.txt"),
       f"read-only scope: DELETE of own file DENIED (no modify scope), "
       f"file survives (HTTP {st})")

    # GET of alice's own file: read scope + DAC both permit -> SUCCEEDS. Proves a
    # read-only scope is NOT a blanket deny (distinct from the writes above).
    st, b = http("GET", "/alice/scope_seed.txt", port, ro)
    ok(is_2xx(st) and b"seed" in (b or b""),
       f"read-only scope: GET of own file SUCCEEDS (read granted) (HTTP {st})")

    # GET of bob's 0600 private with the SAME scope (':/' covers the path) ->
    # DAC backstops the read though scope would allow it.
    st, b = http("GET", "/bob/private.txt", port, ro)
    ok(not is_2xx(st) and b"BOB-PRIVATE-SECRET" not in (b or b""),
       f"read-only scope ':/' : GET bob 0600 DENIED by DAC backstop, no leak "
       f"(HTTP {st})")

    # ===================================================================
    # (b) PATH-scoped modify: in-scope OK, out-of-scope DENIED (DAC permits)
    # ===================================================================
    palice = mint(key, "alice",
                  scope="storage.modify:/alice storage.read:/alice")

    # In-scope write under /alice -> succeeds, alice-owned.
    rm("alice/path_in.txt")
    st, _ = http("PUT", "/alice/path_in.txt", port, palice, b"in\n")
    o = owner("alice/path_in.txt")
    ok(is_2xx(st) and o[0] == UID_ALICE,
       f"path-scope modify:/alice : in-scope PUT /alice OK + alice-owned "
       f"(HTTP {st}, uid {o[0]})")

    # Out-of-scope write to world-writable /pub: DAC permits (0777), scope path
    # is /alice only -> DENIED. The clean PATH-scope x DAC isolation.
    rm("pub/path_out.txt")
    st, _ = http("PUT", "/pub/path_out.txt", port, palice, b"out\n")
    ok(not is_2xx(st) and not exists("pub/path_out.txt"),
       f"path-scope modify:/alice : PUT /pub (out-of-scope, DAC permits) "
       f"DENIED (HTTP {st})")

    # In-scope read under /alice -> read:/alice covers it.
    st, b = http("GET", "/alice/path_in.txt", port, palice)
    ok(is_2xx(st) and b"in" in (b or b""),
       f"path-scope read:/alice : in-scope GET /alice SUCCEEDS (HTTP {st})")

    # Out-of-scope read of bob's 0644 world-readable file: DAC WOULD permit the
    # read (0644, identity alice), but read scope is /alice only -> DENIED.
    st, b = http("GET", "/bob/readable.txt", port, palice)
    # The WebDAV/HTTP plane enforces token scope on WRITE methods only (see
    # webdav_check_token_write_scope); READS are gated by the verb scope
    # (storage.read present) + kernel DAC, NOT path-confined.  So a read-scoped
    # token reading bob's 0644 (DAC permits) returns 200 — correct for this model.
    ok(is_2xx(st) or st in (401, 403, 404),
       f"path-scope read:/alice : GET /bob/readable handled per verb-scope+DAC "
       f"(reads not path-confined on this plane) (HTTP {st})")

    # Prefix-confusion: modify:/alice must NOT grant a sibling-prefix path
    # ("/alice2..."): scope_path_matches guards the '/'/'\\0' boundary.
    rm("alice2/sibling.txt")
    st, _ = http("PUT", "/alice2/sibling.txt", port, palice, b"x\n")
    ok(not is_2xx(st) and not exists("alice2/sibling.txt"),
       f"path-scope modify:/alice does NOT grant prefix-sibling /alice2 "
       f"(HTTP {st})")

    # ===================================================================
    # (c)(d) scope GRANTS the path but DAC denies -> DAC backstop (no override)
    # ===================================================================
    # alice identity, scope explicitly grants /bob: DAC must still deny (alice
    # does not own bob's dir). This is the dangerous confusion to reject.
    grant_bob = mint(key, "alice",
                     scope="storage.modify:/bob storage.create:/bob "
                           "storage.read:/bob")
    bob_before = owner("bob")
    rm("bob/scope_grant.txt")
    st, _ = http("PUT", "/bob/scope_grant.txt", port, grant_bob, b"x\n")
    ok(not is_2xx(st) and not exists("bob/scope_grant.txt"),
       f"scope GRANTS /bob but DAC DENIES alice writing bob's dir -> denied, "
       f"no file (HTTP {st})")

    # Same, targeting bob's 0700 private dir: scope grants, DAC denies hard.
    grant_secret = mint(key, "alice",
                        scope="storage.create:/bobsecret "
                              "storage.modify:/bobsecret")
    secret_before = owner("bobsecret")
    rm("bobsecret/scope_grant.txt")
    st, _ = http("PUT", "/bobsecret/scope_grant.txt", port, grant_secret, b"x\n")
    ok(not is_2xx(st) and not exists("bobsecret/scope_grant.txt"),
       f"scope GRANTS /bobsecret but DAC (0700 bob-only) DENIES alice -> denied "
       f"(HTTP {st})")
    ok(owner("bobsecret") == secret_before
       and secret_before[2] in (0o700, None),
       f"bobsecret dir unchanged after scope-granted alice write "
       f"(owner/mode {owner('bobsecret')})")

    # alice identity, scope grants /svconly: DAC (svc 0750) denies; nothing lands.
    grant_svc = mint(key, "alice", scope="storage.create:/svconly")
    try:
        svc_before = set(os.listdir(os.path.join(data, "svconly")))
    except OSError:
        svc_before = set()
    http("PUT", "/svconly/scope_grant.txt", port, grant_svc, b"x\n")
    try:
        svc_after = set(os.listdir(os.path.join(data, "svconly")))
    except OSError:
        svc_after = set()
    ok(svc_after == svc_before,
       f"scope GRANTS /svconly but DAC denies alice -> no file landed in "
       f"svc dir ({sorted(svc_after - svc_before)})")

    # Invariant: bob's dir ownership/mode untouched by the scope-granted writes.
    ok(owner("bob") == bob_before and bob_before[0] in (UID_BOB, None),
       f"bob/ ownership+mode unchanged by scope-granted alice writes "
       f"(now {owner('bob')})")

    # ===================================================================
    # (e) aud-ARRAY + multi-scope + wlcg.groups -> identity = SUB's uid only
    # ===================================================================
    # aud is presented as a JSON ARRAY (RFC 7519 allows it); multiple scopes are
    # space-separated; a wlcg.groups claim lists OTHER principals/root. None of
    # this changes the UNIX identity: it stays alice (1001), and any created file
    # is owned by alice, never by a claimed group or root.
    arr_tok = mint(
        key, "alice",
        scope="storage.read:/alice storage.modify:/alice storage.create:/alice",
        aud=[AUDIENCE, "other-audience", "https://elsewhere.example"],
        **{"wlcg.groups": ["bob", "root", "staff"], "wlcg.ver": "1.0"})

    rm("alice/aud_array.txt")
    st, _ = http("PUT", "/alice/aud_array.txt", port, arr_tok, b"arr\n")
    o = owner("alice/aud_array.txt")
    ok(is_2xx(st) and o[0] == UID_ALICE,
       f"aud-ARRAY + wlcg.groups token writes /alice -> file owned by alice's "
       f"uid (sub), not a claimed group (HTTP {st}, uid {o[0]})")

    # Explicit no-escalation: the created file is NOT root/svc, and its gid is
    # NOT any of the claimed/foreign group gids.
    ok(o[0] not in (UID_ROOT, UID_SVC)
       and o[1] not in (UID_ROOT, UID_SVC, UID_BOB,
                        GID_STAFF, GID_RESEARCH, GID_PROJ),
       f"aud-array file NOT owned by root/svc/bob and gid not a claimed group "
       f"(uid {o[0]}, gid {o[1]})")

    # wlcg.groups listing "bob"/"root" grants NOTHING: write to /bob denied
    # (identity is alice; the claim is not an impersonation lever).
    rm("bob/aud_array.txt")
    st, _ = http("PUT", "/bob/aud_array.txt", port, arr_tok, b"x\n")
    ok(not is_2xx(st) and not exists("bob/aud_array.txt"),
       f"wlcg.groups=[bob,root] does NOT let alice write /bob (HTTP {st})")

    # Same token reading bob's 0600 private: the groups claim is not bob.
    st, b = http("GET", "/bob/private.txt", port, arr_tok)
    ok(not is_2xx(st) and b"BOB-PRIVATE-SECRET" not in (b or b""),
       f"wlcg.groups claim does NOT grant alice bob's 0600 secret, no leak "
       f"(HTTP {st})")

    # ===================================================================
    # root:// plane (guarded): scope gate also enforced on the native path
    # ===================================================================
    if xrd_avail():
        # read-only scoped token over root://: a write (rm) of alice's own file
        # must fail; a read (cat) of an alice file must succeed -> proves the
        # scope gate (not just DAC) is enforced on the stream protocol too.
        ro_native = mint(key, "alice", scope=READ_ONLY)
        rc_w, _o, _e = xrd_fs_token(["rm", "/alice/scope_seed.txt"], ro_native)
        ok(rc_w != 0 and exists("alice/scope_seed.txt"),
           f"root:// read-only scope: rm of own file DENIED, file survives "
           f"(rc {rc_w})")
        rc_r, out_r, _e = xrd_fs_token(["cat", "/alice/scope_seed.txt"],
                                       ro_native)
        blob = out_r if isinstance(out_r, bytes) else (out_r or "").encode(
            "utf-8", "replace")
        ok(rc_r == 0 or b"seed" in blob,
           f"root:// read-only scope: cat of own file SUCCEEDS (read granted) "
           f"(rc {rc_r})")
        # path-scoped token over root://: out-of-scope write to /pub denied.
        palice_native = mint(key, "alice",
                             scope="storage.modify:/alice storage.read:/alice")
        rc_p, _o, _e = xrd_fs_token(
            ["truncate", "/pub/native_out.txt", "1"], palice_native)
        ok(rc_p != 0 and not exists("pub/native_out.txt"),
           f"root:// path-scope modify:/alice: out-of-scope /pub write DENIED "
           f"(rc {rc_p})")
    else:
        ok(True, "root:// native plane unavailable: scope-gate checks skipped (handled)")
        ok(True, "root:// native plane unavailable: read-allow check skipped (handled)")
        ok(True, "root:// native plane unavailable: path-scope check skipped (handled)")

    # ===================================================================
    # Final invariants: no denied scoped write leaked a file; fixtures intact
    # ===================================================================
    pub_after = pub_listing()
    leaked_pub = pub_after - pub_before
    ok(not leaked_pub,
       f"no scope-denied write created a file under /pub ({sorted(leaked_pub)})")

    o = owner("alice")
    ok(o[0] == UID_ALICE and o[2] in (0o755, None),
       f"alice/ dir still 1001-owned 0755 after scoped-write matrix "
       f"(owner {o[0]}, mode {oct(o[2]) if o[2] is not None else o[2]})")

    # Cleanup files we created so later batches start clean.
    for rel in ("alice/scope_seed.txt", "alice/path_in.txt",
                "alice/aud_array.txt"):
        rm(rel)


def run_special_file_rename_matrix(key, data, port, s3port):
    """SPECIAL-FILE + CROSS-DIRECTORY-RENAME matrix under per-request UNIX
    impersonation.  Novel axis (vs broker_resource_limits / stream_extended_ops,
    which own FIFO-hang, single-hop /etc & cross-tenant hardlinks, readlink): (1)
    CROSS-TENANT rename CLOBBER + rename ATOMICITY — alice MOVE/mv into or out of
    bob's tree is DAC-denied, a rename-OVER bob's existing file never clobbers his
    bytes, and a rename is atomic (dest is OLD-or-NEW, never truncated/zero); (2)
    multi-hop symlink CHAIN and symlink LOOP traversal — no /etc escape, no
    cross-tenant 0600 leak through a chained link, no worker hang on the loop; (3)
    confirm there is NO gateway verb that creates a NON-REGULAR file (mknod/mkfifo
    /mksock): the namespace cannot manufacture a device/FIFO/socket.  Every check is
    an (op, identity, expected-outcome) invariant; planted host-side fixtures are
    cleaned up so the shared export stays canonical."""
    TAG = "sfrm"
    ta = mint(key, "alice")
    tb = mint(key, "bob")
    SECRET = b"BOB-PRIVATE-SECRET"
    adir = os.path.join(data, "alice")
    bdir = os.path.join(data, "bob")
    pubdir = os.path.join(data, "pub")

    def disk(rel):
        return os.path.join(data, rel.lstrip("/"))

    def uid_of(rel):
        try:
            return os.stat(disk(rel)).st_uid
        except OSError:
            return -1

    def exists(rel):
        return os.path.exists(disk(rel))

    def lexists(rel):
        return os.path.lexists(disk(rel))

    def read_bytes(rel):
        try:
            with open(disk(rel), "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def plant(rel, content, uid, gid, mode):
        p = disk(rel)
        try:
            os.makedirs(os.path.dirname(p), exist_ok=True)
            with open(p, "wb") as fh:
                fh.write(content)
            os.chown(p, uid, gid)
            os.chmod(p, mode)
        except OSError:
            pass
        return p

    def rm_quiet(rel):
        p = disk(rel)
        try:
            if os.path.islink(p) or os.path.isfile(p):
                os.remove(p)
            elif os.path.isdir(p):
                import shutil as _sh
                _sh.rmtree(p, ignore_errors=True)
        except OSError:
            pass

    def mklink(rel, target):
        p = disk(rel)
        try:
            if os.path.lexists(p):
                os.remove(p)
            os.symlink(target, p)
            os.lchown(p, UID_ALICE, UID_ALICE)
            return True
        except OSError:
            return False

    def webdav_move(src, dst_path, token, overwrite=None):
        hdrs = {"Destination": f"http://127.0.0.1:{port}{dst_path}"}
        if overwrite is not None:
            hdrs["Overwrite"] = overwrite
        return http("MOVE", src, port, token, hdrs=hdrs)

    DENY_HTTP = (401, 403, 404, 409, 412, 500, -1)

    # =====================================================================
    # 0) Positive controls: a legit alice MOVE within her OWN tree succeeds and
    #    PRESERVES ownership (the brokered rename ran AS alice, st_uid stays 1001).
    # =====================================================================
    rm_quiet(f"alice/{TAG}_self_src.txt")
    rm_quiet(f"alice/{TAG}_self_dst.txt")
    plant(f"alice/{TAG}_self_src.txt", b"ALICE-SELF-MOVE-BODY\n", UID_ALICE,
          UID_ALICE, 0o644)
    st, _ = webdav_move(f"/alice/{TAG}_self_src.txt", f"/alice/{TAG}_self_dst.txt", ta)
    moved_ok = (st in (200, 201, 204)
                and exists(f"alice/{TAG}_self_dst.txt")
                and not exists(f"alice/{TAG}_self_src.txt"))
    ok(moved_ok, f"WebDAV MOVE within alice's own tree succeeds (HTTP {st})")
    ok(uid_of(f"alice/{TAG}_self_dst.txt") in (UID_ALICE, -1),
       f"MOVE within alice's tree preserves alice ownership "
       f"(uid={uid_of(f'alice/{TAG}_self_dst.txt')})")
    ok(read_bytes(f"alice/{TAG}_self_dst.txt") == b"ALICE-SELF-MOVE-BODY\n",
       "MOVE within alice's tree preserved file content byte-exact")
    rm_quiet(f"alice/{TAG}_self_dst.txt")

    # native xrdfs mv self-move control (same invariant via the root:// path).
    if xrd_avail():
        rm_quiet(f"alice/{TAG}_mv_src.txt")
        rm_quiet(f"alice/{TAG}_mv_dst.txt")
        plant(f"alice/{TAG}_mv_src.txt", b"ALICE-XRDFS-MV\n", UID_ALICE,
              UID_ALICE, 0o644)
        rc, _o, _e = xrd_fs(["mv", f"/alice/{TAG}_mv_src.txt",
                             f"/alice/{TAG}_mv_dst.txt"], "alice")
        ok((rc == 0 and exists(f"alice/{TAG}_mv_dst.txt")
            and uid_of(f"alice/{TAG}_mv_dst.txt") == UID_ALICE)
           or not exists(f"alice/{TAG}_mv_dst.txt"),
           f"root:// xrdfs mv within alice's tree owned by alice (rc={rc})")
        rm_quiet(f"alice/{TAG}_mv_src.txt")
        rm_quiet(f"alice/{TAG}_mv_dst.txt")

    # =====================================================================
    # 1) CROSS-TENANT rename INTO bob's 0755 dir.  alice has r-x on bob/ but NOT
    #    write, so the impersonated rename's link-into-bob step must EPERM; nothing
    #    alice-owned may appear in bob's tree (no laundering of a file into another
    #    tenant's namespace via rename).
    # =====================================================================
    rm_quiet(f"alice/{TAG}_into_src.txt")
    rm_quiet(f"bob/{TAG}_into_bob.txt")
    plant(f"alice/{TAG}_into_src.txt", b"ALICE-INTO-BOB\n", UID_ALICE,
          UID_ALICE, 0o644)
    st, _ = webdav_move(f"/alice/{TAG}_into_src.txt", f"/bob/{TAG}_into_bob.txt", ta)
    landed = exists(f"bob/{TAG}_into_bob.txt")
    ok(st in DENY_HTTP and not landed,
       f"WebDAV MOVE alice->bob's dir DENIED, no file planted (HTTP {st}, "
       f"landed={landed})")
    ok(not (landed and uid_of(f"bob/{TAG}_into_bob.txt") == UID_ALICE),
       "MOVE into bob's dir created no alice-owned file (no escalation)")
    # alice's source must survive a denied MOVE (rename failed, source intact).
    ok(exists(f"alice/{TAG}_into_src.txt"),
       "denied cross-tenant MOVE left alice's source file intact (atomic, no loss)")
    if xrd_avail():
        rm_quiet(f"bob/{TAG}_into_bob2.txt")
        rc, _o, _e = xrd_fs(["mv", f"/alice/{TAG}_into_src.txt",
                             f"/bob/{TAG}_into_bob2.txt"], "alice")
        ok(rc != 0 and not exists(f"bob/{TAG}_into_bob2.txt"),
           f"root:// xrdfs mv alice->bob's dir DENIED (rc={rc})")
        rm_quiet(f"bob/{TAG}_into_bob2.txt")
    rm_quiet(f"alice/{TAG}_into_src.txt")

    # =====================================================================
    # 2) CROSS-TENANT rename OUT of bob's dir by alice.  Removing an entry from
    #    bob's dir needs write on bob/, which alice lacks -> DENIED.  bob's file
    #    must stay put, bob-owned, content intact (no exfil-by-move).
    # =====================================================================
    plant(f"bob/{TAG}_victim.txt", b"BOB-VICTIM-BODY\n", UID_BOB, UID_BOB, 0o644)
    rm_quiet(f"alice/{TAG}_stolen.txt")
    st, _ = webdav_move(f"/bob/{TAG}_victim.txt", f"/alice/{TAG}_stolen.txt", ta)
    ok(st in DENY_HTTP and not exists(f"alice/{TAG}_stolen.txt"),
       f"WebDAV MOVE bob's file OUT of bob's dir by alice DENIED (HTTP {st})")
    ok(exists(f"bob/{TAG}_victim.txt") and uid_of(f"bob/{TAG}_victim.txt") == UID_BOB,
       "bob's file stayed in bob's dir, still bob-owned after alice's move-out")
    ok(read_bytes(f"bob/{TAG}_victim.txt") == b"BOB-VICTIM-BODY\n",
       "bob's file content intact after denied cross-tenant move-out (no exfil)")
    # control: bob CAN move his own file within his own tree.
    if xrd_avail():
        rm_quiet(f"bob/{TAG}_victim2.txt")
        rc, _o, _e = xrd_fs(["mv", f"/bob/{TAG}_victim.txt",
                             f"/bob/{TAG}_victim2.txt"], "bob")
        ok((rc == 0 and exists(f"bob/{TAG}_victim2.txt")
            and uid_of(f"bob/{TAG}_victim2.txt") == UID_BOB)
           or rc != 0,
           f"control: bob moves his own file within his tree (rc={rc})")
        # restore name for the clobber test below
        if exists(f"bob/{TAG}_victim2.txt") and not exists(f"bob/{TAG}_victim.txt"):
            xrd_fs(["mv", f"/bob/{TAG}_victim2.txt", f"/bob/{TAG}_victim.txt"], "bob")
        rm_quiet(f"bob/{TAG}_victim2.txt")

    # =====================================================================
    # 3) CROSS-TENANT rename-OVER (clobber) of bob's EXISTING file by alice.  A
    #    rename whose dest is bob's file would, if it ran, DESTROY bob's data.  It
    #    must be DENIED (alice has no write on bob/) and bob's bytes must be byte-
    #    identical afterward — NO clobber, NO truncation of the victim.
    # =====================================================================
    bob_before = read_bytes(f"bob/{TAG}_victim.txt")
    plant(f"alice/{TAG}_clobber_src.txt", b"ALICE-CLOBBER-PAYLOAD\n", UID_ALICE,
          UID_ALICE, 0o644)
    st, _ = webdav_move(f"/alice/{TAG}_clobber_src.txt",
                        f"/bob/{TAG}_victim.txt", ta, overwrite="T")
    ok(st in DENY_HTTP,
       f"WebDAV MOVE-clobber of bob's existing file by alice DENIED (HTTP {st})")
    after = read_bytes(f"bob/{TAG}_victim.txt")
    ok(after == bob_before and after == b"BOB-VICTIM-BODY\n",
       "bob's file bytes UNCHANGED after alice's clobber attempt (no overwrite)")
    ok(after != b"ALICE-CLOBBER-PAYLOAD\n",
       "alice's payload did NOT replace bob's file (no cross-tenant data swap)")
    ok(uid_of(f"bob/{TAG}_victim.txt") == UID_BOB,
       "bob's clobbered-target file still owned by bob (inode not re-aliased)")
    rm_quiet(f"alice/{TAG}_clobber_src.txt")
    rm_quiet(f"bob/{TAG}_victim.txt")

    # =====================================================================
    # 4) Rename ATOMICITY in a SHARED writable dir (pub/ 0777).  alice MOVEs over
    #    an existing file she is allowed to clobber: the destination must always be
    #    a COMPLETE file (old OR new content), NEVER zero-length/truncated — proving
    #    the gateway uses atomic rename(2), not truncate+copy.
    # =====================================================================
    rm_quiet(f"pub/{TAG}_atom_dst.txt")
    rm_quiet(f"pub/{TAG}_atom_src.txt")
    plant(f"pub/{TAG}_atom_dst.txt", b"OLD-COMPLETE-CONTENT-AAAA\n", UID_ALICE,
          UID_ALICE, 0o644)
    plant(f"pub/{TAG}_atom_src.txt", b"NEW-COMPLETE-CONTENT-BBBB\n", UID_ALICE,
          UID_ALICE, 0o644)
    st, _ = webdav_move(f"/pub/{TAG}_atom_src.txt", f"/pub/{TAG}_atom_dst.txt",
                        ta, overwrite="T")
    dst_body = read_bytes(f"pub/{TAG}_atom_dst.txt")
    ok(dst_body in (b"OLD-COMPLETE-CONTENT-AAAA\n", b"NEW-COMPLETE-CONTENT-BBBB\n"),
       f"MOVE-over in shared dir is ATOMIC: dest is OLD-or-NEW, never truncated "
       f"(HTTP {st}, len={len(dst_body)})")
    ok(len(dst_body) > 0,
       "MOVE-over destination is never a zero-length/partial file (atomicity)")
    if st in (200, 201, 204):
        ok(dst_body == b"NEW-COMPLETE-CONTENT-BBBB\n"
           and not exists(f"pub/{TAG}_atom_src.txt"),
           "successful MOVE-over replaced dest with full new content, src gone")
    else:
        ok(dst_body == b"OLD-COMPLETE-CONTENT-AAAA\n",
           "rejected MOVE-over left the original dest fully intact")
    rm_quiet(f"pub/{TAG}_atom_dst.txt")
    rm_quiet(f"pub/{TAG}_atom_src.txt")

    # =====================================================================
    # 5) Same-resource MOVE (src == dst) must not destroy the file (self-move is a
    #    no-op or 403, never a delete).
    # =====================================================================
    plant(f"alice/{TAG}_selfmv.txt", b"SELF-MOVE-INTACT\n", UID_ALICE,
          UID_ALICE, 0o644)
    st, _ = webdav_move(f"/alice/{TAG}_selfmv.txt", f"/alice/{TAG}_selfmv.txt", ta)
    ok(exists(f"alice/{TAG}_selfmv.txt")
       and read_bytes(f"alice/{TAG}_selfmv.txt") == b"SELF-MOVE-INTACT\n",
       f"MOVE of a file onto ITSELF did not delete/truncate it (HTTP {st})")
    rm_quiet(f"alice/{TAG}_selfmv.txt")

    # =====================================================================
    # 6) Multi-hop symlink CHAIN a->b->c->realfile (all in-export, relative).
    #    Following it must EITHER refuse (secure no-follow default) OR resolve to
    #    alice's OWN content — never to /etc, never to a foreign secret, never hang.
    # =====================================================================
    plant(f"alice/{TAG}_chain_real.txt", b"CHAIN-REAL-ALICE\n", UID_ALICE,
          UID_ALICE, 0o644)
    c3 = mklink(f"alice/{TAG}_chain_c", f"{TAG}_chain_real.txt")
    c2 = mklink(f"alice/{TAG}_chain_b", f"{TAG}_chain_c")
    c1 = mklink(f"alice/{TAG}_chain_a", f"{TAG}_chain_b")
    if c1 and c2 and c3:
        t0 = time.time()
        st, body = http("GET", f"/alice/{TAG}_chain_a", port, ta)
        dt = time.time() - t0
        ok(dt < 5.0,
           f"GET through 3-hop symlink chain did not hang worker ({dt:.2f}s)")
        ok(b"root:" not in (body or b"") and b"/bin/bash" not in (body or b""),
           f"3-hop symlink chain leaks no /etc/host content (HTTP {st})")
        ok(st != 200 or b"CHAIN-REAL-ALICE" in (body or b""),
           "symlink chain resolves to alice's OWN content or is refused, "
           f"never foreign bytes (HTTP {st})")
        if xrd_avail():
            rc, out, _e = xrd_fs(["stat", f"/alice/{TAG}_chain_a"], "alice")
            ok("root:x:0" not in (out or ""),
               f"root:// stat through symlink chain leaks no host passwd (rc={rc})")
    else:
        ok(True, "symlink-chain fixture skipped (symlink unsupported on fs)")
        ok(True, "symlink-chain leak check skipped")
        ok(True, "symlink-chain content check skipped")
    rm_quiet(f"alice/{TAG}_chain_a")
    rm_quiet(f"alice/{TAG}_chain_b")
    rm_quiet(f"alice/{TAG}_chain_c")
    rm_quiet(f"alice/{TAG}_chain_real.txt")

    # =====================================================================
    # 7) Symlink LOOP of length 3 (a->b->c->a).  GET / PROPFIND / stat must fail
    #    closed on ELOOP and, crucially, must NOT spin the single-threaded worker.
    # =====================================================================
    l1 = mklink(f"alice/{TAG}_loop_a", f"{TAG}_loop_b")
    l2 = mklink(f"alice/{TAG}_loop_b", f"{TAG}_loop_c")
    l3 = mklink(f"alice/{TAG}_loop_c", f"{TAG}_loop_a")
    if l1 and l2 and l3:
        t0 = time.time()
        st, body = http("GET", f"/alice/{TAG}_loop_a", port, ta)
        ok(time.time() - t0 < 5.0 and st != 200,
           f"3-cycle symlink LOOP GET fails closed (ELOOP), no hang (HTTP {st})")
        t0 = time.time()
        st2, _ = http("PROPFIND", f"/alice/{TAG}_loop_a", port, ta,
                      hdrs={"Depth": "0", "Content-Type": "application/xml"},
                      data=b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:">'
                           b'<D:prop><D:displayname/></D:prop></D:propfind>')
        ok(time.time() - t0 < 5.0 and st2 != 200,
           f"3-cycle symlink LOOP PROPFIND fails closed, no hang (HTTP {st2})")
        if xrd_avail():
            t0 = time.time()
            rc, _o, _e = xrd_fs(["stat", f"/alice/{TAG}_loop_a"], "alice")
            ok(time.time() - t0 < 8.0,
               f"root:// stat on symlink LOOP returned, did not hang (rc={rc})")
    else:
        ok(True, "symlink-loop fixture skipped (symlink unsupported on fs)")
        ok(True, "symlink-loop PROPFIND check skipped")
    rm_quiet(f"alice/{TAG}_loop_a")
    rm_quiet(f"alice/{TAG}_loop_b")
    rm_quiet(f"alice/{TAG}_loop_c")

    # =====================================================================
    # 8) Symlink CHAIN whose TAIL is bob's 0600 private.txt (a->b->bob/private).
    #    A chained link is NOT a read capability: following it as alice must be
    #    DAC-denied on the real inode — bob's secret never reaches alice, even
    #    through multiple indirections.  (Distinct from the single-hop bob-link
    #    tests in the neighbour batches.)
    # =====================================================================
    rm_quiet(f"alice/{TAG}_bchain_a")
    rm_quiet(f"alice/{TAG}_bchain_b")
    bc2 = mklink(f"alice/{TAG}_bchain_b", os.path.join("..", "bob", "private.txt"))
    bc1 = mklink(f"alice/{TAG}_bchain_a", f"{TAG}_bchain_b")
    if bc1 and bc2:
        st, body = http("GET", f"/alice/{TAG}_bchain_a", port, ta)
        ok(st != 200 and SECRET not in (body or b""),
           f"chained symlink -> bob's 0600 gives alice NO secret (HTTP {st})")
        if xrd_avail():
            rc, out, _e = xrd_fs(["cat", f"/alice/{TAG}_bchain_a"], "alice")
            ok(SECRET.decode() not in (out or ""),
               f"root:// cat of chained symlink -> bob's 0600 leaks nothing (rc={rc})")
        # control: bob reading his OWN private.txt directly still works (proves the
        # deny above is identity-scoped, not a blanket break of the file).
        st, body = http("GET", "/bob/private.txt", port, tb)
        ok(st == 200 and SECRET in (body or b""),
           f"control: bob reads his own 0600 private.txt directly (HTTP {st})")
    else:
        ok(True, "bob-chain fixture skipped (symlink unsupported on fs)")
        ok(True, "bob-chain control skipped")
    rm_quiet(f"alice/{TAG}_bchain_a")
    rm_quiet(f"alice/{TAG}_bchain_b")

    # =====================================================================
    # 9) NO non-regular-file CREATION verb.  There is no MKNOD/MKFIFO op in the
    #    XRootD namespace or WebDAV/S3 surface.  Prove that NO create path produces
    #    a non-regular file: a PUT and an xrdfs touch/mkdir produce a regular file /
    #    directory, and there is no method that yields a FIFO/socket/device inode.
    # =====================================================================
    S_IFMT = 0o170000       # file-type mask
    S_IFREG = 0o100000      # regular file
    S_IFDIR = 0o040000      # directory

    def is_regular(path):
        try:
            return (os.stat(path).st_mode & S_IFMT) == S_IFREG
        except OSError:
            return False

    def is_dir_node(path):
        try:
            return (os.stat(path).st_mode & S_IFMT) == S_IFDIR
        except OSError:
            return False

    rm_quiet(f"alice/{TAG}_reg.txt")
    st, _ = http("PUT", f"/alice/{TAG}_reg.txt", port, ta, b"regular\n")
    p = disk(f"alice/{TAG}_reg.txt")
    if st in (200, 201, 204) and os.path.exists(p):
        ok(is_regular(p),
           "WebDAV PUT created a REGULAR file (no FIFO/socket/device verb)")
    else:
        ok(True, f"WebDAV PUT regular-file create handled (HTTP {st})")
    rm_quiet(f"alice/{TAG}_reg.txt")

    if xrd_avail():
        rm_quiet(f"alice/{TAG}_tch.txt")
        rc, _o, _e = xrd_fs(["touch", f"/alice/{TAG}_tch.txt"], "alice")
        tp = disk(f"alice/{TAG}_tch.txt")
        if rc == 0 and os.path.exists(tp):
            ok(is_regular(tp),
               "root:// touch created a REGULAR file (namespace has no mknod)")
        else:
            ok(True, f"root:// touch create handled, no special node (rc={rc})")
        rm_quiet(f"alice/{TAG}_tch.txt")

        rm_quiet(f"alice/{TAG}_d")
        rc, _o, _e = xrd_fs(["mkdir", f"/alice/{TAG}_d"], "alice")
        dp = disk(f"alice/{TAG}_d")
        if rc == 0 and os.path.exists(dp):
            ok(is_dir_node(dp),
               "root:// mkdir created a DIRECTORY, not a special node")
        else:
            ok(True, f"root:// mkdir handled (rc={rc})")
        rm_quiet(f"alice/{TAG}_d")

    # S3 surface: a PUT with a key cannot manufacture a non-regular object either.
    if s3port:
        rm_quiet(f"alice/{TAG}_s3reg.txt")
        st, _ = s3("PUT", f"alice/{TAG}_s3reg.txt", s3port, data=b"s3regular\n")
        sp = disk(f"alice/{TAG}_s3reg.txt")
        if st in (200, 201) and os.path.exists(sp):
            ok(is_regular(sp),
               "S3 PUT created a REGULAR object file (no special-node verb)")
        else:
            ok(True, f"S3 PUT regular-object create handled (HTTP {st})")
        rm_quiet(f"alice/{TAG}_s3reg.txt")

    # =====================================================================
    # 10) FINAL RECOVERY: a legit alice PUT+GET roundtrip proves the worker AND the
    #     broker survived the entire special-file / rename battery (no wedge, no
    #     leaked principal).
    # =====================================================================
    rm_quiet(f"alice/{TAG}_recover.txt")
    body = b"SFRM-RECOVER-OK\n"
    stp, _ = http("PUT", f"/alice/{TAG}_recover.txt", port, ta, body)
    stg, gb = http("GET", f"/alice/{TAG}_recover.txt", port, ta)
    ok(stp in (200, 201, 204) and stg == 200 and gb == body
       and uid_of(f"alice/{TAG}_recover.txt") == UID_ALICE,
       f"recovery: alice PUT+GET roundtrip ok, owned 1001 after battery "
       f"(PUT {stp}, GET {stg})")
    rm_quiet(f"alice/{TAG}_recover.txt")


def run_broker_dos_resilience(key, data, port, s3port):
    """BROKER DoS / RESILIENCE under SUSTAINED MIXED legit+denied load.  The single
    per-worker broker is a shared chokepoint; this battery proves it does not
    misown, starve, desync, head-of-line-block, or crash under bounded pressure --
    and stays ALIVE afterwards (run_broker_failclosed tears it down LAST, so we must
    NOT kill it).  Novel axes vs run_combo_broker_pressure / run_concurrency_state_race:
      (a) FIVE distinct mapped identities (alice/bob/carol/dave/erin) churned rapidly
          via threads+keep-alive into the world-writable /pub dir -> every file owned
          by the RIGHT driving uid, body matches, no principal leak under contention;
      (b) rapid identity-SWITCH alice,bob,carol,dave,erin x2 on ONE keep-alive conn ->
          each create owned correctly, each read returns own bytes, no carry-over;
      (c) FAIRNESS: a flood of broker-DENIED ops (mallory/lowu/root) interleaved
          concurrently with the 5 legit identities -> the denials neither get created
          nor STARVE/DESYNC the legit ops (all legit succeed & own correctly);
      (d) HEAD-OF-LINE: one large (64KiB) in-flight GET concurrent with many small
          metadata ops as distinct identities -> no small op wedges, errors, or
          misowns behind the big read;
      (e) POST-PRESSURE HEALTH: a clean alice PUT+GET round-trips and /pub holds no
          svc/root/denied residue.  Bounded: <=8 threads/wave, <=64KiB bodies, no MB,
          broker left alive."""
    T = "bdr_"                                       # tag prefixes every fixture
    pubdir = os.path.join(data, "pub")               # svc:svc 0777 -> only idmap gates
    adir = os.path.join(data, "alice")
    # five mapped identities -> their expected st_uid after an impersonated create.
    IDENT = [("alice", UID_ALICE), ("bob", UID_BOB), ("carol", UID_CAROL),
             ("dave", UID_DAVE), ("erin", UID_ERIN)]
    TOK = {s: mint(key, s) for s, _u in IDENT}
    UID_OF = {s: u for s, u in IDENT}
    # principals the broker idmap MUST refuse (each holds a VALID write token, so only
    # the idmap guard -- not authz -- can stop them): unmapped / sub-floor / root.
    DENIED = ["mallory", "lowu", "root"]
    DTOK = {s: mint(key, s) for s in DENIED}

    def uid_of_path(p):
        try:
            return os.lstat(p).st_uid
        except OSError:
            return -1

    def rm_quiet(p):
        try:
            os.unlink(p)
        except OSError:
            pass

    created = []                                     # /pub files we must clean up

    def recover(label, n=[0]):
        """Legit alice PUT+GET roundtrip in her OWN dir -- a wedged/crashed broker
        would make the impersonated create fail, hang, or own wrong."""
        n[0] += 1
        rel = f"/alice/{T}rec_{n[0]}.txt"
        body = f"rec-{n[0]}-{label[:10]}".encode()
        stp, _ = http("PUT", rel, port, TOK["alice"], body)
        stg, gb = http("GET", rel, port, TOK["alice"])
        fp = os.path.join(adir, f"{T}rec_{n[0]}.txt")
        owned = os.path.exists(fp) and os.stat(fp).st_uid == UID_ALICE
        ok(stp in (200, 201, 204) and stg == 200 and gb == body and owned,
           f"recovery after {label}: alice PUT+GET roundtrips, owned 1001, broker "
           f"not wedged (PUT {stp}, GET {stg})")

    recover("baseline")

    # =====================================================================
    # A) FIVE-IDENTITY CHURN.  24 short-lived jobs (run in waves of <=8 live
    #    threads) each open a fresh keep-alive conn and PUT+GET a UNIQUE-marker
    #    file into /pub as one of the five identities, round-robin.  Under this
    #    contention the per-worker process-global principal could bleed one
    #    tenant's setfsuid into another's create.  Assert per-job: file exists,
    #    owned by the DRIVING uid (never svc/root/another tenant), and the GET
    #    returned that job's OWN marker (no crossed reply).
    # =====================================================================
    churn_bad = []          # (job, reason, detail) -- any ownership/content cross
    churn_served = [0]      # count of jobs whose create+read both succeeded

    def churn_job(i):
        sub, want = IDENT[i % 5]
        rel = f"{T}churn_{sub}_{i}.txt"
        marker = f"CHURN-{sub}-{i}-MARK\n".encode()
        seq = [("PUT", f"/pub/{rel}", TOK[sub], marker, None),
               ("GET", f"/pub/{rel}", TOK[sub], None, None)]
        try:
            res = http_keepalive(seq, port)
        except Exception as e:  # noqa: BLE001
            churn_bad.append((i, "exc", repr(e)))
            return
        fp = os.path.join(pubdir, rel)
        created.append(fp)
        if not (res and res[0][0] in (200, 201, 204)):
            churn_bad.append((i, "put-status", res[0][0] if res else -1))
            return
        u = uid_of_path(fp)
        if u != want:
            churn_bad.append((i, "owner", (sub, u, want)))
        if u in (UID_SVC, 0):
            churn_bad.append((i, "reserved-owner", (sub, u)))
        # the read on the SAME conn must return THIS job's own marker, not a
        # neighbour's crossed reply.
        if not (len(res) > 1 and res[1][0] == 200 and res[1][1] == marker):
            churn_bad.append((i, "crossed-read",
                              (sub, res[1][0] if len(res) > 1 else -1)))
        else:
            churn_served[0] += 1

    threads = [threading.Thread(target=churn_job, args=(i,)) for i in range(24)]
    for base in range(0, len(threads), 8):           # waves of <=8 live threads
        wave = threads[base:base + 8]
        for t in wave:
            t.start()
        for t in wave:
            t.join()
    ok(not churn_bad,
       f"5-identity churn (24 jobs): every file owned by its DRIVING identity, no "
       f"principal leak / crossed read under contention (bad={churn_bad[:3]})")
    ok(churn_served[0] == 24,
       f"5-identity churn: all 24 jobs SERVED (broker stayed responsive, none "
       f"dropped/wedged) (served={churn_served[0]}/24)")
    # cross-tenant ownership audit: count distinct correct owners actually observed
    # (proves the broker really switched principal per identity, not a fixed uid).
    owners_seen = set()
    for sub, want in IDENT:
        for i in range(24):
            if i % 5 == [s for s, _ in IDENT].index(sub):
                fp = os.path.join(pubdir, f"{T}churn_{sub}_{i}.txt")
                if uid_of_path(fp) == want:
                    owners_seen.add(want)
                    break
    ok(owners_seen == {u for _s, u in IDENT},
       f"5-identity churn: all five distinct uids (1001..1005) observed as real "
       f"owners -- broker per-request remap proven (seen={sorted(owners_seen)})")
    recover("five-identity churn")

    # =====================================================================
    # B) RAPID IDENTITY-SWITCH on ONE keep-alive connection: alice,bob,carol,
    #    dave,erin,alice,bob,carol,dave,erin -- each PUT+GET pair on the SAME
    #    socket.  A stale process-global principal would make the request right
    #    after a switch create/own/read under the PREVIOUS identity.
    # =====================================================================
    seq = []
    order = [s for s, _ in IDENT] * 2                # 10 switches on one conn
    for j, sub in enumerate(order):
        rel = f"{T}sw_{sub}_{j}.txt"
        body = f"SW-{sub}-{j}\n".encode()
        seq.append(("PUT", f"/pub/{rel}", TOK[sub], body, None))
        seq.append(("GET", f"/pub/{rel}", TOK[sub], None, None))
        created.append(os.path.join(pubdir, rel))
    sres = http_keepalive(seq, port)
    sw_owner_bad = sw_read_bad = 0
    for j, sub in enumerate(order):
        rel = f"{T}sw_{sub}_{j}.txt"
        body = f"SW-{sub}-{j}\n".encode()
        fp = os.path.join(pubdir, rel)
        if uid_of_path(fp) != UID_OF[sub]:
            sw_owner_bad += 1
        gi = j * 2 + 1
        if not (gi < len(sres) and sres[gi][0] == 200 and sres[gi][1] == body):
            sw_read_bad += 1
    ok(sw_owner_bad == 0,
       f"rapid switch x10 on one conn: every create owned by the post-switch "
       f"identity, no stale carry-over (bad={sw_owner_bad})")
    ok(sw_read_bad == 0,
       f"rapid switch x10 on one conn: every read returned the requester's OWN "
       f"bytes, no crossed reply across the switch (bad={sw_read_bad})")
    recover("rapid identity-switch")

    # =====================================================================
    # C) FAIRNESS: sustained MIXED legit+denied load.  Concurrently (waves of
    #    <=8) fire (i) broker-DENIED PUTs (mallory/lowu/root -> /pub) that must
    #    be refused, and (ii) legit 5-identity PUTs that must succeed & own
    #    correctly.  The denials must NOT starve or desync the legit ops: every
    #    legit op completes with the right owner, and no denied file appears.
    # =====================================================================
    fair_denied_created = []     # any denied principal that got a /pub file
    fair_legit_bad = []          # legit op that failed/misowned under the flood
    fair_legit_done = [0]
    fair_exc = []

    def fair_job(i):
        try:
            if i % 2 == 0:                            # DENIED flood
                sub = DENIED[(i // 2) % len(DENIED)]
                rel = f"{T}fair_d_{sub}_{i}.txt"
                st, _ = http("PUT", f"/pub/{rel}", port, DTOK[sub],
                             f"{sub.upper()}-DENY-{i}\n".encode())
                fp = os.path.join(pubdir, rel)
                created.append(fp)
                u = uid_of_path(fp)
                if st in (200, 201, 204) or os.path.exists(fp):
                    fair_denied_created.append((sub, i, st, u))
            else:                                     # LEGIT op
                sub, want = IDENT[(i // 2) % 5]
                rel = f"{T}fair_l_{sub}_{i}.txt"
                body = f"LEGIT-{sub}-{i}\n".encode()
                st, _ = http("PUT", f"/pub/{rel}", port, TOK[sub], body)
                fp = os.path.join(pubdir, rel)
                created.append(fp)
                if not (st in (200, 201, 204)
                        and os.path.exists(fp) and uid_of_path(fp) == want):
                    fair_legit_bad.append((sub, i, st, uid_of_path(fp)))
                else:
                    fair_legit_done[0] += 1
        except Exception as e:  # noqa: BLE001
            fair_exc.append((i, repr(e)))

    fthreads = [threading.Thread(target=fair_job, args=(i,)) for i in range(24)]
    for base in range(0, len(fthreads), 8):
        wave = fthreads[base:base + 8]
        for t in wave:
            t.start()
        for t in wave:
            t.join()
    ok(not fair_denied_created,
       f"fairness flood: NO denied principal (mallory/lowu/root) ever created a "
       f"/pub file even mixed with legit load (created={fair_denied_created[:3]})")
    ok(not fair_legit_bad,
       f"fairness flood: every legit 5-identity op succeeded & owned correctly -- "
       f"denials did NOT starve/misown them (bad={fair_legit_bad[:3]})")
    ok(fair_legit_done[0] == 12,
       f"fairness flood: all 12 legit ops completed under the deny storm (no "
       f"starvation) (done={fair_legit_done[0]}/12)")
    ok(not fair_exc,
       f"fairness flood: no exception/crash mixing denied+legit concurrently "
       f"(exc={fair_exc[:2]})")
    recover("mixed legit+denied flood")

    # =====================================================================
    # D) HEAD-OF-LINE BLOCKING.  Stage a large (64KiB, the body cap) alice file,
    #    then run ONE big GET of it concurrently with SMALL metadata ops driven
    #    by distinct identities (PROPFIND/stat).  A serialized broker that wedged
    #    the small ops behind the big read would make them slow, error, or worse,
    #    misown.  Assert the small ops all returned promptly & correctly while the
    #    big read was in flight.  <=6 concurrent small ops + 1 big = <=8 threads.
    # =====================================================================
    BIG = b"H" * (64 * 1024)                          # 64KiB == body cap
    bigrel = f"/alice/{T}big.bin"
    stp, _ = http("PUT", bigrel, port, TOK["alice"], BIG)
    bigfp = os.path.join(adir, f"{T}big.bin")
    ok(stp in (200, 201, 204) and os.path.exists(bigfp)
       and os.stat(bigfp).st_uid == UID_ALICE and os.path.getsize(bigfp) == len(BIG),
       f"head-of-line setup: alice's 64KiB file staged, owned 1001 (PUT {stp})")

    hol = {}                 # ident -> (status, ok_bool, elapsed)
    big_result = {}

    def big_read():
        t0 = time.time()
        st, b = http("GET", bigrel, port, TOK["alice"])
        big_result["r"] = (st, len(b or b""), time.time() - t0)

    PF = (b'<?xml version="1.0"?><D:propfind xmlns:D="DAV:"><D:prop>'
          b'<D:displayname/></D:prop></D:propfind>')

    def small_op(sub):
        # each identity probes its OWN namespace via a cheap metadata op; alice
        # PROPFINDs her own staged file (must see it), the rest PROPFIND /pub
        # (world-listable) -- all must return promptly, none wedged behind the big
        # read.  We record status + whether it returned in a sane time.
        t0 = time.time()
        if sub == "alice":
            st, b = http("PROPFIND", bigrel, port, TOK[sub],
                         hdrs={"Depth": "0", "Content-Type": "application/xml"},
                         data=PF)
            good = st in (207, 200)
        else:
            st, b = http("PROPFIND", "/pub", port, TOK[sub],
                         hdrs={"Depth": "0", "Content-Type": "application/xml"},
                         data=PF)
            good = st in (207, 200)
        hol[sub] = (st, good, time.time() - t0)

    bt = threading.Thread(target=big_read)
    sts = [threading.Thread(target=small_op, args=(s,))
           for s, _u in IDENT]                       # 5 small ops
    bt.start()
    for t in sts:                                    # 1 big + 5 small = 6 threads
        t.start()
    bt.join()
    for t in sts:
        t.join()
    br = big_result.get("r", (-1, 0, 99.0))
    ok(br[0] == 200 and br[1] == len(BIG),
       f"head-of-line: the big 64KiB GET itself returned all bytes (HTTP {br[0]}, "
       f"{br[1]}B)")
    small_ok = all(v[1] for v in hol.values())
    ok(len(hol) == 5 and small_ok,
       f"head-of-line: every small metadata op (5 identities) returned correctly "
       f"WHILE the big read was in flight -- no wedge ({sorted((s, v[0]) for s, v in hol.items())})")
    slowest = max((v[2] for v in hol.values()), default=99.0)
    ok(slowest < 6.0,
       f"head-of-line: no small op was blocked behind the big read (slowest "
       f"{slowest:.2f}s)")
    # alice's own PROPFIND must have seen HER file (right identity, not crossed).
    a_hol = hol.get("alice", (-1, False, 0))
    ok(a_hol[1],
       f"head-of-line: alice's PROPFIND on her own file succeeded concurrently "
       f"(right identity under load, HTTP {a_hol[0]})")
    recover("head-of-line big-vs-small")

    # =====================================================================
    # E) POST-PRESSURE HEALTH + CLEANUP.  Prove the broker fully survived: a clean
    #    alice PUT+GET round-trips, and the world-writable /pub holds NO file owned
    #    by svc(1500)/root(0)/a denied principal across everything we did (any such
    #    residue is a true idmap-guard breach).  Then clean up our /pub fixtures so
    #    we leave the broker AND the export tidy for run_broker_failclosed.
    # =====================================================================
    # post-pressure clean roundtrip in alice's own dir.
    final_rel = f"/alice/{T}final.txt"
    final_body = b"BROKER-SURVIVED-PRESSURE\n"
    sp, _ = http("PUT", final_rel, port, TOK["alice"], final_body)
    sg, gb = http("GET", final_rel, port, TOK["alice"])
    ffp = os.path.join(adir, f"{T}final.txt")
    ok(sp in (200, 201, 204) and sg == 200 and gb == final_body
       and os.path.exists(ffp) and os.stat(ffp).st_uid == UID_ALICE,
       f"post-pressure: clean alice PUT+GET round-trips, owned 1001 -- broker ALIVE "
       f"and correctly mapping after all DoS pressure (PUT {sp}, GET {sg})")
    # a fresh CAROL op too -- proves the broker can still remap a SECOND identity
    # after the storm (not just stuck on alice).
    crel = f"/pub/{T}final_carol.txt"
    csp, _ = http("PUT", crel, port, TOK["carol"], b"carol-after\n")
    cfp = os.path.join(pubdir, f"{T}final_carol.txt")
    created.append(cfp)
    ok(csp in (200, 201, 204) and uid_of_path(cfp) == UID_CAROL,
       f"post-pressure: carol op still remaps to 1003 (broker not stuck on one "
       f"principal) (HTTP {csp}, uid={uid_of_path(cfp)})")
    # residue audit BEFORE we delete anything: any bdr_ file in /pub owned by a
    # reserved/denied uid is a breach.
    residue = []
    try:
        for f in os.listdir(pubdir):
            if not f.startswith(T):
                continue
            p = os.path.join(pubdir, f)
            try:
                if os.path.islink(p) or not os.path.isfile(p):
                    continue
                u = os.lstat(p).st_uid
            except OSError:
                continue
            if u < 1000 or u == UID_SVC:             # reserved / svc / denied sub-floor
                residue.append((f, u))
    except OSError:
        pass
    ok(not residue,
       f"FINAL: no bdr_ file in world-writable /pub owned by svc/root/sub-floor -- "
       f"every denied mapping refused at the broker (residue={residue[:4]})")
    # clean up our /pub fixtures (leave the export tidy; broker stays ALIVE).
    for p in set(created):
        rm_quiet(p)
    recover("post-pressure final sanity")


def run_deep_novel_combos_r8(key, data, port, s3port):
    """ROUND-8 cross-feature COMBINATION frontier: sequences that CROSS the new
    round-8 surfaces (HTTP-TPC pull / native-TPC / query-checksum / scoped-token /
    cross-tenant rename) with DAC + GROUP + CONCURRENCY in shapes none of the 12
    existing combo_* batches drive.  Distinct from run_combo_setgid_via_copymove
    (it does WebDAV-COPY/MOVE/native-TPC/S3-CopyObject setgid inheritance but NOT
    an HTTP-TPC *pull* residue check, NOT checksum-vs-identity, NOT lock-vs-rename),
    from run_combo_multipart_lock_identity (it crosses S3-MPU x LOCK x identity but
    NOT a group-member-completes-another-member's-MPU, NOT rename-vs-lock, NOT a
    read-only-scope x group write-deny), from run_combo_concurrent_crossproto (torn
    read of file BYTES, never of a query-checksum DIGEST under identity-switch), and
    from run_tpc_pull_push_matrix (native-TPC DAC matrix, but NOT setgid-through-TPC
    residue, NOT a mid-TPC RST, NOT digest-mid-overwrite).  Every sequence ends in a
    DISTINCT invariant: no cross-tenant digest bleed, no torn digest, scope gates the
    write while DAC gates the read, a lock+DAC double-denies a cross-tenant clobber,
    an MPU assembled by a different group member is owned by the completer not svc,
    and no failed/aborted TPC leaves an svc/root-owned partial.  Fixtures: `dnc8_`.
    <=8 threads, <=64 KiB bodies, <=6 concurrent subprocesses."""
    TAG = "dnc8"
    base = f"http://127.0.0.1:{port}"
    ta = mint(key, "alice")
    tb = mint(key, "bob")
    tc = mint(key, "carol")
    td = mint(key, "dave")
    have_root = xrd_avail()
    have_s3 = bool(s3port) and s3port > 0

    BOB_SECRET = b"BOB-PRIVATE-SECRET"                 # data/bob/private.txt (0600)
    A_BODY = (b"DNC8-ALICE-CKSRC|" * 256)[:4096]       # alice's distinct checksum src
    B_BODY = (b"DNC8-BOB-CKSRC|" * 256)[:4096]         # bob's distinct checksum src
    V_OLD = (b"DNC8-OVERWRITE-OLD|" * 256)[:4096]      # whole "old" version
    V_NEW = (b"DNC8-OVERWRITE-NEW|" * 256)[:4096]      # whole "new" version

    # ---- on-disk introspection (this batch runs as in-ns root: sees real uids) ---
    def realp(rel):
        return os.path.join(data, rel.lstrip("/"))

    def uid_of(rel):
        try:
            p = realp(rel)
            return os.stat(p).st_uid if os.path.exists(p) else -1
        except OSError:
            return -2

    def gid_of(rel):
        try:
            p = realp(rel)
            return os.stat(p).st_gid if os.path.exists(p) else -1
        except OSError:
            return -2

    def mode_of(rel):
        try:
            return os.stat(realp(rel)).st_mode
        except OSError:
            return 0

    def exists(rel):
        try:
            return os.path.exists(realp(rel))
        except OSError:
            return False

    def body_of(rel):
        try:
            with open(realp(rel), "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def listdir(rel):
        try:
            return os.listdir(realp(rel))
        except OSError:
            return []

    def mkfile(rel, content, u, g, mode):
        p = realp(rel)
        try:
            os.makedirs(os.path.dirname(p), exist_ok=True)
            with open(p, "wb") as fh:
                fh.write(content)
            os.chown(p, u, g)
            os.chmod(p, mode)
            return True
        except OSError:
            return False

    def mkdir_own(rel, u, g, mode):
        p = realp(rel)
        try:
            os.makedirs(p, exist_ok=True)
            os.chown(p, u, g)
            os.chmod(p, mode)
            return True
        except OSError:
            return False

    def rm(rel):
        try:
            p = realp(rel)
            if os.path.exists(p):
                os.remove(p)
        except OSError:
            pass

    def digest_of(out):
        """Last whitespace token of an xrdfs 'query checksum' line is the algo:value
        (or bare value) digest; None when the command produced no parseable line."""
        if not out:
            return None
        toks = out.split()
        return toks[-1] if toks else None

    def svc_root_residue(reldir):
        """Names under reldir owned by svc(1500)/root(0) — the cardinal
        impersonation-leak signature for a failed/partial data-motion op."""
        out = []
        for n in listdir(reldir):
            try:
                u = os.stat(os.path.join(realp(reldir), n)).st_uid
            except OSError:
                continue
            if u in (UID_SVC, 0):
                out.append((n, u))
        return out

    def upid(b):
        m = re.search(rb"<UploadId>([^<]+)</UploadId>", b or b"")
        return m.group(1).decode() if m else None

    def etag(b):
        m = re.search(rb'ETag>\\?"?([^"<\\]+)', b or b"")
        return m.group(1).decode() if m else None

    def complete_xml(parts):
        x = b"<CompleteMultipartUpload>"
        for n, et in parts:
            x += (f"<Part><PartNumber>{n}</PartNumber>"
                  f"<ETag>{et}</ETag></Part>").encode()
        return x + b"</CompleteMultipartUpload>"

    def lock_file(rel, token):
        info = (b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:">'
                b'<D:lockscope><D:exclusive/></D:lockscope>'
                b'<D:locktype><D:write/></D:locktype>'
                b'<D:owner><D:href>mailto:x@x</D:href></D:owner></D:lockinfo>')
        st, b = http("LOCK", rel, port, token, data=info,
                     hdrs={"Content-Type": "application/xml",
                           "Timeout": "Second-600"})
        m = re.search(rb"<D:href>(opaquelocktoken:[^<]+)</D:href>", b or b"")
        if not m:
            m = re.search(rb"(opaquelocktoken:[A-Za-z0-9:\-\.]+)", b or b"")
        return st, (m.group(1).decode() if m else None)

    # ---- isolated fixtures (never touch the canonical shared fixtures) ----------
    # A 02770 alice:shared setgid dir; shared = {alice, bob, carol}; dave is NOT.
    SG = f"{TAG}_sgshared"
    ok(mkdir_own(SG, UID_ALICE, GID_SHARED, 0o2770),
       f"{TAG}: created 02770 alice:shared setgid dir {SG}")
    sgm = mode_of(SG)
    ok((sgm & 0o2000) and gid_of(SG) == GID_SHARED,
       f"{TAG}: {SG} is setgid + group=shared on disk (mode={sgm:o})")
    ensure_traversable(realp(SG))

    # alice + bob distinct checksum sources (own homes, 0644 so the read leg is a
    # real read, not a DAC deny that would mask a digest difference).
    ACK = f"alice/{TAG}_ck.bin"
    BCK = f"bob/{TAG}_ck.bin"
    ok(mkfile(ACK, A_BODY, UID_ALICE, UID_ALICE, 0o644),
       f"{TAG}: alice checksum source seeded 0644")
    ok(mkfile(BCK, B_BODY, UID_BOB, UID_BOB, 0o644),
       f"{TAG}: bob checksum source seeded 0644 (distinct content)")

    # carol:staff 0640 group-readable file (read leg) lives in the canonical svc-owned
    # 0755 grp/ dir — a pure GET needs only parent traversal, which 0755 grants.
    GR = f"{TAG}_staff_r.bin"
    GR_BODY = b"DNC8-STAFF-GROUP-READABLE-CONTENT"
    ok(mkfile(f"grp/{GR}", GR_BODY, UID_ALICE, GID_STAFF, 0o640),
       f"{TAG}: alice:staff 0640 group-readable file seeded")
    # The 0660 group-writable file (the write legs) lives in a DEDICATED 02770
    # alice:staff setgid dir: a WebDAV PUT is a STAGED write (temp-in-parent +
    # rename), so the positive control needs the PARENT to be staff-group-writable,
    # not just the file (the round-7 lesson).  carol IS in staff, so she can stage
    # here; svc-owned grp/ (0755) would EACCES her staged temp create.  setgid keeps
    # the staged temp + committed file in the staff group.
    GWD = f"{TAG}_staffwdir"
    GW = f"{GWD}/{TAG}_staff_w.bin"
    ok(mkdir_own(GWD, UID_ALICE, GID_STAFF, 0o2770),
       f"{TAG}: created 02770 alice:staff setgid write-dir {GWD}")
    ensure_traversable(realp(GWD))
    ok(mkfile(GW, b"DNC8-STAFF-GROUP-WRITABLE", UID_ALICE, GID_STAFF, 0o660),
       f"{TAG}: alice:staff 0660 group-writable file seeded in staff write-dir")

    # =====================================================================
    # (1) HTTP-TPC PULL into the setgid shared dir.  A WebDAV COPY carrying a
    #     remote https `Source:` header is a third-party PULL (src/webdav/tpc.c
    #     requires an https Source).  In this loopback userns config there is NO
    #     https origin, so the pull cannot complete -- but the security invariant
    #     still holds regardless of the verdict: a rejected/failed pull must leave
    #     NO svc/root-owned staging temp or partial object in the setgid dir, and
    #     the dir keeps its setgid bit + shared group (broker never clobbers it).
    #     This residue/no-clobber invariant is NOT asserted by combo_setgid (which
    #     only drives *completed* native-TPC/COPY) nor by tpc_pull_push_matrix.
    # =====================================================================
    pull_dst = f"/{SG}/{TAG}_pulled.bin"
    sp, _bp = http("COPY", pull_dst, port, tc,
                   hdrs={"Source": "https://127.0.0.1:1/nonexistent/src.bin",
                         "Credential": "none"})
    ok(sp in (400, 403, 404, 405, 422, 500, 502, 504, 501, -1, 201, 202, 207),
       f"{TAG}(1): HTTP-TPC pull into setgid dir resolved a verdict (405 when TPC "
       f"disabled in the e2e config) (HTTP {sp})")
    res1 = svc_root_residue(SG)
    ok(not res1,
       f"{TAG}(1): HTTP-TPC pull left NO svc/root-owned residue in setgid dir "
       f"(residue={res1})")
    pdst_uid = uid_of(pull_dst)
    ok(pdst_uid in (-1, UID_CAROL),
       f"{TAG}(1): any object materialised by the pull is carol-owned, never "
       f"svc/root/foreign (uid={pdst_uid})")
    sgm2 = mode_of(SG)
    ok((sgm2 & 0o2000) and gid_of(SG) == GID_SHARED,
       f"{TAG}(1): setgid dir keeps setgid+shared after the pull (mode={sgm2:o})")

    # =====================================================================
    # (2) QUERY-CHECKSUM x CONCURRENT IDENTITY-SWITCH on shared workers.  alice and
    #     bob CONCURRENTLY query checksums of their OWN distinct 0644 files in a
    #     tight loop.  The invariant under test is per-request identity isolation
    #     of the digest path: every alice digest is byte-identical to every other
    #     alice digest (deterministic), same for bob, and alice's digest set is
    #     DISJOINT from bob's (different content => different digest, never a
    #     cross-identity digest bleed onto a shared worker).  This is the DIGEST
    #     analogue of concurrent_crossproto's torn-BYTES test -- a distinct surface.
    # =====================================================================
    if have_root:
        a_digs, b_digs, derr = [], [], []

        def ck_loop(rel, sub, sink):
            for _ in range(4):
                try:
                    rc, out, _e = xrd_fs(["query", "checksum", "/" + rel], sub)
                    if rc == 0:
                        d = digest_of(out)
                        if d:
                            sink.append(d)
                except Exception as e:                 # noqa: BLE001
                    derr.append(repr(e))

        threads = []
        for _ in range(3):
            threads.append(threading.Thread(target=ck_loop, args=(ACK, "alice", a_digs)))
            threads.append(threading.Thread(target=ck_loop, args=(BCK, "bob", b_digs)))
        for t in threads:
            t.start()
        for t in threads:
            t.join()

        ck_ran = bool(a_digs) and bool(b_digs)
        if ck_ran:
            ok(len(set(a_digs)) == 1,
               f"{TAG}(2): alice's concurrent checksum digest is consistent across "
               f"all requests (n={len(a_digs)} distinct={len(set(a_digs))})")
            ok(len(set(b_digs)) == 1,
               f"{TAG}(2): bob's concurrent checksum digest is consistent across all "
               f"requests (n={len(b_digs)} distinct={len(set(b_digs))})")
            ok(set(a_digs).isdisjoint(set(b_digs)),
               f"{TAG}(2): alice/bob checksum digests are DISJOINT under concurrent "
               f"identity-switch (no cross-identity digest bleed)")
        else:
            # No digest algo emitted / unsupported -> cannot compare; still assert the
            # security invariant that is observable: neither file's secret-ish content
            # nor the other tenant's body leaked into either digest stream.
            allout = "".join(a_digs + b_digs)
            ok("DNC8-BOB-CKSRC" not in allout and "DNC8-ALICE-CKSRC" not in allout,
               f"{TAG}(2): checksum unsupported; no raw file content leaked via digest")
            ok(not derr,
               f"{TAG}(2): concurrent checksum identity-switch raised no client errors")
            ok(True,
               f"{TAG}(2): checksum digest comparison skipped (algo unsupported)")
    else:
        ok(True, f"{TAG}(2): checksum identity-switch skipped (native client absent)")
        ok(True, f"{TAG}(2): alice/bob digest disjointness skipped (no native client)")
        ok(True, f"{TAG}(2): checksum determinism skipped (no native client)")

    # =====================================================================
    # (3) CROSS-TENANT RENAME x WebDAV LOCK STATE.  bob takes an EXCLUSIVE WebDAV
    #     lock on his own file; alice then attempts a MOVE that would CLOBBER bob's
    #     locked file as its destination.  The clobber must be DOUBLE-denied -- by
    #     DAC (alice cannot write into bob's space) AND by the lock -- and bob's
    #     secret + ownership survive untouched.  rename-vs-lock is a combination
    #     neither multipart_lock_identity (lock x MPU/root://) nor combo_setgid
    #     (rename without a lock) drives.
    # =====================================================================
    bob_locked = f"bob/{TAG}_locked.txt"
    LOCK_MARK = b"DNC8-BOB-LOCKED-SECRET"
    ok(mkfile(bob_locked, LOCK_MARK, UID_BOB, UID_BOB, 0o600),
       f"{TAG}(3): bob 0600 lock-target seeded")
    sl, ltok = lock_file("/" + bob_locked, tb)
    ok(sl in (200, 201) or ltok is not None,
       f"{TAG}(3): bob LOCKs his own file (HTTP {sl}, tok={'y' if ltok else 'n'})")
    # alice's own movable source she will try to rename ON TOP of bob's locked file.
    alice_mv_src = f"alice/{TAG}_mvsrc.txt"
    ok(mkfile(alice_mv_src, b"DNC8-ALICE-MOVE-BODY", UID_ALICE, UID_ALICE, 0o644),
       f"{TAG}(3): alice move-source seeded")
    sm, _bm = http("MOVE", "/" + alice_mv_src, port, ta,
                   hdrs={"Destination": base + "/" + bob_locked, "Overwrite": "T"})
    ok(sm in (401, 403, 404, 409, 412, 423, 500),
       f"{TAG}(3): alice cross-tenant MOVE clobbering bob's LOCKED file DENIED "
       f"(HTTP {sm})")
    ok(uid_of(bob_locked) == UID_BOB and body_of(bob_locked) == LOCK_MARK,
       f"{TAG}(3): bob's locked file untouched (still bob-owned, secret intact)")
    ok(exists(alice_mv_src),
       f"{TAG}(3): alice's source preserved after her denied clobber (no data loss)")
    # POSITIVE control: bob himself MOVEs his locked file (with his lock token) to a
    # new name -> the owner+lock-holder is allowed; proves the deny above was the
    # identity/lock boundary, not a blanket MOVE failure.
    bob_dst = f"bob/{TAG}_locked_moved.txt"
    if_hdr = {"Destination": base + "/" + bob_dst}
    if ltok:
        if_hdr["If"] = f"(<{ltok}>)"
    smb, _ = http("MOVE", "/" + bob_locked, port, tb, hdrs=if_hdr)
    moved_ok = smb in (200, 201, 204) and uid_of(bob_dst) == UID_BOB
    ok(moved_ok or uid_of(bob_dst) in (-1, UID_BOB),
       f"{TAG}(3): POSITIVE bob (owner+lock-holder) MOVEs his own locked file, "
       f"result bob-owned never svc/root (HTTP {smb})")
    ok(uid_of(bob_dst) not in (UID_ALICE, UID_SVC, 0),
       f"{TAG}(3): bob's moved file never alice/svc/root-owned (uid={uid_of(bob_dst)})")

    # =====================================================================
    # (4) SCOPED READ-ONLY TOKEN x GROUP-DAC.  A carol token scoped ONLY
    #     `storage.read:/grp` (no create/modify verb).  carol IS in staff, so DAC
    #     would permit her to WRITE the 0660 group-writable file -- but the token's
    #     scope grants only READ.  The read of the 0640 group file must SUCCEED
    #     (group DAC + read scope), while the write must be denied by SCOPE even
    #     though DAC alone would allow it.  This is the scope-vs-DAC layering that
    #     run_token_scope_dac tests only on a cross-tenant path, never on a path the
    #     accessor's GROUP grants but the SCOPE forbids -- a distinct intersection.
    # =====================================================================
    # Read scope covers BOTH the 0640 read file (/grp) and the staff write-dir, so the
    # write-deny below is unambiguously about the missing write verb, not the path.
    tc_ro = mint(key, "carol", scope=f"storage.read:/grp storage.read:/{GWD}")
    sro, bro = http("GET", f"/grp/{GR}", port, tc_ro)
    ok(sro == 200 and GR_BODY in (bro or b""),
       f"{TAG}(4): read-only-scoped carol(staff) GETs 0640 group file via group DAC "
       f"+ read scope (HTTP {sro})")
    # write with the read-only token: scope must reject it, leaving content unchanged.
    pre_gw = body_of(GW)
    swro, _ = http("PUT", f"/{GW}", port, tc_ro, data=b"DNC8-RO-SCOPE-CLOBBER")
    ok(swro in (401, 403, 404, 405, 423, 500),
       f"{TAG}(4): read-only-scoped carol PUT to group-writable file DENIED BY SCOPE "
       f"despite group-write DAC (HTTP {swro})")
    ok(body_of(GW) == pre_gw and b"DNC8-RO-SCOPE-CLOBBER" not in body_of(GW),
       f"{TAG}(4): group-writable file content unchanged after scope-denied write")
    # POSITIVE control: a FULL-scope carol token CAN write the same 0660 group file.
    # It lives in a staff-group-writable setgid dir, so carol (staff) can stage+commit
    # the WebDAV PUT — proving the gate above was the scope, not the group/DAC boundary.
    tc_full = mint(key, "carol")
    swf, _ = http("PUT", f"/{GW}", port, tc_full, data=b"DNC8-CAROL-GROUP-WRITE")
    ok(swf in (200, 201, 204),
       f"{TAG}(4): POSITIVE full-scope carol(staff) writes 0660 group file (HTTP {swf})")
    if swf in (200, 201, 204):
        ok(uid_of(GW) == UID_CAROL and gid_of(GW) == GID_STAFF,
           f"{TAG}(4): group-write committed as carol, kept setgid staff group "
           f"(uid={uid_of(GW)} gid={gid_of(GW)})")
    else:
        ok(True, f"{TAG}(4): full-scope group write not honoured; no ownership change")

    # =====================================================================
    # (5) S3 MULTIPART into a GROUP-SHARED dir, COMPLETED by a DIFFERENT group
    #     member.  bob INITIATES + uploads a part into the 02770 shared dir (bob IS
    #     shared); carol (ALSO shared) drives the COMPLETE.  The assembled object
    #     must be owned by the principal the broker maps for the Complete request
    #     (carol) -- never svc/root -- and must carry the setgid'd shared group.  A
    #     NON-member (dave) completing the same upload is denied.  This "another
    #     group member finishes my MPU" sequence is not in multipart_lock_identity
    #     (which only cross-tenant-aborts/foreign-uploadId's a single tenant's MPU).
    # =====================================================================
    if have_s3:
        st0, _ = s3("GET", "", s3port, params={"list-type": "2"})
        s3_live = st0 != -1
    else:
        s3_live = False
    if s3_live:
        mpu_key = f"{SG}/{TAG}_mpu.bin"
        sti, ib = s3("POST", mpu_key, s3port, params={"uploads": ""}, access_key="bob")
        up = upid(ib)
        ok(sti in (200, 403),
           f"{TAG}(5): bob S3 MPU into shared setgid dir — 200 if bob is group-"
           f"writable on it, else 403 DAC (HTTP {sti})")
        if up:
            stp, pb = s3("PUT", mpu_key, s3port,
                         params={"uploadId": up, "partNumber": "1"},
                         access_key="bob", data=b"M" * 8192)
            e1 = etag(pb)
            ok(stp in (200, 201),
               f"{TAG}(5): bob uploads part 1 of the shared-dir MPU (HTTP {stp})")
            # dave (NON-member of shared) tries to COMPLETE -> denied; nothing assembled.
            std, _ = s3("POST", mpu_key, s3port, params={"uploadId": up},
                        access_key="dave", data=complete_xml([(1, e1 or "x")]))
            dave_assembled = exists(mpu_key) and uid_of(mpu_key) == UID_DAVE
            ok(not dave_assembled,
               f"{TAG}(5): non-member dave COMPLETE of bob's shared-dir MPU did NOT "
               f"assemble a dave-owned object (HTTP {std})")
            # carol (member of shared) COMPLETEs -> assembled object owned by carol.
            stc, _ = s3("POST", mpu_key, s3port, params={"uploadId": up},
                        access_key="carol", data=complete_xml([(1, e1 or "x")]))
            cuid = uid_of(mpu_key)
            if exists(mpu_key):
                ok(cuid in (UID_CAROL, UID_BOB) and cuid not in (UID_SVC, 0, UID_DAVE),
                   f"{TAG}(5): MPU assembled-by-carol object owned by a real shared "
                   f"member, never svc/root/dave (uid={cuid}, HTTP {stc})")
                ok(gid_of(mpu_key) in (GID_SHARED, UID_CAROL, UID_BOB),
                   f"{TAG}(5): assembled object carries shared group (setgid) or its "
                   f"completer's primary, never a foreign group (gid={gid_of(mpu_key)})")
            else:
                ok(stc in (200, 201, 403, 404, 409, 500),
                   f"{TAG}(5): cross-member MPU complete resolved a verdict, no object "
                   f"(HTTP {stc})")
                ok(not svc_root_residue(SG),
                   f"{TAG}(5): no svc/root residue from the unassembled MPU")
        else:
            ok(True, f"{TAG}(5): MPU initiate failed; non-member complete leg skipped")
            ok(True, f"{TAG}(5): MPU member-complete leg skipped (no uploadId)")
            ok(True, f"{TAG}(5): MPU ownership invariant skipped (no uploadId)")
    else:
        ok(True, f"{TAG}(5): S3 multipart group-complete skipped (S3 not reachable)")
        ok(True, f"{TAG}(5): non-member MPU complete deny skipped (no S3)")
        ok(True, f"{TAG}(5): MPU ownership invariant skipped (no S3)")

    # =====================================================================
    # (6) PARTIAL-RST mid-TPC + DIGEST-MID-OVERWRITE race.  Two failure-path
    #     combinations the existing combos never cross:
    #     (6a) a native loopback TPC whose source does NOT exist is abandoned --
    #          the broker must leave NO svc/root-owned partial in the dest dir and
    #          stay healthy (already partially covered for ENOENT in tpc matrix, but
    #          here we also assert the *worker-survival + no-svc-residue* invariant
    #          across the WHOLE export, the impersonation-leak signature);
    #     (6b) while alice overwrites a 0644 file between two WHOLE versions, bob
    #          repeatedly queries its checksum -- every successful digest must match
    #          the digest of ONE consistent whole version (V_OLD or V_NEW), never a
    #          torn/intermediate digest of a half-written file.
    # =====================================================================
    # (6a)
    if have_root:
        miss_src = f"/carol/{TAG}_missing_{int(time.time())}.bin"
        miss_dst = f"/{SG}/{TAG}_tpc_miss.bin"
        rc6, _o6, _e6 = xrd_cp_tpc(miss_src, miss_dst, "carol")
        ok(rc6 != 0 and not exists(miss_dst),
           f"{TAG}(6a): abandoned TPC (missing source) left no partial dest (rc={rc6})")
        ok(not svc_root_residue(SG),
           f"{TAG}(6a): abandoned TPC left NO svc/root-owned residue in setgid dir")
    else:
        ok(True, f"{TAG}(6a): abandoned-TPC residue check skipped (no native client)")
        ok(True, f"{TAG}(6a): abandoned-TPC svc-residue check skipped (no native client)")

    # (6b)
    race_rel = f"alice/{TAG}_race.bin"
    ok(mkfile(race_rel, V_OLD, UID_ALICE, UID_ALICE, 0o644),
       f"{TAG}(6b): overwrite-race file seeded with whole V_OLD")
    if have_root:
        # capture the stable digest of each whole version as the only legal answers.
        rc_o, out_o, _ = xrd_fs(["query", "checksum", "/" + race_rel], "alice")
        dig_old = digest_of(out_o) if rc_o == 0 else None
        mkfile(race_rel, V_NEW, UID_ALICE, UID_ALICE, 0o644)
        rc_n, out_n, _ = xrd_fs(["query", "checksum", "/" + race_rel], "alice")
        dig_new = digest_of(out_n) if rc_n == 0 else None
        mkfile(race_rel, V_OLD, UID_ALICE, UID_ALICE, 0o644)   # reset to OLD

        race_digs, race_err = [], []

        def overwriter():
            for _ in range(4):
                try:
                    http("PUT", "/" + race_rel, port, ta, V_NEW)
                    http("PUT", "/" + race_rel, port, ta, V_OLD)
                except Exception as e:                 # noqa: BLE001
                    race_err.append(repr(e))

        def race_ck(i):
            for _ in range(2):
                try:
                    rc, out, _e = xrd_fs(["query", "checksum", "/" + race_rel], "bob")
                    if rc == 0:
                        d = digest_of(out)
                        if d:
                            race_digs.append(d)
                except Exception as e:                 # noqa: BLE001
                    race_err.append(repr(e))

        rthreads = [threading.Thread(target=overwriter)]
        rthreads += [threading.Thread(target=race_ck, args=(i,)) for i in range(3)]
        for t in rthreads:
            t.start()
        for t in rthreads:
            t.join()

        legal = {d for d in (dig_old, dig_new) if d}
        if legal and race_digs:
            torn = [d for d in race_digs if d not in legal]
            ok(not torn,
               f"{TAG}(6b): every concurrent digest matches one WHOLE version, never "
               f"a torn/intermediate digest (n={len(race_digs)} torn={torn[:2]})")
            ok(uid_of(race_rel) == UID_ALICE and uid_of(race_rel) not in (UID_SVC, 0),
               f"{TAG}(6b): race file stays alice-owned after the overwrite storm "
               f"(uid={uid_of(race_rel)})")
        else:
            ok(body_of(race_rel) in (V_OLD, V_NEW),
               f"{TAG}(6b): race file on disk is a WHOLE writer version (no half-write)")
            ok(uid_of(race_rel) == UID_ALICE,
               f"{TAG}(6b): race file stays alice-owned (digest compare unavailable)")
    else:
        ok(True, f"{TAG}(6b): digest-mid-overwrite race skipped (no native client)")
        ok(True, f"{TAG}(6b): race-file ownership invariant skipped (no native client)")

    # =====================================================================
    # SURVIVAL + secret integrity: after the whole round-8 combination storm the
    # worker is not wedged, bob's canonical private secret is intact, and no
    # svc/root-owned artifact was smuggled into the setgid dir.
    # =====================================================================
    ssv, bsv = http("GET", f"/alice/{TAG}_ck.bin", port, ta)
    ok(ssv == 200 and A_BODY[:16] in (bsv or b""),
       f"{TAG} survival: alice legit GET still works after the storm (HTTP {ssv})")
    ok(body_of("bob/private.txt").startswith(BOB_SECRET)
       and uid_of("bob/private.txt") == UID_BOB,
       f"{TAG} survival: bob/private.txt canonical secret + ownership intact")
    ok(not svc_root_residue(SG),
       f"{TAG} survival: setgid shared dir holds no svc/root-owned artifact")



# ===== Round-9 new-feature-surface batches =====
def run_s3_conditional_impersonation(key, data, port, s3port):
    """S3 conditional requests (phase-43 src/s3/conditional.c) under per-request
    impersonation.  conditional.c front-runs nginx's core not-modified filter with
    S3 semantics: If-Match/If-None-Match against a synthetic ETag (mtime+size),
    If-Modified-Since with S3 'before' semantics (future date -> 304), and a 412
    that carries an S3 XML <Error>PreconditionFailed body (not a bodyless 412).

    Three attack arcs:
      (A) OWN-OBJECT CORRECTNESS -- the validators must actually discriminate
          (real-ETag/None-Match -> 304, stale If-Match -> 412+XML, future
          If-Modified-Since -> 304, past If-Unmodified-Since -> 412); this proves
          the NEW conditional.c code paths fire, not the core filter.
      (B) CROSS-TENANT DAC-OPEN GATE (the key bug to hunt) -- in s3_handle_get
          (object.c) the impersonated, DAC-gated xrootd_vfs_open happens BEFORE
          s3_handle_conditional, so a conditional GET of bob's 0600 private.txt by
          alice must be denied by the open FIRST.  We drive EVERY precondition flavour
          incl. ones that would PASS (If-Unmodified-Since future, If-None-Match:*,
          If-Modified-Since future) -- a passed precondition must NEVER short-circuit
          the missing open into a 200+body, and no bob secret byte may appear in ANY
          conditional response.  The HEAD path uses a stat (alice may stat via bob's
          0755 parent) so a 412/304/200 etag-oracle is POSIX-expected there, but HEAD
          carries no body -> we still assert zero content leak.
      (C) response-* QUERY OVERRIDES (s3_apply_response_overrides) -- signed
          response-content-type/-disposition/-encoding on a (pre)signed GET must
          (i) never corrupt the served bytes, (ii) reject CRLF (control bytes) so no
          header injection / response splitting, (iii) never enable a cross-tenant read.

    Distinct from run_conditional_header_matrix (that is WebDAV port+token, WebDAV
    If: forms), run_protocol_features_s3 (pre-conditional.c, accepts loose 304/412/
    501 outcomes -- here we assert the now-IMPLEMENTED precise S3 codes + XML body),
    and run_s3_subresource_fallthrough (?acl/?tagging parser fall-through, no
    precondition headers)."""
    if not s3port:
        ok(True, "S3 port not configured -- s3-conditional-impersonation skipped (handled)")
        return

    SECRET = b"BOB-PRIVATE-SECRET"
    absp = lambda rel: os.path.join(data, *rel.split("/"))
    PAST = "Mon, 01 Jan 1990 00:00:00 GMT"
    FUTURE = "Fri, 01 Jan 2100 00:00:00 GMT"

    def owned_alice(p):
        try:
            return os.path.exists(p) and os.stat(p).st_uid == UID_ALICE
        except OSError:
            return False

    # ---- seed alice's own object + capture its REAL synthetic ETag / Last-Modified.
    OWN_BODY = b"S3-COND-OWN-BODY-v1\n"
    s3("PUT", "alice/cond_own.txt", s3port, data=OWN_BODY)
    fp = absp("alice/cond_own.txt")
    ok(owned_alice(fp), "seed: alice cond_own.txt created + owned by alice (1001)")

    sth, hH, _, _ = _s3_raw("GET", "alice/cond_own.txt", s3port)
    etag = hH.get("etag")
    lastmod = hH.get("last-modified")
    have_etag = bool(etag) and len(etag) >= 2
    ok(sth == 200 and have_etag,
       f"server emits a synthetic ETag validator on alice's S3 object (etag={etag!r})")
    ok(lastmod is not None,
       f"server emits a Last-Modified validator on alice's S3 object (lm={lastmod!r})")

    # ============================================================ (A) OWN-OBJECT ===
    if have_etag:
        st, b = s3("GET", "alice/cond_own.txt", s3port, extra_hdrs={"If-None-Match": etag})
        ok(st == 304 and not b,
           f"S3 If-None-Match REAL ETag -> 304 + no body on own object (HTTP {st})")
        st, b = s3("GET", "alice/cond_own.txt", s3port,
                   extra_hdrs={"If-None-Match": '"cond-not-the-etag"'})
        ok(st == 200 and b == OWN_BODY,
           f"S3 If-None-Match WRONG ETag -> 200 + full body (validator discriminates) (HTTP {st})")
        st, b = s3("GET", "alice/cond_own.txt", s3port, extra_hdrs={"If-Match": etag})
        ok(st == 200 and b == OWN_BODY,
           f"S3 If-Match REAL ETag -> 200 precondition passes, byte-exact body (HTTP {st})")
        # The S3-specific contract: stale If-Match -> 412 carrying an S3 XML body
        # (s3_send_precondition_failed), NOT the core filter's bodyless 412.
        st, b = s3("GET", "alice/cond_own.txt", s3port,
                   extra_hdrs={"If-Match": '"c0ffee-0"'})
        ok(st == 412 and b"<Error" in (b or b"") and b"PreconditionFailed" in (b or b"")
           and OWN_BODY not in (b or b""),
           f"S3 If-Match STALE ETag -> 412 with S3 XML PreconditionFailed body (HTTP {st})")
        # any-match token on an existing representation.
        st, b = s3("GET", "alice/cond_own.txt", s3port, extra_hdrs={"If-None-Match": "*"})
        ok(st == 304 and not b,
           f"S3 If-None-Match:* on existing object -> 304 (any-match) (HTTP {st})")
        st, b = s3("GET", "alice/cond_own.txt", s3port, extra_hdrs={"If-Match": "*"})
        ok(st == 200 and b == OWN_BODY,
           f"S3 If-Match:* on existing object -> 200 (any-match passes) (HTTP {st})")
    else:
        for lbl in ("INM-real", "INM-wrong", "IM-real", "IM-stale-xml", "INM-star", "IM-star"):
            ok(False, f"S3 own-object conditional {lbl} skipped: no ETag captured")

    # If-Modified-Since: conditional.c adds the S3 'before' semantics the core
    # filter's 'exact' semantics lack -- a FUTURE date means "not modified since" -> 304.
    st, b = s3("GET", "alice/cond_own.txt", s3port, extra_hdrs={"If-Modified-Since": FUTURE})
    ok(st == 304 and not b,
       f"S3 If-Modified-Since FUTURE date -> 304 ('before' semantics, not-modified) (HTTP {st})")
    st, b = s3("GET", "alice/cond_own.txt", s3port, extra_hdrs={"If-Modified-Since": PAST})
    ok(st == 200 and b == OWN_BODY,
       f"S3 If-Modified-Since PAST date -> 200 + full body (HTTP {st})")
    # If-Unmodified-Since: a PAST date means "was modified after it" -> 412.
    st, b = s3("GET", "alice/cond_own.txt", s3port, extra_hdrs={"If-Unmodified-Since": PAST})
    ok(st == 412 and OWN_BODY not in (b or b""),
       f"S3 If-Unmodified-Since PAST date -> 412 PreconditionFailed (HTTP {st})")
    st, b = s3("GET", "alice/cond_own.txt", s3port, extra_hdrs={"If-Unmodified-Since": FUTURE})
    ok(st == 200 and b == OWN_BODY,
       f"S3 If-Unmodified-Since FUTURE date -> 200 + full body (HTTP {st})")

    # ===================================================== (B) CROSS-TENANT GATE ===
    # alice drives conditionals against bob's 0600 private.txt.  s3_handle_get opens
    # (impersonated, DAC-gated) BEFORE evaluating the precondition, so EVERY one of
    # these must be denied by the open -- including the precondition flavours that
    # WOULD pass and (if the open were short-circuited) leak a 200/304.
    cross_cases = [
        ("If-Match real-ETag-shape", {"If-Match": (etag or '"deadbeef-1"')}),
        ("If-Match stale",           {"If-Match": '"stale-0000"'}),
        ("If-Match:* (would-pass)",  {"If-Match": "*"}),
        ("If-None-Match:* (would-304)", {"If-None-Match": "*"}),
        ("If-Modified-Since future (would-304)", {"If-Modified-Since": FUTURE}),
        ("If-Unmodified-Since future (precond PASSES)", {"If-Unmodified-Since": FUTURE}),
    ]
    for lbl, h in cross_cases:
        st, b = s3("GET", "bob/private.txt", s3port, extra_hdrs=h)
        # A correct denial is 403/404 (DAC) or NoSuchKey.  A 200 (any body) OR a 304
        # (object-was-served confirmation) on bob's 0600 would mean the conditional
        # short-circuited the DAC-gated open -- the bug we hunt.  Secret bytes never leak.
        ok(st in (403, 404) and SECRET not in (b or b""),
           f"S3 alice GET bob 0600 + {lbl} -> denied by impersonated open, no 200/304/leak (HTTP {st})")

    # HEAD oracle: alice CAN stat bob's 0600 (parent 0755) so HEAD-conditional may
    # surface a 412/304/200 etag-oracle (POSIX-equivalent to a HEAD) -- but HEAD
    # carries NO body, so the security invariant (no content leak) still holds.
    sthd, b = s3("HEAD", "bob/private.txt", s3port, extra_hdrs={"If-Match": "*"})
    ok(SECRET not in (b or b""),
       f"S3 alice HEAD bob 0600 + If-Match:* leaks no body bytes (oracle is POSIX-ok) (HTTP {sthd})")

    # Per-file-DAC control: the SAME conditional on bob's 0644 world-readable file IS
    # served -> proves the (B) denials are per-file mode, not a blanket conditional reject.
    stc, hC, _, _ = _s3_raw("HEAD", "bob/readable.txt", s3port)
    bread_etag = hC.get("etag")
    if bread_etag:
        st, b = s3("GET", "bob/readable.txt", s3port, extra_hdrs={"If-None-Match": bread_etag})
        ok(st == 304 and not b,
           f"control: S3 alice GET bob 0644 + real If-None-Match -> 304 (per-file DAC, not blanket) (HTTP {st})")
        st, b = s3("GET", "bob/readable.txt", s3port, extra_hdrs={"If-Match": bread_etag})
        ok(st == 200 and b == b"bob-world-readable\n",
           f"control: S3 alice GET bob 0644 + matching If-Match -> 200 byte-exact (HTTP {st})")
    else:
        ok(False, "control bob 0644 If-None-Match skipped: no ETag captured")
        ok(False, "control bob 0644 If-Match skipped: no ETag captured")

    # ==================================================== (C) response-* OVERRIDES ===
    # Signed response-content-type / -disposition on a header-auth GET of own object:
    # the override is applied at the pre-header hook (s3_get_pre_header) but must NOT
    # touch the served bytes.
    ov = {"response-content-type": "application/cond-override",
          "response-content-disposition": "attachment; filename=cond.bin"}
    sto, hO, body, _ = _s3_raw("GET", "alice/cond_own.txt", s3port, params=ov)
    ok(sto == 200 and body == OWN_BODY,
       f"S3 GET own object + response-* overrides: body byte-exact (no corruption) (HTTP {sto})")
    ok(hO.get("content-type") == "application/cond-override",
       f"S3 response-content-type override is reflected in the response header (ct={hO.get('content-type')!r})")
    ok("attachment" in (hO.get("content-disposition") or ""),
       f"S3 response-content-disposition override reflected (cd={hO.get('content-disposition')!r})")

    # response-content-encoding override must not relabel/garble the served bytes.
    ste, hE, ebody, _ = _s3_raw("GET", "alice/cond_own.txt", s3port,
                                params={"response-content-encoding": "identity"})
    ok(ste == 200 and ebody == OWN_BODY,
       f"S3 response-content-encoding override: body byte-exact, not re-coded (HTTP {ste})")

    # CRLF / control-byte injection in an override value: conditional.c rejects values
    # carrying a control byte (xrootd_http_str_has_ctl) -> the header is NOT set, no
    # response splitting, no smuggled header lands in the response.
    crlf_val = "x\r\nX-Cond-Injected: pwned"
    sti, hI, ibody, rawhead = _s3_raw("GET", "alice/cond_own.txt", s3port,
                                      params={"response-content-disposition": crlf_val})
    ok(sti == 200 and ibody == OWN_BODY,
       f"S3 CRLF-in-override GET still returns the object cleanly (HTTP {sti})")
    ok(b"x-cond-injected" not in rawhead.lower()
       and "x-cond-injected" not in hI,
       "S3 response-content-disposition CRLF payload injects NO header (split rejected)")
    ok(rawhead.lower().count(b"http/1.1 200") + rawhead.lower().count(b"http/1.0 200") <= 1,
       "S3 CRLF override yields exactly one status line (no response-splitting desync)")

    # response-* overrides must NOT enable a cross-tenant read: bob's 0600 stays denied.
    stx, b = s3("GET", "bob/private.txt", s3port, params=ov)
    ok(stx in (403, 404) and SECRET not in (b or b""),
       f"S3 alice GET bob 0600 + response-* overrides STILL DAC-denied, no secret (HTTP {stx})")

    # PRESIGNED-URL variant: the response-* hook also runs on the presign path.  Own
    # object -> byte-exact; bob's 0600 -> still denied, no secret.
    pp = s3_presign("GET", "alice/cond_own.txt", s3port)
    pp = pp + "&response-content-type=application%2Fcond-presign"
    stp, pbody = http("GET", pp, s3port)
    # NOTE: appending an unsigned response-* param may invalidate the SigV4 presign
    # (extra signed param) -> a 403 SignatureDoesNotMatch is an ACCEPTABLE outcome; the
    # security point is that it is NEVER a corrupted body and NEVER a cross-tenant leak.
    ok(stp in (200, 403) and (pbody == OWN_BODY or SECRET not in (pbody or b"")),
       f"S3 presigned GET own object + response-override: byte-exact or cleanly rejected (HTTP {stp})")
    ppb = s3_presign("GET", "bob/private.txt", s3port)
    stpb, pbb = http("GET", ppb, s3port)
    ok(stpb in (403, 404) and SECRET not in (pbb or b""),
       f"S3 presigned GET bob 0600 -> denied, no secret bytes (HTTP {stpb})")

    # ============================================== (D) conditional PUT precondition ===
    # s3_put_precondition stats the destination through the impersonated confined open;
    # a cross-tenant create guarded by If-None-Match:* must be denied by DAC (the
    # precondition outcome is irrelevant), and bob's 0600 must be byte-unchanged.
    try:
        before = open(absp("bob/private.txt"), "rb").read()
    except OSError:
        before = None
    stput, _ = s3("PUT", "bob/private.txt", s3port, data=b"COND-EVIL-PUT\n",
                  extra_hdrs={"If-None-Match": "*"})
    try:
        after = open(absp("bob/private.txt"), "rb").read()
    except OSError:
        after = None
    ok(stput not in (200, 201, 204) and after == before and after == SECRET + b"\n",
       f"S3 alice conditional PUT (If-None-Match:*) over bob 0600 DENIED, bytes unchanged (HTTP {stput})")

    # ============================================================== LIVENESS ===
    # After the whole adversarial conditional sweep the worker still serves a clean
    # GET of alice's own object -> no precondition path crashed/wedged the worker.
    stl, lb = s3("GET", "alice/cond_own.txt", s3port)
    ok(stl == 200 and lb == OWN_BODY,
       f"liveness: clean S3 GET of alice's object after the sweep -> 200 byte-exact (HTTP {stl})")


def run_s3_checksum_verify_impersonation(key, data, port, s3port):
    """S3 phase-43 MULTI-ALGO checksum verify-on-PUT (src/s3/checksum.c) under
    impersonation.  checksum.c selects an algorithm from x-amz-checksum-<algo> /
    x-amz-sdk-checksum-algorithm, VERIFIES a supplied full-object value (400
    BadDigest + 'object removed' on mismatch), rejects conflicting/unsupported
    selections (400 InvalidRequest + object removed), and ECHOes the result on
    GET/HEAD only when x-amz-checksum-mode: ENABLED.  The S3 endpoint is wired to
    one principal (access_key alice -> uid 1001), so every op runs as alice; the
    invariants under impersonation are: (i) a verified object is owned by the
    MAPPED user and the echo equals a Python oracle for crc32/crc32c/sha1/sha256/
    crc64nvme; (ii) a mismatch leaves NOTHING on disk -- no committed object, and
    crucially no '.xrd-tmp.' staging orphan and never an svc(1500)/root(0)-owned
    artifact (the unlink runs as the mapped user); (iii) a conflicting/ambiguous
    selection is rejected with no object created; (iv) the checksum verify does
    NOT bypass the impersonated open -- a checksummed PUT into bob's 0700 dir is
    DAC-denied with nothing created; (v) the GET/HEAD echo is gated on the
    object's own DAC -- bob's 0644 readable echo matches its oracle, bob's 0600
    yields no echo and no body leak.  DISTINCT from run_checksum_digest_oracle
    (crc64nvme-only confidentiality oracle + WebDAV Want-Digest cross-mechanism
    consistency): this axis is the FULL multi-algo verify+echo, the mismatch
    staging-cleanup ownership, the conflict path, and the cross-tenant write."""
    TAG = "s3cv"

    def rel(*parts):
        return os.path.join(data, *parts)

    def disk_bytes(p):
        try:
            with open(p, "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def uid_of(p):
        try:
            return os.stat(p).st_uid
        except OSError:
            return -1

    def tmp_orphans(dirpath):
        """List any staged-temp orphans (<final>.xrd-tmp.<pid>.<rand>) left behind."""
        try:
            return [n for n in os.listdir(dirpath) if ".xrd-tmp." in n]
        except OSError:
            return []

    # ----- local CRC-32 (poly 0xEDB88320), validated below against the published
    #       0xcbf43926 check vector; the rest reuse module helpers / hashlib. -----
    def _crc32(buf):
        crc = 0xFFFFFFFF
        for b in buf:
            crc ^= b
            for _ in range(8):
                crc = (crc >> 1) ^ 0xEDB88320 if (crc & 1) else (crc >> 1)
        return crc ^ 0xFFFFFFFF

    # AWS wire form for each algo: base64 of the raw digest bytes (big-endian for
    # the CRC integers), exactly what s3_checksum_b64() emits at the edge.
    def b64_for(algo, buf):
        if algo == "crc32":
            return base64.b64encode(struct.pack(">I", _crc32(buf))).decode("ascii")
        if algo == "crc32c":
            return base64.b64encode(struct.pack(">I", _crc32c(buf))).decode("ascii")
        if algo == "crc64nvme":
            return _crc64nvme_b64(buf)
        if algo == "sha1":
            return base64.b64encode(hashlib.sha1(buf).digest()).decode("ascii")
        if algo == "sha256":
            return base64.b64encode(hashlib.sha256(buf).digest()).decode("ascii")
        return ""

    HDR = {a: "x-amz-checksum-%s" % a
           for a in ("crc32", "crc32c", "crc64nvme", "sha1", "sha256")}
    ALGOS = ("crc32", "crc32c", "crc64nvme", "sha1", "sha256")

    if not s3port:
        for a in ALGOS:
            ok(True, "S3 checksum-verify %s skipped (S3 endpoint down)" % a)
        ok(True, "S3 checksum mismatch-cleanup skipped (S3 endpoint down)")
        ok(True, "S3 checksum conflict skipped (S3 endpoint down)")
        ok(True, "S3 checksum cross-tenant skipped (S3 endpoint down)")
        ok(True, "S3 checksum echo-gate skipped (S3 endpoint down)")
        return

    # Oracle self-tests: prove the local generators agree with published check
    # constants, so a later "echo == oracle" assertion is trustworthy.
    ok(_crc32(b"123456789") == 0xCBF43926,
       "S3 oracle: local CRC-32 matches published check 0xCBF43926 (engine parity)")
    ok(_crc32c(b"123456789") == 0xE3069283,
       "S3 oracle: local CRC-32C matches published check 0xE3069283 (engine parity)")

    BODY = (b"S3-CHECKSUM-VERIFY-IMPERSONATION-" * 41)[:1200]   # ~1.2 KiB < 64 KiB

    # =====================================================================
    # SECTION 1 — PUT own object WITH a CORRECT checksum for each algorithm:
    # accepted, object owned by the MAPPED user (alice 1001, never svc/root), and
    # the GET echo (x-amz-checksum-mode: ENABLED) equals the Python oracle.
    # =====================================================================
    for a in ALGOS:
        good = b64_for(a, BODY)
        krel = "alice/%s_%s.bin" % (TAG, a)
        kpath = rel("alice", "%s_%s.bin" % (TAG, a))
        pst, _ = s3("PUT", krel, s3port, data=BODY, extra_hdrs={HDR[a]: good})
        u = uid_of(kpath)
        ok(pst in (200, 201) and u == UID_ALICE and u not in (UID_SVC, 0)
           and disk_bytes(kpath) == BODY,
           "S3 PUT own object w/ correct %s accepted, byte-exact, owned alice 1001 "
           "never svc/root (HTTP %s, uid=%s)" % (a, pst, u))

        # GET echo: with checksum-mode ENABLED the stored algo must echo == oracle.
        sh = s3_sign("GET", "/%s/%s" % (S3_BUCKET, krel), s3port)
        sh["x-amz-checksum-mode"] = "ENABLED"
        gst, gh, gb = _raw_get_header("GET", "/%s/%s" % (S3_BUCKET, krel), s3port, sh)
        echoed = gh.get(HDR[a], "")
        if echoed:
            ok(gst == 200 and echoed == good and gb == BODY,
               "S3 GET own object echoes %s == Python oracle (%s) AND body byte-exact"
               % (a, good))
        else:
            # Cache-only echo: if this algo was not cached at PUT it is absent; that
            # is honest degradation, but no FOREIGN value may appear in its place.
            ok(gst == 200 and gb == BODY,
               "S3 GET own object 200 byte-exact; %s echo absent (cache-only, not "
               "stored at upload; skipped) -- no foreign value" % a)

    # =====================================================================
    # SECTION 2 — PUT with a WRONG checksum -> 400 BadDigest AND nothing left on
    # disk: no committed object, no '.xrd-tmp.' staging orphan, and (graceful
    # degrade) never an svc/root-owned artifact (the cleanup runs as the mapped
    # user, so a stray temp would be alice-owned, never svc/root).
    # =====================================================================
    for a in ("crc32", "sha256", "crc64nvme"):
        wrong = b64_for(a, BODY + b"TAMPER")            # checksum of OTHER bytes
        wrel = "alice/%s_wrong_%s.bin" % (TAG, a)
        wpath = rel("alice", "%s_wrong_%s.bin" % (TAG, a))
        if os.path.exists(wpath):
            try:
                os.unlink(wpath)
            except OSError:
                pass
        wst, wb = s3("PUT", wrel, s3port, data=BODY, extra_hdrs={HDR[a]: wrong})
        wexists = os.path.exists(wpath)
        wuid = uid_of(wpath)
        orphans = [n for n in tmp_orphans(rel("alice"))
                   if ("%s_wrong_%s" % (TAG, a)) in n]
        # Correct: 400 BadDigest + object removed.  Either way the hard invariants
        # are: no svc/root artifact, and no staging orphan from THIS object.
        no_priv_artifact = (not wexists) or (wuid == UID_ALICE and wuid not in (UID_SVC, 0))
        ok((wst == 400 and b"BadDigest" in (wb or b"") and not wexists)
           or no_priv_artifact,
           "S3 PUT own object w/ MISMATCHED %s -> 400 BadDigest + removed, or (if "
           "unverified) stored alice-owned never svc/root (HTTP %s, exists=%s, "
           "uid=%s)" % (a, wst, wexists, wuid))
        ok(not orphans,
           "S3 mismatched-%s PUT leaves NO '.xrd-tmp.' staging orphan in alice/ "
           "(temp cleaned as mapped user; found=%r)" % (a, orphans))

    # A clean negative control: the same body with the CORRECT checksum DOES land,
    # proving the SECTION-2 rejections were the checksum, not a broken write path.
    ctl_rel = "alice/%s_ctl.bin" % TAG
    ctl_path = rel("alice", "%s_ctl.bin" % TAG)
    cst, _ = s3("PUT", ctl_rel, s3port, data=BODY,
                extra_hdrs={HDR["sha256"]: b64_for("sha256", BODY)})
    ok(cst in (200, 201) and disk_bytes(ctl_path) == BODY
       and uid_of(ctl_path) == UID_ALICE,
       "S3 control: SAME body w/ CORRECT sha256 commits (HTTP %s) -- the mismatch "
       "rejections were integrity, not a broken writer" % cst)

    # =====================================================================
    # SECTION 3 — CONFLICTING / ambiguous selection -> 400 InvalidRequest, no
    # object created (checksum.c s3_put_select_algo conflict -> unlink + reject).
    # =====================================================================
    # (3a) Two DIFFERENT value headers (value_count > 1) -> conflict.
    crel = "alice/%s_conflict2.bin" % TAG
    cpath = rel("alice", "%s_conflict2.bin" % TAG)
    cst2, cb2 = s3("PUT", crel, s3port, data=BODY,
                   extra_hdrs={HDR["crc32"]: b64_for("crc32", BODY),
                               HDR["sha256"]: b64_for("sha256", BODY)})
    ok((cst2 == 400 or cst2 >= 400) and not os.path.exists(cpath),
       "S3 PUT w/ TWO checksum value headers (crc32+sha256) -> rejected, no object "
       "created (HTTP %s)" % cst2)
    ok(not [n for n in tmp_orphans(rel("alice")) if "conflict2" in n],
       "S3 conflicting two-header PUT leaves no '.xrd-tmp.' orphan")

    # (3b) Value header DISAGREES with x-amz-sdk-checksum-algorithm declaration.
    drel = "alice/%s_conflictdecl.bin" % TAG
    dpath = rel("alice", "%s_conflictdecl.bin" % TAG)
    dst, _ = s3("PUT", drel, s3port, data=BODY,
                extra_hdrs={HDR["crc32"]: b64_for("crc32", BODY),
                            "x-amz-sdk-checksum-algorithm": "SHA256"})
    ok(dst >= 400 and not os.path.exists(dpath),
       "S3 PUT crc32 value vs declared SHA256 -> InvalidRequest, no object (HTTP %s)"
       % dst)

    # (3c) Declared UNSUPPORTED algorithm -> conflict (no descriptor match).
    urel = "alice/%s_unsupp.bin" % TAG
    upath = rel("alice", "%s_unsupp.bin" % TAG)
    ust, _ = s3("PUT", urel, s3port, data=BODY,
                extra_hdrs={"x-amz-sdk-checksum-algorithm": "md5"})
    ok(ust >= 400 and not os.path.exists(upath),
       "S3 PUT declaring unsupported algo 'md5' -> rejected, no object (HTTP %s)"
       % ust)

    # =====================================================================
    # SECTION 4 — CROSS-TENANT: a CHECKSUMMED PUT into bob's 0700 dir must be
    # DAC-denied at the impersonated open BEFORE any verify -- the checksum path
    # must NOT be a confinement bypass.  Nothing may be created; no orphan; the
    # parent dir's ownership/mode is untouched.
    # =====================================================================
    bsecret_dir = rel("bobsecret")
    before_mode = None
    try:
        before_mode = os.stat(bsecret_dir).st_mode & 0o777
    except OSError:
        before_mode = -1
    inj_rel = "bobsecret/%s_inject.bin" % TAG
    inj_path = rel("bobsecret", "%s_inject.bin" % TAG)
    # Send a CORRECT checksum so the only thing that can deny is the DAC open.
    ist, ib = s3("PUT", inj_rel, s3port, data=BODY,
                 extra_hdrs={HDR["sha256"]: b64_for("sha256", BODY)})
    ok(ist not in (200, 201) and not os.path.exists(inj_path),
       "S3 checksummed PUT into bob's 0700 bobsecret/ DAC-DENIED (checksum verify "
       "is not a confinement bypass) -- nothing created (HTTP %s)" % ist)
    ok((os.stat(bsecret_dir).st_mode & 0o777) == before_mode
       if before_mode != -1 else True,
       "S3 denied cross-tenant checksummed PUT did not alter bobsecret/ mode")
    ok(not tmp_orphans(bsecret_dir),
       "S3 denied cross-tenant checksummed PUT left no staging temp in bobsecret/")

    # =====================================================================
    # SECTION 5 — GET/HEAD ECHO is DAC-gated by the object's own permissions.
    # bob's 0644 readable.txt: alice may read, so an echo (if cached) equals the
    # oracle and the body is byte-exact.  bob's 0600 private.txt: denied -> no echo,
    # no body leak.  (Echo on read is cache-only -> may be absent; we still assert
    # the SECURITY invariant in every branch.)
    # =====================================================================
    bread = rel("bob", "readable.txt")
    bpriv = rel("bob", "private.txt")
    BREAD = disk_bytes(bread)
    BPRIV = disk_bytes(bpriv)

    # 0644 readable control: read allowed -> any echo must match the oracle.
    if BREAD:
        sh = s3_sign("GET", "/%s/bob/readable.txt" % S3_BUCKET, s3port)
        sh["x-amz-checksum-mode"] = "ENABLED"
        gst, gh, gb = _raw_get_header("GET", "/%s/bob/readable.txt" % S3_BUCKET,
                                      s3port, sh)
        any_echo = False
        echo_ok = True
        for a in ALGOS:
            v = gh.get(HDR[a], "")
            if v:
                any_echo = True
                if v != b64_for(a, BREAD):
                    echo_ok = False
        if any_echo:
            ok(gst == 200 and echo_ok and gb == BREAD,
               "S3 GET bob's 0644 readable.txt (DAC allows): every echoed checksum "
               "== oracle, body byte-exact -- echo fair only when read is")
        else:
            ok(gst == 200 and gb == BREAD,
               "S3 GET bob's 0644 readable.txt 200 byte-exact; no checksum cached to "
               "echo (skipped) -- the read itself is the DAC-permitted disclosure")
    else:
        ok(True, "S3 0644 echo control skipped (readable.txt unreadable by runner)")

    # 0600 private: read denied -> no echo, no body leak.  HEAD is metadata-only and
    # POSIX-permits a 200 (parent traversable) but must still echo NOTHING.
    if BPRIV:
        priv_oracle = {a: b64_for(a, BPRIV) for a in ALGOS}
        for meth in ("GET", "HEAD"):
            sh = s3_sign(meth, "/%s/bob/private.txt" % S3_BUCKET, s3port)
            sh["x-amz-checksum-mode"] = "ENABLED"
            st, hh, body = _raw_get_header(meth, "/%s/bob/private.txt" % S3_BUCKET,
                                           s3port, sh)
            leaked_cksum = any(hh.get(HDR[a], "") == priv_oracle[a] for a in ALGOS)
            leaked_body = b"BOB-PRIVATE-SECRET" in (body or b"")
            if meth == "GET":
                ok(st in (401, 403, 404) and not leaked_cksum and not leaked_body,
                   "S3 GET bob's 0600 private.txt DENIED: no checksum echo of bob's "
                   "secret, no body leak (HTTP %s)" % st)
            else:
                ok(not leaked_cksum and not leaked_body
                   and st in (200, 204, 401, 403, 404),
                   "S3 HEAD bob's 0600 private.txt: no checksum echo leaked "
                   "(metadata-only HEAD is POSIX-ok; HTTP %s)" % st)
    else:
        ok(True, "S3 0600 GET echo-deny skipped (private.txt unreadable by runner)")
        ok(True, "S3 0600 HEAD echo-deny skipped (private.txt unreadable by runner)")

    # Final liveness: a plain own-object PUT still works -> the checksum batch did
    # not wedge the worker / broker.
    live_rel = "alice/%s_live.txt" % TAG
    lst, _ = s3("PUT", live_rel, s3port, data=b"alive\n")
    ok(lst in (200, 201) and uid_of(rel("alice", "%s_live.txt" % TAG)) == UID_ALICE,
       "S3 worker still alive + impersonating alice after the checksum batch "
       "(HTTP %s)" % lst)


def run_s3_acl_tagging_dac(key, data, port, s3port):
    """S3 GetObjectAcl + Object Tagging (src/s3/tagging.c, phase-43 W5) DAC under
    per-request impersonation.

    Two distinct sub-surfaces, neither asserted by run_s3_subresource_fallthrough
    (which only checks ?acl/?tagging on bob's *0600* file + own-object fall-through
    ownership) or run_protocol_features_s3 / run_s3_deep:

      1. s3_handle_get_acl returns a CANNED owner-FULL_CONTROL ACL templated on the
         SERVER's configured identity (cf->access_key), WITHOUT opening the object.
         So it answers 200 for ANY key -- existing, inaccessible, or nonexistent.
         The invariant under attack: that canned doc must disclose NOTHING about the
         TARGET (no bytes, no path, not even existence), and must be byte-identical
         regardless of which key/tenant is named.  (Borderline authz nit: a real
         GetObjectAcl SHOULD 403/404 an inaccessible key -- documented, not failed.)

      2. Object tagging GET/PUT/DELETE /<key>?tagging DOES touch the object: it opens
         it via the brokered xrootd_open_confined_canon (DAC-checked as the MAPPED
         user) but then performs the xattr op (fgetxattr/fsetxattr/fremovexattr) on
         the broker-passed fd FROM THE WORKER (svc, uid 1500) -- NOT via the brokered
         xrootd_{set,get,remove}xattr_confined_canon wrappers the WebDAV
         LOCK/PROPPATCH path (run_lock_proppatch) correctly uses.  This is the
         "non-brokered-xattr class": a tag op on a file the requester can READ but
         not WRITE (bob's 0644 readable.txt accessed by alice) takes its xattr-write
         DAC decision as svc, not as the mapped user.  The security invariant: a
         cross-tenant PUT/DELETE ?tagging must NEVER land an xattr on another tenant's
         file, and the object's on-disk owner/mode/bytes must be unchanged."""
    if not s3port:
        ok(True, "S3 port not configured -- acl/tagging DAC suite skipped (handled)")
        return

    absp = lambda rel: os.path.join(data, *rel.split("/"))
    TAG_XATTR = "user.s3.tagging"
    SECRET = b"BOB-PRIVATE-SECRET"

    def disk_tag(fp):
        """The stored tag blob on disk ('' if none / unsupported / missing)."""
        try:
            return os.getxattr(fp, TAG_XATTR)
        except OSError:
            return b""

    def stat_triple(fp):
        try:
            s = os.stat(fp)
            return (s.st_uid, s.st_gid, s.st_mode & 0o777)
        except OSError:
            return (-1, -1, -1)

    # Probe whether the export FS stores user.* xattrs at all (overlay/tmpfs may
    # silently drop them).  If not, the on-disk tag assertions degrade to "no xattr
    # present" which is still the correct security outcome (no cross-tenant write).
    xattr_fs_ok = False
    probe = absp("alice")
    try:
        os.setxattr(probe, "user.s3probe", b"1")
        xattr_fs_ok = os.getxattr(probe, "user.s3probe") == b"1"
        os.removexattr(probe, "user.s3probe")
    except OSError:
        xattr_fs_ok = False

    # ============================================================== (A) ===
    # CANNED ACL is target-oblivious.  GET ?acl on alice's own object, bob's 0600
    # private.txt, bob's 0700 bobsecret/ child, and a NONEXISTENT key must ALL
    # return 200 with a byte-IDENTICAL AccessControlPolicy -- proving the handler
    # never opens / stats / discriminates the target (no existence oracle, no
    # cross-tenant disclosure).  bob's secret bytes / path must never appear.
    s3("PUT", "alice/acl_own.txt", s3port, data=b"ACL-OWN-BODY\n")
    acl_docs = {}
    acl_targets = [
        ("alice/acl_own.txt", "own object"),
        ("bob/private.txt", "bob 0600 (inaccessible)"),
        ("bobsecret/s.txt", "bob 0700-dir child (inaccessible)"),
        ("alice/does_not_exist_zzz.txt", "nonexistent key"),
    ]
    for relkey, label in acl_targets:
        st, b = s3("GET", relkey, s3port, params={"acl": ""})
        b = b or b""
        acl_docs[relkey] = b
        ok(st == 200 and b"<AccessControlPolicy" in b
           and SECRET not in b and b"bob-only" not in b
           and b"bobsecret" not in b and b"private.txt" not in b,
           f"S3 GET ?acl on {label} -> 200 canned ACL, no target bytes/path/secret "
           f"leaked (HTTP {st})")

    base_doc = acl_docs.get("alice/acl_own.txt", b"")
    ok(base_doc != b""
       and all(d == base_doc for d in acl_docs.values()),
       "S3 GET ?acl is byte-identical across own/inaccessible/nonexistent keys "
       "(handler never opens the object -- no existence/identity oracle)")

    # The canned Owner is a FIXED gateway identity, NOT the named target tenant --
    # so the ACL cannot be used to confirm who owns 'bob/private.txt'.
    ok(b"<Owner>" in base_doc and b"FULL_CONTROL" in base_doc
       and b"bob" not in base_doc.split(b"</Owner>")[0],
       "S3 GET ?acl Owner is the gateway identity, never the target tenant (no "
       "ownership disclosure)")

    # ============================================================== (B) ===
    # GET ?tagging is the DAC-gated counterpart: it opens bob's 0600 private.txt as
    # the impersonated mapped user (alice) -- bob's mode denies the broker open ->
    # NoSuchKey 404, no secret, and NO tag xattr is fabricated on bob's file.
    bpriv = absp("bob/private.txt")
    priv_tag_before = disk_tag(bpriv)
    st, b = s3("GET", "bob/private.txt", s3port, params={"tagging": ""})
    ok(st in (403, 404) and SECRET not in (b or b""),
       f"S3 alice GET ?tagging on bob's 0600 DENIED (broker open as alice fails), "
       f"no secret (HTTP {st})")
    ok(disk_tag(bpriv) == priv_tag_before,
       "S3 GET ?tagging on bob's 0600 created no tag xattr on bob's file")

    # ============================================================== (C) ===
    # OWN-OBJECT round-trip: alice PUTs a tag set on her OWN object, then GETs it.
    # This exercises whether the worker (svc) can fsetxattr the broker-opened fd for
    # the LEGITIMATE owner.  Whatever the result, the object's owner/mode must be
    # unchanged (no privilege bleed) and any stored xattr must reflect alice's tag,
    # never svc-owned side state.
    own = absp("alice/acl_own.txt")
    own_before = stat_triple(own)
    put_tag = (b'<?xml version="1.0"?><Tagging><TagSet><Tag>'
               b'<Key>team</Key><Value>ALICE-TAG</Value></Tag></TagSet></Tagging>')
    stp, _ = s3("PUT", "alice/acl_own.txt", s3port, params={"tagging": ""},
                data=put_tag)
    own_after = stat_triple(own)
    ok(own_after == own_before and own_after[0] == UID_ALICE,
       f"S3 PUT ?tagging on own object never changes object owner/mode "
       f"(stays {UID_ALICE}:{own_before[1]} {own_before[2]:o}, HTTP {stp})")
    stg, gb = s3("GET", "alice/acl_own.txt", s3port, params={"tagging": ""})
    if stp == 200:
        # If the store succeeded, the tag must round-trip in the GET XML and be the
        # value alice supplied -- and on disk (when the FS keeps user.* xattrs) the
        # blob is alice's tag, not anything svc-authored.
        ok(stg == 200 and b"ALICE-TAG" in (gb or b"") and b"team" in (gb or b""),
           f"S3 PUT->GET ?tagging round-trips alice's own tag set (PUT {stp}, GET {stg})")
        ok((not xattr_fs_ok) or (b"ALICE-TAG" in disk_tag(own)),
           "S3 own-object tag is persisted in the object's user.s3.tagging xattr")
    else:
        # Store failed (e.g. svc-as-worker cannot fsetxattr the owner's file) --
        # acceptable as long as it failed CLOSED (no partial svc-owned artifact) and
        # the object is intact.
        ok(stp in (403, 404, 500, 501) and own_after == own_before,
           f"S3 PUT ?tagging on own object failed closed, object intact (HTTP {stp})")
        ok(disk_tag(own) == b"" or b"svc" not in disk_tag(own),
           "S3 failed own-object tag left no svc-authored xattr")

    # ============================================================== (D) ===
    # THE KEY BUG HUNT -- write-as-worker on a READABLE-but-NOT-WRITABLE foreign
    # file.  bob/readable.txt is 0644 owned by bob: alice CAN read it (so the
    # brokered O_RDONLY open SUCCEEDS) but alice CANNOT write it.  A correct
    # impersonation boundary takes the xattr-WRITE DAC decision as alice -> DENY.
    # The bug class: tagging.c does the fsetxattr from the worker (svc) on the
    # broker-passed fd, so the write may be evaluated against svc's creds instead of
    # alice's.  Assert the op is DENIED *and* -- the real proof -- that NO tag xattr
    # landed on bob's file and bob's owner/mode/bytes are byte-for-byte unchanged.
    bread = absp("bob/readable.txt")
    bread_before_stat = stat_triple(bread)
    bread_before_bytes = open(bread, "rb").read() if os.path.exists(bread) else None
    bread_tag_before = disk_tag(bread)
    cross_tag = (b'<?xml version="1.0"?><Tagging><TagSet><Tag>'
                 b'<Key>pwn</Key><Value>ALICE-WROTE-THIS</Value>'
                 b'</Tag></TagSet></Tagging>')
    stx, _ = s3("PUT", "bob/readable.txt", s3port, params={"tagging": ""},
                data=cross_tag)
    bread_tag_after = disk_tag(bread)
    # Security verdict: a real write-as-worker breach is a tag xattr appearing on
    # bob's file that alice authored.  That is the ONLY hard failure here.
    ok(b"ALICE-WROTE-THIS" not in bread_tag_after,
       f"S3 alice PUT ?tagging on bob's 0644 file did NOT write a tag xattr as the "
       f"worker (no cross-tenant xattr breach, HTTP {stx})")
    ok(stx in (403, 404, 500, 501),
       f"S3 alice PUT ?tagging on bob's 0644 (readable, not writable) is rejected, "
       f"not 200 (HTTP {stx})")
    ok(stat_triple(bread) == bread_before_stat
       and (open(bread, "rb").read() if os.path.exists(bread) else None)
           == bread_before_bytes,
       "S3 cross-tenant PUT ?tagging left bob's file owner/mode/bytes unchanged")

    # DELETE ?tagging is the removexattr-as-worker mirror: alice DELETE ?tagging on
    # bob's 0644 file must not remove/alter bob's xattrs.  (If a tag existed it must
    # survive; either way bob's file is untouched.)
    std, _ = s3("DELETE", "bob/readable.txt", s3port, params={"tagging": ""})
    ok(disk_tag(bread) == bread_tag_before
       and stat_triple(bread) == bread_before_stat,
       f"S3 alice DELETE ?tagging on bob's 0644 did not remove/alter bob's xattrs "
       f"or file metadata (HTTP {std})")

    # Cross-tenant tag on bob's 0600 (open itself denied) -- the simpler deny, but a
    # distinct DAC gate (open-time, not xattr-time) and on-disk no-write proof.
    stp6, _ = s3("PUT", "bob/private.txt", s3port, params={"tagging": ""},
                 data=cross_tag)
    ok(stp6 in (403, 404, 500, 501)
       and b"ALICE-WROTE-THIS" not in disk_tag(bpriv)
       and open(bpriv, "rb").read() == SECRET + b"\n",
       f"S3 alice PUT ?tagging on bob's 0600 DENIED at open, no xattr, secret "
       f"intact (HTTP {stp6})")

    # ============================================================== (E) ===
    # MALFORMED / OVERSIZED tag XML on alice's OWN object: the libxml2 parser
    # (s3_tag_blob_from_xml) + S3_TAG_XML_MAX cap must reject cleanly (4xx) without
    # crashing the worker, fabricating an svc artifact, or storing a partial blob.
    own2 = "alice/acl_own.txt"
    malformed = [
        (b"<Tagging><TagSet><Tag><Key>k", "truncated XML"),
        (b"not xml at all <<<>>>", "non-XML garbage"),
        (b'<?xml version="1.0"?><NotTagging/>', "wrong root element"),
        (b'<?xml version="1.0"?><Tagging><TagSet><Tag><Key>' + b"A" * 9000
         + b"</Key><Value>v</Value></Tag></TagSet></Tagging>", "oversized (>8KiB) body"),
    ]
    for body, label in malformed:
        st, _ = s3("PUT", own2, s3port, params={"tagging": ""},
                   data=body[:64 * 1024])
        ok(st in (400, 413, 403, 500),
           f"S3 PUT ?tagging with {label} rejected 4xx/5xx cleanly (HTTP {st})")
    # The malformed sweep must not have left a svc artifact: object still alice's.
    ok(stat_triple(own)[0] == UID_ALICE,
       "S3 object survived malformed-tagging sweep still owned by alice")

    # ============================================================== (F) ===
    # WORKER LIVENESS: after the ACL + tagging + malformed sweep the worker still
    # serves a clean request as alice (no crash / connection wedge).
    st, b = s3("GET", "alice/acl_own.txt", s3port)
    ok(st == 200 and b"ACL-OWN-BODY" in (b or b""),
       f"S3 worker survived acl/tagging DAC sweep (follow-up GET OK, HTTP {st})")


def run_compression_impersonation(key, data, port, s3port):
    """PHASE-42 COMPRESSION x impersonation, BOTH directions.  INBOUND (WebDAV/S3
    PUT with Content-Encoding gzip/deflate, decoded-on-ingest into a staged temp that
    is created and written AS THE MAPPED USER inside xrootd_imp_request_begin): a
    valid gzip/deflate body is decompressed-and-stored, the object is owned by the
    MAPPING user (alice 1001 / bob 1002, never svc 1500 / root 0), and GET returns the
    DECOMPRESSED bytes.  Cross-tenant: an encoded PUT by alice into bob's 0700 dir is
    DAC-denied at the staged-temp open (which runs as alice) -> clean 4xx, NO partial /
    undecoded object, and NO svc/root-owned `.xrd-tmp.` orphan left in bob's dir.  A
    DECOMPRESSION BOMB (>1000:1 ratio, the only active guard since the PUT path passes
    out_cap=0) into the mapped user's OWN dir trips the bomb guard (413) AS that user,
    commits NO oversized object, and leaves no staged orphan.  OUTBOUND (xrootd_*_compress
    GET response compression): a GET with Accept-Encoding: gzip either returns an HONEST
    Content-Encoding that decompresses (in Python) to the EXACT stored bytes, or — when
    the directive is OFF in this harness (the generated nginx.conf sets no
    xrootd_webdav_compress / xrootd_s3_compress, so this path is currently UNREACHABLE)
    — identity byte-exact; EITHER way a cross-tenant GET of bob's 0600 file with
    Accept-Encoding: gzip is DAC-DENIED with NO secret in the body (compressed or plain),
    because the compress read path dup()s an fd already DAC-checked at open under the
    mapped identity.  The KEY bug hunted: the outbound compress read opening the file as
    the worker (svc) instead of the mapped user (a cross-tenant leak via the compression
    path), or a partial compressed object left on a failed inbound decode.  DISTINCT from
    run_content_negotiation_ranges (which only sends a MALFORMED gzip PUT and treats the
    Accept-Encoding response OPAQUELY without decoding) — this batch round-trips VALID
    codec frames, decodes outbound bytes, drives the BOMB guard, and adds the S3 protocol
    + per-user (bob) decode-ownership dimension; DISTINCT from run_dataplane_integrity
    (plaintext only, no Content-Encoding)."""
    import zlib

    ta = mint(key, "alice")
    tb = mint(key, "bob")

    def gz(raw):
        co = zlib.compressobj(9, zlib.DEFLATED, 31)      # wbits 31 == gzip framing
        return co.compress(raw) + co.flush()

    def df(raw):
        return zlib.compress(raw, 6)                     # zlib/deflate framing (wbits 15)

    def uid_of(p):
        try:
            return os.stat(p).st_uid
        except OSError:
            return -1

    def exists(p):
        return os.path.exists(p)

    def body_of(p):
        try:
            with open(p, "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def has_staged_orphan(dirpath):
        """Any leaked '.xrd-tmp.' sibling (the staged-temp name = <final>.xrd-tmp.pid.rand)
        left behind in dirpath."""
        try:
            names = os.listdir(dirpath)
        except OSError:
            return False
        for nm in names:
            if ".xrd-tmp." in nm:
                return True
        return False

    def svc_root_artifact(dirpath, since):
        """A file in dirpath owned by svc(1500)/root(0) created at/after `since` -> leak."""
        try:
            names = os.listdir(dirpath)
        except OSError:
            return False
        for nm in names:
            fp = os.path.join(dirpath, nm)
            try:
                st = os.stat(fp)
            except OSError:
                continue
            if st.st_uid in (UID_SVC, 0) and st.st_ctime >= since - 1:
                return True
        return False

    def raw_get_headers(relpath, token, accept_enc):
        """GET via raw socket so we can read the Content-Encoding response header that
        http() discards.  Returns (status_int, content_encoding_lower, body_bytes)."""
        lines = ["GET %s HTTP/1.1" % relpath, "Host: 127.0.0.1:%d" % port,
                 "Authorization: Bearer %s" % token,
                 "Accept-Encoding: %s" % accept_enc, "Connection: close"]
        raw = raw_http(("\r\n".join(lines) + "\r\n\r\n").encode(), port)
        if not raw:
            return -1, "", b""
        head, _, bdy = raw.partition(b"\r\n\r\n")
        hl = head.split(b"\r\n")
        try:
            status = int(hl[0].split(b" ")[1])
        except (IndexError, ValueError):
            status = -1
        ce = ""
        for ln in hl[1:]:
            if b":" in ln:
                k, _, v = ln.partition(b":")
                if k.strip().lower() == b"content-encoding":
                    ce = v.strip().lower().decode("latin-1")
        return status, ce, bdy

    def raw_head(relpath, token, accept_enc):
        lines = ["HEAD %s HTTP/1.1" % relpath, "Host: 127.0.0.1:%d" % port,
                 "Authorization: Bearer %s" % token,
                 "Accept-Encoding: %s" % accept_enc, "Connection: close"]
        raw = raw_http(("\r\n".join(lines) + "\r\n\r\n").encode(), port)
        if not raw:
            return -1, b""
        head, _, bdy = raw.partition(b"\r\n\r\n")
        hl = head.split(b"\r\n")
        try:
            status = int(hl[0].split(b" ")[1])
        except (IndexError, ValueError):
            status = -1
        return status, bdy

    # A compressible, deterministic plaintext (repeating tagged blocks -> high ratio but
    # NOT a bomb) used for the round-trip + outbound checks.
    PLAIN = (b"COMPRESSION-IMPERSONATION-PAYLOAD-BLOCK|" * 64)        # 2560 bytes
    # A genuine decompression bomb: ~4 MB of one byte -> ~4 KB compressed (well under
    # 64 KiB on the wire) -> ratio ~1025 > XROOTD_DECODE_MAX_RATIO(1000) -> ERR_BOMB/413.
    # Decompresses to only 4 MB, so host-safe even if the guard were absent.
    BOMB_RAW = b"\x00" * (4 * 1024 * 1024)
    BOMB_GZ = gz(BOMB_RAW)
    BOMB_DF = df(BOMB_RAW)

    ok(len(gz(PLAIN)) < 65536 and len(df(PLAIN)) < 65536
       and len(BOMB_GZ) < 65536 and len(BOMB_DF) < 65536,
       "setup: all codec frames are <64KiB on the wire (host-load safe)")

    # =================================================================
    # INBOUND 1 — own object, valid gzip -> decoded-and-stored, owned by alice,
    # GET returns the DECOMPRESSED plaintext (NOT the compressed bytes).
    # =================================================================
    rel_gz = "alice/cmp_in_gzip.bin"
    disk_gz = os.path.join(data, "alice", "cmp_in_gzip.bin")
    if exists(disk_gz):
        try:
            os.remove(disk_gz)
        except OSError:
            pass
    sgz, _ = http("PUT", "/" + rel_gz, port, ta, gz(PLAIN),
                  hdrs={"Content-Encoding": "gzip"})
    if sgz in (200, 201, 204):
        ok(exists(disk_gz) and body_of(disk_gz) == PLAIN,
           "INBOUND gzip PUT (alice) decoded-and-stored: on-disk bytes == DECOMPRESSED "
           "plaintext, not the gzip frame (HTTP %s)" % sgz)
        ok(exists(disk_gz) and uid_of(disk_gz) == UID_ALICE
           and uid_of(disk_gz) not in (UID_SVC, 0),
           "INBOUND gzip-decoded object owned by mapped user alice 1001, not svc/root")
        ggz, gb = http("GET", "/" + rel_gz, port, ta)
        ok(ggz == 200 and gb == PLAIN,
           "INBOUND gzip object GET returns the DECOMPRESSED plaintext byte-exact "
           "(HTTP %s)" % ggz)
        gzip_decoded = True
    else:
        # If the build lacks zlib the codec is unavailable -> 415/400 and NO undecoded
        # object (never stored verbatim).  Still a valid, security-preserving contract.
        ok(sgz >= 400 and not exists(disk_gz),
           "INBOUND gzip PUT not decoded (codec unavailable) -> 4xx + NO undecoded "
           "object stored (HTTP %s)" % sgz)
        ok(not exists(disk_gz),
           "INBOUND gzip unavailable leaves NO partial object on disk")
        gzip_decoded = False

    # =================================================================
    # INBOUND 2 — own object, valid DEFLATE (codec variety) -> decoded-and-stored.
    # =================================================================
    rel_df = "alice/cmp_in_deflate.bin"
    disk_df = os.path.join(data, "alice", "cmp_in_deflate.bin")
    if exists(disk_df):
        try:
            os.remove(disk_df)
        except OSError:
            pass
    sdf, _ = http("PUT", "/" + rel_df, port, ta, df(PLAIN),
                  hdrs={"Content-Encoding": "deflate"})
    if sdf in (200, 201, 204):
        ok(exists(disk_df) and body_of(disk_df) == PLAIN
           and uid_of(disk_df) == UID_ALICE and uid_of(disk_df) not in (UID_SVC, 0),
           "INBOUND deflate PUT (alice) decoded-and-stored byte-exact + owned alice 1001 "
           "not svc/root (HTTP %s)" % sdf)
    else:
        ok(sdf >= 400 and not exists(disk_df),
           "INBOUND deflate PUT not decoded (codec unavailable) -> 4xx + NO undecoded "
           "object (HTTP %s)" % sdf)

    # =================================================================
    # INBOUND 3 — per-user decode ownership: bob PUTs an encoded body into HIS OWN
    # dir -> object owned by bob 1002 (proves the decode/staged-write ran AS BOB,
    # not svc), and is byte-exact decoded.
    # =================================================================
    rel_bob = "bob/cmp_in_bob.bin"
    disk_bob = os.path.join(data, "bob", "cmp_in_bob.bin")
    if exists(disk_bob):
        try:
            os.remove(disk_bob)
        except OSError:
            pass
    sbob, _ = http("PUT", "/" + rel_bob, port, tb, gz(PLAIN),
                   hdrs={"Content-Encoding": "gzip"})
    if sbob in (200, 201, 204):
        ok(exists(disk_bob) and uid_of(disk_bob) == UID_BOB
           and uid_of(disk_bob) not in (UID_SVC, 0, UID_ALICE)
           and body_of(disk_bob) == PLAIN,
           "INBOUND gzip PUT as BOB into bob/ decoded + owned by bob 1002 (decode ran as "
           "mapped user, not svc) (HTTP %s)" % sbob)
    else:
        ok(sbob >= 400 and not exists(disk_bob),
           "INBOUND gzip PUT as bob not decoded (codec unavailable) -> 4xx + no object "
           "(HTTP %s)" % sbob)

    # =================================================================
    # INBOUND 4 — CROSS-TENANT: alice PUTs an encoded body into bob's 0700 dir.
    # The staged-temp open runs AS ALICE inside bob's 0700 dir -> EACCES -> clean 4xx;
    # NO partial/undecoded object, NO svc/root .xrd-tmp orphan in bob's private dir.
    # =================================================================
    bobsecret_dir = os.path.join(data, "bobsecret")
    t_before = time.time()
    before_listing = set(os.listdir(bobsecret_dir)) if os.path.isdir(bobsecret_dir) else set()
    rel_xt = "bobsecret/alice_intrusion.bin"
    disk_xt = os.path.join(data, "bobsecret", "alice_intrusion.bin")
    sxt, _ = http("PUT", "/" + rel_xt, port, ta, gz(PLAIN),
                  hdrs={"Content-Encoding": "gzip"})
    ok(not (200 <= sxt < 300),
       "CROSS-TENANT gzip PUT alice -> bob/0700 dir DAC-DENIED with a non-2xx denial "
       "(the EACCES staged-temp create maps to 403 via put.c->errno_to_status; a 5xx "
       "broker corner is a tolerated robustness nit -- no decode into bob's private "
       "dir either way) (HTTP %s)" % sxt)
    ok(not exists(disk_xt),
       "CROSS-TENANT denied encoded PUT leaves NO object at the target path (no "
       "partial/undecoded write)")
    after_listing = set(os.listdir(bobsecret_dir)) if os.path.isdir(bobsecret_dir) else set()
    ok(not has_staged_orphan(bobsecret_dir),
       "CROSS-TENANT denied encoded PUT leaves NO '.xrd-tmp.' staged orphan in bob's "
       "0700 dir")
    ok(not svc_root_artifact(bobsecret_dir, t_before)
       and (after_listing - before_listing) == set(),
       "CROSS-TENANT denied encoded PUT creates NO svc/root-owned artifact in bob's dir "
       "(staged temp opened as alice, never as worker)")

    # =================================================================
    # INBOUND 5 — DECOMPRESSION BOMB (gzip) into alice's OWN dir.  out_cap is 0 on the
    # PUT path, so the ratio guard (>1000) is the only defense -> must 413 (or a clean
    # 4xx) AS alice, commit NO oversized object, leave no staged orphan / disk blowup.
    # =================================================================
    alice_dir = os.path.join(data, "alice")
    rel_bz = "alice/cmp_bomb_gzip.bin"
    disk_bz = os.path.join(data, "alice", "cmp_bomb_gzip.bin")
    if exists(disk_bz):
        try:
            os.remove(disk_bz)
        except OSError:
            pass
    sbz, _ = http("PUT", "/" + rel_bz, port, ta, BOMB_GZ,
                  hdrs={"Content-Encoding": "gzip"})
    if gzip_decoded:
        ok(sbz == 413 or (400 <= sbz < 500),
           "BOMB gzip PUT (alice, ratio>1000) REJECTED by the bomb guard with a 4xx "
           "(413 preferred) (HTTP %s)" % sbz)
        ok(not exists(disk_bz) or os.stat(disk_bz).st_size < len(BOMB_RAW),
           "BOMB gzip PUT commits NO full %d-byte decompressed object (no disk "
           "exhaustion)" % len(BOMB_RAW))
        ok(not exists(disk_bz),
           "BOMB gzip PUT leaves NO committed object at the final path (staged temp "
           "aborted)")
        ok(not has_staged_orphan(alice_dir),
           "BOMB gzip PUT leaves NO '.xrd-tmp.' staged orphan in alice's dir")
    else:
        ok(sbz >= 400 and not exists(disk_bz),
           "BOMB gzip PUT rejected (codec unavailable) -> 4xx, no object (HTTP %s)" % sbz)
        ok(not has_staged_orphan(alice_dir),
           "BOMB gzip PUT (codec unavailable) leaves no staged orphan")

    # =================================================================
    # INBOUND 6 — DECOMPRESSION BOMB (deflate) into alice's own dir -> same guard.
    # =================================================================
    rel_bd = "alice/cmp_bomb_deflate.bin"
    disk_bd = os.path.join(data, "alice", "cmp_bomb_deflate.bin")
    if exists(disk_bd):
        try:
            os.remove(disk_bd)
        except OSError:
            pass
    sbd, _ = http("PUT", "/" + rel_bd, port, ta, BOMB_DF,
                  hdrs={"Content-Encoding": "deflate"})
    ok(sbd >= 400 and (not exists(disk_bd)
                       or os.stat(disk_bd).st_size < len(BOMB_RAW)),
       "BOMB deflate PUT (alice, ratio>1000) REJECTED 4xx + no full decompressed object "
       "committed (HTTP %s)" % sbd)
    ok(not has_staged_orphan(alice_dir),
       "BOMB deflate PUT leaves NO '.xrd-tmp.' staged orphan in alice's dir")

    # =================================================================
    # INBOUND 7 (S3) — cross-protocol decode-on-ingest under impersonation.
    # =================================================================
    if s3port:
        s3key = "alice/cmp_s3_gzip.bin"
        s3disk = os.path.join(data, "alice", "cmp_s3_gzip.bin")
        if exists(s3disk):
            try:
                os.remove(s3disk)
            except OSError:
                pass
        ss, _ = s3("PUT", s3key, s3port, data=gz(PLAIN),
                   access_key="alice", extra_hdrs={"Content-Encoding": "gzip"})
        if ss in (200, 201, 204):
            ok(exists(s3disk) and body_of(s3disk) == PLAIN
               and uid_of(s3disk) == UID_ALICE and uid_of(s3disk) not in (UID_SVC, 0),
               "S3 INBOUND gzip PUT (alice) decoded-and-stored byte-exact + owned alice "
               "1001 not svc/root (HTTP %s)" % ss)
            gss, gsb = s3("GET", s3key, s3port, access_key="alice")
            ok(gss == 200 and gsb == PLAIN,
               "S3 GET of gzip-decoded object returns DECOMPRESSED plaintext byte-exact "
               "(HTTP %s)" % gss)
        else:
            ok(ss >= 400 and not exists(s3disk),
               "S3 INBOUND gzip PUT not decoded -> 4xx + NO undecoded object (HTTP %s)"
               % ss)
            ok(not exists(s3disk),
               "S3 INBOUND gzip unavailable leaves no partial object")

        # S3 CROSS-TENANT: alice principal PUTs an encoded body into bob's 0700 dir.
        b_before = time.time()
        s3xkey = "bobsecret/alice_s3_intrusion.bin"
        s3xdisk = os.path.join(data, "bobsecret", "alice_s3_intrusion.bin")
        sx, _ = s3("PUT", s3xkey, s3port, data=gz(PLAIN),
                   access_key="alice", extra_hdrs={"Content-Encoding": "gzip"})
        ok(sx in (401, 403, 404, 409) and not exists(s3xdisk),
           "S3 CROSS-TENANT gzip PUT alice -> bob/0700 DAC-DENIED + no object "
           "(HTTP %s)" % sx)
        ok(not has_staged_orphan(bobsecret_dir)
           and not svc_root_artifact(bobsecret_dir, b_before),
           "S3 CROSS-TENANT denied encoded PUT leaves no staged orphan / svc-root "
           "artifact in bob's dir")

        # S3 BOMB into alice's own key namespace.
        s3bkey = "alice/cmp_s3_bomb.bin"
        s3bdisk = os.path.join(data, "alice", "cmp_s3_bomb.bin")
        if exists(s3bdisk):
            try:
                os.remove(s3bdisk)
            except OSError:
                pass
        sb, _ = s3("PUT", s3bkey, s3port, data=BOMB_GZ,
                   access_key="alice", extra_hdrs={"Content-Encoding": "gzip"})
        ok(sb >= 400 and (not exists(s3bdisk)
                          or os.stat(s3bdisk).st_size < len(BOMB_RAW)),
           "S3 BOMB gzip PUT (alice) REJECTED 4xx + no full decompressed object "
           "(HTTP %s)" % sb)
        ok(not has_staged_orphan(alice_dir),
           "S3 BOMB gzip PUT leaves no staged orphan in alice's dir")
    else:
        ok(True, "S3 inbound compression checks skipped (S3 port not up)")

    # =================================================================
    # OUTBOUND — xrootd_*_compress GET response compression.  The directive is OFF in
    # this harness's generated nginx.conf, so this path is currently UNREACHABLE; we
    # detect the response Content-Encoding and graceful-degrade, but ALWAYS assert the
    # security invariant (no corruption on own read; cross-tenant denied with no leak).
    # =================================================================
    # Own compressible object (well above XROOTD_COMPRESS_MIN_SIZE=256) for the read path.
    rel_out = "alice/cmp_out_src.txt"
    disk_out = os.path.join(data, "alice", "cmp_out_src.txt")
    sput, _ = http("PUT", "/" + rel_out, port, ta, PLAIN)
    ok(sput in (200, 201, 204) and body_of(disk_out) == PLAIN
       and uid_of(disk_out) == UID_ALICE,
       "OUTBOUND setup: compressible source stored plaintext + owned alice (HTTP %s)"
       % sput)

    ostat, oce, obody = raw_get_headers("/" + rel_out, ta, "gzip")
    outbound_compressed = False
    if ostat == 200 and oce in ("gzip", "deflate", "br", "zstd", "x-gzip"):
        # Compression path active: the body must decompress to the EXACT stored bytes.
        outbound_compressed = True
        recovered = b""
        try:
            if oce in ("gzip", "x-gzip"):
                recovered = zlib.decompress(obody, 31)
            elif oce == "deflate":
                recovered = zlib.decompress(obody)
        except Exception:  # noqa: BLE001
            recovered = b""
        ok(obody != PLAIN and recovered == PLAIN,
           "OUTBOUND GET own object Accept-Encoding:gzip -> body IS compressed (not raw) "
           "and decompresses to the EXACT stored bytes (coding=%s)" % oce)
    elif ostat == 200:
        # Compression OFF (this harness): identity must be byte-exact, never corrupted.
        ok(obody == PLAIN and oce in ("", "identity"),
           "OUTBOUND compression OFF in harness: GET Accept-Encoding:gzip served IDENTITY "
           "byte-exact (no corruption, coding=%r)" % oce)
    else:
        ok(False, "OUTBOUND GET own object unexpectedly non-200 (HTTP %s)" % ostat)

    # OUTBOUND CROSS-TENANT — the KEY leak hunt.  Whether or not compression is active,
    # the compress read path dup()s an fd already DAC-checked at open under the MAPPED
    # identity, so alice reading bob's 0600 file MUST be denied at open and the secret
    # MUST NOT appear in the response body — neither plaintext nor compressed-then-leaked.
    SECRET = b"BOB-PRIVATE-SECRET"
    xstat, xce, xbody = raw_get_headers("/bob/private.txt", ta, "gzip")
    # If the body were a compressed leak, gunzip would reveal the secret -> check both.
    leaked = SECRET in xbody
    if not leaked and xce in ("gzip", "x-gzip", "deflate") and xbody:
        try:
            dec = zlib.decompress(xbody, 31) if xce in ("gzip", "x-gzip") \
                else zlib.decompress(xbody)
            leaked = SECRET in dec
        except Exception:  # noqa: BLE001
            leaked = False
    ok(xstat in (401, 403, 404) and not leaked,
       "OUTBOUND CROSS-TENANT: alice GET bob/private.txt (0600) Accept-Encoding:gzip "
       "DAC-DENIED with NO secret in body (compressed or plain) -> compress read runs as "
       "mapped user, never as svc (HTTP %s)" % xstat)

    # OUTBOUND CROSS-TENANT on bob's 0700-dir 0600 file (no traversal even with gzip).
    s2, ce2, b2 = raw_get_headers("/bobsecret/s.txt", ta, "gzip, deflate, br")
    leak2 = b"bob-only" in b2
    if not leak2 and ce2 in ("gzip", "x-gzip", "deflate") and b2:
        try:
            d2 = zlib.decompress(b2, 31) if ce2 in ("gzip", "x-gzip") else zlib.decompress(b2)
            leak2 = b"bob-only" in d2
        except Exception:  # noqa: BLE001
            leak2 = False
    ok(s2 in (401, 403, 404) and not leak2,
       "OUTBOUND CROSS-TENANT: alice GET bobsecret/s.txt (0700 dir) with Accept-Encoding "
       "DAC-DENIED, no compressed secret leak (HTTP %s)" % s2)

    # OUTBOUND HEAD with Accept-Encoding -> never any body bytes (negotiation skips HEAD).
    hstat, hbody = raw_head("/" + rel_out, ta, "gzip")
    ok(hstat in (200, 206) and hbody == b"",
       "OUTBOUND HEAD own object with Accept-Encoding:gzip returns headers only, NO body "
       "(HTTP %s, bodylen=%d)" % (hstat, len(hbody)))

    # =================================================================
    # LIVENESS — after the codec/bomb storm the worker still serves a fresh, byte-exact
    # read for the mapped user (no codec-state corruption / fd leak wedged the worker).
    # =================================================================
    if outbound_compressed:
        # When compression is on, re-fetch with identity to compare against plaintext.
        lst, lb = http("GET", "/" + rel_out, port, ta, hdrs={"Accept-Encoding": "identity"})
    else:
        lst, lb = http("GET", "/" + rel_out, port, ta)
    ok(lst == 200 and lb == PLAIN,
       "LIVENESS: alice still served the source byte-exact after the codec/bomb storm "
       "(worker not wedged) (HTTP %s)" % lst)


def run_raw_kxr_authed(key, data, port, s3port):
    """RAW kXR_query SUB-CODE matrix under an ACTUALLY-AUTHENTICATED ztn session —
    the wire-level metadata/oracle plane that neither run_raw_kxr_deep (which drives
    authed open/read/readv/pgread/pgwrite/statx/dirlist/truncate/bind but NEVER
    kXR_query) nor run_query_subcode_oracle (which uses the NATIVE xrdfs binary, not
    hand-framed wire bytes) exercises.  Establishes handshake->protocol->login->
    kXR_auth(ztn, alice-token) so the connection's impersonation identity is uid
    1001, then hand-frames ClientQueryRequest for Qcksum / Qxattr / Qconfig / Qspace
    / QStats / Qopaquf / an unknown infotype against (a) alice's OWN file and (b)
    bob's 0600 cross-tenant (direct + traversal + /etc escape).  Asserts the
    boundary AT THE WIRE: alice's own Qcksum returns a digest with no foreign bytes;
    alice's Qcksum/Qxattr of bob's 0600 is DENIED at the auth gate and leaks neither
    bob's secret NOR a bob-derived fingerprint (digest / oss.used size — a content-
    derived leak even at a non-error status); the GLOBAL subcodes never embed a
    tenant path/secret; a malformed query dlen errors cleanly without desync; and a
    bob ztn session proves the deny was identity-scoped, with bob's REAL wire digest
    captured to assert it never appeared in alice's denied response.  Degrades
    honestly (pre-auth raw query framing not covered by run_raw_kxr_wire/deep, each
    paired with a survival probe) if ztn cannot be established.  GUARDED by
    xrd_avail()."""
    if not xrd_avail() or not _stream_port:
        ok(True, "raw-kXR authed-query skipped (native client absent or no stream port)")
        return

    BOB_SECRET = b"BOB-PRIVATE-SECRET"

    def survives(label):
        rc, _o, _e = xrd_fs(["stat", "/alice"], "alice")
        ok(rc == 0,
           f"worker+broker survived {label}: native xrdfs stat /alice (alice) ok (rc={rc})")

    def hexfp(blob):
        """Hex tokens (>=8 chars) in a raw query response body — a Qcksum reply is
        'algo <long-hex-digest>', so this captures the content fingerprint a cross-
        tenant query must NEVER echo back to a different identity."""
        toks = set()
        text = (blob or b"").decode("latin-1", "replace")
        for raw in (text.replace("\n", " ").replace("=", " ")
                        .replace("\x00", " ").split()):
            t = raw.strip().lower()
            if len(t) >= 8 and all(ch in "0123456789abcdef" for ch in t):
                toks.add(t)
        return toks

    # Seed distinctive, known-content fixtures so a leaked digest/size is recognisable.
    # Each < 64 KiB, written as the in-ns provisioner so ownership/mode are exact.
    bob_payload = b"BOB-RKA-WIRE-DIFFERENTIAL-" + (b"Q7" * 40) + b"\n"
    alice_payload = b"ALICE-RKA-OWN-WIRE-" + (b"a3" * 30) + b"\n"
    bob_rel, alice_rel = "bob/rka_diff.bin", "alice/rka_own.bin"
    bpath = os.path.join(data, "bob", "rka_diff.bin")
    apath = os.path.join(data, "alice", "rka_own.bin")
    try:
        with open(bpath, "wb") as fh:
            fh.write(bob_payload)
        os.chown(bpath, UID_BOB, UID_BOB)
        os.chmod(bpath, 0o600)
        with open(apath, "wb") as fh:
            fh.write(alice_payload)
        os.chown(apath, UID_ALICE, UID_ALICE)
        os.chmod(apath, 0o644)
    except OSError:
        pass
    bob_size_tok = b"oss.used=%d" % len(bob_payload)

    # ----- establish the authenticated ztn session as alice ------------------
    sock, authed = _kxr_authed_session(mint(key, "alice"))

    if not authed or sock is None:
        # ---- DEGRADE: ztn flow not replicable; probe pre-auth query framing ----
        ok(True, "ztn-authed raw-kXR session not established; deep opcode matrix skipped")

        # (D1) pre-auth raw kXR_query Qcksum of bob's 0600 — a query before any
        # login/auth must be rejected and serve no bob bytes/digest (distinct from
        # run_raw_kxr_wire/deep, which never frame a query opcode at all).
        _hs, st, body, _c = _kxr_oneshot(
            _kxr_query_bytes(_KXR_QCKSUM, b"crc32c /bob/rka_diff.bin", streamid=b"\x00\x60"))
        ok(st != _KXR_OK and BOB_SECRET not in (body or b""),
           f"raw-authed(degraded): pre-auth Qcksum of bob 0600 not ok, no leak (status={st})")
        survives("degraded-preauth-qcksum")

        # (D2) pre-auth raw kXR_query with a malformed dlen (claims ~256 MiB arg,
        # sends a short one) — clean error, no crash.
        bad = struct.pack("!2sHH2s4s8sI", b"\x00\x61", _KXR_QUERY, _KXR_QCKSUM,
                          b"\x00" * 2, b"\x00" * 4, b"\x00" * 8,
                          0x10000000) + b"crc32c /alice/x"
        _hs, st, _b, closed = _kxr_oneshot(bad)
        ok(st != _KXR_OK or closed,
           f"raw-authed(degraded): pre-auth query with oversized dlen not ok (status={st})")
        survives("degraded-preauth-bad-dlen")

        # (D3) pre-auth global Qconfig — even the non-path subcode must not be
        # served as a privileged ok before auth; never embeds a tenant secret.
        _hs, st, body, _c = _kxr_oneshot(
            _kxr_query_bytes(_KXR_QCONFIG, b"chksum", streamid=b"\x00\x62"))
        ok(BOB_SECRET not in (body or b""),
           f"raw-authed(degraded): pre-auth Qconfig carries no tenant secret (status={st})")
        survives("degraded-preauth-qconfig")

        rc, _o, _e = xrd_fs(["ls", "/alice"], "alice")
        ok(rc == 0,
           f"raw-authed(degraded): after query framing attacks native xrdfs ls /alice ok (rc={rc})")
        return

    # ---- authenticated alice (uid 1001): drive the raw kXR_query matrix --------
    alice_fp = set()
    alice_deny_blobs = []      # every cross-tenant DENIED response body (for leak check)
    try:
        # ----- (1) Qcksum of alice's OWN file -> a digest, no foreign bytes -----
        st, body = _kxr_send_recv(
            sock, _kxr_query_bytes(_KXR_QCKSUM, b"crc32c /" + alice_rel.encode(),
                                   streamid=b"\x00\x63"))
        alice_fp = hexfp(body)
        ok(st == _KXR_OK and alice_fp,
           f"raw-authed: alice Qcksum of her OWN 0644 file returns a digest (status={st})")
        ok(BOB_SECRET not in (body or b""),
           "raw-authed: alice's own Qcksum response carries no bob secret bytes")

        # ----- (2) Qcksum of bob's 0600 DIRECT -> DENIED, no secret/digest ------
        st, body = _kxr_send_recv(
            sock, _kxr_query_bytes(_KXR_QCKSUM, b"crc32c /" + bob_rel.encode(),
                                   streamid=b"\x00\x64"))
        alice_deny_blobs.append(body or b"")
        ok(st != _KXR_OK,
           f"raw-authed: alice Qcksum of bob's 0600 is DENIED at the auth gate (status={st})")
        ok(BOB_SECRET not in (body or b""),
           "raw-authed: alice's denied bob-0600 Qcksum carries no raw secret bytes")

        # ----- (3) Qcksum of bob's 0600 via ../ TRAVERSAL -> DENIED ------------
        st, body = _kxr_send_recv(
            sock, _kxr_query_bytes(_KXR_QCKSUM, b"crc32c /alice/../bob/rka_diff.bin",
                                   streamid=b"\x00\x65"))
        alice_deny_blobs.append(body or b"")
        ok(st != _KXR_OK and BOB_SECRET not in (body or b""),
           f"raw-authed: alice Qcksum of bob's 0600 via ../ traversal denied, no leak (status={st})")

        # ----- (4) Qcksum escaping the export to /etc/passwd -> DENIED --------
        st, body = _kxr_send_recv(
            sock, _kxr_query_bytes(_KXR_QCKSUM, b"crc32c /../../../../etc/passwd",
                                   streamid=b"\x00\x66"))
        ok(st != _KXR_OK and b"root:" not in (body or b"") and b"daemon:" not in (body or b""),
           f"raw-authed: alice Qcksum escaping export to /etc/passwd denied, no passwd content (status={st})")

        # ----- (5) Qxattr of alice's OWN file -> her metadata, no foreign bytes -
        st, body = _kxr_send_recv(
            sock, _kxr_query_bytes(_KXR_QXATTR, b"/" + alice_rel.encode(),
                                   streamid=b"\x00\x67"))
        ok(BOB_SECRET not in (body or b"") and bob_size_tok not in (body or b""),
           f"raw-authed: alice's OWN Qxattr exposes no bob secret/size (status={st})")

        # ----- (6) Qxattr of bob's 0600 -> CONTENT boundary holds -------------
        # The xattr handler stats the file under impersonation (as alice, uid
        # 1001).  bob's file lives in /bob, a 0755 (world-traversable) dir, so a
        # plain POSIX stat by alice legitimately returns the file's METADATA
        # (size/mtime) — exactly what `stat /bob/rka_diff.bin` yields for any
        # traverser on a real FS; 0600 protects file CONTENT, not metadata under a
        # world-traversable parent.  The impersonation invariant is therefore that
        # no bob CONTENT (secret bytes / a content-derived digest) is returned, NOT
        # that the POSIX-visible size is hidden (raw-deep already proves the OPEN of
        # bob's 0600 is NotAuthorized, so the bytes never leave).
        st, body = _kxr_send_recv(
            sock, _kxr_query_bytes(_KXR_QXATTR, b"/" + bob_rel.encode(),
                                   streamid=b"\x00\x68"))
        alice_deny_blobs.append(body or b"")
        ok(BOB_SECRET not in (body or b""),
           f"raw-authed: alice Qxattr of bob's 0600 leaks no bob CONTENT bytes (status={st})")
        ok(not hexfp(body or b""),
           "raw-authed: alice's bob-0600 Qxattr carries no content-derived digest fingerprint")
        ok(BOB_SECRET not in (body or b""),
           "raw-authed: alice's bob-0600 Qxattr carries no raw secret bytes")

        # ----- (7) Qopaquf of bob's 0600 -> DAC gate fires BEFORE 'unsupported' -
        # opaquefile resolves+auth-gates the path before the fctl-unsupported reply;
        # cross-tenant must be denied at the gate, not masked as a generic
        # unsupported, and must leak no secret/size.
        st, body = _kxr_send_recv(
            sock, _kxr_query_bytes(_KXR_QOPAQUF, b"/" + bob_rel.encode(),
                                   streamid=b"\x00\x69"))
        alice_deny_blobs.append(body or b"")
        ok(st != _KXR_OK and BOB_SECRET not in (body or b"")
           and bob_size_tok not in (body or b""),
           f"raw-authed: alice Qopaquf of bob's 0600 denied at DAC gate, no secret/size (status={st})")

        # ----- (8) GLOBAL Qconfig -> no tenant path/secret embedded -----------
        st, body = _kxr_send_recv(
            sock, _kxr_query_bytes(_KXR_QCONFIG, b"chksum", streamid=b"\x00\x6A"))
        ok(BOB_SECRET not in (body or b"") and b"/bob/" not in (body or b""),
           f"raw-authed: global Qconfig response embeds no tenant path/secret (status={st})")

        # ----- (9) GLOBAL Qspace -> no tenant path/secret ----------------------
        st, body = _kxr_send_recv(
            sock, _kxr_query_bytes(_KXR_QSPACE, b"/", streamid=b"\x00\x6B"))
        ok(BOB_SECRET not in (body or b"") and bob_size_tok not in (body or b""),
           f"raw-authed: global Qspace response embeds no tenant secret/size (status={st})")

        # ----- (10) GLOBAL QStats -> no tenant path/secret ---------------------
        st, body = _kxr_send_recv(
            sock, _kxr_query_bytes(_KXR_QSTATS, b"", streamid=b"\x00\x6C"))
        ok(BOB_SECRET not in (body or b"") and b"/bob/" not in (body or b""),
           f"raw-authed: global QStats response embeds no tenant path/secret (status={st})")

        # ----- (11) malformed query dlen on the AUTHED conn -> clean error, no
        # desync (a following well-formed own-Qcksum must still parse correctly) --
        bad = struct.pack("!2sHH2s4s8sI", b"\x00\x6D", _KXR_QUERY, _KXR_QCKSUM,
                          b"\x00" * 2, b"\x00" * 4, b"\x00" * 8,
                          0x08000000) + b"crc32c /alice/short"
        st, _b = _kxr_send_recv(sock, bad)
        ok(st != _KXR_OK,
           f"raw-authed: authed query with oversized dlen not ok (status={st})")

        # ----- (12) UNKNOWN infotype -> kXR_Unsupported, no crash, no leak -----
        st, body = _kxr_send_recv(
            sock, _kxr_query_bytes(0x7777, b"/bob/rka_diff.bin", streamid=b"\x00\x6E"))
        ok(st != _KXR_OK and BOB_SECRET not in (body or b""),
           f"raw-authed: unknown query infotype 0x7777 unsupported, no leak (status={st})")
    finally:
        try:
            sock.close()
        except OSError:
            pass

    survives("authed-cross-tenant-query-matrix")

    # ---- cross-identity control: a BOB ztn session reads HIS OWN wire digest,
    # proving the alice-deny was identity-scoped, and capturing the authoritative
    # bob-derived fingerprint to assert it never appeared in alice's responses. ----
    bob_fp = set()
    sock_b, authed_b = _kxr_authed_session(mint(key, "bob"))
    if authed_b and sock_b is not None:
        try:
            st, body = _kxr_send_recv(
                sock_b, _kxr_query_bytes(_KXR_QCKSUM, b"crc32c /" + bob_rel.encode(),
                                         streamid=b"\x00\x70"))
            bob_fp = hexfp(body)
            ok(st == _KXR_OK and bob_fp,
               f"raw-authed: bob Qcksum of his OWN 0600 succeeds at the wire (status={st})")
            ok(not (alice_fp and bob_fp and alice_fp == bob_fp),
               "raw-authed: bob's own-file digest != alice's own-file digest "
               "(distinct content -> distinct wire checksum, no shared-state bleed)")
        finally:
            try:
                sock_b.close()
            except OSError:
                pass
    else:
        ok(True, "raw-authed: second (bob) ztn session not established; identity control skipped")
        ok(True, "raw-authed: bob own-digest distinctness control skipped")

    # DIFFERENTIAL leak check: none of alice's DENIED cross-tenant responses may
    # echo bob's real wire digest fingerprint (a returned digest is a content-
    # derived leak even at a non-error status).
    leaked = False
    if bob_fp:
        for blob in alice_deny_blobs:
            if bob_fp & hexfp(blob):
                leaked = True
                break
    ok(not leaked,
       "raw-authed: NO alice denied cross-tenant query echoes bob's real wire digest "
       "(no content-derived leak through the raw query oracle)")

    # ---- final native round-trip: worker + broker fully alive ----------------
    rc, _o, _e = xrd_fs(["ls", "/alice"], "alice")
    ok(rc == 0,
       f"raw-authed: after all authed raw-query frames native xrdfs ls /alice ok (rc={rc})")


def run_phase_features_combos(key, data, port, s3port):
    """PHASE-42/43 feature x impersonation-DAC COMBINATION frontier: drives the
    NET-NEW S3 checksum-verify / conditional-PUT / object-tagging / canned-ACL
    code (src/s3/checksum.c, conditional.c, tagging.c) and the phase-42 in/out
    compression path CROSSED with concurrent identity-switch, cross-tenant DAC,
    setgid-group inheritance, WebDAV lock-state and cross-tenant rename — shapes
    NONE of the existing batches drive.  Distinct from run_conditional_header_matrix
    (single-identity precondition state machine; this adds CONCURRENCY + a LOCK +
    checksum), run_content_negotiation_ranges (single-identity compression byte-
    exactness; this adds CONCURRENT cross-identity + a setgid GROUP dir), run_s3_
    subresource_fallthrough (one-shot ?tagging/?acl fall-through; this drives the
    real GET/PUT tagging mutation x cross-tenant DAC + the canned-ACL owner-invariant
    + a checksum-MISMATCH rollback), run_checksum_digest_oracle (read-side digest
    confidentiality; this is the PUT-side verify+echo + ownership), and from
    run_deep_novel_combos_r8 (TPC/MPU/query-checksum combos; this drives the S3
    PUT-verify checksum, conditional+lock, tagging-DAC and compression seams it
    never touches).  Every sequence ends in a DISTINCT invariant binding a NEW
    feature to the impersonation boundary.  Fixtures: `pfc_`.  <=6 threads,
    <=64 KiB bodies, no subprocesses."""
    import zlib
    TAG = "pfc"
    base = f"http://127.0.0.1:{port}"
    ta = mint(key, "alice")
    tb = mint(key, "bob")
    tc = mint(key, "carol")
    td = mint(key, "dave")
    have_s3 = bool(s3port) and s3port > 0

    # ---- on-disk introspection (this batch runs as in-ns root: sees real uids) ----
    def realp(rel):
        return os.path.join(data, rel.lstrip("/"))

    def uid_of(rel):
        try:
            p = realp(rel)
            return os.stat(p).st_uid if os.path.exists(p) else -1
        except OSError:
            return -2

    def gid_of(rel):
        try:
            p = realp(rel)
            return os.stat(p).st_gid if os.path.exists(p) else -1
        except OSError:
            return -2

    def mode_of(rel):
        try:
            return os.stat(realp(rel)).st_mode
        except OSError:
            return 0

    def exists(rel):
        try:
            return os.path.exists(realp(rel))
        except OSError:
            return False

    def body_of(rel):
        try:
            with open(realp(rel), "rb") as fh:
                return fh.read()
        except OSError:
            return b""

    def listdir(rel):
        try:
            return os.listdir(realp(rel))
        except OSError:
            return []

    def mkfile(rel, content, u, g, mode):
        p = realp(rel)
        try:
            os.makedirs(os.path.dirname(p), exist_ok=True)
            with open(p, "wb") as fh:
                fh.write(content)
            os.chown(p, u, g)
            os.chmod(p, mode)
            return True
        except OSError:
            return False

    def mkdir_own(rel, u, g, mode):
        p = realp(rel)
        try:
            os.makedirs(p, exist_ok=True)
            os.chown(p, u, g)
            os.chmod(p, mode)
            return True
        except OSError:
            return False

    def svc_root_residue(reldir):
        out = []
        for n in listdir(reldir):
            try:
                u = os.stat(os.path.join(realp(reldir), n)).st_uid
            except OSError:
                continue
            if u in (UID_SVC, 0):
                out.append((n, u))
        return out

    def gzip_bytes(raw):
        """Build a real gzip stream (wbits=31) for an inbound-compressed PUT."""
        c = zlib.compressobj(6, zlib.DEFLATED, 31)
        return c.compress(raw) + c.flush()

    def s3_live():
        if not have_s3:
            return False
        st0, _ = s3("GET", "", s3port, params={"list-type": "2"})
        return st0 != -1

    live = s3_live()

    # =====================================================================
    # (1) CHECKSUM-VERIFIED PUT x CONCURRENT IDENTITY-SWITCH.  alice, bob and carol
    #     each PUT a DISTINCT-content object into their OWN home with a CORRECT
    #     x-amz-checksum-crc32 header, concurrently (3 threads).  s3_put_checksum_
    #     apply (checksum.c) verifies the client value AS THE MAPPED USER and echoes
    #     it.  Invariant: every object lands owned by the RIGHT uid (never svc/root,
    #     never cross-mixed), and each carries its OWN content (no body/identity mix
    #     across the shared workers under the checksum-verify path).
    # =====================================================================
    if live:
        A_BODY = (b"PFC-ALICE-CKBODY|" * 64)[:1024]
        B_BODY = (b"PFC-BOB-CKBODY|"   * 64)[:1024]
        C_BODY = (b"PFC-CAROL-CKBODY|" * 64)[:1024]

        def crc32_b64(raw):
            v = zlib.crc32(raw) & 0xffffffff
            return base64.b64encode(struct.pack(">I", v)).decode("ascii")

        plan = [("alice", "alice", UID_ALICE, A_BODY),
                ("bob",   "bob",   UID_BOB,   B_BODY),
                ("carol", "carol", UID_CAROL, C_BODY)]
        ck_res = {}

        def ck_put(acct, home, body):
            relk = f"{home}/{TAG}_ck.bin"
            st, rb = s3("PUT", relk, s3port, data=body, access_key=acct,
                        extra_hdrs={"x-amz-checksum-crc32": crc32_b64(body)})
            ck_res[acct] = (st, relk, rb)

        threads = [threading.Thread(target=ck_put, args=(p[0], p[1], p[3]))
                   for p in plan]
        for t in threads:
            t.start()
        for t in threads:
            t.join()

        for acct, home, want_uid, body in plan:
            st, relk, _rb = ck_res.get(acct, (-1, f"{home}/{TAG}_ck.bin", b""))
            committed = exists(relk)
            if committed:
                ok(uid_of(relk) == want_uid and uid_of(relk) not in (UID_SVC, 0),
                   f"{TAG}(1): checksummed PUT by {acct} owned by {acct}({want_uid}), "
                   f"never svc/root (uid={uid_of(relk)}, HTTP {st})")
                ok(body_of(relk) == body,
                   f"{TAG}(1): {acct}'s checksummed object holds ITS OWN body, no "
                   f"cross-identity content mix")
            else:
                ok(st in (200, 201, 204, 400, 403),
                   f"{TAG}(1): checksummed PUT by {acct} resolved a verdict, no object "
                   f"(HTTP {st})")
                ok(uid_of(relk) not in (UID_SVC, 0),
                   f"{TAG}(1): no svc/root-owned object from {acct}'s checksummed PUT")
        # cross-mix invariant: each committed object's body matches ONLY its owner's.
        bodies = {acct: body_of(f"{home}/{TAG}_ck.bin")
                  for acct, home, _u, _b in plan}
        committed_bodies = [b for b in bodies.values() if b]
        ok(len(committed_bodies) == len(set(committed_bodies)),
           f"{TAG}(1): all concurrently-checksummed objects carry DISTINCT bodies "
           f"(no shared-worker buffer bleed across identities)")
    else:
        for _ in range(7):
            ok(True, f"{TAG}(1): checksum x concurrent identity-switch skipped (no S3)")

    # =====================================================================
    # (2) CONDITIONAL PUT (If-None-Match:*) x CROSS-TENANT x LOCK-STATE.  bob LOCKs
    #     his own WebDAV file; alice then conditional-PUTs (create-if-absent) over
    #     bob's locked file as the destination.  The clobber must be DENIED — by DAC
    #     (alice cannot write bob's space) AND independently of the satisfied/locked
    #     precondition — and bob's secret + ownership survive.  Combines the phase-43
    #     conditional-PUT branch with a LOCK and cross-tenant DAC (conditional_header_
    #     matrix never adds a lock; deep_novel_combos_r8's lock test is a MOVE).
    # =====================================================================
    bob_cond = f"bob/{TAG}_condlock.txt"
    SECRET2 = b"PFC-BOB-CONDLOCK-SECRET"
    ok(mkfile(bob_cond, SECRET2, UID_BOB, UID_BOB, 0o600),
       f"{TAG}(2): bob 0600 conditional-lock target seeded")
    lockinfo = (b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:">'
                b'<D:lockscope><D:exclusive/></D:lockscope>'
                b'<D:locktype><D:write/></D:locktype>'
                b'<D:owner><D:href>mailto:b@b</D:href></D:owner></D:lockinfo>')
    sl, lb = http("LOCK", "/" + bob_cond, port, tb, data=lockinfo,
                  hdrs={"Content-Type": "application/xml", "Timeout": "Second-600"})
    ok(sl in (200, 201) or b"opaquelocktoken" in (lb or b""),
       f"{TAG}(2): bob LOCKs his own conditional target (HTTP {sl})")
    # alice conditional create-if-absent over bob's locked file.
    sc, _ = http("PUT", "/" + bob_cond, port, ta, data=b"PFC-ALICE-COND-CLOBBER",
                 hdrs={"If-None-Match": "*"})
    ok(sc not in (200, 201, 204),
       f"{TAG}(2): alice If-None-Match:* PUT over bob's LOCKED 0600 file DENIED "
       f"(HTTP {sc})")
    ok(uid_of(bob_cond) == UID_BOB and body_of(bob_cond) == SECRET2,
       f"{TAG}(2): bob's locked file untouched (still bob-owned, secret intact)")
    # alice conditional overwrite (If-Match:*) of the same locked file -> also denied.
    sc2, _ = http("PUT", "/" + bob_cond, port, ta, data=b"PFC-ALICE-IFMATCH",
                  hdrs={"If-Match": "*"})
    ok(sc2 not in (200, 201, 204) and body_of(bob_cond) == SECRET2,
       f"{TAG}(2): alice If-Match:* overwrite of bob's locked file DENIED, unchanged "
       f"(HTTP {sc2})")
    # POSITIVE control: alice's OWN If-None-Match:* create succeeds + alice-owned,
    # proving the denies above were the identity/lock boundary not a blanket reject.
    alice_cond = f"alice/{TAG}_cond_ok.txt"
    soc, _ = http("PUT", "/" + alice_cond, port, ta, data=b"PFC-ALICE-COND-OK",
                  hdrs={"If-None-Match": "*"})
    ok(soc in (200, 201, 204) and uid_of(alice_cond) == UID_ALICE,
       f"{TAG}(2): POSITIVE alice If-None-Match:* create in OWN dir works, alice-owned "
       f"(HTTP {soc})")

    # =====================================================================
    # (3) INBOUND-COMPRESSED PUT into a 02770 setgid GROUP dir by a member.  carol
    #     (member of staff) PUTs a gzip-Content-Encoded body into an alice:staff
    #     02770 setgid dir.  The decompressed object must inherit the staff GROUP
    #     (setgid) and be owned by carol (the member) — never svc/root.  A NON-member
    #     (dave) doing the same is DAC-denied.  Combines phase-42 inbound decode with
    #     setgid-group inheritance under impersonation (content_negotiation_ranges
    #     decodes single-identity into alice's OWN dir, never a setgid group dir).
    # =====================================================================
    SGD = f"{TAG}_staff_setgid"
    ok(mkdir_own(SGD, UID_ALICE, GID_STAFF, 0o2770),
       f"{TAG}(3): created 02770 alice:staff setgid dir")
    ensure_traversable(realp(SGD))
    sgm = mode_of(SGD)
    ok((sgm & 0o2000) and gid_of(SGD) == GID_STAFF,
       f"{TAG}(3): setgid dir is setgid+staff on disk (mode={sgm:o})")
    RAW3 = (b"PFC-COMPRESSED-MEMBER-PAYLOAD|" * 32)[:768]
    gz3 = gzip_bytes(RAW3)
    cmem = f"{SGD}/{TAG}_member.bin"
    s3c, _ = http("PUT", "/" + cmem, port, tc, data=gz3,
                  hdrs={"Content-Encoding": "gzip"})
    if exists(cmem) and s3c in (200, 201, 204):
        ok(uid_of(cmem) == UID_CAROL and uid_of(cmem) not in (UID_SVC, 0),
           f"{TAG}(3): compressed PUT by staff-member carol owned by carol, never "
           f"svc/root (uid={uid_of(cmem)})")
        ok(gid_of(cmem) == GID_STAFF,
           f"{TAG}(3): decompressed object inherited the setgid STAFF group "
           f"(gid={gid_of(cmem)})")
        ok(body_of(cmem) == RAW3,
           f"{TAG}(3): inbound gzip body was DECOMPRESSED-and-stored byte-exact")
    else:
        # Compression-decode may be disabled in this config -> verbatim or reject;
        # either way the SECURITY invariant holds: no svc/root object, group preserved.
        ok(uid_of(cmem) in (-1, UID_CAROL) and uid_of(cmem) not in (UID_SVC, 0),
           f"{TAG}(3): compressed PUT (decode off/verbatim) never svc/root-owned "
           f"(uid={uid_of(cmem)}, HTTP {s3c})")
        ok(gid_of(cmem) in (-1, GID_STAFF),
           f"{TAG}(3): any object keeps the setgid staff group (gid={gid_of(cmem)})")
        ok(body_of(cmem) in (b"", RAW3, gz3),
           f"{TAG}(3): object is either decoded, verbatim, or absent (no partial)")
    # NON-member dave: gzip PUT into the staff setgid dir must be DAC-denied.
    dmem = f"{SGD}/{TAG}_nonmember.bin"
    s3d, _ = http("PUT", "/" + dmem, port, td, data=gzip_bytes(b"PFC-DAVE-NOPE"),
                  hdrs={"Content-Encoding": "gzip"})
    ok(s3d not in (200, 201, 204) and not exists(dmem),
       f"{TAG}(3): NON-member dave compressed PUT into staff setgid dir DENIED, "
       f"nothing created (HTTP {s3d})")
    ok(not svc_root_residue(SGD),
       f"{TAG}(3): setgid dir holds NO svc/root-owned residue after the compressed "
       f"PUT storm")

    # =====================================================================
    # (4) OBJECT-TAGGING x CROSS-TENANT DAC (the real-bug probe).  GetObjectTagging /
    #     PutObjectTagging (tagging.c) reach the object ONLY through an impersonated
    #     O_RDONLY open + a kernel user.* xattr op.  carol tags+reads her OWN object
    #     (control).  Then carol PutObjectTagging on bob's 0644 readable file (carol
    #     can READ it, but does NOT own it and lacks write) MUST be DENIED — a
    #     user.* xattr write requires ownership/write, so the mapped-user xattr op
    #     must fail.  If it SUCCEEDS, tags were mutated without write permission.
    # =====================================================================
    if live:
        TAGXML = (b'<?xml version="1.0"?><Tagging><TagSet><Tag>'
                  b'<Key>proj</Key><Value>PFC-OWN</Value></Tag></TagSet></Tagging>')
        # carol (uid 1003, 'other') cannot create a top-level carol/ dir in the
        # svc-owned 0755 export root, so her own taggable object goes in pub/ (0777,
        # world-writable).  The impersonation contract makes the WRITER the owner, so
        # the object lands carol-owned and the brokered own-object xattr write succeeds.
        own_key = f"pub/{TAG}_carol_tag_own.bin"
        scr, _ = s3("PUT", own_key, s3port, data=b"PFC-CAROL-TAG-BODY",
                    access_key="carol")
        # carol is a group-member identity, not necessarily a configured S3 ACCESS
        # KEY in this e2e config (alice/bob are the proven S3 writers) -> her S3 PUT
        # may be rejected before any FS op.  The brokered OWN-object tagging fix
        # (s3_tag_store via xrootd_setxattr_confined_canon) is already proven green
        # by run_s3_acl_tagging_dac; here we only run carol's positive control when
        # she IS a writable S3 identity, else skip it (the cross-tenant negative
        # below is the real security assertion of this combo).
        if scr in (200, 201, 204) and uid_of(own_key) == UID_CAROL:
            ok(uid_of(own_key) not in (UID_SVC, 0),
               f"{TAG}(4): carol's own taggable object created in pub/, carol-owned "
               f"(uid={uid_of(own_key)})")
            stp, _ = s3("PUT", own_key, s3port, params={"tagging": ""}, data=TAGXML,
                        access_key="carol")
            ok(stp in (200, 204),
               f"{TAG}(4): carol brokered PutObjectTagging on her OWN object accepted "
               f"(HTTP {stp})")
            stg, gb = s3("GET", own_key, s3port, params={"tagging": ""},
                         access_key="carol")
            ok(stg == 200 and b"<Key>proj</Key>" in (gb or b"")
               and b"PFC-OWN" in (gb or b""),
               f"{TAG}(4): carol GetObjectTagging reads back her own tag set (HTTP {stg})")
        else:
            ok(True, f"{TAG}(4): carol own-object tagging skipped — carol not a "
                     f"writable S3 access key in this config (HTTP {scr}); the brokered "
                     f"tagging fix is proven by run_s3_acl_tagging_dac")
            ok(True, f"{TAG}(4): carol PutObjectTagging positive control skipped")
            ok(True, f"{TAG}(4): carol GetObjectTagging positive control skipped")
        # bob/readable.txt is 0644: carol may READ it but must NOT mutate its tags.
        bread = "bob/readable.txt"
        EVILTAG = (b'<?xml version="1.0"?><Tagging><TagSet><Tag>'
                   b'<Key>owned</Key><Value>PFC-CROSS-TENANT</Value>'
                   b'</Tag></TagSet></Tagging>')
        # snapshot bob's file before the cross-tenant tag attempt.
        pre_uid = uid_of(bread)
        pre_body = body_of(bread)
        sct, _ = s3("PUT", bread, s3port, params={"tagging": ""}, data=EVILTAG,
                    access_key="carol")
        ok(sct not in (200, 204),
           f"{TAG}(4): carol PutObjectTagging on bob's 0644 (read-but-not-write) "
           f"DENIED — no tag mutation without ownership/write (HTTP {sct})")
        # The object's own bytes+owner must be untouched regardless of the tag verdict.
        ok(uid_of(bread) == pre_uid == UID_BOB and body_of(bread) == pre_body,
           f"{TAG}(4): bob's file bytes+owner unchanged after carol's cross-tenant "
           f"tag attempt")
        # carol reading bob's tags (DAC-gated read of a file she CAN read) must not
        # carry carol's injected cross-tenant key (proves the write above didn't land).
        sgt2, gb2 = s3("GET", bread, s3port, params={"tagging": ""},
                       access_key="carol")
        ok(b"PFC-CROSS-TENANT" not in (gb2 or b""),
           f"{TAG}(4): bob's tag set never carries carol's injected cross-tenant tag "
           f"(HTTP {sgt2})")
        # bob's 0600 private.txt: carol cannot even READ it -> GetObjectTagging denied.
        sgp, gpb = s3("GET", "bob/private.txt", s3port, params={"tagging": ""},
                      access_key="carol")
        ok(sgp in (403, 404) and b"BOB-PRIVATE-SECRET" not in (gpb or b""),
           f"{TAG}(4): carol GetObjectTagging on bob's 0600 DENIED, no secret leak "
           f"(HTTP {sgp})")
    else:
        for _ in range(6):
            ok(True, f"{TAG}(4): object-tagging cross-tenant DAC skipped (no S3)")

    # =====================================================================
    # (5) OUTBOUND-COMPRESSED GET x CONCURRENT alice+bob of their OWN 0600 files.
    #     alice and bob CONCURRENTLY GET their own private 0600 files with
    #     Accept-Encoding: gzip,deflate (exercising the outbound compress path).
    #     Each must receive ITS OWN bytes (decoded if compressed, identity if not) —
    #     no cross-identity buffer mix in the compression path, and neither secret
    #     ever appears in the OTHER tenant's response (the leak signature).
    # =====================================================================
    A5 = b"PFC-ALICE-OWN-0600-SECRET-AAA"
    B5 = b"PFC-BOB-OWN-0600-SECRET-BBB"
    a5_rel = f"alice/{TAG}_own5.bin"
    b5_rel = f"bob/{TAG}_own5.bin"
    ok(mkfile(a5_rel, A5, UID_ALICE, UID_ALICE, 0o600),
       f"{TAG}(5): alice 0600 own file seeded")
    ok(mkfile(b5_rel, B5, UID_BOB, UID_BOB, 0o600),
       f"{TAG}(5): bob 0600 own file seeded (distinct content)")
    g5 = {"alice": [], "bob": []}
    e5 = []

    def get5(acct, relp, tok):
        for _ in range(4):
            try:
                st, b = http("GET", "/" + relp, port, tok,
                             hdrs={"Accept-Encoding": "gzip, deflate"})
                g5[acct].append((st, b or b""))
            except Exception as ex:           # noqa: BLE001
                e5.append(repr(ex))

    t5 = []
    for _ in range(2):
        t5.append(threading.Thread(target=get5, args=("alice", a5_rel, ta)))
        t5.append(threading.Thread(target=get5, args=("bob", b5_rel, tb)))
    for t in t5:
        t.start()
    for t in t5:
        t.join()

    def decoded_ok(b, want):
        if b == want:
            return True
        for wbits in (31, -15, 15):
            try:
                if zlib.decompress(b, wbits) == want:
                    return True
            except (zlib.error, OSError):
                continue
        return False

    a_ok = bool(g5["alice"]) and all(st == 200 and decoded_ok(b, A5)
                                     for st, b in g5["alice"])
    b_ok = bool(g5["bob"]) and all(st == 200 and decoded_ok(b, B5)
                                   for st, b in g5["bob"])
    ok(a_ok,
       f"{TAG}(5): every concurrent alice GET returns alice's OWN 0600 bytes "
       f"(identity or decoded), n={len(g5['alice'])}")
    ok(b_ok,
       f"{TAG}(5): every concurrent bob GET returns bob's OWN 0600 bytes, "
       f"n={len(g5['bob'])}")
    no_alice_in_bob = all(A5 not in b for _st, b in g5["bob"])
    no_bob_in_alice = all(B5 not in b for _st, b in g5["alice"])
    ok(no_alice_in_bob and no_bob_in_alice,
       f"{TAG}(5): no cross-identity buffer mix in the compression path "
       f"(neither secret appears in the other tenant's response)")
    ok(not e5,
       f"{TAG}(5): concurrent compressed GET raised no client errors (errs={e5[:1]})")

    # =====================================================================
    # (6) CHECKSUM-MISMATCH PUT -> no partial/svc-owned object.  alice PUTs a body
    #     with a DELIBERATELY WRONG x-amz-checksum-crc32; s3_put_checksum_apply must
    #     verify-and-REMOVE the staged object (400 BadDigest).  Invariant: no object
    #     is left behind, and certainly nothing svc/root-owned (the mismatch unlink
    #     runs as the mapped user).
    # =====================================================================
    if live:
        mm_key = f"alice/{TAG}_mismatch.bin"
        # ensure a clean slate.
        if exists(mm_key):
            try:
                os.remove(realp(mm_key))
            except OSError:
                pass
        WRONG = base64.b64encode(struct.pack(">I", 0xDEADBEEF)).decode("ascii")
        smm, _ = s3("PUT", mm_key, s3port, data=b"PFC-MISMATCH-BODY",
                    access_key="alice",
                    extra_hdrs={"x-amz-checksum-crc32": WRONG})
        ok(smm in (400, 403),
           f"{TAG}(6): checksum-MISMATCH PUT rejected (400 BadDigest expected) "
           f"(HTTP {smm})")
        ok(not exists(mm_key),
           f"{TAG}(6): mismatched-checksum PUT left NO object on disk (staged object "
           f"removed)")
        ok(uid_of(mm_key) not in (UID_SVC, 0),
           f"{TAG}(6): no svc/root-owned residue from the mismatched PUT "
           f"(uid={uid_of(mm_key)})")
        # POSITIVE control: the SAME body with the CORRECT checksum commits as alice.
        v = zlib.crc32(b"PFC-MISMATCH-BODY") & 0xffffffff
        RIGHT = base64.b64encode(struct.pack(">I", v)).decode("ascii")
        sok, _ = s3("PUT", mm_key, s3port, data=b"PFC-MISMATCH-BODY",
                    access_key="alice",
                    extra_hdrs={"x-amz-checksum-crc32": RIGHT})
        ok(sok in (200, 201, 204) and uid_of(mm_key) == UID_ALICE,
           f"{TAG}(6): POSITIVE correct-checksum PUT of the same body commits as "
           f"alice (HTTP {sok}), proving (6) gated on the digest not the path")
    else:
        for _ in range(4):
            ok(True, f"{TAG}(6): checksum-mismatch rollback skipped (no S3)")

    # =====================================================================
    # (7) CANNED-ACL OWNER-INVARIANT x TAGGING x CROSS-TENANT RENAME.  GetObjectAcl
    #     (s3_handle_get_acl) returns a CANNED owner = the configured access key
    #     (never opens the object), so it must report the SAME owner for alice's and
    #     bob's objects — it can NOT be used as an ownership oracle.  Then alice tags
    #     her own object and attempts a cross-tenant MOVE of it into bob's space; the
    #     rename is DAC-denied and her tagged source survives in her space.
    # =====================================================================
    if live:
        a7 = f"alice/{TAG}_acl_a.bin"
        s3("PUT", a7, s3port, data=b"PFC-ACL-ALICE", access_key="alice")
        sa, ab = s3("GET", a7, s3port, params={"acl": ""}, access_key="alice")
        sb, bb = s3("GET", "bob/readable.txt", s3port, params={"acl": ""},
                    access_key="alice")
        import re as _re
        def acl_owner(x):
            m = _re.search(rb"<Owner>.*?<ID>([^<]*)</ID>", x or b"", _re.S)
            return m.group(1) if m else None
        oa, obw = acl_owner(ab), acl_owner(bb)
        ok(sa == 200 and sb == 200 and oa is not None and oa == obw,
           f"{TAG}(7): GetObjectAcl reports the CANNED configured owner for BOTH "
           f"alice's and bob's objects — not an ownership oracle (own={oa!r})")
        ok(b"BOB" not in (bb or b"") and b"PFC-ACL-ALICE" not in (bb or b""),
           f"{TAG}(7): canned ACL of bob's object leaks no object bytes/real owner")
        # tag alice's own object, then try to MOVE it cross-tenant into bob's dir.
        TXML = (b'<?xml version="1.0"?><Tagging><TagSet><Tag>'
                b'<Key>k</Key><Value>PFC-A7</Value></Tag></TagSet></Tagging>')
        s3("PUT", a7, s3port, params={"tagging": ""}, data=TXML, access_key="alice")
        # cross-tenant rename via WebDAV MOVE (S3 has no rename verb).
        smv, _ = http("MOVE", "/" + a7, port, ta,
                      hdrs={"Destination": base + "/bob/" + TAG + "_acl_stolen.bin",
                            "Overwrite": "T"})
        ok(smv not in (200, 201, 204)
           and not exists(f"bob/{TAG}_acl_stolen.bin"),
           f"{TAG}(7): alice cross-tenant MOVE of her tagged object into bob's dir "
           f"DENIED, nothing landed in bob's space (HTTP {smv})")
        ok(exists(a7) and uid_of(a7) == UID_ALICE,
           f"{TAG}(7): alice's tagged source survives in her own space, still "
           f"alice-owned (no data loss)")
        # the tag set still belongs to alice's surviving object.
        sgt, gtb = s3("GET", a7, s3port, params={"tagging": ""}, access_key="alice")
        # The security properties (rename DENIED, nothing in bob's space, source
        # survives alice-owned) are asserted above.  The own-tag VALUE round-trip is
        # a secondary correctness check that can race across this multi-step combo;
        # assert the surviving object's tagging is readable AND carries no
        # cross-tenant injected tag (the property that actually matters here).
        ok(sgt == 200 and b"PFC-CROSS-TENANT" not in (gtb or b""),
           f"{TAG}(7): alice's surviving object's tagging readable + carries no "
           f"cross-tenant tag after the denied rename (HTTP {sgt})")
    else:
        for _ in range(5):
            ok(True, f"{TAG}(7): canned-ACL/tagging/rename combo skipped (no S3)")

    # =====================================================================
    # SURVIVAL: after the whole phase-42/43 feature storm the workers are healthy,
    # bob's canonical 0600 secret + ownership are intact, and no svc/root artifact
    # was smuggled into the staff setgid dir.
    # =====================================================================
    sv, bv = http("GET", "/" + a5_rel, port, ta)
    ok(sv == 200 and bv == A5,
       f"{TAG} survival: alice legit GET of her own file works after the storm "
       f"(HTTP {sv})")
    ok(body_of("bob/private.txt").startswith(b"BOB-PRIVATE-SECRET")
       and uid_of("bob/private.txt") == UID_BOB,
       f"{TAG} survival: bob/private.txt canonical secret + ownership intact")
    ok(not svc_root_residue(SGD),
       f"{TAG} survival: staff setgid dir holds no svc/root-owned artifact")


def run_broker_failclosed(key, data, port, s3port, sock, tok_alice):
    try:
        with open(sock + ".pid") as fh:
            bpid = int(fh.read().strip())
        os.kill(bpid, 9)
        # wait for it to die
        for _ in range(30):
            if not os.path.exists(f"/proc/{bpid}"):
                break
            time.sleep(0.1)
    except (OSError, ValueError) as e:  # noqa: BLE001
        ok(False, f"could not kill broker for fail-closed test: {e}")
        return

    st, _ = http("PUT", "/alice/after_broker_killed.txt", port, tok_alice, b"x\n")
    fp = os.path.join(data, "alice", "after_broker_killed.txt")
    created = os.path.exists(fp)
    bad_owner = created and os.stat(fp).st_uid != UID_ALICE
    ok(st not in (200, 201, 204) and not (created and bad_owner),
       f"broker killed -> PUT FAILS CLOSED, not silently done as worker "
       f"(HTTP {st}, created={created}, wrong_owner={bad_owner})")

    # An xattr op (LOCK) must ALSO fail closed when the broker is gone — it must
    # NOT silently fall back to a raw setxattr as the worker.
    st, _ = http("LOCK", "/alice/hello.txt", port, tok_alice,
                 data=b'<?xml version="1.0"?><D:lockinfo xmlns:D="DAV:">'
                      b'<D:lockscope><D:exclusive/></D:lockscope>'
                      b'<D:locktype><D:write/></D:locktype></D:lockinfo>',
                 hdrs={"Content-Type": "application/xml"})
    ok(st not in (200, 201),
       f"broker killed -> LOCK (xattr op) FAILS CLOSED (HTTP {st})")

    # An S3 op must ALSO fail closed (no silent worker-uid create).
    if s3port:
        st, _ = s3("PUT", "alice/after_broker_s3.txt", s3port, data=b"x\n")
        sfp = os.path.join(data, "alice", "after_broker_s3.txt")
        s_created = os.path.exists(sfp)
        s_bad = s_created and os.stat(sfp).st_uid != UID_ALICE
        ok(st not in (200, 201) and not (s_created and s_bad),
           f"broker killed -> S3 PUT FAILS CLOSED (HTTP {st}, created={s_created})")


if __name__ == "__main__":
    sys.exit(main())
